-- Daily-Puzzle-Bücher (17 „1001 Chess Exercises", 40 „Ultimate Chess Puzzle Book",
-- 41 „Checkmate Patterns Manual"): Nach-(Re-)Import-Fixup — NACH JEDEM NEUIMPORT EINSPIELEN.
-- Macht zwei Dinge:
--   1) Spoiler in Kapitel-/Puzzle-Titeln entschärfen (Thema/Taktik-/Mattname verrät die Lösung).
--   2) Vorberechnete Tipps wiederherstellen (Sicherungsnetz; Block wird nach der Generierung angehängt).
-- Matcht per Buchdatei (portabel Dev/Prod). Alle UPDATEs idempotent.
--
-- Anwenden (Prod):
--   docker exec -i rookhub-mariadb mariadb -u<user> -p'<pw>' rookhub < scripts/hints/daily_puzzle_books.sql

-- 1) Kapitelnamen entschärfen → „Chapter N"
--    17 & 41: Format „N. <Thema>" → „Chapter N"
UPDATE BookPuzzles SET Chapter = CONCAT('Chapter ', SUBSTRING_INDEX(Chapter, '.', 1))
  WHERE BookFileName IN ('chessable-u5-21646.pgn','chessable-u5-243265.pgn')
    AND Chapter REGEXP '^[0-9]+[.]';
--    40: Format „Chapter N: <Thema>" → „Chapter N"
UPDATE BookPuzzles SET Chapter = SUBSTRING_INDEX(Chapter, ':', 1)
  WHERE BookFileName = 'chessable-u5-49693.pgn' AND Chapter LIKE 'Chapter %:%';

-- 2) Spoiler-Titel entschärfen
--    40: die 15 Lehr-Titel in Chapter 1 sind reine Taktiknamen (keine Ziffer) → neutralisieren.
--        (Partie-Titel beginnen mit „N) …" und bleiben unberührt.)
UPDATE BookPuzzles SET Title = 'Tactical example'
  WHERE BookFileName = 'chessable-u5-49693.pgn' AND Title NOT REGEXP '[0-9]';
--    41: Titel ohne „vs" sind Mattnamen („Anastasia's Mate") → neutralisieren.
--        (Partie-Titel „A vs. B (Jahr)" bleiben unberührt.)
UPDATE BookPuzzles SET Title = 'Checkmate puzzle'
  WHERE BookFileName = 'chessable-u5-243265.pgn' AND Title NOT LIKE '% vs%';

-- 3) Tipps (wiederherstellen / sichern): wird nach der Generierung angehängt.

-- ===== Tipps (3087 Puzzles, Bücher 17/40/41), generiert 2026-06-22 =====
-- Book 17 (chessable-u5-21646.pgn): 1036 Tipps
UPDATE BookPuzzles SET HintsJson='{"de":["Ein überlasteter Verteidiger kann nicht zwei Dinge zugleich schützen – nutze das aus, um Material zu gewinnen.","Der Läufer kann die feindliche Dame von einem ihrer Schützlinge wegjagen.","Läufer schlägt auf a7 – vertreibt die Dame und gewinnt Material."],"en":["An overloaded defender cannot guard two things at once — exploit it to win material.","The bishop can chase the enemy queen away from one of her duties.","Bishop takes on a7 — drives off the queen and wins material."],"hr":["Preopterećeni branitelj ne može čuvati dvije stvari odjednom — iskoristi to za osvajanje materijala.","Lovac može otjerati protivničku damu s jedne od njezinih dužnosti.","Lovac uzima na a7 — tjera damu i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.003' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Beseitige die Verteidiger geschickt, dann fällt Material oder es droht Matt.","Ein Springer beginnt die Kombination, indem er einen Schlüsselverteidiger entfernt.","Springer schlägt auf d4 – Auftakt einer Kombination, die Material gewinnt."],"en":["Strip away the defenders cleverly, then material falls or mate looms.","A knight starts the combination by removing a key defender.","Knight takes on d4 — the start of a combination that wins material."],"hr":["Vješto ukloni branitelje, pa pada materijal ili prijeti mat.","Skakač započinje kombinaciju uklanjajući ključnog branitelja.","Skakač uzima na d4 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.004' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorbereitender Zug ebnet den Weg, danach gewinnt eine Kombination Material.","Die Dame lockt zunächst eine feindliche Figur auf ein ungünstiges Feld.","Dame zieht nach h6 – leitet die materialgewinnende Kombination ein."],"en":["A preparatory move paves the way, then a combination wins material.","The queen first lures an enemy piece onto an awkward square.","Queen to h6 — sets the material-winning combination in motion."],"hr":["Pripremni potez krči put, a zatim kombinacija osvaja materijal.","Dama najprije namami protivničku figuru na nezgodno polje.","Dama na h6 — pokreće kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.005' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Durch Unterbrechung der Verbindung der Verteidiger lässt sich Material erobern.","Der Läufer stellt sich zwischen die feindlichen Türme und stört ihre Zusammenarbeit.","Läufer schlägt auf d8 – beginnt die Kombination, die Material gewinnt."],"en":["Cutting the link between the defenders lets you win material.","The bishop steps between the enemy rooks and breaks their cooperation.","Bishop takes on d8 — launches the combination that wins material."],"hr":["Prekidanjem veze između branitelja možeš osvojiti materijal.","Lovac se ubacuje između protivničkih topova i prekida njihovu suradnju.","Lovac uzima na d8 — pokreće kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.006' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein spektakuläres Opfer auf einem zentralen Feld erzwingt das Matt.","Die Dame opfert sich so, dass jede Wiedernahme einen eigenen Verteidiger verstellt.","Dame schlägt auf e6 – erzwungenes Matt folgt."],"en":["A spectacular sacrifice on a central square forces mate.","The queen sacrifices herself so that any recapture blocks one of Black''s own pieces.","Queen takes on e6 — forced mate follows."],"hr":["Spektakularna žrtva na središnjem polju forsira mat.","Dama se žrtvuje tako da svako uzimanje zakrči jednu od crnih figura.","Dama uzima na e6 — slijedi prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.007' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schlage den Verteidiger weg und kassiere danach Material.","Der Turm eröffnet die Folge, indem er einen Schützenstein vom Brett räumt.","Turm schlägt auf a7 – Auftakt zum Materialgewinn."],"en":["Capture the defender and then collect material.","The rook opens the sequence by clearing a guard off the board.","Rook takes on a7 — the start of the material win."],"hr":["Uzmi branitelja, a zatim pokupi materijal.","Top otvara niz uklanjajući čuvara s ploče.","Top uzima na a7 — početak osvajanja materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:003.009' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Entferne den Königsschützer und eine Kombination gewinnt Material.","Ein Springer schlägt zuerst zu und reißt die Deckung vor dem König auf.","Springer schlägt auf f6 – leitet die materialgewinnende Folge ein."],"en":["Remove the king''s shield and a combination wins material.","A knight strikes first, tearing open the cover in front of the king.","Knight takes on f6 — begins the material-winning sequence."],"hr":["Ukloni kraljev štit i kombinacija osvaja materijal.","Skakač prvi udara i razbija zaklon ispred kralja.","Skakač uzima na f6 — započinje niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.010' AND BookFileName='chessable-u5-21646.pgn';
