UPDATE BookPuzzles SET HintsJson='{"de":["Beseitige den wichtigsten Verteidiger des Gegners, und das Material fällt dir zu.","Ein zentraler Springer hält die feindliche Stellung zusammen – nimm ihn ins Visier.","Springer schlägt auf f6 – beginnt die materialgewinnende Kombination."],"en":["Remove the opponent''s key defender and the material is yours.","A central knight is holding the enemy position together — target it.","Knight takes on f6 — starting the material-winning combination."],"hr":["Ukloni glavnog branitelja protivnika i materijal je tvoj.","Središnji skakač drži neprijateljsku poziciju na okupu — uzmi ga na nišan.","Skakač uzima na f6 — započinje kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.034' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Reiße die Bauernkette auseinander und gewinne entscheidendes Material.","Ein Turm bricht in die gegnerische Festung ein – die Stützbauern fallen.","Turm schlägt auf b6 – Auftakt der materialgewinnenden Folge."],"en":["Tear open the pawn chain and win decisive material.","A rook crashes into the enemy fortress — the supporting pawns fall.","Rook takes on b6 — the start of the material-winning sequence."],"hr":["Rastrgaj pješački lanac i osvoji odlučujući materijal.","Top upada u neprijateljsku tvrđavu — potporni pješaci padaju.","Top uzima na b6 — početak slijeda koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.035' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke den Verteidiger weg und kassiere entscheidendes Material.","Ein vorgeschobener Bauer lockt eine feindliche Figur von ihrer Aufgabe weg.","Bauer nach f4 – leitet die materialgewinnende Kombination ein."],"en":["Lure the defender away and collect decisive material.","An advancing pawn pulls an enemy piece off its duty.","Pawn to f4 — launching the material-winning combination."],"hr":["Odmami branitelja i pokupi odlučujući materijal.","Pješak u prodoru odvlači neprijateljsku figuru s njezine dužnosti.","Pješak na f4 — pokreće kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.036' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zwischenmanöver schaltet die Verteidigung aus und gewinnt Material.","Der Läufer drängt sich ins Zentrum und stört die feindliche Koordination.","Läufer schlägt auf d3 – Beginn der materialgewinnenden Folge."],"en":["An in-between move knocks out the defence and wins material.","The bishop barges into the centre and disrupts the enemy coordination.","Bishop takes on d3 — starting the material-winning sequence."],"hr":["Međupotez izbacuje obranu iz igre i osvaja materijal.","Lovac upada u središte i remeti koordinaciju protivnika.","Lovac uzima na d3 — početak slijeda koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.037' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – verstelle und schlage zu.","Ein Läufer durchschneidet die Verteidigung und öffnet den Weg zum König.","Läufer nach e2 – Auftakt des erzwungenen Mattangriffs."],"en":["A forced mate is in the air — interfere, then strike.","A bishop cuts through the defence and opens the road to the king.","Bishop to e2 — the start of the forced mating attack."],"hr":["Prisilni mat visi u zraku — presijeci obranu pa udari.","Lovac presijeca obranu i otvara put do kralja.","Lovac na e2 — početak prisilnog matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:003.038' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schalte den Springer aus, der die Verteidigung trägt, und gewinne Material.","Der Läufer geht aktiv vor und nimmt den feindlichen Springer ins Visier.","Läufer nach g5 – leitet die materialgewinnende Folge ein."],"en":["Eliminate the knight that holds the defence and win material.","The bishop steps forward actively, eyeing the enemy knight.","Bishop to g5 — beginning the material-winning sequence."],"hr":["Ukloni skakača koji drži obranu i osvoji materijal.","Lovac aktivno istupa i cilja neprijateljskog skakača.","Lovac na g5 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.039' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Verstelle die Verteidigungslinie und gewinne entscheidendes Material.","Ein Läufer übernimmt die Schlüsseldiagonale und fesselt die Kräfte des Gegners.","Läufer nach c4 – Auftakt der materialgewinnenden Kombination."],"en":["Interfere on the defensive line and win decisive material.","A bishop seizes the key diagonal and ties down the enemy forces.","Bishop to c4 — the start of the material-winning combination."],"hr":["Presijeci obrambenu liniju i osvoji odlučujući materijal.","Lovac preuzima ključnu dijagonalu i sputava protivničke snage.","Lovac na c4 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.040' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Sprenge die gegnerische Bauernkette und gewinne Material.","Ein vorgeschobener Bauer reißt die feindliche Struktur auseinander.","Bauer nach b4 – beginnt die materialgewinnende Folge."],"en":["Blast open the opponent''s pawn chain and win material.","An advanced pawn rips apart the enemy structure.","Pawn to b4 — starting the material-winning sequence."],"hr":["Razbij protivnički pješački lanac i osvoji materijal.","Istureni pješak razdire neprijateljsku strukturu.","Pješak na b4 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.041' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Beseitige den Verteidiger durch ein Damenmanöver und gewinne Material.","Die Dame schaltet die feindliche Dame aus und entlarvt die Schwächen.","Dame schlägt auf c3 – Auftakt der materialgewinnenden Folge."],"en":["Remove the defender with a queen stroke and win material.","The queen knocks out the enemy queen and lays bare the weaknesses.","Queen takes on c3 — the start of the material-winning sequence."],"hr":["Ukloni branitelja daminim potezom i osvoji materijal.","Dama izbacuje neprijateljsku damu i ogoljava slabosti.","Dama uzima na c3 — početak slijeda koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.042' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke den verteidigenden Turm ab und gewinne Material.","Ein Läufer macht sich auf, den feindlichen Turm zu jagen.","Läufer nach d2 – leitet die materialgewinnende Folge ein."],"en":["Deflect the defending rook and win material.","A bishop sets off to hunt the enemy rook.","Bishop to d2 — beginning the material-winning sequence."],"hr":["Odvuci obrambenog topa i osvoji materijal.","Lovac kreće u lov na neprijateljskog topa.","Lovac na d2 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.043' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsstellung auf und gewinnt Material.","Der Läufer dringt entscheidend ein und legt die feindliche Deckung lahm.","Läufer schlägt auf e3 – Auftakt der materialgewinnenden Kombination."],"en":["A sacrifice rips open the king''s shelter and wins material.","The bishop breaks in decisively and paralyses the enemy cover.","Bishop takes on e3 — the start of the material-winning combination."],"hr":["Žrtva razbija kraljev zaklon i osvaja materijal.","Lovac odlučno prodire i paralizira neprijateljsku zaštitu.","Lovac uzima na e3 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.044' AND BookFileName='chessable-u5-21646.pgn';
