UPDATE BookPuzzles SET HintsJson='{"de":["Verwandle entscheidend und beseitige danach den Verteidiger – Material fällt.","Ein durchbrechender Bauer wird zur Dame und sprengt die Verteidigung.","Bauer verwandelt sich auf d1 zur Dame – Auftakt der materialgewinnenden Folge."],"en":["Promote decisively, then clear away the defender — material falls.","A breakthrough pawn becomes a queen and shatters the defence.","Pawn promotes to a queen on d1 — the start of the material-winning sequence."],"hr":["Promoviraj odlučno, pa ukloni branitelja — materijal pada.","Probojni pješak postaje dama i razbija obranu.","Pješak se promovira u damu na d1 — početak slijeda koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.046' AND BookFileName='chessable-u5-21646.pgn';
