UPDATE BookPuzzles SET HintsJson='{"de":["Treibe den König und beseitige die Verteidiger – ein Matt wartet.","Ein Springer jagt den König und reißt die Deckung weg.","Springer nach b6 – Auftakt des erzwungenen Mattangriffs."],"en":["Drive the king and clear the defenders — a mate awaits.","A knight chases the king and tears away the cover.","Knight to b6 — the start of the forced mating attack."],"hr":["Tjeraj kralja i ukloni branitelje — mat čeka.","Skakač goni kralja i otkida zaštitu.","Skakač na b6 — početak prisilnog matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:003.060' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke den Verteidiger ab, dann setzt du den König matt.","Die Dame zwingt den feindlichen Verteidiger zur Aufgabe seines Postens.","Dame schlägt auf f8 – Auftakt des erzwungenen Mattangriffs."],"en":["Deflect the defender, then mate the king.","The queen forces the enemy defender off its post.","Queen takes on f8 — the start of the forced mating attack."],"hr":["Odvuci branitelja, zatim matiraj kralja.","Dama prisiljava neprijateljskog branitelja da napusti svoje mjesto.","Dama uzima na f8 — početak prisilnog matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:003.061' AND BookFileName='chessable-u5-21646.pgn';
