UPDATE BookPuzzles SET HintsJson='{"de":["Beseitige den deckenden Bauern und ein erzwungenes Matt folgt.","Die Dame opfert sich, um die Königsstellung aufzureißen.","Dame nach g5 – Auftakt des erzwungenen Mattangriffs."],"en":["Remove the shielding pawn and a forced mate follows.","The queen sacrifices itself to rip open the king''s position.","Queen to g5 — the start of the forced mating attack."],"hr":["Ukloni zaštitnog pješaka i slijedi prisilni mat.","Dama se žrtvuje da razbije kraljevu poziciju.","Dama na g5 — početak prisilnog matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:003.063' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Räume den Verteidiger weg und ein erzwungenes Matt steht bereit.","Deine Dame schlägt einen lästigen Verteidiger, dann übernehmen die schweren Figuren.","Dame schlägt auf e3 – Auftakt zum erzwungenen Matt."],"en":["Remove the key defender and a forced mate appears.","Your queen takes off an annoying defender, then the heavy pieces finish.","Queen takes on e3 — starting the forced mate."],"hr":["Ukloni branitelja i prisilni mat je tu.","Tvoja dama uzima dosadnog branitelja, a teške figure dovršavaju.","Dama uzima na e3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.064' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst ein Mattnetz im Stil von Anastasia erzwingen.","Springer und Turm spinnen das Netz, ein Bauernopfer öffnet den Weg.","Dame schlägt auf e2 – Beginn der erzwungenen Mattfolge."],"en":["You can force a mating net in the Anastasia style.","Knight and rook weave the net after a clearing capture.","Queen takes on e2 — start of the forced mating sequence."],"hr":["Možeš prisiliti matnu mrežu u stilu Anastasije.","Skakač i top pletu mrežu nakon raščišćavajućeg uzimanja.","Dama uzima na e2 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.065' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke die Verteidiger ab und das Matt wird unausweichlich.","Opfere Schwerfiguren, damit der Springer den Königskäfig schließt.","Turm schlägt auf e8 – Einleitung des erzwungenen Matts."],"en":["Deflect the defenders and mate becomes unavoidable.","Sacrifice heavy pieces so the knight can seal the king''s cage.","Rook takes on e8 — beginning the forced mate."],"hr":["Odvuci branitelje i mat postaje neizbježan.","Žrtvuj teške figure da skakač zatvori kraljev kavez.","Top uzima na e8 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.066' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da, wenn du den Verteidiger beseitigst.","Deine Dame dringt entscheidend in die Königsstellung ein.","Dame schlägt auf c7 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is there once you remove the defender.","Your queen breaks decisively into the king''s shelter.","Queen takes on c7 — start of the forced mating sequence."],"hr":["Prisilni mat je tu kad ukloniš branitelja.","Tvoja dama presudno prodire u kraljevo sklonište.","Dama uzima na c7 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.067' AND BookFileName='chessable-u5-21646.pgn';
