UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft, sobald der Schlüsselverteidiger entfernt ist.","Ein Läuferopfer reißt die Königsstellung auf und Dame und Springer geben den Rest.","Läufer schlägt auf h6 – eröffnet das erzwungene Matt."],"en":["A forced mate appears once the key defender is removed.","A bishop sacrifice tears open the king and queen plus knight finish.","Bishop takes on h6 — starting the forced mate."],"hr":["Prisilni mat dolazi čim se ukloni glavni branitelj.","Žrtva lovca razbija kraljev zaklon, a dama i skakač dovršavaju.","Lovac uzima na h6 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.094' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer lockt die Verteidigung weg und ein erzwungenes Matt folgt.","Der Turm beginnt, doch der dunkelfeldrige Läufer setzt die Maschinerie in Gang.","Turm schlägt auf d2 – Beginn der Mattkombination."],"en":["A queen sacrifice drags the defence away and a forced mate follows.","The rook leads off, but the dark-squared bishop drives the attack.","Rook takes on d2 — the start of the mating combination."],"hr":["Žrtva dame odvlači obranu i slijedi prisilni mat.","Top započinje, ali lovac po crnim poljima pokreće napad.","Top uzima na d2 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.095' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Opfere Material, um den entscheidenden Verteidiger abzulenken – Matt ist erzwungen.","Der Turm geht voran, danach schlägt der Läufer auf der langen Diagonale durch.","Turm schlägt auf e1 – Auftakt zum erzwungenen Matt."],"en":["Give up material to remove the crucial defender — mate is forced.","The rook clears the way, then the bishop strikes on the long diagonal.","Rook takes on e1 — the prelude to forced mate."],"hr":["Žrtvuj materijal da ukloniš ključnog branitelja — mat je prisilan.","Top krči put, a zatim lovac udara po dugoj dijagonali.","Top uzima na e1 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.096' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Beseitige den Verteidiger und ein erzwungenes Matt steht bereit.","Der Turm leitet ein, der Springer und die Dame vollenden den Angriff.","Turm schlägt auf e2 – Beginn der erzwungenen Mattführung."],"en":["Eliminate the defender and a forced mate is waiting.","The rook opens, then the knight and queen complete the attack.","Rook takes on e2 — beginning the forced mating sequence."],"hr":["Ukloni branitelja i prisilni mat je tu.","Top otvara, a skakač i dama dovršavaju napad.","Top uzima na e2 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.097' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidendes Material durch Ablenkung des Verteidigers.","Der Springer schlägt zuerst zu, dann dringt die Dame entscheidend ein.","Springer schlägt auf c3 – Beginn der gewinnenden Kombination."],"en":["A combination wins decisive material by removing the defender.","The knight strikes first, then the queen breaks through decisively.","Knight takes on c3 — the start of the winning combination."],"hr":["Kombinacija osvaja odlučujući materijal uklanjanjem branitelja.","Skakač prvi udara, a zatim dama presudno prodire.","Skakač uzima na c3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.098' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Räume den Verteidiger weg und ein erzwungenes Matt erscheint.","Der Läufer beseitigt einen Wächter, dann brechen Dame und Turm durch.","Läufer schlägt auf f4 – Auftakt zum erzwungenen Matt."],"en":["Clear away the defender and a forced mate appears.","The bishop removes a guard, then queen and rook break through.","Bishop takes on f4 — the prelude to forced mate."],"hr":["Ukloni branitelja i pojavljuje se prisilni mat.","Lovac uklanja čuvara, a zatim dama i top probijaju.","Lovac uzima na f4 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.099' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Verteidiger werden Schritt für Schritt entfernt, bis das Matt erzwungen ist.","Die Dame leitet ein, danach geben Springer und Läufer den entscheidenden Stoß.","Dame nach a5 – Beginn der erzwungenen Mattjagd."],"en":["The defenders are peeled away until mate is forced.","The queen leads, then knight and bishop deliver the decisive blow.","Queen to a5 — the start of the forced mating hunt."],"hr":["Branitelji se uklanjaju jedan po jedan dok mat ne postane prisilan.","Dama započinje, a zatim skakač i lovac zadaju odlučujući udarac.","Dama na a5 — početak prisilne matne hajke."]}', HintsVersion=1 WHERE LineId LIKE '%:003.100' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit, nachdem die Verteidigung beseitigt ist.","Ein Turm schwenkt zum Flügel, die Dame opfert sich für den Rundumschlag.","Turm nach a4 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is ready once the defence is removed.","A rook swings to the flank while the queen sacrifices to wrap it up.","Rook to a4 — the prelude to forced mate."],"hr":["Prisilni mat je spreman čim se ukloni obrana.","Top se prebacuje na krilo dok se dama žrtvuje za završnicu.","Top na a4 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.101' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Opfere, um die Deckung des Königs zu sprengen – Matt ist erzwungen.","Ein Turm beginnt das Opfer, dann setzen Läufer und Dame den König matt.","Turm schlägt auf e7 – Beginn der erzwungenen Mattkombination."],"en":["Sacrifice to strip the king''s cover — mate is forced.","A rook starts the offer, then bishop and queen finish the king.","Rook takes on e7 — the start of the forced mating combination."],"hr":["Žrtvuj da skineš kraljev zaklon — mat je prisilan.","Top započinje žrtvu, a zatim lovac i dama matiraju kralja.","Top uzima na e7 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.102' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke die Verteidigung ab und ein erzwungenes Matt taucht auf.","Der Turm opfert sich, dann liefern Springer und Dame den Mattangriff.","Turm schlägt auf e4 – Beginn der erzwungenen Mattführung."],"en":["Deflect the defence and a forced mate appears.","The rook sacrifices itself, then knight and queen deliver mate.","Rook takes on e4 — beginning the forced mating sequence."],"hr":["Odvuci obranu i pojavljuje se prisilni mat.","Top se žrtvuje, a zatim skakač i dama zadaju matni napad.","Top uzima na e4 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.103' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Entferne die Verteidiger nacheinander und ein erzwungenes Matt folgt.","Die Dame schlägt zuerst, dann öffnen Springer und Läufer den Weg zum König.","Dame schlägt auf f4 – Auftakt zur erzwungenen Mattkombination."],"en":["Remove the defenders one by one and a forced mate follows.","The queen strikes first, then knight and bishop open the path to the king.","Queen takes on f4 — the prelude to the forced mating combination."],"hr":["Ukloni branitelje jednog po jednog i slijedi prisilni mat.","Dama prvo udara, a zatim skakač i lovac otvaraju put do kralja.","Dama uzima na f4 — uvod u prisilnu matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:003.104' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt bereit, sobald der Verteidiger weg ist.","Der Springer beginnt, dann reißen Turm und Dame die Königsstellung ein.","Springer schlägt auf f6 – Beginn der erzwungenen Mattjagd."],"en":["A forced mate is ready once the defender is gone.","The knight begins, then rook and queen tear down the king''s shelter.","Knight takes on f6 — the start of the forced mating hunt."],"hr":["Prisilni mat je spreman čim branitelj nestane.","Skakač započinje, a zatim top i dama ruše kraljev zaklon.","Skakač uzima na f6 — početak prisilne matne hajke."]}', HintsVersion=1 WHERE LineId LIKE '%:003.105' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzugsschlag verstellt die Verteidigung und führt zum erzwungenen Matt.","Der Läufer opfert sich, um eine entscheidende Linie zu unterbrechen.","Läufer schlägt auf g3 – Beginn der erzwungenen Mattführung."],"en":["An interfering blow blocks the defence and leads to forced mate.","The bishop sacrifices to cut a vital defensive line.","Bishop takes on g3 — beginning the forced mating sequence."],"hr":["Ometajući udarac blokira obranu i vodi u prisilni mat.","Lovac se žrtvuje da presiječe ključnu obrambenu liniju.","Lovac uzima na g3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.106' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Verstelle die Verteidigung mit einem Opfer – ein erzwungenes Matt folgt.","Der Läufer dringt ein und unterbricht die Deckung der ersten Reihe.","Läufer schlägt auf e1 – Auftakt zum erzwungenen Matt."],"en":["Block the defence with a sacrifice — a forced mate follows.","The bishop intrudes and interferes with the back-rank guard.","Bishop takes on e1 — the prelude to forced mate."],"hr":["Blokiraj obranu žrtvom — slijedi prisilni mat.","Lovac upada i presijeca obranu zadnjeg reda.","Lovac uzima na e1 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.107' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination mit Linienunterbrechung gewinnt entscheidendes Material.","Der Springer schlägt ein und stört das Zusammenspiel der Verteidiger.","Springer schlägt auf c6 – Beginn der gewinnenden Kombination."],"en":["A combination using interference wins decisive material.","The knight strikes in and disrupts the coordination of the defenders.","Knight takes on c6 — the start of the winning combination."],"hr":["Kombinacija s presijecanjem osvaja odlučujući materijal.","Skakač udara i remeti suradnju branitelja.","Skakač uzima na c6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.108' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauerndurchbruch sprengt die Deckung und erzwingt das Matt.","Ein vorgerückter Bauer unterbricht die Verteidigung, dann setzt die Dame matt.","Bauer nach d6 – Beginn der erzwungenen Mattkombination."],"en":["A pawn breakthrough cracks the cover and forces mate.","An advancing pawn interferes with the defence, then the queen mates.","Pawn to d6 — the start of the forced mating combination."],"hr":["Pješakov proboj razbija zaklon i prisiljava mat.","Napredujući pješak presijeca obranu, a zatim dama matira.","Pješak na d6 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.109' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Beseitige die Verteidiger nacheinander und ein erzwungenes Matt folgt.","Ein Turm opfert sich, dann reißen Springer und Dame den König heraus.","Turm schlägt auf e5 – Auftakt zum erzwungenen Matt."],"en":["Eliminate the defenders one by one and a forced mate follows.","A rook sacrifices itself, then knight and queen drag the king out.","Rook takes on e5 — the prelude to forced mate."],"hr":["Ukloni branitelje jednog po jednog i slijedi prisilni mat.","Top se žrtvuje, a zatim skakač i dama izvlače kralja.","Top uzima na e5 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.110' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination mit Linienunterbrechung gewinnt entscheidendes Material.","Der Springer schlägt zuerst und stört das Verteidigungsnetz.","Springer schlägt auf d8 – Beginn der gewinnenden Kombination."],"en":["A combination with interference wins decisive material.","The knight strikes first and disrupts the defensive web.","Knight takes on d8 — the start of the winning combination."],"hr":["Kombinacija s presijecanjem osvaja odlučujući materijal.","Skakač prvi udara i remeti obrambenu mrežu.","Skakač uzima na d8 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.111' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Verstelle die Verteidigung mit einem Opfer – ein erzwungenes Matt erscheint.","Der Läufer beginnt, dann brechen Dame und Türme zum König durch.","Läufer schlägt auf e5 – Beginn der erzwungenen Mattführung."],"en":["Interfere with the defence by a sacrifice — a forced mate appears.","The bishop begins, then queen and rooks break through to the king.","Bishop takes on e5 — beginning the forced mating sequence."],"hr":["Presijeci obranu žrtvom — pojavljuje se prisilni mat.","Lovac započinje, a zatim dama i topovi probijaju do kralja.","Lovac uzima na e5 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.112' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer unterbricht die Verteidigung und ein erzwungenes Matt folgt.","Ein Turm lockt einen Verteidiger auf eine störende Linie, dann schlägt die Dame zu.","Turm schlägt auf c6 – Auftakt zum erzwungenen Matt."],"en":["A sacrifice interferes with the defence and a forced mate follows.","A rook lures a defender onto a blocking line, then the queen strikes.","Rook takes on c6 — the prelude to forced mate."],"hr":["Žrtva presijeca obranu i slijedi prisilni mat.","Top mami branitelja na ometajuću liniju, a zatim dama udara.","Top uzima na c6 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.113' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Opfere, um die Verteidigung zu verstellen – das Matt ist erzwungen.","Der Läufer opfert sich, dann unterbricht die Dame die Deckung entscheidend.","Läufer schlägt auf c7 – Beginn der erzwungenen Mattkombination."],"en":["Sacrifice to interfere with the defence — mate is forced.","The bishop sacrifices, then the queen cuts the defence decisively.","Bishop takes on c7 — the start of the forced mating combination."],"hr":["Žrtvuj da presiječeš obranu — mat je prisilan.","Lovac se žrtvuje, a zatim dama presudno presijeca obranu.","Lovac uzima na c7 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.114' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer lockt die Verteidigung weg und erzwingt das Matt.","Der Springer beginnt das Opfer, dann setzt die Dame den König unter Feuer.","Springer schlägt auf f3 – Beginn der erzwungenen Mattführung."],"en":["A knight sacrifice drags the defence away and forces mate.","The knight starts the offer, then the queen puts the king under fire.","Knight takes on f3 — beginning the forced mating sequence."],"hr":["Žrtva skakača odvlači obranu i prisiljava mat.","Skakač započinje žrtvu, a zatim dama stavlja kralja pod vatru.","Skakač uzima na f3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.115' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Sperre die Fluchtfelder des Königs ein und ein erzwungenes Matt folgt.","Ein Turm opfert sich, um ein Feld zu blockieren, dann schließt die Dame das Netz.","Turm nach e7 – Auftakt zum erzwungenen Matt."],"en":["Block the king''s escape squares and a forced mate follows.","A rook sacrifices to block a flight square, then the queen seals the net.","Rook to e7 — the prelude to forced mate."],"hr":["Zatvori kralju polja za bijeg i slijedi prisilni mat.","Top se žrtvuje da blokira polje bijega, a zatim dama zatvara mrežu.","Top na e7 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.116' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß blockiert ein Feld und gewinnt durch Ablenkung entscheidend.","Ein Bauer verstellt die Deckung, dann erzwingt der Damentausch den Gewinn.","Bauer nach b4 – Beginn der gewinnenden Kombination."],"en":["A pawn push blocks a square and wins decisively by deflection.","A pawn blocks the defence, then a queen trade forces the win.","Pawn to b4 — the start of the winning combination."],"hr":["Pješakov potez blokira polje i odlučujuće dobiva odvlačenjem.","Pješak blokira obranu, a zatim razmjena dama prisiljava dobitak.","Pješak na b4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.117' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer blockiert ein Schlüsselfeld und ein erzwungenes Matt erscheint.","Der Springer opfert sich, dann hämmern Dame und Turm den König nieder.","Springer schlägt auf e2 – Beginn der erzwungenen Mattführung."],"en":["A sacrifice blocks a key square and a forced mate appears.","The knight sacrifices, then queen and rook hammer the king down.","Knight takes on e2 — beginning the forced mating sequence."],"hr":["Žrtva blokira ključno polje i pojavljuje se prisilni mat.","Skakač se žrtvuje, a zatim dama i top obaraju kralja.","Skakač uzima na e2 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.118' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Opfere, um ein Fluchtfeld zu blockieren – das Matt ist erzwungen.","Der Turm opfert sich, dann verstellt der Läufer und der Springer setzt matt.","Turm schlägt auf e5 – Beginn der erzwungenen Mattkombination."],"en":["Sacrifice to block a flight square — mate is forced.","The rook sacrifices, then the bishop blocks and the knight mates.","Rook takes on e5 — the start of the forced mating combination."],"hr":["Žrtvuj da blokiraš polje bijega — mat je prisilan.","Top se žrtvuje, zatim lovac blokira, a skakač matira.","Top uzima na e5 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.119' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge von Opfern engt den König ein und erzwingt das Matt.","Der Springer beginnt, dann blockieren und treiben die Figuren den König.","Springer schlägt auf e1 – Beginn der erzwungenen Mattführung."],"en":["A series of sacrifices boxes in the king and forces mate.","The knight begins, then the pieces block and herd the king.","Knight takes on e1 — beginning the forced mating sequence."],"hr":["Niz žrtava zatvara kralja i prisiljava mat.","Skakač započinje, a zatim figure blokiraju i tjeraju kralja.","Skakač uzima na e1 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.120' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Opfere, um die Fluchtfelder des Königs zu blockieren – Matt ist erzwungen.","Ein Turm leitet ein, dann blockiert eine Figur und der andere Turm setzt matt.","Turm nach d7 – Auftakt zur erzwungenen Mattkombination."],"en":["Sacrifice to block the king''s escape squares — mate is forced.","A rook leads, then a piece blocks and the other rook mates.","Rook to d7 — the prelude to the forced mating combination."],"hr":["Žrtvuj da blokiraš kralju polja bijega — mat je prisilan.","Top započinje, zatim figura blokira, a drugi top matira.","Top na d7 — uvod u prisilnu matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:003.121' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer blockiert ein Feld und ein erzwungenes Matt liegt bereit.","Der Turm opfert sich, dann verstellt der Läufer und die Dame schlägt durch.","Turm schlägt auf f4 – Beginn der erzwungenen Mattführung."],"en":["A sacrifice blocks a square and a forced mate is ready.","The rook sacrifices, then the bishop blocks and the queen breaks through.","Rook takes on f4 — beginning the forced mating sequence."],"hr":["Žrtva blokira polje i prisilni mat je spreman.","Top se žrtvuje, zatim lovac blokira, a dama probija.","Top uzima na f4 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.122' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination beseitigt einen Verteidiger und gewinnt entscheidendes Material.","Die Dame schlägt zuerst, dann sammelt sie Schritt für Schritt die Beute ein.","Dame schlägt auf c3 – Beginn der gewinnenden Kombination."],"en":["A combination removes a defender and wins decisive material.","The queen strikes first, then mops up the spoils step by step.","Queen takes on c3 — the start of the winning combination."],"hr":["Kombinacija uklanja branitelja i osvaja odlučujući materijal.","Dama prvo udara, a zatim korak po korak skuplja plijen.","Dama uzima na c3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.123' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König im Eck ist verwundbar – ein forciertes Matt steckt in der Stellung.","Räume die Diagonale zum Königsflügel und lass deine Schwerfiguren durch.","Läufer schlägt auf f3 – Beginn der Mattführung."],"en":["The cornered king is exposed — a forced mate is hidden here.","Clear the diagonal toward the king and let your heavy pieces in.","Bishop takes on f3 — starting the mating attack."],"hr":["Kralj u kutu je ranjiv — skriveni mat na potezu te čeka.","Otvori dijagonalu prema kraljevom krilu i pusti teške figure.","Lovac uzima na f3 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.124' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Königsschutz lässt sich zertrümmern – ein erzwungenes Matt wartet.","Ein Bauer vor dem König ist der Schlüssel; reiße die Stellung auf.","Läufer schlägt auf f6 – Auftakt zum Mattangriff."],"en":["The king''s cover can be shattered — a forced mate awaits.","A pawn shielding the king is the key; tear the position open.","Bishop takes on f6 — launching the mating attack."],"hr":["Zaštita kralja se može razbiti — slijedi prisilni mat.","Pješak ispred kralja je ključ; otvori poziciju.","Lovac uzima na f6 — početak matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:003.125' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Verteidiger steht im Weg – beseitige ihn und das Matt ist da.","Opfere, um den wichtigsten Deckungsstein abzulenken.","Läufer nach f4 – leitet die Mattkombination ein."],"en":["A defender stands in the way — remove it and mate follows.","Sacrifice to lure away the key defending piece.","Bishop to f4 — beginning the mating combination."],"hr":["Branitelj stoji na putu — ukloni ga i slijedi mat.","Žrtvuj kako bi odvukao ključnu obrambenu figuru.","Lovac na f4 — pokreće matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:003.126' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauer hält die Linie geschlossen – sprenge sie und es mattet.","Lock den Bauern weg und öffne die Linie für deine Türme.","Dame schlägt auf d5 – erster Schritt der Mattführung."],"en":["A pawn keeps the file closed — break it open and mate is on.","Lure the pawn away and open the file for your rooks.","Queen takes on d5 — the first step of the mating sequence."],"hr":["Pješak drži liniju zatvorenom — razbij je i slijedi mat.","Odvuci pješaka i otvori liniju za topove.","Dama uzima na d5 — prvi korak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.127' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gegen die Königsstellung gewinnt entscheidend Material.","Reiße den Schutzbauern weg und nutze die offene Linie.","Turm schlägt auf b3 – Auftakt der entscheidenden Kombination."],"en":["A blow against the king''s shelter wins material decisively.","Tear away the shielding pawn and exploit the open file.","Rook takes on b3 — starting the winning combination."],"hr":["Udarac na zaštitu kralja osvaja odlučujući materijal.","Ukloni zaštitnog pješaka i iskoristi otvorenu liniju.","Top uzima na b3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:003.128' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damentausch räumt den Weg für einen materialgewinnenden Plan.","Lenke die feindliche Dame ab, dann schnappt sich dein Turm Beute.","Dame schlägt auf a1 – Beginn der gewinnenden Folge."],"en":["A queen trade clears the path to a material-winning idea.","Pull the enemy queen away, then your rook grabs the loot.","Queen takes on a1 — starting the winning sequence."],"hr":["Zamjena dama otvara put planu za dobitak materijala.","Odvuci protivničku damu, a tvoj top pokupi plijen.","Dama uzima na a1 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:004.003' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug stellt einen Doppelangriff auf – Material fällt.","Stell deinen Springer so, dass er gleich zwei Ziele bedroht.","Springer nach g2 – gewinnt mit Doppelangriff Material."],"en":["A quiet move sets up a double attack — material drops.","Reposition your knight to hit two targets at once.","Knight to g2 — winning material by a double attack."],"hr":["Tihi potez priprema dvostruki napad — materijal pada.","Premjesti skakača da napadne dvije mete odjednom.","Skakač na g2 — dvostrukim napadom osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.004' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsopfer ebnet den Weg zu einem Doppelangriff.","Dein Läufer stört zuerst, dann schlägt die Dame doppelt zu.","Läufer nach b8 – leitet den materialgewinnenden Doppelschlag ein."],"en":["A deflecting sacrifice paves the way to a double attack.","Your bishop interferes first, then the queen strikes twice.","Bishop to b8 — beginning the material-winning double blow."],"hr":["Žrtva za odvlačenje priprema dvostruki napad.","Prvo smeta lovac, zatim dama udara na dvije strane.","Lovac na b8 — pokreće dvostruki udarac za dobitak."]}', HintsVersion=1 WHERE LineId LIKE '%:004.005' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorbereitender Zug schafft einen materialgewinnenden Doppelangriff.","Bring deinen Springer in eine Gabelstellung gegen zwei Ziele.","Springer nach d4 – Auftakt zum gewinnenden Doppelangriff."],"en":["A preparatory move creates a material-winning double attack.","Bring your knight to a forking post against two targets.","Knight to d4 — starting the winning double attack."],"hr":["Pripremni potez stvara dvostruki napad za dobitak.","Dovedi skakača na mjesto s kojeg napada dvije mete.","Skakač na d4 — početak dobitnog dvostrukog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:004.006' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Bringe den König in Sicherheit und aktiviere zugleich einen Turm.","Die Rochade verbindet Königssicherheit mit einer drohenden Kombination.","König rochiert lang – Auftakt zur materialgewinnenden Folge."],"en":["Tuck the king away and activate a rook in one move.","Castling links king safety with a looming combination.","King castles queenside — starting the material-winning sequence."],"hr":["Skloni kralja i istodobno aktiviraj top.","Rokada spaja sigurnost kralja s prijetećom kombinacijom.","Kralj rokira na damino krilo — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:004.008' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schnapp dir die Figur und bereite zugleich einen Doppelangriff vor.","Dein Läufer holt Material, dann kommt der König ins Spiel.","Läufer schlägt auf a1 – Beginn der gewinnenden Kombination."],"en":["Grab the piece and prepare a double attack at the same time.","Your bishop wins material, then the king joins the action.","Bishop takes on a1 — starting the winning combination."],"hr":["Uzmi figuru i istodobno pripremi dvostruki napad.","Lovac osvaja materijal, zatim se uključuje kralj.","Lovac uzima na a1 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.009' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer-Vorstoß bereitet einen entscheidenden Doppelangriff vor.","Stell deinen Springer auf ein Feld mit Gabeldrohung.","Springer nach f3 – leitet den materialgewinnenden Doppelangriff ein."],"en":["A knight thrust prepares a decisive double attack.","Place your knight on a square that threatens a fork.","Knight to f3 — beginning the material-winning double attack."],"hr":["Prodor skakača priprema odlučujući dvostruki napad.","Postavi skakača na polje s prijetnjom viljuške.","Skakač na f3 — pokreće dvostruki napad za dobitak."]}', HintsVersion=1 WHERE LineId LIKE '%:004.010' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Köderzug lenkt eine Figur in einen Doppelangriff.","Dein Läufer zieht zurück und stellt eine Falle.","Läufer nach e7 – Auftakt der materialgewinnenden Folge."],"en":["A luring move drags a piece into a double attack.","Your bishop steps back and sets a trap.","Bishop to e7 — starting the material-winning sequence."],"hr":["Mamac potezom uvlačiš figuru u dvostruki napad.","Tvoj lovac se povlači i postavlja zamku.","Lovac na e7 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:004.011' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Abfolge von Schlägen endet in einem materialgewinnenden Doppelangriff.","Tausche zuerst ab, dann erzwingt dein Springer die Gabel.","Springer schlägt auf c4 – leitet den Materialgewinn ein."],"en":["A run of captures ends in a material-winning double attack.","Trade first, then your knight forces the fork.","Knight takes on c4 — beginning the material gain."],"hr":["Niz uzimanja završava dvostrukim napadom za dobitak.","Prvo zamijeni, zatim skakač forsira viljušku.","Skakač uzima na c4 — početak dobitka materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:004.012' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt eine Figur ins Schussfeld eines Doppelangriffs.","Räume den Verteidiger weg, dann gabelt deine Dame zwei Ziele.","Läufer schlägt auf b7 – Auftakt zum gewinnenden Doppelangriff."],"en":["A sacrifice lures a piece into the line of a double attack.","Remove the defender, then your queen forks two targets.","Bishop takes on b7 — starting the winning double attack."],"hr":["Žrtva uvlači figuru na udar dvostrukog napada.","Ukloni branitelja, zatim dama napada dvije mete.","Lovac uzima na b7 — početak dobitnog dvostrukog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:004.013' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Köderschlag bereitet einen materialgewinnenden Doppelangriff vor.","Lenke die Figur weg, dann stößt ein Bauer doppelt drohend vor.","Läufer schlägt auf c5 – leitet die gewinnende Folge ein."],"en":["A luring capture prepares a material-winning double attack.","Decoy the piece, then a pawn lunges with a double threat.","Bishop takes on c5 — beginning the winning sequence."],"hr":["Mamac uzimanjem priprema dvostruki napad za dobitak.","Odvuci figuru, zatim pješak prodire s dvostrukom prijetnjom.","Lovac uzima na c5 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:004.014' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt eine Figur in einen materialgewinnenden Doppelangriff.","Zieh den Verteidiger heran, dann schlägt deine Dame doppelt zu.","Turm schlägt auf a8 – Auftakt zum gewinnenden Doppelangriff."],"en":["A sacrifice lures a piece into a material-winning double attack.","Draw the defender in, then your queen strikes on two fronts.","Rook takes on a8 — starting the winning double attack."],"hr":["Žrtva uvlači figuru u dvostruki napad za dobitak.","Privuci branitelja, zatim dama udara s dvije strane.","Top uzima na a8 — početak dobitnog dvostrukog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:004.015' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt den König und schafft einen Doppelangriff.","Zieh den König heraus, dann gabelt dein Springer zwei Ziele.","Läufer schlägt auf f7 – leitet den materialgewinnenden Doppelangriff ein."],"en":["A sacrifice lures the king and sets up a double attack.","Pull the king out, then your knight forks two targets.","Bishop takes on f7 — beginning the material-winning double attack."],"hr":["Žrtva izvlači kralja i stvara dvostruki napad.","Izvuci kralja, zatim skakač napada dvije mete.","Lovac uzima na f7 — pokreće dvostruki napad za dobitak."]}', HintsVersion=1 WHERE LineId LIKE '%:004.016' AND BookFileName='chessable-u5-21646.pgn';
