UPDATE BookPuzzles SET HintsJson='{"de":["Ein Köderopfer leitet einen erzwungenen Mattangriff ein.","Lock den Verteidiger weg, dann gabelt deine Dame mit Mattdrohung.","Läufer schlägt auf e7 – Auftakt zur Mattführung."],"en":["A luring sacrifice opens a forced mating attack.","Decoy the defender, then your queen forks with mate looming.","Bishop takes on e7 — starting the mating attack."],"hr":["Mamac žrtvom pokreće prisilni matni napad.","Odvuci branitelja, zatim dama napada uz prijetnju mata.","Lovac uzima na e7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.018' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gegen den König gewinnt entscheidend Material.","Dein Turm dringt am Königsflügel ein und stellt einen Doppelangriff.","Turm schlägt auf h7 – beginnt den entscheidenden Angriff."],"en":["A blow against the king wins material decisively.","Your rook crashes in on the king''s flank to set a double attack.","Rook takes on h7 — beginning the decisive attack."],"hr":["Udarac na kralja osvaja odlučujući materijal.","Tvoj top upada na kraljevo krilo i sprema dvostruki napad.","Top uzima na h7 — početak odlučujućeg napada."]}', HintsVersion=1 WHERE LineId LIKE '%:004.019' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Opferfolge mündet in einen materialgewinnenden Doppelangriff.","Räume die Verteidiger weg, dann gabelt deine Dame zwei Ziele.","Turm schlägt auf b1 – Auftakt der gewinnenden Kombination."],"en":["A string of sacrifices leads to a material-winning double attack.","Clear the defenders, then your queen forks two targets.","Rook takes on b1 — starting the winning combination."],"hr":["Niz žrtava vodi do dvostrukog napada za dobitak.","Ukloni branitelje, zatim dama napada dvije mete.","Top uzima na b1 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.020' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Köderschlag mit Fesselung bereitet einen Doppelangriff vor.","Lock die Figur in eine Fesselung, dann gabelt dein Springer.","Dame schlägt auf d3 – Auftakt der materialgewinnenden Folge."],"en":["A luring capture using a pin prepares a double attack.","Draw the piece into a pin, then your knight forks.","Queen takes on d3 — starting the material-winning sequence."],"hr":["Mamac uzimanjem uz vezivanje priprema dvostruki napad.","Uvuci figuru u vezu, zatim skakač izvodi viljušku.","Dama uzima na d3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:004.021' AND BookFileName='chessable-u5-21646.pgn';
