UPDATE BookPuzzles SET HintsJson='{"de":["Eine Opferfolge mit Unterverwandlung gewinnt entscheidend Material.","Räume die Verteidiger weg, dann gabelt ein neuer Springer.","Turm nach f8 – Auftakt der gewinnenden Kombination."],"en":["A sacrificial run with underpromotion wins material decisively.","Clear the defenders, then a new knight delivers the fork.","Rook to f8 — starting the winning combination."],"hr":["Niz žrtava s podpretvorbom osvaja odlučujući materijal.","Ukloni branitelje, zatim novi skakač izvodi viljušku.","Top na f8 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.023' AND BookFileName='chessable-u5-21646.pgn';
