UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag öffnet den Weg zu einem zweifachen Treffer.","Dein Springer kommt in den Angriff, sobald ein Bauer beseitigt ist.","Dame schlägt auf d5 – leitet den materialgewinnenden Zug ein."],"en":["A capture opens the way to a double strike.","Your knight swings in once a pawn is cleared.","Queen takes on d5 — opening the material-winning sequence."],"hr":["Uzimanje otvara put do dvostrukog udarca.","Tvoj skakač uskače čim se makne pješak.","Dama uzima na d5 — pokreće niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.030' AND BookFileName='chessable-u5-21646.pgn';
