UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff gewinnt entscheidend Material.","Deine Dame schlägt zu und greift zwei Ziele gleichzeitig an.","Dame schlägt auf e5 – gewinnt entscheidend Material."],"en":["A double attack wins decisive material.","Your queen captures and hits two targets at once.","Queen takes on e5 — winning decisive material."],"hr":["Dvostruki napad osvaja odlučujući materijal.","Tvoja dama uzima i napada dva cilja odjednom.","Dama uzima na e5 — osvaja odlučujući materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.047' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit.","Jage den König mit Turm und Läufer ins Mattnetz.","Turm schlägt auf d8 – beginnt das erzwungene Matt."],"en":["A forced mate is available.","Hunt the king into the net with rook and bishop.","Rook takes on d8 — beginning the forced mate."],"hr":["Prisilni mat je na raspolaganju.","Potjeraj kralja u matnu mrežu topom i lovcem.","Top uzima na d8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.048' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt weg und ein Doppelangriff gewinnt Material.","Erst die Dame ablenken, dann gabelt der Springer.","Dame schlägt auf b5 – startet die materialgewinnende Kombination."],"en":["A sacrifice deflects and a double attack wins material.","Deflect the queen first, then the knight forks.","Queen takes on b5 — starting the material-winning combination."],"hr":["Žrtva odvlači i dvostruki napad osvaja materijal.","Prvo odvuci damu, pa skakač napravi vilicu.","Dama uzima na b5 — počinje kombinacija koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.049' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Treibe den König und ein Doppelangriff gewinnt Material.","Deine Dame jagt mit, bis sie zwei Ziele gleichzeitig fasst.","Bauer nach g3 – leitet die materialgewinnende Jagd ein."],"en":["Chase the king and a double attack wins material.","Your queen joins the hunt until she grabs two targets.","Pawn to g3 — beginning the material-winning chase."],"hr":["Potjeraj kralja i dvostruki napad osvaja materijal.","Tvoja dama lovi dok ne uhvati dva cilja odjednom.","Pješak na g3 — pokreće potjeru koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.050' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Treibe den König und ein Doppelangriff gewinnt Material.","Dame und Springer jagen gemeinsam, bis die Gabel sitzt.","Dame schlägt auf g7 – startet die materialgewinnende Jagd."],"en":["Chase the king and a double attack wins material.","Queen and knight hunt together until the fork lands.","Queen takes on g7 — launching the material-winning chase."],"hr":["Potjeraj kralja i dvostruki napad osvaja materijal.","Dama i skakač love zajedno dok vilica ne sjedne.","Dama uzima na g7 — pokreće potjeru koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.051' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Treibe die Figuren und ein Doppelangriff gewinnt Material.","Dein Läufer setzt den entscheidenden Doppelschlag an.","Läufer schlägt auf f7 – startet die materialgewinnende Jagd."],"en":["Chase the pieces and a double attack wins material.","Your bishop sets up the decisive double blow.","Bishop takes on f7 — launching the material-winning chase."],"hr":["Potjeraj figure i dvostruki napad osvaja materijal.","Tvoj lovac priprema odlučujući dvostruki udarac.","Lovac uzima na f7 — pokreće potjeru koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.052' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Treibe den König und ein Doppelangriff gewinnt Material.","Deine Dame schwingt herum, bis sie zwei Ziele fasst.","Dame nach a3 – startet die materialgewinnende Jagd."],"en":["Chase the king and a double attack wins material.","Your queen swings around until she grabs two targets.","Queen to a3 — launching the material-winning chase."],"hr":["Potjeraj kralja i dvostruki napad osvaja materijal.","Tvoja dama kruži dok ne uhvati dva cilja.","Dama na a3 — pokreće potjeru koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.053' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Treibe die Figuren und ein Doppelangriff gewinnt Material.","Deine Dame jagt, bis sie zwei Ziele gleichzeitig anvisiert.","Dame nach g3 – startet die materialgewinnende Jagd."],"en":["Chase the pieces and a double attack wins material.","Your queen hunts until she eyes two targets at once.","Queen to g3 — launching the material-winning chase."],"hr":["Potjeraj figure i dvostruki napad osvaja materijal.","Tvoja dama lovi dok ne nacilja dva cilja odjednom.","Dama na g3 — pokreće potjeru koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.054' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff gewinnt entscheidend Material.","Dein Springer dringt ein und visiert zwei Ziele an.","Springer schlägt auf d7 – beginnt die materialgewinnende Kombination."],"en":["A double attack wins decisive material.","Your knight invades and eyes two targets.","Knight takes on d7 — starting the material-winning combination."],"hr":["Dvostruki napad osvaja odlučujući materijal.","Tvoj skakač prodire i cilja dva cilja.","Skakač uzima na d7 — počinje kombinacija koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.055' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff gewinnt entscheidend Material.","Dein Springer dringt ein und gabelt zwei Ziele.","Springer schlägt auf e2 – startet die materialgewinnende Kombination."],"en":["A double attack wins decisive material.","Your knight invades and forks two targets.","Knight takes on e2 — launching the material-winning combination."],"hr":["Dvostruki napad osvaja odlučujući materijal.","Tvoj skakač prodire i radi vilicu na dva cilja.","Skakač uzima na e2 — pokreće kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.056' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff gewinnt entscheidend Material.","Dein Springer springt auf ein Feld, das gleich zwei Ziele bedroht.","Springer nach c5 – gewinnt entscheidend Material."],"en":["A double attack wins decisive material.","Your knight lands on a square threatening two targets at once.","Knight to c5 — winning decisive material."],"hr":["Dvostruki napad osvaja odlučujući materijal.","Tvoj skakač skače na polje koje prijeti dvama ciljevima.","Skakač na c5 — osvaja odlučujući materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.057' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff gewinnt eine Figur.","Dein Springer manövriert, um zwei Ziele zugleich zu treffen.","Springer nach h4 – beginnt die figurengewinnende Kombination."],"en":["A double attack wins a piece.","Your knight maneuvers to hit two targets at once.","Knight to h4 — starting the piece-winning combination."],"hr":["Dvostruki napad osvaja figuru.","Tvoj skakač manevrira da pogodi dva cilja odjednom.","Skakač na h4 — počinje kombinacija koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:004.058' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine kleine Aktion räumt ein Feld – danach trifft ein Doppelangriff zwei Ziele.","Erst muss der Springer verschwinden, dann übernimmt die Dame die Doppeldrohung.","Springer schlägt auf c3 – nach dem Rücknehmen gewinnt die Dame mit einem Doppelangriff Material."],"en":["A small clearance opens a square, and a double attack then strikes two targets.","First the knight clears the way, then the queen delivers the fork.","Knight takes on c3 — after the recapture the queen wins material with a double attack."],"hr":["Mali potez oslobađa polje, a dvostruki napad zatim pogađa dva cilja.","Najprije skakač mora otići, potom dama preuzima dvostruku prijetnju.","Skakač uzima na c3 — nakon uzvraćanja dama dvostrukim napadom osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.059' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Tempogewinn räumt den Weg für einen materialgewinnenden Doppelangriff.","Die Dame zieht zunächst weg, dann schlägt der Springer mit Gabel zu.","Dame nach g5 – das leitet die Kombination ein, die mit einer Springergabel Material gewinnt."],"en":["A clearing move opens the way for a material-winning double attack.","The queen steps aside first, then the knight forks with effect.","Queen to g5 — this starts the combination that wins material via a knight fork."],"hr":["Potez s tempom oslobađa put za dvostruki napad koji osvaja materijal.","Dama se najprije miče, zatim skakač udara viljuškom.","Dama na g5 — to započinje kombinaciju koja skakačevom viljuškom osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.060' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Erst wird eine Linie geöffnet, dann gewinnt ein Doppelangriff Material.","Der Springer verschwindet mit Tempo, danach greift die Dame doppelt an.","Springer schlägt auf d7 – das öffnet die Linie für den entscheidenden Damen-Doppelangriff."],"en":["First a line is opened, then a double attack wins material.","The knight vanishes with tempo, after which the queen attacks two points.","Knight takes on d7 — clearing the line for the decisive queen double attack."],"hr":["Najprije se otvara linija, potom dvostruki napad osvaja materijal.","Skakač nestaje s tempom, zatim dama napada dva cilja.","Skakač uzima na d7 — otvara liniju za odlučujući damin dvostruki napad."]}', HintsVersion=1 WHERE LineId LIKE '%:004.061' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Linienöffner bereitet einen Doppelangriff vor, der Material einbringt.","Der Turm räumt eine Linie, danach trifft die Dame zwei Ziele.","Turm nach c5 – das öffnet die Linie für die folgende Doppeldrohung der Dame."],"en":["A line-clearing move sets up a double attack that wins material.","The rook vacates a line, then the queen hits two targets.","Rook to c5 — opening the line for the queen''s coming double threat."],"hr":["Otvaranje linije priprema dvostruki napad koji donosi materijal.","Top oslobađa liniju, zatim dama pogađa dva cilja.","Top na c5 — otvara liniju za nadolazeću daminu dvostruku prijetnju."]}', HintsVersion=1 WHERE LineId LIKE '%:004.062' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß öffnet Linien für eine materialgewinnende Kombination.","Der Bauer sprengt das Zentrum auf, danach arbeiten Springer und Dame zusammen.","Bauer nach d5 – das leitet die Linienöffnung ein, die schließlich Material gewinnt."],"en":["A pawn break opens lines for a material-winning combination.","The pawn cracks the centre, then knight and queen combine.","Pawn to d5 — starting the line-opening that ultimately wins material."],"hr":["Pješakov prodor otvara linije za kombinaciju koja osvaja materijal.","Pješak razbija centar, zatim skakač i dama surađuju.","Pješak na d5 — započinje otvaranje linija koje naposljetku osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.063' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt den König heraus und mündet in einen materialgewinnenden Doppelschlag.","Die Dame leitet ein, dann reißen die Leichtfiguren die Verteidigung ein.","Dame nach h5 – Auftakt der Kombination, die durch Anlocken Material gewinnt."],"en":["A sacrifice lures the king out and ends in a material-winning double blow.","The queen sets it up, then the minor pieces tear down the defence.","Queen to h5 — the start of the combination that wins material by luring."],"hr":["Žrtva izvlači kralja i završava dvostrukim udarcem koji osvaja materijal.","Dama započinje, zatim lake figure ruše obranu.","Dama na h5 — početak kombinacije koja mamljenjem osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.064' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Anlock-Manöver gewinnt durch eine anschließende Doppeldrohung Material.","Der Springer beginnt, lockt die Dame und führt zum Materialgewinn.","Springer nach d6 – das lockt die Dame und leitet den Materialgewinn ein."],"en":["A luring manoeuvre wins material through a following double threat.","The knight starts, draws the queen and brings in the material.","Knight to d6 — luring the queen and beginning the material win."],"hr":["Manevar mamljenja dvostrukom prijetnjom osvaja materijal.","Skakač počinje, mami damu i vodi do dobitka materijala.","Skakač na d6 — mami damu i započinje dobitak materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:004.065' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abtausch lockt die Figur heran, dann gewinnt eine Gabel Material.","Erst tauscht der Läufer, danach gabelt der Springer.","Läufer schlägt auf d5 – das lockt und bereitet die materialgewinnende Springergabel vor."],"en":["A trade lures a piece in, then a fork wins material.","First the bishop exchanges, then the knight forks.","Bishop takes on d5 — luring, and preparing the material-winning knight fork."],"hr":["Zamjena mami figuru, zatim viljuška osvaja materijal.","Najprije lovac mijenja, potom skakač udara viljuškom.","Lovac uzima na d5 — mami i priprema skakačevu viljušku koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.066' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt eine Figur, danach gabelt der Springer zum Materialgewinn.","Zuerst wird die Verteidigung gelockt, dann schlägt der Springer doppelt zu.","Turm schlägt auf g1 – das Opfer lockt und führt zur materialgewinnenden Springergabel."],"en":["A sacrifice lures a piece, then a knight fork wins material.","First the defence is lured, then the knight strikes on two squares.","Rook takes on g1 — the sacrifice lures and leads to the material-winning knight fork."],"hr":["Žrtva mami figuru, zatim skakačeva viljuška osvaja materijal.","Najprije se mami obrana, potom skakač udara na dva polja.","Top uzima na g1 — žrtva mami i vodi do skakačeve viljuške koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.067' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Anlock-Opfer treibt den König heraus und gewinnt anschließend Material.","Die Dame opfert sich scheinbar, dann jagt sie zum Doppelangriff.","Dame nach d8 – Beginn der Kombination, die durch Anlocken Material gewinnt."],"en":["A luring sacrifice drives the king out and then wins material.","The queen appears to give herself up, then chases into a double attack.","Queen to d8 — the start of the combination that wins material by luring."],"hr":["Žrtva mamljenja izgoni kralja i potom osvaja materijal.","Dama se naizgled žrtvuje, zatim tjera u dvostruki napad.","Dama na d8 — početak kombinacije koja mamljenjem osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.068' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer zieht den König heraus und mündet in einen materialgewinnenden Doppelangriff.","Der Läufer schlägt ein, danach jagt der Springer König und Dame.","Läufer schlägt auf f7 – das lockt den König und leitet den Materialgewinn ein."],"en":["A bishop sacrifice pulls the king out and ends in a material-winning double attack.","The bishop strikes, then the knight chases king and queen.","Bishop takes on f7 — luring the king and starting the material win."],"hr":["Žrtva lovca izvlači kralja i završava dvostrukim napadom koji osvaja materijal.","Lovac udara, zatim skakač goni kralja i damu.","Lovac uzima na f7 — mami kralja i započinje dobitak materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:004.069' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt den König, dann gewinnt ein Damen-Doppelangriff Material.","Der Turm opfert sich, danach jagt die Dame König und Turm.","Turm schlägt auf f7 – das lockt den König und führt zum materialgewinnenden Doppelangriff."],"en":["A sacrifice lures the king, then a queen double attack wins material.","The rook gives itself up, then the queen chases king and rook.","Rook takes on f7 — luring the king and leading to the material-winning double attack."],"hr":["Žrtva mami kralja, zatim damin dvostruki napad osvaja materijal.","Top se žrtvuje, potom dama goni kralja i topa.","Top uzima na f7 — mami kralja i vodi do dvostrukog napada koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.070' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Dame jagt den König systematisch heran, bis ein Doppelangriff Material gewinnt.","Mit Schachs treibt die Dame den König ins Verderben.","Dame nach e3 – Beginn der Jagd, die den König ins materialverlierende Netz treibt."],"en":["The queen chases the king step by step until a double attack wins material.","With checks the queen drives the king to its doom.","Queen to e3 — starting the chase that herds the king into a material-losing net."],"hr":["Dama korak po korak goni kralja dok dvostruki napad ne osvoji materijal.","Šahovima dama tjera kralja u propast.","Dama na e3 — početak gonjenja koje kralja tjera u mrežu gubitka materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:004.071' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Reihe von Manövern lockt und gewinnt schließlich eine Figur.","Der Turm opfert sich, danach holt sich der Läufer das Material zurück.","Turm nach c2 – Auftakt der Kombination, die durch Anlocken und Zielsuche Material gewinnt."],"en":["A sequence of manoeuvres lures and finally wins a piece.","The rook gives itself up, then the bishop collects the material.","Rook to c2 — the start of the combination that wins material by luring and targeting."],"hr":["Niz manevara mami i naposljetku osvaja figuru.","Top se žrtvuje, zatim lovac skuplja materijal.","Top na c2 — početak kombinacije koja mamljenjem i ciljanjem osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.072' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver lockt die Verteidigung und gewinnt am Ende Material.","Der Springer beginnt, dann setzt die Dame zum Materialgewinn nach.","Springer nach d3 – Beginn der Kombination, die durch Anlocken Material gewinnt."],"en":["A knight manoeuvre lures the defence and ends up winning material.","The knight starts, then the queen follows up to win material.","Knight to d3 — the start of the combination that wins material by luring."],"hr":["Skakačev manevar mami obranu i naposljetku osvaja materijal.","Skakač počinje, zatim dama nastavlja do dobitka materijala.","Skakač na d3 — početak kombinacije koja mamljenjem osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.073' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt eine Figur, danach gewinnt eine Springergabel Material.","Der Läufer opfert sich, dann übernimmt der Springer mit einer Gabel.","Läufer schlägt auf g2 – das lockt und bereitet die materialgewinnende Springergabel vor."],"en":["A sacrifice lures a piece, then a knight fork wins material.","The bishop gives itself up, then the knight takes over with a fork.","Bishop takes on g2 — luring, and setting up the material-winning knight fork."],"hr":["Žrtva mami figuru, zatim skakačeva viljuška osvaja materijal.","Lovac se žrtvuje, potom skakač preuzima viljuškom.","Lovac uzima na g2 — mami i priprema skakačevu viljušku koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.074' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Turm jagt den König weg, danach gewinnt eine Gabel Material.","Erst wird der König vertrieben, dann gabelt der Springer.","Turm schlägt auf e5 – das jagt den König und leitet die materialgewinnende Springergabel ein."],"en":["The rook chases the king off, then a fork wins material.","First the king is driven away, then the knight forks.","Rook takes on e5 — chasing the king and starting the material-winning knight fork."],"hr":["Top goni kralja, zatim viljuška osvaja materijal.","Najprije se kralj otjera, potom skakač udara viljuškom.","Top uzima na e5 — goni kralja i započinje skakačevu viljušku koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.075' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springersprung jagt die Dame, danach gewinnt ein Doppelangriff Material.","Der Springer beginnt die Jagd, dann holt die Dame Material.","Springer nach c5 – Beginn der Kombination, die durch Jagd und Zielsuche Material gewinnt."],"en":["A knight leap chases the queen, then a double attack wins material.","The knight starts the chase, then the queen reaps the material.","Knight to c5 — the start of the combination that wins material by chasing and targeting."],"hr":["Skakačev skok goni damu, zatim dvostruki napad osvaja materijal.","Skakač počinje gonjenje, zatim dama uzima materijal.","Skakač na c5 — početak kombinacije koja gonjenjem i ciljanjem osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.076' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge von Opfern und Drohungen gewinnt am Ende Material.","Der Springer schlägt zuerst, danach arbeiten Läufer und Dame zusammen.","Springer schlägt auf d5 – Beginn der Kombination, die mit gemischten Motiven Material gewinnt."],"en":["A sequence of sacrifices and threats finally wins material.","The knight strikes first, then bishop and queen combine.","Knight takes on d5 — the start of the combination that wins material with mixed motifs."],"hr":["Niz žrtava i prijetnji naposljetku osvaja materijal.","Skakač prvi udara, zatim lovac i dama surađuju.","Skakač uzima na d5 — početak kombinacije koja miješanim motivima osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.077' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein verdeckter Angriff bereitet einen materialgewinnenden Doppelschlag vor.","Der Springer springt heran und droht, danach öffnet sich der Abzug.","Springer nach b5 – das leitet den Abzugsangriff ein, der Material gewinnt."],"en":["A discovered attack sets up a material-winning double blow.","The knight jumps in and threatens, then the discovery springs.","Knight to b5 — beginning the discovered attack that wins material."],"hr":["Otkriveni napad priprema dvostruki udarac koji osvaja materijal.","Skakač uskače i prijeti, zatim se otvara otkriće.","Skakač na b5 — započinje otkriveni napad koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.078' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer löst einen Abzug aus, der zum Materialgewinn führt.","Der Springer beginnt, dann nutzt die Dame den verdeckten Angriff.","Springer nach b6 – Beginn der Kombination, die per Abzugsangriff Material gewinnt."],"en":["A knight triggers a discovery that leads to winning material.","The knight starts, then the queen exploits the discovered attack.","Knight to b6 — the start of the combination that wins material by discovery."],"hr":["Skakač pokreće otkriće koje vodi do dobitka materijala.","Skakač počinje, zatim dama iskorištava otkriveni napad.","Skakač na b6 — početak kombinacije koja otkrivenim napadom osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.079' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug räumt den Weg für einen materialgewinnenden Doppelangriff.","Der Turm zieht mit Abzug, danach gabelt der Springer.","Turm schlägt auf f5 – das leitet den Abzug ein, der schließlich Material gewinnt."],"en":["A discovery clears the way for a material-winning double attack.","The rook moves with discovery, then the knight forks.","Rook takes on f5 — beginning the discovery that ends up winning material."],"hr":["Otkriće oslobađa put za dvostruki napad koji osvaja materijal.","Top se miče uz otkriće, zatim skakač udara viljuškom.","Top uzima na f5 — započinje otkriće koje naposljetku osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.080' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzugsangriff trifft zwei Ziele auf einmal und gewinnt Material.","Der Springer zieht weg und entfesselt den verdeckten Angriff.","Springer nach c1 – Beginn des Abzugs, der mit Doppeldrohung Material gewinnt."],"en":["A discovered attack hits two targets at once and wins material.","The knight steps away and unleashes the discovery.","Knight to c1 — starting the discovery that wins material with a double threat."],"hr":["Otkriveni napad odjednom pogađa dva cilja i osvaja materijal.","Skakač se miče i oslobađa otkriveni napad.","Skakač na c1 — početak otkrića koje dvostrukom prijetnjom osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.081' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, danach entfesselt ein Springer einen materialgewinnenden Abzug.","Erst opfert sich der Läufer, dann arbeiten die Springer mit Abzug.","Läufer schlägt auf e2 – das lockt und leitet den Abzugsangriff zum Materialgewinn ein."],"en":["A sacrifice lures, then a knight unleashes a material-winning discovery.","First the bishop sacrifices, then the knights work with a discovery.","Bishop takes on e2 — luring and beginning the discovered attack that wins material."],"hr":["Žrtva mami, zatim skakač oslobađa otkriće koje osvaja materijal.","Najprije se lovac žrtvuje, potom skakači rade s otkrićem.","Lovac uzima na e2 — mami i započinje otkriveni napad koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:004.082' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Batterie aus Läufer und Dame zielt verdeckt auf die gegnerische Dame.","Der Springer löst den Abzug aus, dann entscheidet die Batterie.","Springer nach b5 – das entfesselt den Abzugsangriff, der Material gewinnt."],"en":["A bishop-and-queen battery aims through at the enemy queen.","The knight springs the discovery, then the battery decides.","Knight to b5 — unleashing the discovered attack that wins material."],"hr":["Baterija lovca i dame otkriveno cilja na protivničku damu.","Skakač pokreće otkriće, zatim baterija odlučuje.","Skakač na b5 — oslobađa otkriveni napad koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.003' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein verdeckter Angriff gewinnt Material, doch danach folgt noch ein Nachschlag.","Der Springer zieht mit Abzug, dann holt der Turm das Material.","Springer schlägt auf d2 – Abzug mit Nachfolge, der schließlich Material gewinnt."],"en":["A discovery wins material, but a follow-up is still needed.","The knight moves with discovery, then the rook collects.","Knight takes on d2 — a discovery with a follow-up that wins material."],"hr":["Otkriveni napad osvaja materijal, ali slijedi još jedan udarac.","Skakač se miče uz otkriće, zatim top uzima materijal.","Skakač uzima na d2 — otkriće s nastavkom koje naposljetku osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.004' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Batterie wird sorgfältig aufgebaut und gewinnt dann Material.","Erst stellt sich der Turm bereit, danach entscheidet die Dame-Läufer-Batterie.","Turm nach d1 – Beginn des Aufbaus, der per Abzug Material gewinnt."],"en":["A battery is carefully built up and then wins material.","First the rook gets into place, then the queen-bishop battery decides.","Rook to d1 — starting the build-up that wins material by discovery."],"hr":["Baterija se pažljivo postavlja i zatim osvaja materijal.","Najprije se top postavlja, potom odlučuje baterija dame i lovca.","Top na d1 — početak postavljanja koje otkrićem osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.005' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Köder lockt eine Figur, danach gewinnt ein verdeckter Angriff Material.","Die Dame opfert sich als Köder, dann schlägt der Läufer mit Abzug zu.","Dame schlägt auf d8 – das lockt und leitet den materialgewinnenden Abzug ein."],"en":["A decoy lures a piece, then a discovery wins material.","The queen offers herself as a decoy, then the bishop strikes with discovery.","Queen takes on d8 — luring, and beginning the material-winning discovery."],"hr":["Mamac mami figuru, zatim otkriveni napad osvaja materijal.","Dama se nudi kao mamac, potom lovac udara otkrićem.","Dama uzima na d8 — mami i započinje otkriće koje osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.006' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt den König, danach gewinnt ein Abzug Material.","Die Dame opfert sich, dann springt der Springer mit Abzug.","Dame schlägt auf f2 – das lockt den König und leitet den materialgewinnenden Abzug ein."],"en":["A sacrifice lures the king, then a discovery wins material.","The queen gives herself up, then the knight leaps with discovery.","Queen takes on f2 — luring the king and starting the material-winning discovery."],"hr":["Žrtva mami kralja, zatim otkriveni napad osvaja materijal.","Dama se žrtvuje, potom skakač skače uz otkriće.","Dama uzima na f2 — mami kralja i započinje otkriće koje osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.007' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, danach gewinnt ein verdeckter Angriff Material.","Die Dame opfert sich, dann schlägt sie über die geöffnete Linie zu.","Dame schlägt auf e8 – das lockt und leitet den materialgewinnenden Abzug ein."],"en":["A sacrifice lures, then a discovery wins material.","The queen sacrifices, then strikes along the opened line.","Queen takes on e8 — luring, and beginning the material-winning discovery."],"hr":["Žrtva mami, zatim otkriveni napad osvaja materijal.","Dama se žrtvuje, potom udara duž otvorene linije.","Dama uzima na e8 — mami i započinje otkriće koje osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.008' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination erzwingt das Matt – treib den Gegner systematisch in die Enge.","Der Turm gibt sich her, um den König zu entblößen, dann übernimmt die schwere Figur.","Turm schlägt auf e5 – Beginn der forcierten Mattführung."],"en":["A combination forces mate — herd the enemy king into the net.","The rook offers itself to strip a defender, then the heavy pieces take over.","Rook takes on e5 — starting the forced mating sequence."],"hr":["Kombinacija forsira mat — natjeraj protivničkog kralja u zamku.","Top se žrtvuje da ogoli obranu, a onda preuzimaju teške figure.","Top uzima na e5 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.009' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein verstecktes Manöver lockt eine Figur weg und gewinnt entscheidend Material.","Der Springer zwingt die Dame an einen unglücklichen Platz, dann schlägt der zweite Springer zu.","Läufer schlägt auf c4 – Auftakt der materialgewinnenden Kombination."],"en":["A hidden maneuver lures a piece away and wins decisive material.","The knight drags the queen to a bad square, then the second knight strikes.","Bishop takes on c4 — opening the material-winning combination."],"hr":["Skriveni manevar odvlači figuru i osvaja odlučujući materijal.","Skakač vuče damu na loše polje, a onda udara drugi skakač.","Lovac uzima na c4 — uvod u kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.010' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsopfer macht die Bahn für einen entscheidenden Vorteil frei.","Der Läufer lockt die Dame weg, dann marschiert der Freibauer durch.","Läufer schlägt auf e7 – Beginn der gewinnenden Folge."],"en":["A deflection sacrifice clears the path to a decisive edge.","The bishop lures the queen off, then the passed pawn marches through.","Bishop takes on e7 — starting the winning sequence."],"hr":["Žrtva odvlačenja čisti put do odlučujuće prednosti.","Lovac odvlači damu, a onda prolazi slobodni pješak.","Lovac uzima na e7 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.011' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Lockopfer öffnet die Stellung und gewinnt Material.","Der Läufer gibt sich her, um eine Figur wegzulocken, danach entscheidet ein Vorstoß.","Läufer schlägt auf c5 – Auftakt der gewinnenden Kombination."],"en":["A luring sacrifice opens the position and wins material.","The bishop offers itself to drag a piece away, then a pawn break decides.","Bishop takes on c5 — opening the winning combination."],"hr":["Žrtva mamac otvara poziciju i osvaja materijal.","Lovac se žrtvuje da odvuče figuru, a onda odlučuje prodor.","Lovac uzima na c5 — uvod u dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.012' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Durch Abräumen eines Verteidigers entsteht ein materialgewinnender Angriff.","Die Dame schlägt den Verteidiger weg, dann übernehmen Läufer und Springer.","Dame schlägt auf b6 – Beginn der gewinnenden Folge."],"en":["Removing a defender by capture sets up a material-winning attack.","The queen takes off the defender, then bishop and knight take over.","Queen takes on b6 — starting the winning sequence."],"hr":["Uklanjanje branitelja udarcem stvara napad koji osvaja materijal.","Dama skida branitelja, a onda preuzimaju lovac i skakač.","Dama uzima na b6 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.013' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver vertreibt den Verteidiger und gewinnt Material.","Der Springer hüpft vor, um den schützenden Springer zu verjagen, dann fällt der Turm.","Springer nach g5 – Auftakt der materialgewinnenden Folge."],"en":["A knight maneuver chases off the defender and wins material.","The knight leaps forward to drive away the guarding knight, then the rook falls.","Knight to g5 — opening the material-winning sequence."],"hr":["Manevar skakača tjera branitelja i osvaja materijal.","Skakač skače naprijed da otjera skakača-branitelja, a onda pada top.","Skakač na g5 — uvod u niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.014' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Beseitigen des Verteidigers verschafft entscheidenden Vorteil.","Der Läufer opfert sich, um den deckenden Bauern wegzulenken, dann bricht ein Bauer durch.","Läufer schlägt auf e4 – Beginn der gewinnenden Folge."],"en":["Eliminating the key defender brings a decisive advantage.","The bishop sacrifices to lure away the guarding pawn, then a pawn breaks through.","Bishop takes on e4 — starting the winning sequence."],"hr":["Uklanjanje ključnog branitelja donosi odlučujuću prednost.","Lovac se žrtvuje da odvuče pješaka-branitelja, a onda probija pješak.","Lovac uzima na e4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.015' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Lockopfer reißt die a-Linie auf und gewinnt entscheidend.","Der Läufer opfert sich, um den deckenden Bauern abzulenken, dann dringt der Turm ein.","Läufer schlägt auf b6 – Auftakt der gewinnenden Kombination."],"en":["A luring sacrifice rips open a file and wins decisively.","The bishop sacrifices to lure away the guarding pawn, then the rook invades.","Bishop takes on b6 — opening the winning combination."],"hr":["Žrtva mamac otvara liniju i osvaja odlučujuće.","Lovac se žrtvuje da odvuče pješaka-branitelja, a onda upada top.","Lovac uzima na b6 — uvod u dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.016' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsopfer holt den deckenden Bauern weg und entscheidet.","Der Springer opfert sich, um den Bauern wegzulocken, dann wird ein Vorstoß tödlich.","Springer schlägt auf g4 – Beginn der gewinnenden Folge."],"en":["A deflection sacrifice removes the guarding pawn and decides.","The knight sacrifices to lure the pawn away, then a pawn push turns deadly.","Knight takes on g4 — starting the winning sequence."],"hr":["Žrtva odvlačenja uklanja pješaka-branitelja i odlučuje.","Skakač se žrtvuje da odvuče pješaka, a onda prodor postaje smrtonosan.","Skakač uzima na g4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.017' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Doppeltes Wegräumen der Deckung bringt entscheidenden Vorteil.","Erst der Läufer, dann die Dame opfern sich, um den Bauern wegzulocken.","Läufer schlägt auf c5 – Auftakt der gewinnenden Kombination."],"en":["Twice clearing away the cover yields a decisive advantage.","First the bishop, then the queen sacrifice to lure the pawn off.","Bishop takes on c5 — opening the winning combination."],"hr":["Dvostruko uklanjanje pokrića donosi odlučujuću prednost.","Prvo lovac, pa dama žrtvuju se da odvuku pješaka.","Lovac uzima na c5 — uvod u dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.018' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß verdrängt den König und enthüllt einen materialgewinnenden Angriff.","Der Turm rückt vor und treibt den König weg, dann springt der Springer mit Doppelangriff.","Turm nach d8 – Beginn der gewinnenden Folge."],"en":["A push displaces the king and reveals a material-winning attack.","The rook advances to drive the king off, then the knight jumps in with a double attack.","Rook to d8 — starting the winning sequence."],"hr":["Prodor istiskuje kralja i otkriva napad koji osvaja materijal.","Top napreduje i tjera kralja, a onda skakač uskače s dvostrukim napadom.","Top na d8 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.019' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination treibt den König ins Matt.","Der Springer jagt den König herum, dann setzt die Dame den Schlusspunkt.","Springer schlägt auf f6 – Auftakt der erzwungenen Mattführung."],"en":["A combination chases the king into mate.","The knight harries the king, then the queen delivers the finish.","Knight takes on f6 — opening the forced mating sequence."],"hr":["Kombinacija tjera kralja u mat.","Skakač goni kralja, a onda dama daje završni udarac.","Skakač uzima na f6 — uvod u prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.020' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß lenkt den Turm ab und ermöglicht eine materialgewinnende Gabel.","Der Springer gabelt nach der Ablenkung König und Turm.","Bauer nach b5 – Beginn der gewinnenden Folge."],"en":["A pawn push deflects the rook and sets up a material-winning fork.","After the deflection the knight forks king and rook.","Pawn to b5 — starting the winning sequence."],"hr":["Prodor pješaka odvlači top i priprema viljušku koja osvaja materijal.","Nakon odvlačenja skakač viljuškom napada kralja i top.","Pješak na b5 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.021' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmzug öffnet eine Linie und gewinnt entscheidend Material.","Der Turm räumt die Bahn, dann arbeiten Springer und Läufer den Vorteil heraus.","Turm nach g3 – Auftakt der gewinnenden Kombination."],"en":["A rook move opens a line and wins decisive material.","The rook clears the path, then knight and bishop work up the advantage.","Rook to g3 — opening the winning combination."],"hr":["Potez topa otvara liniju i osvaja odlučujući materijal.","Top čisti put, a onda skakač i lovac izvlače prednost.","Top na g3 — uvod u dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.022' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Rückzug fängt die Dame und gewinnt Material.","Der Läufer zieht zurück, jagt die Dame, dann fällt eine Figur am Brettrand.","Läufer nach f8 – Beginn der gewinnenden Folge."],"en":["A retreat traps the queen and wins material.","The bishop steps back, chasing the queen, then a piece drops at the edge.","Bishop to f8 — starting the winning sequence."],"hr":["Povlačenje hvata damu i osvaja materijal.","Lovac se povlači, goni damu, a onda pada figura na rubu.","Lovac na f8 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.023' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß jagt die Figuren und gewinnt entscheidend Material.","Der Bauer rückt vor, treibt Springer und Läufer herum, dann fällt eine Figur.","Bauer nach c4 – Auftakt der gewinnenden Folge."],"en":["A pawn advance harries the pieces and wins decisive material.","The pawn pushes on, chasing knight and bishop, then a piece falls.","Pawn to c4 — opening the winning sequence."],"hr":["Prodor pješaka goni figure i osvaja odlučujući materijal.","Pješak napreduje, goni skakača i lovca, a onda pada figura.","Pješak na c4 — uvod u dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.024' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Liniumräumung schafft eine entscheidende Kombination.","Die Dame opfert sich, um die Grundreihe freizumachen, dann dringt der Turm ein.","Dame schlägt auf a1 – Beginn der gewinnenden Folge."],"en":["A line-clearance creates a decisive combination.","The queen sacrifices to clear the back rank, then the rook invades.","Queen takes on a1 — starting the winning sequence."],"hr":["Čišćenje linije stvara odlučujuću kombinaciju.","Dama se žrtvuje da oslobodi zadnji red, a onda upada top.","Dama uzima na a1 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.025' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernopfer öffnet die Linie und gewinnt entscheidend.","Der Bauer reißt die Stellung auf, dann gabelt der Springer und die Dame räumt ab.","Bauer schlägt auf g6 – Auftakt der gewinnenden Folge."],"en":["A pawn sacrifice opens the line and wins decisively.","The pawn rips the position open, then the knight forks and the queen clears up.","Pawn takes on g6 — opening the winning sequence."],"hr":["Žrtva pješaka otvara liniju i osvaja odlučujuće.","Pješak otvara poziciju, a onda skakač viljuškom udara i dama pokupi.","Pješak uzima na g6 — uvod u dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.026' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine doppelte Liniumräumung gewinnt entscheidend Material.","Erst der Turm, dann der zweite Turm opfern sich, dann setzt die Dame mit Doppelangriff den Punkt.","Turm schlägt auf f1 – Beginn der gewinnenden Folge."],"en":["A double line-clearance wins decisive material.","First a rook, then the other sacrifice, then the queen lands a double attack.","Rook takes on f1 — starting the winning sequence."],"hr":["Dvostruko čišćenje linije osvaja odlučujući materijal.","Prvo jedan top, pa drugi žrtvuju se, a onda dama dolazi s dvostrukim napadom.","Top uzima na f1 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.027' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Lockopfer und Abräumen der Deckung gewinnen Material.","Der Turm opfert sich, dann lockt der Springer, und der Läufer gabelt entscheidend.","Turm schlägt auf f4 – Auftakt der gewinnenden Kombination."],"en":["A luring sacrifice plus removing the cover wins material.","The rook sacrifices, then the knight lures, and the bishop forks decisively.","Rook takes on f4 — opening the winning combination."],"hr":["Žrtva mamac uz uklanjanje pokrića osvaja materijal.","Top se žrtvuje, pa skakač mami, a lovac odlučujuće viljuškom udara.","Top uzima na f4 — uvod u dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.028' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lockt den König weg und gewinnt mit einem Vorstoß entscheidend.","Der Turm rückt vor, dann opfert sich der zweite Turm, danach marschiert ein Bauer.","Turm schlägt auf c4 – Beginn der gewinnenden Folge."],"en":["Lure the king away and win decisively with a push.","The rook advances, then the other rook sacrifices, then a pawn marches.","Rook takes on c4 — starting the winning sequence."],"hr":["Odvuci kralja i pobijedi odlučujuće prodorom.","Top napreduje, pa se drugi top žrtvuje, a onda kreće pješak.","Top uzima na c4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.029' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelopfer lockt den König und gewinnt mit einer Gabel.","Erst der Turm, dann der zweite Turm opfern sich, dann gabelt der Springer.","Turm schlägt auf h2 – Auftakt der gewinnenden Folge."],"en":["A double sacrifice lures the king and wins with a fork.","First a rook, then the other sacrifice, then the knight forks.","Rook takes on h2 — opening the winning sequence."],"hr":["Dvostruka žrtva mami kralja i pobjeđuje viljuškom.","Prvo jedan top, pa drugi žrtvuju se, a onda skakač viljuškom udara.","Top uzima na h2 — uvod u dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.030' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge von Opfern lockt den König und gewinnt entscheidend.","Erst der Turm, dann Dame und Läufer locken den König, danach entscheidet ein Schlag.","Turm schlägt auf d1 – Beginn der gewinnenden Folge."],"en":["A string of sacrifices lures the king and wins decisively.","First the rook, then queen and bishop drag the king out, then a blow decides.","Rook takes on d1 — starting the winning sequence."],"hr":["Niz žrtava mami kralja i osvaja odlučujuće.","Prvo top, pa dama i lovac vuku kralja, a onda odlučuje udarac.","Top uzima na d1 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.031' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination erzwingt das Matt – jag den König und räum die Deckung weg.","Der Springer opfert sich, dann dringt der Turm ein und die Dame setzt zu.","Springer schlägt auf f3 – Beginn der erzwungenen Mattführung."],"en":["A combination forces mate — chase the king and clear the defense.","The knight sacrifices, then the rook invades and the queen finishes.","Knight takes on f3 — starting the forced mating sequence."],"hr":["Kombinacija forsira mat — goni kralja i ukloni obranu.","Skakač se žrtvuje, a onda upada top i dama dovršava.","Skakač uzima na f3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.032' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmzug lenkt die Dame ab und gewinnt entscheidend Material.","Der Turm jagt die Dame, dann gabelt der Springer und ein Doppelschlag entscheidet.","Turm schlägt auf f4 – Auftakt der gewinnenden Folge."],"en":["A rook move deflects the queen and wins decisive material.","The rook chases the queen, then the knight forks and a double blow decides.","Rook takes on f4 — opening the winning sequence."],"hr":["Potez topa odvlači damu i osvaja odlučujući materijal.","Top goni damu, a onda skakač viljuškom udara i dvostruki udarac odlučuje.","Top uzima na f4 — uvod u dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.033' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination führt zum erzwungenen Matt.","Der Läufer opfert sich, lockt die Dame, dann setzt der Läufer mit Schach zum Matt.","Läufer schlägt auf f8 – Beginn der erzwungenen Mattführung."],"en":["A combination leads to forced mate.","The bishop sacrifices, lures the queen, then the bishop delivers mate.","Bishop takes on f8 — starting the forced mating sequence."],"hr":["Kombinacija vodi do prisilnog mata.","Lovac se žrtvuje, mami damu, a onda lovac daje mat.","Lovac uzima na f8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.034' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abräumen der Deckung gewinnt Material.","Der Turm opfert sich, lockt die Dame, dann fällt sie nach einem Zwischenschach.","Turm schlägt auf e3 – Beginn der gewinnenden Folge."],"en":["Removing the defense wins material.","The rook sacrifices, drags the queen out, then she falls after an in-between check.","Rook takes on e3 — starting the winning sequence."],"hr":["Uklanjanje obrane osvaja materijal.","Top se žrtvuje, vuče damu, a onda ona pada nakon međušaha.","Top uzima na e3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.035' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver mit Folgeschlag gewinnt Material.","Der Springer springt vor, dann nimmt er nach einem Zwischenschach die Dame.","Springer schlägt auf d5 – Beginn der gewinnenden Folge."],"en":["A knight maneuver with a follow-up wins material.","The knight leaps in, then after an in-between check it grabs the queen.","Knight takes on d5 — starting the winning sequence."],"hr":["Manevar skakača s nastavkom osvaja materijal.","Skakač uskače, a onda nakon međušaha uzima damu.","Skakač uzima na d5 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.036' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Folgeschlag nutzt ein Zwischenschach und gewinnt Material.","Der Läufer schlägt zu, dann holt er sich nach dem Zwischenschach die Dame.","Läufer schlägt auf f8 – Beginn der gewinnenden Folge."],"en":["A follow-up using an in-between check wins material.","The bishop strikes, then after the in-between check it collects the queen.","Bishop takes on f8 — starting the winning sequence."],"hr":["Nastavak koristeći međušah osvaja materijal.","Lovac udara, a onda nakon međušaha kupi damu.","Lovac uzima na f8 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.037' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Folgeschlag nutzt ein Zwischenschach und gewinnt Material.","Der Läufer schlägt zu, dann holt er sich nach dem Zwischenschach die Dame.","Läufer schlägt auf d7 – Beginn der gewinnenden Folge."],"en":["A follow-up using an in-between check wins material.","The bishop strikes, then after the in-between check it collects the queen.","Bishop takes on d7 — starting the winning sequence."],"hr":["Nastavak koristeći međušah osvaja materijal.","Lovac udara, a onda nakon međušaha kupi damu.","Lovac uzima na d7 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:005.038' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein verstecktes Manöver gewinnt Material durch eine Abzugswirkung.","Der Springer im Zentrum schlägt zu und entfesselt dabei Druck auf die gegnerischen Figuren.","Springer schlägt auf e4 – beginnt die Kombination und gewinnt einen Bauern."],"en":["A hidden resource wins material through a discovered effect.","The centralized knight strikes and unleashes pressure on the enemy pieces.","Knight takes on e4 — starting the combination that wins a pawn."],"hr":["Skriveni resurs osvaja materijal otkrivenim djelovanjem.","Centralizirani skakač udara i oslobađa pritisak na protivničke figure.","Skakač uzima na e4 — započinje kombinaciju koja osvaja pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:005.039' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug bringt entscheidenden Materialgewinn.","Der Springer am Rand öffnet die Linie und greift dabei gleich mehrere Ziele an.","Springer nach b5 – leitet die gewinnbringende Kombination ein."],"en":["A discovered attack brings decisive material gain.","The knight jumps aside, opening a line and hitting several targets at once.","Knight to b5 — launching the winning combination."],"hr":["Otkriveni napad donosi odlučujuću materijalnu prednost.","Skakač skače u stranu, otvarajući liniju i napadajući više ciljeva odjednom.","Skakač na b5 — pokreće dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.040' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzugsschlag gewinnt entscheidend Material.","Der zentrale Springer verschwindet mit Tempo und reißt die gegnerische Stellung auf.","Springer schlägt auf e5 – Auftakt zur gewinnbringenden Kombination."],"en":["A discovered blow wins material decisively.","The central knight vanishes with tempo and tears open the enemy setup.","Knight takes on e5 — the start of the winning combination."],"hr":["Otkriveni udarac odlučujuće osvaja materijal.","Centralni skakač nestaje s tempom i razbija protivničku postavu.","Skakač uzima na e5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.041' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorbereitender Zug ebnet den Weg zum Materialgewinn.","Der zentrale Springer zieht zurück und stellt eine Gabel in Aussicht.","Springer nach c2 – beginnt die Kombination, die die Dame jagt."],"en":["A preparatory move paves the way to winning material.","The central knight retreats and sets up a fork to come.","Knight to c2 — beginning the combination that hunts the queen."],"hr":["Pripremni potez utire put do osvajanja materijala.","Centralni skakač se povlači i priprema viljušku koja slijedi.","Skakač na c2 — započinje kombinaciju koja lovi damu."]}', HintsVersion=1 WHERE LineId LIKE '%:005.042' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug gewinnt entscheidend Material.","Zuerst fällt der Verteidiger – der Läufer schlägt einen wichtigen Stein.","Läufer schlägt auf c6 – Auftakt zur gewinnbringenden Kombination."],"en":["A discovered attack wins material decisively.","First the defender falls — the bishop removes a key guard.","Bishop takes on c6 — the start of the winning combination."],"hr":["Otkriveni napad odlučujuće osvaja materijal.","Prvo pada branitelj — lovac uklanja ključnog čuvara.","Lovac uzima na c6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.043' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorbereitendes Bauernopfer leitet einen gewinnenden Abzug ein.","Erst wird ein Bauer weggelockt, dann wirkt der Springer mit Abzugskraft.","Bauer nach f5 – Beginn der gewinnbringenden Kombination."],"en":["A preparatory pawn thrust sets up a winning discovered attack.","First a pawn is lured away, then the knight works with discovered power.","Pawn to f5 — the start of the winning combination."],"hr":["Pripremni prodor pješaka priprema dobitni otkriveni napad.","Prvo se pješak namami, a zatim skakač djeluje otkrivenom snagom.","Pješak na f5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.044' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Batterie entsteht, während der König gejagt wird – Material fällt.","Die Dame zieht mit Tempo und bereitet das Zusammenspiel mit dem Springer vor.","Dame nach c1 – beginnt die gewinnbringende Kombination."],"en":["A battery forms as the king is chased — material will fall.","The queen moves with tempo and prepares the knight''s cooperation.","Queen to c1 — beginning the winning combination."],"hr":["Baterija nastaje dok se kralj progoni — materijal pada.","Dama se kreće s tempom i priprema suradnju sa skakačem.","Dama na c1 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.045' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug verschafft entscheidenden Vorteil, indem eine Batterie aufgebaut wird.","Der Turm zieht und der König wird vertrieben, während die Linie geladen wird.","Turm schlägt auf f6 – Auftakt zur gewinnbringenden Kombination."],"en":["A discovered attack secures decisive advantage by forming a battery.","The rook moves and the king is driven off while the line is loaded.","Rook takes on f6 — the start of the winning combination."],"hr":["Otkriveni napad osigurava odlučujuću prednost stvaranjem baterije.","Top se pomiče i kralj se tjera dok se linija puni.","Top uzima na f6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.046' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug bringt entscheidenden Vorteil über eine Batterie.","Der Turm rückt vor und treibt den König, während die Batterie geladen wird.","Turm nach g4 – beginnt die gewinnbringende Kombination."],"en":["A discovered attack brings decisive advantage via a battery.","The rook advances and drives the king while the battery is loaded.","Rook to g4 — beginning the winning combination."],"hr":["Otkriveni napad donosi odlučujuću prednost preko baterije.","Top napreduje i tjera kralja dok se baterija puni.","Top na g4 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.047' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug gewinnt entscheidend Material.","Der zentrale Springer schlägt einen Verteidiger und legt eine Batterie an.","Springer schlägt auf f6 – Auftakt zur gewinnbringenden Kombination."],"en":["A discovered attack wins material decisively.","The central knight removes a defender and sets up a battery.","Knight takes on f6 — the start of the winning combination."],"hr":["Otkriveni napad odlučujuće osvaja materijal.","Centralni skakač uklanja branitelja i postavlja bateriju.","Skakač uzima na f6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.048' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug verschafft entscheidenden Vorteil über eine Batterie.","Die Dame zieht zur Seite und ladet die Wirkung der anderen Figuren.","Dame nach h3 – beginnt die gewinnbringende Kombination."],"en":["A discovered attack secures decisive advantage via a battery.","The queen steps aside and charges the power of the other pieces.","Queen to h3 — beginning the winning combination."],"hr":["Otkriveni napad osigurava odlučujuću prednost preko baterije.","Dama se izmiče u stranu i nabija snagu ostalih figura.","Dama na h3 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.049' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug baut eine Batterie auf und gewinnt entscheidend Material.","Der Springer schlägt zu, dann jagt die Dame den König in den Abzug.","Springer schlägt auf f4 – Auftakt zur gewinnbringenden Kombination."],"en":["A discovered attack builds a battery and wins material decisively.","The knight strikes, then the queen drives the king into the discovery.","Knight takes on f4 — the start of the winning combination."],"hr":["Otkriveni napad gradi bateriju i odlučujuće osvaja materijal.","Skakač udara, a zatim dama tjera kralja u otkriveni napad.","Skakač uzima na f4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.050' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug als Vorbereitung gewinnt eine Figur.","Der vorrückende Springerbauer entfesselt einen doppelten Angriff.","Bauer nach f4 – beginnt die gewinnbringende Kombination."],"en":["A discovered attack as preparation wins a piece.","The advancing knight''s pawn unleashes a double attack.","Pawn to f4 — beginning the winning combination."],"hr":["Otkriveni napad kao priprema osvaja figuru.","Napredujući pješak ispred skakača oslobađa dvostruki napad.","Pješak na f4 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.051' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug als Vorbereitung gewinnt entscheidend Material.","Ein vorrückender Bauer öffnet die Linie und entfesselt einen Doppelangriff.","Bauer nach c4 – beginnt die gewinnbringende Kombination."],"en":["A discovered attack as preparation wins material decisively.","An advancing pawn opens a line and unleashes a double attack.","Pawn to c4 — beginning the winning combination."],"hr":["Otkriveni napad kao priprema odlučujuće osvaja materijal.","Napredujući pješak otvara liniju i oslobađa dvostruki napad.","Pješak na c4 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.052' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["König und Dame auf einer Linie – ein Spieß gewinnt Material.","Erst opfert die Dame sich, dann durchbohrt der Turm die Reihe.","Dame schlägt auf g7 – Auftakt zur gewinnbringenden Kombination."],"en":["King and queen on one line — a skewer wins material.","First the queen sacrifices itself, then the rook impales the rank.","Queen takes on g7 — the start of the winning combination."],"hr":["Kralj i dama na istoj liniji — ražanj osvaja materijal.","Prvo se dama žrtvuje, a zatim top probada vrstu.","Dama uzima na g7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:006.003' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Spieß auf der Diagonale gewinnt Material.","Der Läufer öffnet erst die Diagonale, um König und Dame aufzuspießen.","Läufer schlägt auf c3 – beginnt die gewinnbringende Kombination."],"en":["A skewer along the diagonal wins material.","The bishop first clears the diagonal to skewer king and queen.","Bishop takes on c3 — beginning the winning combination."],"hr":["Ražanj po dijagonali osvaja materijal.","Lovac prvo čisti dijagonalu da nabode kralja i damu.","Lovac uzima na c3 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:006.004' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Anlockung schafft einen gewinnenden Spieß.","Der Turm opfert sich, damit der Läufer König und Turm aufspießt.","Turm schlägt auf e6 – Auftakt zur gewinnbringenden Kombination."],"en":["A luring sacrifice creates a winning skewer.","The rook sacrifices itself so the bishop can skewer king and rook.","Rook takes on e6 — the start of the winning combination."],"hr":["Žrtva mamac stvara dobitni ražanj.","Top se žrtvuje da lovac nabode kralja i topa.","Top uzima na e6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:006.005' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Anlockung führt zu einem gewinnenden Spieß.","Der Turm opfert sich, um die Dame auf die verwundbare Linie zu locken.","Turm nach e2 – beginnt die gewinnbringende Kombination."],"en":["A luring tactic leads to a winning skewer.","The rook offers itself to lure the queen onto a vulnerable line.","Rook to e2 — beginning the winning combination."],"hr":["Mamljenje vodi do dobitnog ražnja.","Top se nudi da namami damu na ranjivu liniju.","Top na e2 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:006.006' AND BookFileName='chessable-u5-21646.pgn';
