UPDATE BookPuzzles SET HintsJson='{"de":["Eine kleine Kombination lockt eine Figur weg und fesselt – Material winkt.","Der Springer opfert sich, um den Läufer zu einer fesselnden Aktion zu befreien.","Springer schlägt auf h6 – Beginn der gewinnbringenden Kombination."],"en":["A small combination lures a piece away and pins — material is yours.","The knight sacrifices itself to free the bishop for a pinning blow.","Knight takes on h6 — the start of the winning combination."],"hr":["Mala kombinacija odvlači figuru i veže — slijedi dobitak materijala.","Skakač se žrtvuje da oslobodi lovca za vezivanje.","Skakač uzima na h6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.012' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt den Bauern weg und schafft eine entscheidende Fesselung.","Der Springer gibt sich hin, danach entscheidet der Turm an der freien Linie.","Springer schlägt auf h3 – Auftakt zur gewinnbringenden Fesselung."],"en":["A sacrifice lures a pawn away and creates a decisive pin.","The knight gives itself up, then the rook exploits the open line.","Knight takes on h3 — the start of the winning pin."],"hr":["Žrtva odvlači pješaka i stvara odlučujuće vezivanje.","Skakač se predaje, a zatim top koristi otvorenu liniju.","Skakač uzima na h3 — početak dobitnog vezivanja."]}', HintsVersion=1 WHERE LineId LIKE '%:007.013' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer räumt eine Figur weg, dann fesselt der Läufer tödlich.","Der Springer opfert sich, damit der Läufer auf der langen Diagonale zuschlägt.","Springer nach g5 – Beginn der gewinnbringenden Fesselung."],"en":["A sacrifice clears a piece, then the bishop pins fatally.","The knight offers itself so the bishop strikes along the long diagonal.","Knight to g5 — the start of the winning pin."],"hr":["Žrtva uklanja figuru, a zatim lovac kobno veže.","Skakač se nudi da lovac udari po dugoj dijagonali.","Skakač na g5 — početak dobitnog vezivanja."]}', HintsVersion=1 WHERE LineId LIKE '%:007.014' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Den König jagen und dann eine Fesselung anlegen bringt Material.","Die Dame treibt den König, dann entscheidet eine Fesselung des Läufers.","Dame schlägt auf h4 – Auftakt zur gewinnbringenden Jagd."],"en":["Chase the king, then set a pin to win material.","The queen drives the king, then a pin on the bishop decides.","Queen takes on h4 — the start of the winning chase."],"hr":["Tjeraj kralja, a zatim postavi vezivanje za dobitak.","Dama tjera kralja, a zatim vezivanje lovca odlučuje.","Dama uzima na h4 — početak dobitne hajke."]}', HintsVersion=1 WHERE LineId LIKE '%:007.015' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß auf die Grundreihe zielt und führt zu einer Fesselung.","Die Dame dringt ein und richtet sich dann gegen einen gefesselten Turm.","Dame nach c8 – Beginn der gewinnbringenden Kombination."],"en":["A thrust to the back rank targets and leads to a pin.","The queen invades, then turns against a pinned rook.","Queen to c8 — the start of the winning combination."],"hr":["Prodor na zadnji red cilja i vodi do vezivanja.","Dama upada, a zatim se okreće protiv vezanog topa.","Dama na c8 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.016' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Linie wird geöffnet, dann fesselt die Dame entscheidend.","Der Läufer schlägt, um die Diagonale für die Dame freizuräumen.","Läufer schlägt auf c6 – Auftakt zur gewinnbringenden Fesselung."],"en":["A line is opened, then the queen pins decisively.","The bishop captures to clear the diagonal for the queen.","Bishop takes on c6 — the start of the winning pin."],"hr":["Linija se otvara, a zatim dama odlučujuće veže.","Lovac uzima da oslobodi dijagonalu za damu.","Lovac uzima na c6 — početak dobitnog vezivanja."]}', HintsVersion=1 WHERE LineId LIKE '%:007.017' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mehrfaches Locken bereitet eine vernichtende Fesselung vor.","Bauern und Türme werden geopfert, bis der Läufer tödlich fesselt.","Bauer schlägt auf c5 – Beginn der gewinnbringenden Kombination."],"en":["Repeated luring prepares a crushing pin.","Pawns and rooks are given up until the bishop pins fatally.","Pawn takes on c5 — the start of the winning combination."],"hr":["Višestruko odvlačenje priprema razorno vezivanje.","Pješaci i topovi se žrtvuju dok lovac kobno ne veže.","Pješak uzima na c5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.018' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Zielen und Locken münden in eine gewinnbringende Fesselung.","Der Läufer zieht zurück, dann fesselt der Turm den Läufer.","Läufer nach e1 – Auftakt zur gewinnbringenden Kombination."],"en":["Targeting and luring end in a winning pin.","The bishop retreats, then the rook pins the bishop.","Bishop to e1 — the start of the winning combination."],"hr":["Ciljanje i odvlačenje vode do dobitnog vezivanja.","Lovac se povlači, a zatim top veže lovca.","Lovac na e1 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.019' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, dann wird die gefesselte Figur attackiert.","Der Turm opfert sich, danach dringt die Dame entscheidend ein.","Turm schlägt auf e3 – Beginn der gewinnbringenden Kombination."],"en":["A sacrifice lures, then the pinned piece is attacked.","The rook sacrifices itself, then the queen invades decisively.","Rook takes on e3 — the start of the winning combination."],"hr":["Žrtva odvlači, a zatim se napada vezana figura.","Top se žrtvuje, a zatim dama odlučujuće upada.","Top uzima na e3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.020' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Locken und dann die gefesselte Figur angreifen bringt Material.","Der Springer opfert sich, danach entscheidet der Druck auf den gefesselten Turm.","Springer schlägt auf e5 – Auftakt zur gewinnbringenden Kombination."],"en":["Lure, then attack the pinned piece to win material.","The knight sacrifices itself, then pressure on the pinned rook decides.","Knight takes on e5 — the start of the winning combination."],"hr":["Odvuci, pa napadni vezanu figuru za dobitak.","Skakač se žrtvuje, a zatim pritisak na vezani top odlučuje.","Skakač uzima na e5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.021' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Locken und die gefesselte Figur angreifen gewinnt entscheidend.","Der Läufer zieht zurück, dann fällt die gefesselte Figur unter Druck.","Läufer nach c2 – Beginn der gewinnbringenden Kombination."],"en":["Luring and attacking the pinned piece wins decisively.","The bishop retreats, then the pinned piece collapses under pressure.","Bishop to c2 — the start of the winning combination."],"hr":["Odvlačenje i napad na vezanu figuru odlučujuće dobiva.","Lovac se povlači, a zatim vezana figura pada pod pritiskom.","Lovac na c2 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.022' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag öffnet den Weg zum Angriff auf eine gefesselte Figur.","Der Turm opfert sich, dann attackiert der Läufer die gefesselte Figur.","Turm schlägt auf f7 – Auftakt zur gewinnbringenden Kombination."],"en":["A capture opens the way to attack a pinned piece.","The rook sacrifices itself, then the bishop attacks the pinned piece.","Rook takes on f7 — the start of the winning combination."],"hr":["Uzimanje otvara put za napad na vezanu figuru.","Top se žrtvuje, a zatim lovac napada vezanu figuru.","Top uzima na f7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.023' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur wird verjagt, dann wird die gefesselte Figur angegriffen.","Ein Bauernvorstoß treibt den Läufer, danach entscheidet die Fesselung.","Bauer nach g5 – Beginn der gewinnbringenden Kombination."],"en":["A piece is chased away, then the pinned piece is attacked.","A pawn push drives the bishop, then the pin decides.","Pawn to g5 — the start of the winning combination."],"hr":["Figura se otjera, a zatim se napada vezana figura.","Potez pješaka tjera lovca, a zatim vezivanje odlučuje.","Pješak na g5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.024' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur weglocken und die gefesselte Figur angreifen gewinnt.","Der Turm opfert sich, danach attackiert ein Bauer die gefesselte Figur.","Turm schlägt auf g5 – Auftakt zur gewinnbringenden Kombination."],"en":["Lure a piece away and attack the pinned piece to win.","The rook sacrifices itself, then a pawn attacks the pinned piece.","Rook takes on g5 — the start of the winning combination."],"hr":["Odvuci figuru i napadni vezanu figuru za dobitak.","Top se žrtvuje, a zatim pješak napada vezanu figuru.","Top uzima na g5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.025' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur weglocken bereitet den Angriff auf die Fesselung vor.","Der Läufer opfert sich, danach fällt die gefesselte Figur.","Läufer schlägt auf g6 – Beginn der gewinnbringenden Kombination."],"en":["Luring a piece away sets up the attack on the pin.","The bishop sacrifices itself, then the pinned piece falls.","Bishop takes on g6 — the start of the winning combination."],"hr":["Odvlačenje figure priprema napad na vezivanje.","Lovac se žrtvuje, a zatim vezana figura pada.","Lovac uzima na g6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.026' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Ablenkung leitet einen Angriff auf die gefesselte Figur ein.","Der Springer schlägt zu, danach entscheidet der Druck auf den gefesselten Turm.","Springer schlägt auf d7 – Auftakt zur gewinnbringenden Kombination."],"en":["An interference launches an attack on the pinned piece.","The knight strikes, then pressure on the pinned rook decides.","Knight takes on d7 — the start of the winning combination."],"hr":["Ometanje pokreće napad na vezanu figuru.","Skakač udara, a zatim pritisak na vezani top odlučuje.","Skakač uzima na d7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.027' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Batterie wird aufgebaut, um die gefesselte Figur zu erlegen.","Die Dame und ihr Helfer richten sich gemeinsam gegen die gefesselte Figur.","Turm nach d4 – Beginn der gewinnbringenden Kombination."],"en":["A battery is built to bring down the pinned piece.","The queen and her partner aim together at the pinned piece.","Rook to d4 — the start of the winning combination."],"hr":["Gradi se baterija da obori vezanu figuru.","Dama i njezin pomoćnik zajedno ciljaju na vezanu figuru.","Top na d4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.028' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Mischung aus Locken und Fesseln gewinnt entscheidend.","Der Springer schlägt zu und leitet den Druck auf die gefesselte Figur ein.","Springer schlägt auf c6 – Auftakt zur gewinnbringenden Kombination."],"en":["A mix of luring and pinning wins decisively.","The knight strikes and opens pressure on the pinned piece.","Knight takes on c6 — the start of the winning combination."],"hr":["Mješavina odvlačenja i vezivanja odlučujuće dobiva.","Skakač udara i otvara pritisak na vezanu figuru.","Skakač uzima na c6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.029' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine längere Kombination nutzt Fesselungen zum Materialgewinn.","Ein Bauernopfer öffnet die Stellung, dann fesseln Turm und Läufer.","Bauer nach g4 – Beginn der gewinnbringenden Kombination."],"en":["A longer combination uses pins to win material.","A pawn sacrifice opens the position, then rook and bishop pin.","Pawn to g4 — the start of the winning combination."],"hr":["Dulja kombinacija koristi vezivanja za dobitak materijala.","Žrtva pješaka otvara poziciju, a zatim top i lovac vežu.","Pješak na g4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.030' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenzug bereitet eine entscheidende Fesselung vor.","Die Dame manövriert, dann fesselt sie den Läufer tödlich.","Dame nach f4 – Auftakt zur gewinnbringenden Kombination."],"en":["A queen move prepares a decisive pin.","The queen maneuvers, then pins the bishop fatally.","Queen to f4 — the start of the winning combination."],"hr":["Potez dame priprema odlučujuće vezivanje.","Dama manevrira, a zatim kobno veže lovca.","Dama na f4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.031' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, dann ist die gefesselte Figur ein schlechter Verteidiger.","Der Springer opfert sich, danach attackiert der Läufer entscheidend.","Springer schlägt auf g7 – Beginn der gewinnbringenden Kombination."],"en":["A sacrifice lures, then the pinned piece proves a poor defender.","The knight sacrifices itself, then the bishop attacks decisively.","Knight takes on g7 — the start of the winning combination."],"hr":["Žrtva odvlači, a zatim je vezana figura loš branitelj.","Skakač se žrtvuje, a zatim lovac odlučujuće napada.","Skakač uzima na g7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.032' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, dann scheitert der gefesselte Verteidiger.","Der Turm opfert sich, danach fesselt die Dame entscheidend.","Turm schlägt auf a7 – Auftakt zur gewinnbringenden Kombination."],"en":["A sacrifice lures, then the pinned defender fails.","The rook sacrifices itself, then the queen pins decisively.","Rook takes on a7 — the start of the winning combination."],"hr":["Žrtva odvlači, a zatim vezani branitelj zakaže.","Top se žrtvuje, a zatim dama odlučujuće veže.","Top uzima na a7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.033' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, dann taugt die gefesselte Figur nicht zur Verteidigung.","Der Springer opfert sich, danach öffnet der Turm die Linie zur Fesselung.","Springer schlägt auf b7 – Beginn der gewinnbringenden Kombination."],"en":["A sacrifice lures, then the pinned piece can''t defend.","The knight sacrifices itself, then the rook opens the line to pin.","Knight takes on b7 — the start of the winning combination."],"hr":["Žrtva odvlači, a zatim vezana figura ne može braniti.","Skakač se žrtvuje, a zatim top otvara liniju za vezivanje.","Skakač uzima na b7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.034' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mehrfaches Locken zeigt, dass der gefesselte Verteidiger versagt.","Ein Bauernvorstoß öffnet die Linien, dann fesselt die Dame entscheidend.","Bauer nach b5 – Auftakt zur gewinnbringenden Kombination."],"en":["Repeated luring shows the pinned defender fails.","A pawn push opens lines, then the queen pins decisively.","Pawn to b5 — the start of the winning combination."],"hr":["Višestruko odvlačenje pokazuje da vezani branitelj zakaže.","Potez pješaka otvara linije, a zatim dama odlučujuće veže.","Pješak na b5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.035' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, dann ist die gefesselte Figur wertlos zur Abwehr.","Die Dame opfert sich, danach schlägt der Läufer entscheidend ein.","Dame schlägt auf f5 – Beginn der gewinnbringenden Kombination."],"en":["A sacrifice lures, then the pinned piece is useless on defense.","The queen sacrifices itself, then the bishop strikes decisively.","Queen takes on f5 — the start of the winning combination."],"hr":["Žrtva odvlači, a zatim je vezana figura beskorisna u obrani.","Dama se žrtvuje, a zatim lovac odlučujuće udara.","Dama uzima na f5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.036' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt, dann ist der gefesselte Verteidiger machtlos.","Der Springer opfert sich, danach schlägt die Dame entscheidend ein.","Springer schlägt auf d5 – Auftakt zur gewinnbringenden Kombination."],"en":["A sacrifice lures, then the pinned defender is helpless.","The knight sacrifices itself, then the queen strikes decisively.","Knight takes on d5 — the start of the winning combination."],"hr":["Žrtva odvlači, a zatim je vezani branitelj nemoćan.","Skakač se žrtvuje, a zatim dama odlučujuće udara.","Skakač uzima na d5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.037' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur dringt ein und nutzt aus, dass der Verteidiger gefesselt ist.","Der Springer manövriert, danach fällt der gefesselte Bauer.","Springer nach e8 – Beginn der gewinnbringenden Kombination."],"en":["A piece invades, exploiting that the defender is pinned.","The knight maneuvers, then the pinned pawn falls.","Knight to e8 — the start of the winning combination."],"hr":["Figura upada koristeći to što je branitelj vezan.","Skakač manevrira, a zatim vezani pješak pada.","Skakač na e8 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.038' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur wird verjagt, dann versagt der gefesselte Verteidiger.","Ein Bauernvorstoß treibt den Läufer, danach entscheidet die Fesselung.","Bauer nach g5 – Auftakt zur gewinnbringenden Kombination."],"en":["A piece is chased, then the pinned defender fails.","A pawn push drives the bishop, then the pin decides.","Pawn to g5 — the start of the winning combination."],"hr":["Figura se tjera, a zatim vezani branitelj zakaže.","Potez pješaka tjera lovca, a zatim vezivanje odlučuje.","Pješak na g5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.039' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur wird verjagt, dann ist der gefesselte Verteidiger nutzlos.","Der Springer schlägt zu, danach entscheidet die Dame gegen die Fesselung.","Springer schlägt auf e7 – Beginn der gewinnbringenden Kombination."],"en":["A piece is chased, then the pinned defender is useless.","The knight strikes, then the queen decides against the pin.","Knight takes on e7 — the start of the winning combination."],"hr":["Figura se tjera, a zatim je vezani branitelj beskoristan.","Skakač udara, a zatim dama odlučuje protiv vezivanja.","Skakač uzima na e7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.040' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Linie wird geräumt, dann fällt der gefesselte Verteidiger.","Der Springer opfert sich, danach fesselt der Läufer entscheidend.","Springer schlägt auf f6 – Auftakt zur gewinnbringenden Kombination."],"en":["A line is cleared, then the pinned defender falls.","The knight sacrifices itself, then the bishop pins decisively.","Knight takes on f6 — the start of the winning combination."],"hr":["Linija se čisti, a zatim vezani branitelj pada.","Skakač se žrtvuje, a zatim lovac odlučujuće veže.","Skakač uzima na f6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.041' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag auf ein verteidigtes Feld zerstört die gegnerische Koordination und gewinnt Material.","Der Läufer leitet ein, dann nutzt ein Springer eine gefesselte Figur als schwachen Verteidiger.","Läufer schlägt auf f4 – gewinnt entscheidend Material."],"en":["A capture on a guarded square shatters the defense and wins material.","The bishop opens the door, then a knight exploits a pinned, helpless defender.","Bishop takes on f4 — winning decisive material."],"hr":["Žrtva na branjenom polju razbija obranu i osvaja materijal.","Lovac otvara, zatim skakač iskorištava vezanu, bespomoćnu figuru.","Lovac uzima na f4 — osvaja odlučujući materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.042' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß lockt die Dame, dann fällt sie einer Fesselung zum Opfer.","Der Springer drängt vor, eine gefesselte Figur deckt nichts mehr.","Springer nach c4 – leitet den materialgewinnenden Angriff ein."],"en":["A thrust lures the queen, then a pin makes a defender useless.","The knight pushes forward while a pinned piece guards nothing.","Knight to c4 — starting the material-winning combination."],"hr":["Naletom mami se dama, a vezana figura ne brani ništa.","Skakač gura naprijed dok vezana figura ništa ne čuva.","Skakač na c4 — započinje kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.043' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet, getragen von einer tödlichen Fesselung.","Die Dame dringt ein, der gefesselte Verteidiger kann nicht wegschlagen.","Dame nach e3 – beginnt das erzwungene Matt."],"en":["A forced mate is there, powered by a deadly pin.","The queen infiltrates while a pinned defender cannot capture.","Queen to e3 — starting the forced mate."],"hr":["Tu je prisilni mat, nošen smrtonosnom vezom.","Dama prodire dok vezani branitelj ne smije uzeti.","Dama na e3 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:007.044' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine zentrale Aktion gewinnt durch eine doppelte Fesselung Material.","Die Dame tritt ins Zentrum und überlastet eine festgenagelte Figur.","Dame nach e4 – Kreuzfesselung gewinnt Material."],"en":["A central blow wins material via a double pin.","The queen steps to the center and overloads a pinned piece.","Queen to e4 — a cross-pin wins material."],"hr":["Središnji udar dvostrukom vezom osvaja materijal.","Dama ulazi u centar i preopterećuje vezanu figuru.","Dama na e4 — unakrsna veza osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.045' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abtausch auf der entscheidenden Linie führt zu einer doppelten Fesselung, die Material gewinnt.","Die Türme räumen, dann nagelt die Dame eine Figur doppelt fest.","Turm schlägt auf e1 – leitet die gewinnende Kreuzfesselung ein."],"en":["A trade on the key file sets up a double pin that wins material.","The rooks clear off, then the queen pins a piece two ways.","Rook takes on e1 — starting the winning cross-pin."],"hr":["Zamjena na ključnoj liniji stvara dvostruku vezu koja osvaja materijal.","Topovi se uklanjaju, zatim dama dvostruko veže figuru.","Top uzima na e1 — započinje pobjedničku unakrsnu vezu."]}', HintsVersion=1 WHERE LineId LIKE '%:007.046' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt in der Luft, gestützt auf eine Fesselung.","Der Turm gibt sich her, dann fesselt er den Verteidiger tödlich.","Turm schlägt auf f7 – beginnt das erzwungene Matt."],"en":["A forced mate is in the air, resting on a pin.","The rook offers itself, then pins the defender fatally.","Rook takes on f7 — starting the forced mate."],"hr":["U zraku je prisilni mat, oslonjen na vezu.","Top se nudi, zatim smrtonosno veže branitelja.","Top uzima na f7 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:007.047' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Achtung: das verlockende Eindringen scheitert – aber die richtige Folge gewinnt Material durch eine Fesselung.","Der Turm dringt ein und nutzt eine gefesselte Figur als schwachen Verteidiger.","Turm nach d3 – leitet den materialgewinnenden Plan ein."],"en":["Beware the tempting raid — the correct sequence wins material via a pin.","The rook penetrates and exploits a pinned, weak defender.","Rook to d3 — starting the material-winning plan."],"hr":["Pozor: primamljivi upad ne uspijeva, ali ispravan slijed vezom osvaja materijal.","Top prodire i iskorištava vezanu, slabu figuru.","Top na d3 — započinje plan koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.048' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Vorsicht: das naheliegende Eindringen gewinnt durch eine geschickte Gegenfesselung Material.","Der Turm stößt vor, doch eine Gegenfesselung kehrt den Spieß um.","Turm nach c2 – beginnt die Folge, die Material gewinnt."],"en":["Take care: the obvious raid wins material through a clever counter-pin.","The rook pushes in, but a counter-pin turns the tables.","Rook to c2 — starting the line that wins material."],"hr":["Oprez: očiti upad protuvezom osvaja materijal.","Top prodire, no protuveza okreće stvari.","Top na c2 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.049' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Vorsicht beim verlockenden Schlag – die richtige Idee gewinnt durch eine Kreuzfesselung Material.","Der Läufer schlägt ins Zentrum, danach entscheidet eine Kreuzfesselung.","Läufer schlägt auf e4 – leitet den Materialgewinn ein."],"en":["Beware the tempting capture — the right idea wins material via a cross-pin.","The bishop takes in the center, then a cross-pin decides.","Bishop takes on e4 — starting the material gain."],"hr":["Pozor na primamljivu žrtvu — prava ideja unakrsnom vezom osvaja materijal.","Lovac uzima u centru, zatim odlučuje unakrsna veza.","Lovac uzima na e4 — započinje osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:007.050' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer auf zentraler Linie gewinnt durch eine Fesselung Material.","Der Turm gibt sich, dann nagelt der zweite Turm die Dame fest.","Turm schlägt auf d5 – beginnt die materialgewinnende Folge."],"en":["A sacrifice on the central file wins material via a pin.","One rook gives itself, then the other pins the queen down.","Rook takes on d5 — starting the material-winning line."],"hr":["Žrtva na središnjoj liniji vezom osvaja materijal.","Jedan top se nudi, zatim drugi prikiva damu.","Top uzima na d5 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.051' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmschlag eröffnet eine Kreuzfesselung, die Material gewinnt.","Der Turm schlägt, dann fesselt ein zweiter die gegnerische Figur tödlich.","Turm schlägt auf c7 – leitet die gewinnende Kreuzfesselung ein."],"en":["A rook capture opens a cross-pin that wins material.","The rook takes, then a second rook pins the enemy piece fatally.","Rook takes on c7 — starting the winning cross-pin."],"hr":["Žrtva topa otvara unakrsnu vezu koja osvaja materijal.","Top uzima, zatim drugi smrtonosno veže protivničku figuru.","Top uzima na c7 — započinje pobjedničku unakrsnu vezu."]}', HintsVersion=1 WHERE LineId LIKE '%:007.052' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt entsteht aus einer Kreuzfesselung.","Die Dame dringt vor, dann hält eine Fesselung den Verteidiger fest.","Dame nach e6 – beginnt das erzwungene Matt."],"en":["A forced mate grows out of a cross-pin.","The queen advances, then a pin freezes the defender.","Queen to e6 — starting the forced mate."],"hr":["Iz unakrsne veze izrasta prisilni mat.","Dama napreduje, zatim veza zamrzava branitelja.","Dama na e6 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:007.053' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit, getragen von einer Kreuzfesselung.","Der Läufer schlägt, dann verstrickt eine Fesselung den weißen König.","Läufer schlägt auf f5 – beginnt das erzwungene Matt."],"en":["A forced mate is ready, carried by a cross-pin.","The bishop captures, then a pin entangles the white king.","Bishop takes on f5 — starting the forced mate."],"hr":["Spreman je prisilni mat, nošen unakrsnom vezom.","Lovac uzima, zatim veza zaplete bijelog kralja.","Lovac uzima na f5 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:007.054' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springerschlag öffnet die Stellung und gewinnt durch eine Kreuzfesselung Material.","Der Springer schlägt, danach fesselt die Dame eine Figur entscheidend.","Springer schlägt auf c6 – leitet den Materialgewinn ein."],"en":["A knight capture cracks the position and wins material via a cross-pin.","The knight takes, then the queen pins a piece decisively.","Knight takes on c6 — starting the material gain."],"hr":["Žrtva skakača otvara poziciju i unakrsnom vezom osvaja materijal.","Skakač uzima, zatim dama odlučujuće veže figuru.","Skakač uzima na c6 — započinje osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:007.055' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferschlag schafft eine dauerhafte Fesselung, die zum Vorteil führt.","Der Läufer schlägt, dann hält eine ewige Fesselung die Figur gefangen.","Läufer schlägt auf g7 – beginnt die vorteilbringende Folge."],"en":["A bishop capture creates a lasting pin that brings a decisive edge.","The bishop takes, then an eternal pin holds the piece captive.","Bishop takes on g7 — starting the advantageous line."],"hr":["Žrtva lovca stvara trajnu vezu koja donosi prednost.","Lovac uzima, zatim vječna veza drži figuru zarobljenom.","Lovac uzima na g7 — započinje slijed koji donosi prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:007.056' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferschlag erzwingt eine dauerhafte Fesselung mit klarem Vorteil.","Der Läufer schlägt, dann hält eine ewige Fesselung den König fest.","Läufer schlägt auf g7 – leitet den entscheidenden Vorteil ein."],"en":["A bishop capture forces a permanent pin with a clear edge.","The bishop takes, then an eternal pin ties the king down.","Bishop takes on g7 — starting the decisive advantage."],"hr":["Žrtva lovca prisiljava trajnu vezu s jasnom prednošću.","Lovac uzima, zatim vječna veza vezuje kralja.","Lovac uzima na g7 — započinje odlučujuću prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:007.057' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springerschlag bahnt den Weg zu einer ewigen Fesselung und Materialgewinn.","Der Springer schlägt zuerst, dann arbeiten Turm und Läufer an der Fesselung.","Springer schlägt auf d5 – beginnt die materialgewinnende Folge."],"en":["A knight capture paves the way to an eternal pin and material.","The knight takes first, then rook and bishop work the pin.","Knight takes on d5 — starting the material-winning line."],"hr":["Žrtva skakača otvara put vječnoj vezi i osvajanju materijala.","Skakač prvo uzima, zatim top i lovac rade na vezi.","Skakač uzima na d5 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.058' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernstoß im Zentrum gewinnt durch eine Fesselung Material.","Der Bauer stößt vor und nutzt eine festgenagelte Figur aus.","Bauer nach d5 – leitet den Materialgewinn ein."],"en":["A central pawn push wins material by exploiting a pin.","The pawn advances and skewers a pinned, helpless piece.","Pawn to d5 — starting the material gain."],"hr":["Središnji potez pijuna vezom osvaja materijal.","Pijun napreduje i iskorištava vezanu figuru.","Pijun na d5 — započinje osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:007.059' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springerschlag öffnet eine Fesselung, die entscheidend Material gewinnt.","Der Springer schlägt zuerst, dann nagelt der Turm eine Figur fest.","Springer schlägt auf b6 – beginnt die materialgewinnende Folge."],"en":["A knight capture opens a pin that wins decisive material.","The knight takes first, then the rook nails a piece down.","Knight takes on b6 — starting the material-winning line."],"hr":["Žrtva skakača otvara vezu koja osvaja odlučujući materijal.","Skakač prvo uzima, zatim top prikiva figuru.","Skakač uzima na b6 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.060' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer im Zentrum gewinnt durch eine Fesselung Material.","Der Turm gibt sich her, dann entscheidet ein vorrückender Bauer in der Fesselung.","Turm schlägt auf d5 – leitet den Materialgewinn ein."],"en":["A central rook sacrifice wins material via a pin.","The rook gives itself, then an advancing pawn exploits the pin.","Rook takes on d5 — starting the material gain."],"hr":["Žrtva topa u centru vezom osvaja materijal.","Top se nudi, zatim pijun u vezi odlučuje.","Top uzima na d5 — započinje osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:007.061' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag auf der offenen Linie leitet eine Folge ein, die Material gewinnt.","Der Turm schlägt, dann nutzt das Zusammenspiel der Schwerfiguren eine Fesselung.","Turm schlägt auf h6 – beginnt die materialgewinnende Folge."],"en":["A capture on the open file starts a sequence that wins material.","The rook takes, then the heavy pieces exploit a pin together.","Rook takes on h6 — starting the material-winning line."],"hr":["Žrtva na otvorenoj liniji započinje slijed koji osvaja materijal.","Top uzima, zatim teške figure zajedno iskorištavaju vezu.","Top uzima na h6 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.062' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenmanöver gewinnt durch eine Fesselung entscheidend Material.","Die Dame zieht vor, dann holt ein Springer in der Fesselung die Beute.","Dame nach f4 – leitet den Materialgewinn ein."],"en":["A queen maneuver wins decisive material via a pin.","The queen steps forward, then a knight in the pin grabs the prize.","Queen to f4 — starting the material gain."],"hr":["Manevar dame vezom osvaja odlučujući materijal.","Dama kreće naprijed, zatim skakač u vezi uzima plijen.","Dama na f4 — započinje osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:007.063' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernstoß sprengt die Stellung und gewinnt durch eine Fesselung Material.","Der Vorstoß räumt, dann fesselt der Läufer eine Figur entscheidend.","Bauer nach d4 – beginnt die materialgewinnende Folge."],"en":["A pawn break cracks the position and wins material via a pin.","The push clears the way, then the bishop pins a piece decisively.","Pawn to d4 — starting the material-winning line."],"hr":["Prodor pijuna otvara poziciju i vezom osvaja materijal.","Potez pijuna raščišćava, zatim lovac odlučujuće veže figuru.","Pijun na d4 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.064' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer beim König gewinnt durch eine Fesselung Material.","Der Läufer schlägt zuerst, dann arbeitet die zweite Figur in der Fesselung.","Läufer schlägt auf g2 – leitet die materialgewinnende Folge ein."],"en":["A capture near the king wins material via a pin.","The bishop takes first, then the other piece works the pin.","Bishop takes on g2 — starting the material-winning line."],"hr":["Žrtva blizu kralja vezom osvaja materijal.","Lovac prvo uzima, zatim druga figura radi na vezi.","Lovac uzima na g2 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.065' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die gegnerische Dame steckt fest – mit den richtigen Zügen fällt sie.","Der Turm dringt ein und schneidet der gefangenen Dame die letzten Felder ab.","Turm nach e5 – beginnt die Folge, die die Dame fängt."],"en":["The enemy queen is stuck — with the right moves she falls.","The rook penetrates and cuts off the trapped queen''s last squares.","Rook to e5 — starting the line that traps the queen."],"hr":["Protivnička dama je zarobljena — pravim potezima pada.","Top prodire i oduzima zarobljenoj dami zadnja polja.","Top na e5 — započinje slijed koji hvata damu."]}', HintsVersion=1 WHERE LineId LIKE '%:008.003' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwarze Dame am Rand lässt sich mit Tempogewinn einfangen.","Der König marschiert mit Drohungen heran und schnürt die Dame ein.","König nach c5 – beginnt die Folge, die die Dame fängt."],"en":["The black queen on the edge can be trapped with tempo.","The king marches up with threats and boxes the queen in.","King to c5 — starting the line that traps the queen."],"hr":["Crna dama na rubu može se uhvatiti uz dobitak tempa.","Kralj prilazi s prijetnjama i zatvara damu.","Kralj na c5 — započinje slijed koji hvata damu."]}', HintsVersion=1 WHERE LineId LIKE '%:008.004' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein durchgelaufener Bauer und ein eingesperrter Turm bringen entscheidenden Vorteil.","Der Turm schneidet zuerst dem gegnerischen Turm die Grundreihe ab.","Turm nach f8 – beginnt die Folge, die den Turm einfängt."],"en":["A passed pawn and a boxed-in rook bring a decisive edge.","The rook first shuts the enemy rook off from the back rank.","Rook to f8 — starting the line that traps the rook."],"hr":["Prolazni pijun i zatvoreni top donose odlučujuću prednost.","Top prvo odsijeca protivničkom topu zadnju liniju.","Top na f8 — započinje slijed koji hvata topa."]}', HintsVersion=1 WHERE LineId LIKE '%:008.005' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine ablenkende Idee fängt die gegnerische Dame ein und gewinnt Material.","Der Läufer manövriert, am Ende ist die Dame in der Falle.","Läufer nach d3 – beginnt die Folge, die die Dame fängt."],"en":["A deflecting idea traps the enemy queen and wins material.","The bishop maneuvers, and in the end the queen is caught.","Bishop to d3 — starting the line that traps the queen."],"hr":["Odvlačeća ideja hvata protivničku damu i osvaja materijal.","Lovac manevrira, a na kraju je dama u zamci.","Lovac na d3 — započinje slijed koji hvata damu."]}', HintsVersion=1 WHERE LineId LIKE '%:008.006' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Lockopfer treibt die gegnerische Dame in die Falle.","Der Turm bietet sich an, dann sperrt ein Vorstoß die Dame ein.","Turm nach a6 – beginnt die Folge, die die Dame fängt."],"en":["A luring sacrifice drives the enemy queen into a trap.","The rook offers itself, then a thrust seals the queen in.","Rook to a6 — starting the line that traps the queen."],"hr":["Mamac tjera protivničku damu u zamku.","Top se nudi, zatim potez zatvara damu.","Top na a6 — započinje slijed koji hvata damu."]}', HintsVersion=1 WHERE LineId LIKE '%:008.007' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer lockt den König heraus und fängt eine Figur ein.","Der Läufer opfert sich, dann jagt der Springer die gegnerische Figur in die Falle.","Läufer schlägt auf f7 – beginnt die Folge, die Material gewinnt."],"en":["A sacrifice draws the king out and traps a piece.","The bishop offers itself, then the knight hunts a piece into a trap.","Bishop takes on f7 — starting the line that wins material."],"hr":["Žrtva izvlači kralja i hvata figuru.","Lovac se žrtvuje, zatim skakač tjera figuru u zamku.","Lovac uzima na f7 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.008' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Der Bauer wird geopfert, um eine gegnerische Figur einzufangen.","Bauer nach f4 – leitet die gewinnbringende Kombination ein."],"en":["A combination wins decisive material.","Sacrifice the pawn to ensnare an enemy piece.","Pawn to f4 — starting the winning combination."],"hr":["Kombinacija osvaja odlučujući materijal.","Žrtvuj pješaka da uhvatiš protivničku figuru.","Pješak na f4 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:008.009' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur lässt sich auf dem Brett einsperren.","Locke die feindliche Dame in ein Netz, das sie nicht mehr verlässt.","Bauer nach c3 – treibt die Dame in die Falle."],"en":["A piece can be hunted down and trapped.","Lure the enemy queen into a net she cannot escape.","Pawn to c3 — driving the queen into the trap."],"hr":["Figura se može uloviti na ploči.","Namami protivničku damu u mrežu iz koje nema izlaza.","Pješak na c3 — tjera damu u zamku."]}', HintsVersion=1 WHERE LineId LIKE '%:008.010' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine gegnerische Figur lässt sich gewinnbringend einfangen.","Ein Bauernzug am Rand fixiert die feindliche Figur.","Bauer nach a5 – beginnt das Einfangen der Figur."],"en":["An enemy piece can be trapped for material gain.","A pawn push on the wing pins the enemy piece down.","Pawn to a5 — beginning to trap the piece."],"hr":["Protivnička figura može se uloviti za dobitak.","Potez pješaka na krilu prikiva protivničku figuru.","Pješak na a5 — započinje hvatanje figure."]}', HintsVersion=1 WHERE LineId LIKE '%:008.011' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Erst ein Tausch, dann schlägt ein Läufer im Zentrum durch.","Läufer schlägt auf f6 – Auftakt zum Materialgewinn."],"en":["A combination wins decisive material.","Trade first, then a bishop breaks through in the center.","Bishop takes on f6 — the prelude to winning material."],"hr":["Kombinacija osvaja odlučujući materijal.","Prvo zamjena, zatim lovac probija u centru.","Lovac uzima na f6 — uvod u osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:008.012' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Ein Turmopfer lockt einen Bauern, dann fängt der Springer eine Figur.","Turm schlägt auf c6 – Beginn der gewinnenden Kombination."],"en":["A combination wins decisive material.","A rook offer lures a pawn, then a knight traps a piece.","Rook takes on c6 — starting the winning combination."],"hr":["Kombinacija osvaja odlučujući materijal.","Žrtva topa namami pješaka, pa skakač lovi figuru.","Top uzima na c6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:008.013' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Ein Springer verjagt die Dame, dann wird ein Läufer eingefangen.","Springer nach c4 – leitet den Materialgewinn ein."],"en":["A combination wins decisive material.","A knight chases the queen, then a bishop gets trapped.","Knight to c4 — starting the material win."],"hr":["Kombinacija osvaja odlučujući materijal.","Skakač tjera damu, pa se lovac uhvati u zamku.","Skakač na c4 — započinje osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:008.014' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Ein Abtausch am Rand öffnet den Weg, um eine Figur zu fangen.","Bauer schlägt auf b5 – beginnt die gewinnende Kombination."],"en":["A combination wins decisive material.","A swap on the wing clears the path to trap a piece.","Pawn takes on b5 — starting the winning combination."],"hr":["Kombinacija osvaja odlučujući materijal.","Zamjena na krilu otvara put za hvatanje figure.","Pješak uzima na b5 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:008.015' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Ein Turmopfer lenkt die Verteidigung ab und fängt eine Figur.","Turm schlägt auf b7 – Auftakt der gewinnenden Folge."],"en":["A combination wins decisive material.","A rook sacrifice deflects the defense and traps a piece.","Rook takes on b7 — the start of the winning sequence."],"hr":["Kombinacija osvaja odlučujući materijal.","Žrtva topa odvlači obranu i lovi figuru.","Top uzima na b7 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:008.016' AND BookFileName='chessable-u5-21646.pgn';
