UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug fängt eine Figur ein.","Der Läufer nimmt dem Turm die Fluchtfelder und schließt das Netz.","Läufer nach c5 – nimmt dem Turm die Felder und gewinnt Material."],"en":["A quiet move traps a piece.","The bishop takes away the rook''s escape squares and seals the net.","Bishop to c5 — removes the rook''s squares and wins material."],"hr":["Tihi potez lovi figuru.","Lovac oduzima topu polja za bijeg i zatvara mrežu.","Lovac na c5 — oduzima topu polja i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.055' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug bereitet den Materialgewinn vor.","Der Läufer manövriert, dann fängt der Turm die feindliche Figur.","Läufer nach d7 – beginnt die materialgewinnende Folge."],"en":["A quiet move sets up the win of material.","The bishop maneuvers, then the rook nets the enemy piece.","Bishop to d7 — begins the material-winning sequence."],"hr":["Tihi potez priprema osvajanje materijala.","Lovac manevrira, a zatim top lovi protivničku figuru.","Lovac na d7 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.056' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug fängt eine Figur ein.","Der Läufer zieht sich zurück und engt die gegnerische Dame ein.","Läufer nach f8 – nimmt der Dame die Felder und gewinnt Material."],"en":["A quiet move traps a piece.","The bishop retreats and boxes in the enemy queen.","Bishop to f8 — takes squares from the queen and wins material."],"hr":["Tihi potez lovi figuru.","Lovac se povlači i stišnjava protivničku damu.","Lovac na f8 — oduzima dami polja i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.057' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug fängt die feindliche Dame.","Ein Bauer nimmt der Dame ein Fluchtfeld, dann schnappt das Netz zu.","Bauer nach a3 – beginnt die Folge, die die Dame fängt."],"en":["A quiet move traps the enemy queen.","A pawn removes one of the queen''s escape squares, then the net closes.","Pawn to a3 — begins the line that snares the queen."],"hr":["Tihi potez lovi protivničku damu.","Pješak oduzima dami polje za bijeg, a zatim se mreža zatvara.","Pješak na a3 — započinje slijed koji lovi damu."]}', HintsVersion=1 WHERE LineId LIKE '%:008.058' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug fängt eine Figur ein.","Die Dame zieht ruhig um und das feindliche Schwergewicht steckt fest.","Dame nach c2 – fängt die Figur und gewinnt Material."],"en":["A quiet move traps a piece.","The queen calmly reroutes and the enemy heavyweight is stuck.","Queen to c2 — traps the piece and wins material."],"hr":["Tihi potez lovi figuru.","Dama se mirno premješta i protivnička teška figura ostaje zarobljena.","Dama na c2 — lovi figuru i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.059' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug fängt die gegnerische Dame.","Die Dame nimmt der feindlichen Dame die Fluchtfelder.","Dame nach d7 – nimmt der Dame die Felder und gewinnt sie."],"en":["A quiet move traps the enemy queen.","The queen takes away the hostile queen''s escape squares.","Queen to d7 — removes the queen''s squares and wins it."],"hr":["Tihi potez lovi protivničku damu.","Dama oduzima neprijateljskoj dami polja za bijeg.","Dama na d7 — oduzima dami polja i osvaja je."]}', HintsVersion=1 WHERE LineId LIKE '%:008.060' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug ermöglicht den Materialgewinn.","Der Turm tritt zur Seite und bereitet das Manöver vor, das eine Figur fängt.","Turm nach f8 – beginnt die materialgewinnende Folge."],"en":["A quiet move enables the win of material.","The rook steps aside to prepare the maneuver that nets a piece.","Rook to f8 — begins the material-winning sequence."],"hr":["Tihi potez omogućuje osvajanje materijala.","Top se sklanja da pripremi manevar koji lovi figuru.","Top na f8 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.061' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur lässt sich durch eine Kombination gewinnen.","Der Läufer schlägt ein, dann fängt ein Springer die Figur.","Läufer schlägt auf d3 – beginnt die materialgewinnende Folge."],"en":["A piece can be won through a combination.","The bishop strikes, then a knight traps the piece.","Bishop takes on d3 — begins the material-winning sequence."],"hr":["Figura se može osvojiti kombinacijom.","Lovac udara, a zatim skakač lovi figuru.","Lovac uzima na d3 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.062' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur lässt sich durch ein Opfer gewinnen.","Der Läufer schlägt sich frei, dann fängt der Turm die gefesselte Figur.","Läufer schlägt auf f2 – beginnt die Folge, die die Dame fängt."],"en":["A piece can be won via a sacrifice.","The bishop crashes through, then the rook traps the pinned defender.","Bishop takes on f2 — begins the line that snares the queen."],"hr":["Figura se može osvojiti žrtvom.","Lovac probija, a zatim top lovi vezanu figuru.","Lovac uzima na f2 — započinje slijed koji lovi damu."]}', HintsVersion=1 WHERE LineId LIKE '%:008.063' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur lässt sich einfangen und gewinnen.","Der Läufer greift an und treibt die Folge voran, die Material bringt.","Läufer nach b4 – beginnt die materialgewinnende Kombination."],"en":["A piece can be cornered and won.","The bishop attacks and drives the material-winning sequence.","Bishop to b4 — begins the material-winning combination."],"hr":["Figura se može uloviti i osvojiti.","Lovac napada i pokreće slijed koji donosi materijal.","Lovac na b4 — započinje kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.064' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur lässt sich durch Rückzug und Vortreiben gewinnen.","Der Springer geht zurück, dann wird die feindliche Figur in die Falle gelockt.","Springer nach b8 – beginnt die Folge, die Material gewinnt."],"en":["A piece can be won by retreating and then driving it back.","The knight steps back, then the enemy piece is lured into the trap.","Knight to b8 — begins the line that wins material."],"hr":["Figura se može osvojiti povlačenjem pa potjerivanjem.","Skakač se vraća, a zatim se protivnička figura mami u zamku.","Skakač na b8 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.065' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur lässt sich durch Vortreiben gewinnen.","Ein Läufer und ein Bauernstoß setzen die feindliche Dame unter Druck.","Läufer nach g5 – beginnt die Folge, die die Dame fängt."],"en":["A piece can be won by driving it back.","A bishop and a pawn thrust pressure the enemy queen.","Bishop to g5 — begins the line that snares the queen."],"hr":["Figura se može osvojiti potjerivanjem.","Lovac i udar pješaka pritišću protivničku damu.","Lovac na g5 — započinje slijed koji lovi damu."]}', HintsVersion=1 WHERE LineId LIKE '%:008.066' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer leitet einen Angriff ein, der eine Figur fängt.","Der Läufer schlägt ein, dann jagt ein Springer das Ziel.","Läufer schlägt auf f7 – beginnt die materialgewinnende Kombination."],"en":["A sacrifice launches an attack that nets a piece.","The bishop strikes, then a knight hunts the target down.","Bishop takes on f7 — begins the material-winning combination."],"hr":["Žrtva pokreće napad koji lovi figuru.","Lovac udara, a zatim skakač progoni metu.","Lovac uzima na f7 — započinje kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.067' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer öffnet den Weg, eine Figur zu fangen.","Der Turm schlägt ein, dann engt ein Läufer das Ziel ein.","Turm schlägt auf a7 – beginnt die materialgewinnende Folge."],"en":["A sacrifice opens the way to trap a piece.","The rook strikes, then a bishop hems the target in.","Rook takes on a7 — begins the material-winning sequence."],"hr":["Žrtva otvara put za hvatanje figure.","Top udara, a zatim lovac stišnjava metu.","Top uzima na a7 — započinje slijed koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:008.068' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt hier Material – such den taktischen Bruch.","Der Läufer leitet alles ein, danach übernehmen die Schwerfiguren auf der offenen Linie.","Läufer schlägt auf f5 – Beginn der gewinnbringenden Folge."],"en":["A combination wins material here — look for the tactical break.","The bishop sets it in motion, then the heavy pieces take over on the open file.","Bishop takes on f5 — the start of the winning sequence."],"hr":["Kombinacija ovdje osvaja materijal — potraži taktički prodor.","Lovac sve pokreće, a potom teške figure preuzimaju na otvorenoj liniji.","Lovac uzima na f5 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:008.069' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit einem präzisen Zug lässt sich gegnerisches Material erobern.","Die Dame ergreift die Initiative und holt sich einen eingedrungenen Springer.","Dame nach b3 – schlägt den Springer und eröffnet die Gewinnfolge."],"en":["A precise move lets you scoop up enemy material.","The queen seizes the initiative and collects a stranded knight.","Queen to b3 — takes the knight and opens the winning line."],"hr":["Preciznim potezom može se zaplijeniti protivnički materijal.","Dama preuzima inicijativu i kupi zalutalog skakača.","Dama na b3 — uzima skakača i otvara dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:008.070' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Wendung verschafft hier einen entscheidenden materiellen Vorteil.","Der Springer öffnet die Stellung und die Dame folgt zum Beutezug.","Springer schlägt auf e4 – Auftakt der vorteilbringenden Folge."],"en":["A turn here yields a decisive material edge.","The knight pries the position open and the queen follows for the haul.","Knight takes on e4 — the opening of the advantageous line."],"hr":["Obrat ovdje donosi odlučujuću materijalnu prednost.","Skakač otvara poziciju, a dama slijedi po plijen.","Skakač uzima na e4 — uvod u povoljni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:008.071' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein scharfer Zug gewinnt hier klar an Material.","Der Läufer geht aktiv vor und nutzt die ungedeckte Schwerfigur.","Läufer nach g4 – Beginn der gewinnträchtigen Folge."],"en":["A sharp move clearly wins material here.","The bishop steps up actively and exploits the loose heavy piece.","Bishop to g4 — the start of the winning sequence."],"hr":["Oštar potez ovdje jasno osvaja materijal.","Lovac aktivno istupa i iskorištava nezaštićenu tešku figuru.","Lovac na g4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:008.072' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination erobert hier einen entscheidenden Vorteil.","Der Läufer schlägt zu und lockt eine Figur in die Falle.","Läufer schlägt auf h6 – Auftakt der vorteilbringenden Folge."],"en":["A combination wins a decisive advantage here.","The bishop strikes and lures a piece into the trap.","Bishop takes on h6 — the start of the advantageous line."],"hr":["Kombinacija ovdje osvaja odlučujuću prednost.","Lovac udara i mami figuru u zamku.","Lovac uzima na h6 — uvod u povoljni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:008.073' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein kühner Zug bringt hier entscheidenden materiellen Gewinn.","Der Springer dringt ein und stört die feindliche Koordination.","Springer nach c6 – Beginn der vorteilbringenden Folge."],"en":["A bold move brings a decisive material gain here.","The knight invades and disrupts the enemy coordination.","Knight to c6 — the start of the advantageous line."],"hr":["Smion potez ovdje donosi odlučujući materijalni dobitak.","Skakač upada i remeti protivničku koordinaciju.","Skakač na c6 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:008.074' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit Tempo lässt sich der Bauer trotz Gegendrohung zur Umwandlung führen.","Die hintere Schwerfigur schlägt mit Abzugsschach und macht den Weg frei.","Turm schlägt auf d4 – Auftakt der vorteilbringenden Folge."],"en":["With tempo the pawn can be steered to promotion despite the counterthreat.","The back heavy piece captures with discovered check and clears the path.","Rook takes on d4 — the start of the advantageous line."],"hr":["S tempom se pješak može dovesti do promocije unatoč protivnoj prijetnji.","Stražnja teška figura uzima s otkrivenim šahom i čisti put.","Top uzima na d4 — uvod u povoljni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:009.003' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zug treibt den König so, dass danach ein Spieß folgt.","Der Turm setzt den Plan in Gang und bereitet den Doppelangriff vor.","Turm nach a2 – Beginn der vorteilbringenden Folge."],"en":["A move drives the king so that a skewer follows next.","The rook sets the plan in motion and prepares the double hit.","Rook to a2 — the start of the advantageous line."],"hr":["Potez tjera kralja tako da slijedi ražanj.","Top pokreće plan i priprema dvostruki udar.","Top na a2 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.004' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Freibauer kann auch im Mittelspiel verheerend wirken – nutze ihn.","Der vorgeschobene Bauer ist der Held, gestützt durch einen Doppelangriff.","Bauer nach b3 – Auftakt der vorteilbringenden Folge."],"en":["A passed pawn can be devastating even in the middlegame — use it.","The advanced pawn is the hero, backed by a double attack.","Pawn to b3 — the start of the advantageous line."],"hr":["Slobodni pješak može biti razoran i u sredini igre — iskoristi ga.","Napredni pješak je junak, potpomognut dvostrukim napadom.","Pješak na b3 — uvod u povoljni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:009.005' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Locke einen Verteidiger weg, um den Bauern durchzubringen.","Die Dame opfert sich, um die Bahn für den Bauern zu räumen.","Dame schlägt auf e3 – Beginn der vorteilbringenden Folge."],"en":["Lure a defender away to push the pawn through.","The queen sacrifices herself to clear the lane for the pawn.","Queen takes on e3 — the start of the advantageous line."],"hr":["Odmami branitelja kako bi pješak prošao.","Dama se žrtvuje da očisti put pješaku.","Dama uzima na e3 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.006' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsopfer ebnet dem Bauern den Weg.","Die Dame zieht den gegnerischen Schwerfiguren-Wächter beiseite.","Dame nach g5 – Auftakt der vorteilbringenden Folge."],"en":["A deflection sacrifice paves the way for the pawn.","The queen pulls the heavy guard aside.","Queen to g5 — the start of the advantageous line."],"hr":["Žrtva odvlačenja krči put pješaku.","Dama odmiče teškog čuvara u stranu.","Dama na g5 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.007' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Locke den Verteidiger weg, dann läuft der Bauer durch.","Die Dame opfert sich, um die feindliche Hauptfigur abzulenken.","Dame schlägt auf g7 – Beginn der vorteilbringenden Folge."],"en":["Lure the defender away, then the pawn marches through.","The queen sacrifices to deflect the main enemy piece.","Queen takes on g7 — the start of the advantageous line."],"hr":["Odmami branitelja, pa pješak prolazi.","Dama se žrtvuje da odvuče glavnu protivničku figuru.","Dama uzima na g7 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.008' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Räume den Verteidiger weg, um den Bauern zu krönen.","Die Dame opfert sich und lockt die gegnerische Dame fort.","Dame nach d8 – Auftakt der vorteilbringenden Folge."],"en":["Clear the defender to crown the pawn.","The queen sacrifices herself and lures the enemy queen away.","Queen to d8 — the start of the advantageous line."],"hr":["Ukloni branitelja da okruniš pješaka.","Dama se žrtvuje i odmami protivničku damu.","Dama na d8 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.009' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Vorsicht – das naheliegende Schlagen verschenkt den Gewinn; finde das Bessere.","Der Turm droht zugleich eine Figur und das Umwandlungsfeld.","Turm schlägt auf f2 – Beginn der vorteilbringenden Folge."],"en":["Careful — the obvious capture throws away the win; find the better way.","The rook threatens both a piece and the promotion square.","Rook takes on f2 — the start of the advantageous line."],"hr":["Oprez — očito uzimanje propušta dobitak; nađi bolje.","Top istovremeno prijeti figuri i polju promocije.","Top uzima na f2 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.010' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Locke die feindlichen Steine weg, um einen Bauern umzuwandeln.","Der weit vorgerückte Bauer führt, gestützt vom Mitstreiter.","Bauer nach d7 – Auftakt der vorteilbringenden Folge."],"en":["Lure the enemy pieces away to promote a pawn.","The far-advanced pawn leads, supported by its partner.","Pawn to d7 — the start of the advantageous line."],"hr":["Odmami protivničke figure kako bi promovirao pješaka.","Daleko napredni pješak vodi, uz potporu suborca.","Pješak na d7 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.011' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsopfer bringt den Freibauern durch.","Die Dame opfert sich, um den gegnerischen Wächter wegzulocken.","Dame schlägt auf e6 – Beginn der vorteilbringenden Folge."],"en":["A deflection sacrifice pushes the passer through.","The queen sacrifices to lure the enemy guard away.","Queen takes on e6 — the start of the advantageous line."],"hr":["Žrtva odvlačenja progura slobodnog pješaka.","Dama se žrtvuje da odmami protivničkog čuvara.","Dama uzima na e6 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.012' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke den Blockierer ab, um den Bauern durchzubringen.","Der Turm opfert sich, um den feindlichen Wächter fortzulocken.","Turm nach a3 – Auftakt der vorteilbringenden Folge."],"en":["Deflect the blocker to push the pawn through.","The rook sacrifices itself to lure the enemy guard away.","Rook to a3 — the start of the advantageous line."],"hr":["Odvuci blokatora kako bi pješak prošao.","Top se žrtvuje da odmami protivničkog čuvara.","Top na a3 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.013' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Locke die Verteidiger weg und führe den Bauern zur Umwandlung.","Die Dame opfert sich, um den gegnerischen Wächter abzulenken.","Dame schlägt auf b6 – Beginn der vorteilbringenden Folge."],"en":["Lure the defenders away and march the pawn home.","The queen sacrifices to deflect the enemy guard.","Queen takes on b6 — the start of the advantageous line."],"hr":["Odmami branitelje i dovedi pješaka do promocije.","Dama se žrtvuje da odvuče protivničkog čuvara.","Dama uzima na b6 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.014' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wird der Gegner durch Ablenkung mattgesetzt.","Der Läufer leitet das Opfer ein, das die Verteidiger wegzieht.","Läufer nach g5 – Beginn der erzwungenen Mattfolge."],"en":["The opponent is mated here through deflection.","The bishop launches the sacrifice that pulls the defenders away.","Bishop to g5 — the start of the forced mating line."],"hr":["Protivnik se ovdje matira odvlačenjem.","Lovac pokreće žrtvu koja odvlači branitelje.","Lovac na g5 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.015' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Räume die Linie frei, damit ein Bauer durchläuft.","Der vorgeschobene Bauer schlägt zu und beginnt eine Räumungskette.","Bauer schlägt auf e4 – Auftakt der vorteilbringenden Folge."],"en":["Clear the file so a pawn can run through.","The advanced pawn captures and starts a clearance chain.","Pawn takes on e4 — the start of the advantageous line."],"hr":["Očisti liniju da pješak protrči.","Napredni pješak uzima i započinje lanac čišćenja.","Pješak uzima na e4 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.016' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke den Verteidiger ab, um den eigenen Bauern durchzubringen.","Der Turm opfert sich, um die gegnerische Figur wegzulocken.","Turm schlägt auf h1 – Beginn der vorteilbringenden Folge."],"en":["Deflect the defender to push your pawn through.","The rook sacrifices itself to lure the enemy piece away.","Rook takes on h1 — the start of the advantageous line."],"hr":["Odvuci branitelja da progura vlastitog pješaka.","Top se žrtvuje da odmami protivničku figuru.","Top uzima na h1 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.017' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Locke die Deckung weg und bring den Bauern zur Umwandlung.","Der Springer schlägt zu und reißt die Königsdeckung auf.","Springer schlägt auf g6 – Auftakt der vorteilbringenden Folge."],"en":["Lure the cover away and run the pawn to promotion.","The knight captures and rips open the king''s cover.","Knight takes on g6 — the start of the advantageous line."],"hr":["Odmami zaštitu i dovedi pješaka do promocije.","Skakač uzima i razbija zaklon kralja.","Skakač uzima na g6 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.018' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Reihe von Opfern lockt die Verteidiger ab und der Freibauer läuft.","Der Turm opfert sich zuerst, dann öffnen weitere Schläge den Weg.","Turm schlägt auf g7 – Auftakt zur Ablenkung und Bekrönung."],"en":["A series of sacrifices lures the defenders away and the passer runs.","The rook sacrifices first, then further blows open the road.","Rook takes on g7 — starting the deflection toward promotion."],"hr":["Niz žrtava odvlači branitelje i prolaznik juri.","Top se prvi žrtvuje, a zatim daljnji udarci otvaraju put.","Top uzima na g7 — uvod u odvlačenje i promociju."]}', HintsVersion=1 WHERE LineId LIKE '%:009.019' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lenke den Blockierer ab, dann läuft der Freibauer durch.","Der Turm dringt ein und zwingt den König von der Deckung weg.","Turm nach c7 – Auftakt der vorteilbringenden Folge."],"en":["Deflect the blocker, then the passer runs through.","The rook invades and forces the king off the guard.","Rook to c7 — the start of the advantageous line."],"hr":["Odvuci blokatora, pa slobodni pješak protrči.","Top upada i tjera kralja s čuvanja.","Top na c7 — početak povoljnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.020' AND BookFileName='chessable-u5-21646.pgn';
