UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer öffnet die Grundreihe für den durchgebrochenen Bauern.","Der Turm opfert sich, um die letzte Verteidigung zu sprengen.","Turm schlägt auf g2 – Auftakt zur gewinnenden Umwandlung."],"en":["A rook sacrifice opens the back rank for the passed pawn.","The rook sacrifices itself to blow up the last line of defense.","Rook takes on g2 — the start of a winning promotion."],"hr":["Žrtva topa otvara zadnju liniju prolaznom pješaku.","Top se žrtvuje kako bi razbio posljednju obranu.","Top uzima na g2 — početak dobitne promocije."]}', HintsVersion=1 WHERE LineId LIKE '%:009.056' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die weit vorgerückte Bauernkraft entscheidet die Stellung zugunsten von Weiß.","Turm und gedeckter Freibauer arbeiten zusammen, der König muss nur sicher manövrieren.","Turm nach c8 – leitet die gewinnende Aktion ein."],"en":["Advanced pawn power tips the position decisively for White.","The rook and the protected passer cooperate while the king walks up safely.","Rook to c8 — starting the winning sequence."],"hr":["Daleko napredovala pješačka snaga odlučuje poziciju u korist bijelog.","Top i zaštićeni slobodnjak surađuju dok kralj sigurno napreduje.","Top na c8 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:009.057' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein kleiner taktischer Schlag verschafft einen entscheidenden Materialvorteil.","Der Läufer schlägt zu und der Freibauer am Rand wird unaufhaltsam.","Läufer schlägt auf d5 – Beginn der gewinnenden Kombination."],"en":["A small tactical strike yields a decisive material edge.","The bishop crashes through and the wing passer becomes unstoppable.","Bishop takes on d5 — beginning the winning combination."],"hr":["Mali taktički udar donosi odlučujuću materijalnu prednost.","Lovac probija, a krilni slobodnjak postaje nezaustavljiv.","Lovac uzima na d5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:009.058' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauerndurchbruch am Königsflügel entscheidet zugunsten von Schwarz.","Der Läufer lenkt eine Figur weg, damit der Freibauer durchläuft.","Bauer nach g4 – startet die gewinnende Aktion."],"en":["A kingside pawn breakthrough decides in Black''s favour.","The bishop lures a piece away so the passer can run.","Pawn to g4 — launching the winning sequence."],"hr":["Pješački proboj na kraljevom krilu odlučuje u korist crnog.","Lovac odvlači figuru kako bi slobodnjak protrčao.","Pješak na g4 — pokreće dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:009.059' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß bahnt sich den Weg zur Umwandlung.","Läufer und Freibauer setzen den Springer matt und schaffen Raum.","Bauer nach b4 – Beginn der gewinnenden Folge."],"en":["A pawn advance carves the path toward promotion.","The bishop and passed pawn outmuscle the knight and clear the way.","Pawn to b4 — beginning the winning line."],"hr":["Napredovanje pješaka krči put prema promociji.","Lovac i slobodnjak nadvladavaju skakača i otvaraju put.","Pješak na b4 — početak dobitne linije."]}', HintsVersion=1 WHERE LineId LIKE '%:009.060' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauerndurchbruch entscheidet die Stellung für Weiß.","Die Bauern reißen die Linie für die Umwandlung auf, der Läufer gewinnt das Tempo.","Bauer nach b5 – leitet den Durchbruch ein."],"en":["A pawn breakthrough decides the position for White.","The pawns tear open the promotion path while the bishop wins the key tempo.","Pawn to b5 — launching the breakthrough."],"hr":["Pješački proboj odlučuje poziciju za bijelog.","Pješaci razbijaju put do promocije dok lovac dobiva ključni tempo.","Pješak na b5 — pokreće proboj."]}', HintsVersion=1 WHERE LineId LIKE '%:009.061' AND BookFileName='chessable-u5-21646.pgn';
