UPDATE BookPuzzles SET HintsJson='{"de":["Trotz der Damen rettest du dich mit Dauerschach ins Remis.","Erst das Opfer, dann jagt die Dame den König ohne Ende.","Turm nach f8 – der Auftakt zum rettenden Dauerschach."],"en":["Despite the queens you save the draw with a perpetual.","Sacrifice first, then the queen hounds the king forever.","Rook to f8 — the start of the saving perpetual."],"hr":["Unatoč damama spašavaš remi vječitim šahom.","Najprije žrtva, zatim dama beskrajno progoni kralja.","Top na f8 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.027' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Rette das Remis mit einem nicht endenden Schachschauer.","Dame und Springer reichen sich beim Schachgeben die Hand.","Dame nach f1 – Beginn des rettenden Dauerschachs."],"en":["Save the draw with a never-ending shower of checks.","Queen and knight join forces to keep checking.","Queen to f1 — the start of the saving perpetual."],"hr":["Spasi remi beskrajnom kišom šahova.","Dama i skakač zajedno neprestano daju šah.","Dama na f1 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.028' AND BookFileName='chessable-u5-21646.pgn';
