UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorspiel mit dem Springer ebnet den Weg zum Remis.","Erst räumt der Springer ab, dann setzt die Dame ewig Schach.","Springer schlägt auf e6 – der Auftakt zum rettenden Dauerschach."],"en":["A knight prelude paves the way to the draw.","The knight clears first, then the queen checks forever.","Knight takes on e6 — the start of the saving perpetual."],"hr":["Uvod skakačem otvara put do remija.","Najprije skakač čisti, zatim dama vječito daje šah.","Skakač uzima na e6 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.030' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit Opfer und Dauerschach holst du das Remis.","Die Dame zwingt nach einem Turmopfer ewiges Schach herbei.","Dame nach e3 – der Auftakt zum rettenden Dauerschach."],"en":["With a sacrifice and a perpetual you grab the draw.","After a rook offer the queen forces endless checks.","Queen to e3 — the start of the saving perpetual."],"hr":["Žrtvom i vječitim šahom uzimaš remi.","Nakon žrtve topa dama prisiljava beskrajne šahove.","Dama na e3 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.031' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer leitet das rettende Dauerschach ein.","Nach dem Turmopfer treibt die Dame den König vor sich her.","Turm schlägt auf g7 – der Auftakt zum rettenden Dauerschach."],"en":["A sacrifice ushers in the saving perpetual.","After the rook offer the queen drives the king around.","Rook takes on g7 — the start of the saving perpetual."],"hr":["Žrtva uvodi spasonosni vječiti šah.","Nakon žrtve topa dama tjera kralja pred sobom.","Top uzima na g7 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.032' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier sicherst du das Remis durch ewiges Schach.","Springer und Dame setzen dem König ohne Pause zu.","Springer nach h6 – Beginn des rettenden Dauerschachs."],"en":["Here you secure the draw with eternal checks.","Knight and queen harry the king without pause.","Knight to h6 — the start of the saving perpetual."],"hr":["Ovdje osiguravaš remi vječitim šahom.","Skakač i dama bez predaha pritišću kralja.","Skakač na h6 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.033' AND BookFileName='chessable-u5-21646.pgn';
