UPDATE BookPuzzles SET HintsJson='{"de":["Rette dich mit Dauerschach ins Remis.","Die Dame verfolgt den König von Feld zu Feld.","Dame nach g2 – der Auftakt zum rettenden Dauerschach."],"en":["Save yourself into a draw with a perpetual.","The queen pursues the king from square to square.","Queen to g2 — the start of the saving perpetual."],"hr":["Spasi se u remi vječitim šahom.","Dama progoni kralja s polja na polje.","Dama na g2 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.036' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier liegt ein erzwungenes Matt in der Stellung.","Der Springer leitet den Mattangriff ein, die Dame vollendet ihn.","Springer nach e4 – Beginn der erzwungenen Mattführung."],"en":["A forced mate is hiding in this position.","The knight launches the attack and the queen finishes it.","Knight to e4 — the start of the forced mate."],"hr":["U poziciji se krije prisilni mat.","Skakač pokreće napad, a dama ga dovršava.","Skakač na e4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.037' AND BookFileName='chessable-u5-21646.pgn';
