UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet das rettende Dauerschach ein.","Die Dame schlägt sich frei und treibt den König vor sich her.","Dame schlägt auf h7 – der Auftakt zum rettenden Dauerschach."],"en":["A queen sacrifice ushers in the saving perpetual.","The queen clears the path and drives the king around.","Queen takes on h7 — the start of the saving perpetual."],"hr":["Žrtva dame uvodi spasonosni vječiti šah.","Dama se probija i tjera kralja pred sobom.","Dama uzima na h7 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.040' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer ebnet den Weg zum rettenden Dauerschach.","Nach den Abtäuschen jagt die Dame den entblößten König.","Turm schlägt auf g1 – der Auftakt zum rettenden Dauerschach."],"en":["A rook sacrifice paves the way to the saving perpetual.","After the trades the queen chases the exposed king.","Rook takes on g1 — the start of the saving perpetual."],"hr":["Žrtva topa otvara put spasonosnom vječitom šahu.","Nakon zamjena dama progoni izloženog kralja.","Top uzima na g1 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.041' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Damenendspiel hältst du dich mit Dauerschach ins Remis.","Die Dame setzt dem feindlichen König unermüdlich nach.","Bauer nach h4 – der Auftakt zum rettenden Dauerschach."],"en":["In the queen endgame you hold the draw with a perpetual.","The queen tirelessly pursues the enemy king.","Pawn to h4 — the start of the saving perpetual."],"hr":["U damskoj završnici držiš remi vječitim šahom.","Dama neumorno progoni protivničkog kralja.","Pješak na h4 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.042' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Damenendspiel rettest du dich mit ewigem Schach.","Die Dame jagt den König und kommt nie zur Ruhe.","Dame nach d5 – der Auftakt zum rettenden Dauerschach."],"en":["In the queen endgame you save yourself with eternal checks.","The queen hunts the king and never rests.","Queen to d5 — the start of the saving perpetual."],"hr":["U damskoj završnici spašavaš se vječitim šahom.","Dama lovi kralja i nikada ne miruje.","Dama na d5 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.043' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer leitet das rettende Dauerschach ein.","Nach dem Opfer treibt die Dame den König unaufhörlich umher.","Turm schlägt auf a2 – der Auftakt zum rettenden Dauerschach."],"en":["A rook sacrifice ushers in the saving perpetual.","After the offer the queen drives the king around endlessly.","Rook takes on a2 — the start of the saving perpetual."],"hr":["Žrtva topa uvodi spasonosni vječiti šah.","Nakon žrtve dama neprestano tjera kralja uokolo.","Top uzima na a2 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.044' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es ist kein Remis – hier steht ein erzwungenes Matt.","Dame und Bauer arbeiten zusammen am Mattnetz.","Dame nach f2 – Beginn der erzwungenen Mattführung."],"en":["It is no draw — a forced mate is on the board.","Queen and pawn combine to weave the mating net.","Queen to f2 — the start of the forced mate."],"hr":["Nije remi — ovdje stoji prisilni mat.","Dama i pješak zajedno pletu matnu mrežu.","Dama na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.045' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt der Falle hilft dir nur das Dauerschach zum Remis.","Erst geht der eigene König in Sicherheit, dann jagt die Dame.","König nach c2 – der Auftakt zum rettenden Dauerschach."],"en":["Instead of the trap only a perpetual holds the draw.","First your own king steps to safety, then the queen chases.","King to c2 — the start of the saving perpetual."],"hr":["Umjesto zamke samo te vječiti šah vodi do remija.","Najprije vlastiti kralj u sigurnost, zatim dama progoni.","Kralj na c2 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.046' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Nur Dauerschach rettet dich aus der schwächeren Lage ins Remis.","Der Turm verfolgt den König ohne Unterlass.","Turm nach c8 – der Auftakt zum rettenden Dauerschach."],"en":["Only a perpetual rescues your worse position into a draw.","The rook chases the king without letup.","Rook to c8 — the start of the saving perpetual."],"hr":["Samo te vječiti šah iz lošije pozicije vodi u remi.","Top progoni kralja bez prestanka.","Top na c8 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.047' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit Dauerschach hältst du die Partie im Remis.","Der Turm und der Läufer setzen dem König unermüdlich nach.","Turm nach d3 – der Auftakt zum rettenden Dauerschach."],"en":["With a perpetual you hold the game to a draw.","The rook and bishop hound the king tirelessly.","Rook to d3 — the start of the saving perpetual."],"hr":["Vječitim šahom držiš partiju u remiju.","Top i lovac neumorno pritišću kralja.","Top na d3 — početak spasonosnog vječitog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:010.048' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und musst dich ins Remis retten.","Der Turm sucht das rettende Patt am feindlichen König.","Turm nach c5 – der Auftakt zur Remisrettung."],"en":["You are worse and must scramble to save the draw.","The rook seeks the saving stalemate by the enemy king.","Rook to c5 — the start of the saving sequence."],"hr":["Slabiji si i moraš se spasiti u remi.","Top traži spasonosni pat uz protivničkog kralja.","Top na c5 — početak spašavanja remija."]}', HintsVersion=1 WHERE LineId LIKE '%:010.049' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du musst die Stellung mit einem Trick ins Remis halten.","Der Turm opfert sich und sucht das rettende Patt.","Turm schlägt auf b5 – der Auftakt zur Remisrettung."],"en":["You must hold the position to a draw with a trick.","The rook sacrifices itself in search of the saving stalemate.","Rook takes on b5 — the start of the saving sequence."],"hr":["Poziciju moraš održati u remiju trikom.","Top se žrtvuje tražeći spasonosni pat.","Top uzima na b5 — početak spašavanja remija."]}', HintsVersion=1 WHERE LineId LIKE '%:010.050' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Versuchung lockt, doch der naheliegende Schlag verliert – du musst hier mit Mühe das Remis retten.","Dein Springer steht vor einer Schicksalsfrage, und der Turm im Hintergrund entscheidet über das Halten.","Springer nach h3 – beginnt den Weg, der trotz allem zum Remis führt."],"en":["The obvious capture is a trap; you are worse and must scramble for a draw here.","Your knight faces a fateful choice, and the rook in the background decides whether you hold.","Knight to h3 — starts the line that still salvages the draw."],"hr":["Očiti udarac je zamka; u gorem si položaju i moraš se izboriti za remi.","Tvoj skakač pred sudbonosnim je izborom, a top u pozadini odlučuje hoćeš li održati.","Skakač na h3 — započinje liniju koja ipak spašava remi."]}', HintsVersion=1 WHERE LineId LIKE '%:010.051' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Gewinnversuch lockt, aber in Wahrheit musst du hier ums Remis kämpfen.","Dein Springer geht voran, doch der Turm muss sich ins Patt opfern, um zu halten.","Springer nach e3 – leitet die rettende Folge ein, die ins Patt mündet."],"en":["A win seems tempting, but in truth you must fight here just to draw.","Your knight leads off, yet the rook must sacrifice itself into stalemate to hold.","Knight to e3 — begins the saving sequence that ends in stalemate."],"hr":["Pobjeda mami, ali zapravo se ovdje moraš boriti tek za remi.","Tvoj skakač kreće, no top se mora žrtvovati u pat da bi održao.","Skakač na e3 — započinje spasonosni niz koji završava patom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.052' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und kannst dich nur noch ins Patt retten.","Deine Dame muss sich anbieten, damit der eingeengte König remis hält.","Dame nach g7 – beginnt die Patt-Rettung."],"en":["You stand worse and can only escape into stalemate.","Your queen must offer herself so the boxed-in king holds the draw.","Queen to g7 — sets up the stalemate save."],"hr":["U gorem si položaju i možeš se spasiti jedino patom.","Tvoja dama mora se ponuditi kako bi stiješnjeni kralj održao remi.","Dama na g7 — započinje spas patom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.053' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist in Bedrängnis und musst dich ins Patt flüchten.","Dein Turm opfert sich, damit der eigene König keine Züge mehr hat.","Turm nach g7 – leitet das rettende Patt ein."],"en":["You are in trouble and must flee into stalemate.","Your rook sacrifices itself so your own king is left without moves.","Rook to g7 — initiates the saving stalemate."],"hr":["U nevolji si i moraš pobjeći u pat.","Tvoj top se žrtvuje kako tvoj kralj ne bi imao poteza.","Top na g7 — započinje spasonosni pat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.054' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz Materialnachteil ist hier ein Patt zum Remis versteckt.","Deine Dame jagt den feindlichen König, bis sich keine eigenen Züge mehr finden.","Dame nach f6 – beginnt die Folge, die ins rettende Patt führt."],"en":["Despite the material deficit, a stalemate draw is hidden here.","Your queen hounds the enemy king until your side has no moves left.","Queen to f6 — begins the line that leads to the saving stalemate."],"hr":["Unatoč manjku materijala, ovdje je skriven remi patom.","Tvoja dama goni neprijateljskog kralja dok tvoja strana ne ostane bez poteza.","Dama na f6 — započinje liniju koja vodi do spasonosnog pata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.055' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst auf Verlust, aber ein Patt hält das Remis.","Deine Dame opfert sich, dann erzwingt der Turm die Pattstellung.","Dame nach g7 – beginnt die Rettung ins Patt."],"en":["You are losing, but a stalemate holds the draw.","Your queen sacrifices itself, then the rook forces the stalemate.","Queen to g7 — begins the rescue into stalemate."],"hr":["Gubiš, ali pat održava remi.","Tvoja dama se žrtvuje, zatim top prisiljava pat.","Dama na g7 — započinje spas u pat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.056' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist schlechter dran und musst dich ins Patt retten.","Dein Läufer geht voran, danach opfert sich der Turm in die Pattfalle.","Läufer nach f4 – leitet die Folge ins rettende Patt ein."],"en":["You are worse and must save yourself into stalemate.","Your bishop leads, then the rook sacrifices into the stalemate trap.","Bishop to f4 — starts the line into the saving stalemate."],"hr":["U gorem si položaju i moraš se spasiti patom.","Tvoj lovac kreće, zatim se top žrtvuje u pat-zamku.","Lovac na f4 — započinje liniju do spasonosnog pata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.057' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du musst hier das Remis durch Patt sichern.","Der Freibauer wird zur Dame – nur um sich sofort zu opfern und den eigenen König lahmzulegen.","Bauer wird auf h8 zur Dame – beginnt die Patt-Rettung."],"en":["You must secure the draw here by stalemate.","The passed pawn promotes — only to sacrifice itself at once and freeze your own king.","Pawn promotes to a queen on h8 — begins the stalemate save."],"hr":["Ovdje moraš osigurati remi patom.","Prolazni pješak postaje dama — samo da se odmah žrtvuje i sledi vlastitog kralja.","Pješak postaje dama na h8 — započinje spas patom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.058' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und musst ein Patt herbeiführen.","Dein Bauer wird zur Dame, doch das Ziel ist, den eigenen König einzumauern.","Bauer wird auf a1 zur Dame – beginnt die Folge ins rettende Patt."],"en":["You stand worse and must engineer a stalemate.","Your pawn promotes, yet the aim is to wall in your own king.","Pawn promotes to a queen on a1 — begins the line into the saving stalemate."],"hr":["U gorem si položaju i moraš isforsirati pat.","Tvoj pješak postaje dama, no cilj je zazidati vlastitog kralja.","Pješak postaje dama na a1 — započinje liniju do spasonosnog pata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.059' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz Mehrmaterials gegen dich ist hier ein Patt-Remis möglich.","Dein Turm opfert sich, und beide Türme räumen das Feld, bis kein Zug mehr bleibt.","Turm schlägt auf g7 – beginnt die Opferfolge ins rettende Patt."],"en":["Even against extra force, a stalemate draw is available here.","Your rook sacrifices, and the rooks clear the way until no move remains.","Rook takes on g7 — begins the sacrificial line into the saving stalemate."],"hr":["I protiv viška materijala, ovdje je moguć remi patom.","Tvoj top se žrtvuje, a topovi raščišćavaju put dok ne ostane poteza.","Top uzima na g7 — započinje žrtveni niz do spasonosnog pata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.060' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier gewinnst du entscheidend Material durch eine Zugfolge.","Dein Turm und der Freibauer arbeiten zusammen, um die Figur einzufangen.","Turm nach b7 – beginnt die Folge, die Material gewinnt."],"en":["Here you win decisive material through a forcing sequence.","Your rook and the passed pawn combine to trap the piece.","Rook to b7 — begins the line that wins material."],"hr":["Ovdje osvajaš odlučujući materijal forsiranim nizom.","Tvoj top i prolazni pješak surađuju kako bi uhvatili figuru.","Top na b7 — započinje liniju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.061' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier liegt ein erzwungenes Matt verborgen.","Dein Turm verstellt eine Linie, dann führt die Dame den Angriff zu Ende.","Turm nach e1 – beginnt die Folge, die zum Matt führt."],"en":["A forced mate lies hidden here.","Your rook blocks a line, then the queen finishes the attack.","Rook to e1 — begins the line that leads to mate."],"hr":["Ovdje je skriven prisilni mat.","Tvoj top zatvara liniju, zatim dama dovršava napad.","Top na e1 — započinje liniju koja vodi do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.062' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier kannst du entscheidend Material gewinnen.","Dein König läuft nach vorn und nimmt der gegnerischen Figur die Schachs, dann fällt sie.","König nach d5 – beginnt die Folge, die Material gewinnt."],"en":["Here you can win decisive material.","Your king walks forward, stripping the enemy piece of checks until it falls.","King to d5 — begins the line that wins material."],"hr":["Ovdje možeš osvojiti odlučujući materijal.","Tvoj kralj kreće naprijed i oduzima protivničkoj figuri šahove dok ne padne.","Kralj na d5 — započinje liniju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.063' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier gewinnst du Material, indem du den Schachs entkommst.","Dein König marschiert dem feindlichen Turm entgegen und nimmt ihm die sicheren Schachs.","König nach e5 – beginnt den Königsmarsch, der Material gewinnt."],"en":["Here you win material by escaping the checks.","Your king marches toward the enemy rook, taking away its safe checks.","King to e5 — begins the king walk that wins material."],"hr":["Ovdje osvajaš materijal bijegom od šahova.","Tvoj kralj kreće prema neprijateljskom topu i oduzima mu sigurne šahove.","Kralj na e5 — započinje šetnju kralja koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.064' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier gewinnst du entscheidend Material trotz der vielen Schachs.","Dein König wandert quer übers Brett und entzieht sich den gegnerischen Schachs.","Turm nach f2 – beginnt die Folge, in der der König entkommt und Material gewinnt."],"en":["Here you win decisive material despite the stream of checks.","Your king wanders across the board, dodging the enemy checks.","Rook to f2 — begins the line where the king escapes and wins material."],"hr":["Ovdje osvajaš odlučujući materijal unatoč nizu šahova.","Tvoj kralj putuje preko ploče izmičući protivničkim šahovima.","Top na f2 — započinje liniju u kojoj kralj bježi i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.065' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter, doch durch Dauerschach und Patt rettest du das Remis.","Deine Dame jagt und opfert sich dann, damit dein König keine Züge mehr hat.","Dame nach a6 – beginnt die Folge aus Schach und Patt zum Remis."],"en":["You stand worse, but perpetual check and stalemate rescue the draw.","Your queen harasses and then sacrifices so your king has no moves left.","Queen to a6 — begins the check-and-stalemate sequence to the draw."],"hr":["U gorem si položaju, ali vječni šah i pat spašavaju remi.","Tvoja dama uznemiruje pa se žrtvuje da tvoj kralj ostane bez poteza.","Dama na a6 — započinje niz šaha i pata do remija."]}', HintsVersion=1 WHERE LineId LIKE '%:010.066' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist auf Verlust, doch Dauerschach mündet ins rettende Patt.","Deine Dame schachs den König, bis er den eigenen König einsperrt.","Dame nach d2 – beginnt die Schachfolge, die ins Patt zum Remis führt."],"en":["You are losing, but the perpetual flows into a saving stalemate.","Your queen checks the king until it pens in your own monarch.","Queen to d2 — begins the checking sequence that leads into the stalemate draw."],"hr":["Gubiš, ali vječni šah prelazi u spasonosni pat.","Tvoja dama šahira kralja dok on ne zatvori tvog kralja.","Dama na d2 — započinje niz šahova koji vodi u remi patom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.067' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und rettest dich mit Dauerschach und Patt.","Deine Dame schachs unermüdlich, dann hilft der Springer, das Patt zu erzwingen.","Dame nach g2 – beginnt die Folge aus Schach und Patt zum Remis."],"en":["You stand worse and save yourself with perpetual check and stalemate.","Your queen checks relentlessly, then the knight helps force the stalemate.","Queen to g2 — begins the check-and-stalemate line to the draw."],"hr":["U gorem si položaju i spašavaš se vječnim šahom i patom.","Tvoja dama neumorno šahira, zatim skakač pomaže isforsirati pat.","Dama na g2 — započinje niz šaha i pata do remija."]}', HintsVersion=1 WHERE LineId LIKE '%:010.068' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier holst du dir mit einem kleinen Trick einen entscheidenden Vorteil.","Dein Bauer lockt den Springer weg, und dann genügt eine winzige Restkraft.","Bauer nach g2 – beginnt die Folge, die den Springer abzieht und gewinnt."],"en":["A small trick here lands you a decisive advantage.","Your pawn lures the knight away, and a tiny remaining force suffices.","Pawn to g2 — begins the line that deflects the knight and wins."],"hr":["Malim trikom ovdje stječeš odlučujuću prednost.","Tvoj pješak odvlači skakača, a sitna preostala snaga je dovoljna.","Pješak na g2 — započinje liniju koja odvlači skakača i pobjeđuje."]}', HintsVersion=1 WHERE LineId LIKE '%:010.069' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier sicherst du dir mit einem Opfer einen entscheidenden Vorteil.","Dein Läufer opfert sich, und danach hält dein Springer den Gegner in Schach.","Läufer nach c7 – beginnt die Folge, die einen entscheidenden Vorteil sichert."],"en":["A sacrifice here secures you a decisive advantage.","Your bishop offers itself, and afterward your knight holds the enemy at bay.","Bishop to c7 — begins the line that secures a decisive advantage."],"hr":["Žrtvom ovdje osiguravaš odlučujuću prednost.","Tvoj lovac se žrtvuje, a potom tvoj skakač drži protivnika na uzdi.","Lovac na c7 — započinje liniju koja osigurava odlučujuću prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:010.070' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier verschaffst du dir mit einem Opfer einen entscheidenden Vorteil.","Dein Springer opfert sich, danach übernehmen die übrigen Figuren die Arbeit.","Springer nach g4 – beginnt die Folge, die einen entscheidenden Vorteil bringt."],"en":["A sacrifice here gives you a decisive advantage.","Your knight sacrifices, then the remaining pieces do the work.","Knight to g4 — begins the line that brings a decisive advantage."],"hr":["Žrtvom ovdje stječeš odlučujuću prednost.","Tvoj skakač se žrtvuje, zatim preostale figure obavljaju posao.","Skakač na g4 — započinje liniju koja donosi odlučujuću prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:010.071' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier setzt du dir mit Dauerschach und einem Trick einen entscheidenden Vorteil zusammen.","Dein Bauer drängt vor und der Springer baut die Falle für den König.","König nach c7 – beginnt die Folge, die einen entscheidenden Vorteil sichert."],"en":["Here a mix of perpetual ideas builds you a decisive advantage.","Your pawn pushes ahead while the knight sets the trap around the king.","King to c7 — begins the line that secures a decisive advantage."],"hr":["Ovdje spojem ideja gradiš odlučujuću prednost.","Tvoj pješak napreduje dok skakač namješta zamku oko kralja.","Kralj na c7 — započinje liniju koja osigurava odlučujuću prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:010.072' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter, doch mit Opfer und Patt rettest du das Remis.","Dein Läufer opfert sich, dann engt der König den eigenen König ein.","Läufer nach e4 – beginnt die Folge ins rettende Patt."],"en":["You stand worse, but a sacrifice and stalemate rescue the draw.","Your bishop offers itself, then the king boxes in your own monarch.","Bishop to e4 — begins the line into the saving stalemate."],"hr":["U gorem si položaju, ali žrtva i pat spašavaju remi.","Tvoj lovac se žrtvuje, zatim kralj zatvara vlastitog kralja.","Lovac na e4 — započinje liniju do spasonosnog pata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.073' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du musst hier das Remis durch Patt erzwingen.","Dein Freibauer wird zur Dame, nur um sich für die Pattfalle zu opfern.","Bauer wird auf f8 zur Dame – beginnt die Folge ins rettende Patt."],"en":["You must force the draw here by stalemate.","Your passed pawn promotes, only to sacrifice itself for the stalemate trap.","Pawn promotes to a queen on f8 — begins the line into the saving stalemate."],"hr":["Ovdje moraš isforsirati remi patom.","Tvoj prolazni pješak postaje dama, samo da se žrtvuje za pat-zamku.","Pješak postaje dama na f8 — započinje liniju do spasonosnog pata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.074' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier verschaffst du dir einen entscheidenden Vorteil.","Dein Turm und der weit vorgerückte Freibauer setzen den Gegner in die Zwickmühle.","Turm nach b8 – beginnt die Folge, die einen entscheidenden Vorteil bringt."],"en":["Here you secure a decisive advantage.","Your rook and the far-advanced passed pawn put the foe in a bind.","Rook to b8 — begins the line that brings a decisive advantage."],"hr":["Ovdje stječeš odlučujuću prednost.","Tvoj top i daleko napredovali prolazni pješak stavljaju protivnika u škripac.","Top na b8 — započinje liniju koja donosi odlučujuću prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:010.075' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Magnetopfer zieht den König ins Freie und bringt entscheidenden Vorteil.","Deine Dame opfert sich, dann jagen die schweren Figuren den blanken König.","Dame schlägt auf h2 – beginnt das Magnetopfer mit entscheidendem Vorteil."],"en":["A magnet sacrifice drags the king into the open for a decisive advantage.","Your queen sacrifices, then the heavy pieces hunt the bared king.","Queen takes on h2 — begins the magnet sacrifice with a decisive advantage."],"hr":["Magnetska žrtva izvlači kralja na otvoreno za odlučujuću prednost.","Tvoja dama se žrtvuje, zatim teške figure love ogoljenog kralja.","Dama uzima na h2 — započinje magnetsku žrtvu s odlučujućom prednošću."]}', HintsVersion=1 WHERE LineId LIKE '%:011.004' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Schlag bricht die Mauer vor dem König – kein Schach nötig.","Deine Dame stößt mitten in die Bauernkette vor dem feindlichen König.","Dame nach g6 – ein zerstörerischer Einschlag mit entscheidendem Vorteil."],"en":["A quiet blow shatters the wall in front of the king — no check needed.","Your queen crashes into the pawn cover of the enemy king.","Queen to g6 — a devastating strike with a decisive advantage."],"hr":["Tihi udarac ruši zid pred kraljem — bez šaha.","Tvoja dama upada u pješački zaklon neprijateljskog kralja.","Dama na g6 — razoran udarac s odlučujućom prednošću."]}', HintsVersion=1 WHERE LineId LIKE '%:011.005' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kette erzwungener Schachs führt zum Matt.","Deine Damen wirken zusammen und treiben den König ins Netz.","Dame nach g1 – beginnt die Schachfolge, die zum Matt führt."],"en":["A chain of forcing checks delivers mate.","Your queens work together to drive the king into the net.","Queen to g1 — begins the checking sequence that leads to mate."],"hr":["Niz prisilnih šahova vodi do mata.","Tvoje dame surađuju i tjeraju kralja u mrežu.","Dama na g1 — započinje niz šahova koji vodi do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.006' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Treppenmatt.","Deine Türme arbeiten Stufe für Stufe und treiben den König an den Rand.","Turm nach g2 – beginnt die Schachfolge, die zum Matt führt."],"en":["A sequence of forcing checks brings the ladder mate.","Your rooks work step by step, pushing the king to the edge.","Rook to g2 — begins the checking sequence that leads to mate."],"hr":["Niz prisilnih šahova donosi ljestvičasti mat.","Tvoji topovi rade korak po korak i tjeraju kralja na rub.","Top na g2 — započinje niz šahova koji vodi do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.007' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Reihe erzwungener Züge endet im Matt.","Dein Turm und der Läufer schnüren das Netz um den feindlichen König.","Turm nach d6 – beginnt die Folge, die zum Matt führt."],"en":["A series of forcing moves ends in mate.","Your rook and bishop tighten the net around the enemy king.","Rook to d6 — begins the line that leads to mate."],"hr":["Niz prisilnih poteza završava matom.","Tvoj top i lovac stežu mrežu oko neprijateljskog kralja.","Top na d6 — započinje liniju koja vodi do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.008' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Der Springer leitet ein, danach mattsetzt der schwere Geräteangriff am Rand.","Springer nach f6 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The knight opens, then the heavy pieces deliver the corner mate.","Knight to f6 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Skakač otvara, a teške figure daju mat u kutu.","Skakač na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.009' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit einer Opferfolge erzwingst du das Matt.","Die Dame opfert sich, dann liefern Springer und Turm das Netz.","Dame schlägt auf h1 – Beginn des erzwungenen Matts."],"en":["A string of sacrifices forces mate.","The queen sacrifices herself, then knight and rook weave the net.","Queen takes on h1 — the start of the forced mate."],"hr":["Niz žrtava prisiljava mat.","Dama se žrtvuje, a skakač i top pletu mrežu.","Dama uzima na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.010' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Der Springer holt den König heraus, dann schlagen Dame und Turm zu.","Springer schlägt auf e8 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The knight drags the king out, then queen and rook strike.","Knight takes on e8 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Skakač izvlači kralja, a dama i top zatim udaraju.","Skakač uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.011' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Der Springer öffnet, dann dringt der Turm zur Grundreihe vor.","Springer schlägt auf f3 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The knight opens up, then the rook crashes to the back rank.","Knight takes on f3 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Skakač otvara, a top zatim provaljuje na zadnji red.","Skakač uzima na f3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.012' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Der Turm jagt den König in die Ecke, der Läufer hilft mit.","Turm nach f7 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The rook chases the king into the corner with the bishop''s help.","Rook to f7 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Top tjera kralja u kut uz pomoć lovca.","Top na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.013' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Ein Damenopfer öffnet die Linie für den Turm.","Dame nach g6 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","A queen sacrifice clears the file for the rook.","Queen to g6 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Žrtva dame otvara liniju za topa.","Dama na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.014' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Der Springer lockt, dann opfert die Dame zum Mattnetz.","Springer schlägt auf f7 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The knight lures, then the queen sacrifices into the mating net.","Knight takes on f7 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Skakač mami, a dama se žrtvuje u matnu mrežu.","Skakač uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.015' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Der Springer beginnt die Jagd, gestützt von Dame und Läufer.","Springer nach f1 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The knight starts the hunt, backed by queen and bishop.","Knight to f1 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Skakač započinje lov uz potporu dame i lovca.","Skakač na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.016' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Ein Damenopfer und der Springer reißen die Königsstellung auf.","Dame schlägt auf g8 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","A queen sacrifice and the knight tear open the king''s shelter.","Queen takes on g8 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Žrtva dame i skakač razbijaju kraljev zaklon.","Dama uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.017' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Ein Turmopfer und der Springer schnüren das Netz zu.","Turm nach b8 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","A rook sacrifice and the knight close the net.","Rook to b8 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Žrtva topa i skakač zatvaraju mrežu.","Top na b8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.018' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Die Dame zieht den König ins Freie, der Läufer setzt nach.","Dame nach b4 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The queen pulls the king into the open, the bishop follows up.","Queen to b4 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Dama izvlači kralja na otvoreno, lovac nastavlja.","Dama na b4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.019' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Der Springer öffnet die dritte Reihe für die Dame.","Springer nach d5 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","The knight clears the rank for the queen to swing across.","Knight to d5 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Skakač čisti red za prijelaz dame.","Skakač na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.020' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge erzwungener Schachs führt zum Matt.","Ein Springeropfer und die Dame zwingen den König ins Netz.","Springer nach g6 – Beginn des erzwungenen Matts."],"en":["A sequence of forcing checks ends in mate.","A knight sacrifice and the queen force the king into the net.","Knight to g6 — the start of the forced mate."],"hr":["Niz prisilnih šahova vodi do mata.","Žrtva skakača i dama tjeraju kralja u mrežu.","Skakač na g6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.021' AND BookFileName='chessable-u5-21646.pgn';
