UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – locke den König mit einem Opfer ins Freie.","Die Dame eröffnet, dann liefert ein leichter Stein das klassische Eckmatt.","Dame schlägt auf g7 – beginnt das erzwungene Matt."],"en":["A forced mate is here — drag the king out with a sacrifice.","The queen opens the door, then a minor piece delivers the classic corner mate.","Queen takes on g7 — starting the forced mate."],"hr":["Ovdje je prisilni mat — žrtvom izvuci kralja na otvoreno.","Dama otvara vrata, a zatim laka figura daje klasični kutni mat.","Dama uzima na g7 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.039' AND BookFileName='chessable-u5-21646.pgn';
