UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – hole den König mit einem Opfer heran.","Der Turm zieht den König heran, dann vollendet die Dame.","Turm schlägt auf h6 – Beginn des erzwungenen Matts."],"en":["A forced mate is here — draw the king out with a sacrifice.","The rook pulls the king forward, then the queen finishes.","Rook takes on h6 — the start of the forced mate."],"hr":["Ovdje je prisilni mat — žrtvom izvuci kralja.","Top privlači kralja, a zatim dama dovršava.","Top uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.042' AND BookFileName='chessable-u5-21646.pgn';
