UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – opfere, um die Mauer einzureißen.","Erst der Läufer, dann die Türme und die Dame liefern das Matt.","Läufer schlägt auf g7 – Beginn des erzwungenen Matts."],"en":["A forced mate awaits — sacrifice to break down the wall.","First the bishop, then the rooks and queen deliver mate.","Bishop takes on g7 — the start of the forced mate."],"hr":["Čeka prisilni mat — žrtvuj da srušiš zid.","Prvo lovac, a zatim topovi i dama daju mat.","Lovac uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.058' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – opfere, um den König herzuziehen.","Die Türme ködern abwechselnd, dann setzt die Dame matt.","Turm schlägt auf h8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is here — sacrifice to draw the king in.","The rooks bait in turn, then the queen delivers mate.","Rook takes on h8 — the prelude to forced mate."],"hr":["Ovdje je prisilni mat — žrtvuj da privučeš kralja.","Topovi naizmjenično mame, a zatim dama matira.","Top uzima na h8 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.059' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – locke den König mit Turmopfern.","Die Türme ködern nacheinander, dann vollendet die Dame.","Turm schlägt auf h8 – Beginn des erzwungenen Matts."],"en":["A forced mate awaits — lure the king with rook sacrifices.","The rooks bait one after another, then the queen finishes.","Rook takes on h8 — the start of the forced mate."],"hr":["Čeka prisilni mat — namami kralja žrtvama topova.","Topovi mame jedan za drugim, a zatim dama dovršava.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.060' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – beackere die offene Linie zum König.","Die Türme opfern sich nacheinander, dann setzt der letzte Turm matt.","Turm schlägt auf h8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is hidden — pound the open line to the king.","The rooks sacrifice one after another, then the last rook mates.","Rook takes on h8 — the prelude to forced mate."],"hr":["Ovdje je skriven prisilni mat — udari po otvorenoj liniji prema kralju.","Topovi se žrtvuju jedan za drugim, a zatim zadnji top matira.","Top uzima na h8 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.061' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter – rette dich mit einer Schachserie zum Dauerschach oder Matt.","Türme ködern den feindlichen König, dann holt die Dame entscheidenden Vorteil.","Turm schlägt auf h1 – Beginn der rettenden Schachfolge."],"en":["You are worse — save yourself with a series of checks toward perpetual or mate.","Rooks lure the enemy king, then the queen secures a decisive edge.","Rook takes on h1 — the start of the saving check sequence."],"hr":["Lošiji si — spasi se nizom šahova prema vječnom šahu ili matu.","Topovi mame protivničkog kralja, a zatim dama osvaja odlučujuću prednost.","Top uzima na h1 — početak spasonosnog niza šahova."]}', HintsVersion=1 WHERE LineId LIKE '%:011.062' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – opfere, um den König herzulocken.","Der Turm ködert, dann übernehmen Dame und Türme die Jagd.","Turm schlägt auf c7 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is here — sacrifice to draw the king out.","The rook baits, then queen and rooks take over the hunt.","Rook takes on c7 — the prelude to forced mate."],"hr":["Ovdje je prisilni mat — žrtvuj da izvučeš kralja.","Top mami, a zatim dama i topovi preuzimaju lov.","Top uzima na c7 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.063' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – jage den König mit der Dame und dem Turm.","Der Turm opfert sich, dann treibt die Dame den König vor sich her.","Turm schlägt auf h7 – Beginn des erzwungenen Matts."],"en":["A forced mate awaits — hunt the king with queen and rook.","The rook sacrifices, then the queen drives the king before it.","Rook takes on h7 — the start of the forced mate."],"hr":["Čeka prisilni mat — lovi kralja damom i topom.","Top se žrtvuje, a zatim dama tjera kralja pred sobom.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.064' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – locke den König mit einem Opfer.","Der Läufer ködert, dann gibt die Dame den Ton an.","Läufer schlägt auf f2 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is here — lure the king with a sacrifice.","The bishop baits, then the queen calls the tune.","Bishop takes on f2 — the prelude to forced mate."],"hr":["Ovdje je prisilni mat — namami kralja žrtvom.","Lovac mami, a zatim dama vodi glavnu riječ.","Lovac uzima na f2 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.065' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – ziehe den König mit einem Opfer heran.","Die Dame ködert, dann jagen Turm und Springer den König ins Matt.","Dame schlägt auf h6 – Beginn des erzwungenen Matts."],"en":["A forced mate awaits — draw the king in with a sacrifice.","The queen baits, then rook and knight hunt the king into mate.","Queen takes on h6 — the start of the forced mate."],"hr":["Čeka prisilni mat — žrtvom privuci kralja.","Dama mami, a zatim top i skakač tjeraju kralja u mat.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.066' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – locke den König mit einem Opfer.","Der Läufer ködert, dann weben die Springer und Bauern das Mattnetz.","Läufer schlägt auf g2 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is hidden — lure the king with a sacrifice.","The bishop baits, then the knights and pawns weave the mating net.","Bishop takes on g2 — the prelude to forced mate."],"hr":["Ovdje je skriven prisilni mat — namami kralja žrtvom.","Lovac mami, a zatim skakači i pješaci pletu mrežu mata.","Lovac uzima na g2 — uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.067' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – opfere, um den König freizulegen.","Die Dame ködert, dann übernehmen Turm und Läufer die Jagd.","Dame schlägt auf h6 – Beginn des erzwungenen Matts."],"en":["A forced mate is here — sacrifice to expose the king.","The queen baits, then rook and bishop take over the hunt.","Queen takes on h6 — the start of the forced mate."],"hr":["Ovdje je prisilni mat — žrtvuj da otvoriš kralja.","Dama mami, a zatim top i lovac preuzimaju lov.","Dama uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.068' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – locke den König ins Verderben.","Der dunkelfeldrige Läufer und die Dame ziehen den feindlichen König heran.","Läufer schlägt auf e5 – Beginn des Mattangriffs."],"en":["A forced mate is hiding here — lure the king to its doom.","The dark-squared bishop and the queen drag the enemy king forward.","Bishop takes on e5 — starting the mating attack."],"hr":["Ovdje se krije prisilni mat — namami kralja u propast.","Lovac na tamnim poljima i dama privlače neprijateljskog kralja.","Lovac uzima na e5 — početak matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:011.069' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – öffne die Königsstellung.","Die schweren Figuren stürmen über die offene h-Seite ein.","Turm schlägt auf h8 – Auftakt zur Mattkombination."],"en":["A forced mate is in the air — pry open the king''s shelter.","The heavy pieces storm in down the open edge file.","Rook takes on h8 — beginning the mating combination."],"hr":["Prisilni mat visi u zraku — razbij kraljev zaklon.","Teške figure provaljuju duž otvorene linije.","Top uzima na h8 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.070' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsdeckung auf und erzwingt Matt.","Turm, Dame und Läufer arbeiten gegen den entblößten König.","Turm schlägt auf h7 – Beginn der erzwungenen Mattfolge."],"en":["A sacrifice rips open the king''s cover and forces mate.","Rook, queen and bishop combine against the exposed king.","Rook takes on h7 — starting the forced mating sequence."],"hr":["Žrtva razbija kraljev zaklon i prisiljava mat.","Top, dama i lovac udružuju se protiv izloženog kralja.","Top uzima na h7 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.071' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein erzwungenes Matt – treibe den König heraus.","Die schweren Figuren und der Läufer hetzen den König über das Brett.","Turm schlägt auf h7 – Beginn der Mattjagd."],"en":["A forced mate awaits here — drive the king into the open.","The heavy pieces and bishop hound the king across the board.","Rook takes on h7 — beginning the mating hunt."],"hr":["Ovdje čeka prisilni mat — istjeraj kralja na otvoreno.","Teške figure i lovac gone kralja preko ploče.","Top uzima na h7 — početak matnog lova."]}', HintsVersion=1 WHERE LineId LIKE '%:011.072' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein erzwungenes Matt ein.","Die Dame und die Türme ziehen den König ans offene Verderben.","Dame schlägt auf h8 – Auftakt zur erzwungenen Mattfolge."],"en":["A queen sacrifice ushers in a forced mate.","The queen and rooks draw the king into the open.","Queen takes on h8 — beginning the forced mating sequence."],"hr":["Žrtva dame uvodi prisilni mat.","Dama i topovi vuku kralja na otvoreno.","Dama uzima na h8 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.073' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Vorbereitungszug bahnt ein erzwungenes Matt an.","Die Dame und der Turm an der Flanke vollenden das Mattnetz.","Dame nach d4 – Beginn der erzwungenen Mattfolge."],"en":["A quiet preparatory move sets up a forced mate.","The queen and the rook on the flank complete the mating net.","Queen to d4 — starting the forced mating sequence."],"hr":["Tihi pripremni potez priprema prisilni mat.","Dama i top na krilu dovršavaju matnu mrežu.","Dama na d4 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.074' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorbereitendes Opfer ebnet den Weg zum erzwungenen Matt.","Türme, Dame und der heranziehende Freibauer setzen den König matt.","Turm nach e8 – Beginn der Mattkombination."],"en":["A preparatory sacrifice clears the path to forced mate.","Rooks, queen and the advancing passed pawn deliver the mate.","Rook to e8 — beginning the mating combination."],"hr":["Pripremna žrtva otvara put prisilnom matu.","Topovi, dama i nadolazeći slobodni pješak daju mat.","Top na e8 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.075' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Drücker – ein erzwungenes Matt liegt bereit.","Die Dame mit Bauernunterstützung umzingelt den feindlichen König.","Bauer schlägt auf b2 – Beginn der erzwungenen Mattfolge."],"en":["You hold the initiative — a forced mate is ready.","The queen, backed by a pawn, hems in the enemy king.","Pawn takes on b2 — starting the forced mating sequence."],"hr":["Inicijativa je tvoja — prisilni mat je spreman.","Dama uz potporu pješaka stješnjava neprijateljskog kralja.","Pješak uzima na b2 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.076' AND BookFileName='chessable-u5-21646.pgn';
