UPDATE BookPuzzles SET HintsJson='{"de":["Du hast ein erzwungenes Matt – schlage zuerst die Deckung weg.","Läufer, Springer und Dame stricken das Mattnetz um den König.","Springer schlägt auf h3 – Beginn der erzwungenen Mattfolge."],"en":["You have a forced mate — first clear away the defence.","Bishop, knight and queen weave the mating net around the king.","Knight takes on h3 — starting the forced mating sequence."],"hr":["Imaš prisilni mat — najprije ukloni obranu.","Lovac, skakač i dama pletu matnu mrežu oko kralja.","Skakač uzima na h3 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.078' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorbereitendes Opfer leitet ein erzwungenes Matt ein.","Springer, Läufer und Dame treiben den König ins offene Feld.","Springer schlägt auf f7 – Beginn der Mattkombination."],"en":["A preparatory sacrifice ushers in a forced mate.","Knight, bishop and queen drive the king into the open.","Knight takes on f7 — beginning the mating combination."],"hr":["Pripremna žrtva uvodi prisilni mat.","Skakač, lovac i dama gone kralja na otvoreno.","Skakač uzima na f7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.079' AND BookFileName='chessable-u5-21646.pgn';
