UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug zum erzwungenen Matt – mit Doppelschach.","Dame und Springer setzen den weißen König mit Doppelschach matt.","Dame schlägt auf b1 – Beginn der erzwungenen Mattfolge."],"en":["It is your move to a forced mate — featuring a double check.","Queen and knight mate the white king with a double check.","Queen takes on b1 — starting the forced mating sequence."],"hr":["Na tebi je potez do prisilnog mata — s dvostrukim šahom.","Dama i skakač matiraju bijelog kralja dvostrukim šahom.","Dama uzima na b1 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.087' AND BookFileName='chessable-u5-21646.pgn';
