UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer zieht den König heraus – der schnellste Weg zum Matt.","Dame, Turm und Läufer hetzen den König ins Freie.","Dame schlägt auf h6 – Beginn der erzwungenen Mattfolge."],"en":["A sacrifice draws the king out — the quickest road to mate.","Queen, rook and bishop drive the king into the open.","Queen takes on h6 — starting the forced mating sequence."],"hr":["Žrtva izvlači kralja — najbrži put do mata.","Dama, top i lovac gone kralja na otvoreno.","Dama uzima na h6 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.090' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer entblößt den König und erzwingt Matt mit Doppelschach.","Beide Läufer, Springer und Dame umzingeln den König.","Läufer schlägt auf f7 – Beginn der Mattkombination."],"en":["A bishop sacrifice bares the king and forces mate with a double check.","Both bishops, the knight and queen surround the king.","Bishop takes on f7 — beginning the mating combination."],"hr":["Žrtva lovca ogoljava kralja i prisiljava mat dvostrukim šahom.","Oba lovca, skakač i dama opkoljavaju kralja.","Lovac uzima na f7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.091' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Drücker – ein erzwungenes Matt mit Doppelschach wartet.","Dame, Springer und Läufer überrollen den weißen König.","Dame schlägt auf b2 – Beginn der erzwungenen Mattfolge."],"en":["You hold the initiative — a forced mate with double check awaits.","Queen, knight and bishop overwhelm the white king.","Queen takes on b2 — starting the forced mating sequence."],"hr":["Inicijativa je tvoja — čeka prisilni mat s dvostrukim šahom.","Dama, skakač i lovac preplavljuju bijelog kralja.","Dama uzima na b2 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.092' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein klassisches Damenopfer erzwingt Matt mit Doppelschach.","Beide Läufer und die Dame ziehen den König mitten ins Feuer.","Dame schlägt auf d7 – Beginn der erzwungenen Mattfolge."],"en":["A classic queen sacrifice forces mate with a double check.","Both bishops and the queen drag the king into the crossfire.","Queen takes on d7 — starting the forced mating sequence."],"hr":["Klasična žrtva dame prisiljava mat dvostrukim šahom.","Oba lovca i dama vuku kralja u unakrsnu vatru.","Dama uzima na d7 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.093' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer reißt die Königsstellung auf und erzwingt Matt.","Beide Läufer, Turm und Dame jagen den König ins Verderben.","Dame schlägt auf h7 – Auftakt zur Mattkombination."],"en":["A queen sacrifice rips open the king''s position and forces mate.","Both bishops, the rook and queen hunt the king to its doom.","Queen takes on h7 — beginning the mating combination."],"hr":["Žrtva dame razbija kraljevu poziciju i prisiljava mat.","Oba lovca, top i dama gone kralja u propast.","Dama uzima na h7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.094' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein erzwungenes Matt mit Doppelschach ein.","Dame, Springer und Läufer ziehen den König ins Freie und matt.","Dame nach h1 – Beginn der erzwungenen Mattfolge."],"en":["A queen sacrifice ushers in a forced mate with a double check.","Queen, knight and bishop draw the king into the open and mate.","Queen to h1 — starting the forced mating sequence."],"hr":["Žrtva dame uvodi prisilni mat s dvostrukim šahom.","Dama, skakač i lovac vuku kralja na otvoreno do mata.","Dama na h1 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.095' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorbereitendes Opfer ebnet den Weg zum erzwungenen Matt.","Beide Türme und der Läufer treiben den König ins offene Feld.","Turm schlägt auf g7 – Beginn der Mattkombination."],"en":["A preparatory sacrifice clears the path to forced mate.","Both rooks and the bishop drive the king into the open.","Rook takes on g7 — beginning the mating combination."],"hr":["Pripremna žrtva otvara put prisilnom matu.","Oba topa i lovac gone kralja na otvoreno.","Top uzima na g7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.096' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer mit Doppelschach erzwingt das Matt.","Dame, beide Türme und die Läufer überwältigen den König.","Dame schlägt auf g7 – Beginn der erzwungenen Mattfolge."],"en":["A queen sacrifice with a double check forces the mate.","Queen, both rooks and the bishops overwhelm the king.","Queen takes on g7 — starting the forced mating sequence."],"hr":["Žrtva dame s dvostrukim šahom prisiljava mat.","Dama, oba topa i lovci preplavljuju kralja.","Dama uzima na g7 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.097' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Drücker – ein erzwungenes Doppelschach-Matt wartet.","Erst die Fluchtfelder nehmen, dann setzen Läufer, Springer und Dame matt.","Turm schlägt auf g3 – Beginn der erzwungenen Mattfolge."],"en":["You hold the initiative — a forced double-check mate awaits.","First seal the escape squares, then bishop, knight and queen mate.","Rook takes on g3 — starting the forced mating sequence."],"hr":["Inicijativa je tvoja — čeka prisilni mat dvostrukim šahom.","Najprije oduzmi polja za bijeg, pa lovac, skakač i dama matiraju.","Top uzima na g3 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:011.098' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Lock den feindlichen König heran und spinn ein Mattnetz, das entscheidend Material gewinnt.","Die Dame opfert sich, um den König ins Freie zu ziehen, dann übernehmen die Türme.","Dame nach h4 – zieht den König heran und startet die gewinnbringende Kombination."],"en":["Lure the enemy king forward and weave a net that wins decisively.","A queen sacrifice drags the king out, then the rooks take over.","Queen takes on h4 — pulling the king out to start the winning combination."],"hr":["Privuci protivničkog kralja i ispleti mrežu koja odlučno dobiva.","Žrtva dame izvlači kralja, a onda topovi preuzimaju posao.","Dama uzima na h4 — izvlači kralja i pokreće dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:011.099' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – der gegnerische König ist gefangen.","Eine geopferte Figur lockt den König heran, dann schließt sich das Netz.","Bauer schlägt auf g4 – Auftakt zum erzwungenen Mattangriff."],"en":["A forced mate is here — the king has nowhere to hide.","A sacrifice lures the king forward, then the net closes.","Pawn takes on g4 — the start of a forced mating attack."],"hr":["Tu je prisilni mat — kralj nema kamo pobjeći.","Žrtva privlači kralja, a onda se mreža zatvara.","Pješak uzima na g4 — početak prisilnog matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:011.100' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – der König wird hinausgezogen.","Das Damenopfer reißt die Königsstellung auf, Läufer und Turm vollenden.","Dame schlägt auf f6 – Beginn der erzwungenen Mattführung."],"en":["A forced mate is in the air — the king gets dragged into the open.","A queen sacrifice rips open the king and the bishop finishes the job.","Queen takes on f6 — the start of the forced mating sequence."],"hr":["U zraku je prisilni mat — kralj se izvlači na otvoreno.","Žrtva dame otvara kralja, a lovac dovršava posao.","Dama uzima na f6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.101' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der König wird aus seinem Versteck gerissen.","Ein Turmopfer holt den König heraus, dann jagen Dame und Läufer ihn nieder.","Turm schlägt auf h7 – der erste Schlag der erzwungenen Mattjagd."],"en":["A forced mate awaits — the king is torn from his shelter.","A rook sacrifice flushes the king out, then queen and bishop hunt him down.","Rook takes on h7 — the first blow of the forced mating hunt."],"hr":["Čeka prisilni mat — kralj se izvlači iz zaklona.","Žrtva topa izvlači kralja, a onda ga dama i lovac love.","Top uzima na h7 — prvi udarac prisilnog matnog lova."]}', HintsVersion=1 WHERE LineId LIKE '%:011.102' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – der König wird ins Freie gezwungen.","Ein Turmopfer zieht den König heran, dann schnürt die Dame das Netz zu.","Turm nach h5 – Auftakt zur erzwungenen Mattkombination."],"en":["A forced mate is here — the king is driven into the open.","A rook sacrifice draws the king out, then the queen seals the net.","Rook to h5 — the start of the forced mating combination."],"hr":["Tu je prisilni mat — kralj se tjera na otvoreno.","Žrtva topa izvlači kralja, a onda dama zatvara mrežu.","Top na h5 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.103' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material – nutze die Schwäche der Grundreihe.","Die Dame zwingt sich hinein, dann fällt durch eine Gabel das Material.","Dame nach f2 – Auftakt zur materialgewinnenden Kombination."],"en":["A combination wins decisive material — exploit the back-rank weakness.","The queen forces her way in, then a fork harvests the material.","Queen to f2 — the start of the material-winning combination."],"hr":["Kombinacija dobiva odlučan materijal — iskoristi slabost zadnjeg reda.","Dama se silom probija, a onda viljuška skida materijal.","Dama na f2 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:011.104' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material auf der offenen Linie.","Ein Turmopfer öffnet die Linie, dann gewinnt der Doppelangriff die Dame.","Turm schlägt auf h7 – Auftakt, der am Ende die Dame gewinnt."],"en":["A combination wins decisive material down the open file.","A rook sacrifice opens the file, then a double attack nets the queen.","Rook takes on h7 — the start that ultimately wins the queen."],"hr":["Kombinacija dobiva odlučan materijal po otvorenom stupcu.","Žrtva topa otvara stupac, a dvostruki napad osvaja damu.","Top uzima na h7 — početak koji na kraju osvaja damu."]}', HintsVersion=1 WHERE LineId LIKE '%:011.105' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Grundreihe und der gefesselte Bauer verraten den König.","Ein Turmopfer öffnet die Bahn, dann dringt die Dame tödlich ein.","Turm schlägt auf h1 – erster Zug des erzwungenen Matts."],"en":["A forced mate is here — the back rank and a pinned pawn doom the king.","A rook sacrifice clears the path, then the queen invades fatally.","Rook takes on h1 — the first move of the forced mate."],"hr":["Tu je prisilni mat — zadnji red i vezani pješak osuđuju kralja.","Žrtva topa otvara put, a onda dama smrtonosno prodire.","Top uzima na h1 — prvi potez prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.106' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – der gefesselte Bauer ist ein schlechter Verteidiger.","Ein Turmopfer holt den König heraus, dann gibt die Dame den tödlichen Schlag.","Turm schlägt auf h8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is here — the pinned pawn defends poorly.","A rook sacrifice draws the king out, then the queen delivers the blow.","Rook takes on h8 — the start of the forced mate."],"hr":["Tu je prisilni mat — vezani pješak loše brani.","Žrtva topa izvlači kralja, a onda dama zadaje udarac.","Top uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.107' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein berühmtes Opferfeuerwerk gegen die Rochadestellung.","Der Läufer opfert sich vorn, dann liefert der Bauernvorstoß den Mattstoß.","Läufer schlägt auf g4 – Auftakt der erzwungenen Mattkombination."],"en":["A forced mate is here — a famous sacrificial storm against the castled king.","The bishop sacrifices itself first, then a pawn thrust delivers mate.","Bishop takes on g4 — the start of the forced mating combination."],"hr":["Tu je prisilni mat — slavna žrtvena oluja protiv rokiranog kralja.","Lovac se prvo žrtvuje, a onda prodor pješaka donosi mat.","Lovac uzima na g4 — početak prisilne matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.108' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der König wird über das Brett getrieben.","Ein Opfer lockt den König heran, dann jagt der Turm ihn ins Matt.","Läufer schlägt auf b6 – Auftakt zur erzwungenen Königsjagd."],"en":["A forced mate awaits — the king is driven across the board.","A sacrifice lures the king out, then the rook chases him into mate.","Bishop takes on b6 — the start of the forced king hunt."],"hr":["Čeka prisilni mat — kralj se tjera preko ploče.","Žrtva izvlači kralja, a onda ga top tjera u mat.","Lovac uzima na b6 — početak prisilnog lova na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:011.109' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material gegen den König.","Ein Läuferopfer reißt die Stellung auf, dann erntet der Springer Material.","Läufer schlägt auf f2 – Auftakt der materialgewinnenden Kombination."],"en":["A combination wins decisive material against the king.","A bishop sacrifice rips the position open, then the knight reaps material.","Bishop takes on f2 — the start of the material-winning combination."],"hr":["Kombinacija dobiva odlučan materijal protiv kralja.","Žrtva lovca otvara položaj, a onda skakač skuplja materijal.","Lovac uzima na f2 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:011.110' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material – das Bauernzentrum wird gesprengt.","Ein Läuferopfer lockt den König heraus, dann gabelt der Springer.","Läufer schlägt auf f7 – Auftakt der materialgewinnenden Kombination."],"en":["A combination wins decisive material — the center is blown apart.","A bishop sacrifice exposes the king, then the knight forks.","Bishop takes on f7 — the start of the material-winning combination."],"hr":["Kombinacija dobiva odlučan materijal — centar se razbija.","Žrtva lovca izlaže kralja, a onda skakač viljuška.","Lovac uzima na f7 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:011.111' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material – der König wird langsam herangezogen.","Ein Turmopfer holt den König heran, dann gewinnt der Doppelangriff die Dame.","Turm schlägt auf h8 – Auftakt, der die Dame gewinnt."],"en":["A combination wins decisive material — the king is slowly drawn in.","A rook sacrifice pulls the king closer, then a double attack wins the queen.","Rook takes on h8 — the start that wins the queen."],"hr":["Kombinacija dobiva odlučan materijal — kralj se polako privlači.","Žrtva topa privlači kralja, a dvostruki napad osvaja damu.","Top uzima na h8 — početak koji osvaja damu."]}', HintsVersion=1 WHERE LineId LIKE '%:011.112' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein klassisches Mattbild am Königsflügel.","Ein Turmopfer reißt den König heraus, dann setzt die Dame zum Matt an.","Turm schlägt auf h7 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is here — a classic mating pattern on the king''s side.","A rook sacrifice drags the king out, then the queen sets up mate.","Rook takes on h7 — the start of the forced mate."],"hr":["Tu je prisilni mat — klasičan matni uzorak na kraljevom krilu.","Žrtva topa izvlači kralja, a onda dama sprema mat.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.113' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Bauernkette zerbricht den Königsschutz.","Ein Damenopfer zieht den Bauern weg, dann vollendet der Turm das Matt.","Dame schlägt auf g6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here — the pawn cover is torn away.","A queen sacrifice removes the defender, then the rook finishes the mate.","Queen takes on g6 — the start of the forced mating sequence."],"hr":["Tu je prisilni mat — pješačka zaštita se uklanja.","Žrtva dame uklanja branitelja, a onda top dovršava mat.","Dama uzima na g6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.114' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – leise Züge schnüren das Netz zu.","Ein Springer schiebt sich heran, dann gibt der Läufer den Mattstoß.","Springer nach g4 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate awaits — quiet moves draw the net tight.","A knight slips in, then the bishop delivers the mating blow.","Knight to g4 — the start of the forced mating sequence."],"hr":["Čeka prisilni mat — tihi potezi zatežu mrežu.","Skakač se uvlači, a onda lovac zadaje matni udarac.","Skakač na g4 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.115' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – die Dame manövriert leise zum tödlichen Feld.","Die Dame umgeht die Deckung, dann fällt das Matt am Königsflügel.","Dame nach d3 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here — the queen maneuvers quietly to a deadly square.","The queen sidesteps the defense, then mate falls on the king''s wing.","Queen to d3 — the start of the forced mating sequence."],"hr":["Tu je prisilni mat — dama se tiho premješta na smrtonosno polje.","Dama zaobilazi obranu, a onda mat pada na kraljevom krilu.","Dama na d3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.116' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend – ein Turmmatt lässt sich nicht verhindern.","Ein Springer opfert sich, dann öffnet sich die Linie für den Turm.","Springer schlägt auf f3 – Auftakt der entscheidenden Kombination."],"en":["A combination wins decisively — a rook mate cannot be prevented.","A knight sacrifices itself, then the file opens for the rook.","Knight takes on f3 — the start of the decisive combination."],"hr":["Kombinacija odlučno dobiva — matu topom nema obrane.","Skakač se žrtvuje, a onda se stupac otvara za topa.","Skakač uzima na f3 — početak odlučne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.117' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend – ein stiller Bauer entscheidet die Partie.","Ein Damenopfer zerstört den Schutz, dann marschiert der Bauer tödlich vor.","Dame schlägt auf g6 – Auftakt der entscheidenden Kombination."],"en":["A combination wins decisively — a quiet pawn settles the game.","A queen sacrifice shatters the cover, then the pawn marches in fatally.","Queen takes on g6 — the start of the decisive combination."],"hr":["Kombinacija odlučno dobiva — tihi pješak rješava partiju.","Žrtva dame razbija zaštitu, a onda pješak smrtonosno kreće.","Dama uzima na g6 — početak odlučne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.118' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend – leise Züge umzingeln den König.","Ein Damenopfer öffnet die Stellung, dann setzt der Läufer den stillen Schlag.","Dame schlägt auf g6 – Auftakt der entscheidenden Kombination."],"en":["A combination wins decisively — quiet moves surround the king.","A queen sacrifice opens the position, then the bishop lands the quiet blow.","Queen takes on g6 — the start of the decisive combination."],"hr":["Kombinacija odlučno dobiva — tihi potezi okružuju kralja.","Žrtva dame otvara položaj, a onda lovac zadaje tihi udarac.","Dama uzima na g6 — početak odlučne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.119' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – stille Züge ersticken den König.","Ein Läuferopfer reißt die Stellung auf, dann vollenden Dame und Läufer.","Läufer schlägt auf g3 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate awaits — quiet moves smother the king.","A bishop sacrifice rips the position open, then queen and bishop finish.","Bishop takes on g3 — the start of the forced mating sequence."],"hr":["Čeka prisilni mat — tihi potezi guše kralja.","Žrtva lovca otvara položaj, a onda dama i lovac dovršavaju.","Lovac uzima na g3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.120' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – mit ruhigen Zügen wird der König eingekreist.","Ein Springer dringt ein, dann schnürt die Dame das Mattnetz zu.","Springer nach h6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here — calm moves encircle the king.","A knight invades, then the queen draws the mating net tight.","Knight to h6 — the start of the forced mating sequence."],"hr":["Tu je prisilni mat — mirni potezi okružuju kralja.","Skakač prodire, a onda dama zateže matnu mrežu.","Skakač na h6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.121' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Königsdeckung wird leise zerlegt.","Ein Läuferopfer öffnet den König, dann gibt der Springer den letzten Stoß.","Läufer schlägt auf h6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here — the king''s cover is quietly dismantled.","A bishop sacrifice exposes the king, then the knight strikes last.","Bishop takes on h6 — the start of the forced mating sequence."],"hr":["Tu je prisilni mat — kraljeva zaštita se tiho razgrađuje.","Žrtva lovca izlaže kralja, a onda skakač zadaje posljednji udarac.","Lovac uzima na h6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.122' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend – ein stilles Matt droht unaufhaltsam.","Ein Damenopfer öffnet die Linie, dann krönt der Läufer den Angriff.","Dame schlägt auf f3 – Auftakt der entscheidenden Kombination."],"en":["A combination wins decisively — a quiet mate looms unstoppably.","A queen sacrifice opens the line, then the bishop crowns the attack.","Queen takes on f3 — the start of the decisive combination."],"hr":["Kombinacija odlučno dobiva — tihi mat nezaustavljivo prijeti.","Žrtva dame otvara liniju, a onda lovac kruni napad.","Dama uzima na f3 — početak odlučne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.123' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend – leise Drohungen lähmen die Verteidigung.","Ein Turmopfer öffnet die Linie, dann setzt die Dame zum stillen Schlag an.","Turm schlägt auf h3 – Auftakt der entscheidenden Kombination."],"en":["A combination wins decisively — quiet threats paralyze the defense.","A rook sacrifice opens the line, then the queen sets up the quiet blow.","Rook takes on h3 — the start of the decisive combination."],"hr":["Kombinacija odlučno dobiva — tihe prijetnje paraliziraju obranu.","Žrtva topa otvara liniju, a onda dama sprema tihi udarac.","Top uzima na h3 — početak odlučne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.124' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – das alte Turm-Springer-Mattbild lauert.","Ein Springer dringt ein, dann führt das Zusammenspiel mit Turm und Dame zum Matt.","Springer schlägt auf f6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here — the old rook-and-knight pattern lurks.","A knight invades, then the rook and queen combine for mate.","Knight takes on f6 — the start of the forced mating sequence."],"hr":["Tu je prisilni mat — vreba stari uzorak topa i skakača.","Skakač prodire, a onda se top i dama udružuju za mat.","Skakač uzima na f6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.125' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – ruhige Züge ziehen das Netz zusammen.","Ein Damenopfer öffnet die Königsstellung, dann übernehmen die Türme.","Dame schlägt auf g6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate awaits — calm moves draw the net together.","A queen sacrifice opens the king, then the rooks take over.","Queen takes on g6 — the start of the forced mating sequence."],"hr":["Čeka prisilni mat — mirni potezi stežu mrežu.","Žrtva dame otvara kralja, a onda topovi preuzimaju.","Dama uzima na g6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.126' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein berühmtes Mattbild gegen die Rochade.","Ein Springeropfer reißt die Bauern weg, dann jagen Dame und Turm den König.","Springer schlägt auf g6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here — a famous pattern against the castled king.","A knight sacrifice strips the pawns, then queen and rook hunt the king.","Knight takes on g6 — the start of the forced mating sequence."],"hr":["Tu je prisilni mat — slavni uzorak protiv rokiranog kralja.","Žrtva skakača skida pješake, a onda dama i top love kralja.","Skakač uzima na g6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.127' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – stille Züge erdrücken den König.","Ein Läuferopfer zieht den Bauern weg, dann jagen Dame und Turm das Matt.","Läufer schlägt auf g6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here — quiet moves crush the king.","A bishop sacrifice removes the pawn, then queen and rook deliver mate.","Bishop takes on g6 — the start of the forced mating sequence."],"hr":["Tu je prisilni mat — tihi potezi gnječe kralja.","Žrtva lovca uklanja pješaka, a onda dama i top donose mat.","Lovac uzima na g6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:011.128' AND BookFileName='chessable-u5-21646.pgn';
