UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König ist im Netz – hier wartet ein erzwungenes Matt.","Dein Turm in der zweiten Reihe spinnt zusammen mit den vorgerückten Bauern das Mattnetz.","Turm nach c2 – Auftakt der Mattführung."],"en":["The enemy king is caught — there is a forced mate here.","Your rook on the back side ranks works with the advanced pawns to weave the net.","Rook to c2 — the start of the forced mate."],"hr":["Protivnički kralj je u mreži — ovdje čeka prisilni mat.","Tvoj top na drugoj liniji s napredovalim pješacima plete matnu mrežu.","Top na c2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.159' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König lässt sich einschnüren – mit einem Königsmarsch holst du das Material.","Dein eigener König rückt vor und nimmt dem Gegner die Fluchtfelder.","König nach c4 – Beginn der entscheidenden Einkreisung."],"en":["The white king can be hemmed in — a king march wins decisive material.","Your own king steps forward and strips the enemy of escape squares.","King to c4 — the start of the decisive squeeze."],"hr":["Bijelog kralja se može stisnuti — kraljevim maršem osvajaš materijal.","Tvoj vlastiti kralj kreće naprijed i oduzima protivniku polja bijega.","Kralj na c4 — početak odlučujućeg stiskanja."]}', HintsVersion=1 WHERE LineId LIKE '%:011.160' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein leiser Zug schneidet dem König die Flucht ab und erzwingt das Matt.","Deine Dame übernimmt die Hauptarbeit und schließt den König ein.","Dame nach h4 – Eröffnung der Mattführung."],"en":["A quiet move cuts off the king''s escape and forces mate.","Your queen does the heavy lifting and seals the king in.","Queen to h4 — the start of the forced mate."],"hr":["Tihi potez kralju oduzima bijeg i prisiljava mat.","Tvoja dama obavlja glavni posao i zatvara kralja.","Dama na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.161' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer reißt die Königsstellung auf und gewinnt entscheidend.","Die Dame opfert sich, danach übernehmen Turm und Läufer.","Dame schlägt auf g6 – Einleitung der gewinnenden Kombination."],"en":["A queen sacrifice tears open the king and wins decisively.","The queen offers herself, then the rook and bishop finish the job.","Queen takes on g6 — the start of the winning combination."],"hr":["Žrtva dame razbija kraljev položaj i odlučujuće dobiva.","Dama se žrtvuje, a zatim top i lovac preuzimaju posao.","Dama uzima na g6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.162' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König ist eingemauert – ein Opfer erzwingt das Matt.","Deine Dame opfert sich, damit Turm und Läufer das Netz schließen.","Dame nach f2 – Auftakt der erzwungenen Mattführung."],"en":["The king is boxed in — a sacrifice forces mate.","Your queen sacrifices herself so the rook and bishop can close the net.","Queen to f2 — the start of the forced mate."],"hr":["Kralj je zazidan — žrtva prisiljava mat.","Tvoja dama se žrtvuje da top i lovac zatvore mrežu.","Dama na f2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.163' AND BookFileName='chessable-u5-21646.pgn';
