UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße Freibauer droht zu wandeln – ein präziser Zug stoppt ihn und gewinnt Material.","Dein Springer springt ein und legt der gegnerischen Dame eine Falle.","Springer nach c6 – Beginn der gewinnenden Verteidigung."],"en":["The white passed pawn threatens to queen — a precise move stops it and wins material.","Your knight steps in and sets a trap for the enemy queen.","Knight to c6 — the start of the winning defence."],"hr":["Bijeli slobodni pješak prijeti pretvorbom — precizan potez ga zaustavlja i osvaja materijal.","Tvoj skakač uskače i postavlja zamku protivničkoj dami.","Skakač na c6 — početak dobitne obrane."]}', HintsVersion=1 WHERE LineId LIKE '%:012.004' AND BookFileName='chessable-u5-21646.pgn';
