UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die königliche Deckung auf und sichert dir entscheidenden Vorteil.","Deine Dame leitet die Kombination ein, der gegnerische König wird entblößt.","Dame schlägt auf h2 – Beginn der gewinnbringenden Kombination."],"en":["A sacrifice tears open the king''s cover and wins decisively.","Your queen launches the combination and strips the enemy king bare.","Queen takes on h2 — the start of the winning combination."],"hr":["Žrtva razbija zaštitu kralja i osvaja odlučujuću prednost.","Tvoja dama pokreće kombinaciju i ogoljuje protivničkog kralja.","Dama uzima na h2 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.006' AND BookFileName='chessable-u5-21646.pgn';
