UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst unter Druck durch den Freibauern, doch ein zäher Konter sichert dir den entscheidenden Vorteil.","Der Springer muss aktiv eingreifen und die feindliche Stellung stören.","Springer nach d3 – leitet die rettende Gegenaktion ein."],"en":["The passed pawn presses you, but an accurate counter secures a decisive edge.","Your knight must jump in and disrupt the enemy setup.","Knight to d3 — starting the saving counter."],"hr":["Slobodni pješak te pritišće, ali precizan protuudar osigurava odlučujuću prednost.","Tvoj skakač mora uskočiti i poremetiti protivnički raspored.","Skakač na d3 — započinje spasonosni protuudar."]}', HintsVersion=1 WHERE LineId LIKE '%:012.066' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen den gefährlichen Freibauern hilft ein scharfer Schlag, der dir den Vorteil verschafft.","Der Läufer nimmt eine wichtige Figur und ebnet den Weg.","Läufer schlägt auf c6 – startet die gewinnträchtige Folge."],"en":["Against the dangerous passer, a sharp capture turns the tables in your favor.","Your bishop removes a key piece and clears the path.","Bishop takes on c6 — beginning the winning sequence."],"hr":["Protiv opasnog slobodnjaka oštar udarac preokreće stvari u tvoju korist.","Tvoj lovac uklanja ključnu figuru i krči put.","Lovac uzima na c6 — početak dobitne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:012.067' AND BookFileName='chessable-u5-21646.pgn';
