UPDATE BookPuzzles SET HintsJson='{"de":["Kein Remis – ein präziser Schlag holt den vollen Vorteil heraus.","Der Läufer schaltet eine Figur aus und entscheidet.","Läufer schlägt auf f8 – gewinnt material."],"en":["No draw here — a precise capture grabs the full advantage.","Your bishop eliminates a piece and decides matters.","Bishop takes on f8 — winning material."],"hr":["Bez remija — precizan udarac uzima punu prednost.","Tvoj lovac uklanja figuru i odlučuje stvar.","Lovac uzima na f8 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:012.069' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Kein Remis – ein versteckter Trick führt zum vollen Punkt.","Der Läufer opfert sich, um den entscheidenden Springervorstoß zu ermöglichen.","Läufer nach b5 – leitet die gewinnträchtige Kombination ein."],"en":["No draw — a hidden trick brings home the full point.","Your bishop sacrifices itself to set up the decisive knight blow.","Bishop to b5 — launching the winning combination."],"hr":["Bez remija — skriveni trik donosi puni bod.","Tvoj lovac se žrtvuje da omogući odlučujući udarac skakača.","Lovac na b5 — pokreće dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.070' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt Remis steckt hier ein gewinnender Angriff drin.","Erst opfert die Dame, dann reitet der Springer die Attacke.","Dame schlägt auf f2 – Auftakt der gewinnträchtigen Kombination."],"en":["Rather than a draw, a winning attack is lurking here.","First the queen offers itself, then the knight rides the attack home.","Queen takes on f2 — the start of the winning combination."],"hr":["Umjesto remija, ovdje vreba dobitni napad.","Prvo se dama žrtvuje, a onda skakač privodi napad kraju.","Dama uzima na f2 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.071' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Kein Remis – der König marschiert mutig zum Sieg.","Der eigene König greift selbst aktiv ein und gewinnt das Tempo.","König nach d4 – beginnt den entscheidenden Vormarsch."],"en":["No draw — the king himself marches boldly to victory.","Your own king becomes the active piece and wins the race.","King to d4 — starting the decisive march."],"hr":["Bez remija — kralj sam hrabro maršira do pobjede.","Tvoj kralj postaje aktivna figura i dobiva utrku.","Kralj na d4 — započinje odlučujući marš."]}', HintsVersion=1 WHERE LineId LIKE '%:012.072' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Kein Remis – der König läuft den feindlichen Schachs davon und gewinnt.","Der König muss selbst vorrücken und sich der Verfolgung entziehen.","König nach h4 – leitet den siegbringenden Königsmarsch ein."],"en":["No draw — the king outruns the checks and wins.","The king must advance himself and escape the pursuit.","King to h4 — beginning the winning king walk."],"hr":["Bez remija — kralj izmiče šahovima i pobjeđuje.","Kralj mora sam napredovati i izbjeći progon.","Kralj na h4 — započinje pobjednički marš kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:012.073' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Kein Remis – hier steht ein erzwungenes Matt zur Verfügung.","Die Dame führt die Jagd, der eigene Freibauer entscheidet im Hintergrund.","Dame nach g8 – beginnt das erzwungene Matt."],"en":["No draw — a forced mate is available here.","The queen leads the hunt while your passed pawn decides in the background.","Queen to g8 — beginning the forced mate."],"hr":["Bez remija — ovdje je dostupan prisilni mat.","Dama vodi lov dok tvoj slobodni pješak odlučuje u pozadini.","Dama na g8 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:012.074' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine entlastende Kombination dreht den Spieß um und gewinnt.","Erst opfert die Dame, dann erobert der Turm das Feld.","Dame schlägt auf e1 – Auftakt der gewinnträchtigen Folge."],"en":["A liberating combination turns the tables and wins.","First the queen sacrifices, then the rook seizes the square.","Queen takes on e1 — the start of the winning sequence."],"hr":["Oslobađajuća kombinacija preokreće stvari i pobjeđuje.","Prvo se dama žrtvuje, a onda top zauzima polje.","Dama uzima na e1 — početak dobitne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:012.075' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen die Mattdrohung hilft ein Schlag, der eine ganze Figur einbringt.","Der Turm räumt eine Figur ab und entschärft die Gefahr.","Turm schlägt auf c4 – beginnt die gewinnbringende Folge."],"en":["Against the mate threat, a capture nets a whole piece.","Your rook removes a piece and defuses the danger.","Rook takes on c4 — starting the winning sequence."],"hr":["Protiv prijetnje matom, udarac donosi cijelu figuru.","Tvoj top uklanja figuru i razoružava opasnost.","Top uzima na c4 — započinje dobitnu sekvencu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.076' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Mattgefahr lässt sich abwehren, ja sogar in Vorteil verwandeln.","Der Läufer geht aktiv vor und stellt eine eigene Drohung auf.","Läufer nach g5 – leitet die vorteilbringende Verteidigung ein."],"en":["The mating danger can be parried — even turned into an edge.","Your bishop steps forward and sets up a threat of its own.","Bishop to g5 — beginning the advantageous defense."],"hr":["Prijetnja matom se može odbiti — čak pretvoriti u prednost.","Tvoj lovac istupa naprijed i postavlja vlastitu prijetnju.","Lovac na g5 — započinje povoljnu obranu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.077' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen die Mattdrohung gibt es eine aktive Lösung, die ausgleicht und mehr.","Die Dame zentralisiert sich und schafft Gegenspiel.","Dame nach d5 – beginnt die rettende Gegenaktion."],"en":["Against the mate threat there is an active solution that equalizes and more.","Your queen centralizes and creates counterplay.","Queen to d5 — beginning the saving counteraction."],"hr":["Protiv prijetnje matom postoji aktivno rješenje koje izjednačava i više.","Tvoja dama se centralizira i stvara protuigru.","Dama na d5 — započinje spasonosni protuudar."]}', HintsVersion=1 WHERE LineId LIKE '%:012.078' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Mattdrohung wehrst du mit einem aktiven Zug ab, der selbst angreift.","Die Dame springt heraus und stellt eine Gegendrohung.","Dame nach g5 – beginnt die vorteilbringende Verteidigung."],"en":["You meet the mate threat with an active move that strikes back.","Your queen leaps out and sets up a counter-threat.","Queen to g5 — beginning the advantageous defense."],"hr":["Prijetnju matom dočekuješ aktivnim potezom koji uzvraća udarac.","Tvoja dama iskače i postavlja protuprijetnju.","Dama na g5 — započinje povoljnu obranu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.079' AND BookFileName='chessable-u5-21646.pgn';
