UPDATE BookPuzzles SET HintsJson='{"de":["Die Mattgefahr verschwindet durch eine Kombination, die den Vorteil sichert.","Erst opfert die Dame, dann übernimmt der Turm die Initiative.","Dame schlägt auf g1 – Auftakt der gewinnträchtigen Folge."],"en":["The mating danger vanishes via a combination that secures the advantage.","First the queen sacrifices, then the rook takes over the initiative.","Queen takes on g1 — the start of the winning sequence."],"hr":["Prijetnja matom nestaje kombinacijom koja osigurava prednost.","Prvo se dama žrtvuje, a onda top preuzima inicijativu.","Dama uzima na g1 — početak dobitne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:012.081' AND BookFileName='chessable-u5-21646.pgn';
