UPDATE BookPuzzles SET HintsJson='{"de":["Die Mattgefahr drehst du mit Tempozügen in eigenen Vorteil um.","Die Dame jagt mit Schachs und manövriert zur entscheidenden Stelle.","Dame nach e3 – beginnt die vorteilbringende Verteidigung."],"en":["You turn the mating danger into your own edge with tempo moves.","Your queen drives with checks and maneuvers to the key square.","Queen to e3 — beginning the advantageous defense."],"hr":["Prijetnju matom pretvaraš u vlastitu prednost potezima s tempom.","Tvoja dama goni šahovima i manevrira do ključnog polja.","Dama na e3 — započinje povoljnu obranu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.083' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen die Mattdrohung verteidigst du aktiv und behältst den Vorteil.","Der Läufer schaltet sich ein und sichert die kritischen Felder.","Läufer nach g5 – leitet die rettende Verteidigung ein."],"en":["You defend the mate threat actively and keep the advantage.","Your bishop steps in and shores up the critical squares.","Bishop to g5 — beginning the saving defense."],"hr":["Prijetnju matom braniš aktivno i zadržavaš prednost.","Tvoj lovac se uključuje i osigurava kritična polja.","Lovac na g5 — započinje spasonosnu obranu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.084' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen das drohende Matt rettet eine kühle Verteidigung, die in Vorteil mündet.","Der Turm zieht sich klug zurück und deckt entscheidende Punkte.","Turm nach b1 – beginnt die vorteilbringende Verteidigung."],"en":["Against the looming mate, a cool defense rescues you and yields an edge.","Your rook retreats cleverly and covers the decisive points.","Rook to b1 — beginning the advantageous defense."],"hr":["Protiv prijetećeg mata, hladna obrana te spašava i donosi prednost.","Tvoj top se mudro povlači i pokriva odlučujuće točke.","Top na b1 — započinje povoljnu obranu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.085' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Mattgefahr lässt sich durch beherztes Abtauschen in Vorteil verwandeln.","Die Dame bietet sich an und vereinfacht zu deinen Gunsten.","Dame nach f6 – leitet die vorteilbringende Folge ein."],"en":["The mating danger can be turned into an edge by bold exchanges.","Your queen offers itself and simplifies in your favor.","Queen to f6 — beginning the advantageous sequence."],"hr":["Prijetnja matom se može pretvoriti u prednost smjelim razmjenama.","Tvoja dama se nudi i pojednostavljuje u tvoju korist.","Dama na f6 — započinje povoljnu sekvencu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.086' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen die Mattdrohung verteidigst du genau und sicherst dir den Vorteil.","Der König weicht geschickt aus und überlebt die Angriffe.","König nach c1 – beginnt die rettende Verteidigung."],"en":["Against the mate threat you defend precisely and secure the advantage.","Your king sidesteps cleverly and survives the assaults.","King to c1 — beginning the saving defense."],"hr":["Protiv prijetnje matom braniš se precizno i osiguravaš prednost.","Tvoj kralj vješto izmiče i preživljava napade.","Kralj na c1 — započinje spasonosnu obranu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.087' AND BookFileName='chessable-u5-21646.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen die Mattdrohung gibt es eine aktive Lösung, die dir den Vorteil bringt.","Der Springer greift mit Schach ein und gewinnt das nötige Tempo.","Springer nach e7 – leitet die vorteilbringende Verteidigung ein."],"en":["Against the mate threat there is an active solution that gives you the edge.","Your knight intervenes with check and wins the needed tempo.","Knight to e7 — beginning the advantageous defense."],"hr":["Protiv prijetnje matom postoji aktivno rješenje koje ti daje prednost.","Tvoj skakač se umiješa šahom i dobiva potreban tempo.","Skakač na e7 — započinje povoljnu obranu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.088' AND BookFileName='chessable-u5-21646.pgn';
