UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff trifft zwei Figuren auf einmal und gewinnt Material.","Die Dame stellt sich so auf, dass sie beide gegnerischen Leichtfiguren gleichzeitig bedroht.","Dame nach e4 – sie gabelt beide Springer und gewinnt einen."],"en":["A double attack hits two pieces at once and wins material.","The queen places herself to threaten both enemy minor pieces at the same time.","Queen to e4 — forking both knights and winning one."],"hr":["Dvostruki napad pogađa dvije figure odjednom i osvaja materijal.","Dama se postavlja tako da istovremeno prijeti objema protivničkim lakim figurama.","Dama na e4 — napada oba skakača i osvaja jednoga."]}', HintsVersion=1 WHERE LineId LIKE '%:002.004' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Fesselung legt eine Figur lahm und gewinnt sie.","Der Turm fesselt die Leichtfigur gegen ihren König.","Turm nach e1 – fesselt den Springer und gewinnt ihn."],"en":["A pin freezes a piece and wins it.","The rook pins the minor piece against its king.","Rook to e1 — pinning the knight and winning it."],"hr":["Vezivanje sputava figuru i osvaja je.","Top veže laku figuru uz njezina kralja.","Top na e1 — veže skakača i osvaja ga."]}', HintsVersion=1 WHERE LineId LIKE '%:002.005' AND BookFileName='chessable-u5-49693.pgn';
