UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelschach schränkt den Gegner brutal ein und gewinnt.","Der Läufer schaltet sich ein, während der Turm zugleich Schach bietet.","Läufer nach h5 – Doppelschach, dem nur Königszüge ausweichen."],"en":["A double check brutally restricts the opponent and wins.","The bishop joins in while the rook checks at the same time.","Bishop to h5 — a double check that only a king move can meet."],"hr":["Dvostruki šah brutalno ograničava protivnika i dobiva.","Lovac se uključuje dok top istovremeno daje šah.","Lovac na h5 — dvostruki šah na koji odgovara samo potez kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:002.009' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schlägt man den Beschützer, fällt die geschützte Figur.","Der Läufer beseitigt den Verteidiger der gegnerischen Figur.","Läufer schlägt auf d6 – zerstört den Beschützer und gewinnt."],"en":["Capture the protector and the guarded piece falls.","The bishop removes the defender of the enemy piece.","Bishop takes on d6 — destroying the guard and winning."],"hr":["Uzmi zaštitnika i zaštićena figura pada.","Lovac uklanja branitelja protivničke figure.","Lovac uzima na d6 — uništava zaštitnika i osvaja."]}', HintsVersion=1 WHERE LineId LIKE '%:002.010' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauer lockt einen Verteidiger weg und ermöglicht den Durchbruch.","Der vorrückende Bauer wirkt als Ablenker der gegnerischen Dame.","Bauer nach c7 – lenkt die Dame ab und leitet die Entscheidung ein."],"en":["A pawn lures a defender away and opens the breakthrough.","The advancing pawn acts as a deflector of the enemy queen.","Pawn to c7 — deflecting the queen and starting the decisive line."],"hr":["Pješak odvlači branitelja i otvara proboj.","Pješak koji napreduje djeluje kao odvlačitelj protivničke dame.","Pješak na c7 — odvlači damu i pokreće odlučujući slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:002.011' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Stellung.","Die Dame opfert sich, um den Turm auf ein verhängnisvolles Feld zu locken.","Dame nach g8 – Opfer, das den Turm anlockt und zum Matt führt."],"en":["A forced mate is hidden in the position.","The queen sacrifices herself to lure the rook to a fatal square.","Queen to g8 — a decoy sacrifice that leads to mate."],"hr":["U položaju se krije prisilni mat.","Dama se žrtvuje da namami topa na pogubno polje.","Dama na g8 — žrtva mamac koja vodi do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:002.012' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft.","Der Turm räumt ein Feld, damit die Dame das tödliche Feld besetzen kann.","Turm schlägt auf h6 – räumt das Feld und bahnt der Dame das Matt."],"en":["A forced mate is in the air.","A rook clears a square so the queen can occupy the killing square.","Rook takes on h6 — vacating the square to open the queen''s mate."],"hr":["U zraku je prisilni mat.","Top oslobađa polje da dama može zauzeti smrtonosno mjesto.","Top uzima na h6 — oslobađa polje i otvara damin mat."]}', HintsVersion=1 WHERE LineId LIKE '%:002.013' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Liniendurchbruch entfesselt eine Drohung und gewinnt.","Der Läufer räumt die Linie, damit die Dame zur Mattdrohung durchgreift.","Läufer schlägt auf c7 – öffnet die Linie und droht entscheidend."],"en":["Clearing a line unleashes a threat and wins.","The bishop vacates the file so the queen breaks through to threaten mate.","Bishop takes on c7 — opening the file with a decisive threat."],"hr":["Oslobađanje linije oslobađa prijetnju i dobiva.","Lovac napušta liniju da dama probije do prijetnje matom.","Lovac uzima na c7 — otvara liniju uz odlučujuću prijetnju."]}', HintsVersion=1 WHERE LineId LIKE '%:002.014' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zwischenzug kehrt den scheinbar erzwungenen Abtausch um.","Der Läufer schlägt zu und legt eine versteckte Gegendrohung frei.","Läufer schlägt auf f6 – ein Zwischenschlag, der Material gewinnt."],"en":["An in-between move overturns the seemingly forced exchange.","The bishop captures and reveals a hidden counter-threat.","Bishop takes on f6 — an in-between blow that wins material."],"hr":["Međupotez preokreće naizgled prisilnu razmjenu.","Lovac uzima i otkriva skrivenu protuprijetnju.","Lovac uzima na f6 — međupotez koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:002.015' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine ohnehin verlorene Figur richtet vorher noch Schaden an.","Der Springer ist nicht zu retten, ruiniert aber die gegnerische Struktur.","Springer nach f6 – ein Desperado, der die Königsstellung zerschlägt."],"en":["A doomed piece does damage before it goes.","The knight cannot be saved but wrecks the enemy structure.","Knight to f6 — a desperado that smashes the king''s shelter."],"hr":["Ionako izgubljena figura prije nestanka nanosi štetu.","Skakač se ne može spasiti, ali razara protivničku strukturu.","Skakač na f6 — očajnik koji razbija kraljev zaklon."]}', HintsVersion=1 WHERE LineId LIKE '%:002.016' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier ist Weiß im Vorteil; der schwarze König muss weichen und gibt Boden preis.","Der König muss zur Seite, sodass der weiße König entscheidend vordringt.","König nach d8 – aus Zugzwang weichend, danach dringt Weiß durch."],"en":["White stands well here; the black king must give way and yield ground.","The king is forced aside, letting the white king push through decisively.","King to d8 — stepping back in zugzwang, then White breaks through."],"hr":["Bijeli stoji dobro; crni kralj mora ustuknuti i prepustiti teren.","Kralj je prisiljen u stranu, što bijelom kralju omogućuje odlučujući prodor.","Kralj na d8 — uzmiče u cugcvangu, nakon čega bijeli probija."]}', HintsVersion=1 WHERE LineId LIKE '%:002.017' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß steht schlechter im Tempokampf und muss sich ins Remis retten.","Der König muss ziehen und gibt dabei den Vorteil aus der Hand – nur Remis.","König nach d6 – der einzige Versuch, das Remis zu halten."],"en":["White is on the wrong side of the tempo battle and must hold a draw.","The king must move and surrenders the edge — only a draw remains.","King to d6 — the lone try to keep the draw."],"hr":["Bijeli je na lošoj strani borbe za tempo i mora spasiti remi.","Kralj mora potezati i predaje prednost — ostaje samo remi.","Kralj na d6 — jedini pokušaj da se zadrži remi."]}', HintsVersion=1 WHERE LineId LIKE '%:002.018' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Schach beendet die Partie sofort.","Die Dame greift quer übers Brett zur Mattführung.","Dame nach f8 – matt."],"en":["A single check ends the game at once.","The queen reaches across the board to deliver mate.","Queen to f8 — mate."],"hr":["Jedan jedini šah odmah završava partiju.","Dama seže preko ploče da zada mat.","Dama na f8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.003' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein gefangener Turm ohne Fluchtfeld lässt sich erbeuten.","Ein Läufer greift den fluchtunfähigen Turm an.","Läufer nach c2 – fängt den eingeklemmten Turm."],"en":["A trapped rook with no flight square can be won.","A bishop attacks the rook that has nowhere to run.","Bishop to c2 — trapping the immobile rook."],"hr":["Zarobljeni top bez polja za bijeg može se osvojiti.","Lovac napada topa koji nema kamo pobjeći.","Lovac na c2 — hvata sputanog topa."]}', HintsVersion=1 WHERE LineId LIKE '%:003.004' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die verwundbare Grundreihe erlaubt ein erzwungenes Matt.","Ein Abzug der Dame und die Türme arbeiten gegen die letzte Reihe.","Dame schlägt auf c1 – leitet das Grundreihenmatt ein."],"en":["The vulnerable back rank allows a forced mate.","A queen sacrifice and the rooks combine against the last rank.","Queen takes on c1 — starting the back-rank mate."],"hr":["Ranjivi zadnji red dopušta prisilni mat.","Žrtva dame i topovi udružuju se protiv posljednjeg reda.","Dama uzima na c1 — pokreće mat po zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:003.005' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff trifft beide Springer auf einmal.","Der Läufer stellt sich zentral und gabelt die zwei Springer.","Läufer nach e4 – gabelt beide Springer und gewinnt einen."],"en":["A double attack hits both knights at once.","The bishop comes to the centre and forks the two knights.","Bishop to e4 — forking both knights and winning one."],"hr":["Dvostruki napad pogađa oba skakača odjednom.","Lovac dolazi u centar i napada oba skakača.","Lovac na e4 — napada oba skakača i osvaja jednoga."]}', HintsVersion=1 WHERE LineId LIKE '%:003.006' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein gefangener Läufer entscheidet die Partie.","Ein vorrückender Bauer treibt den König weg und fängt den Läufer.","Bauer nach c5 – beginnt den Marsch, der den Läufer einkassiert."],"en":["A trapped bishop decides the game.","An advancing pawn drives the king off and snares the bishop.","Pawn to c5 — beginning the march that wins the bishop."],"hr":["Zarobljeni lovac odlučuje partiju.","Pješak koji napreduje tjera kralja i hvata lovca.","Pješak na c5 — započinje pohod koji osvaja lovca."]}', HintsVersion=1 WHERE LineId LIKE '%:003.007' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Angriffsstellung.","Die Dame greift den Turm an und entfesselt zugleich einen Angriff auf die weiße Dame.","Dame nach g4 – Doppeldrohung, die in ein erzwungenes Matt mündet."],"en":["A forced mate lies in the attacking position.","The queen attacks the rook while uncovering a hit on the white queen.","Queen to g4 — a double threat that leads to forced mate."],"hr":["U napadačkom položaju krije se prisilni mat.","Dama napada topa i istovremeno otkriva napad na bijelu damu.","Dama na g4 — dvostruka prijetnja koja vodi do prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.008' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein schlecht platzierter Turm lässt sich einfangen.","Ein Läufer schwenkt herüber und nimmt dem Turm die Felder.","Läufer schlägt auf c7 – fängt und gewinnt den Turm."],"en":["A badly placed rook can be trapped.","A bishop swings over and takes away the rook''s squares.","Bishop takes on c7 — trapping and winning the rook."],"hr":["Loše postavljeni top može se uhvatiti.","Lovac se prebacuje i oduzima topu polja.","Lovac uzima na c7 — hvata i osvaja topa."]}', HintsVersion=1 WHERE LineId LIKE '%:003.009' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die gegnerische Dame steht eingesperrt und fällt.","Ein Turm stößt vor und schneidet der Dame die Fluchtwege ab.","Turm nach d5 – fängt die weiße Dame."],"en":["The enemy queen is boxed in and falls.","A rook thrusts forward and cuts off the queen''s escape.","Rook to d5 — trapping the white queen."],"hr":["Protivnička dama je zatvorena i pada.","Top prodire i presijeca dami puteve bijega.","Top na d5 — hvata bijelu damu."]}', HintsVersion=1 WHERE LineId LIKE '%:003.010' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gegen den König ist trotz Materialrückstand entscheidend.","Der Springer stürmt heran, danach setzt die Dame nach.","Springer nach f6 – Auftakt zur entscheidenden Königsjagd."],"en":["A blow at the king is decisive despite the material deficit.","The knight storms in, then the queen follows up.","Knight to f6 — the start of the decisive attack on the king."],"hr":["Udarac na kralja je odlučujući unatoč manjku materijala.","Skakač juriša, a zatim dama nastavlja napad.","Skakač na f6 — početak odlučujućeg napada na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:003.011' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug enthüllt einen Angriff auf die Dame und gewinnt sie.","Der Läufer schlägt mit Schach und legt den Treffer auf die Dame frei.","Läufer schlägt auf h2 – Abzug, der die weiße Dame gewinnt."],"en":["A discovery uncovers an attack on the queen and wins it.","The bishop captures with check, revealing the hit on the queen.","Bishop takes on h2 — a discovery that wins the white queen."],"hr":["Otkriće razotkriva napad na damu i osvaja je.","Lovac uzima sa šahom i otkriva udar na damu.","Lovac uzima na h2 — otkriće koje osvaja bijelu damu."]}', HintsVersion=1 WHERE LineId LIKE '%:003.012' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein eingesperrter Turm ohne Ausweg fällt.","Die Dame greift den Turm an, der nirgendwohin ausweichen kann.","Dame nach d6 – fängt den bewegungslosen Turm."],"en":["A boxed-in rook with no escape falls.","The queen attacks the rook that has nowhere to go.","Queen to d6 — trapping the immobile rook."],"hr":["Zatvoreni top bez izlaza pada.","Dama napada topa koji nema kamo poći.","Dama na d6 — hvata nepomičnog topa."]}', HintsVersion=1 WHERE LineId LIKE '%:003.013' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die ungünstige Aufstellung von König und Dame lässt sich ausnutzen.","Ein Läufer fesselt die Dame gegen den König und gewinnt sie.","Läufer nach d4 – fesselt und gewinnt die schwarze Dame."],"en":["The awkward placing of king and queen can be exploited.","A bishop pins the queen against the king and wins it.","Bishop to d4 — pinning and winning the black queen."],"hr":["Nezgodan raspored kralja i dame može se iskoristiti.","Lovac veže damu uz kralja i osvaja je.","Lovac na d4 — veže i osvaja crnu damu."]}', HintsVersion=1 WHERE LineId LIKE '%:003.014' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zerstörungsopfer reißt den König heraus und gewinnt entscheidend.","Der Läufer opfert sich gegen den Bauernschild, dann greift die Dame zu.","Läufer schlägt auf h7 – Opfer, das die entscheidende Kombination einleitet."],"en":["A destruction sacrifice rips the king out and wins decisively.","The bishop sacrifices against the pawn shield, then the queen strikes.","Bishop takes on h7 — a sacrifice that starts the winning combination."],"hr":["Žrtva razaranja izvlači kralja i odlučujuće dobiva.","Lovac se žrtvuje protiv pješačkog štita, a zatim dama udara.","Lovac uzima na h7 — žrtva koja pokreće dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:003.015' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt war hier zum Greifen nah.","Die Dame dringt ein, dann hilft der Springer beim Mattnetz.","Dame schlägt auf c2 – Auftakt zum erzwungenen Matt."],"en":["A forced mate was within reach here.","The queen breaks in, then the knight helps weave the mating net.","Queen takes on c2 — the start of the forced mate."],"hr":["Prisilni mat bio je nadohvat ruke.","Dama prodire, a zatim skakač pomaže isplesti matnu mrežu.","Dama uzima na c2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.016' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt beendet den Widerstand rasch.","Die Dame stößt vor und Turm und Dame jagen den König.","Dame nach f4 – beginnt die schnelle Mattführung."],"en":["A forced mate ends the resistance quickly.","The queen pushes forward and queen and rook hunt the king.","Queen to f4 — beginning the swift mating sequence."],"hr":["Prisilni mat brzo okončava otpor.","Dama prodire, a dama i top progone kralja.","Dama na f4 — započinje brzi matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:003.017' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springersprung gabelt zwei wertvolle Stücke gleichzeitig.","Der Springer findet einen Vorposten, der Dame und Turm zugleich bedroht.","Springer nach e4 – gabelt Dame und Turm und gewinnt die Qualität."],"en":["A knight leap forks two valuable pieces at once.","The knight reaches an outpost that hits both the queen and a rook.","Knight to e4 — forking the queen and rook to win the exchange."],"hr":["Skok skakača istovremeno napada dvije vrijedne figure.","Skakač pronalazi uporište koje prijeti i dami i topu.","Skakač na e4 — viljuška na damu i topa, osvaja kvalitetu."]}', HintsVersion=1 WHERE LineId LIKE '%:003.018' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weit vorgerückte Freibauer lässt sich nicht mehr aufhalten.","Der Bauer marschiert zur Umwandlung, gedeckt von der Dame.","Bauer nach b3 – treibt den Freibauern unaufhaltsam zur Umwandlung."],"en":["The advanced passed pawn can no longer be stopped.","The pawn pushes toward promotion, backed by the queen.","Pawn to b3 — driving the passer unstoppably toward a new queen."],"hr":["Daleko napredovani slobodni pješak više se ne može zaustaviti.","Pješak juri u promociju, podržan damom.","Pješak na b3 — slobodnjak nezadrživo ide u promociju."]}', HintsVersion=1 WHERE LineId LIKE '%:003.019' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Fessel verwandelt den Angriff auf die Dame in einen Gewinn.","Die Dame schlägt furchtlos zu, weil der angreifende Läufer gefesselt steht.","Dame schlägt auf d3 – nutzt die Fesselung und gewinnt eine Figur."],"en":["A pin turns the attack on your queen into a winning blow.","The queen strikes fearlessly because the attacking bishop is pinned.","Queen takes on d3 — using the pin to win a piece."],"hr":["Vezivanje pretvara napad na damu u dobitni udarac.","Dama uzima bez straha jer je napadački lovac vezan.","Dama uzima na d3 — koristi vezu i osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:003.020' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein überlasteter Verteidiger erlaubt einen entscheidenden Gewinnstoß.","Der Springer schlägt zu, weil der deckende Läufer zwei Aufgaben hat.","Springer schlägt auf c7 – beginnt eine Kombination, die Material gewinnt."],"en":["An overloaded defender allows a decisive winning blow.","The knight strikes because the covering bishop has two jobs at once.","Knight takes on c7 — starting a combination that wins material."],"hr":["Preopterećeni branitelj dopušta odlučujući dobitni udarac.","Skakač udara jer pokrivajući lovac ima dvije zadaće.","Skakač uzima na c7 — započinje kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.021' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt den König heraus und entscheidet die Partie.","Der Läufer opfert sich, damit die Dame mit Gewinn eindringt.","Läufer schlägt auf f7 – lenkt den König ab und gewinnt entscheidend."],"en":["A sacrifice drags the king out and decides the game.","The bishop sacrifices itself so the queen can crash in.","Bishop takes on f7 — deflecting the king and winning decisively."],"hr":["Žrtva izvlači kralja i odlučuje partiju.","Lovac se žrtvuje da dama prodre s dobitkom.","Lovac uzima na f7 — odvlači kralja i odlučno dobiva."]}', HintsVersion=1 WHERE LineId LIKE '%:003.022' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zwischenzug entlarvt den überlasteten Verteidiger der weit entfernten Figur.","Ein Tausch lenkt die Dame ab, dann gabelt ein Läufer zwei Ziele.","Turm schlägt auf a7 – Auftakt zu einer Kombination, die eine Figur gewinnt."],"en":["A clearance move exposes the overloaded defender of the far-flung piece.","A trade pulls the queen away, then a bishop forks two targets.","Rook takes on a7 — beginning a combination that wins a piece."],"hr":["Uklanjanje otkriva preopterećenog branitelja udaljene figure.","Zamjena odvlači damu, a zatim lovac napada dva cilja.","Top uzima na a7 — početak kombinacije koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:003.023' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorabtausch räumt die Linie für eine Spießkombination frei.","Ein Springertausch öffnet die Bahn, dann spießt ein Turm zwei Figuren auf.","Springer schlägt auf d5 – Auftakt zum Spieß, der Material gewinnt."],"en":["A preliminary trade clears the line for a skewering combination.","A knight trade opens the path, then a rook skewers two pieces.","Knight takes on d5 — starting the skewer that wins material."],"hr":["Uvodna zamjena otvara liniju za nabod.","Zamjena skakača otvara put, a top nabada dvije figure.","Skakač uzima na d5 — početak nabadanja koje osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.024' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver landet auf einem Feld, das zwei Schwerfiguren gabelt.","Der Springer steuert einen Posten an, der Dame und Turm zugleich angreift.","Springer nach f6 – Auftakt zur Gabel auf Dame und Turm."],"en":["A knight maneuver lands on a square forking two heavy pieces.","The knight heads for a post that hits both queen and rook.","Knight to f6 — beginning the sequence that forks queen and rook."],"hr":["Manevar skakača vodi na polje koje napada dvije teške figure.","Skakač cilja na polje koje istovremeno prijeti dami i topu.","Skakač na f6 — početak niza koji daje viljušku na damu i topa."]}', HintsVersion=1 WHERE LineId LIKE '%:003.025' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Überlastung der gegnerischen Dame gewinnt einen wichtigen Bauern.","Ein Turmopfer lenkt die Dame ab, dann holt die eigene Dame Material.","Turm schlägt auf f2 – überlastet die Dame und gewinnt einen Bauern."],"en":["Overloading the enemy queen wins a vital pawn.","A rook offer pulls the queen off, then your own queen grabs material.","Rook takes on f2 — overloading the queen to win a pawn."],"hr":["Preopterećenje protivničke dame osvaja važnog pješaka.","Žrtva topa odvlači damu, a zatim vlastita dama uzima materijal.","Top uzima na f2 — preopterećuje damu i osvaja pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:003.026' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Vorstoß fängt eine Figur ohne Fluchtfeld ein.","Ein Bauernzug nimmt dem Springer das letzte Rückzugsfeld.","Bauer nach b4 – fängt den Springer, der nirgendwohin entweichen kann."],"en":["A quiet advance traps a piece with no escape square.","A pawn move removes the knight''s last retreat.","Pawn to b4 — trapping the knight, which has nowhere to flee."],"hr":["Tihi prodor zarobljava figuru bez polja za bijeg.","Potez pješaka oduzima skakaču posljednje polje za uzmak.","Pješak na b4 — zarobljava skakača koji nema kamo pobjeći."]}', HintsVersion=1 WHERE LineId LIKE '%:003.027' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine eingeengte Dame mit wenig Fluchtfeldern lädt zu einer Spießkombination ein.","Erst lenken, dann spießt eine Schwerfigur die Dame an die dahinter stehende.","Läufer nach d2 – Auftakt zum Spieß, der die Dame fängt und Material gewinnt."],"en":["A cramped queen with few squares invites a skewering combination.","First deflect, then a heavy piece skewers the queen to the rook behind.","Bishop to d2 — beginning the skewer that wins material."],"hr":["Stiješnjena dama s malo polja poziva na nabod.","Prvo odvlačenje, zatim teška figura nabada damu na top iza nje.","Lovac na d2 — početak nabadanja koje osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.028' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsstoß reißt die Dame von der Deckung einer Figur weg.","Ein Bauernvorstoß vertreibt die Dame, dann fällt der ungedeckte Läufer.","Bauer nach h4 – lenkt die Dame ab und gewinnt eine Figur für einen Bauern."],"en":["A deflecting thrust tears the queen from defending a piece.","A pawn push chases the queen away, then the bishop falls.","Pawn to h4 — deflecting the queen to win a bishop for a pawn."],"hr":["Odvlačeći udarac otkida damu od obrane figure.","Prodor pješaka tjera damu, a zatim pada nebranjeni lovac.","Pješak na h4 — odvlači damu i osvaja lovca za pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:003.029' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine versteckte Spießkombination gewinnt eine Figur.","Ein Turm tritt auf eine Linie und spießt die Dame an einen Springer.","Turm nach d1 – spießt die Dame an den Springer und gewinnt eine Figur."],"en":["A hidden skewer along the open line wins a piece.","A rook steps onto a file, pinning the queen against a knight.","Rook to d1 — skewering the queen to the knight to win a piece."],"hr":["Skriveni nabod duž otvorene linije osvaja figuru.","Top staje na liniju i nabada damu na skakača.","Top na d1 — nabada damu na skakača i osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:003.030' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine überlastete Dame kann nicht zwei bedrohte Punkte zugleich decken.","Ein Springervorstoß stört die Dame und entfesselt eine Gewinnkombination.","Springer nach b6 – beginnt die Kombination, die eine Figur gewinnt."],"en":["An overloaded queen cannot guard two threatened points at once.","A knight thrust harasses the queen and unleashes a winning combination.","Knight to b6 — starting the combination that nets a piece."],"hr":["Preopterećena dama ne može braniti dvije ugrožene točke odjednom.","Skok skakača uznemiruje damu i pokreće dobitnu kombinaciju.","Skakač na b6 — započinje kombinaciju koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:003.031' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die richtige Zugfolge verwandelt Remis in einen klaren Vorteil.","Erst ein Läuferopfer, dann fängt ein Dameneinfall den Läufer doppelt.","Läufer schlägt auf f5 – Auftakt zur Folge, die entscheidend Material gewinnt."],"en":["Finding the right move order turns a draw into a clear edge.","First a bishop strike, then a queen sortie traps the bishop.","Bishop takes on f5 — starting the sequence that wins material."],"hr":["Pravi redoslijed poteza pretvara remi u jasnu prednost.","Prvo udar lovca, zatim damin ispad hvata lovca u dvostrukom napadu.","Lovac uzima na f5 — početak niza koji odlučno osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:003.032' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein erzwungenes Matt.","Ein Turm lockt durch Opfer den König heraus, dann mattet die Dame.","Turm schlägt auf g8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is waiting here.","A rook sacrifice lures the king out, then the queen delivers mate.","Rook takes on g8 — beginning the forced mating sequence."],"hr":["Ovdje čeka prisilni mat.","Žrtva topa izvlači kralja, a zatim dama daje mat.","Top uzima na g8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:003.033' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schachgebot mit Zwischenzug bringt die Stellung zum Einsturz.","Die Dame gibt Schach, danach schlägt ein Springer einen Turm.","Dame schlägt auf f2 – Schach als Auftakt, der entscheidend Material gewinnt."],"en":["An in-between check makes the whole position collapse.","The queen gives check, then a knight snaps off a rook.","Queen takes on f2 — a check that starts a decisive material win."],"hr":["Međupotez sa šahom ruši cijelu poziciju.","Dama daje šah, a zatim skakač uzima topa.","Dama uzima na f2 — šah koji započinje odlučujući dobitak materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:003.034' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Ablenkung der Verteidigung leitet eine Gewinnjagd auf den König ein.","Ein Turmopfer zieht den deckenden Turm fort, dann jagt die Dame den König.","Turm schlägt auf f8 – Auftakt zur Kombination, die entscheidend gewinnt."],"en":["Deflecting a defender launches a winning hunt against the king.","A rook offer removes the guarding rook, then the queen chases the king.","Rook takes on f8 — beginning the combination that wins decisively."],"hr":["Odvlačenje branitelja pokreće dobitni lov na kralja.","Žrtva topa uklanja čuvajućeg topa, a zatim dama goni kralja.","Top uzima na f8 — početak kombinacije koja odlučno dobiva."]}', HintsVersion=1 WHERE LineId LIKE '%:003.035' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Drei Schwerfiguren auf einer Linie laden zu einem Abzug ein.","Die Dame zieht weg, greift eine Figur an und enthüllt einen Treffer auf die Dame.","Dame nach b5 – greift einen Springer an und deckt zugleich die Dame auf."],"en":["Three heavy pieces lined up invite a discovered attack.","The queen steps aside, hitting a piece while uncovering an attack on the queen.","Queen to b5 — attacking a knight and unveiling an attack on the queen."],"hr":["Tri teške figure na istoj liniji pozivaju na otkriveni napad.","Dama se makne, napada figuru i otkriva napad na damu.","Dama na b5 — napada skakača i otkriva napad na damu."]}', HintsVersion=1 WHERE LineId LIKE '%:003.036' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steht ein Matt in einem Zug bereit.","Ein Turm zieht auf die Grundreihe und setzt sofort matt.","Turm nach a8 – matt."],"en":["A mate in one is available here.","A rook swings to the back rank and delivers immediate mate.","Rook to a8 — mate."],"hr":["Ovdje je dostupan mat u jednom potezu.","Top dolazi na zadnji red i odmah daje mat.","Top na a8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.037' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Zug setzt den feindlichen König matt.","Ein Turm dringt ein und liefert sofort das Matt.","Turm schlägt auf f2 – matt."],"en":["A single move checkmates the enemy king.","A rook crashes in and delivers immediate mate.","Rook takes on f2 — mate."],"hr":["Jedan potez matira protivničkog kralja.","Top prodire i odmah daje mat.","Top uzima na f2 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.038' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer findet ein Mattnetz in einem Zug.","Der Springer springt in den Königsbereich und setzt matt.","Springer nach h3 – matt."],"en":["A knight delivers mate in a single move.","The knight hops into the king''s zone and gives mate.","Knight to h3 — mate."],"hr":["Skakač daje mat u jednom potezu.","Skakač uskače u kraljevu zonu i daje mat.","Skakač na h3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.039' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine ungewöhnliche Grundreihenkombination führt zum erzwungenen Matt.","Ein Damenopfer lockt den König, dann mattet ein Turm auf der Grundreihe.","Dame schlägt auf f8 – Auftakt zum erzwungenen Matt."],"en":["An unusual back-rank combination forces mate.","A queen sacrifice lures the king, then a rook mates on the back rank.","Queen takes on f8 — beginning the forced mate."],"hr":["Neobična kombinacija na zadnjem redu prisiljava mat.","Žrtva dame mami kralja, a zatim top matira na zadnjem redu.","Dama uzima na f8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.040' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Ablenkung leitet eine Kombination ein, die entscheidend gewinnt.","Die Dame opfert sich, danach dringt ein Turm mattdrohend ein.","Dame schlägt auf f7 – Auftakt zur Kombination mit Mattdrohung."],"en":["A deflection sets up a combination that wins decisively.","The queen sacrifices itself, then a rook invades with mate to follow.","Queen takes on f7 — starting a combination that mates next move."],"hr":["Odvlačenje priprema kombinaciju koja odlučno dobiva.","Dama se žrtvuje, a zatim top prodire uz prijetnju mata.","Dama uzima na f7 — početak kombinacije koja matira sljedećim potezom."]}', HintsVersion=1 WHERE LineId LIKE '%:003.041' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsdeckung weg und erzwingt Matt.","Erst lockt ein Damenopfer den König, dann mattet ein Turm.","Dame schlägt auf h2 – Auftakt zum erzwungenen Matt."],"en":["A sacrifice rips open the king''s cover and forces mate.","First a queen offer drags the king, then a rook delivers mate.","Queen takes on h2 — beginning the forced mate."],"hr":["Žrtva razbija kraljevu zaštitu i prisiljava mat.","Prvo žrtva dame mami kralja, a zatim top daje mat.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.042' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf der Schwachstelle erzwingt das Matt im nächsten Zug.","Die Dame opfert sich, dann liefert ein Turm das entscheidende Schach.","Dame schlägt auf f2 – Auftakt zur Folge, die Matt erzwingt."],"en":["A sacrifice on the weak point forces mate next move.","The queen sacrifices itself, then a rook gives the decisive check.","Queen takes on f2 — starting the sequence that forces mate."],"hr":["Žrtva na slaboj točki prisiljava mat sljedećim potezom.","Dama se žrtvuje, a zatim top daje odlučujući šah.","Dama uzima na f2 — početak niza koji prisiljava mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.043' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver gewinnt eine ganze Figur.","Der Springer springt zurück und fängt eine gegnerische Figur ein.","Springer nach e3 – gewinnt eine Figur."],"en":["A knight maneuver wins a whole piece.","The knight hops back and traps an enemy piece.","Knight to e3 — winning a piece."],"hr":["Manevar skakača osvaja cijelu figuru.","Skakač skače natrag i hvata protivničku figuru.","Skakač na e3 — osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:003.044' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf dem Königsflügel erzwingt ein schnelles Matt.","Ein Läufer opfert sich, dann jagen Dame und Springer den König.","Läufer schlägt auf h6 – Auftakt zum erzwungenen Matt."],"en":["A sacrifice on the kingside forces a quick mate.","A bishop sacrifices itself, then queen and knight hunt the king.","Bishop takes on h6 — beginning the forced mate."],"hr":["Žrtva na kraljevom krilu prisiljava brzi mat.","Lovac se žrtvuje, a zatim dama i skakač gone kralja.","Lovac uzima na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.045' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag auf einen Schlüsselpunkt gewinnt eine Figur.","Ein Läufer schlägt zu und fängt nach dem Tausch eine weitere Figur.","Läufer schlägt auf f3 – Auftakt zur Folge, die eine Figur gewinnt."],"en":["A strike on a key square wins a piece.","A bishop captures and, after the trade, snares another piece.","Bishop takes on f3 — beginning the sequence that wins a piece."],"hr":["Udar na ključno polje osvaja figuru.","Lovac uzima i nakon zamjene hvata još jednu figuru.","Lovac uzima na f3 — početak niza koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:003.046' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Fessel des deckenden Bauern erlaubt einen Gewinnsprung.","Der Springer springt ein und nutzt die Fesselung, um die Qualität zu gewinnen.","Springer nach g3 – nutzt die Fesselung und gewinnt die Qualität."],"en":["A pin on the guarding pawn allows a winning leap.","The knight jumps in, exploiting the pin to win the exchange.","Knight to g3 — exploiting the pin to win the exchange."],"hr":["Veza pješaka koji brani omogućuje dobitni skok.","Skakač uskače i koristi vezu da osvoji kvalitetu.","Skakač na g3 — koristi vezu i osvaja kvalitetu."]}', HintsVersion=1 WHERE LineId LIKE '%:003.047' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forcierter Matt steht bereit, wenn die Dame entscheidend eingreift.","Die Dame stürzt in die königliche Grundreihe und der weiße König findet kein Entkommen.","Dame nach f1 – matt."],"en":["A forced mate is waiting once the queen strikes decisively.","The queen plunges into the back rank where the enemy king cannot escape.","Queen to f1 — mate."],"hr":["Spreman je prisilni mat čim dama presudno udari.","Dama uranja na posljednji red gdje kralj nema bijega.","Dama na f1 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.048' AND BookFileName='chessable-u5-49693.pgn';
