UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf dem Königsflügel reißt die Verteidigung weg und führt zum Matt.","Die Dame opfert sich, damit der Turm den blanken König stellt.","Dame schlägt auf f7 – Beginn der erzwungenen Mattfolge."],"en":["A sacrifice near the king strips the defence and leads to mate.","The queen sacrifices herself so the rook can trap the bare king.","Queen takes on f7 — the start of the forced mating line."],"hr":["Žrtva kraj kralja skida obranu i vodi do mata.","Dama se žrtvuje kako bi top zarobio golog kralja.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:003.051' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein bescheidener Bauernzug fängt eine Figur ein und gewinnt sie.","Dem Läufer werden die Fluchtfelder genommen, bis er gefangen ist.","Bauer nach a4 – fängt den Läufer und gewinnt ihn."],"en":["A modest pawn move traps a piece and wins it.","The bishop''s escape squares are taken away until it is caught.","Pawn to a4 — trapping the bishop and winning it."],"hr":["Skroman potez pješaka zarobljava figuru i osvaja je.","Lovcu se oduzimaju polja za bijeg dok ne bude uhvaćen.","Pješak na a4 — zarobljava lovca i osvaja ga."]}', HintsVersion=1 WHERE LineId LIKE '%:003.052' AND BookFileName='chessable-u5-49693.pgn';
