UPDATE BookPuzzles SET HintsJson='{"de":["Ein forcierter Matt wartet, wenn die Dame entscheidend einschlägt.","Die Dame opfert sich auf der langen Reihe und macht den König matt.","Dame nach h8 – matt."],"en":["A forced mate awaits once the queen lands decisively.","The queen sacrifices herself along the rank and delivers mate.","Queen to h8 — mate."],"hr":["Prisilni mat čeka čim dama presudno udari.","Dama se žrtvuje po redu i daje mat.","Dama na h8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:003.055' AND BookFileName='chessable-u5-49693.pgn';
