UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt in wenigen Zügen das Matt.","Ein Läuferopfer zieht den König heraus, dann übernimmt die Dame.","Läufer nimmt auf f7 – Beginn der erzwungenen Mattführung."],"en":["White forces mate in a few moves.","A bishop sacrifice drags the king out, then the queen finishes.","Bishop takes on f7 — the forced mate begins."],"hr":["Bijeli prisiljava mat u nekoliko poteza.","Žrtva lovca izvlači kralja, a tada dama dovršava posao.","Lovac uzima na f7 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.029' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß führt einen Mattangriff zum erzwungenen Abschluss.","Die Türme treiben den König gnadenlos vor sich her, der Läufer hilft mit.","Turm nach d3 – Auftakt zur erzwungenen Mattjagd."],"en":["White can finish with a forced mating attack.","The rooks drive the king relentlessly, with the bishop lending support.","Rook to d3 — the start of the forced mating hunt."],"hr":["Bijeli zaključuje prisilnim matnim napadom.","Topovi nemilosrdno tjeraju kralja, a lovac pomaže.","Top na d3 — početak prisilnog matnog lova."]}', HintsVersion=1 WHERE LineId LIKE '%:004.030' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz fängt den eingeengten König ein und gewinnt entscheidend.","Der König wird auf das Randfeld gedrängt, dann gibt der Turm den letzten Stoß.","König nach g4 – Beginn der entscheidenden Wendung."],"en":["Black traps the cramped king for a decisive finish.","The king is pushed to the edge, then the rook delivers the final blow.","King to g4 — the start of the decisive sequence."],"hr":["Crni hvata stiješnjenog kralja za odlučujući kraj.","Kralj je potjeran na rub, a tada top zadaje konačni udarac.","Kralj na g4 — početak odlučujućeg niza."]}', HintsVersion=1 WHERE LineId LIKE '%:004.031' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat eine entscheidende Mattkombination.","Ein Springer kommt mit Tempo ein, dann setzt der Turm den Schlusspunkt.","Springer nach f4 – Auftakt zur entscheidenden Kombination."],"en":["Black has a decisive mating combination.","A knight jumps in with tempo, then the rook lands the finishing blow.","Knight to f4 — the start of the decisive combination."],"hr":["Crni ima odlučujuću matnu kombinaciju.","Skakač uskače s tempom, a tada top zadaje završni udarac.","Skakač na f4 — početak odlučujuće kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.032' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß setzt in wenigen Zügen erzwungen matt.","Eine Umwandlung lockt eine Figur weg, dann webt das Leichtfigurenduo das Mattnetz.","Bauer wandelt auf b8 in eine Dame um – Beginn des erzwungenen Matts."],"en":["White has a forced mate in a few moves.","A promotion decoys a piece, then the minor pieces weave the mating net.","Pawn promotes to a queen on b8 — the forced mate begins."],"hr":["Bijeli daje prisilni mat u nekoliko poteza.","Promocija odvlači figuru, a tada laki figuri pletu matnu mrežu.","Pješak se promovira u damu na b8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.033' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß setzt mit Gewalt erzwungen matt.","Ein Bauernvorstoß sprengt den Königsschild, dann führen Dame und Springer zu Ende.","Bauer nach f4 – Auftakt zum erzwungenen Matt."],"en":["White has a forced mate by force.","A pawn thrust shatters the king''s shield, then queen and knight conclude.","Pawn to f4 — the start of the forced mate."],"hr":["Bijeli daje prisilni mat silom.","Prodor pješaka razbija kraljev štit, a tada dama i skakač dovršavaju.","Pješak na f4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.034' AND BookFileName='chessable-u5-49693.pgn';
