UPDATE BookPuzzles SET HintsJson='{"de":["Ein verblüffendes Opfer führt zu einer gewinnenden Stellung.","Der Läufer stellt sich mitten ins Feuer – jeder Schlag führt ins Verderben.","Läufer nach d5 – Auftakt zur entscheidenden Kombination."],"en":["A startling sacrifice leads to a winning position.","The bishop plants itself in the crossfire — every capture leads to ruin.","Bishop to d5 — the start of the decisive combination."],"hr":["Iznenađujuća žrtva vodi do pobjedničke pozicije.","Lovac se postavlja usred vatre — svako uzimanje vodi u propast.","Lovac na d5 — početak odlučujuće kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.019' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Wendung gewinnt entscheidendes Material.","Die Dame stürmt auf die ungedeckte Grundreihe und wird zur Hauptfigur.","Dame nach b8 – leitet den materialgewinnenden Zwang ein."],"en":["A tactic wins decisive material.","The queen storms onto the loose back rank and does the work.","Queen to b8 — starting the winning sequence."],"hr":["Kombinacija osvaja odlučujući materijal.","Dama upada na slabu zadnju liniju i nosi glavni teret.","Dama na b8 — početak dobitne prisile."]}', HintsVersion=1 WHERE LineId LIKE '%:005.020' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer öffnet den schnellsten Weg zum Sieg.","Die Dame schlägt sich ein und macht der vorrückenden Bauern den Weg frei.","Dame schlägt auf f2 – Auftakt zur entscheidenden Umwandlung."],"en":["A sacrifice opens the fastest route to victory.","The queen crashes in to clear the path for the advancing pawn.","Queen takes on f2 — launching the decisive promotion."],"hr":["Žrtva otvara najbrži put do pobjede.","Dama se zabija i krči put pješaku koji napreduje.","Dama uzima na f2 — uvod u odlučujuće pretvaranje."]}', HintsVersion=1 WHERE LineId LIKE '%:005.021' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Tempogewinn bestraft den fehlerhaften Springerzug und holt Material.","Der Springer schlägt zu und reißt die Stellung des Gegners auseinander.","Springer schlägt auf e5 – Beginn der materialgewinnenden Folge."],"en":["A forcing blow punishes the faulty knight move and wins material.","The knight strikes and tears the opposing setup apart.","Knight takes on e5 — beginning the winning line."],"hr":["Prisilni udarac kažnjava pogrešan skok i osvaja materijal.","Skakač udara i razbija protivnički raspored.","Skakač uzima na e5 — početak dobitne linije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.022' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Druck auf der Grundreihe gewinnt eine Figur.","Die Dame nutzt die ungedeckte hinterste Reihe als Hebel.","Dame nach a8 – startet den figurengewinnenden Druck."],"en":["Pressure along the back rank wins a piece.","The queen exploits the undefended last rank as leverage.","Queen to a8 — building the piece-winning pressure."],"hr":["Pritisak po zadnjoj liniji osvaja figuru.","Dama iskorištava nezaštićenu zadnju liniju kao polugu.","Dama na a8 — pokreće pritisak koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.023' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Doppelangriff entscheidet die Partie zu Schwarz'' Gunsten.","Der Turm geht in die Mitte und droht an zwei Stellen zugleich.","Turm nach e6 – Beginn der gewinnbringenden Doppeldrohung."],"en":["A double attack settles the game for Black.","The rook swings into the centre and threatens on two fronts.","Rook to e6 — starting the winning double threat."],"hr":["Dvostruki napad rješava partiju u Crnu korist.","Top ulazi u centar i prijeti na dva mjesta odjednom.","Top na e6 — početak dobitne dvostruke prijetnje."]}', HintsVersion=1 WHERE LineId LIKE '%:005.024' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Fesselung auf der offenen Linie gewinnt eine Figur.","Der Läufer setzt sich neben den König und nutzt die Fesselung aus.","Läufer nach b3 – verstärkt die figurengewinnende Fesselung."],"en":["A pin on the open file wins a piece.","The bishop slides alongside the king and exploits the pin.","Bishop to b3 — pressing the piece-winning pin."],"hr":["Vezivanje po otvorenoj liniji osvaja figuru.","Lovac se postavlja uz kralja i iskorištava vez.","Lovac na b3 — pojačava vez koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.025' AND BookFileName='chessable-u5-49693.pgn';
