UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gewinnt einen wichtigen Bauern und durchkreuzt den Plan des Gegners.","Der Läufer schlägt zu und beseitigt die Grundlage der gegnerischen Idee.","Läufer schlägt auf b4 – gewinnt den entscheidenden Bauern."],"en":["A capture wins a vital pawn and undoes the opponent''s plan.","The bishop strikes and removes the basis of the enemy idea.","Bishop takes on b4 — winning the key pawn."],"hr":["Udarac osvaja važnog pješaka i ruši protivnikov plan.","Lovac udara i uklanja temelj protivničke zamisli.","Lovac uzima na b4 — osvaja ključnog pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:005.031' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Wendung bestraft den Königszug und gewinnt entscheidend.","Der Springer rückt zentral vor und stellt den Gegner vor Probleme.","Springer nach e5 – Beginn der entscheidenden Folge."],"en":["A tactic punishes the king move and wins decisively.","The knight steps to the centre and creates problems.","Knight to e5 — starting the decisive sequence."],"hr":["Kombinacija kažnjava potez kralja i odlučujuće dobiva.","Skakač skače u centar i stvara probleme.","Skakač na e5 — početak odlučujuće linije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.032' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt zu verteidigen geht Schwarz selbst zum Angriff über.","Die Dame schwingt sich ins Zentrum und übernimmt die Initiative.","Dame nach e4 – startet den gewinnbringenden Gegenangriff."],"en":["Instead of defending, Black goes onto the attack.","The queen swings to the centre and seizes the initiative.","Queen to e4 — launching the winning counterattack."],"hr":["Umjesto obrane, Crni sam prelazi u napad.","Dama izlazi u centar i preuzima inicijativu.","Dama na e4 — pokreće dobitni protunapad."]}', HintsVersion=1 WHERE LineId LIKE '%:005.033' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gier wird mit einem Damenfang bestraft.","Der Springer zieht zur Seite und legt der eingedrungenen Dame ein Netz.","Springer nach a5 – beginnt die Jagd, die die Dame fängt."],"en":["Greed is punished by trapping the queen.","The knight steps aside to weave a net around the intruding queen.","Knight to a5 — starting the hunt that traps the queen."],"hr":["Pohlepa se kažnjava hvatanjem dame.","Skakač se izmiče i plete mrežu oko upale dame.","Skakač na a5 — počinje hajka koja hvata damu."]}', HintsVersion=1 WHERE LineId LIKE '%:005.034' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag auf der Diagonale räumt den Weg zu einem doppelten Angriff.","Der Turm opfert sich, um die Königsstellung zu sprengen.","Turm schlägt auf c3 – Auftakt zur gewinnbringenden Folge."],"en":["A capture clears the way to a double attack.","The rook sacrifices itself to shatter the king''s shelter.","Rook takes on c3 — starting the winning sequence."],"hr":["Uzimanje krči put dvostrukom napadu.","Top se žrtvuje da razbije kraljevo sklonište.","Top uzima na c3 — uvod u dobitnu liniju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.035' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Das Interferenz-Motiv unterbricht die Deckung und entscheidet.","Ein leichtfiguriger Schlag verstellt die Verteidigung der zweiten Reihe.","Läufer schlägt auf e2 – beginnt die entscheidende Folge."],"en":["The interference theme cuts a defence and decides.","A minor-piece capture blocks the second-rank defence.","Bishop takes on e2 — starting the decisive sequence."],"hr":["Motiv presijecanja prekida obranu i odlučuje.","Uzimanje lakom figurom blokira obranu druge linije.","Lovac uzima na e2 — početak odlučujuće linije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.036' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Interferenz-Motiv erzwingt matt.","Ein Springeropfer verstellt die Deckung und öffnet das Mattnetz.","Springer nach g3 – Beginn des erzwungenen Matts."],"en":["An interference theme forces mate.","A knight sacrifice blocks the defence and opens the mating net.","Knight to g3 — beginning the forced mate."],"hr":["Motiv presijecanja prisiljava mat.","Žrtva skakača blokira obranu i otvara matnu mrežu.","Skakač na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.037' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag startet den schnellsten Angriff auf den König.","Die Dame schlägt einen Bauern und reißt die Königsstellung auf.","Dame schlägt auf b2 – Auftakt zur entscheidenden Folge."],"en":["A capture starts the fastest attack on the king.","The queen grabs a pawn and tears open the king''s position.","Queen takes on b2 — beginning the decisive sequence."],"hr":["Uzimanje pokreće najbrži napad na kralja.","Dama uzima pješaka i otvara kraljevu poziciju.","Dama uzima na b2 — uvod u odlučujuću liniju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.038' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß bestraft den natürlichen Springerzug und gewinnt eine gefesselte Figur.","Der Bauer im Zentrum verdrängt die Dame und legt die Fesselung bloß.","Bauer nach c4 – Beginn der figurengewinnenden Folge."],"en":["A pawn thrust punishes the natural knight move and wins a pinned piece.","The central pawn shoves the queen away and exposes the pin.","Pawn to c4 — starting the piece-winning sequence."],"hr":["Prodor pješaka kažnjava prirodan skok i osvaja vezanu figuru.","Središnji pješak tjera damu i otkriva vez.","Pješak na c4 — početak linije koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.039' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt sicher zu spielen, gewinnt Schwarz mit einem beherzten Schlag Material.","Ein Bauernschlag öffnet Linien und setzt eine gewinnbringende Folge in Gang.","Bauer schlägt auf b4 – Auftakt zur materialgewinnenden Folge."],"en":["Rather than playing safe, Black wins material with a bold capture.","A pawn capture opens lines and sets a winning sequence in motion.","Pawn takes on b4 — beginning the material-winning line."],"hr":["Umjesto sigurne igre, Crni hrabrim uzimanjem osvaja materijal.","Uzimanje pješakom otvara linije i pokreće dobitnu liniju.","Pješak uzima na b4 — uvod u liniju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.040' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat einen erzwungenen Mattangriff.","Die Dame zieht zur Grundreihe und leitet das Mattnetz ein.","Dame nach d8 – Beginn des erzwungenen Matts."],"en":["Black has a forced mating attack.","The queen drops to the back rank to begin the mating net.","Queen to d8 — beginning the forced mate."],"hr":["Crni ima prisilni matni napad.","Dama silazi na zadnju liniju i pokreće matnu mrežu.","Dama na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.041' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein präziser Manövrierzug erledigt den Gegner rasch.","Der Turm gruppiert sich um und bringt die Dame in Angriffsstellung.","Turm nach g3 – Beginn der entscheidenden Folge."],"en":["A precise regrouping finishes the opponent off quickly.","The rook repositions to bring the queen into attacking play.","Rook to g3 — starting the decisive sequence."],"hr":["Precizan manevar brzo dokrajčuje protivnika.","Top se premješta i dovodi damu u napadački položaj.","Top na g3 — početak odlučujuće linije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.042' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein scheinbar unmöglicher Bauernzug entscheidet taktisch.","Der Bauer rückt vor und reißt die Königsstellung des Gegners auf.","Bauer nach g4 – Beginn der gewinnbringenden Folge."],"en":["An apparently impossible pawn move decides tactically.","The pawn advances and breaks open the enemy king''s position.","Pawn to g4 — starting the winning sequence."],"hr":["Naizgled nemoguć potez pješaka odlučuje taktički.","Pješak napreduje i razbija položaj protivničkog kralja.","Pješak na g4 — početak dobitne linije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.043' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gewinnt sofort Material.","Der Läufer schlägt zu und nutzt eine Fesselung tödlich aus.","Läufer schlägt auf f5 – gewinnt Material."],"en":["A capture wins material at once.","The bishop strikes and exploits a pin lethally.","Bishop takes on f5 — winning material."],"hr":["Uzimanje odmah osvaja materijal.","Lovac udara i smrtonosno iskorištava vez.","Lovac uzima na f5 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.044' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Wendung gewinnt eine gefesselte Figur.","Die Dame schlägt zu und legt die Fesselung auf der Grundreihe bloß.","Dame schlägt auf c4 – Auftakt zur figurengewinnenden Folge."],"en":["A tactic wins a pinned piece.","The queen captures and lays bare the pin on the back rank.","Queen takes on c4 — beginning the piece-winning sequence."],"hr":["Kombinacija osvaja vezanu figuru.","Dama uzima i otkriva vez na zadnjoj liniji.","Dama uzima na c4 — uvod u liniju koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.045' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz steht verloren und muss sich in ein Remis retten.","Ein Damenopfer ist der einzige Trick, der die Partie hält.","Dame schlägt auf h3 – erzwingt das rettende Patt."],"en":["Black is lost and must rescue a draw.","A queen sacrifice is the only trick that holds the game.","Queen takes on h3 — forcing the saving stalemate."],"hr":["Crni stoji izgubljeno i mora spasiti remi.","Žrtva dame jedini je trik koji drži partiju.","Dama uzima na h3 — prisiljava spasonosni pat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.046' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein zentraler Bauernvorstoß ist hier am stärksten und sichert Schwarz Material.","Der Bauer öffnet das Zentrum und nutzt die gegnerische Figurenstellung aus.","Bauer nach e5 – Auftakt zur vorteilbringenden Folge."],"en":["A central pawn thrust is strongest and secures Black material.","The pawn opens the centre and exploits the enemy piece placement.","Pawn to e5 — beginning the advantageous sequence."],"hr":["Središnji prodor pješaka ovdje je najjači i Crnom osigurava materijal.","Pješak otvara centar i iskorištava raspored protivničkih figura.","Pješak na e5 — uvod u povoljnu liniju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.047' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer leitet das schnellste erzwungene Matt ein.","Die Dame schlägt sich an den König und reißt seine Deckung ein.","Dame schlägt auf h7 – Beginn des erzwungenen Matts."],"en":["A sacrifice launches the fastest forced mate.","The queen crashes into the king and tears away his cover.","Queen takes on h7 — beginning the forced mate."],"hr":["Žrtva pokreće najbrži prisilni mat.","Dama se zabija u kralja i razbija mu zaštitu.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.048' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß rettet die schwierige Stellung durch Dauerschach.","Der Bauer rückt vor und öffnet der Dame den Weg zum ewigen Schach.","Bauer nach f3 – Auftakt zur rettenden Folge."],"en":["A pawn thrust saves the difficult position with perpetual check.","The pawn advances and clears the queen''s path to perpetual check.","Pawn to f3 — beginning the saving sequence."],"hr":["Prodor pješaka spašava tešku poziciju vječitim šahom.","Pješak napreduje i otvara dami put do vječitog šaha.","Pješak na f3 — uvod u spasonosnu liniju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.049' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – treib den König in die Enge.","Die schwere Figur auf der siebten Reihe leitet den entscheidenden Angriff ein, der Turm vollendet.","Turm schlägt auf g7 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is hiding here — drive the king into the net.","The heavy piece on the seventh rank starts the decisive assault, the other rook finishes.","Rook takes on g7 — the start of a forced mate."],"hr":["Ovdje se krije prisilni mat — natjeraj kralja u mrežu.","Teška figura na sedmom redu pokreće odlučujući napad, drugi top dovršava.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.050' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zwischenzug gewinnt Material, statt einfach zurückzuschlagen.","Erst die Dame mit Schach einschalten, dann schlägt der Springer entscheidend zu.","Dame nach d1 – Schach mit Materialgewinn im Anschluss."],"en":["A zwischenzug wins material instead of recapturing at once.","Insert the queen with check first, then the knight strikes decisively.","Queen to d1 — a check that wins material afterwards."],"hr":["Međupotez osvaja materijal umjesto da odmah uzme nazad.","Prvo ubaci damu sa šahom, zatim skakač odlučno udara.","Dama na d1 — šah koji potom osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.051' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die angegriffene Dame kann sich teuer verkaufen – eine Kombination bringt entscheidenden Vorteil.","Der Springer schlägt eine Leichtfigur und entfacht eine Folge, die für die Dame reichlich Holz einbringt.","Springer schlägt auf e2 – Beginn der materialgewinnenden Kombination."],"en":["The attacked queen can sell herself dearly — a combination wins a decisive edge.","The knight grabs a minor piece and starts a sequence that nets plenty for the queen.","Knight takes on e2 — the start of the material-winning combination."],"hr":["Napadnuta dama može se skupo prodati — kombinacija donosi odlučujuću prednost.","Skakač uzima laku figuru i pokreće niz koji za damu donosi obilje materijala.","Skakač uzima na e2 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.052' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein hübsches Turmmanöver gewinnt einen wichtigen Bauern.","Der aktive Turm schlägt zu und nutzt das geometrische Muster aus.","Turm schlägt auf f7 – gewinnt einen wichtigen Bauern."],"en":["A pretty rook maneuver wins an important pawn.","The active rook strikes, exploiting a neat geometric pattern.","Rook takes on f7 — winning an important pawn."],"hr":["Lijep manevar topa osvaja važnog pješaka.","Aktivni top udara, iskorištavajući urednu geometriju.","Top uzima na f7 — osvaja važnog pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:005.053' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Stellung sieht heikel aus – doch ein Damenzug rettet und gewinnt sogar.","Die Dame greift den vorgerückten Bauern an und löst die Verteidigungsprobleme.","Dame nach e3 – wendet die Lage entscheidend."],"en":["The position looks awkward — but one queen move saves and even wins.","The queen attacks the advanced pawn and untangles all the problems.","Queen to e3 — turning the tables decisively."],"hr":["Pozicija izgleda neugodno — ali jedan potez damom spašava i čak dobiva.","Dama napada nadvinutog pješaka i razrješava sve probleme.","Dama na e3 — odlučno mijenja tijek."]}', HintsVersion=1 WHERE LineId LIKE '%:005.054' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["In der ruhigen Stellung steckt ein Schlag, der eine Figur gewinnt.","Ein Turmopfer lenkt ab, dann holt sich ein Springer die Beute.","Turm schlägt auf e4 – Beginn der Kombination, die eine Figur gewinnt."],"en":["This quiet position hides a blow that wins a piece.","A rook sacrifice deflects, then a knight collects the spoils.","Rook takes on e4 — the start of the combination that wins a piece."],"hr":["Ova mirna pozicija krije udarac koji osvaja figuru.","Žrtva topa odvlači, zatim skakač pokupi plijen.","Top uzima na e4 — početak kombinacije koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.055' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der entblößte König lässt eine entscheidende Kombination zu.","Die Dame dringt mit Schach ein und der Turm setzt nach – das kostet die Dame.","Dame nach e6 – Schach, das die feindliche Dame kostet."],"en":["The exposed king allows a decisive combination.","The queen invades with check and the rook follows up — winning the queen.","Queen to e6 — a check that wins the enemy queen."],"hr":["Otkriveni kralj dopušta odlučujuću kombinaciju.","Dama prodire sa šahom, a top nastavlja — to košta damu.","Dama na e6 — šah koji osvaja protivničku damu."]}', HintsVersion=1 WHERE LineId LIKE '%:005.056' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die exponierte schwarze Dame lässt sich einfangen – Material winkt.","Ein bescheidener Bauernzug beginnt die Treibjagd auf die Dame.","Bauer nach b3 – Auftakt zum Damenfang, der Material gewinnt."],"en":["The exposed black queen can be trapped — material beckons.","A modest pawn move begins the hunt that corners the queen.","Pawn to b3 — the start of the queen hunt that wins material."],"hr":["Izložena crna dama može se uhvatiti — slijedi materijal.","Skroman potez pješakom započinje hajku na damu.","Pješak na b3 — početak lova na damu koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.057' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt für den Anziehenden – nimm den Angriff an.","Ein Läuferopfer reißt die Königsstellung auf, dann jagen die schweren Figuren den König.","Läufer schlägt auf h6 – Auftakt zur Mattjagd."],"en":["A forced mate is here for the side to move — accept the attack.","A bishop sacrifice rips open the king''s shelter, then the heavy pieces hunt him down.","Bishop takes on h6 — the start of the mating attack."],"hr":["Ovdje je prisilni mat za stranu na potezu — prihvati napad.","Žrtva lovca razbija kraljevo sklonište, zatim teške figure progone kralja.","Lovac uzima na h6 — početak matne hajke."]}', HintsVersion=1 WHERE LineId LIKE '%:005.058' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die ungünstig stehende schwarze Dame erlaubt einen Materialgewinn.","Ein Springerzug öffnet eine Doppeldrohung und treibt einen Bauern weit vor.","Springer nach d2 – Beginn der Kombination, die Material gewinnt."],"en":["The awkwardly placed black queen permits a material gain.","A knight move opens a double threat and pushes a pawn far forward.","Knight to d2 — the start of the combination that wins material."],"hr":["Nezgodno postavljena crna dama dopušta osvajanje materijala.","Potez skakačem otvara dvostruku prijetnju i gura pješaka daleko naprijed.","Skakač na d2 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.059' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorrückender Bauer ist viel stärker als der naheliegende Springerzug – Material winkt.","Der weit vorgeschobene Bauer wird zur Macht und entscheidet die Kombination.","Bauer nach e6 – Auftakt zur materialgewinnenden Kombination."],"en":["An advancing pawn is far stronger than the obvious knight move — material beckons.","The far-advanced pawn becomes a force and decides the combination.","Pawn to e6 — the start of the material-winning combination."],"hr":["Pješak koji napreduje mnogo je jači od očitog poteza skakačem — slijedi materijal.","Daleko nadvinuti pješak postaje sila i odlučuje kombinaciju.","Pješak na e6 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.060' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Etwas weit Schärferes als der ruhige Zug gewinnt eine Figur.","Die Dame schlägt zu und nutzt aus, dass die feindliche Dame einen Läufer decken muss.","Dame schlägt auf c6 – Beginn der Folge, die eine Figur gewinnt."],"en":["Something far sharper than the quiet move wins a piece.","The queen strikes, exploiting that the enemy queen must keep guarding a bishop.","Queen takes on c6 — the start of the line that wins a piece."],"hr":["Nešto mnogo oštrije od mirnog poteza osvaja figuru.","Dama udara, iskorištavajući to da protivnička dama mora čuvati lovca.","Dama uzima na c6 — početak niza koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.061' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz beidseitiger Grundreihenmotive gewinnt Schwarz entscheidend.","Der Turm rückt vor, deckt eine Drohung ab und stellt selbst zwei vor.","Turm nach d4 – Beginn der Kombination, die für Schwarz gewinnt."],"en":["Despite back-rank threats on both sides, Black wins decisively.","The rook advances, parrying one threat while setting up two of its own.","Rook to d4 — the start of the combination that wins for Black."],"hr":["Unatoč prijetnjama po zadnjem redu s obje strane, crni odlučno dobiva.","Top napreduje, odbija jednu prijetnju i postavlja dvije svoje.","Top na d4 — početak kombinacije koja dobiva za crnog."]}', HintsVersion=1 WHERE LineId LIKE '%:005.062' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt nur das ewige Schach zu nehmen, gewinnt ein Damenzug mehr.","Die Dame zieht sich geschickt zurück und bereitet entscheidenden Gewinn vor.","Dame nach f8 – stärker als das bloße Dauerschach."],"en":["Rather than settling for the perpetual, one queen move wins more.","The queen steps back cleverly, preparing a decisive gain.","Queen to f8 — stronger than just taking the perpetual."],"hr":["Umjesto da se zadovolji vječnim šahom, jedan potez damom dobiva više.","Dama se vješto povlači, pripremajući odlučujući dobitak.","Dama na f8 — jače od pukog vječnog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:005.063' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt des Damenschachs erzwingt ein Turmschlag ein schnelles Matt.","Der Turm schlägt mit Schach, dann dringen Dame und Läufer zum König durch.","Turm schlägt auf e7 – Schach, das ein schnelles Matt erzwingt."],"en":["Instead of the queen check, a rook capture forces a quick mate.","The rook takes with check, then queen and bishop break through to the king.","Rook takes on e7 — a check that forces a quick mate."],"hr":["Umjesto šaha damom, uzimanje topom prisiljava brzi mat.","Top uzima sa šahom, zatim dama i lovac probijaju do kralja.","Top uzima na e7 — šah koji prisiljava brzi mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.064' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße Turmzug auf den Flügel war ein Fehler – Schwarz hat ein Matt.","Ein Springerschach öffnet die Stellung, dann führen die schweren Figuren das Matt herbei.","Springer nach e3 – Schach als Auftakt zur Mattführung."],"en":["White''s rook move to the wing was a blunder — Black has a mate.","A knight check cracks the position, then the heavy pieces deliver the mate.","Knight to e3 — a check that begins the mating attack."],"hr":["Bijeli potez topom na krilo bio je pogreška — crni ima mat.","Šah skakačem otvara poziciju, zatim teške figure izvode mat.","Skakač na e3 — šah kao uvod u matnu hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:005.065' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt das vernichtende Matt – schließe den Angriff ab.","Ein Damenopfer reißt den König heraus, dann jagen Turm und Bauern ihn matt.","Dame schlägt auf h6 – Auftakt zur erzwungenen Mattführung."],"en":["The devastating mate is here — conclude the attack.","A queen sacrifice drags the king out, then rook and pawns hunt him to mate.","Queen takes on h6 — the start of the forced mating sequence."],"hr":["Ovdje je razarajući mat — privedi napad kraju.","Žrtva dame izvlači kralja, zatim ga top i pješaci tjeraju u mat.","Dama uzima na h6 — početak prisilne matne hajke."]}', HintsVersion=1 WHERE LineId LIKE '%:005.066' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine große Gelegenheit wurde verpasst – ein Läuferopfer gewinnt entscheidend.","Der Läufer schlägt mit Schach und reißt die Königsstellung auf, die Dame folgt.","Läufer schlägt auf h3 – Schach, das die gewinnende Kombination einleitet."],"en":["A great chance was missed — a bishop sacrifice wins decisively.","The bishop strikes with check and tears open the king, the queen follows.","Bishop takes on h3 — a check that begins the winning combination."],"hr":["Propuštena je velika prilika — žrtva lovca odlučno dobiva.","Lovac udara sa šahom i razbija kraljevo sklonište, dama slijedi.","Lovac uzima na h3 — šah koji započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.067' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt für Weiß.","Erst lockt der Läufer mit Schach, dann liefert die Dame das Matt auf der Grundreihe.","Läufer nach c4 – Schach als Auftakt zum erzwungenen Matt."],"en":["A forced mate is here for White.","First the bishop lures with check, then the queen delivers mate on the back rank.","Bishop to c4 — a check that begins the forced mate."],"hr":["Ovdje je prisilni mat za bijelog.","Prvo lovac mami sa šahom, zatim dama daje mat po zadnjem redu.","Lovac na c4 — šah kao uvod u prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.068' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Aus der Fessel auf der Linie lässt sich ein Matt zaubern.","Der Turm schlägt, verwandelt die Fessel in einen Abzug und ebnet den Weg zum Matt.","Turm schlägt auf c1 – Auftakt zur erzwungenen Mattführung."],"en":["The pin on the file can be turned into a mate.","The rook captures, converting the pin into a discovered attack and clearing the path to mate.","Rook takes on c1 — the start of the forced mating sequence."],"hr":["Vezanje po liniji može se pretvoriti u mat.","Top uzima, pretvarajući vezu u otkriveni napad i otvarajući put do mata.","Top uzima na c1 — početak prisilne matne hajke."]}', HintsVersion=1 WHERE LineId LIKE '%:005.069' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine große Möglichkeit wurde übersehen – hier steckt ein Matt.","Ein Turmopfer reißt den König heraus, dann treibt die Dame ihn ins Mattnetz.","Turm schlägt auf f2 – Opfer als Auftakt zur Mattführung."],"en":["A great possibility was overlooked — a mate is here.","A rook sacrifice drags the king out, then the queen chases him into the mating net.","Rook takes on f2 — a sacrifice that begins the mating attack."],"hr":["Propuštena je velika mogućnost — ovdje je mat.","Žrtva topa izvlači kralja, zatim ga dama tjera u matnu mrežu.","Top uzima na f2 — žrtva kao uvod u matnu hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:005.070' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Auf das schockierende Damenschlagen gibt es eine starke Antwort, die Material gewinnt.","Erst opfert der Turm sich auf der Springerlinie, dann kassiert der König den Eindringling.","Turm schlägt auf f3 – Beginn der materialgewinnenden Folge."],"en":["The shocking queen capture has a strong reply that wins material.","First the rook offers itself on the knight''s square, then the king collects the intruder.","Rook takes on f3 — the start of the material-winning sequence."],"hr":["Šokantno uzimanje damom ima jak odgovor koji osvaja materijal.","Prvo se top žrtvuje na skakačevu polju, zatim kralj uzima uljeza.","Top uzima na f3 — početak niza koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.071' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine deutliche Verbesserung gegenüber dem ruhigen Zug gewinnt die Qualität.","Der Läufer schlägt im Zentrum und öffnet die Linie für den entscheidenden Damenzug.","Läufer schlägt auf e5 – Beginn der Kombination, die die Qualität gewinnt."],"en":["A clear improvement on the quiet move wins the exchange.","The bishop captures in the center, opening the file for the decisive queen move.","Bishop takes on e5 — the start of the combination that wins the exchange."],"hr":["Jasno poboljšanje nad mirnim potezom osvaja kvalitetu.","Lovac uzima u centru, otvarajući liniju za odlučujući potez damom.","Lovac uzima na e5 — početak kombinacije koja osvaja kvalitetu."]}', HintsVersion=1 WHERE LineId LIKE '%:005.072' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die vorgerückte Stellung des weißen Königs lässt sich entscheidend ausnutzen.","Ein bescheidener Bauernzug bereitet einen Zwischenzug vor, der eine Figur gewinnt.","Bauer nach f6 – Auftakt zur Kombination, die eine Figur gewinnt."],"en":["The advanced white king can be exploited decisively.","A modest pawn move sets up a zwischenzug that wins a piece.","Pawn to f6 — the start of the combination that wins a piece."],"hr":["Nadvinuti bijeli kralj može se odlučno iskoristiti.","Skroman potez pješakom priprema međupotez koji osvaja figuru.","Pješak na f6 — početak kombinacije koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.073' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stilles Damenmanöver ist stärker als der direkte Bauernvorstoß und gewinnt.","Die Dame zieht beiseite und droht zum Königsflügel zu kommen, was entscheidet.","Dame nach e3 – Beginn der gewinnenden Kombination."],"en":["A quiet queen maneuver is stronger than the direct pawn push and wins.","The queen steps aside, threatening to swing to the kingside decisively.","Queen to e3 — the start of the winning combination."],"hr":["Tihi manevar damom jači je od izravnog poteza pješakom i dobiva.","Dama se izmiče, prijeteći prebacivanjem na kraljevo krilo, što odlučuje.","Dama na e3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.074' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt des naheliegenden Schlags gewinnt ein Doppelangriff eine Figur.","Erst ein Springeropfer, das ablenkt, dann setzt die Dame zum Doppelangriff an.","Springer schlägt auf d6 – Auftakt zum Doppelangriff, der eine Figur gewinnt."],"en":["Instead of the obvious capture, a double attack wins a piece.","First a deflecting knight sacrifice, then the queen launches the double attack.","Knight takes on d6 — the start of the double attack that wins a piece."],"hr":["Umjesto očitog uzimanja, dvostruki napad osvaja figuru.","Prvo žrtva skakača koja odvlači, zatim dama kreće u dvostruki napad.","Skakač uzima na d6 — početak dvostrukog napada koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:005.075' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Auf den schwarzen Turmschlag gibt es eine starke Antwort, die Material gewinnt.","Die Dame dringt mit Schach ein und leitet eine entscheidende Folge ein.","Dame schlägt auf e8 – Schach als Beginn der materialgewinnenden Folge."],"en":["The black rook capture has a strong reply that wins material.","The queen invades with check and starts a decisive sequence.","Queen takes on e8 — a check that begins the material-winning sequence."],"hr":["Crno uzimanje topom ima jak odgovor koji osvaja materijal.","Dama prodire sa šahom i pokreće odlučujući niz.","Dama uzima na e8 — šah kao početak niza koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.076' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine sofortige Gewinnchance wurde verpasst – ein Damenschach entscheidet.","Die Dame gibt Schach und zwingt den König, dann fällt der König dem Angriff zum Opfer.","Dame nach c3 – Schach, das die gewinnende Kombination einleitet."],"en":["An immediate winning chance was missed — a queen check decides.","The queen checks and herds the king, then he falls to the attack.","Queen to c3 — a check that begins the winning combination."],"hr":["Propuštena je trenutna prilika za pobjedu — šah damom odlučuje.","Dama daje šah i tjera kralja, koji zatim pada pod napadom.","Dama na c3 — šah koji započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.077' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein besserer Zug als der Damenzug gewinnt entscheidend Material.","Erst tauscht der Turm mit Schach auf der offenen Linie, dann gewinnt die Dame.","Turm schlägt auf e8 – Schach als Auftakt zur materialgewinnenden Folge."],"en":["A better move than the queen move wins material decisively.","First the rook trades with check on the open file, then the queen wins.","Rook takes on e8 — a check that begins the material-winning sequence."],"hr":["Bolji potez od onog damom odlučno osvaja materijal.","Prvo top mijenja sa šahom po otvorenoj liniji, zatim dama dobiva.","Top uzima na e8 — šah kao uvod u niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.078' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein schmerzloserer Gewinn als das gespielte Schach steckt drin – ein Abzug gewinnt die Dame.","Die Dame zieht mit Schach, dann gewinnt ein Abzugsangriff die feindliche Dame.","Dame nach h4 – Schach, das per Abzug die Dame gewinnt."],"en":["A more painless win than the played check is here — a discovery wins the queen.","The queen moves with check, then a discovered attack wins the enemy queen.","Queen to h4 — a check that wins the queen by discovery."],"hr":["Ovdje je bezbolnija pobjeda od odigranog šaha — otkriveni napad osvaja damu.","Dama ide sa šahom, zatim otkriveni napad osvaja protivničku damu.","Dama na h4 — šah koji otkrivenim napadom osvaja damu."]}', HintsVersion=1 WHERE LineId LIKE '%:005.079' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König ist entblößt – hier gibt es ein erzwungenes Matt.","Dein König geht mutig vor und öffnet die Linien für Dame und Turm.","König nach h3 – startet die Mattkombination."],"en":["The enemy king is exposed — there is a forced mate here.","Your own king marches up boldly to open lines for queen and rook.","King to h3 — begins the mating combination."],"hr":["Protivnički kralj je razgolićen — ovdje postoji prisilni mat.","Tvoj kralj hrabro kreće naprijed i otvara linije za damu i top.","Kralj na h3 — započinje matni kombinacijski niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.080' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer reißt die Verteidigung des Königs auf und gewinnt Material.","Der Turm opfert sich, damit die Dame entscheidend zuschlagen kann.","Turm schlägt auf b6 – leitet die Gewinnkombination ein."],"en":["A sacrifice rips open the king''s cover and wins material.","The rook sacrifices itself so the queen can deliver the decisive blow.","Rook takes on b6 — starting the winning combination."],"hr":["Žrtva razbija zaklon kralja i osvaja materijal.","Top se žrtvuje kako bi dama mogla zadati odlučujući udarac.","Top uzima na b6 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.081' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein bescheidener Bauernzug schafft eine vernichtende Doppeldrohung.","Der vorrückende Bauer entfesselt Dame und Läufer gleichzeitig.","Bauer nach e3 – gewinnt mit doppelter Drohung."],"en":["A modest pawn push creates a crushing double threat.","The advancing pawn unleashes both queen and bishop at once.","Pawn to e3 — winning with a double threat."],"hr":["Skroman potez pješakom stvara razornu dvostruku prijetnju.","Pješak koji napreduje istovremeno oslobađa damu i lovca.","Pješak na e3 — pobjeđuje dvostrukom prijetnjom."]}', HintsVersion=1 WHERE LineId LIKE '%:005.082' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer auf der vollen Linie räumt den Weg zur Gewinnführung.","Der Turm gibt sich her, danach entscheidet das Zusammenspiel von Dame und Springer.","Turm schlägt auf a8 – beginnt die Gewinnkombination."],"en":["A sacrifice on the open file clears the way to win.","The rook gives itself up, then queen and knight combine decisively.","Rook takes on a8 — starting the winning combination."],"hr":["Žrtva na otvorenoj liniji čisti put do pobjede.","Top se žrtvuje, a zatim dama i skakač odlučujuće surađuju.","Top uzima na a8 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.083' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet eine entscheidende Kombination ein.","Die Dame schlägt zu, damit der Turm auf der offenen Linie triumphiert.","Dame schlägt auf f7 – Auftakt zur Gewinnkombination."],"en":["A queen sacrifice launches a decisive combination.","The queen strikes so the rook can dominate the open file.","Queen takes on f7 — the start of the winning combination."],"hr":["Žrtva dame pokreće odlučujuću kombinaciju.","Dama udara kako bi top zavladao otvorenom linijom.","Dama uzima na f7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.084' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Reihe von Abtäuschen führt in ein gewonnenes Endspiel mit Mehrbauer.","Der Läufer gibt den Startschuss zur erzwungenen Vereinfachung.","Läufer schlägt auf e5 – beginnt die vereinfachende Gewinnkombination."],"en":["A series of exchanges leads to a won ending with an extra pawn.","The bishop fires the first shot in a forced simplification.","Bishop takes on e5 — beginning the simplifying winning sequence."],"hr":["Niz zamjena vodi u dobivenu završnicu s pješakom viška.","Lovac ispaljuje prvi hitac u prisilnom pojednostavljenju.","Lovac uzima na e5 — započinje pojednostavljujući dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.085' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein kühner Einbruch ins gegnerische Lager gewinnt einen wichtigen Bauern und mehr.","Der Turm dringt entscheidend in die siebte Reihe ein.","Turm schlägt auf d7 – Beginn der Gewinnkombination."],"en":["A bold incursion into the enemy camp wins a vital pawn and more.","The rook smashes decisively into the seventh rank.","Rook takes on d7 — the start of the winning combination."],"hr":["Smion prodor u protivnički tabor osvaja ključnog pješaka i više.","Top odlučujuće prodire na sedmi red.","Top uzima na d7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.086' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Figuren werden zum gegnerischen König umgruppiert – Matt ist erzwungen.","Der Turm schwenkt auf die offene Linie zum König herüber.","Turm nach d4 – leitet die Mattführung ein."],"en":["The pieces regroup toward the enemy king — mate is forced.","The rook swings across to the open line aimed at the king.","Rook to d4 — beginning the forced mate."],"hr":["Figure se pregrupiraju prema protivničkom kralju — mat je prisilan.","Top se prebacuje na otvorenu liniju usmjerenu na kralja.","Top na d4 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.087' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein unscheinbarer Bauernzug erzwingt Materialgewinn.","Der Bauer drängt vor und schafft Druck, der eine Figur freisetzt.","Bauer nach f5 – Auftakt zur materialgewinnenden Kombination."],"en":["An unassuming pawn move forces a material gain.","The pawn pushes forward, creating pressure that frees a piece.","Pawn to f5 — the start of the material-winning combination."],"hr":["Neugledan potez pješakom prisiljava na dobitak materijala.","Pješak napreduje i stvara pritisak koji oslobađa figuru.","Pješak na f5 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.088' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein zwischengeschobener Bauernzug holt sich einen Mehrbauern im Endspiel.","Der Bauer stört die gegnerische Bauernkette und schafft den Vorteil.","Bauer nach c5 – beginnt die vorteilbringende Folge."],"en":["A clever pawn move nets an extra pawn in the endgame.","The pawn disrupts the enemy pawn chain to gain the advantage.","Pawn to c5 — beginning the advantageous sequence."],"hr":["Domišljat potez pješakom donosi pješaka viška u završnici.","Pješak razbija protivnički pješački lanac i stvara prednost.","Pješak na c5 — započinje povoljan niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.089' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König steht entblößt – ein Opfer erzwingt das Matt auf der offenen Linie.","Die Dame opfert sich, um die Deckung des Königs zu sprengen.","Dame schlägt auf f6 – leitet das erzwungene Matt ein."],"en":["The king is bare — a sacrifice forces mate down the open file.","The queen sacrifices herself to tear open the king''s shelter.","Queen takes on f6 — beginning the forced mate."],"hr":["Kralj je razgolićen — žrtva prisiljava mat po otvorenoj liniji.","Dama se žrtvuje kako bi razbila zaklon kralja.","Dama uzima na f6 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:005.090' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Figur manövriert zum entscheidenden Angriff gegen den König.","Der Läufer geht in die Ecke und bereitet eine tödliche Drohung vor.","Läufer nach f8 – Auftakt zur Gewinnführung gegen den König."],"en":["A piece maneuvers in for a decisive attack on the king.","The bishop tucks into the corner to set up a deadly threat.","Bishop to f8 — beginning the winning attack on the king."],"hr":["Figura manevrira za odlučujući napad na kralja.","Lovac se uvlači u kut i priprema smrtonosnu prijetnju.","Lovac na f8 — započinje dobitni napad na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:005.091' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du musst ein Mattnetz aufrechterhalten und entscheidenden Vorteil sichern.","Der eigene König weicht zurück und hält das Netz gegen den weißen König intakt.","König nach g7 – beginnt die vorteilbringende Verteidigung."],"en":["You must keep your mating net intact and secure a decisive edge.","Your king steps back, preserving the net around the white king.","King to g7 — beginning the advantageous sequence."],"hr":["Moraš održati matnu mrežu i osigurati odlučujuću prednost.","Tvoj kralj uzmiče i čuva mrežu oko bijelog kralja netaknutom.","Kralj na g7 — započinje povoljan niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.092' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Damenzug lenkt ab und führt rasch zum Sieg.","Die Dame stürzt sich ins Lager und zwingt eine schnelle Entscheidung herbei.","Dame schlägt auf e7 – gewinnt durch Ablenkung."],"en":["A single queen move deflects and wins quickly.","The queen plunges into the camp and forces a swift decision.","Queen takes on e7 — winning by deflection."],"hr":["Jedan potez dame odvlači i brzo donosi pobjedu.","Dama uranja u tabor i prisiljava brzo rješenje.","Dama uzima na e7 — pobjeđuje odvlačenjem."]}', HintsVersion=1 WHERE LineId LIKE '%:005.093' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine kraftvolle Kombination gegen den entblößten König gewinnt entscheidend.","Der Turm schwenkt heran und zwingt die gegnerischen Figuren in die Defensive.","Turm schlägt auf f4 – Auftakt zur Gewinnkombination."],"en":["A powerful combination against the bare king wins decisively.","The rook swings in and forces the enemy pieces onto the defensive.","Rook takes on f4 — the start of the winning combination."],"hr":["Snažna kombinacija protiv razgolićenog kralja odlučno pobjeđuje.","Top se prebacuje i tjera protivničke figure u obranu.","Top uzima na f4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:005.094' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein überraschendes Springeropfer gewinnt Material.","Der Springer schlägt in der Ecke ein und nutzt eine versteckte Fesselung.","Springer schlägt auf a2 – gewinnt Material."],"en":["A surprising knight capture wins material.","The knight strikes in the corner, exploiting a hidden pin.","Knight takes on a2 — winning material."],"hr":["Iznenađujuće uzimanje skakačem osvaja materijal.","Skakač udara u kutu i iskorištava skrivenu vezanost.","Skakač uzima na a2 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.095' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer entkleidet den König und gewinnt entscheidend.","Der Springer schlägt zu, damit Dame und Turm den König einkreisen.","Springer schlägt auf f7 – beginnt die Gewinnkombination."],"en":["A knight sacrifice strips the king and wins decisively.","The knight strikes so queen and rook can hunt down the king.","Knight takes on f7 — starting the winning combination."],"hr":["Žrtva skakača razgolićuje kralja i odlučno pobjeđuje.","Skakač udara kako bi dama i top opkolili kralja.","Skakač uzima na f7 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.096' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du musst eine drohende Mattgefahr abwehren und Vorteil behalten – die Dame eilt zurück.","Die Dame schlägt einen Bauern und kehrt zur Verteidigung des Königs zurück.","Dame schlägt auf f7 – beginnt die rettende Gewinnführung."],"en":["You must parry a mating threat while keeping the edge — the queen rushes back.","The queen grabs a pawn and returns to shield her own king.","Queen takes on f7 — beginning the saving winning sequence."],"hr":["Moraš odbiti prijetnju matom uz zadržavanje prednosti — dama hita natrag.","Dama uzima pješaka i vraća se braniti svog kralja.","Dama uzima na f7 — započinje spasonosni dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.097' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Turmzug ist stärker als jedes Schlagen – er gewinnt.","Der Turm tritt zur Seite und entfesselt eine entscheidende Drohung.","Turm nach d7 – gewinnt entscheidend."],"en":["A quiet rook move beats any capture — it wins.","The rook steps aside and unleashes a decisive threat.","Rook to d7 — winning decisively."],"hr":["Tihi potez topom jači je od svakog uzimanja — pobjeđuje.","Top se izmiče u stranu i oslobađa odlučujuću prijetnju.","Top na d7 — odlučno pobjeđuje."]}', HintsVersion=1 WHERE LineId LIKE '%:005.098' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein leiser Turmzug schafft eine Mattdrohung und gewinnt Material.","Der Turm doppelt auf der offenen Linie und droht das Eindringen.","Turm nach d1 – beginnt die Gewinnkombination."],"en":["A quiet rook move creates a mate threat and wins material.","The rook doubles on the open file, threatening to crash in.","Rook to d1 — starting the winning combination."],"hr":["Tihi potez topom stvara prijetnju matom i osvaja materijal.","Top se udvostručuje na otvorenoj liniji i prijeti prodorom.","Top na d1 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:005.099' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver bereitet ein erzwungenes Matt vor.","Der Springer leitet einen Abzugsangriff gegen den eingeengten König ein.","Springer nach e7 – beginnt die Mattkombination."],"en":["A knight maneuver sets up a forced mate.","The knight launches a discovered attack against the boxed-in king.","Knight to e7 — beginning the mating combination."],"hr":["Manevar skakača priprema prisilni mat.","Skakač pokreće otkriveni napad na stiješnjenog kralja.","Skakač na e7 — započinje matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:005.100' AND BookFileName='chessable-u5-49693.pgn';
