UPDATE BookPuzzles SET HintsJson='{"de":["Ein paradoxer Rückzug in die Ecke gewinnt Material.","Der Springer weicht zurück, blockiert den Bauern und nutzt eine Fesselung.","Springer nach h8 – beginnt die materialgewinnende Folge."],"en":["A paradoxical retreat into the corner wins material.","The knight steps back, blocking the pawn and exploiting a pin.","Knight to h8 — beginning the material-winning sequence."],"hr":["Paradoksalno povlačenje u kut osvaja materijal.","Skakač uzmiče, blokira pješaka i iskorištava vezanost.","Skakač na h8 — započinje niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:005.102' AND BookFileName='chessable-u5-49693.pgn';
