UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schachopfer zwingt den Gegner, die Dame herzugeben.","Der Springer gibt Schach und zerstört die Königsdeckung.","Springer nach b3 – beginnt die gewinnbringende Kombination."],"en":["A checking sacrifice forces the opponent to give up the queen.","The knight checks and shatters the king''s cover.","Knight to b3 — the start of the winning combination."],"hr":["Žrtva sa šahom prisiljava protivnika da preda damu.","Skakač daje šah i razbija kraljevu zaštitu.","Skakač na b3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:006.011' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmschach erzwingt eine Folge, die zum Matt führt.","Der Turm gibt Schach, danach setzt der Läufer den König matt.","Turm schlägt auf h7 – beginnt das erzwungene Matt."],"en":["A rook check forces a sequence that leads to mate.","The rook checks, then the bishop delivers mate.","Rook takes on h7 — beginning the forced mate."],"hr":["Šah topom prisiljava niz koji vodi do mata.","Top daje šah, a zatim lovac matira.","Top uzima na h7 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:006.012' AND BookFileName='chessable-u5-49693.pgn';
