UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer leitet einen vernichtenden Angriff ein.","Der Turm opfert sich, dann zwingen Dame und Läufer den Materialgewinn.","Turm schlägt auf e3 – beginnt die gewinnbringende Kombination."],"en":["A rook sacrifice launches a crushing attack.","The rook sacrifices itself, then queen and bishop force material gain.","Rook takes on e3 — the start of the winning combination."],"hr":["Žrtva topa pokreće razoran napad.","Top se žrtvuje, a zatim dama i lovac prisiljavaju dobitak materijala.","Top uzima na e3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:006.014' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag zerschlägt die zentrale Verteidigung und gewinnt Material.","Der Springer schlägt, dann brechen Springer und Türme entscheidend durch.","Springer schlägt auf d5 – beginnt die gewinnbringende Kombination."],"en":["A capture shatters the central defence and wins material.","The knight strikes, then knight and rooks break through decisively.","Knight takes on d5 — the start of the winning combination."],"hr":["Uzimanje razbija središnju obranu i osvaja materijal.","Skakač udara, a zatim skakač i topovi odlučujuće probijaju.","Skakač uzima na d5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:006.015' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Bauernopfer-Trick lenkt eine Figur ab und entscheidet die Partie zu deinen Gunsten.","Dein dunkelfeldriger Läufer bietet sich an, um die gegnerische Dame von der Verteidigung wegzulocken.","Läufer nach a3 – beginnt die gewinnbringende Kombination."],"en":["A quiet offer deflects a defender and wins decisive material.","Your dark-squared bishop steps up to lure the enemy queen off guard duty.","Bishop to a3 — starting the winning combination."],"hr":["Tihi potez odvlači branitelja i osvaja odlučujući materijal.","Tvoj lovac po crnim poljima nudi se da odvuče protivničku damu s obrane.","Lovac na a3 — počinje dobitna kombinacija."]}', HintsVersion=1 WHERE LineId LIKE '%:006.016' AND BookFileName='chessable-u5-49693.pgn';
