UPDATE BookPuzzles SET HintsJson='{"de":["Ein unscheinbarer Bauernstoß gewinnt einen wichtigen Bauern.","Ein Bauer rückt vor und greift die gegnerische Dame an.","Bauer nach g4 – Beginn der materialgewinnenden Folge."],"en":["An inconspicuous pawn push wins a vital pawn.","A pawn advances and attacks the enemy queen.","Pawn to g4 — starting the material-winning sequence."],"hr":["Neugledan prodor pješaka osvaja važnog pješaka.","Pješak napreduje i napada protivničku damu.","Pješak na g4 — početak niza koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:006.044' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Umwandlung leitet ein erzwungenes Matt ein.","Dein Freibauer wird zur Dame und führt den entscheidenden Angriff an.","Bauer wandelt auf d1 zur Dame um – Beginn des erzwungenen Matts."],"en":["A promotion begins a forced mate.","Your passed pawn becomes a queen and leads the decisive attack.","Pawn promotes to a queen on d1 — the start of the forced mate."],"hr":["Promocija pokreće prisilni mat.","Tvoj prolazni pješak postaje dama i vodi odlučujući napad.","Pješak se promovira u damu na d1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.045' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – öffne die Stellung um den feindlichen König mit aller Kraft.","Ein Turmopfer reißt die Königsstellung auf, der zweite Turm und der Läufer geben den Rest.","Turm schlägt auf g5 – Beginn der Mattführung."],"en":["A forced mate is here — tear open the shelter around the enemy king.","A rook sacrifice rips the king''s cover, then the other rook and the bishop finish.","Rook takes on g5 — the start of the mating attack."],"hr":["Tu postoji prisilni mat — razbij zaklon oko protivničkog kralja.","Žrtva topa otvara kraljev zaklon, a drugi top i lovac dovršavaju.","Top uzima na g5 — početak matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:006.046' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springervorstoß bringt eine entscheidende Kombination ins Rollen und gewinnt Material.","Der Springer zwingt die Antwort, danach trifft ein Läuferschlag den entblößten König.","Springer nach f6 – leitet die gewinnbringende Kombination ein."],"en":["A knight thrust sets off a decisive combination winning material.","The knight forces the reply, then a bishop strike hits the bared king.","Knight to f6 — launching the winning combination."],"hr":["Skok skakača pokreće odlučujuću kombinaciju koja osvaja materijal.","Skakač iznuđuje odgovor, a potom udar lovca pogađa razgolićenog kralja.","Skakač na f6 — pokreće dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:006.047' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination an der gegnerischen Grundreihe gewinnt entscheidend Material.","Ein Turmvorstoß auf der offenen Linie leitet alles ein, die Dame erntet später.","Turm nach e8 – Beginn der gewinnbringenden Folge."],"en":["A combination on the back rank wins decisive material.","A rook push down the open file starts it; the queen reaps the harvest later.","Rook to e8 — the start of the winning sequence."],"hr":["Kombinacija na zadnjem redu osvaja odlučujući materijal.","Prodor topa po otvorenoj liniji sve pokreće, a dama kasnije žanje.","Top na e8 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.048' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein weit vorgerückter Freibauer entscheidet die Partie zu deinen Gunsten.","Schiebe den Randbauern vor und lass die Läufer den Weg freiräumen.","Bauer nach h7 – beginnt den entscheidenden Vormarsch."],"en":["A far-advanced passed pawn decides the game in your favour.","Push the rook''s pawn forward and let the bishops clear the path.","Pawn to h7 — beginning the decisive advance."],"hr":["Daleko odmaknuti slobodni pješak odlučuje partiju u tvoju korist.","Gurni rubnog pješaka naprijed i pusti lovce da raščiste put.","Pješak na h7 — početak odlučujućeg prodora."]}', HintsVersion=1 WHERE LineId LIKE '%:006.049' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination um die Türme herum gewinnt entscheidend Material.","Ein Turmvorstoß lockt, dann gabelt die Dame beide Türme.","Turm nach d6 – Auftakt zur materialgewinnenden Folge."],"en":["A combination around the rooks wins decisive material.","A rook thrust lures, then the queen forks both rooks.","Rook to d6 — the prelude to winning material."],"hr":["Kombinacija oko topova osvaja odlučujući materijal.","Prodor topa mami, a zatim dama viljuškom napada oba topa.","Top na d6 — uvod u osvajanje materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:006.050' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier gibt es ein Matt in einem Zug – sieh es einfach.","Die Dame liefert den tödlichen Schlag aus nächster Nähe.","Dame nach e7 – matt."],"en":["There is mate in one here — just spot it.","The queen delivers the killing blow at close range.","Queen to e7 — mate."],"hr":["Tu postoji mat u jednom potezu — samo ga uoči.","Dama zadaje smrtonosni udarac iz neposredne blizine.","Dama na e7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:006.051' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einfacher Schlag gewinnt eine Figur.","Ein Schwerfigur-Schlag nutzt eine ungedeckte Leichtfigur aus.","Turm schlägt auf b5 – gewinnt eine Figur."],"en":["A simple capture wins a piece.","A heavy-piece capture exploits an undefended minor piece.","Rook takes on b5 — winning a piece."],"hr":["Jednostavno uzimanje osvaja figuru.","Uzimanje teškom figurom iskorištava nebranjenu laku figuru.","Top uzima na b5 — osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:006.052' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein kleiner Bauernstoß sprengt die gegnerische Stellung und gewinnt Material.","Der Bauer reißt die Königsstellung auf, danach dringt die Dame ein.","Bauer nach c3 – Beginn der gewinnbringenden Kombination."],"en":["A small pawn push cracks the position open and wins material.","The pawn rips open the king''s cover, then the queen invades.","Pawn to c3 — the start of the winning combination."],"hr":["Mali prodor pješaka otvara poziciju i osvaja materijal.","Pješak otvara kraljev zaklon, a zatim dama prodire.","Pješak na c3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:006.053' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein erzwungenes Matt für den Anziehenden – pardon, für dich.","Ein Turmopfer lenkt die Dame ab, dann setzt die andere Figur matt.","Turm schlägt auf d3 – Beginn der Mattführung."],"en":["A forced mate awaits you here.","A rook sacrifice deflects the queen, then the other piece mates.","Rook takes on d3 — the start of the mating sequence."],"hr":["Tu te čeka prisilni mat.","Žrtva topa odvlači damu, a zatim druga figura matira.","Top uzima na d3 — početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.054' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Hebung über die Linie gewinnt eine Figur.","Der Turm tritt vor und schafft eine Doppeldrohung, die eine Figur gewinnt.","Turm nach e7 – gewinnt eine Figur."],"en":["A maneuver along the file wins a piece.","The rook steps up to create a double threat that nets a piece.","Rook to e7 — winning a piece."],"hr":["Manevar po liniji osvaja figuru.","Top istupa i stvara dvostruku prijetnju koja osvaja figuru.","Top na e7 — osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:006.055' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gewinnt Material durch eine doppelte Drohung.","Der Läufer schlägt und droht zugleich Matt und einen Turmgewinn.","Läufer schlägt auf f5 – gewinnt Material."],"en":["A capture wins material through a double threat.","The bishop takes and threatens both mate and a rook at once.","Bishop takes on f5 — winning material."],"hr":["Uzimanje osvaja materijal kroz dvostruku prijetnju.","Lovac uzima i istovremeno prijeti matom i topom.","Lovac uzima na f5 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:006.056' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein überraschendes Läuferopfer leitet eine Kombination ein, die eine Figur gewinnt.","Der Läufer schlägt am Königsflügel und legt einen Springervorstoß frei.","Läufer schlägt auf h3 – Beginn der gewinnbringenden Kombination."],"en":["A surprising bishop sacrifice begins a combination that wins a piece.","The bishop strikes near the king and opens the way for a knight leap.","Bishop takes on h3 — the start of the winning combination."],"hr":["Iznenađujuća žrtva lovca pokreće kombinaciju koja osvaja figuru.","Lovac udara uz kralja i otvara put skoku skakača.","Lovac uzima na h3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:006.057' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsstellung auf und gewinnt entscheidend.","Der Turm opfert sich, dann dringt der Springer mit Tempo ein.","Turm schlägt auf g7 – leitet den entscheidenden Angriff ein."],"en":["A sacrifice tears open the king''s cover and wins decisively.","The rook sacrifices itself, then the knight invades with tempo.","Rook takes on g7 — launching the decisive attack."],"hr":["Žrtva otvara kraljev zaklon i odlučujuće dobiva.","Top se žrtvuje, a zatim skakač prodire s tempom.","Top uzima na g7 — pokreće odlučujući napad."]}', HintsVersion=1 WHERE LineId LIKE '%:006.058' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – treibe den König ins Verderben.","Ein Bauernschach öffnet die Diagonale, dann liefert die Dame den Schlag.","Bauer nach f6 – Beginn der Mattführung."],"en":["A forced mate is here — drive the king to its doom.","A pawn check opens the line, then the queen delivers the blow.","Pawn to f6 — the start of the mating attack."],"hr":["Tu postoji prisilni mat — natjeraj kralja u propast.","Šah pješakom otvara liniju, a zatim dama zadaje udarac.","Pješak na f6 — početak matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:006.059' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination im Zentrum gewinnt entscheidend Material.","Ein Turmstoß lockt die Dame weg, dann fällt die Zentrumsfigur.","Turm schlägt auf c4 – Beginn der gewinnbringenden Folge."],"en":["A combination in the centre wins decisive material.","A rook strike lures the queen away, then the central piece falls.","Rook takes on c4 — the start of the winning sequence."],"hr":["Kombinacija u centru osvaja odlučujući materijal.","Udar topa odvlači damu, a zatim pada središnja figura.","Top uzima na c4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.060' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier liegt ein erzwungenes Matt in der Luft – stelle die tödliche Drohung auf.","Die Dame schwenkt herüber und bereitet das entscheidende Eindringen vor.","Dame nach b7 – Beginn der Mattführung."],"en":["A forced mate is in the air — set up the killing threat.","The queen swings across to prepare the decisive breakthrough.","Queen to b7 — the start of the mating attack."],"hr":["Tu se nazire prisilni mat — postavi smrtonosnu prijetnju.","Dama prelazi na drugu stranu i priprema odlučujući prodor.","Dama na b7 — početak matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:006.061' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Bauernstoß zwingt den Gegner, Material gegen das Matt herzugeben.","Der Bauer öffnet Linien am König, dann dringt die Dame tödlich ein.","Bauer nach h3 – Beginn der gewinnbringenden Folge."],"en":["A quiet pawn push forces the opponent to shed material to avoid mate.","The pawn opens lines around the king, then the queen invades fatally.","Pawn to h3 — the start of the winning sequence."],"hr":["Tihi prodor pješaka tjera protivnika da preda materijal kako bi izbjegao mat.","Pješak otvara linije oko kralja, a zatim dama kobno prodire.","Pješak na h3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.062' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – ein verblüffendes stilles Opfer beginnt es.","Ein Läuferopfer im Zentrum lenkt ab und macht den Vorbauern unaufhaltsam.","Läufer nach d4 – Beginn der Mattführung."],"en":["A forced mate is here — a stunning quiet sacrifice begins it.","A bishop sacrifice in the centre deflects and makes the advanced pawn unstoppable.","Bishop to d4 — the start of the mating sequence."],"hr":["Tu postoji prisilni mat — pokreće ga zapanjujuća tiha žrtva.","Žrtva lovca u centru odvlači i čini odmaknutog pješaka nezaustavljivim.","Lovac na d4 — početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.063' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination am Königsflügel gewinnt entscheidend Material.","Erst tritt der zweite Turm hinzu, dann bricht das Opfer durch.","Turm nach f1 – bereitet die gewinnbringende Folge vor."],"en":["A combination on the kingside wins decisive material.","First the second rook joins in, then the sacrifice breaks through.","Rook to f1 — preparing the winning sequence."],"hr":["Kombinacija na kraljevom krilu osvaja odlučujući materijal.","Prvo se pridružuje drugi top, a zatim žrtva probija.","Top na f1 — priprema dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.064' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag räumt den Verteidiger weg und macht den Freibauern unaufhaltsam.","Der Läufer schlägt eine Leichtfigur, dann rollt der Bauer durch.","Läufer schlägt auf f6 – Beginn der gewinnbringenden Folge."],"en":["A capture removes the defender and makes the passed pawn unstoppable.","The bishop takes a minor piece, then the pawn rolls through.","Bishop takes on f6 — the start of the winning sequence."],"hr":["Uzimanje uklanja branitelja i čini slobodnog pješaka nezaustavljivim.","Lovac uzima laku figuru, a zatim pješak prolazi.","Lovac uzima na f6 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.065' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt den Königsschutz weg und führt zu entscheidendem Materialgewinn.","Der Springer schlägt vor dem König, dann setzt die Dame nach.","Springer schlägt auf f7 – leitet den entscheidenden Angriff ein."],"en":["A sacrifice tears away the king''s guard and leads to decisive material.","The knight takes in front of the king, then the queen follows up.","Knight takes on f7 — launching the decisive attack."],"hr":["Žrtva uklanja kraljevu zaštitu i vodi do odlučujućeg materijala.","Skakač uzima pred kraljem, a zatim dama nastavlja.","Skakač uzima na f7 — pokreće odlučujući napad."]}', HintsVersion=1 WHERE LineId LIKE '%:006.066' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein Matt in zwei Zügen für dich.","Ein Turmschach treibt den König, dann setzt der andere Turm matt.","Turm nach d1 – Beginn der kurzen Mattführung."],"en":["A mate in two awaits you here.","A rook check drives the king, then the other rook delivers mate.","Rook to d1 — the start of the short mating sequence."],"hr":["Tu te čeka mat u dva poteza.","Šah topom tjera kralja, a zatim drugi top matira.","Top na d1 — početak kratkog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.067' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug gewinnt die Dame für eine Leichtfigur.","Der Springer geht mit Schach weg und legt einen Angriff auf die Dame frei.","Springer nach f6 – gewinnt die Dame."],"en":["A discovery wins the queen for a minor piece.","The knight moves away with check and unveils an attack on the queen.","Knight to f6 — winning the queen."],"hr":["Otkriveni napad osvaja damu za laku figuru.","Skakač odlazi sa šahom i otkriva napad na damu.","Skakač na f6 — osvaja damu."]}', HintsVersion=1 WHERE LineId LIKE '%:006.068' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein zentraler Damenzug greift mehrere Ziele zugleich an und gewinnt Material.","Die Dame stellt sich so, dass sie drei Punkte gleichzeitig bedroht.","Dame nach g3 – gewinnt Material."],"en":["A central queen move hits several targets at once and wins material.","The queen plants itself to menace three points simultaneously.","Queen to g3 — winning material."],"hr":["Središnji potez dame pogađa više meta odjednom i osvaja materijal.","Dama se postavlja tako da istovremeno prijeti trima točkama.","Dama na g3 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:006.069' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Bauernstoß leitet eine Kombination ein, die Material gewinnt.","Der Bauer stört die Dame, dann springt der Springer entscheidend ein.","Bauer nach c4 – Beginn der gewinnbringenden Folge."],"en":["A quiet pawn push begins a combination that wins material.","The pawn jostles the queen, then the knight leaps in decisively.","Pawn to c4 — the start of the winning sequence."],"hr":["Tihi prodor pješaka pokreće kombinaciju koja osvaja materijal.","Pješak gura damu, a zatim skakač odlučujuće uskače.","Pješak na c4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.070' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer nutzt eine Fesselung aus und gewinnt entscheidend Material.","Der Turm schlägt, dann ist die wiedernehmende Figur gefesselt.","Turm schlägt auf d3 – Beginn der gewinnbringenden Folge."],"en":["A sacrifice exploits a pin and wins decisive material.","The rook captures, then the recapturing piece is pinned.","Rook takes on d3 — the start of the winning sequence."],"hr":["Žrtva iskorištava vezivanje i osvaja odlučujući materijal.","Top uzima, a zatim je figura koja uzima vezana.","Top uzima na d3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.071' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenschach leitet eine Kombination ein, die eine Figur gewinnt.","Die Dame gibt Schach im Zentrum und bereitet einen Springersprung vor.","Dame nach d4 – Beginn der gewinnbringenden Folge."],"en":["A queen check begins a combination that wins a piece.","The queen checks in the centre and prepares a knight leap.","Queen to d4 — the start of the winning sequence."],"hr":["Šah damom pokreće kombinaciju koja osvaja figuru.","Dama daje šah u centru i priprema skok skakača.","Dama na d4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.072' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und musst die Partie mit Dauerschach retten.","Der Turm allein jagt den König und erzwingt die ewige Wiederholung.","Turm nach g2 – Beginn des rettenden Dauerschachs."],"en":["You are worse and must save the game with perpetual check.","The rook alone hunts the king and forces the endless repetition.","Rook to g2 — the start of the saving perpetual check."],"hr":["Stojiš lošije i moraš spasiti partiju vječnim šahom.","Sam top progoni kralja i iznuđuje vječno ponavljanje.","Top na g2 — početak spasonosnog vječnog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:006.073' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gegen den Königsflügel gewinnt entscheidend Material.","Die Dame schwenkt heran, dann bricht ein Opfer die Bauernkette auf.","Dame nach h5 – leitet den entscheidenden Angriff ein."],"en":["A combination against the kingside wins decisive material.","The queen swings over, then a sacrifice cracks open the pawn shield.","Queen to h5 — launching the decisive attack."],"hr":["Kombinacija protiv kraljevog krila osvaja odlučujući materijal.","Dama prilazi, a zatim žrtva razbija pješački štit.","Dama na h5 — pokreće odlučujući napad."]}', HintsVersion=1 WHERE LineId LIKE '%:006.074' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf dem schwachen Punkt vor dem König gewinnt entscheidend Material.","Der Springer schlägt vor dem König und leitet die Kombination ein.","Springer schlägt auf f7 – Beginn der gewinnbringenden Folge."],"en":["A sacrifice on the weak point in front of the king wins decisive material.","The knight takes in front of the king and begins the combination.","Knight takes on f7 — the start of the winning sequence."],"hr":["Žrtva na slaboj točki pred kraljem osvaja odlučujući materijal.","Skakač uzima pred kraljem i pokreće kombinaciju.","Skakač uzima na f7 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:006.075' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Turmendspiel lässt sich ein entscheidender Vorteil herausholen.","Dein Turm muss aktiv werden und den Gegner an seine Schwächen fesseln.","Turm nach a4 – beginnt das gewinnträchtige Manöver."],"en":["A decisive edge is hidden in this rook ending.","Your rook must turn active and tie the opponent to his weaknesses.","Rook to a4 — starting the winning maneuver."],"hr":["U topovskoj završnici krije se odlučujuća prednost.","Tvoj top mora postati aktivan i vezati protivnika uz njegove slabosti.","Top na a4 — započinje dobitni manevar."]}', HintsVersion=1 WHERE LineId LIKE '%:006.076' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein scharfer Damen-Stoß bahnt einen entscheidenden Angriff an.","Die Dame schaltet sich mit Schach ein und ebnet dem Turm den Weg.","Dame nach a8 – leitet die gewinnbringende Kombination ein."],"en":["A sharp queen thrust opens a decisive attack.","The queen joins in with check and clears the path for the rook.","Queen to a8 — beginning the winning combination."],"hr":["Oštar damin upad otvara odlučujući napad.","Dama se uključuje sa šahom i krči put topu.","Dama na a8 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:006.077' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernzug entfesselt eine materialgewinnende Kombination.","Der Läufer greift einen Schlüsselverteidiger an und reißt die Stellung auf.","Läufer nach g4 – startet die gewinnbringende Folge."],"en":["A bishop move unleashes a material-winning combination.","The bishop attacks a key defender and tears the position open.","Bishop to g4 — starting the winning sequence."],"hr":["Potez lovcem pokreće kombinaciju koja osvaja materijal.","Lovac napada ključnog branitelja i otvara poziciju.","Lovac na g4 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:006.078' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein zweiter Freibauer entscheidet das Turmendspiel.","Der vorgeschobene Bauer muss laufen, während dein Turm den Gegner bindet.","Bauer nach c5 – beginnt das gewinnträchtige Vorgehen."],"en":["A second passed pawn decides this rook ending.","The advanced pawn must run while your rook ties the enemy down.","Pawn to c5 — starting the winning plan."],"hr":["Drugi slobodni pješak odlučuje topovsku završnicu.","Napredni pješak mora krenuti dok tvoj top veže protivnika.","Pješak na c5 — započinje dobitni plan."]}', HintsVersion=1 WHERE LineId LIKE '%:006.079' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein überraschendes Opfer fängt die gegnerische Dame.","Der Läufer lockt einen Bauern weg, dann schlägt der Springer ein.","Läufer schlägt auf a6 – leitet den entscheidenden Materialgewinn ein."],"en":["A surprising sacrifice traps the enemy queen.","The bishop lures a pawn away, then the knight strikes.","Bishop takes on a6 — beginning the decisive material gain."],"hr":["Iznenađujuća žrtva hvata protivničku damu.","Lovac odvlači pješaka, a zatim skakač udara.","Lovac uzima na a6 — započinje odlučujući dobitak materijala."]}', HintsVersion=1 WHERE LineId LIKE '%:006.080' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein verblüffendes Opfer erzwingt ein Matt.","Der Turm lenkt einen Verteidiger von der entscheidenden Linie ab.","Turm nach a2 – beginnt die erzwungene Mattführung."],"en":["A stunning sacrifice forces mate.","The rook deflects a defender from the vital file.","Rook to a2 — starting the forced mating sequence."],"hr":["Zapanjujuća žrtva forsira mat.","Top odvlači branitelja s ključne linije.","Top na a2 — započinje prisilni niz koji vodi do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:006.081' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und musst dich mit einem Trick retten.","Der Turm geht aktiv vor und steuert auf ein Patt zu.","Turm nach c1 – leitet die rettende Patt-Kombination ein."],"en":["You stand worse and must save yourself with a trick.","The rook turns active and steers toward a stalemate.","Rook to c1 — beginning the saving stalemate combination."],"hr":["Stojiš lošije i moraš se spasiti trikom.","Top postaje aktivan i smjera prema patu.","Top na c1 — započinje spasonosnu pat kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:006.082' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf einem Schlüsselfeld gewinnt eine Figur.","Der Turm opfert sich mit Schach, dann gabelt die Dame.","Turm schlägt auf f2 – startet die figurengewinnende Folge."],"en":["A sacrifice on a key square wins a piece.","The rook gives itself up with check, then the queen forks.","Rook takes on f2 — starting the piece-winning sequence."],"hr":["Žrtva na ključnom polju osvaja figuru.","Top se žrtvuje sa šahom, a zatim dama vilicom udara.","Top uzima na f2 — započinje niz koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:007.003' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer öffnet die Königsstellung und gewinnt entscheidend.","Erst räumt der Springer, dann dringt die Dame zum König vor.","Springer schlägt auf g5 – beginnt die gewinnbringende Kombination."],"en":["A sacrifice rips open the king and wins decisively.","The knight clears the way, then the queen breaks through to the king.","Knight takes on g5 — starting the winning combination."],"hr":["Žrtva otvara kraljevu poziciju i odlučujuće pobjeđuje.","Prvo skakač čisti put, zatim dama prodire do kralja.","Skakač uzima na g5 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:007.004' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der scheinbare Bauernfang ist nur ein Bluff – du gewinnst Material.","Erst der Läufer, dann die Verwicklung im Zentrum kostet Weiß eine Figur.","Läufer schlägt auf a5 – startet die materialgewinnende Folge."],"en":["The apparent pawn snatch is only a bluff — you win material.","First the bishop, then the central tangle costs White a piece.","Bishop takes on a5 — starting the material-winning sequence."],"hr":["Prividno hvatanje pješaka samo je blef — osvajaš materijal.","Prvo lovac, a zatim zaplet u centru košta bijelog figuru.","Lovac uzima na a5 — započinje niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.005' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Turmzug bereitet den entscheidenden Schlag vor.","Der Turm schwenkt herüber und stellt eine tödliche Drohung am König auf.","Turm nach h3 – beginnt die gewinnbringende Kombination."],"en":["A quiet rook move prepares the decisive blow.","The rook swings over and sets up a lethal threat at the king.","Rook to h3 — starting the winning combination."],"hr":["Tihi potez topom priprema odlučujući udarac.","Top se prebacuje i postavlja smrtonosnu prijetnju kralju.","Top na h3 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:007.006' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagen mit Schach leitet eine gewinnträchtige Folge ein.","Der Springer schlägt mit Schach, dann läuft der König nach den Bauern.","Springer schlägt auf g4 – startet die vorteilbringende Folge."],"en":["A capture with check launches an advantageous sequence.","The knight takes with check, then the king hunts down the pawns.","Knight takes on g4 — starting the advantageous sequence."],"hr":["Uzimanje sa šahom pokreće povoljan niz.","Skakač uzima sa šahom, a zatim kralj juri za pješacima.","Skakač uzima na g4 — započinje povoljan niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.007' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein präziser Königszug bereitet ein schnelles Matt vor.","Erst die Dame in Sicherheit, dann brechen die Türme durch.","Dame nach c7 – leitet die zum Matt führende Folge ein."],"en":["A precise king move sets up a quick mate.","First the queen steps aside, then the rooks break through.","Queen to c7 — beginning the sequence that forces mate."],"hr":["Precizan potez kraljem priprema brzi mat.","Prvo dama u sigurnost, zatim topovi probijaju.","Dama na c7 — započinje niz koji vodi do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.008' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination bestraft die zu frühe Befreiung.","Erst lenkt der Läufer ab, dann gabelt der Springer.","Läufer schlägt auf e7 – startet die materialgewinnende Folge."],"en":["A combination punishes the premature freeing move.","First the bishop deflects, then the knight forks.","Bishop takes on e7 — starting the material-winning sequence."],"hr":["Kombinacija kažnjava prerano oslobađanje.","Prvo lovac odvlači, a zatim skakač udara vilicom.","Lovac uzima na e7 — započinje niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.009' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und musst ein Remis erzwingen.","Erst opfert der Turm, dann sorgt der Springer für ewiges Schach.","Turm nach e1 – beginnt die rettende Dauerschach-Folge."],"en":["You stand worse and must force a draw.","First the rook sacrifices, then the knight delivers perpetual check.","Rook to e1 — starting the saving perpetual-check sequence."],"hr":["Stojiš lošije i moraš isforsirati remi.","Prvo top se žrtvuje, zatim skakač drži vječni šah.","Top na e1 — započinje spasonosni niz vječnog šaha."]}', HintsVersion=1 WHERE LineId LIKE '%:007.010' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein unscheinbarer Bauernzug gewinnt Material.","Der Bauer greift einen Läufer an und legt dem König eine Falle.","Bauer nach g6 – startet die materialgewinnende Folge."],"en":["An inconspicuous pawn move wins material.","The pawn attacks a bishop and sets a trap for the king.","Pawn to g6 — starting the material-winning sequence."],"hr":["Neugledan potez pješakom osvaja materijal.","Pješak napada lovca i postavlja zamku kralju.","Pješak na g6 — započinje niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.011' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit der Mehrfigur gewinnst du am schnellsten durch einen Stoß.","Der Läufer geht entscheidend vor und stellt unparierbare Drohungen.","Läufer nach e3 – startet die gewinnbringende Folge."],"en":["With the extra piece a single thrust wins fastest.","The bishop steps in decisively and sets unstoppable threats.","Bishop to e3 — starting the winning sequence."],"hr":["S viškom figure jedan upad pobjeđuje najbrže.","Lovac odlučujuće stupa i postavlja neodbranjive prijetnje.","Lovac na e3 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.012' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer leitet einen Abzugsschach-Gewinn ein.","Der Turm opfert sich, danach gewinnt ein Abzug den schwarzen Turm.","Turm schlägt auf d8 – beginnt die materialgewinnende Folge."],"en":["A rook sacrifice sets up a discovered-check win.","The rook gives itself up, then a discovery wins the black rook.","Rook takes on d8 — starting the material-winning sequence."],"hr":["Žrtva topa priprema dobitak otkrivenim šahom.","Top se žrtvuje, a zatim otkriveni napad osvaja crnog topa.","Top uzima na d8 — započinje niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.013' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Dame und Läufer treiben den König ins Matt.","Erst die Dame, dann der Läufer schnüren das Mattnetz zu.","Dame schlägt auf f6 – beginnt die erzwungene Mattführung."],"en":["Queen and bishop drive the king into mate.","The queen, then the bishop, draw the mating net tight.","Queen takes on f6 — starting the forced mating sequence."],"hr":["Dama i lovac tjeraju kralja u mat.","Prvo dama, zatim lovac stežu matnu mrežu.","Dama uzima na f6 — započinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.014' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagen leitet einen Bauern- und Königslauf zum Vorteil ein.","Der Turm schlägt, dann jagt dein König die gegnerische Figur und die Bauern.","Turm schlägt auf h4 – startet die vorteilbringende Folge."],"en":["A capture begins a pawn-and-king march to advantage.","The rook takes, then your king chases the enemy piece and pawns.","Rook takes on h4 — starting the advantageous sequence."],"hr":["Uzimanje pokreće pohod pješaka i kralja prema prednosti.","Top uzima, a zatim tvoj kralj goni protivničku figuru i pješake.","Top uzima na h4 — započinje povoljan niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.015' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß ins Herz der Stellung entscheidet die Partie.","Der Turm dringt entscheidend ein und unterstützt den Angriff am König.","Turm nach e2 – startet die gewinnbringende Folge."],"en":["A thrust into the heart of the position decides the game.","The rook penetrates decisively and backs the attack on the king.","Rook to e2 — starting the winning sequence."],"hr":["Prodor u srce pozicije odlučuje partiju.","Top odlučujuće prodire i podupire napad na kralja.","Top na e2 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.016' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer reißt den König heraus und erzwingt Matt.","Erst der Läufer, dann der Turm sprengen die Königsdeckung.","Läufer schlägt auf g7 – beginnt die erzwungene Mattführung."],"en":["A bishop sacrifice drags the king out and forces mate.","First the bishop, then the rook blast open the king''s cover.","Bishop takes on g7 — starting the forced mating sequence."],"hr":["Žrtva lovca izvlači kralja i forsira mat.","Prvo lovac, zatim top razbijaju kraljev zaklon.","Lovac uzima na g7 — započinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.017' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer in der Mitte gewinnt entscheidend Material.","Der Läufer schlägt im Zentrum und zwingt den Gegner zu Verlusten.","Läufer schlägt auf d4 – startet die materialgewinnende Folge."],"en":["A central bishop sacrifice wins decisive material.","The bishop captures in the center and forces the opponent to give up material.","Bishop takes on d4 — starting the material-winning sequence."],"hr":["Žrtva lovca u centru osvaja odlučujući materijal.","Lovac uzima u centru i prisiljava protivnika na gubitke.","Lovac uzima na d4 — započinje niz koji osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.018' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer mit Schach rettet die Stellung und gewinnt.","Die Dame schlägt mit Schach, dann läuft dein König dem Freibauern entgegen.","Dame schlägt auf g3 – startet die vorteilbringende Folge."],"en":["A queen sacrifice with check turns the position around and wins.","The queen takes with check, then your king walks toward the passed pawn.","Queen takes on g3 — starting the advantageous sequence."],"hr":["Žrtva dame sa šahom preokreće poziciju i pobjeđuje.","Dama uzima sa šahom, a zatim tvoj kralj kreće prema slobodnom pješaku.","Dama uzima na g3 — započinje povoljan niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.019' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernopfer lenkt den Läufer ab und gewinnt eine Figur.","Erst der Bauer lockt den Läufer weg, dann gabelt die Dame.","Bauer nach c5 – startet die figurengewinnende Folge."],"en":["A pawn sacrifice deflects the bishop and wins a piece.","First the pawn lures the bishop away, then the queen forks.","Pawn to c5 — starting the piece-winning sequence."],"hr":["Žrtva pješaka odvlači lovca i osvaja figuru.","Prvo pješak odvlači lovca, a zatim dama udara vilicom.","Pješak na c5 — započinje niz koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:007.020' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Läuferzug stellt den König vor Damenverlust oder Matt.","Der Läufer zieht ruhig ein und knüpft mit dem Turm ein Mattnetz.","Läufer schlägt auf h7 – beginnt die erzwungene Mattführung."],"en":["A quiet bishop move leaves the king facing queen loss or mate.","The bishop slips in quietly and, with the rook, weaves a mating net.","Bishop takes on h7 — starting the forced mating sequence."],"hr":["Tihi potez lovcem suočava kralja s gubitkom dame ili matom.","Lovac se tiho ušuljava i s topom plete matnu mrežu.","Lovac uzima na h7 — započinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.021' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du musst die gefährlichen Drohungen abwehren und das Spiel wenden.","Erst rettet die Dame mit Schach, dann verteidigt der König gegen die Figuren.","Dame nach b1 – beginnt die rettende, vorteilbringende Folge."],"en":["You must parry the dangerous threats and turn the game around.","First the queen saves itself with check, then the king defends against the pieces.","Queen to b1 — starting the saving, advantageous sequence."],"hr":["Moraš odbiti opasne prijetnje i preokrenuti partiju.","Prvo dama se spašava sa šahom, zatim kralj brani od figura.","Dama na b1 — započinje spasonosni, povoljan niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.022' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß mit Umwandlungsdrohung gewinnt entscheidend.","Der vorgerückte Bauer drängt vor und ein Springer gabelt anschließend.","Bauer nach d7 – startet die gewinnbringende Folge."],"en":["A pawn push with a promotion threat wins decisively.","The advanced pawn presses on and a knight then forks.","Pawn to d7 — starting the winning sequence."],"hr":["Prodor pješaka s prijetnjom promocije odlučujuće pobjeđuje.","Napredni pješak gura naprijed, a skakač zatim udara vilicom.","Pješak na d7 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.023' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Turmzug erzwingt den entscheidenden Vorteil.","Der Turm geht herüber und macht die gegnerische Mattdrohung unhaltbar stark.","Turm schlägt auf g7 – sichert den entscheidenden Vorteil."],"en":["A single rook move forces the decisive advantage.","The rook swings over and makes the looming mate unstoppable.","Rook takes on g7 — securing the decisive advantage."],"hr":["Jedan potez topom forsira odlučujuću prednost.","Top se prebacuje i čini prijeteći mat neodbranjivim.","Top uzima na g7 — osigurava odlučujuću prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:007.024' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Zug nutzt die Fesselung auf der langen Diagonale aus.","Erst weicht der König aus, dann kommt die verheerende Drohung gegen den Turm.","König nach h8 – startet die gewinnbringende Folge."],"en":["A quiet move exploits the pin on the long diagonal.","First the king steps aside, then a devastating threat against the rook follows.","King to h8 — starting the winning sequence."],"hr":["Tihi potez iskorištava vezivanje na dugoj dijagonali.","Prvo kralj se izmiče, a zatim slijedi razorna prijetnja topu.","Kralj na h8 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:007.025' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Bauernzug stellt eine Doppeldrohung und gewinnt entscheidend.","Der Vorstoß des Bauern öffnet Linien für deine schweren Figuren gegen den König.","Bauer nach f5 – startet die gewinnende Kombination."],"en":["A quiet pawn move sets up a double threat and wins decisively.","Advancing the pawn opens lines for your heavy pieces against the king.","Pawn to f5 — begins the winning combination."],"hr":["Tihi potez pješakom stvara dvostruku prijetnju i odlučno dobiva.","Pomak pješaka otvara linije tvojim teškim figurama prema kralju.","Pješak na f5 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:007.026' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Eindringen in die letzte Reihe gewinnt eine Figur.","Der Turm dringt mit Schach ein und der Läufer setzt die Drohung fort.","Turm nach d1 – beginnt die gewinnende Folge."],"en":["An invasion of the back rank wins a piece.","The rook breaks in with check and the bishop follows up the threat.","Rook to d1 — starts the winning sequence."],"hr":["Prodor na zadnju liniju osvaja figuru.","Top upada sa šahom, a lovac nastavlja prijetnju.","Top na d1 — započinje dobitni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:007.027' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gegen die Verteidiger zerstört die Königsstellung und gewinnt klar.","Ein Läuferopfer reißt die Bauerndeckung vor dem König auf.","Läufer schlägt auf e5 – Auftakt der starken Kombination."],"en":["A blow against the defenders shatters the king''s shelter and wins clearly.","A bishop sacrifice tears open the pawn cover around the king.","Bishop takes on e5 — the start of the strong combination."],"hr":["Udarac po braniteljima razbija kraljev zaklon i jasno dobiva.","Žrtva lovca razbija pješački zaklon oko kralja.","Lovac uzima na e5 — početak snažne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.028' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz Minusfigur erzwingt der starke Freibauer einen Matt.","Der vorrückende Freibauer und die schweren Figuren weben das Mattnetz.","Bauer nach f7 – leitet das erzwungene Matt ein."],"en":["Despite being down a piece, the powerful passed pawn forces mate.","The advancing passed pawn together with the heavy pieces builds the mating net.","Pawn to f7 — sets the forced mate in motion."],"hr":["Unatoč manjku figure, snažni slobodni pješak forsira mat.","Pješak koji napreduje i teške figure tkaju matnu mrežu.","Pješak na f7 — pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:007.029' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Angriff auf den überlasteten Verteidiger gewinnt Material.","Der Turm zielt auf die Dame, die einen Läufer nicht mehr halten kann.","Turm nach e3 – gewinnt Material."],"en":["An attack on the overloaded defender wins material.","The rook targets the queen, which can no longer hold the bishop.","Rook to e3 — wins material."],"hr":["Napad na preopterećenog branitelja osvaja materijal.","Top cilja damu koja više ne može držati lovca.","Top na e3 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.030' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz beidseitig offener Könige setzt der Anziehende ein erzwungenes Matt durch.","Der Springer schlägt zu und die Dame führt den Königsangriff zu Ende.","Springer schlägt auf d6 – Beginn des erzwungenen Matts."],"en":["With both kings exposed, the side to move forces a mate.","The knight strikes and the queen drives the king attack home.","Knight takes on d6 — the beginning of the forced mate."],"hr":["Uz oba izložena kralja, onaj na potezu forsira mat.","Skakač udara, a dama dovršava napad na kralja.","Skakač uzima na d6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.031' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein wuchtiges Opfer öffnet den Weg zu einem erzwungenen Matt.","Ein Turmopfer reißt die Königsstellung auf, damit die Figuren zuschlagen.","Turm schlägt auf b2 – Auftakt des erzwungenen Matts."],"en":["A crushing sacrifice clears the path to a forced mate.","A rook sacrifice rips open the king''s position so the pieces can strike.","Rook takes on b2 — the start of the forced mate."],"hr":["Razorna žrtva otvara put do prisilnog mata.","Žrtva topa razbija kraljev položaj kako bi figure udarile.","Top uzima na b2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:007.032' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer an der Königsstellung leitet einen gewinnenden Angriff ein.","Der Springer schlägt vor dem König ein und reißt die Bauerndeckung weg.","Springer schlägt auf g6 – Beginn der gewinnenden Kombination."],"en":["A sacrifice at the king''s shelter launches a winning attack.","The knight crashes in front of the king and removes the pawn cover.","Knight takes on g6 — the start of the winning combination."],"hr":["Žrtva na kraljevom zaklonu pokreće dobitni napad.","Skakač upada ispred kralja i uklanja pješački zaklon.","Skakač uzima na g6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:007.033' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorrückender Bauer greift eine Leichtfigur an und gewinnt Material.","Der Bauer stößt eine der weißen Figuren an und löst die Abwicklung aus.","Bauer nach e6 – beginnt die materialgewinnende Folge."],"en":["An advancing pawn attacks a minor piece and wins material.","The pawn pokes one of White''s pieces and triggers the liquidation.","Pawn to e6 — begins the material-winning sequence."],"hr":["Pješak u napredovanju napada laku figuru i osvaja materijal.","Pješak dira jednu od bijelih figura i pokreće razmjene.","Pješak na e6 — započinje slijed koji dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.034' AND BookFileName='chessable-u5-49693.pgn';
