UPDATE BookPuzzles SET HintsJson='{"de":["Ein Angriff auf einen ungedeckten Läufer gewinnt Material.","Der Turm geht in der Reihe seitwärts und greift den Läufer an.","Turm nach b4 – beginnt die materialgewinnende Folge."],"en":["An attack on a loose bishop wins material.","The rook slides along the rank and hits the bishop.","Rook to b4 — begins the material-winning sequence."],"hr":["Napad na nezaštićenog lovca osvaja materijal.","Top klizi po liniji i napada lovca.","Top na b4 — započinje slijed koji dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:007.037' AND BookFileName='chessable-u5-49693.pgn';
