UPDATE BookPuzzles SET HintsJson='{"de":["Ein doppeltes Drohmanöver gewinnt eine Figur.","Die Dame baut sich auf und greift gleich zwei Ziele an.","Dame nach e3 – Beginn der gewinnenden Folge."],"en":["A double-threat maneuver wins a piece.","The queen repositions and takes aim at two targets at once.","Queen to e3 — the start of the winning sequence."],"hr":["Manevar s dvostrukom prijetnjom osvaja figuru.","Dama se prebacuje i cilja na dvije mete odjednom.","Dama na e3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:009.076' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag in der Mitte gewinnt durch einen anschließenden Spieß Material.","Der Springer schlägt, dann hebt die Dame zwei Figuren auf einer Linie aus.","Springer schlägt auf d5 – Beginn der gewinnenden Kombination."],"en":["A central capture wins material via a follow-up skewer.","The knight takes, then the queen lines up two pieces to win one.","Knight takes on d5 — the start of the winning combination."],"hr":["Uzimanje u sredini osvaja materijal kasnijim raženjem.","Skakač uzima, a zatim dama poreda dvije figure i osvaja jednu.","Skakač uzima na d5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:009.077' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer lockt den König heraus und gewinnt entscheidend.","Der Turm wird als Köder geopfert, dann gabelt der Springer König und Dame.","Turm nach d8 – Beginn der gewinnenden Kombination."],"en":["A sacrifice decoys the king and wins decisively.","The rook is offered as bait, then the knight forks king and queen.","Rook to d8 — the start of the winning combination."],"hr":["Žrtva mami kralja i odlučno pobjeđuje.","Top se nudi kao mamac, a zatim skakač viljuškom hvata kralja i damu.","Top na d8 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:009.078' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag öffnet die Linie zum König – ein erzwungenes Matt liegt vor.","Der Läufer beginnt, dann reißen Turm, Springer und Dame den König nieder.","Läufer nach c3 – Auftakt zum erzwungenen Matt."],"en":["A capture opens the line to the king — a forced mate is there.","The bishop begins, then rook, knight and queen run the king down.","Bishop to c3 — the start of a forced mate."],"hr":["Uzimanje otvara liniju prema kralju — slijedi prisilni mat.","Lovac započinje, a top, skakač i dama obaraju kralja.","Lovac na c3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.079' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver gewinnt entscheidend Material.","Der Springer schafft Raum, dann fängt der Läufer die feindliche Dame.","Springer nach c4 – Beginn der gewinnenden Kombination."],"en":["A knight maneuver wins decisive material.","The knight makes room, then the bishop snares the enemy queen.","Knight to c4 — the start of the winning combination."],"hr":["Manevar skakačem osvaja odlučujući materijal.","Skakač stvara prostor, a zatim lovac hvata protivničku damu.","Skakač na c4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:009.080' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein leiser Zug bereitet ein erzwungenes Matt vor.","Der Turm wechselt die Linie und öffnet den Läufern und der Dame die Bahn.","Turm nach h1 – Auftakt zum erzwungenen Matt."],"en":["A quiet move sets up a forced mate.","The rook switches files and clears the way for the bishops and queen.","Rook to h1 — the start of a forced mate."],"hr":["Tihi potez priprema prisilni mat.","Top mijenja liniju i otvara put lovcima i dami.","Top na h1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:009.081' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schach beginnt einen unaufhaltsamen Turmvormarsch.","Der Turm dringt mit Schach ein, dem der König nichts entgegensetzen kann.","Turm nach c3 – Beginn der gewinnenden Kombination."],"en":["A check launches an unstoppable rook invasion.","The rook breaks in with check and the king has no defense.","Rook to c3 — the start of the winning combination."],"hr":["Šah pokreće nezaustavljiv prodor topa.","Top upada sa šahom, a kralj nema obrane.","Top na c3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:009.082' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer im Endspiel gewinnt eine Figur.","Der Turm wird hergegeben, dann gabelt der Läufer König und Turm.","Turm nach c5 – Beginn der gewinnenden Kombination."],"en":["An endgame sacrifice wins a piece.","The rook is given up, then the bishop forks king and rook.","Rook to c5 — the start of the winning combination."],"hr":["Žrtva u završnici osvaja figuru.","Top se daje, a zatim lovac viljuškom hvata kralja i top.","Top na c5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:010.003' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die beiden Türme auf der siebten Reihe entscheiden schnell.","Ein Bauernzug öffnet die Bahn, dann brechen die Türme durch.","Bauer nach f5 – Beginn der gewinnenden Folge."],"en":["The two rooks on the seventh rank decide quickly.","A pawn move opens the way, then the rooks crash through.","Pawn to f5 — the start of the winning sequence."],"hr":["Dva topa na sedmom redu brzo odlučuju.","Potez pješakom otvara put, a zatim topovi probijaju.","Pješak na f5 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.004' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Tausch führt in ein gewonnenes Bauernendspiel.","Der Turm opfert sich, danach läuft der König dem Freibauern voraus.","Turm schlägt auf g6 – Beginn der gewinnenden Folge."],"en":["A trade liquidates into a winning pawn ending.","The rook gives itself up, then the king escorts the passed pawn.","Rook takes on g6 — the start of the winning sequence."],"hr":["Zamjena prelazi u dobivenu pješačku završnicu.","Top se žrtvuje, a zatim kralj prati slobodnog pješaka.","Top uzima na g6 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.005' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der eigene Freibauer entscheidet – richtig vorbereitet.","Der Turm wechselt die Linie und stützt den Vormarsch des Bauern.","Turm nach e1 – Beginn der gewinnenden Folge."],"en":["The passed pawn decides — if prepared correctly.","The rook switches files to support the pawn''s advance.","Rook to e1 — the start of the winning sequence."],"hr":["Vlastiti slobodni pješak odlučuje — uz pravilnu pripremu.","Top mijenja liniju i podupire napredovanje pješaka.","Top na e1 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.006' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel ist solides Zurückschlagen besser als die Gabel.","Der Bauer schlägt zurück und behält die bessere Struktur.","Bauer schlägt auf f4 – sichert den Vorteil."],"en":["In the endgame, the solid recapture beats the fork.","The pawn recaptures and keeps the better structure.","Pawn takes on f4 — securing the advantage."],"hr":["U završnici je čvrsto uzimanje bolje od viljuške.","Pješak uzima natrag i zadržava bolju strukturu.","Pješak uzima na f4 — osigurava prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:010.007' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauerndurchbruch verschafft einen entscheidenden Freibauern.","Ein Opferbauer lenkt ab, dann läuft der andere Bauer durch.","Bauer nach b4 – Beginn der gewinnenden Folge."],"en":["A pawn breakthrough creates a decisive passer.","One pawn deflects, then the other pawn runs through.","Pawn to b4 — the start of the winning sequence."],"hr":["Pješački proboj stvara odlučujućeg slobodnjaka.","Jedan pješak odvlači, a zatim drugi pješak prolazi.","Pješak na b4 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.008' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Königszug bringt den Gegner in Zugzwang.","Der König geht nach vorn und der Gegner muss nachgeben.","König nach e5 – Beginn der gewinnenden Folge."],"en":["A quiet king move puts the opponent in zugzwang.","The king steps forward and the opponent must give ground.","King to e5 — the start of the winning sequence."],"hr":["Tihi potez kraljem stavlja protivnika u cugcvang.","Kralj kreće naprijed i protivnik mora popustiti.","Kralj na e5 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.009' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer ebnet dem Freibauern den Weg zur Umwandlung.","Der Turm wird hergegeben, dann läuft der Bauer unaufhaltsam durch.","Turm nach c1 – Beginn der gewinnenden Folge."],"en":["A rook sacrifice clears the passed pawn''s path to promotion.","The rook is given up, then the pawn runs through unstoppably.","Rook to c1 — the start of the winning sequence."],"hr":["Žrtva topa krči slobodnom pješaku put do promocije.","Top se daje, a zatim pješak nezaustavljivo prolazi.","Top na c1 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.010' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schlechter stehend muss man hier das Remis ins Patt retten.","Der Turm opfert sich, um den eigenen König ins Patt zu zwingen.","Turm schlägt auf e5 – Beginn der rettenden Pattfolge."],"en":["Worse off, you must rescue the draw via stalemate.","The rook sacrifices itself to force your own king into stalemate.","Rook takes on e5 — the start of the saving stalemate."],"hr":["U lošijem položaju, remi se mora spasiti patom.","Top se žrtvuje kako bi vlastiti kralj dospio u pat.","Top uzima na e5 — početak spasonosnog pata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.011' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die gegnerischen Bauern sehen gefährlich aus, doch ein präziser Stoß neutralisiert sie und sichert den Materialvorteil.","Der Läufer übernimmt die Schlüsselarbeit, um die vorrückenden Bauern aufzuhalten.","Läufer nach c3 – stoppt die Bauern und behält den entscheidenden Vorteil."],"en":["The enemy pawns look scary, but one precise stroke neutralizes them and keeps the material edge.","The bishop does the key work to halt the advancing pawns.","Bishop to c3 — stopping the pawns and keeping the decisive advantage."],"hr":["Protivnički pješaci izgledaju opasno, ali jedan precizan potez ih neutralizira i čuva materijalnu prednost.","Lovac obavlja ključni posao zaustavljajući napredujuće pješake.","Lovac na c3 — zaustavlja pješake i zadržava odlučujuću prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:010.012' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß steht schlechter und muss sich mit einem Trick ins Remis retten.","Der Springer wirft sich opfernd ins Spiel, um eine Pattfalle vorzubereiten.","Springer nach g5 – leitet die Rettungskombination zum Remis ein."],"en":["White is worse and must rescue a draw with a clever resource.","The knight throws itself in as a sacrifice to set up a stalemate trap.","Knight to g5 — beginning the saving sequence to a draw."],"hr":["Bijeli stoji lošije i mora se spasiti remijem domišljatim trikom.","Skakač se žrtvuje da pripremi pat-zamku.","Skakač na g5 — započinje spasonosni niz do remija."]}', HintsVersion=1 WHERE LineId LIKE '%:010.013' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weit vorgerückte Freibauer lässt sich in eine entscheidende Aktion verwandeln.","Der Turm räumt zuerst dem Bauern den Weg und stützt dessen Vormarsch.","Turm nach c8 – startet die siegbringende Kombination um den Freibauern."],"en":["The far-advanced passed pawn can be turned into a decisive force.","The rook clears the way and supports the pawn''s march.","Rook to c8 — launching the winning combination around the passed pawn."],"hr":["Daleko napredovali slobodni pješak može se pretvoriti u odlučujuću snagu.","Top prvo krči put i podupire prodor pješaka.","Top na c8 — pokreće pobjedonosnu kombinaciju oko slobodnog pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:010.014' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer befreit den eigenen Freibauern und führt zur Umwandlung.","Der Läufer opfert sich, damit der Bauer ungehindert durchlaufen kann.","Läufer schlägt auf g4 – leitet die gewinnbringende Bauernumwandlung ein."],"en":["A sacrifice clears the path for the passed pawn to queen.","The bishop gives itself up so the pawn can run home unopposed.","Bishop takes on g4 — starting the winning promotion sequence."],"hr":["Žrtva oslobađa put slobodnom pješaku do promocije.","Lovac se žrtvuje kako bi pješak nesmetano protrčao.","Lovac uzima na g4 — započinje pobjedonosni niz do promocije."]}', HintsVersion=1 WHERE LineId LIKE '%:010.015' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Turm geht ins Opfer, damit der eigene Bauer entscheidend durchbricht.","Der Turm lenkt den weißen Läufer ab und ebnet dem Freibauern den Weg.","Turm nach e6 – beginnt die Kombination, die den Bauern zur Umwandlung trägt."],"en":["The rook is offered so the pawn can break through decisively.","The rook lures the white bishop away to clear the pawn''s road.","Rook to e6 — beginning the combination that carries the pawn to promotion."],"hr":["Top se nudi kako bi pješak odlučujuće probio.","Top odvlači bijelog lovca i otvara put slobodnom pješaku.","Top na e6 — započinje kombinaciju koja pješaka vodi do promocije."]}', HintsVersion=1 WHERE LineId LIKE '%:010.016' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Königszug entzieht dem Gegner das ewige Schach und sichert den Gewinn.","Der König wählt das richtige Feld, sodass die Dame frei wird.","König nach h6 – beginnt die gewinnbringende Verteidigung gegen das Dauerschach."],"en":["A quiet king move denies the perpetual check and wins.","The king picks the correct square so the queen is freed to decide.","King to h6 — starting the winning line that escapes the perpetual."],"hr":["Tihi kraljev potez oduzima vječiti šah i donosi pobjedu.","Kralj bira ispravno polje da oslobodi damu za odluku.","Kralj na h6 — započinje pobjednički niz koji izbjegava vječiti šah."]}', HintsVersion=1 WHERE LineId LIKE '%:010.017' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz ist in Not und muss mit einem Trick ins Patt-Remis flüchten.","Der vorrückende Bauer wird zum Köder für eine Pattstellung.","Bauer nach d2 – leitet die Rettungskombination zum Patt ein."],"en":["Black is in trouble and must escape into a stalemate draw.","The advancing pawn becomes the bait for a stalemate.","Pawn to d2 — beginning the saving sequence toward stalemate."],"hr":["Crni je u nevolji i mora pobjeći u remi patom.","Pješak koji napreduje postaje mamac za pat.","Pješak na d2 — započinje spasonosni niz prema patu."]}', HintsVersion=1 WHERE LineId LIKE '%:010.018' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer reißt die Königsstellung auf und bringt eine entscheidende Doppeldrohung.","Der Turm opfert sich, danach krönt ein Bauer die Aktion.","Turm schlägt auf h8 – startet die siegreiche Kombination mit Doppeldrohung."],"en":["A rook sacrifice rips open the king and creates a decisive double threat.","The rook gives itself up, then a pawn crowns the action.","Rook takes on h8 — launching the winning combination with a double threat."],"hr":["Žrtva topa otvara kralja i stvara odlučujuću dvostruku prijetnju.","Top se žrtvuje, a potom pješak kruni akciju.","Top uzima na h8 — pokreće pobjedonosnu kombinaciju s dvostrukom prijetnjom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.019' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein direkter Plan fängt eine gegnerische Figur und entscheidet schnell.","Der Turm und der König arbeiten zusammen, um den Läufer einzuschnüren.","Turm nach b3 – beginnt die schnelle Gewinnführung, die den Läufer fängt."],"en":["A direct plan traps an enemy piece and decides quickly.","The rook and king cooperate to box in the bishop.","Rook to b3 — beginning the fast winning method that snares the bishop."],"hr":["Izravan plan hvata protivničku figuru i brzo odlučuje.","Top i kralj surađuju da zatvore lovca.","Top na b3 — započinje brzu pobjedonosnu metodu koja hvata lovca."]}', HintsVersion=1 WHERE LineId LIKE '%:010.020' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein subtiler Königszug stellt den Gegner in Zugzwang und gewinnt das Bauernendspiel.","Der König nimmt die Schlüsselopposition ein und zwingt zum Bauernverlust.","König nach e2 – beginnt die Gewinnführung, die den Gegner in Zugzwang treibt."],"en":["A subtle king move puts the opponent in zugzwang and wins the pawn ending.","The king takes the key opposition to force a fatal pawn loss.","King to e2 — beginning the winning method that lands the opponent in zugzwang."],"hr":["Suptilan kraljev potez stavlja protivnika u cugcvang i dobiva pješački završetak.","Kralj zauzima ključnu opoziciju i prisiljava na gubitak pješaka.","Kralj na e2 — započinje pobjedonosnu metodu koja protivnika dovodi u cugcvang."]}', HintsVersion=1 WHERE LineId LIKE '%:010.021' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein direkter Königsmarsch ebnet dem Freibauern den entscheidenden Weg.","Der König drängt vor, damit der Damenflügelbauer unaufhaltsam wird.","Bauer nach g5 – beginnt die schnellste Gewinnführung über den Freibauern."],"en":["A direct king march paves the way for the passed pawn to decide.","The king pushes forward so the queenside pawn becomes unstoppable.","Pawn to g5 — beginning the fastest winning method via the passed pawn."],"hr":["Izravan kraljev marš krči put slobodnom pješaku do odluke.","Kralj se gura naprijed kako bi pješak na daminom krilu postao nezaustavljiv.","Pješak na g5 — započinje najbržu pobjedonosnu metodu preko slobodnog pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:010.022' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge von Schlägen gewinnt Material durch eine versteckte Gabel.","Turm und Läufer wirken zusammen, bis der Läufer am Ende zuschnappt.","Turm schlägt auf b7 – beginnt die Kombination, die Material gewinnt."],"en":["A series of captures wins material through a hidden fork.","Rook and bishop combine until the bishop snaps off the loot at the end.","Rook takes on b7 — beginning the combination that wins material."],"hr":["Niz uzimanja osvaja materijal skrivenom viljuškom.","Top i lovac surađuju dok lovac na kraju ne pokupi plijen.","Top uzima na b7 — započinje kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.023' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Damen jagen den entblößten weißen König in ein erzwungenes Matt.","Die schwarze Dame treibt den König unbarmherzig durchs Brett.","Dame nach d3 – beginnt die erzwungene Mattjagd."],"en":["The queens chase the exposed white king into a forced mate.","The black queen drives the king relentlessly across the board.","Queen to d3 — beginning the forced mating hunt."],"hr":["Dame tjeraju izloženog bijelog kralja u prisilni mat.","Crna dama nemilosrdno goni kralja preko ploče.","Dama na d3 — započinje prisilni lov na mat."]}', HintsVersion=1 WHERE LineId LIKE '%:010.024' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt zu verlieren, kann Weiß sich mit Schachgeboten ins Remis retten.","Die Dame jagt den gegnerischen König und erzwingt das Dauerschach.","Dame schlägt auf f5 – beginnt die Schachserie, die das Remis sichert."],"en":["Instead of losing, White can rescue a draw with checks.","The queen chases the enemy king and forces a perpetual.","Queen takes on f5 — beginning the checking series that secures the draw."],"hr":["Umjesto da izgubi, bijeli se može spasiti remijem nizom šahova.","Dama goni protivničkog kralja i prisiljava vječiti šah.","Dama uzima na f5 — započinje niz šahova koji osigurava remi."]}', HintsVersion=1 WHERE LineId LIKE '%:010.025' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Königszug bereitet eine Drohung vor, die Material einbringt.","Der König nähert sich, um den eigenen Turm aktiv ins Spiel zu bringen.","König nach d1 – beginnt die Gewinnführung, die den Materialvorteil ausbaut."],"en":["A quiet king move sets up a threat that wins material.","The king steps closer to bring its own rook into decisive action.","King to d1 — beginning the winning method that extends the material edge."],"hr":["Tihi kraljev potez priprema prijetnju koja osvaja materijal.","Kralj se približava da svojeg topa uvede u odlučujuću akciju.","Kralj na d1 — započinje pobjedonosnu metodu koja proširuje materijalnu prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:010.026' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferschlag macht den Freibauern unaufhaltsam und entscheidet schnell.","Der Läufer beseitigt den Verteidiger, dann läuft der Randbauer durch.","Läufer schlägt auf c6 – beginnt die Gewinnführung über den unaufhaltsamen Bauern."],"en":["A bishop capture makes the passed pawn unstoppable and decides quickly.","The bishop removes the defender, then the edge pawn runs through.","Bishop takes on c6 — beginning the winning method via the unstoppable pawn."],"hr":["Uzimanje lovcem čini slobodnog pješaka nezaustavljivim i brzo odlučuje.","Lovac uklanja branitelja, a potom rubni pješak protrči.","Lovac uzima na c6 — započinje pobjedonosnu metodu preko nezaustavljivog pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:010.027' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer leitet ein gewinnendes Bauernendspiel mit Freibauern ein.","Der Turm opfert sich auf der achten Reihe, dann entscheidet die Dame.","Turm schlägt auf e8 – beginnt die Kombination ins gewonnene Endspiel."],"en":["A rook sacrifice ushers in a winning pawn ending with a passer.","The rook gives itself up on the back rank, then the queen decides.","Rook takes on e8 — beginning the combination into the won ending."],"hr":["Žrtva topa uvodi dobiveni pješački završetak sa slobodnim pješakom.","Top se žrtvuje na posljednjem redu, a potom dama odlučuje.","Top uzima na e8 — započinje kombinaciju u dobiveni završetak."]}', HintsVersion=1 WHERE LineId LIKE '%:010.028' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz steht verloren und rettet sich mit einem überraschenden Figurenopfer ins Remis.","Der Läufer wirft sich opfernd dem Bauern entgegen, um dessen Umwandlung zu sabotieren.","Läufer schlägt auf b6 – beginnt die Rettungskombination zum Remis."],"en":["Black is lost but saves a draw with a startling piece sacrifice.","The bishop throws itself at the pawn to wreck its promotion.","Bishop takes on b6 — beginning the saving sequence to a draw."],"hr":["Crni stoji izgubljeno, ali se spašava remijem iznenađujućom žrtvom figure.","Lovac se baca na pješaka da osujeti njegovu promociju.","Lovac uzima na b6 — započinje spasonosni niz do remija."]}', HintsVersion=1 WHERE LineId LIKE '%:010.029' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Bauernstoß fängt eine gegnerische Figur und gewinnt Material.","Der Bauer rückt vor und nimmt dem weißen Läufer alle Felder.","Bauer nach c4 – fängt den Läufer und gewinnt Material."],"en":["A quiet pawn push traps an enemy piece and wins material.","The pawn advances and strips the white bishop of every square.","Pawn to c4 — trapping the bishop and winning material."],"hr":["Tihi potez pješakom hvata protivničku figuru i osvaja materijal.","Pješak napreduje i oduzima bijelom lovcu sva polja.","Pješak na c4 — hvata lovca i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.030' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz muss sich präzise ins Remis verteidigen statt auf Gewinn zu spielen.","Der König geht ins Opfer der Läufer, um ein gewonnenes Bauernendspiel zu erreichen.","König schlägt auf d5 – beginnt die Rettung ins remise Bauernendspiel."],"en":["Black must defend precisely into a draw rather than play for a win.","The king trades itself for the bishop to reach a drawn pawn ending.","King takes on d5 — beginning the rescue into the drawn pawn ending."],"hr":["Crni se mora precizno braniti u remi umjesto da igra na pobjedu.","Kralj uzima lovca da dođe do remi pješačkog završetka.","Kralj uzima na d5 — započinje spas u remi pješački završetak."]}', HintsVersion=1 WHERE LineId LIKE '%:010.031' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt das Tempo zu verlieren, gewinnt ein feiner Königszug das Bauernendspiel.","Der König wählt die richtige Route, um die Bauernschwächen auszunutzen.","König nach g5 – beginnt die Gewinnführung im Bauernendspiel."],"en":["Rather than lose the tempo, a fine king move wins the pawn ending.","The king takes the correct route to exploit the pawn weaknesses.","King to g5 — beginning the winning method in the pawn ending."],"hr":["Umjesto da izgubi tempo, fini kraljev potez dobiva pješački završetak.","Kralj bira ispravan put da iskoristi slabosti u pješacima.","Kralj na g5 — započinje pobjedonosnu metodu u pješačkom završetku."]}', HintsVersion=1 WHERE LineId LIKE '%:010.032' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist entblößt und wird in ein erzwungenes Matt getrieben.","Die Dame dringt mit Unterstützung des Läufers in die Königsstellung ein.","Dame nach g5 – beginnt die erzwungene Mattführung."],"en":["The white king is bare and gets driven into a forced mate.","The queen breaks in with the bishop backing her up.","Queen to g5 — beginning the forced mating line."],"hr":["Bijeli kralj je ogoljen i biva otjeran u prisilni mat.","Dama prodire uz potporu lovca.","Dama na g5 — započinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.033' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz kann sich trotz richtigem Läufer mit einem Positionsremis retten.","Der König eilt zur rettenden Ecke, um eine Festung aufzubauen.","König nach d5 – beginnt den Marsch zum rettenden Positionsremis."],"en":["Despite the right-colored bishop, Black can save a positional draw.","The king hurries to the saving corner to build a fortress.","King to d5 — beginning the march toward the saving positional draw."],"hr":["Unatoč pravom lovcu, crni se može spasiti pozicijskim remijem.","Kralj žuri u spasonosni kut da izgradi tvrđavu.","Kralj na d5 — započinje marš prema spasonosnom pozicijskom remiju."]}', HintsVersion=1 WHERE LineId LIKE '%:010.034' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer reißt die Stellung auf und führt zum erzwungenen Matt.","Der Turm geht ins Opfer, dann übernehmen die Freibauern die Mattführung.","Turm schlägt auf h6 – beginnt die erzwungene Mattkombination."],"en":["A rook sacrifice tears things open and leads to a forced mate.","The rook gives itself up, then the passed pawns carry the mate home.","Rook takes on h6 — beginning the forced mating combination."],"hr":["Žrtva topa otvara poziciju i vodi u prisilni mat.","Top se žrtvuje, a zatim slobodni pješaci dovršavaju mat.","Top uzima na h6 — započinje prisilnu matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:010.035' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz steht schlechter und muss das Bauernendspiel mit einem Trick remis halten.","Der König weicht so aus, dass der Gegner in Patt- oder Zugzwangprobleme gerät.","König nach h8 – beginnt die Rettungsführung zum Remis."],"en":["Black is worse and must hold the pawn ending to a draw by a trick.","The king sidesteps so the opponent runs into stalemate trouble.","King to h8 — beginning the saving method to a draw."],"hr":["Crni stoji lošije i mora trikom zadržati pješački završetak remijem.","Kralj se izmiče tako da protivnik upadne u pat-probleme.","Kralj na h8 — započinje spasonosnu metodu do remija."]}', HintsVersion=1 WHERE LineId LIKE '%:010.036' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit dem Gegnerkönig am Rand lässt sich Material durch eine Mattdrohung gewinnen.","Der eigene König rückt vor und der Springer schnappt am Ende den Turm.","König nach f3 – beginnt die Gewinnkombination mit Mattdrohung."],"en":["With the enemy king on the edge, material falls to a mate threat.","The own king advances and the knight grabs the rook at the finish.","King to f3 — beginning the winning combination built on a mate threat."],"hr":["Dok je protivnički kralj na rubu, materijal pada zbog prijetnje matom.","Vlastiti kralj napreduje, a skakač na kraju pokupi topa.","Kralj na f3 — započinje pobjedonosnu kombinaciju temeljenu na prijetnji matom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.037' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einfacher Bauernstoß gewinnt das Tempo und damit das Endspiel.","Der Randbauer rückt vor und entscheidet das Wettrennen.","Bauer nach h4 – beginnt die Gewinnführung im Bauernendspiel."],"en":["A simple pawn push gains the tempo and with it the endgame.","The edge pawn advances and decides the race.","Pawn to h4 — beginning the winning method in the pawn ending."],"hr":["Jednostavan potez pješakom dobiva tempo, a s njim i završnicu.","Rubni pješak napreduje i odlučuje utrku.","Pješak na h4 — započinje pobjedonosnu metodu u pješačkom završetku."]}', HintsVersion=1 WHERE LineId LIKE '%:010.038' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer gewinnt einen Bauern durch eine versteckte Fesselung.","Der Turm opfert sich, dann gewinnt der eigene Bauer die Figur zurück.","Turm schlägt auf h4 – beginnt die Kombination, die einen Bauern gewinnt."],"en":["A rook sacrifice wins a pawn through a hidden pin.","The rook gives itself up, then the pawn wins the piece back.","Rook takes on h4 — beginning the combination that wins a pawn."],"hr":["Žrtva topa osvaja pješaka skrivenim vezanjem.","Top se žrtvuje, a zatim vlastiti pješak vraća figuru.","Top uzima na h4 — započinje kombinaciju koja osvaja pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:010.039' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernstoß öffnet die Linien und gewinnt mit einem Turmopfer Material.","Der Turm wird geopfert, danach erobert der Läufer entscheidend.","Bauer nach f4 – beginnt die siegbringende Kombination."],"en":["A pawn break opens lines and wins material with a rook sacrifice.","The rook is offered, then the bishop captures decisively.","Pawn to f4 — beginning the winning combination."],"hr":["Prodor pješaka otvara linije i osvaja materijal žrtvom topa.","Top se nudi, a potom lovac odlučujuće uzima.","Pješak na f4 — započinje pobjedonosnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:010.040' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer ermöglicht die Umwandlung und gewinnt eine neue Dame.","Der Turm opfert sich, damit der Freibauer zur Dame durchläuft.","Turm nach c1 – beginnt die Kombination, die zur Umwandlung führt."],"en":["A rook sacrifice clears the way to promote and win a new queen.","The rook gives itself up so the passed pawn queens.","Rook to c1 — beginning the combination that leads to promotion."],"hr":["Žrtva topa omogućuje promociju i osvaja novu damu.","Top se žrtvuje kako bi slobodni pješak prošao u damu.","Top na c1 — započinje kombinaciju koja vodi do promocije."]}', HintsVersion=1 WHERE LineId LIKE '%:010.041' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Tausch öffnet die Linie für deine schweren Figuren und gewinnt Material.","Der freche Bauer lockt, doch dann schlägt der Turm in die nun offene Reihe ein.","Bauer nach f4 – beginnt die materialgewinnende Kombination."],"en":["A pawn break opens lines for your heavy pieces and wins material.","The pawn lures away, then the rook crashes into the now-open rank.","Pawn to f4 — starting the material-winning combination."],"hr":["Probojem pješaka otvaraš linije svojim teškim figurama i osvajaš materijal.","Pješak mami, a zatim top udara u sada otvoreni red.","Pješak na f4 — početak kombinacije koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.042' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Reihe von Drohungen überfordert den Verteidiger und gewinnt Material.","Der Turm dringt in die gegnerische Stellung ein und sammelt Beute.","Turm nach e2 – startet die entscheidende Eroberung."],"en":["A cascade of threats overwhelms the defence and wins material.","The rook invades the enemy position and starts collecting.","Rook to e2 — beginning the decisive invasion."],"hr":["Niz prijetnji nadvladava obranu i osvaja materijal.","Top prodire u protivničku poziciju i počinje skupljati plijen.","Top na e2 — početak odlučujućeg prodora."]}', HintsVersion=1 WHERE LineId LIKE '%:010.043' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein kleines Opfer öffnet die Linie für einen vernichtenden Eindringling.","Der Läufer wird hergegeben, damit der Turm matt droht.","Läufer schlägt auf f5 – leitet die siegreiche Kombination ein."],"en":["A small sacrifice opens the line for a deadly invader.","The bishop is given up so the rook can deliver threats along the file.","Bishop takes on f5 — launching the winning combination."],"hr":["Mala žrtva otvara liniju smrtonosnom uljezu.","Lovac se predaje kako bi top mogao prijetiti po liniji.","Lovac uzima na f5 — pokreće pobjedničku kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:010.044' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Ablenkung des Bauern gewinnt eine Figur.","Der Bauer lockt einen Verteidiger weg, dann entscheidet der Läufer.","Bauer nach e3 – beginnt die figurengewinnende Wendung."],"en":["A pawn deflection wins a piece.","The pawn lures a defender away, then the bishop settles it.","Pawn to e3 — starting the piece-winning sequence."],"hr":["Odvlačenjem pješaka osvajaš figuru.","Pješak odvlači branitelja, a zatim lovac odlučuje.","Pješak na e3 — početak niza koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:010.045' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Zug fesselt eine Figur und gewinnt sie.","Der Turm tritt der Springer-Linie gegenüber und nagelt ihn fest.","Turm nach d6 – gewinnt eine Figur."],"en":["A single move pins a piece and wins it.","The rook opposes the knight and ties it down for good.","Rook to d6 — winning a piece."],"hr":["Jedan potez vezuje figuru i osvaja je.","Top se suprotstavlja skakaču i prikiva ga.","Top na d6 — osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:010.046' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Freibauer rennt durch und entscheidet die Partie.","Der König geht aus dem Weg, damit der Bauer zur Dame läuft.","König nach a6 – leitet die gewinnende Umwandlung ein."],"en":["The passed pawn runs through and decides the game.","The king steps aside so the pawn can queen.","King to a6 — preparing the winning promotion."],"hr":["Slobodni pješak prolazi i odlučuje partiju.","Kralj se sklanja kako bi pješak došao do dame.","Kralj na a6 — priprema pobjedničko promaknuće."]}', HintsVersion=1 WHERE LineId LIKE '%:010.047' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein aktiver Turm dringt ein und gewinnt entscheidend.","Der Turm besetzt die siebte Reihe und der Springer hilft mit.","Turm nach d7 – beginnt die siegreiche Aktion."],"en":["An active rook invades and wins decisively.","The rook seizes the seventh rank with the knight in support.","Rook to d7 — starting the winning operation."],"hr":["Aktivni top prodire i odlučno pobjeđuje.","Top zauzima sedmi red uz pomoć skakača.","Top na d7 — pokreće pobjedničku akciju."]}', HintsVersion=1 WHERE LineId LIKE '%:010.048' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernzug erzwingt eine Wendung, die mit Matt endet.","Der eigene Turm liefert nach kurzer Vorbereitung das Matt.","Bauer nach c6 – leitet die erzwungene Mattfolge ein."],"en":["A pawn move forces a sequence that ends in mate.","After a short prelude your own rook delivers the mate.","Pawn to c6 — beginning the forced mating sequence."],"hr":["Potez pješaka forsira niz koji završava matom.","Nakon kratke pripreme tvoj top daje mat.","Pješak na c6 — početak prisilnog niza do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.049' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springergabel-Trick gewinnt Material.","Der Springer springt mit Tempo und greift gleich mehrere Ziele an.","Springer nach d3 – gewinnt Material."],"en":["A knight fork wins material.","The knight leaps in with tempo and hits several targets at once.","Knight to d3 — winning material."],"hr":["Skakačeva vilica osvaja materijal.","Skakač uskače s tempom i napada više meta odjednom.","Skakač na d3 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.050' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernstoß gewinnt durch eine versteckte Drohung Material.","Der Bauer öffnet die Lage und stellt den Turm vor Probleme.","Bauer nach g4 – gewinnt Material."],"en":["A pawn thrust wins material through a hidden threat.","The pawn opens things up and traps the rook''s escape.","Pawn to g4 — winning material."],"hr":["Udar pješaka osvaja materijal skrivenom prijetnjom.","Pješak otvara poziciju i stvara probleme topu.","Pješak na g4 — osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.051' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller König-Zug bereitet eine vernichtende Drohung vor.","Der König weicht aus, damit der Läufer eine Schlüsseldrohung aufstellt.","König nach f4 – beginnt die figurengewinnende Folge."],"en":["A quiet king move prepares a crushing threat.","The king steps up so the bishop can set up the key threat.","King to f4 — starting the piece-winning line."],"hr":["Tihi potez kralja priprema razornu prijetnju.","Kralj se pomiče kako bi lovac postavio ključnu prijetnju.","Kralj na f4 — početak niza koji osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:010.052' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer räumt den Weg für den durchbrechenden Freibauern.","Der Springer wird hingegeben, dann läuft der Bauer zur Dame.","Springer schlägt auf b7 – leitet die siegreiche Wendung ein."],"en":["A sacrifice clears the path for the breakthrough passed pawn.","The knight is given up so the pawn can march to queen.","Knight takes on b7 — launching the winning sequence."],"hr":["Žrtva čisti put probojnom slobodnom pješaku.","Skakač se predaje kako bi pješak krenuo prema dami.","Skakač uzima na b7 — pokreće pobjednički niz."]}', HintsVersion=1 WHERE LineId LIKE '%:010.053' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein durchgebrochener Freibauer entscheidet die Partie.","Der Bauer rückt vor und ist nicht mehr aufzuhalten.","Bauer nach d3 – der unaufhaltsame Freibauer beginnt seinen Lauf."],"en":["A breakthrough passed pawn decides the game.","The pawn pushes forward and can no longer be stopped.","Pawn to d3 — the unstoppable passer begins its run."],"hr":["Probojni slobodni pješak odlučuje partiju.","Pješak napreduje i više se ne može zaustaviti.","Pješak na d3 — nezaustavljivi pješak kreće."]}', HintsVersion=1 WHERE LineId LIKE '%:010.054' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß bahnt dem Bauern den Weg zur Dame und gewinnt.","Der Turm zieht weiter, der Freibauer ist nahe der Umwandlung.","Turm nach d8 – beginnt die siegreiche Folge."],"en":["A push clears the pawn''s road to promotion and wins.","The rook advances while the passer nears queening.","Rook to d8 — starting the winning sequence."],"hr":["Potez raščišćava pješaku put do dame i pobjeđuje.","Top napreduje dok je slobodnjak blizu promaknuća.","Top na d8 — početak pobjedničkog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.055' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsopfer ebnet dem Freibauern den Weg.","Der Turm opfert sich, damit der Bauer zur Dame durchläuft.","Turm nach a4 – leitet die gewinnende Kombination ein."],"en":["A deflection sacrifice paves the way for the passed pawn.","The rook offers itself so the pawn can run through to queen.","Rook to a4 — launching the winning combination."],"hr":["Žrtva odvlačenja krči put slobodnom pješaku.","Top se žrtvuje kako bi pješak prošao do dame.","Top na a4 — pokreće pobjedničku kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:010.056' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Springermanöver und Freibauer gewinnen die Partie.","Der Springer springt herum und sichert den Vormarsch des Bauern.","Springer schlägt auf c6 – beginnt die siegreiche Folge."],"en":["A knight manoeuvre plus the passed pawn wins the game.","The knight hops around and clears the way for the pawn.","Knight takes on c6 — starting the winning sequence."],"hr":["Manevar skakača i slobodni pješak osvajaju partiju.","Skakač skakuće i osigurava napredovanje pješaka.","Skakač uzima na c6 — početak pobjedničkog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.057' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernopfer gewinnt eine Figur durch eine Springergabel.","Der Bauer lockt, dann gabelt der Springer König und Turm.","Bauer nach g4 – leitet die figurengewinnende Gabel ein."],"en":["A pawn sacrifice wins a piece via a knight fork.","The pawn lures in, then the knight forks king and rook.","Pawn to g4 — setting up the piece-winning fork."],"hr":["Žrtva pješaka osvaja figuru skakačevom vilicom.","Pješak mami, a zatim skakač napada kralja i topa.","Pješak na g4 — priprema vilicu koja osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:010.058' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer baut ein unentrinnbares Mattnetz.","Der Springer wird hingegeben, dann nähern sich Läufer dem König.","Springer schlägt auf e5 – beginnt die entscheidende Folge."],"en":["A knight sacrifice weaves an inescapable mating net.","The knight is given up, then the bishops close in on the king.","Knight takes on e5 — starting the decisive sequence."],"hr":["Žrtva skakača plete neizbježnu matnu mrežu.","Skakač se predaje, a zatim lovci stežu kralja.","Skakač uzima na e5 — početak odlučujućeg niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.059' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und musst dich mit einem Trick ins Remis retten.","Der Turm opfert sich, um ein Patt zu erzwingen.","Turm nach c4 – beginnt die rettende Patt-Kombination."],"en":["You are worse and must save the draw with a clever trick.","The rook sacrifices itself to force stalemate.","Rook to c4 — beginning the saving stalemate combination."],"hr":["Lošiji si i moraš spasiti remi domišljatim trikom.","Top se žrtvuje kako bi forsirao pat.","Top na c4 — početak spasonosne patne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:010.060' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Bauernzug schafft eine unparierbare Mattdrohung.","Der Bauer öffnet dem König Luft, sodass Matt unvermeidlich wird.","Bauer nach b5 – stellt die entscheidende Mattdrohung auf."],"en":["A quiet pawn move sets up an unstoppable mate threat.","The pawn gives the king air so the mate cannot be parried.","Pawn to b5 — setting up the decisive mating threat."],"hr":["Tihi potez pješaka stvara neodbranjivu prijetnju matom.","Pješak daje kralju zraka pa se mat ne može spriječiti.","Pješak na b5 — postavlja odlučujuću prijetnju matom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.061' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer treibt den König in ein Mattnetz.","Der Turm wird hingegeben, dann fängt der Läufer den König.","Turm schlägt auf f3 – leitet das entscheidende Mattnetz ein."],"en":["A rook sacrifice drives the king into a mating net.","The rook is given up, then the bishop snares the king.","Rook takes on f3 — launching the decisive mating net."],"hr":["Žrtva topa tjera kralja u matnu mrežu.","Top se predaje, a zatim lovac hvata kralja.","Top uzima na f3 — pokreće odlučujuću matnu mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:010.062' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein König-Zug zwingt den Läufer zu einer Festlegung und gewinnt.","Der König nähert sich, dann läuft der Randbauer zur Dame.","König nach e5 – beginnt die gewinnende Folge."],"en":["A king move forces the bishop to commit and wins.","The king closes in, then the rook''s pawn marches to queen.","King to e5 — starting the winning sequence."],"hr":["Potez kralja prisiljava lovca na odluku i pobjeđuje.","Kralj se približava, a zatim rubni pješak ide do dame.","Kralj na e5 — početak pobjedničkog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.063' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Springerzug stellt eine Doppeldrohung auf und gewinnt Material.","Der Springer springt vor und droht gleich an zwei Stellen.","Springer nach f5 – gewinnt Material durch die Doppeldrohung."],"en":["A single knight move sets up a double threat and wins material.","The knight jumps in and threatens in two places at once.","Knight to f5 — winning material via the double threat."],"hr":["Jedan potez skakača stvara dvostruku prijetnju i osvaja materijal.","Skakač uskače i prijeti na dva mjesta odjednom.","Skakač na f5 — osvaja materijal dvostrukom prijetnjom."]}', HintsVersion=1 WHERE LineId LIKE '%:010.064' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernopfer lässt die verbundenen Freibauern unaufhaltsam werden.","Der Turm wird hingegeben, dann rollen die Bauern durch.","Turm schlägt auf c5 – leitet den siegreichen Bauernsturm ein."],"en":["A pawn sacrifice makes the connected passers unstoppable.","The rook is given up, then the pawns roll through.","Rook takes on c5 — launching the winning pawn avalanche."],"hr":["Žrtva pješaka čini povezane slobodnjake nezaustavljivima.","Top se predaje, a zatim pješaci prolaze.","Top uzima na c5 — pokreće pobjedničku lavinu pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:010.065' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein langes Damenmanöver gewinnt durch ständige Drohungen.","Die Dame umkreist den König und holt sich schließlich Material.","Dame nach a1 – beginnt das gewinnende Damenmanöver."],"en":["A long queen manoeuvre wins through relentless threats.","The queen circles the king and eventually grabs material.","Queen to a1 — beginning the winning queen manoeuvre."],"hr":["Dugi manevar dame pobjeđuje neprekidnim prijetnjama.","Dama kruži oko kralja i naposljetku uzima materijal.","Dama na a1 — početak pobjedničkog manevra dame."]}', HintsVersion=1 WHERE LineId LIKE '%:010.066' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß gewinnt eine Figur.","Der Bauer rückt vor und greift eine schlecht stehende Figur an.","Bauer nach e4 – gewinnt eine Figur."],"en":["A pawn advance wins a piece.","The pawn pushes up and attacks an awkwardly placed piece.","Pawn to e4 — winning a piece."],"hr":["Napredovanje pješaka osvaja figuru.","Pješak napreduje i napada loše postavljenu figuru.","Pješak na e4 — osvaja figuru."]}', HintsVersion=1 WHERE LineId LIKE '%:010.067' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Aktive Turmspiele verwandeln den Vorteil in einen Gewinn.","Der Turm wird beweglich und der Freibauer entscheidet.","Turm nach h6 – beginnt die gewinnende Folge."],"en":["Active rook play converts the edge into a win.","The rook gets mobile and the passed pawn decides matters.","Rook to h6 — starting the winning sequence."],"hr":["Aktivna igra topom pretvara prednost u pobjedu.","Top postaje pokretljiv i slobodni pješak odlučuje.","Top na h6 — početak pobjedničkog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:010.068' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Folge endet im Matt.","König und Läufer arbeiten zusammen und treiben den Gegner ins Matt.","König nach g8 – beginnt die erzwungene Mattfolge."],"en":["A forced sequence ends in mate.","The king and bishop work together to drive the opponent to mate.","King to g8 — beginning the forced mating sequence."],"hr":["Prisilni niz završava matom.","Kralj i lovac zajedno tjeraju protivnika u mat.","Kralj na g8 — početak prisilnog niza do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.069' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König sitzt in einem Mattnetz, das du zuziehst.","Der König rückt vor, dann schließen die Figuren das Netz.","König nach g3 – leitet das entscheidende Mattnetz ein."],"en":["The enemy king is caught in a mating net you tighten.","The king steps up, then the pieces close the net.","King to g3 — launching the decisive mating net."],"hr":["Protivnički kralj je u matnoj mreži koju stežeš.","Kralj se pomiče, a zatim figure zatvaraju mrežu.","Kralj na g3 — pokreće odlučujuću matnu mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:010.070' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer leitet ein Bauernrennen ein, das mit Matt endet.","Der Springer wird hingegeben, dann läuft dein Bauer zur Dame und setzt matt.","Springer nach b1 – beginnt die erzwungene Mattfolge."],"en":["A knight sacrifice starts a pawn race that ends in mate.","The knight is given up, then your pawn queens and forces mate.","Knight to b1 — beginning the forced mating sequence."],"hr":["Žrtva skakača pokreće utrku pješaka koja završava matom.","Skakač se predaje, a zatim tvoj pješak ide do dame i forsira mat.","Skakač na b1 — početak prisilnog niza do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:010.071' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein gut gedeckter Freibauer wird für den schwarzen Springer zu viel.","Treibe den Bauern am Damenflügel voran, der König unterstützt ihn.","Bauer nach b5 – startet den entscheidenden Freibauer-Vormarsch."],"en":["A protected passed pawn will prove too much for the lone knight.","Push the queenside pawn forward, with the king lending support.","Pawn to b5 — launching the decisive passed-pawn advance."],"hr":["Zaštićeni slobodni pješak bit će previše za usamljenog skakača.","Gurni pješaka na daminom krilu naprijed, kralj ga podržava.","Pješak na b5 — pokreće odlučujući prodor slobodnog pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:010.072' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Erzwinge den Turmtausch in ein gewonnenes Bauernendspiel.","Der Turm bietet sich zum Abtausch an, der König entscheidet danach.","Turm nach f6 – erzwingt den Tausch in ein gewonnenes Bauernendspiel."],"en":["Force the rook trade into a winning king-and-pawn ending.","The rook offers itself for exchange, then the king decides.","Rook to f6 — forcing the swap into a won pawn endgame."],"hr":["Iznudi zamjenu topova u dobiveni pješački završetak.","Top se nudi na zamjenu, a kralj zatim odlučuje.","Top na f6 — prisiljava zamjenu u dobivenu pješačku završnicu."]}', HintsVersion=1 WHERE LineId LIKE '%:010.073' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schaffe einen Freibauern am Flügel, der durchläuft.","Schiebe den Randbauern vor, Läufer und Turm halten den Druck.","Bauer nach b5 – beginnt den siegbringenden Freibauer-Vormarsch."],"en":["Create a flank passed pawn that will run through to promotion.","Advance the wing pawn while bishop and rook keep the pressure.","Pawn to b5 — beginning the winning passed-pawn march."],"hr":["Stvori slobodnog pješaka na krilu koji prolazi do promocije.","Pomakni rubnog pješaka, lovac i top drže pritisak.","Pješak na b5 — započinje pobjednički prodor slobodnog pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:010.074' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorgeschobener Freibauer entscheidet das Endspiel.","Schiebe den zentralen Bauern vor und lass den König mitlaufen.","Bauer nach e5 – treibt den entscheidenden Freibauern voran."],"en":["An advancing passed pawn decides the endgame.","Push the central pawn forward and march the king up with it.","Pawn to e5 — driving the decisive passed pawn ahead."],"hr":["Napredujući slobodni pješak odlučuje završnicu.","Gurni središnjeg pješaka naprijed i povedi kralja s njim.","Pješak na e5 — tjera odlučujućeg slobodnog pješaka naprijed."]}', HintsVersion=1 WHERE LineId LIKE '%:010.075' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Opfere den Läufer, um in ein gewonnenes Bauernendspiel zu gelangen.","Der Läufer geht freiwillig, danach gewinnt der Bauernkampf.","Läufer schlägt auf e2 – führt ins gewonnene Bauernendspiel."],"en":["Sacrifice the bishop to reach a winning king-and-pawn ending.","Give up the bishop; the pure pawn race then wins.","Bishop takes on e2 — entering the won pawn endgame."],"hr":["Žrtvuj lovca da dođeš do dobivenog pješačkog završetka.","Daj lovca, čista pješačka utrka tada pobjeđuje.","Lovac uzima na e2 — ulazak u dobivenu pješačku završnicu."]}', HintsVersion=1 WHERE LineId LIKE '%:010.076' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernabtausch öffnet den Weg zum gewonnenen Endspiel.","Tausche im Zentrum, dann läuft dein König zum Sieg.","Turm nach e5 – leitet das gewonnene Bauernendspiel ein."],"en":["A pawn exchange opens the road to a winning endgame.","Trade in the center, then your king marches to victory.","Rook to e5 — initiating the won king-and-pawn ending."],"hr":["Zamjena pješaka otvara put do dobivene završnice.","Zamijeni u centru, zatim kralj korača prema pobjedi.","Top na e5 — pokreće dobiveni pješački završetak."]}', HintsVersion=1 WHERE LineId LIKE '%:010.077' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schaffe zwei entfernte Freibauern, die das Endspiel gewinnen.","Tausche im Zentrum, damit deine Außenbauern frei werden.","Bauer schlägt auf f4 – schafft die siegreichen entfernten Freibauern."],"en":["Create two distant passed pawns that win the endgame.","Trade in the center so your outside pawns break free.","Pawn takes on f4 — creating the winning distant passed pawns."],"hr":["Stvori dva udaljena slobodna pješaka koji dobivaju završnicu.","Zamijeni u centru kako bi se rubni pješaci oslobodili.","Pješak uzima na f4 — stvara pobjedničke udaljene slobodne pješake."]}', HintsVersion=1 WHERE LineId LIKE '%:010.078' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt für den Anziehenden.","Bringe die Dame ins Spiel und nutze die offene Königsstellung.","Dame nach f3 – beginnt die erzwungene Mattkombination."],"en":["A forced mate is here for the side to move.","Bring the queen into play and exploit the exposed king.","Queen to f3 — beginning the forced mating sequence."],"hr":["Ovdje postoji prisilni mat za stranu na potezu.","Uvedi damu u igru i iskoristi izloženog kralja.","Dama na f3 — započinje prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:010.079' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein kurzer forcierter Schlag führt zum Matt.","Lenke den Turm ab, dann gibt der Läufer den letzten Schlag.","Turm schlägt auf c6 – startet die erzwungene Mattkombination."],"en":["A short forcing strike leads to mate.","Deflect the rook, then a bishop delivers the finish.","Rook takes on c6 — starting the forced mating combination."],"hr":["Kratak prisilni udarac vodi do mata.","Odvuci topa, zatim lovac zadaje završni udarac.","Top uzima na c6 — pokreće prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:010.080' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Ein Turmstoß lenkt ab, dann schlägt die Dame entscheidend ein.","Turm nach b3 – leitet die materialgewinnende Kombination ein."],"en":["A combination wins material decisively.","A rook thrust deflects, then the queen strikes home.","Rook to b3 — launching the material-winning combination."],"hr":["Kombinacija odlučujuće osvaja materijal.","Prodor topa odvlači, zatim dama presudno udara.","Top na b3 — pokreće kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.081' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Zug sichert den entscheidenden Vorteil.","Der Turm schiebt sich an den feindlichen König und gewinnt.","Turm nach g7 – gewinnt entscheidend Material."],"en":["A single move secures the decisive advantage.","The rook slides up against the enemy king and wins.","Rook to g7 — winning decisive material."],"hr":["Jedan jedini potez osigurava odlučujuću prednost.","Top se primiče neprijateljskom kralju i pobjeđuje.","Top na g7 — osvaja odlučujući materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:010.082' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Springer manövriert sich zum entscheidenden Vorteil.","Lass den Springer einen geschickten Bauernfang einleiten.","Springer nach e3 – startet das gewinnende Springermanöver."],"en":["The knight maneuvers its way to a decisive advantage.","Let the knight begin a clever round-up of the pawn.","Knight to e3 — starting the winning knight maneuver."],"hr":["Skakač se manevrira do odlučujuće prednosti.","Pusti skakača da započne vješto hvatanje pješaka.","Skakač na e3 — pokreće pobjednički manevar skakačem."]}', HintsVersion=1 WHERE LineId LIKE '%:010.083' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination auf der siebten Reihe gewinnt Material.","Dame und Springer arbeiten gegen den gefesselten Läufer zusammen.","Dame schlägt auf d7 – beginnt die materialgewinnende Kombination."],"en":["A combination on the seventh rank wins material.","Queen and knight team up against the pinned bishop.","Queen takes on d7 — launching the material-winning combination."],"hr":["Kombinacija na sedmom redu osvaja materijal.","Dama i skakač surađuju protiv vezanog lovca.","Dama uzima na d7 — pokreće kombinaciju koja osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:011.003' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Nutze die Fesselung auf der siebten Reihe für Materialgewinn.","Der Läufer greift die gefesselte Figur an und entscheidet.","Läufer nach a5 – nutzt die Fesselung und gewinnt Material."],"en":["Exploit the pin on the seventh rank to win material.","The bishop attacks the pinned piece and decides the game.","Bishop to a5 — exploiting the pin to win material."],"hr":["Iskoristi vezivanje na sedmom redu za osvajanje materijala.","Lovac napada vezanu figuru i odlučuje partiju.","Lovac na a5 — iskorištava vezivanje i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:011.004' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein überraschender Schlag entscheidet sofort die Partie.","Der Läufer dringt ein und nutzt die Schwere der hinteren Reihe.","Läufer nach c8 – gewinnt entscheidend."],"en":["A surprising blow decides the game at once.","The bishop intrudes, exploiting the weak back rank.","Bishop to c8 — winning decisively."],"hr":["Iznenađujući udarac odmah odlučuje partiju.","Lovac prodire, iskorištavajući slab zadnji red.","Lovac na c8 — odlučujuća pobjeda."]}', HintsVersion=1 WHERE LineId LIKE '%:011.005' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt für den Anziehenden.","Ein Turmopfer lockt die Dame weg, dann schlägt eine Figur durch.","Turm nach e2 – beginnt die erzwungene Mattkombination."],"en":["A forced mate is here for the side to move.","A rook offer lures the queen away, then a piece breaks through.","Rook to e2 — starting the forced mating combination."],"hr":["Ovdje postoji prisilni mat za stranu na potezu.","Žrtva topa odvlači damu, zatim figura probija.","Top na e2 — pokreće prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:011.006' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein erzwungenes Matt ein.","Sprenge die Mitte auf, dann dringen Turm und Läufer durch.","Dame schlägt auf e5 – beginnt die erzwungene Mattkombination."],"en":["A queen sacrifice ignites a forced mate.","Blow open the center, then rook and bishop break through.","Queen takes on e5 — starting the forced mating sequence."],"hr":["Žrtva dame pokreće prisilni mat.","Razbij centar, zatim top i lovac probijaju.","Dama uzima na e5 — započinje prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:011.007' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination gewinnt entscheidend Material.","Dein Turm dringt ein und schafft zwei Drohungen gleichzeitig.","Turm nach d3 – schafft Doppeldrohungen und gewinnt Material."],"en":["A combination wins material decisively.","Your rook penetrates and sets up two threats at once.","Rook to d3 — creating double threats to win material."],"hr":["Kombinacija odlučujuće osvaja materijal.","Tvoj top prodire i stvara dvije prijetnje odjednom.","Top na d3 — stvara dvostruke prijetnje i osvaja materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:011.008' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsstellung auf und gewinnt.","Schlage in die Bauernkette vor dem König und nutze die offene Linie.","Turm schlägt auf g5 – leitet die gewinnende Kombination ein."],"en":["A sacrifice rips open the king''s shelter and wins.","Strike at the pawn cover, then exploit the opened file.","Rook takes on g5 — launching the winning combination."],"hr":["Žrtva otvara kraljev zaklon i pobjeđuje.","Udari u pješački zaklon, zatim iskoristi otvorenu liniju.","Top uzima na g5 — pokreće pobjedničku kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:011.009' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gegen den König bringt entscheidenden Materialvorteil.","Die Dame dringt an den König vor, der Läufer hilft mit.","Dame schlägt auf g6 – beginnt die gewinnende Kombination."],"en":["A blow against the king brings a decisive material edge.","The queen pushes up to the king with the bishop assisting.","Queen takes on g6 — launching the winning combination."],"hr":["Udarac protiv kralja donosi odlučujuću materijalnu prednost.","Dama prodire prema kralju uz pomoć lovca.","Dama uzima na g6 — pokreće pobjedničku kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:011.010' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt für den Nachziehenden.","Ein Turmopfer und ein Damenschlag bahnen den Weg zum König.","Turm schlägt auf g1 – beginnt die erzwungene Mattkombination."],"en":["A forced mate is here for the side to move.","A rook sacrifice and a queen strike clear the path to the king.","Rook takes on g1 — starting the forced mating combination."],"hr":["Ovdje postoji prisilni mat za stranu na potezu.","Žrtva topa i udarac damom čiste put do kralja.","Top uzima na g1 — pokreće prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:011.011' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Zug erzeugt eine unhaltbare Drohung.","Bringe den Turm auf die offene Linie hinter den Bauern.","Turm nach d1 – droht unwiderstehlich auf der offenen Linie."],"en":["A quiet move creates an unstoppable threat.","Bring the rook onto the open file behind the pawn.","Rook to d1 — building an irresistible threat on the open file."],"hr":["Tihi potez stvara prijetnju koja se ne može zaustaviti.","Dovedi topa na otvorenu liniju iza pješaka.","Top na d1 — gradi neodoljivu prijetnju na otvorenoj liniji."]}', HintsVersion=1 WHERE LineId LIKE '%:011.012' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag öffnet den Weg zum entscheidenden Materialgewinn.","Beseitige den Verteidiger mit dem Springer, dann schlägt die Dame ein.","Springer schlägt auf e5 – leitet die gewinnende Kombination ein."],"en":["A capture opens the path to decisive material gain.","Remove the defender with the knight, then the queen strikes.","Knight takes on e5 — launching the winning combination."],"hr":["Udarac otvara put do odlučujućeg osvajanja materijala.","Ukloni branitelja skakačem, zatim dama udara.","Skakač uzima na e5 — pokreće pobjedničku kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:011.013' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag lenkt den Verteidiger ab und gewinnt entscheidend.","Räume den Springer mit dem Läufer weg, dann entscheidet die Dame.","Läufer schlägt auf e6 – beginnt die gewinnende Kombination."],"en":["A capture deflects the defender and wins decisively.","Clear the knight with the bishop, then the queen decides.","Bishop takes on e6 — launching the winning combination."],"hr":["Udarac odvlači branitelja i odlučujuće pobjeđuje.","Ukloni skakača lovcem, zatim dama odlučuje.","Lovac uzima na e6 — pokreće pobjedničku kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:011.014' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer gegen den König gewinnt entscheidend.","Schlage zuerst neben dem König ein, dann folgen Dame und Turm.","Läufer schlägt auf h2 – beginnt die gewinnende Königsjagd."],"en":["A bishop sacrifice against the king wins decisively.","Strike beside the king first, then the queen and rook follow.","Bishop takes on h2 — beginning the winning attack on the king."],"hr":["Žrtva lovca protiv kralja odlučujuće pobjeđuje.","Udari prvo pokraj kralja, zatim slijede dama i top.","Lovac uzima na h2 — započinje pobjednički napad na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:011.015' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein verblüffendes Damenopfer gewinnt die Qualität.","Lenke den Springer ab, dann fängt der Läufer die Dame.","Dame schlägt auf e8 – leitet den Qualitätsgewinn ein."],"en":["A stunning queen sacrifice wins the exchange.","Deflect the knight, then a bishop traps the queen.","Queen takes on e8 — launching the exchange-winning combination."],"hr":["Zapanjujuća žrtva dame osvaja kvalitetu.","Odvuci skakača, zatim lovac hvata damu.","Dama uzima na e8 — pokreće osvajanje kvalitete."]}', HintsVersion=1 WHERE LineId LIKE '%:011.016' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer öffnet die Stellung zum Vorteil.","Schlage am Königsflügel ein, dann übernehmen die Türme.","Läufer schlägt auf g6 – beginnt die gewinnende Kombination."],"en":["A bishop sacrifice opens the position to your advantage.","Strike on the kingside, then the rooks take over.","Bishop takes on g6 — launching the advantage-winning combination."],"hr":["Žrtva lovca otvara poziciju u tvoju korist.","Udari na kraljevom krilu, zatim topovi preuzimaju.","Lovac uzima na g6 — pokreće pobjedničku kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:011.017' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein zentraler Bauernstoß stoppt alle Drohungen und gewinnt.","Stoße den Zentrumsbauern vor und nutze die Spannung der Figuren.","Bauer nach d5 – pariert die Drohungen und sichert den Materialvorteil."],"en":["A central pawn break halts every threat and wins.","Advance the center pawn, exploiting the tension among the pieces.","Pawn to d5 — neutralizing the threats and securing the material edge."],"hr":["Prodor središnjeg pješaka zaustavlja sve prijetnje i pobjeđuje.","Gurni središnjeg pješaka, iskorištavajući napetost među figurama.","Pješak na d5 — neutralizira prijetnje i osigurava materijalnu prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:011.018' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt für den Anziehenden.","Ein Springerschach treibt den König in die tödliche Ecke.","Springer nach f6 – beginnt die erzwungene Mattkombination."],"en":["A forced mate is here for the side to move.","A knight check drives the king into the fatal corner.","Knight to f6 — starting the forced mating combination."],"hr":["Ovdje postoji prisilni mat za stranu na potezu.","Šah skakačem tjera kralja u kobni kut.","Skakač na f6 — pokreće prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:011.019' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Zug bereitet einen entscheidenden Schlag vor.","Stelle die Dame so, dass der Schlag neben dem König unhaltbar wird.","Dame nach b8 – bereitet die gewinnende Königsattacke vor."],"en":["A quiet move prepares a decisive blow.","Reposition the queen so the strike beside the king becomes unstoppable.","Queen to b8 — preparing the winning attack on the king."],"hr":["Tihi potez priprema odlučujući udarac.","Premjesti damu tako da udarac pokraj kralja postane neodoljiv.","Dama na b8 — priprema pobjednički napad na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:011.020' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Rückzug entzaubert den Angriff und lässt dich Material gewinnen.","Bring den bedrängten König in Sicherheit, dann übernimmt ein Springer die Initiative.","König nach h7 – leitet die widerlegende Kombination ein."],"en":["A calm retreat defuses the attack and lets you win material.","Tuck the harassed king to safety, then a knight seizes the initiative.","King to h7 — beginning the refuting sequence."],"hr":["Mirno povlačenje gasi napad i donosi ti materijalnu prednost.","Skloni ugroženog kralja na sigurno, a potom skakač preuzima inicijativu.","Kralj na h7 — počinje pobjednički slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:011.021' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zwischenschlag räumt einen Verteidiger weg und gewinnt eine Figur.","Der Turm opfert sich, damit der Läufer eine tödliche Fesselung aufbaut.","Turm schlägt auf d8 – Auftakt zum Figurengewinn."],"en":["An in-between blow removes a defender and wins a piece.","The rook gives itself up so the bishop sets up a fatal pin.","Rook takes on d8 — starting the winning combination."],"hr":["Međuudarac uklanja branitelja i osvaja figuru.","Top se žrtvuje da lovac postavi koban vez.","Top uzima na d8 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.022' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gegen den Bauernschild bricht die Königsstellung auf.","Der Turm reißt die Deckung des Königs ein, der Springer steht schon bereit.","Turm schlägt auf f7 – Beginn der gewinnenden Kombination."],"en":["A strike at the pawn shield cracks open the king''s position.","The rook tears away the king''s cover while the knight stands ready.","Rook takes on f7 — beginning the winning combination."],"hr":["Udarac na pješački štit otvara kraljevu poziciju.","Top razdire kraljev zaklon dok skakač čeka spreman.","Top uzima na f7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.023' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein durchbrechender Bauernzug öffnet die Linien zum erzwungenen Matt.","Ein zentraler Bauer stört, danach erledigen Dame und Türme den König.","Bauer nach d5 – erzwingt das Matt."],"en":["A breaking pawn move opens the lines for a forced mate.","A central pawn deflects, then queen and rooks finish the king.","Pawn to d5 — forcing mate."],"hr":["Proboj pješakom otvara linije za prisilni mat.","Središnji pješak ometa, a potom dama i topovi dokrajče kralja.","Pješak na d5 — prisiljava mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.024' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein weit vorgeschobener Bauer entscheidet die Partie zu deinen Gunsten.","Der gedeckte Freibauer in der Königsnähe wird zur entscheidenden Waffe.","Bauer nach e7 – Beginn der gewinnenden Kombination."],"en":["A far-advanced pawn decides the game in your favour.","The protected passer near the king becomes the decisive weapon.","Pawn to e7 — beginning the winning combination."],"hr":["Daleko napredovani pješak odlučuje partiju u tvoju korist.","Zaštićeni slobodnjak blizu kralja postaje odlučno oružje.","Pješak na e7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.025' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein vorstoßender Bauer setzt den Gegner in Zugzwang und gewinnt Material.","Ein zentraler Bauer öffnet Wege, dann schlägt der Springer entscheidend zu.","Bauer nach e4 – Beginn der gewinnenden Kombination."],"en":["An advancing pawn leaves the opponent with no good move and wins material.","A central pawn opens paths, then the knight strikes decisively.","Pawn to e4 — beginning the winning combination."],"hr":["Pješak u prodoru ostavlja protivnika bez dobrog poteza i osvaja materijal.","Središnji pješak otvara puteve, a potom skakač presudno udara.","Pješak na e4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.026' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein zentraler Vorstoß stellt eine Falle, die die Dame kostet.","Der vorgerückte Bauer und ein gut platzierter Turm fangen die feindliche Dame.","Bauer nach e4 – Beginn der gewinnenden Kombination."],"en":["A central push sets a trap that will cost the queen.","The advanced pawn and a well-placed rook snare the enemy queen.","Pawn to e4 — beginning the winning combination."],"hr":["Središnji prodor postavlja zamku koja košta dame.","Napredovani pješak i dobro postavljen top hvataju protivničku damu.","Pješak na e4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.027' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springervorstoß schafft eine Doppeldrohung, der nicht zu begegnen ist.","Der Springer dringt ein und droht zugleich gegen Dame und Turm.","Dame nach a4 – Beginn der gewinnenden Kombination."],"en":["A knight thrust creates a double threat that cannot be parried.","The knight jumps in, threatening against both queen and rook at once.","Queen to a4 — beginning the winning combination."],"hr":["Skok skakača stvara dvostruku prijetnju koja se ne može odbiti.","Skakač uskače, prijeteći istodobno i dami i topu.","Dama na a4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.028' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernvorstoß am Rand greift eine Figur an und gewinnt Material.","Der Randbauer fängt einen Läufer, dann verwerten die Springer den Vorteil.","Bauer nach h4 – Beginn der gewinnenden Kombination."],"en":["A flank pawn push attacks a piece and wins material.","The rook''s-file pawn traps a bishop, then the knights cash in.","Pawn to h4 — beginning the winning combination."],"hr":["Prodor rubnim pješakom napada figuru i osvaja materijal.","Rubni pješak hvata lovca, a potom skakači unovče prednost.","Pješak na h4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.029' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag gegen den Bauernschild öffnet den Weg zur entscheidenden Drohung.","Ein Springeropfer reißt die Königsstellung auf, dann übernehmen Turm und Läufer.","Springer schlägt auf f7 – Beginn der gewinnenden Kombination."],"en":["A strike at the pawn shield opens the way to a decisive threat.","A knight sacrifice rips open the king while rook and bishop take over.","Knight takes on f7 — beginning the winning combination."],"hr":["Udarac na pješački štit otvara put do odlučujuće prijetnje.","Žrtva skakača razdire kraljevu poziciju, a top i lovac preuzimaju.","Skakač uzima na f7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.030' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Damenrückzug bereitet ein erzwungenes Matt vor.","Die Dame zieht sich zurück, dann jagen Läufer und Türme den weißen König nieder.","Dame nach b8 – leitet das erzwungene Matt ein."],"en":["A quiet queen retreat sets up a forced mate.","The queen steps back, then bishop and rooks hunt down the white king.","Queen to b8 — beginning the forced mate."],"hr":["Mirno povlačenje dame priprema prisilni mat.","Dama se povlači, a potom lovac i topovi love bijelog kralja.","Dama na b8 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.031' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenschach erzwingt eine günstige Vereinfachung in den gewonnenen Bauernlauf.","Die Dame opfert sich, danach läuft der Freibauer zur neuen Dame.","Dame nach d8 mit Schach – Beginn der gewinnenden Kombination."],"en":["A queen check forces a favourable simplification into a winning pawn race.","The queen sacrifices itself, then the passed pawn runs to promotion.","Queen to d8 with check — beginning the winning combination."],"hr":["Šah damom prisiljava povoljno pojednostavljenje u dobitnu pješačku utrku.","Dama se žrtvuje, a potom slobodni pješak juri u promociju.","Dama na d8 sa šahom — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.032' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer gegen die Bauernkette ebnet dem Freibauern den Weg.","Die Dame räumt einen Bauern weg, dann marschiert der Randbauer durch.","Dame schlägt auf g6 mit Schach – Beginn der gewinnenden Kombination."],"en":["A queen sacrifice against the pawns clears the path for the passed pawn.","The queen removes a pawn, then the rook''s-file pawn marches through.","Queen takes on g6 with check — beginning the winning combination."],"hr":["Žrtva dame protiv pješaka čisti put slobodnom pješaku.","Dama uklanja pješaka, a potom rubni pješak prodire.","Dama uzima na g6 sa šahom — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.033' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Manöver gewinnt einen Läufer mit doppelter Drohung.","Der Turm schwenkt ein, dann zielt der Läufer auf den verwundbaren König.","Turm nach f4 – Beginn der gewinnenden Kombination."],"en":["A maneuver wins a bishop through a double threat.","The rook swings over, then the bishop targets the vulnerable king.","Rook to f4 — beginning the winning combination."],"hr":["Manevar osvaja lovca dvostrukom prijetnjom.","Top se prebacuje, a potom lovac cilja ranjivog kralja.","Top na f4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.034' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer auf einem geschwächten Feld erzwingt ein vernichtendes Matt.","Die Dame schlägt sich an den König heran und der Angriff bricht durch.","Dame schlägt auf g3 mit Schach – matt."],"en":["A queen sacrifice on a weakened square forces a crushing mate.","The queen smashes through to the king and the attack breaks in.","Queen takes on g3 with check — mate."],"hr":["Žrtva dame na oslabljenom polju prisiljava razoran mat.","Dama probija do kralja i napad provaljuje.","Dama uzima na g3 sa šahom — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.035' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Umwandlung lenkt eine Figur ab und gewinnt entscheidend Material.","Der Bauer wird zur Dame, was den Läufer von seiner Aufgabe weglockt.","Bauer wandelt auf a1 in eine Dame um – Beginn der gewinnenden Kombination."],"en":["A promotion deflects a piece and wins material decisively.","The pawn becomes a queen, luring the bishop away from its duty.","Pawn promotes to a queen on a1 — beginning the winning combination."],"hr":["Promocija odvlači figuru i osvaja materijal odlučno.","Pješak postaje dama, mameći lovca s njegove zadaće.","Pješak se promovira u damu na a1 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.036' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springerschlag öffnet die Linie für den vorrückenden Freibauern.","Der Springer beseitigt einen Bauern, dann wird der Randbauer unaufhaltsam.","Springer schlägt auf b6 – Beginn der gewinnenden Kombination."],"en":["A knight capture opens the file for the advancing passed pawn.","The knight removes a pawn, then the passer on the edge becomes unstoppable.","Knight takes on b6 — beginning the winning combination."],"hr":["Skakač uzimanjem otvara liniju za napredujućeg slobodnjaka.","Skakač uklanja pješaka, a potom rubni slobodnjak postaje nezaustavljiv.","Skakač uzima na b6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.037' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein zentraler Springervorstoß gewinnt mindestens einen Bauern, oft mehr.","Der Springer springt ins Zentrum und schafft mehrere unangenehme Drohungen.","Springer nach d5 – Beginn der gewinnenden Kombination."],"en":["A central knight leap wins at least a pawn, often more.","The knight jumps to the center, spawning several nasty threats.","Knight to d5 — beginning the winning combination."],"hr":["Skok skakača u središte osvaja barem pješaka, često i više.","Skakač uskače u središte i stvara nekoliko neugodnih prijetnji.","Skakač na d5 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.038' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenvorstoß startet einen Königsangriff, der im Matt endet.","Die Dame dringt ein, dann mahlt sich der schwarze Angriff bis zum König durch.","Dame nach h4 – leitet das erzwungene Matt ein."],"en":["A queen thrust launches a king attack that ends in mate.","The queen barges in, then Black''s pieces grind through to the king.","Queen to h4 — beginning the forced mate."],"hr":["Prodor damom pokreće napad na kralja koji završava matom.","Dama prodire, a potom crni napad melje sve do kralja.","Dama na h4 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.039' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Das Ausschalten eines Verteidigers ermöglicht eine gewinnende Kombination.","Erst wird ein Läufer abgetauscht, dann reißt ein Turmopfer die Stellung auf.","Läufer schlägt auf f4 – Beginn der gewinnenden Kombination."],"en":["Eliminating a defender clears the way for a winning combination.","First a bishop is traded off, then a rook sacrifice rips the position open.","Bishop takes on f4 — beginning the winning combination."],"hr":["Uklanjanje branitelja otvara put dobitnoj kombinaciji.","Najprije se razmijeni lovac, a potom žrtva topa razdire poziciju.","Lovac uzima na f4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.040' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer lockt einen Verteidiger weg und führt zum Matt.","Die Dame opfert sich, dann dringt der Turm matt setzend ein.","Dame schlägt auf f6 – Beginn der mattsetzenden Kombination."],"en":["A queen sacrifice lures away a defender and leads to mate.","The queen gives itself up, then the rook crashes in to mate.","Queen takes on f6 — beginning the mating combination."],"hr":["Žrtva dame odvlači branitelja i vodi u mat.","Dama se žrtvuje, a potom top provaljuje i matira.","Dama uzima na f6 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.041' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springerschlag mit Schach gewinnt entscheidend Material.","Der Springer schlägt den Bauern und springt dann auf ein gabelndes Feld.","Springer schlägt auf g3 mit Schach – Beginn der gewinnenden Kombination."],"en":["A knight capture with check wins material decisively.","The knight takes the pawn, then leaps to a forking square.","Knight takes on g3 with check — beginning the winning combination."],"hr":["Skakač uzima sa šahom i osvaja materijal odlučno.","Skakač uzima pješaka, a potom skače na polje koje viljuškari.","Skakač uzima na g3 sa šahom — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.042' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer öffnet die Linie für ein erzwungenes Matt.","Der Turm opfert sich, dann schnürt der Läufer den weißen König ein.","Turm schlägt auf e2 – leitet das erzwungene Matt ein."],"en":["A rook sacrifice opens the line for a forced mate.","The rook gives itself up, then the bishop weaves the mating net.","Rook takes on e2 — beginning the forced mate."],"hr":["Žrtva topa otvara liniju za prisilni mat.","Top se žrtvuje, a potom lovac plete matnu mrežu oko bijelog kralja.","Top uzima na e2 — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.043' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springerschlag bricht die Königsstellung auf und gewinnt einen wichtigen Bauern.","Der Springer schlägt, dann dringen Läufer und Springer ins Zentrum ein.","Springer schlägt auf g4 – Beginn der gewinnenden Kombination."],"en":["A knight capture cracks the king''s cover and wins a vital pawn.","The knight strikes, then bishop and knight pour into the center.","Knight takes on g4 — beginning the winning combination."],"hr":["Skakač uzimanjem razbija kraljev zaklon i osvaja važnog pješaka.","Skakač udara, a potom lovac i skakač provaljuju u središte.","Skakač uzima na g4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.044' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer auf der offenen Linie leitet eine entscheidende Kombination ein.","Der Turm schlägt mit Schach, dann holt die Dame entscheidend Material.","Turm schlägt auf e8 mit Schach – Beginn der gewinnenden Kombination."],"en":["A rook sacrifice on the open file starts a decisive combination.","The rook strikes with check, then the queen scoops up material.","Rook takes on e8 with check — beginning the winning combination."],"hr":["Žrtva topa na otvorenoj liniji pokreće odlučnu kombinaciju.","Top udara sa šahom, a potom dama kupi odlučujući materijal.","Top uzima na e8 sa šahom — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.045' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmvorstoß schafft unhaltbare Drohungen und gewinnt Material.","Der Turm dringt ein, dann arbeiten Läufer und Dame entscheidend zusammen.","Turm nach c3 – Beginn der gewinnenden Kombination."],"en":["A rook thrust creates unstoppable threats and wins material.","The rook barges in, then bishop and queen combine decisively.","Rook to c3 — beginning the winning combination."],"hr":["Prodor topom stvara nezaustavljive prijetnje i osvaja materijal.","Top prodire, a potom lovac i dama presudno surađuju.","Top na c3 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.046' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer reißt die Königsdeckung auf und erzwingt das Matt.","Der Springer opfert sich, dann dringen Dame und Turm matt setzend ein.","Springer nach f3 mit Schach – leitet das erzwungene Matt ein."],"en":["A knight sacrifice tears open the king''s cover and forces mate.","The knight gives itself up, then queen and rook crash in to mate.","Knight to f3 with check — beginning the forced mate."],"hr":["Žrtva skakača razdire kraljev zaklon i prisiljava mat.","Skakač se žrtvuje, a potom dama i top provaljuju do mata.","Skakač na f3 sa šahom — počinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.047' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst schlechter und musst dich mit einem Opfer ins Remis retten.","Ein Läuferopfer reißt die Königsstellung auf und erzwingt das Dauerschach.","Läufer schlägt auf g2 mit Schach – leitet die Rettung ins Remis ein."],"en":["You are worse and must rescue a draw with a sacrifice.","A bishop sacrifice opens the king''s position and forces perpetual check.","Bishop takes on g2 with check — beginning the saving draw."],"hr":["Stojiš lošije i moraš se žrtvom spasiti u remi.","Žrtva lovca otvara kraljevu poziciju i prisiljava vječiti šah.","Lovac uzima na g2 sa šahom — počinje spas u remi."]}', HintsVersion=1 WHERE LineId LIKE '%:011.048' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springervorstoß stellt eine versteckte Falle und gewinnt Material.","Der Springer springt vor, dann jagen Turm und Dame den schwarzen König.","Springer nach b6 – Beginn der gewinnenden Kombination."],"en":["A knight leap sets a hidden trap and wins material.","The knight jumps forward, then rook and queen chase the black king.","Knight to b6 — beginning the winning combination."],"hr":["Skok skakača postavlja skrivenu zamku i osvaja materijal.","Skakač skače naprijed, a potom top i dama gone crnog kralja.","Skakač na b6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.049' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer beseitigt einen Verteidiger und gewinnt entscheidend.","Der Turm schlägt, dann übernimmt der Turm auf der offenen Linie das Kommando.","Turm schlägt auf f6 – Beginn der gewinnenden Kombination."],"en":["A rook sacrifice removes a defender and wins decisively.","The rook strikes, then the other rook takes command of the open file.","Rook takes on f6 — beginning the winning combination."],"hr":["Žrtva topa uklanja branitelja i osvaja odlučno.","Top udara, a potom drugi top preuzima zapovjedništvo na otvorenoj liniji.","Top uzima na f6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.050' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – die feindliche Königsstellung bricht zusammen.","Deine Dame und ein vorgepreschter Springer geben gemeinsam den Ton an.","Dame nimmt auf g3 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is in the air — the enemy king''s shelter collapses.","Your queen and an advanced knight set the tune together.","Queen takes on g3 — the start of a forced mate."],"hr":["Prisilni mat visi u zraku — kraljev zaklon se ruši.","Tvoja dama i napredni skakač zajedno daju ton.","Dama uzima na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.051' AND BookFileName='chessable-u5-49693.pgn';
