UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer am Königsflügel führt zu entscheidendem Materialgewinn.","Läufer und Springer öffnen die Stellung vor dem König, die Dame folgt.","Läufer schlägt auf h3 – Beginn der gewinnbringenden Opferreihe."],"en":["A kingside sacrifice leads to a decisive material gain.","Bishop and knight rip open the king, the queen follows.","Bishop takes on h3 — the start of the winning sacrificial sequence."],"hr":["Žrtva na kraljevom krilu vodi do odlučne materijalne prednosti.","Lovac i skakač otvaraju kraljevu poziciju, dama slijedi.","Lovac uzima na h3 — početak dobitne žrtvene serije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.055' AND BookFileName='chessable-u5-49693.pgn';
