UPDATE BookPuzzles SET HintsJson='{"de":["Ein ruhiger Königszug bereitet einen entscheidenden Königsflügelangriff vor.","Der König geht beiseite, damit Türme und Bauern stürmen können.","König nach g2 – Auftakt zum gewinnbringenden Angriff."],"en":["A quiet king move prepares a decisive kingside assault.","The king steps aside so rooks and pawns can storm forward.","King to g2 — the start of the winning attack."],"hr":["Tihi kraljev potez priprema odlučan napad na kraljevom krilu.","Kralj se sklanja da bi topovi i pješaci jurišali.","Kralj na g2 — početak dobitnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:011.065' AND BookFileName='chessable-u5-49693.pgn';
