UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer öffnet den Weg zum erzwungenen Matt.","Läufer und Dame koordinieren den entscheidenden Schlag gegen den König.","Läufer schlägt auf g4 – Auftakt zum erzwungenen Matt."],"en":["A sacrifice clears the path to a forced mate.","Bishop and queen coordinate the decisive blow against the king.","Bishop takes on g4 — the start of the forced mate."],"hr":["Žrtva otvara put do prisilnog mata.","Lovac i dama usklađuju odlučan udarac na kralja.","Lovac uzima na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.077' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – der König wird ins Netz getrieben.","Ein Springer treibt den König, Dame und Läufer schließen das Netz.","Springer nach f6 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is ready — the king is driven into a net.","A knight drives the king while queen and bishop close the net.","Knight to f6 — the start of the forced mate."],"hr":["Prisilni mat je spreman — kralj se tjera u mrežu.","Skakač tjera kralja dok dama i lovac zatvaraju mrežu.","Skakač na f6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.078' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer reißt die Königsstellung auf und führt zum Matt.","Die beiden Springer und der Läufer bereiten das Mattnetz vor.","Springer nach f5 – Auftakt zum erzwungenen Matt."],"en":["A knight sacrifice tears open the king and forces mate.","The two knights and the bishop weave the mating net.","Knight to f5 — the start of the forced mate."],"hr":["Žrtva skakača razbija kraljev zaklon i prisiljava mat.","Dva skakača i lovac pletu matnu mrežu.","Skakač na f5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:011.079' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer öffnet die Linien und gewinnt entscheidend.","Dame und Türme vereinen sich zum durchschlagenden Angriff.","Dame schlägt auf h4 – Beginn der gewinnbringenden Kombination."],"en":["A sacrifice opens the lines and wins decisively.","Queen and rooks unite for a crashing attack.","Queen takes on h4 — the start of the winning combination."],"hr":["Žrtva otvara linije i odlučno pobjeđuje.","Dama i topovi se ujedinjuju za razoran napad.","Dama uzima na h4 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:011.080' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["In diesem Endspiel steckt ein gewinnender Plan – der König muss aktiv werden.","Der König marschiert nach vorn und unterstützt die Bauern zum Durchbruch.","König nach g6 – leitet die gewinnende Königswanderung ein."],"en":["This endgame hides a winning plan — the king must come to life.","March the king forward to support the pawns'' breakthrough.","King to g6 — starting the winning king march."],"hr":["U ovoj završnici krije se dobitni plan — kralj mora postati aktivan.","Kralj kreće naprijed i podupire prodor pješaka.","Kralj na g6 — započinje dobitni hod kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:011.081' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein stiller Läuferzug rettet die Stellung und sichert sogar einen Vorteil.","Der Läufer muss sich der drohenden Fesselung entziehen und bleibt geschützt.","Läufer nach c6 – der einzige Zug, der im Spiel hält und Material sichert."],"en":["A quiet bishop move holds the position and even keeps an edge.","The bishop must step off the dangerous file while staying defended.","Bishop to c6 — the only move that stays in the game and wins a pawn."],"hr":["Tihi potez lovca drži poziciju i čak osigurava prednost.","Lovac se mora maknuti s opasne linije i ostati zaštićen.","Lovac na c6 — jedini potez koji ostaje u igri i osvaja pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:011.082' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier ist die Verteidigung schwierig – ein zähes Remis muss erkämpft werden.","Der Turm bleibt aktiv und schikaniert von hinten, um nicht in Zugzwang zu geraten.","Turm nach b3 – beginnt die rettende Dauerstörung zum Remis."],"en":["Defence is hard here — a stubborn draw must be wrung out.","Keep the rook active and harass from behind to avoid being squeezed.","Rook to b3 — starting the saving harassment toward a draw."],"hr":["Obrana je teška — žilavi remi treba izboriti.","Top ostaje aktivan i smeta straga da se izbjegne stiska.","Top na b3 — započinje spasonosno smetanje prema remiju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.003' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damentausch führt in ein gewonnenes Bauernendspiel.","Die Dame zwingt mit Schach den Abtausch herbei und der Bauer entscheidet.","Dame nach f1 – leitet den siegreichen Abtausch ins Bauernendspiel ein."],"en":["A queen trade leads into a won pawn endgame.","The queen forces the exchange with check and a pawn decides.","Queen to f1 — starting the winning trade into the pawn ending."],"hr":["Zamjena dama vodi u dobivenu pješačku završnicu.","Dama šahom prisiljava zamjenu i pješak odlučuje.","Dama na f1 — započinje dobitnu zamjenu u pješačku završnicu."]}', HintsVersion=1 WHERE LineId LIKE '%:012.004' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es schlummert eine taktische Chance, die entscheidenden Vorteil bringt.","Die Dame zieht in die Ecke und bereitet die durchschlagende Idee vor.","Dame nach a1 – der starke Zug, der den Vorteil sichert."],"en":["A tactical chance is lurking that brings a decisive edge.","The queen slips into the corner to prepare the breakthrough idea.","Queen to a1 — the strong move that seizes the advantage."],"hr":["Vreba taktička prilika koja donosi odlučujuću prednost.","Dama odlazi u kut i priprema prodornu zamisao.","Dama na a1 — jaki potez koji osigurava prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:012.005' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Statt des Fehlers gibt es einen Zug, der klaren Vorteil sichert.","Ein Bauer stößt vor und öffnet den Weg für die eigene Verwandlung.","Bauer nach d6 – startet die vorteilbringende Kombination."],"en":["Instead of the mistake there is a move that secures a clear edge.","A pawn pushes forward and clears the path toward promotion.","Pawn to d6 — starting the advantage-winning combination."],"hr":["Umjesto pogreške postoji potez koji osigurava jasnu prednost.","Pješak kreće naprijed i otvara put prema pretvorbi.","Pješak na d6 — započinje kombinaciju koja donosi prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:012.006' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein präziser Zug entschärft die gegnerische Drohung und gewinnt.","Der Läufer schlägt sich ab und räumt den Weg für den entscheidenden Schlag.","Läufer schlägt auf d4 – leitet die gewinnende Folge ein."],"en":["A precise move parries the threat and wins.","The bishop captures to clear the way for the decisive blow.","Bishop takes on d4 — beginning the winning sequence."],"hr":["Precizan potez obesnažuje prijetnju i dobiva.","Lovac uzima i otvara put za odlučujući udarac.","Lovac uzima na d4 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:012.007' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Solver steht schlechter und muss ein Remis retten.","Die Dame opfert sich, um ein Patt zu erzwingen.","Dame nach f1 – leitet die rettende Pattfalle ein."],"en":["The solver is worse and must rescue a draw.","The queen offers itself to force a stalemate.","Queen to f1 — beginning the saving stalemate trick."],"hr":["Onaj na potezu stoji lošije i mora spasiti remi.","Dama se žrtvuje da iznudi pat.","Dama na f1 — započinje spasonosnu pat-zamku."]}', HintsVersion=1 WHERE LineId LIKE '%:012.008' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer reißt die Königsstellung auf und bringt klaren Vorteil.","Der Turm schlägt sich am Königsflügel und die Dame folgt zum Angriff.","Turm schlägt auf f7 – Beginn des gewinnenden Angriffs."],"en":["A rook sacrifice tears open the king and brings a clear edge.","The rook crashes through near the king and the queen joins in.","Rook takes on f7 — starting the winning attack."],"hr":["Žrtva topa razbija kraljev zaklon i donosi jasnu prednost.","Top uzima kod kralja, a dama se pridružuje napadu.","Top uzima na f7 — započinje dobitni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:012.009' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Solver muss genau spielen, um ein Remis zu sichern.","Ein Bauerndurchbruch und der König schaffen die Festung zum Remis.","Bauer nach g5 – leitet die rettende Remisfolge ein."],"en":["The solver must play precisely to secure a draw.","A pawn break and the king together build the drawing fortress.","Pawn to g5 — beginning the saving drawing sequence."],"hr":["Onaj na potezu mora igrati precizno da osigura remi.","Prodor pješaka i kralj zajedno grade tvrđavu za remi.","Pješak na g5 — započinje spasonosni niz prema remiju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.010' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Vereinfachung führt in ein gewonnenes Bauernendspiel.","Ein Bauer stößt vor und erzwingt günstige Abtäusche.","Bauer nach d6 – leitet die gewinnende Vereinfachung ein."],"en":["Simplification leads into a won pawn endgame.","A pawn push forces the favourable exchanges.","Pawn to d6 — starting the winning simplification."],"hr":["Pojednostavljenje vodi u dobivenu pješačku završnicu.","Pješak kreće naprijed i iznuđuje povoljne zamjene.","Pješak na d6 — započinje dobitno pojednostavljenje."]}', HintsVersion=1 WHERE LineId LIKE '%:012.011' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Liquidation führt in ein gewonnenes Endspiel.","Die Dame zieht aktiv und leitet die entscheidenden Abtäusche ein.","Dame nach g4 – Beginn der gewinnenden Liquidation."],"en":["A liquidation leads into a winning endgame.","The queen swings out to force the decisive exchanges.","Queen to g4 — starting the winning liquidation."],"hr":["Likvidacija vodi u dobivenu završnicu.","Dama izlazi aktivno i pokreće odlučujuće zamjene.","Dama na g4 — započinje dobitnu likvidaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.012' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz Minusbauern entscheidet die Figurenaktivität die Partie.","Ein Damenopfer zerstört die Verteidigung und bringt den Vorteil.","Dame schlägt auf f5 – leitet die gewinnende Kombination ein."],"en":["Despite being down pawns, active pieces decide the game.","A queen sacrifice shatters the defence and brings the edge.","Queen takes on f5 — starting the winning combination."],"hr":["Unatoč manjku pješaka, aktivnost figura odlučuje partiju.","Žrtva dame razbija obranu i donosi prednost.","Dama uzima na f5 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.013' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Nur ein einziger Zug hält die Stellung und sichert den Vorteil.","Die Dame muss aktiv bleiben und mit Schachs Druck machen.","Dame nach c8 – der einzige Zug, der den Vorteil bewahrt."],"en":["Only one move holds the position and keeps the edge.","The queen must stay active and press with checks.","Queen to c8 — the only move that preserves the advantage."],"hr":["Samo jedan potez drži poziciju i čuva prednost.","Dama mora ostati aktivna i šahovima vršiti pritisak.","Dama na c8 — jedini potez koji čuva prednost."]}', HintsVersion=1 WHERE LineId LIKE '%:012.014' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Nach dem Figurenopfer wartet ein erzwungenes Matt.","Der Springer geht vor und treibt den Angriff zum Matt voran.","Springer nach g5 – Beginn des forcierten Mattangriffs."],"en":["After the piece sacrifice a forced mate is waiting.","The knight leaps forward to drive the attack home to mate.","Knight to g5 — starting the forced mating attack."],"hr":["Nakon žrtve figure čeka prisilni mat.","Skakač skače naprijed i tjera napad do mata.","Skakač na g5 — započinje prisilni matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:012.015' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz großen Materialnachteils entscheidet der unsichere König.","Der Läufer öffnet mit Schachs die Linien für den Durchbruch.","Läufer nach b5 – leitet die gewinnende Kombination ein."],"en":["Despite a big material deficit, the exposed king decides.","The bishop opens lines with checks for the breakthrough.","Bishop to b5 — starting the winning combination."],"hr":["Unatoč velikom manjku materijala, nesiguran kralj odlučuje.","Lovac šahovima otvara linije za prodor.","Lovac na b5 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.016' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz des angegriffenen Turms gibt es einen entscheidenden Schlag.","Der Turm schlägt auf der siebten Reihe und nutzt den Pendel-Effekt.","Turm schlägt auf g7 – Beginn der gewinnenden Folge."],"en":["Even with the rook attacked, there is a decisive blow.","The rook strikes on the seventh and exploits the seesaw effect.","Rook takes on g7 — starting the winning sequence."],"hr":["Unatoč napadnutom topu, postoji odlučujući udarac.","Top udara na sedmom redu i koristi efekt njihalice.","Top uzima na g7 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:012.017' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["In diesem Bauernendspiel führt der richtige Plan zum Vorteil.","Der König weicht aus und lässt die Bauern den Wettlauf gewinnen.","König nach h6 – leitet das vorteilhafte Bauernrennen ein."],"en":["In this pawn endgame the right plan brings the edge.","The king steps aside to let the pawns win the race.","King to h6 — starting the advantageous pawn race."],"hr":["U ovoj pješačkoj završnici pravi plan donosi prednost.","Kralj se izmiče da pješaci dobiju utrku.","Kralj na h6 — započinje povoljnu pješačku utrku."]}', HintsVersion=1 WHERE LineId LIKE '%:012.018' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Bauernumwandlung sieht riskant aus, gewinnt aber.","Der vorgerückte Bauer wird zur Dame und entscheidet trotz scheinbarer Gefahr.","Bauer verwandelt sich auf g1 in eine Dame – leitet den Gewinn ein."],"en":["A pawn promotion looks risky but wins.","The advanced pawn queens and decides despite the apparent danger.","Pawn promotes to a queen on g1 — starting the win."],"hr":["Pretvorba pješaka izgleda riskantno, ali dobiva.","Daleki pješak postaje dama i odlučuje unatoč prividnoj opasnosti.","Pješak se pretvara u damu na g1 — započinje dobitak."]}', HintsVersion=1 WHERE LineId LIKE '%:012.019' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit der Mehrdame muss der Vorteil präzise verwertet werden.","Die Dame manövriert mit Schachs und treibt den König vor sich her.","Dame nach b1 – leitet die gewinnende Verwertung ein."],"en":["With the extra queen the advantage must be cashed precisely.","The queen maneuvers with checks and herds the king along.","Queen to b1 — starting the winning conversion."],"hr":["S viškom dame prednost treba precizno unovčiti.","Dama manevrira šahovima i tjera kralja pred sobom.","Dama na b1 — započinje dobitno unovčenje."]}', HintsVersion=1 WHERE LineId LIKE '%:012.020' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt etwas Entscheidenderes als den simplen Abtausch.","Die Dame zieht beiseite und hält die gefährliche Drohung am Leben.","Dame nach f5 – leitet die gewinnende Kombination ein."],"en":["There is something more conclusive than the simple trade.","The queen sidesteps to keep the dangerous threat alive.","Queen to f5 — starting the winning combination."],"hr":["Postoji nešto odlučnije od proste zamjene.","Dama se izmiče u stranu i drži opasnu prijetnju živom.","Dama na f5 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.021' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein verborgener Schlag, den beide Spieler übersahen, entscheidet.","Ein Läuferopfer reißt den König heraus und der Turm folgt.","Läufer schlägt auf h2 – Beginn der gewinnenden Kombination."],"en":["A hidden blow both players missed decides the game.","A bishop sacrifice drags the king out and the rook follows.","Bishop takes on h2 — starting the winning combination."],"hr":["Skriveni udarac koji su oba igrača previdjela odlučuje.","Žrtva lovca izvlači kralja, a top slijedi.","Lovac uzima na h2 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.022' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Gegen den drohenden Angriff gibt es eine verteidigende Folge mit Vorteil.","Die Dame zieht zurück und entschärft die Drohung am Königsflügel.","Dame nach b6 – leitet die entschärfende Folge ein."],"en":["Against the looming attack there is a defence that keeps an edge.","The queen retreats to defuse the threat near the king.","Queen to b6 — beginning the defusing sequence."],"hr":["Protiv prijetećeg napada postoji obrana koja čuva prednost.","Dama se povlači i obesnažuje prijetnju kod kralja.","Dama na b6 — započinje obrambeni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:012.023' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer gegen den König startet einen gewinnenden Angriff.","Der Springer schlägt sich und öffnet die Stellung des Königs.","Springer schlägt auf f7 – Beginn des gewinnenden Angriffs."],"en":["A sacrifice against the king starts a winning attack.","The knight captures to rip open the king''s position.","Knight takes on f7 — starting the winning attack."],"hr":["Žrtva protiv kralja pokreće dobitni napad.","Skakač uzima i otvara kraljevu poziciju.","Skakač uzima na f7 — započinje dobitni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:012.024' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet das kürzeste Matt.","Die Dame zieht auf die offene Linie und bereitet das Matt vor.","Dame nach d8 – Beginn des erzwungenen Matts."],"en":["The shortest route to mate is waiting here.","The queen moves to the open file to prepare the mate.","Queen to d8 — starting the forced mate."],"hr":["Ovdje čeka najkraći put do mata.","Dama dolazi na otvorenu liniju i priprema mat.","Dama na d8 — započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:012.025' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Auf das gegnerische Schlagen folgt ein entscheidender Schlag.","Der Läufer dringt am Königsflügel ein und eröffnet den Angriff.","Läufer schlägt auf h6 – leitet die gewinnende Folge ein."],"en":["The opponent''s capture invites a decisive reply.","The bishop bursts in near the king and opens the attack.","Bishop takes on h6 — starting the winning sequence."],"hr":["Protivnikovo uzimanje poziva na odlučujući odgovor.","Lovac prodire kod kralja i otvara napad.","Lovac uzima na h6 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:012.026' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt den Königsschutz auf und gewinnt.","Die Dame schlägt sich und zerschlägt den Bauernschild des Königs.","Dame schlägt auf g7 – Beginn der gewinnenden Kombination."],"en":["A sacrifice tears open the king''s cover and wins.","The queen captures to smash the king''s pawn shield.","Queen takes on g7 — starting the winning combination."],"hr":["Žrtva razbija kraljev zaklon i dobiva.","Dama uzima i ruši pješački štit kralja.","Dama uzima na g7 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.027' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer leitet einen forcierten Gewinn ein.","Die Dame schlägt am Königsflügel und legt den König frei.","Dame schlägt auf g7 – Beginn des forcierten Gewinns."],"en":["A sacrifice leads to a forced win.","The queen captures near the king and lays it bare.","Queen takes on g7 — starting the forced win."],"hr":["Žrtva pokreće prisilni dobitak.","Dama uzima kod kralja i ogoljuje ga.","Dama uzima na g7 — započinje prisilni dobitak."]}', HintsVersion=1 WHERE LineId LIKE '%:012.028' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der einfachste Weg führt über ein klärendes Opfer zum Sieg.","Der Turm opfert sich, um den König herauszuziehen.","Turm nach h7 – Beginn der gewinnenden Folge."],"en":["The easiest path to victory runs through a clearing sacrifice.","The rook sacrifices itself to drag the king out.","Rook to h7 — starting the winning sequence."],"hr":["Najlakši put do pobjede vodi preko razjašnjavajuće žrtve.","Top se žrtvuje da izvuče kralja.","Top na h7 — započinje dobitni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:012.029' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["In diesem Bauernendspiel führt der richtige Zug zum Gewinn.","Der vorgerückte Bauer stößt vor und öffnet den Weg zur Verwandlung.","Bauer nach b4 – leitet das gewinnende Bauernrennen ein."],"en":["In this pawn endgame the right move brings the win.","The advanced pawn pushes on and clears the road to queening.","Pawn to b4 — starting the winning pawn race."],"hr":["U ovoj pješačkoj završnici pravi potez donosi dobitak.","Daleki pješak kreće naprijed i otvara put do pretvorbe.","Pješak na b4 — započinje dobitnu pješačku utrku."]}', HintsVersion=1 WHERE LineId LIKE '%:012.030' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein durchgerechnetes Bauernrennen entscheidet zugunsten von Weiß.","Der weit vorgerückte Freibauer trägt die ganze Last – sein Marsch zur Umwandlung gewinnt.","Bauer nach c7 – leitet das gewinnende Vorstoßen ein."],"en":["A precisely calculated pawn race decides in White''s favour.","The advanced passed pawn does all the work — its run to promotion wins.","Pawn to c7 — starting the winning advance."],"hr":["Točno proračunata utrka pješaka odlučuje u korist bijeloga.","Daleko odmaknuti slobodnjak nosi sav teret — njegov marš do promocije dobiva.","Pješak na c7 — početak dobitnog prodora."]}', HintsVersion=1 WHERE LineId LIKE '%:012.031' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsstellung auf und erzwingt Matt.","Der Läufer leitet das Opfer ein, danach jagt die Dame den König zum Matt.","Läufer schlägt auf f3 – Beginn der erzwungenen Mattfolge."],"en":["A sacrifice tears open the king''s shelter and forces mate.","The bishop launches the sacrifice, then the queen hunts the king down.","Bishop takes on f3 — the start of the forced mating sequence."],"hr":["Žrtva razbija kraljev zaklon i forsira mat.","Lovac započinje žrtvu, a potom dama lovi kralja do mata.","Lovac uzima na f3 — početak prisilnog niza do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.032' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag am Königsflügel bringt entscheidenden Vorteil.","Die Dame dringt zum schwachen König vor und die Leichtfiguren unterstützen den Angriff.","Dame nach h6 – Auftakt der gewinnenden Kombination."],"en":["A blow on the kingside brings a decisive advantage.","The queen invades near the weak king while the minor pieces join in.","Queen to h6 — opening the winning combination."],"hr":["Udarac na kraljevu krilu donosi odlučujuću prednost.","Dama prodire blizu slabog kralja, a lake figure podupiru napad.","Dama na h6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.033' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Abzug am zentralen Läufer reißt die Verteidigung ein und gewinnt.","Der Turm schlägt zu und die Damen-Läufer-Batterie übernimmt den Angriff.","Turm schlägt auf d5 – Beginn der entscheidenden Kombination."],"en":["A blow at the central bishop shreds the defence and wins.","The rook strikes first, then the queen and bishops drive the attack home.","Rook takes on d5 — launching the decisive combination."],"hr":["Udarac na središnjeg lovca razbija obranu i dobiva.","Top udara prvi, a potom dama i lovci dovršavaju napad.","Top uzima na d5 — početak odlučujuće kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.034' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer im Zentrum ebnet den Bauern den Weg zum Sieg.","Der Läufer opfert sich, danach laufen die Freibauern unaufhaltsam durch.","Läufer schlägt auf e6 – Auftakt der gewinnenden Bauernoffensive."],"en":["A bishop sacrifice in the centre clears the path for the pawns to win.","The bishop gives itself up so the passed pawns can march through.","Bishop takes on e6 — beginning the winning pawn breakthrough."],"hr":["Žrtva lovca u središtu otvara put pješacima do pobjede.","Lovac se žrtvuje da slobodni pješaci nezaustavljivo prođu.","Lovac uzima na e6 — početak dobitnog prodora pješaka."]}', HintsVersion=1 WHERE LineId LIKE '%:012.035' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Bauernendspiel führt eine genaue Königswanderung zum Sieg.","Der König muss den Freibauern decken und zur Umwandlung geleiten.","König nach a6 – Beginn des gewinnenden Plans."],"en":["In the pawn ending a precise king march brings the win.","The king must shepherd the passed pawn through to promotion.","King to a6 — starting the winning plan."],"hr":["U pješačkoj završnici precizan hod kralja donosi pobjedu.","Kralj mora štititi slobodnjaka i odvesti ga do promocije.","Kralj na a6 — početak dobitnog plana."]}', HintsVersion=1 WHERE LineId LIKE '%:012.036' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springervorstoß leitet ein erzwungenes Matt ein.","Der Springer öffnet die Linien, dann brechen die Türme durch.","Springer nach f5 – Auftakt der erzwungenen Mattfolge."],"en":["A knight thrust sets up a forced mate.","The knight opens the lines, then the rooks crash through.","Knight to f5 — the start of the forced mating sequence."],"hr":["Skok skakača priprema prisilni mat.","Skakač otvara linije, a potom topovi probijaju.","Skakač na f5 — početak prisilnog niza do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.037' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Leichtfigurenendspiel gewinnt ein präziser Bauernvorstoß entscheidend.","Der Bauer marschiert vor, vom König gedeckt, während der Läufer nicht alles halten kann.","Bauer nach h3 – Beginn der gewinnenden Folge."],"en":["In the minor-piece ending a precise pawn push wins decisively.","The pawn advances with the king''s support while the bishop can''t hold everything.","Pawn to h3 — beginning the winning sequence."],"hr":["U završnici lakih figura precizan potez pješaka odlučno dobiva.","Pješak napreduje uz pomoć kralja dok lovac ne može sve zadržati.","Pješak na h3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:012.038' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer am Königsflügel reißt die Stellung auf und gewinnt.","Der Springer schlägt ein, danach stürzt sich die Dame auf den entblößten König.","Springer schlägt auf f7 – Auftakt der gewinnenden Kombination."],"en":["A sacrifice on the kingside rips the position open and wins.","The knight strikes, then the queen pounces on the exposed king.","Knight takes on f7 — opening the winning combination."],"hr":["Žrtva na kraljevu krilu razbija položaj i dobiva.","Skakač udara, a potom dama navaljuje na izloženog kralja.","Skakač uzima na f7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.039' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß steht schlechter und muss mit präzisem Spiel das Remis retten.","Der Läufer muss sich richtig postieren, um den feindlichen Plan zu neutralisieren.","Läufer nach a2 – Beginn der rettenden Folge zum Remis."],"en":["White is worse and must play precisely to rescue the draw.","The bishop has to find the right square to neutralise the enemy plan.","Bishop to a2 — starting the saving sequence to a draw."],"hr":["Bijeli stoji lošije i mora precizno igrati da spasi remi.","Lovac mora naći pravo polje da neutralizira protivnikov plan.","Lovac na a2 — početak niza koji spašava remi."]}', HintsVersion=1 WHERE LineId LIKE '%:012.040' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit exakter Königsmanöver sichert sich der Nachziehende das Resultat.","Der König muss zurück auf das richtige Feld und darf den Gegner nicht durchlassen.","König nach e7 – Beginn der entscheidenden Folge."],"en":["With an exact king manoeuvre Black secures the result.","The king must step back to the right square and let nothing through.","King to e7 — beginning the decisive sequence."],"hr":["Točnim manevrom kralja crni osigurava rezultat.","Kralj se mora vratiti na pravo polje i ništa ne propustiti.","Kralj na e7 — početak odlučujućeg niza."]}', HintsVersion=1 WHERE LineId LIKE '%:012.041' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer öffnet den König und bringt entscheidenden Vorteil.","Der Turm opfert sich, danach übernehmen Läufer und Dame den Angriff.","Turm schlägt auf e6 – Auftakt der gewinnenden Kombination."],"en":["A capturing sacrifice opens the king and brings a decisive advantage.","The rook gives itself up, then the bishop and queen take over the attack.","Rook takes on e6 — launching the winning combination."],"hr":["Žrtva uzimanjem otvara kralja i donosi odlučujuću prednost.","Top se žrtvuje, a potom lovac i dama preuzimaju napad.","Top uzima na e6 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.042' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Vorstoß ins Herz der Stellung entscheidet zugunsten des Nachziehenden.","Der Turm dringt unaufhaltsam vor und die Dame folgt zum Königsangriff.","Turm nach f3 – Beginn der gewinnenden Folge."],"en":["A thrust into the heart of the position decides for Black.","The rook pushes in unstoppably and the queen follows to the king.","Rook to f3 — beginning the winning sequence."],"hr":["Prodor u srce položaja odlučuje u korist crnoga.","Top nezaustavljivo prodire, a dama slijedi prema kralju.","Top na f3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:012.043' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine ruhige Annäherung der Dame leitet ein erzwungenes Matt ein.","Die Dame schwenkt zum König, danach setzen die schweren Figuren matt.","Dame nach c7 – Auftakt der erzwungenen Mattfolge."],"en":["A quiet queen approach sets up a forced mate.","The queen swings toward the king, then the heavy pieces deliver mate.","Queen to c7 — the start of the forced mating sequence."],"hr":["Tiho približavanje dame priprema prisilni mat.","Dama se okreće prema kralju, a teške figure dovršavaju mat.","Dama na c7 — početak prisilnog niza do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.044' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag auf der offenen Linie bricht die Verteidigung und gewinnt.","Der Turm dringt mit Tempo ein, danach türmen sich die Drohungen auf den König.","Turm schlägt auf e7 – Beginn der gewinnenden Kombination."],"en":["A blow on the open file breaks the defence and wins.","The rook crashes in with tempo, then the threats pile up on the king.","Rook takes on e7 — opening the winning combination."],"hr":["Udarac po otvorenoj liniji slama obranu i dobiva.","Top upada s tempom, a prijetnje se gomilaju na kralju.","Top uzima na e7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.045' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein klassisches Läuferopfer reißt den Königsflügel auf und gewinnt.","Der Läufer schlägt am Königsrand ein, danach jagen Springer und Dame nach.","Läufer schlägt auf h7 – Auftakt der gewinnenden Kombination."],"en":["A classic bishop sacrifice tears open the kingside and wins.","The bishop strikes by the king, then the knight and queen pursue.","Bishop takes on h7 — launching the winning combination."],"hr":["Klasična žrtva lovca razbija kraljevo krilo i dobiva.","Lovac udara uz kralja, a potom skakač i dama nastavljaju lov.","Lovac uzima na h7 — početak dobitne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:012.046' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß steht auf Verlust und muss raffiniert ins Remis steuern.","Eine Schlagfolge fegt das Material weg und steuert auf ein Patt zu.","Läufer schlägt auf d5 – Beginn der rettenden Folge zum Remis."],"en":["White is losing and must steer cleverly toward a draw.","A string of exchanges sweeps the material away and heads for stalemate.","Bishop takes on d5 — starting the saving sequence to a draw."],"hr":["Bijeli gubi i mora se dovitljivo provući do remija.","Niz zamjena pomete materijal i vodi prema patu.","Lovac uzima na d5 — početak niza koji spašava remi."]}', HintsVersion=1 WHERE LineId LIKE '%:012.047' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlagopfer öffnet den König und entscheidet zugunsten des Nachziehenden.","Der Springer schlägt ein, danach dringen Dame und Bauer entscheidend vor.","Springer schlägt auf g3 – Beginn der gewinnenden Folge."],"en":["A capturing sacrifice opens the king and decides for Black.","The knight strikes, then the queen and pawn break through decisively.","Knight takes on g3 — beginning the winning sequence."],"hr":["Žrtva uzimanjem otvara kralja i odlučuje u korist crnoga.","Skakač udara, a potom dama i pješak odlučno probijaju.","Skakač uzima na g3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:012.048' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Bauernendspiel gewinnt ein präziser Königszug entscheidend.","Der König rückt vor und zwingt den Gegner in den Zugzwang.","König nach d4 – Beginn des gewinnenden Plans."],"en":["In the pawn ending a precise king move wins decisively.","The king advances and squeezes the opponent into zugzwang.","King to d4 — starting the winning plan."],"hr":["U pješačkoj završnici precizan kraljev potez odlučno dobiva.","Kralj napreduje i tjera protivnika u cugcvang.","Kralj na d4 — početak dobitnog plana."]}', HintsVersion=1 WHERE LineId LIKE '%:012.049' AND BookFileName='chessable-u5-49693.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenmanöver schließt den König ein und entscheidet die Partie.","Die Dame schwenkt in die Ecke, um dem König alle Fluchtfelder zu nehmen.","Dame nach h1 – Beginn der gewinnenden Folge."],"en":["A queen manoeuvre cages the king and decides the game.","The queen swings to the corner to strip the king of every escape.","Queen to h1 — beginning the winning sequence."],"hr":["Manevar dame zatvara kralja i odlučuje partiju.","Dama se okreće u kut da kralju oduzme sva polja bijega.","Dama na h1 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:012.050' AND BookFileName='chessable-u5-49693.pgn';
