UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel gewinnt ein präziser Königszug auf wunderschöne Weise.","Der König treibt den gegnerischen Springer in die Enge, dann laufen die Bauern durch.","König nach d4 – Beginn des gewinnenden Plans."],"en":["In the ending a precise king move wins in beautiful fashion.","The king herds the enemy knight into a corner, then the pawns run through.","King to d4 — starting the winning plan."],"hr":["U završnici precizan kraljev potez dobiva na prekrasan način.","Kralj tjera protivničkog skakača u kut, a potom pješaci prolaze.","Kralj na d4 — početak dobitnog plana."]}', HintsVersion=1 WHERE LineId LIKE '%:012.055' AND BookFileName='chessable-u5-49693.pgn';
