UPDATE BookPuzzles SET HintsJson='{"de":["Eine ruhige Damenwendung bereitet den entscheidenden Gewinn vor.","Die Dame manövriert gegen die schwache Stellung und gewinnt Material.","Dame nach e3 – Beginn der gewinnenden Folge."],"en":["A quiet queen turn prepares the decisive win.","The queen manoeuvres against the weak setup and wins material.","Queen to e3 — beginning the winning sequence."],"hr":["Tihi okret dame priprema odlučujući dobitak.","Dama manevrira protiv slabog postava i osvaja materijal.","Dama na e3 — početak dobitnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:012.058' AND BookFileName='chessable-u5-49693.pgn';
