UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schlag auf dem Königsflügel gewinnt entscheidend Material.","Die Springer manövrieren tief in die schwarze Stellung hinein.","Springer schlägt auf f5 – beginnt die gewinnende Kombination."],"en":["A kingside blow wins material decisively.","The knights maneuver deep into Black''s position.","Knight takes on f5 — starting the winning combination."],"hr":["Udarac na kraljevu krilu osvaja materijal odlučno.","Skakači manevriraju duboko u crnu poziciju.","Skakač uzima na f5 — započinje dobitnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:012.068' AND BookFileName='chessable-u5-49693.pgn';
