UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – ein Opfer reißt die Königsstellung auf.","Die Dame opfert sich, dann setzt ein Turm an der Seitenlinie matt.","Dame schlägt auf h7 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is hiding here — a sacrifice tears open the king''s shelter.","The queen sacrifices itself, then a rook delivers mate along the side.","Queen takes on h7 — the start of a forced mate."],"hr":["Ovdje se krije prisilni mat — žrtva razbija kraljevo sklonište.","Dama se žrtvuje, a potom top matira po bočnoj liniji.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – ein Opfer öffnet den König.","Erst opfert sich der Turm, dann liefert die Dame das Matt.","Turm schlägt auf h7 – Beginn der Mattkombination."],"en":["A forced mate is in the air — a sacrifice exposes the king.","The rook sacrifices first, then the queen delivers mate.","Rook takes on h7 — the start of the mating combination."],"hr":["Prisilni mat je u zraku — žrtva otvara kralja.","Top se prvo žrtvuje, a zatim dama matira.","Top uzima na h7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – Turm und Springer arbeiten zusammen.","Der Springer beherrscht die Fluchtfelder, der Turm gibt den letzten Stoß.","Turm nach g3 – Auftakt zum erzwungenen Matt."],"en":["There is a forced mate — rook and knight work together.","The knight controls the escape squares while the rook lands the blow.","Rook to g3 — the start of a forced mate."],"hr":["Postoji prisilni mat — top i skakač surađuju.","Skakač drži polja za bijeg dok top zadaje udarac.","Top na g3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – eine stille Umwandlung leitet es ein.","Ein Bauer wird zum Springer und treibt mit Hilfe der Figuren den König ins Netz.","Bauer wird zum Springer auf f8 – Beginn der Mattfolge."],"en":["A forced mate awaits — a quiet promotion sets it up.","A pawn becomes a knight and, with the pieces, snares the king.","Pawn promotes to a knight on f8 — the start of the mating sequence."],"hr":["Čeka prisilni mat — tiha promocija ga priprema.","Pješak postaje skakač i s figurama hvata kralja u mrežu.","Pješak se promovira u skakača na f8 — početak matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steht ein erzwungenes Matt – der Springer dirigiert den feindlichen König.","Der Springer schneidet Felder ab, dann setzt der Turm matt.","Springer nach c3 – Auftakt zum erzwungenen Matt."],"en":["A forced mate stands here — the knight herds the enemy king.","The knight cuts off squares, then the rook delivers mate.","Knight to c3 — the start of a forced mate."],"hr":["Ovdje stoji prisilni mat — skakač tjera neprijateljskog kralja.","Skakač odsijeca polja, a zatim top matira.","Skakač na c3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – ein Damenopfer öffnet die Ecke für den Springer.","Die Dame opfert sich, dann erstickt der Springer den König.","Dame nach g8 – Beginn des erstickten Matts."],"en":["A forced mate looms — a queen sacrifice opens the corner for the knight.","The queen sacrifices, then the knight smothers the king.","Queen to g8 — the start of the smothered mate."],"hr":["Prijeti prisilni mat — žrtva dame otvara kut za skakača.","Dama se žrtvuje, a zatim skakač guši kralja.","Dama na g8 — početak ugušenog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – ein Damenopfer lockt einen Bauern weg.","Die Dame opfert sich, dann setzt der Springer den eingeengten König matt.","Dame nach h6 – Auftakt zum erzwungenen Matt."],"en":["There is a forced mate — a queen sacrifice lures a pawn away.","The queen sacrifices, then the knight mates the boxed-in king.","Queen to h6 — the start of a forced mate."],"hr":["Postoji prisilni mat — žrtva dame odvlači pješaka.","Dama se žrtvuje, a zatim skakač matira sputanog kralja.","Dama na h6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zug genügt zum Matt – der Springer in der Ecke ist tödlich.","Der Springer allein vollendet das Matt am Rand.","Springer nach f7 – matt."],"en":["A single move mates — the knight at the edge is lethal.","The knight alone completes the mate by the corner.","Knight to f7 — mate."],"hr":["Jedan potez matira — skakač uz rub je smrtonosan.","Sam skakač dovršava mat u kutu.","Skakač na f7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – ein Turmopfer zerrt den König an den Rand.","Der Turm opfert sich und kehrt zurück, um matt zu setzen.","Turm schlägt auf g7 – Beginn der Mattfolge."],"en":["A forced mate is here — a rook sacrifice drags the king to the edge.","The rook sacrifices, then returns to deliver mate.","Rook takes on g7 — the start of the mating sequence."],"hr":["Ovdje je prisilni mat — žrtva topa vuče kralja na rub.","Top se žrtvuje, a zatim se vraća da matira.","Top uzima na g7 — početak matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – zwei Türme rollen die letzte Reihe auf.","Ein Turm opfert sich, der zweite Turm liefert das Grundreihenmatt.","Turm schlägt auf g7 – Auftakt zum erzwungenen Matt."],"en":["A forced mate awaits — two rooks roll up the back.","One rook sacrifices, the other rook delivers the back-rank mate.","Rook takes on g7 — the start of a forced mate."],"hr":["Čeka prisilni mat — dva topa razvaljuju zadnji red.","Jedan top se žrtvuje, drugi matira po zadnjem redu.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – ein Damenopfer und ein Läufer wirken zusammen.","Die Dame opfert sich, dann jagt der Turm den König dem Läufer entgegen.","Dame schlägt auf h7 – Beginn der Mattkombination."],"en":["A forced mate looms — a queen sacrifice and a bishop combine.","The queen sacrifices, then the rook drives the king onto the bishop.","Queen takes on h7 — the start of the mating combination."],"hr":["Prijeti prisilni mat — žrtva dame i lovac surađuju.","Dama se žrtvuje, a zatim top tjera kralja prema lovcu.","Dama uzima na h7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Damenopfer lockt den König heraus.","Die Dame opfert sich, dann fängt der Läufer den nackten König ein.","Dame schlägt auf d8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is present — a queen sacrifice lures the king out.","The queen sacrifices, then the bishop traps the bare king.","Queen takes on d8 — the start of a forced mate."],"hr":["Postoji prisilni mat — žrtva dame izvlači kralja.","Dama se žrtvuje, a zatim lovac hvata golog kralja.","Dama uzima na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – der Turm an der offenen Linie schlägt zu.","Der Turm wechselt die Linie und liefert dann das Matt am Rand.","Turm nach h3 – Beginn der Mattfolge."],"en":["There is a forced mate — the rook on the open file strikes.","The rook switches files, then delivers mate on the edge.","Rook to h3 — the start of the mating sequence."],"hr":["Postoji prisilni mat — top na otvorenoj liniji udara.","Top mijenja liniju, a zatim matira uz rub.","Top na h3 — početak matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Dame schwenkt zur entscheidenden Linie.","Die Dame manövriert herum und setzt mit dem Turm zusammen matt.","Dame nach a3 – Auftakt zum erzwungenen Matt."],"en":["A forced mate awaits — the queen swings to the decisive line.","The queen maneuvers around and mates together with the rook.","Queen to a3 — the start of a forced mate."],"hr":["Čeka prisilni mat — dama se prebacuje na odlučujuću liniju.","Dama manevrira i matira zajedno s topom.","Dama na a3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – wiederholte Opfer auf der offenen Linie zwingen es.","Die Schwerfiguren stürmen nacheinander die Linie, bis das Matt fällt.","Turm schlägt auf h1 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here — repeated sacrifices on the open file compel it.","The heavy pieces storm the file in turn until mate falls.","Rook takes on h1 — the start of the forced mating sequence."],"hr":["Ovdje je prisilni mat — uzastopne žrtve na otvorenoj liniji ga prisiljavaju.","Teške figure jurišaju linijom jedna za drugom dok ne padne mat.","Top uzima na h1 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.017' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – ein Läuferopfer reißt den König heraus.","Erst opfert sich der Läufer, dann setzt die Dame mit den Läufern matt.","Läufer schlägt auf h7 – Beginn der Mattkombination."],"en":["A forced mate looms — a bishop sacrifice drags the king out.","The bishop sacrifices first, then the queen mates with the bishops.","Bishop takes on h7 — the start of the mating combination."],"hr":["Prijeti prisilni mat — žrtva lovca izvlači kralja.","Lovac se prvo žrtvuje, a zatim dama matira uz lovce.","Lovac uzima na h7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.018' AND BookFileName='chessable-u5-243265.pgn';
