UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – die Dame nutzt das Bauernnetz um den König.","Die Dame schwenkt herum, während der eigene Bauer die Fluchtfelder versperrt.","Dame nach h3 – Beginn der Mattfolge."],"en":["There is a forced mate — the queen exploits the pawn net around the king.","The queen swings around while the friendly pawn blocks escape.","Queen to h3 — the start of the mating sequence."],"hr":["Postoji prisilni mat — dama iskorištava pješačku mrežu oko kralja.","Dama se prebacuje dok vlastiti pješak zatvara polja za bijeg.","Dama na h3 — početak matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.020' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – ein Turmopfer öffnet den König für die Dame.","Der Turm opfert sich, dann setzt die Dame im Zentrum des Königs matt.","Turm schlägt auf g7 – Auftakt zum erzwungenen Matt."],"en":["A forced mate awaits — a rook sacrifice opens the king for the queen.","The rook sacrifices, then the queen mates the king in the open.","Rook takes on g7 — the start of a forced mate."],"hr":["Čeka prisilni mat — žrtva topa otvara kralja za damu.","Top se žrtvuje, a zatim dama matira otkrivenog kralja.","Top uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.021' AND BookFileName='chessable-u5-243265.pgn';
