UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Türme zielen auf die siebte Reihe.","Ein Springer lockt eine Figur, dann walzen die Türme die Reihe nieder.","Springer schlägt auf e6 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here — the rooks aim at the seventh rank.","A knight lures a piece, then the rooks bulldoze the rank.","Knight takes on e6 — the start of the forced mating sequence."],"hr":["Ovdje je prisilni mat — topovi ciljaju sedmi red.","Skakač odvlači figuru, a zatim topovi gaze po redu.","Skakač uzima na e6 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.028' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – Turmopfer ziehen den König in die Falle.","Die Türme opfern sich nacheinander, dann setzt die Dame matt.","Turm schlägt auf f8 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate looms — rook sacrifices pull the king into the trap.","The rooks sacrifice one after another, then the queen mates.","Rook takes on f8 — the start of the forced mating sequence."],"hr":["Prijeti prisilni mat — žrtve topova uvlače kralja u zamku.","Topovi se žrtvuju jedan za drugim, a zatim dama matira.","Top uzima na f8 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.029' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Schwerfiguren stürmen die Grundreihe.","Die Dame räumt mit einem Opfer den Weg für den Turm auf der letzten Reihe.","Dame nach e4 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate awaits — the heavy pieces storm the back rank.","The queen clears the way with a sacrifice for the rook on the last rank.","Queen to e4 — the start of the forced mating sequence."],"hr":["Čeka prisilni mat — teške figure jurišaju na zadnji red.","Dama žrtvom krči put topu na posljednjem redu.","Dama na e4 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.030' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – ein Damenopfer öffnet die Linie für den Turm.","Die Dame opfert sich, dann walzt der Turm die Reihe zum Matt nieder.","Dame schlägt auf h7 – Beginn der Mattkombination."],"en":["A forced mate looms — a queen sacrifice opens the file for the rook.","The queen sacrifices, then the rook sweeps the rank to mate.","Queen takes on h7 — the start of the mating combination."],"hr":["Prijeti prisilni mat — žrtva dame otvara liniju za topa.","Dama se žrtvuje, a zatim top gazi red do mata.","Dama uzima na h7 — početak matne kombinacije."]}', HintsVersion=1 WHERE LineId LIKE '%:004.031' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – die Dame jagt den König ins eigene Bauernnetz.","Die Dame treibt den König herum, dann setzt sie ihn mit eigener Hilfe matt.","Dame schlägt auf g1 – Beginn der erzwungenen Mattfolge."],"en":["There is a forced mate — the queen chases the king into its own pawn net.","The queen drives the king around, then mates it with support nearby.","Queen takes on g1 — the start of the forced mating sequence."],"hr":["Postoji prisilni mat — dama tjera kralja u vlastitu pješačku mrežu.","Dama vrti kralja, a zatim ga matira uz blisku potporu.","Dama uzima na g1 — početak prisilne matne sekvence."]}', HintsVersion=1 WHERE LineId LIKE '%:004.032' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – treibe den König ins Eck.","Deine schwere Figur baut zusammen mit dem Turm ein tödliches Mattnetz auf.","Dame nach c6 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is here – drive the king into the box.","Your heavy piece teams up with the rook to weave a deadly net.","Queen to c6 – the start of the forced mate."],"hr":["Ovdje postoji prisilni mat — stjeraj kralja u kut.","Tvoja teška figura zajedno s topom plete smrtonosnu mrežu.","Dama na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.033' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der entblößte König erlaubt ein schnelles erzwungenes Matt.","Dame und Läufer schlagen gemeinsam auf der offenen Königsseite zu.","Dame nach h5 – Beginn des erzwungenen Matts."],"en":["The exposed king allows a quick forced mate.","The queen and bishop strike together on the open kingside.","Queen to h5 – the start of the forced mate."],"hr":["Otkriveni kralj dopušta brzi prisilni mat.","Dama i lovac zajedno udaraju na otvorenoj kraljevoj strani.","Dama na h5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.034' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der ungedeckte Königsbauer lädt zum klassischen Schnellmatt ein.","Die Dame, gestützt vom Läufer, liefert das Matt.","Dame schlägt auf f7 – matt."],"en":["The undefended king''s bishop pawn invites a classic quick mate.","The queen, backed by the bishop, delivers the blow.","Queen takes on f7 — mate."],"hr":["Nebranjeni lovčev pješak poziva na klasični brzi mat.","Dama, podržana lovcem, zadaje udarac.","Dama uzima na f7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:004.035' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt den König heraus und erzwingt das Matt.","Dein Läufer öffnet die Stellung, dann schließt der Springer das Netz.","Läufer schlägt auf f7 – Auftakt zum erzwungenen Matt."],"en":["A sacrifice drags the king out and forces mate.","Your bishop rips the position open, then the knight closes the net.","Bishop takes on f7 — the start of the forced mate."],"hr":["Žrtva izvlači kralja i prisiljava mat.","Tvoj lovac otvara položaj, potom skakač zatvara mrežu.","Lovac uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:004.036' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein erzwungenes Matt im Stil von Anastasia.","Der Springer schnürt dem König die Fluchtfelder zu, der Turm beendet es.","Springer nach e7 – Auftakt zum erzwungenen Matt."],"en":["A forced Anastasia-style mate is waiting here.","The knight seals the king''s escape squares while the rook finishes.","Knight to e7 — the start of the forced mate."],"hr":["Ovdje čeka prisilni mat u stilu Anastazije.","Skakač zatvara kralju polja za bijeg, a top dovršava posao.","Skakač na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf der Königsseite leitet ein erzwungenes Matt ein.","Die Dame öffnet die Linie, der zweite Schwerstein gibt das Matt.","Dame schlägt auf h7 – Beginn des erzwungenen Matts."],"en":["A sacrifice on the kingside leads to a forced mate.","The queen pries the file open and a second heavy piece mates.","Queen takes on h7 — the start of the forced mate."],"hr":["Žrtva na kraljevoj strani vodi u prisilni mat.","Dama otvara liniju, a druga teška figura daje mat.","Dama uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer-Eingriff bahnt ein erzwungenes Anastasia-Matt an.","Der Springer fesselt den König, dann öffnet ein Turmopfer die Linie.","Springer nach e7 – Auftakt zum erzwungenen Matt."],"en":["A knight intrusion sets up a forced Anastasia mate.","The knight pins the king down, then a rook sacrifice opens the file.","Knight to e7 — the start of the forced mate."],"hr":["Upad skakača priprema prisilni Anastazijin mat.","Skakač sputava kralja, potom žrtva topa otvara liniju.","Skakač na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du stehst zum Schlag bereit – ein erzwungenes Matt liegt in der Luft.","Ein Damenopfer reißt die Linie auf, dann mattet der Turm.","Dame schlägt auf h2 – Beginn des erzwungenen Matts."],"en":["You are poised to strike – a forced mate is in the air.","A queen sacrifice tears open the file, then the rook mates.","Queen takes on h2 — the start of the forced mate."],"hr":["Spreman si za udarac — prisilni mat visi u zraku.","Žrtva dame otvara liniju, potom top daje mat.","Dama uzima na h2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:005.005' AND BookFileName='chessable-u5-243265.pgn';
