UPDATE BookPuzzles SET HintsJson='{"de":["Ein Erstickungsmatt ist erzwingbar.","Ein Damenopfer öffnet die Königsstellung, dann übernehmen Läufer und Springer.","Dame schlägt auf g2 – beginnt die erzwungene Mattführung."],"en":["A suffocation mate can be forced.","A queen sacrifice opens the king''s position, then bishop and knight take over.","Queen takes on g2 — starts the forced mating sequence."],"hr":["Mat gušenjem može se prisiliti.","Žrtva dame otvara kraljevu poziciju, a zatim lovac i skakač preuzimaju.","Dama uzima na g2 — započinje prisilni niz za mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt im Brett.","Der Springer deckt die Fluchtfelder ab, während der Läufer das Matt setzt.","Springer nach f6 – beginnt die erzwungene Mattführung."],"en":["A forced mate is on the board.","The knight covers the escape squares while the bishop delivers mate.","Knight to f6 — starts the forced mating sequence."],"hr":["Na ploči je prisilni mat.","Skakač pokriva polja za bijeg dok lovac zadaje mat.","Skakač na f6 — započinje prisilni niz za mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.014' AND BookFileName='chessable-u5-243265.pgn';
