UPDATE BookPuzzles SET HintsJson='{"de":["Ein Erstickungsmatt ist erzwingbar.","Die Dame stört zuerst, dann öffnen Springer- und Bauernschläge die Diagonale für den Läufer.","Dame nach e5 – beginnt die erzwungene Mattführung."],"en":["A suffocation mate can be forced.","The queen interferes first, then knight and pawn captures open the diagonal for the bishop.","Queen to e5 — starts the forced mating sequence."],"hr":["Mat gušenjem može se prisiliti.","Dama prvo ometa, a zatim skakačeva i pješačka uzimanja otvaraju dijagonalu lovcu.","Dama na e5 — započinje prisilni niz za mat."]}', HintsVersion=1 WHERE LineId LIKE '%:011.016' AND BookFileName='chessable-u5-243265.pgn';
