UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – ein Opfer räumt den Schlüsselverteidiger weg.","Die Dame opfert sich, damit der Springer das Eckmatt vollendet.","Dame schlägt auf d8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is here – a sacrifice clears away the key defender.","The queen gives herself up so the knight can finish in the corner.","Queen takes on d8 — starting the forced mate."],"hr":["Prisilni mat je tu — žrtva uklanja ključnog branitelja.","Dama se žrtvuje da skakač završi mat u kutu.","Dama uzima na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König in der Ecke lässt sich erzwungen mattsetzen.","Ein Springer liefert das Eckmatt, gestützt durch die Linie.","Springer nach c2 – matt."],"en":["The cornered king can be forced into mate.","A knight delivers the corner mate, backed by the open file.","Knight to c2 — mate."],"hr":["Kralja u kutu se može prisilno matirati.","Skakač daje mat u kutu, podržan otvorenom linijom.","Skakač na c2 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:012.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – zwei Drohungen lassen sich nicht beide parieren.","Turm und Springer arbeiten zusammen am Eckmatt.","Turm nach g4 – Beginn des erzwungenen Matts."],"en":["A forced mate looms — two threats cannot both be met.","Rook and knight combine for the corner mate.","Rook to g4 — starting the forced mate."],"hr":["Prijeti prisilni mat — obje prijetnje ne mogu se odbiti.","Top i skakač zajedno spremaju mat u kutu.","Top na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:012.004' AND BookFileName='chessable-u5-243265.pgn';
