UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Opfer entfernt den Verteidiger des Mattfelds.","Dameopfer beseitigt den Springer, dann setzt der Turm matt.","Dame schlägt auf b8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is available — a sacrifice removes the guard of the mating square.","A queen sacrifice eliminates the knight, then the rook mates.","Queen takes on b8 — starting the forced mate."],"hr":["Prisilni mat je tu — žrtva uklanja čuvara matnog polja.","Žrtva dame uklanja skakača, a zatim top daje mat.","Dama uzima na b8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein Opfer reißt den Verteidiger des Mattfelds weg.","Dameopfer beseitigt den Springer, dann setzt der Turm matt.","Dame schlägt auf b8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is in here — a sacrifice tears away the guard of the mating square.","A queen sacrifice removes the knight, then the rook mates.","Queen takes on b8 — starting the forced mate."],"hr":["Ovdje je prisilni mat — žrtva uklanja čuvara matnog polja.","Žrtva dame uklanja skakača, a zatim top daje mat.","Dama uzima na b8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist vorhanden – ein Opfer beseitigt den einzigen Verteidiger.","Dameopfer lenkt den letzten Verteidiger ab, dann setzt der Turm matt.","Dame schlägt auf c6 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is available — a sacrifice removes the only defender.","A queen sacrifice deflects the last guard, then the rook mates.","Queen takes on c6 — starting the forced mate."],"hr":["Prisilni mat je tu — žrtva uklanja jedinog branitelja.","Žrtva dame skreće posljednjeg branitelja, a zatim top daje mat.","Dama uzima na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der Turm setzt auf der Grundreihe.","Erst wird der deckende Läufer abgelenkt, dann setzt der Turm matt.","Dame schlägt auf d8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is available — the rook mates on the back rank.","First the guarding bishop is deflected, then the rook mates.","Queen takes on d8 — starting the forced mate."],"hr":["Prisilni mat je tu — top mati na zadnjoj liniji.","Najprije se odmami lovac branitelj, a zatim top daje mat.","Dama uzima na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein Opfer öffnet die Bahn für den Turm.","Der Läufer opfert sich, damit der Turm auf der Grundreihe matt setzt.","Läufer schlägt auf d5 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is in here — a sacrifice clears the path for the rook.","The bishop sacrifices itself so the rook mates on the back rank.","Bishop takes on d5 — starting the forced mate."],"hr":["Ovdje je prisilni mat — žrtva otvara put topu.","Lovac se žrtvuje da top da mat na zadnjoj liniji.","Lovac uzima na d5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Opfer zwingt den König ins Mattnetz.","Dameopfer und Läuferdeckung bereiten das Turmmatt vor.","Dame schlägt auf h8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is available — a sacrifice forces the king into the net.","A queen sacrifice and the bishop''s cover set up the rook mate.","Queen takes on h8 — starting the forced mate."],"hr":["Prisilni mat je tu — žrtva tjera kralja u matnu mrežu.","Žrtva dame i zaštita lovca pripremaju mat topom.","Dama uzima na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:015.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein forciertes Matt – treibe den feindlichen König ins Verderben.","Türme öffnen die Reihe, dann setzt der Läufer auf der langen Diagonale den Schlusspunkt.","Turm nach h8 leitet das forcierte Matt ein."],"en":["A forced mate is hiding here — drive the enemy king into the net.","Rooks pry open the back rank, then the bishop on the long diagonal lands the blow.","Rook to h8 begins the forced mating line."],"hr":["Ovdje se krije prisilni mat — natjeraj protivničkog kralja u mrežu.","Topovi otvaraju zadnji red, a lovac na dugoj dijagonali zadaje završni udarac.","Top na h8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt in der Luft – der König ist nicht zu retten.","Das Damenopfer zerstört die Königsstellung, dann übernimmt der Läufer auf der Diagonale.","Dame schlägt auf g8 und beginnt das forcierte Matt."],"en":["A forced mate is in the air — the king cannot survive.","A queen sacrifice rips open the shelter, then the bishop takes over on the diagonal.","Queen takes on g8 to start the forced mate."],"hr":["Prisilni mat visi u zraku — kralj se ne može spasiti.","Žrtva dame ruši zaklon, a zatim lovac preuzima na dijagonali.","Dama uzima na g8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du hast ein forciertes Matt gegen den unrochierten König.","Ein Damenopfer auf der Grundreihe lockt den König, dann entscheidet der Läufer.","Dame schlägt auf d1 und leitet das forcierte Matt ein."],"en":["You have a forced mate against the exposed king.","A queen sacrifice on the back rank lures the king, then the bishop decides.","Queen takes on d1 to begin the forced mate."],"hr":["Imaš prisilni mat protiv izloženog kralja.","Žrtva dame na zadnjem redu mami kralja, a zatim lovac odlučuje.","Dama uzima na d1 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Zug setzt matt.","Der Läufer gibt das Matt, der Turm deckt und sperrt die Fluchtfelder.","Läufer schlägt auf d8 – matt."],"en":["A single move delivers mate.","The bishop gives mate while the rook guards it and seals the escape squares.","Bishop takes on d8 — mate."],"hr":["Jedan jedini potez daje mat.","Lovac daje mat dok ga top čuva i zatvara polja za bijeg.","Lovac uzima na d8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein forciertes Matt gegen den König in der Mitte.","Ein Damenopfer zieht den König heran, dann setzen Läufer und Turm gemeinsam matt.","Dame schlägt auf d8 und beginnt das forcierte Matt."],"en":["A forced mate is hiding against the king stuck in the centre.","A queen sacrifice drags the king forward, then bishop and rook mate together.","Queen takes on d8 to start the forced mate."],"hr":["Ovdje se krije prisilni mat protiv kralja u centru.","Žrtva dame privlači kralja, a zatim lovac i top zajedno matiraju.","Dama uzima na d8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zug genügt zum Matt auf der Grundreihe.","Der Turm liefert das Matt, ein Bauer stützt ihn von hinten.","Turm nach h8 – matt."],"en":["One move mates on the back rank.","The rook delivers mate while a pawn supports it from behind.","Rook to h8 — mate."],"hr":["Jedan potez matira na zadnjem redu.","Top daje mat dok ga pješak podupire straga.","Top na h8 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet – der König wird in die Ecke getrieben.","Bauern und Figuren reißen den Königsschild auf, der Turm vollendet auf der Reihe.","Dame schlägt auf h7 und leitet das forcierte Matt ein."],"en":["A forced mate awaits — the king gets herded into the corner.","Pawns and pieces tear off the king''s cover, the rook finishes on the rank.","Queen takes on h7 to begin the forced mate."],"hr":["Čeka prisilni mat — kralj se tjera u kut.","Pješaci i figure kidaju kraljev zaklon, top dovršava na redu.","Dama uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:015.017' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt bereit – der König hat kaum Luft.","Ein Turmopfer lockt den König, dann krönt der gestützte Dame-Bauern-Block das Werk.","Turm schlägt auf f8 und beginnt das forcierte Matt."],"en":["A forced mate is ready — the king has almost no air.","A rook sacrifice lures the king, then the pawn-backed queen finishes.","Rook takes on f8 to start the forced mate."],"hr":["Prisilni mat je spreman — kralj jedva diše.","Žrtva topa mami kralja, a zatim dama uz potporu pješaka dovršava.","Top uzima na f8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein forciertes Matt gegen den eingeengten König.","Ein Turmopfer zieht den König aufs Schlachtfeld, der gestützte Dame setzt matt.","Turm schlägt auf g8 und leitet das forcierte Matt ein."],"en":["A forced mate is hiding against the cramped king.","A rook sacrifice pulls the king out, the pawn-supported queen mates.","Rook takes on g8 to begin the forced mate."],"hr":["Ovdje se krije prisilni mat protiv stiješnjenog kralja.","Žrtva topa izvlači kralja, a dama uz potporu pješaka matira.","Top uzima na g8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist vorhanden – der König steht völlig offen.","Erst wird die Bauernkette gesprengt, dann opfert sich ein Turm, und die Dame entscheidet.","Bauer schlägt auf e6 und beginnt das forcierte Matt."],"en":["A forced mate is there — the king stands completely exposed.","First the pawn chain is cracked, then a rook is offered and the queen decides.","Pawn takes on e6 to start the forced mate."],"hr":["Prisilni mat postoji — kralj je posve izložen.","Najprije se razbija pješački lanac, zatim se žrtvuje top, a dama odlučuje.","Pješak uzima na e6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet auf den entblößten König.","Erst lockt ein Läuferopfer den König, dann Dame und Turm – der gestützte Dame schließt ab.","Läufer schlägt auf h7 und leitet das forcierte Matt ein."],"en":["A forced mate awaits the stripped-bare king.","A bishop sacrifice draws the king, then queen and rook close in for the kill.","Bishop takes on h7 to begin the forced mate."],"hr":["Prisilni mat čeka ogoljenog kralja.","Žrtva lovca privlači kralja, zatim dama i top zatvaraju mrežu.","Lovac uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit gegen den nackten König.","Türme räumen die Bahn für die Dame, die gestützt den Schlussstrich zieht.","Turm schlägt auf f7 und beginnt das forcierte Matt."],"en":["A forced mate is ready against the bare king.","Rooks clear the path for the queen, which lands the supported finish.","Rook takes on f7 to start the forced mate."],"hr":["Prisilni mat je spreman protiv golog kralja.","Topovi krče put dami, koja uz potporu zadaje završni udarac.","Top uzima na f7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – ein Verteidiger muss nur beseitigt werden.","Ein Opfer entfernt den Beschützer, dann jagt der Turm den König und die gestützte Dame setzt matt.","Dame schlägt auf g6 und leitet das forcierte Matt ein."],"en":["A forced mate is here — only a defender must be removed.","A sacrifice eliminates the guard, then the rook hunts the king and the supported queen mates.","Queen takes on g6 to begin the forced mate."],"hr":["Prisilni mat postoji — treba samo ukloniti branitelja.","Žrtva uklanja čuvara, zatim top lovi kralja, a dama uz potporu matira.","Dama uzima na g6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt vor – der gestützte Dame liefert es.","Ein Turmopfer beseitigt den letzten Verteidiger, dann schlägt die Dame zu.","Turm schlägt auf h6 und beginnt das forcierte Matt."],"en":["A forced mate is at hand — a supported queen delivers it.","A rook sacrifice removes the last defender, then the queen strikes.","Rook takes on h6 to start the forced mate."],"hr":["Prisilni mat je nadohvat — dama uz potporu ga zadaje.","Žrtva topa uklanja posljednjeg branitelja, zatim dama udara.","Top uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet auf den verteidigerlosen König.","Ein Läuferopfer öffnet den König, Dame jagt ihn, der gestützte Dame schließt ab.","Läufer schlägt auf h7 und leitet das forcierte Matt ein."],"en":["A forced mate awaits the king without defenders.","A bishop sacrifice opens the king, the queen hunts and the supported queen finishes.","Bishop takes on h7 to begin the forced mate."],"hr":["Prisilni mat čeka kralja bez branitelja.","Žrtva lovca otvara kralja, dama ga lovi i uz potporu dovršava.","Lovac uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein forciertes Matt – Schwarz schlägt zu.","Ein Turmopfer lockt den weißen Turm, dann reiht sich die Dame zum Mattmuster auf.","Turm schlägt auf e1 und beginnt das forcierte Matt."],"en":["A forced mate is hiding here — Black strikes.","A rook sacrifice lures the white rook, then the queen lines up the mating pattern.","Rook takes on e1 to start the forced mate."],"hr":["Ovdje se krije prisilni mat — crni udara.","Žrtva topa mami bijelog topa, a zatim se dama postavlja u matni obrazac.","Top uzima na e1 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – Schwarz erlegt den rochierten König.","Erst wird der einzige Verteidiger abgelenkt, dann arbeiten Dame und Turm zusammen.","Springer nach f3 leitet das forcierte Matt ein."],"en":["A forced mate is here — Black hunts down the castled king.","First the sole defender is deflected, then queen and rook combine.","Knight to f3 begins the forced mate."],"hr":["Prisilni mat postoji — crni obara rokiranog kralja.","Najprije se odvlači jedini branitelj, a zatim dama i top surađuju.","Skakač na f3 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:016.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt bereit – der König wird in die Ecke gezogen.","Ein Turmopfer lockt den König, dann setzt der gestützte Dame matt.","Turm schlägt auf h8 und beginnt das forcierte Matt."],"en":["A forced mate is ready — the king is dragged into the corner.","A rook sacrifice lures the king, then the supported queen mates.","Rook takes on h8 to start the forced mate."],"hr":["Prisilni mat je spreman — kralj se uvlači u kut.","Žrtva topa mami kralja, a zatim dama uz potporu matira.","Top uzima na h8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bevor gegen den König in der Ecke.","Erst öffnet ein Bauernzug die Linie, dann lockt ein Turmopfer und die Dame vollendet.","Bauer schlägt auf g6 und leitet das forcierte Matt ein."],"en":["A forced mate looms against the king in the corner.","First a pawn move opens the file, then a rook sacrifice lures and the queen finishes.","Pawn takes on g6 to begin the forced mate."],"hr":["Prijeti prisilni mat protiv kralja u kutu.","Najprije pješak otvara liniju, zatim žrtva topa mami, a dama dovršava.","Pješak uzima na g6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist vorhanden – die Türme treiben den König hin und her.","Wiederholte Turmopfer locken den König, dann setzt der gestützte Dame matt.","Turm schlägt auf h8 und beginnt das forcierte Matt."],"en":["A forced mate is there — the rooks bounce the king back and forth.","Repeated rook sacrifices lure the king, then the supported queen mates.","Rook takes on h8 to start the forced mate."],"hr":["Prisilni mat postoji — topovi bacaju kralja naprijed-natrag.","Ponovljene žrtve topova mame kralja, a zatim dama uz potporu matira.","Top uzima na h8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – Schwarz holt den eingeengten König.","Ein Turmopfer auf der Reihe lockt den König, dann übernimmt die Dame.","Turm schlägt auf h2 und beginnt das forcierte Matt."],"en":["A forced mate is here — Black collars the cramped king.","A rook sacrifice on the rank lures the king, then the queen takes over.","Rook takes on h2 to start the forced mate."],"hr":["Prisilni mat postoji — crni hvata stiješnjenog kralja.","Žrtva topa na redu mami kralja, a zatim dama preuzima.","Top uzima na h2 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt vor – Schwarz wirft Turm um Turm in den Kampf.","Mehrere Turmopfer ziehen den König heran, dann setzt der letzte Turm gestützt matt.","Turm nach h8 leitet das forcierte Matt ein."],"en":["A forced mate is at hand — Black throws rook after rook into the fray.","Several rook sacrifices draw the king, then the last rook mates with support.","Rook to h8 begins the forced mate."],"hr":["Prisilni mat je nadohvat — crni baca top za topom u napad.","Nekoliko žrtava topova privlači kralja, a posljednji top uz potporu matira.","Top na h8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – ein Verteidiger muss weichen.","Ein Turmopfer lenkt den Beschützer ab, dann setzt der gestützte Dame matt.","Turm schlägt auf f8 und beginnt das forcierte Matt."],"en":["A forced mate is ready — a defender must be removed.","A rook sacrifice distracts the guard, then the supported queen mates.","Rook takes on f8 to start the forced mate."],"hr":["Prisilni mat je spreman — branitelj mora pasti.","Žrtva topa odvlači čuvara, a zatim dama uz potporu matira.","Top uzima na f8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet – der König ist in der Ecke gefangen.","Ein Turmopfer lenkt den Verteidiger ab, dann öffnet ein Schlag den König für die Dame.","Turm schlägt auf c8 und leitet das forcierte Matt ein."],"en":["A forced mate awaits — the king is trapped in the corner.","A rook sacrifice diverts the defender, then a capture opens the king for the queen.","Rook takes on c8 to begin the forced mate."],"hr":["Prisilni mat čeka — kralj je zarobljen u kutu.","Žrtva topa odvlači branitelja, a zatim udarac otvara kralja dami.","Top uzima na c8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da gegen den eingeengten König.","Erst droht die Dame, dann lenkt ein Springeropfer den Verteidiger ab, und die Dame setzt matt.","Dame schlägt auf h6 und beginnt das forcierte Matt."],"en":["A forced mate is here against the cramped king.","First the queen threatens, then a knight sacrifice diverts the defender and the queen mates.","Queen takes on h6 to start the forced mate."],"hr":["Prisilni mat postoji protiv stiješnjenog kralja.","Najprije dama prijeti, zatim žrtva skakača odvlači branitelja, a dama matira.","Dama uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt vor – der König wird über das Brett gejagt.","Erst lenkt ein Läuferopfer den Verteidiger ab, dann treibt die Dame den König ins Matt.","Dame schlägt auf h7 und leitet das forcierte Matt ein."],"en":["A forced mate is at hand — the king is chased across the board.","First a bishop sacrifice diverts the defender, then the queen drives the king into mate.","Queen takes on h7 to begin the forced mate."],"hr":["Prisilni mat je nadohvat — kralj se goni preko ploče.","Najprije žrtva lovca odvlači branitelja, a zatim dama tjera kralja u mat.","Dama uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – Schwarz schlägt entscheidend zu.","Ein Turmopfer auf der Linie öffnet die Stellung, dann setzt die gestützte Dame matt.","Dame nach h3 leitet das forcierte Matt ein."],"en":["A forced mate is here — Black strikes decisively.","A rook sacrifice on the file opens the position, then the supported queen mates.","Queen to h3 begins the forced mate."],"hr":["Prisilni mat postoji — crni odlučno udara.","Žrtva topa na liniji otvara položaj, a zatim dama uz potporu matira.","Dama na h3 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:017.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt bereit – Dame und Läufer arbeiten zusammen.","Mit Schachs treibt der Läufer den König in Linie, dann setzt die gestützte Dame am Rand matt.","Dame nach e8 leitet das forcierte Matt ein."],"en":["A forced mate is ready — queen and bishop work as a team.","Checks herd the king into line with the bishop, then the supported queen mates at the edge.","Queen to e8 begins the forced mate."],"hr":["Prisilni mat je spreman — dama i lovac rade zajedno.","Šahovima lovac tjera kralja u liniju, a zatim dama uz potporu matira na rubu.","Dama na e8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist vorhanden gegen den König in der Ecke.","Ein Läuferopfer öffnet den König, dann setzt die gestützte Dame am Rand matt.","Läufer schlägt auf h7 und beginnt das forcierte Matt."],"en":["A forced mate is there against the king in the corner.","A bishop sacrifice opens the king, then the supported queen mates at the edge.","Bishop takes on h7 to start the forced mate."],"hr":["Prisilni mat postoji protiv kralja u kutu.","Žrtva lovca otvara kralja, a zatim dama uz potporu matira na rubu.","Lovac uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet – die Leichtfeld-Schwächen werden ausgenutzt.","Mit Damen- und Läuferschachs wird der König gestellt, dann setzt die gestützte Dame matt.","Dame schlägt auf g8 und leitet das forcierte Matt ein."],"en":["A forced mate awaits — the light-square weaknesses are exploited.","Queen and bishop checks corner the king, then the supported queen mates.","Queen takes on g8 to begin the forced mate."],"hr":["Prisilni mat čeka — iskorištavaju se slabosti na bijelim poljima.","Šahovi dame i lovca stjeruju kralja, a zatim dama uz potporu matira.","Dama uzima na g8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwachen weißen Felder rund um den schwarzen König erlauben ein erzwungenes Matt.","Dame und die beiden Springer jagen den König gemeinsam in die Ecke.","Mit der Dame nach h4 beginnt die erzwungene Mattfolge."],"en":["The weak light squares around Black''s king allow a forced mate.","Your queen and the two knights hunt the king together into the corner.","Queen to h4 starts the forced mating sequence."],"hr":["Slaba bijela polja oko crnog kralja omogućuju prisilni mat.","Dama i oba skakača zajedno tjeraju kralja u kut.","Dama na h4 započinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Auf den dunklen Feldern wartet ein erzwungenes Matt.","Dame und der dunkelfeldrige Läufer arbeiten gegen den eingeengten König zusammen.","Die Dame nach h4 eröffnet die Mattjagd."],"en":["A forced mate is waiting on the dark squares.","The queen and the dark-squared bishop combine against the boxed-in king.","Queen to h4 opens the mating hunt."],"hr":["Na tamnim poljima čeka prisilni mat.","Dama i tamnopoljni lovac surađuju protiv stiješnjenog kralja.","Dama na h4 otvara lov na mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht zu offen – ein erzwungenes Matt ist da.","Dame und Läufer schließen den König auf den dunklen Feldern ein.","Die Dame nach h4 leitet die Mattfolge ein."],"en":["The white king is too exposed — a forced mate is there.","Queen and bishop seal the king in on the dark squares.","Queen to h4 launches the mating line."],"hr":["Bijeli kralj je previše izložen — tu je prisilni mat.","Dama i lovac zatvaraju kralja na tamnim poljima.","Dama na h4 pokreće niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:018.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist mattreif – mit Gewalt geht es zum Matt.","Dame und der dunkelfeldrige Läufer treiben den König ins Verderben.","Die Dame nach h4 startet die erzwungene Folge."],"en":["The white king is ripe for mate — force it home.","Queen and the dark-squared bishop drive the king to ruin.","Queen to h4 begins the forced sequence."],"hr":["Bijeli kralj je zreo za mat — silom ga dovedi do kraja.","Dama i tamnopoljni lovac tjeraju kralja u propast.","Dama na h4 započinje prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:018.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Bauernopfer öffnet die Linien zum erzwungenen Matt.","Dame und Läufer dringen über die geöffneten Felder zum König vor.","Die Dame schlägt auf e4 und beginnt die Mattjagd."],"en":["A pawn sacrifice rips open the lines for a forced mate.","Queen and bishop break through to the king over the opened squares.","Queen takes on e4 and the mating hunt begins."],"hr":["Žrtva pijuna otvara linije za prisilni mat.","Dama i lovac probijaju do kralja preko otvorenih polja.","Dama uzima na e4 i počinje lov na mat."]}', HintsVersion=1 WHERE LineId LIKE '%:018.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand erlaubt ein erzwungenes Matt.","Die Dame setzt matt, vom Läufer gedeckt.","Die Dame nach h6 beginnt die Mattfolge."],"en":["The king at the edge allows a forced mate.","The queen delivers mate, shielded by the bishop.","Queen to h6 begins the mating line."],"hr":["Kralj na rubu dopušta prisilni mat.","Dama matira, zaštićena lovcem.","Dama na h6 započinje niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.002' AND BookFileName='chessable-u5-243265.pgn';
