UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsstellung auf und führt zum Matt.","Springer und Läufer bahnen der Dame den Weg zum Matt am Rand.","Der Springer nach g3 eröffnet die erzwungene Folge."],"en":["A sacrifice tears open the king''s cover and leads to mate.","Knight and bishop pave the queen''s path to the mate at the edge.","Knight to g3 opens the forced sequence."],"hr":["Žrtva otvara kraljev zaklon i vodi u mat.","Skakač i lovac krče dami put do mata na rubu.","Skakač na g3 otvara prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:019.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer lockt den König ins Matt.","Der Turm opfert sich, dann setzt die vom Läufer gedeckte Dame matt.","Der Turm schlägt auf h8 und beginnt die Mattfolge."],"en":["A rook sacrifice lures the king into mate.","The rook gives itself up, then the bishop-backed queen mates.","Rook takes on h8 and the mating line begins."],"hr":["Žrtva topa mami kralja u mat.","Top se žrtvuje, a zatim dama uz pomoć lovca matira.","Top uzima na h8 i započinje niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:019.006' AND BookFileName='chessable-u5-243265.pgn';
