UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand wird erzwungen mattgesetzt.","Die Dame setzt matt, von der eigenen Figur gestützt – die Fluchtfelder sind verstellt.","Die Dame nach d8 beginnt die Mattfolge."],"en":["The black king at the edge is mated by force.","The queen mates, backed by a friendly piece — the escape squares are blocked.","Queen to d8 begins the mating line."],"hr":["Crni kralj na rubu biva prisilno matiran.","Dama matira, uz potporu vlastite figure — polja bijega su zatvorena.","Dama na d8 započinje niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:020.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Diagonal-Mattführung mit der Dame zwingt den König ins Netz.","Ein durchgeschobener Bauer und die Dame schnüren den König ein.","Dame schlägt auf f7 – Auftakt zum erzwungenen Matt."],"en":["A forced mate using the queen on a diagonal awaits.","A far-advanced pawn and the queen wrap up the king.","Queen takes on f7 — starting the forced mate."],"hr":["Prisilni mat damom po dijagonali već čeka.","Daleko napredovani pješak i dama stišću kralja.","Dama uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:020.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Dame und Springer setzen den König gemeinsam matt.","Das starke Gespann aus Dame und Springer erledigt den König.","Dame nach e6 – Beginn der erzwungenen Mattführung."],"en":["Queen and knight team up to deliver mate.","The powerful queen-and-knight duo finishes the king off.","Queen to e6 — beginning the forced mate."],"hr":["Dama i skakač zajedno daju mat.","Snažan dvojac dame i skakača dokrajčuje kralja.","Dama na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:020.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier ist ein erzwungenes Matt mit der Dame vorhanden.","Die Dame greift den König von schräg nebenan an.","Dame nach h3 – leitet das erzwungene Matt ein."],"en":["A forced mate with the queen is on the board.","The queen attacks the king from a diagonally adjacent square.","Queen to h3 — launching the forced mate."],"hr":["Na ploči je prisilni mat damom.","Dama napada kralja s dijagonalno susjednog polja.","Dama na h3 — pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:020.005' AND BookFileName='chessable-u5-243265.pgn';
