UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – ein bescheidener Helfer gibt den letzten Stoß.","Ein Damenopfer reißt eine Bauernlinie auf, sodass ein Bauer das Matt setzt.","Die Dame schlägt auf b5; nach a6xb5 axb5 – matt."],"en":["A forced mate is here, with a humble piece dealing the final blow.","A queen sacrifice clears a pawn''s path so a pawn delivers the mate.","The queen takes on b5; after a6xb5 axb5 — mate."],"hr":["Ovdje vreba prisilni mat, a posljednji udarac zadaje skromna figura.","Žrtva dame otvara put pješaku koji daje mat.","Dama uzima na b5; nakon a6xb5 axb5 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz zwingt ein Matt – ein opferfreudiger Schlag leitet es ein.","Die Dame opfert sich, dann übernehmen Turm und Springer das Mattnetz.","Die Dame schlägt auf e2 und startet den erzwungenen Mattangriff."],"en":["Black forces mate, launched by a daring sacrifice.","The queen sacrifices herself, then rook and knight weave the mating net.","The queen takes on e2, beginning the forced mating attack."],"hr":["Crni iznuđuje mat, a uvodi ga smjela žrtva.","Dama se žrtvuje, a top i skakač potom pletu matnu mrežu.","Dama uzima na e2 i započinje prisilni matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:022.005' AND BookFileName='chessable-u5-243265.pgn';
