UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein bescheidener Bauer beendet die Jagd.","Ein Turmopfer und Damenopfer ebnen dem Bauern den Weg.","Der Turm schlägt auf f5 und beginnt die erzwungene Mattführung."],"en":["White forces mate, a humble pawn ending the hunt.","Rook and queen sacrifices pave the way for the pawn.","The rook takes on f5, beginning the forced mating line."],"hr":["Bijeli iznuđuje mat, a hajku završava skromni pješak.","Žrtve topa i dame krče put pješaku.","Top uzima na f5 i započinje prisilni matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:022.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein vorgerückter Bauer wird zur Hauptfigur.","Ein Damenopfer lockt den Springer weg, dann marschiert der Bauer.","Die Dame schlägt auf f5 und leitet das erzwungene Matt ein."],"en":["White forces mate, an advanced pawn becoming the hero.","A queen sacrifice lures the knight away, then the pawn marches.","The queen takes on f5, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a glavnu ulogu preuzima napredni pješak.","Žrtva dame odvlači skakača, a potom pješak kreće.","Dama uzima na f5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – der unscheinbare Bauer gibt den Schlussstoß.","Bauer und Läufer schnüren den König ein, bis ein Bauer mattsetzt.","Der Bauer zieht nach h4 und beginnt die erzwungene Mattführung."],"en":["White forces mate, the modest pawn striking the final blow.","Pawn and bishop hem the king in until a pawn delivers mate.","The pawn advances to h4, beginning the forced mate."],"hr":["Bijeli iznuđuje mat, a posljednji udarac zadaje neugledni pješak.","Pješak i lovac stiskaju kralja dok pješak ne da mat.","Pješak ide na h4 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein einzelner Bauer vollendet es.","Ein Turmopfer besetzt ein Fluchtfeld, danach setzt der Bauer matt.","Der Turm schlägt auf h4 und leitet das erzwungene Matt ein."],"en":["White forces mate, a lone pawn completing it.","A rook sacrifice blocks an escape square, then the pawn mates.","The rook takes on h4, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a dovršava ga usamljeni pješak.","Žrtva topa zaprema polje bijega, a potom pješak daje mat.","Top uzima na h4 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.010' AND BookFileName='chessable-u5-243265.pgn';
