UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein Bauer vollstreckt es.","Ein Damenopfer öffnet eine Linie für den Turm, dann mattet der Bauer.","Die Dame schlägt auf g6 und leitet das erzwungene Matt ein."],"en":["White forces mate, a pawn executing it.","A queen sacrifice opens a file for the rook, then the pawn mates.","The queen takes on g6, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a izvršava ga pješak.","Žrtva dame otvara liniju topu, a onda pješak daje mat.","Dama uzima na g6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt ein Matt – ein winziger Bauer entscheidet.","Ein Springeropfer lenkt den Bauern ab, dann stürmt der eigene Bauer.","Der Springer schlägt auf e5 und beginnt die erzwungene Mattführung."],"en":["Black forces mate, a tiny pawn deciding it.","A knight sacrifice diverts a pawn, then the rook pawn storms in.","The knight takes on e5, beginning the forced mate."],"hr":["Crni iznuđuje mat, a odlučuje sićušni pješak.","Žrtva skakača odvlači pješaka, a onda juriša vlastiti pješak.","Skakač uzima na e5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt ein Matt – ein bescheidener Bauer setzt den Punkt.","Ein Springeropfer reißt eine Linie auf, dann zieht der Bauer durch.","Der Springer schlägt auf a4 und leitet das erzwungene Matt ein."],"en":["Black forces mate, a humble pawn placing the final point.","A knight sacrifice rips open a line, then the pawn drives through.","The knight takes on a4, starting the forced mate."],"hr":["Crni iznuđuje mat, a posljednju riječ ima skromni pješak.","Žrtva skakača otvara liniju, a onda pješak prolazi.","Skakač uzima na a4 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt ein Matt – ein kleiner Bauer vollendet es.","Ein Damenopfer lockt den Bauern weg, dann marschiert der Freibauer.","Die Dame schlägt auf e3 und beginnt die erzwungene Mattführung."],"en":["Black forces mate, a little pawn completing it.","A queen sacrifice lures a pawn away, then the passer marches.","The queen takes on e3, beginning the forced mate."],"hr":["Crni iznuđuje mat, a dovršava ga maleni pješak.","Žrtva dame odvlači pješaka, a onda kreće prolazni pješak.","Dama uzima na e3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.017' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein Bauer gibt den Schlussstoß.","Ein Damenopfer lockt den König, dann setzt der Bauer matt.","Die Dame schlägt auf g8 und leitet das erzwungene Matt ein."],"en":["White forces mate, a pawn striking the final blow.","A queen sacrifice lures the king, then the pawn mates.","The queen takes on g8, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a posljednji udarac zadaje pješak.","Žrtva dame mami kralja, a onda pješak daje mat.","Dama uzima na g8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.018' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – am Ende vollstreckt ein Bauer.","Läufer- und Damenopfer räumen die Verteidiger, dann mattet der Bauer.","Der Läufer schlägt auf e6 und beginnt die erzwungene Mattführung."],"en":["White forces mate, a pawn executing it at the end.","Bishop and queen sacrifices clear the defenders, then the pawn mates.","The bishop takes on e6, beginning the forced mate."],"hr":["Bijeli iznuđuje mat, a na kraju izvršava ga pješak.","Žrtve lovca i dame uklanjaju branitelje, a onda pješak daje mat.","Lovac uzima na e6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.019' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein vorgerückter Bauer vollendet es.","Ein Damenopfer lockt den König heran, dann setzt der Bauer matt.","Die Dame schlägt auf h8 und leitet das erzwungene Matt ein."],"en":["White forces mate, an advanced pawn completing it.","A queen sacrifice draws the king close, then the pawn mates.","The queen takes on h8, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a dovršava ga napredni pješak.","Žrtva dame privlači kralja, a onda pješak daje mat.","Dama uzima na h8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.020' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein bescheidener Bauer beendet die Hatz.","Bauern und Dame treiben den König, bis ein letzter Bauer mattet.","Der Bauer zieht nach g5 und beginnt die erzwungene Mattführung."],"en":["White forces mate, a humble pawn ending the chase.","Pawns and queen drive the king until a last pawn mates.","The pawn advances to g5, beginning the forced mate."],"hr":["Bijeli iznuđuje mat, a hajku završava skromni pješak.","Pješaci i dama tjeraju kralja dok posljednji pješak ne da mat.","Pješak ide na g5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.021' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein kleiner Bauer entscheidet am Ende.","Ein ruhiger Bauernzug schließt das Mattnetz, dann mattet der Bauer.","Der Bauer zieht nach g4 und beginnt die erzwungene Mattführung."],"en":["White forces mate, a little pawn deciding at the end.","A quiet pawn move seals the mating net, then the pawn mates.","The pawn advances to g4, beginning the forced mate."],"hr":["Bijeli iznuđuje mat, a na kraju odlučuje maleni pješak.","Tihi potez pješaka zatvara matnu mrežu, a onda pješak daje mat.","Pješak ide na g4 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.022' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ein Bauer setzt im Bauernendspiel matt.","Ein Läuferopfer und Zugzwang ebnen dem Bauern den Weg.","Der Bauer zieht nach f5 und beginnt die erzwungene Mattführung."],"en":["White forces mate, a pawn delivering it in the pawn ending.","A bishop sacrifice and zugzwang clear the path for the pawn.","The pawn advances to f5, beginning the forced mate."],"hr":["Bijeli iznuđuje mat, a u pješačkoj završnici mat daje pješak.","Žrtva lovca i cugcvang krče put pješaku.","Pješak ide na f5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.023' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt ein Matt – ein bescheidener Bauer vollendet es.","Ein Springerzug öffnet die Bahn, dann setzt der Bauer matt.","Der Springer zieht nach f5 und leitet das erzwungene Matt ein."],"en":["Black forces mate, a humble pawn completing it.","A knight move opens the path, then the pawn mates.","The knight goes to f5, starting the forced mate."],"hr":["Crni iznuđuje mat, a dovršava ga skromni pješak.","Potez skakača otvara put, a onda pješak daje mat.","Skakač ide na f5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.024' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt ein Matt – ein kleiner Bauer gibt den Schlussstoß.","Ein Läuferzug verschärft die Drohung, dann bricht der Bauer durch.","Der Läufer zieht nach e7 und leitet das erzwungene Matt ein."],"en":["Black forces mate, a little pawn striking the final blow.","A bishop move sharpens the threat, then the pawn breaks through.","The bishop goes to e7, starting the forced mate."],"hr":["Crni iznuđuje mat, a posljednji udarac zadaje maleni pješak.","Potez lovca pojačava prijetnju, a onda pješak probija.","Lovac ide na e7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:022.025' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – zwei Läufer kreuzen ihre Diagonalen.","Ein Damenopfer öffnet die Diagonale, auf der der Läufer mattsetzt.","Die Dame schlägt auf c6 und leitet das erzwungene Matt ein."],"en":["White forces mate, two bishops crossing their diagonals.","A queen sacrifice opens the diagonal where a bishop will mate.","The queen takes on c6, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a dva lovca križaju svoje dijagonale.","Žrtva dame otvara dijagonalu na kojoj lovac daje mat.","Dama uzima na c6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – das Läuferpaar bildet das tödliche Netz.","Ein Damenopfer reißt die Diagonale auf, auf der der Läufer mattet.","Die Dame schlägt auf c6 und leitet das erzwungene Matt ein."],"en":["White forces mate, the bishop pair forming the deadly net.","A queen sacrifice tears open the diagonal where a bishop mates.","The queen takes on c6, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a par lovaca plete smrtonosnu mrežu.","Žrtva dame otvara dijagonalu na kojoj lovac daje mat.","Dama uzima na c6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – zwei Läufer kreuzen ihre Linien.","Ein Damenopfer öffnet die Diagonale für den mattsetzenden Läufer.","Die Dame schlägt auf c6 und leitet das erzwungene Matt ein."],"en":["White forces mate, two bishops crossing their lines.","A queen sacrifice opens the diagonal for the mating bishop.","The queen takes on c6, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a dva lovca križaju svoje linije.","Žrtva dame otvara dijagonalu lovcu koji daje mat.","Dama uzima na c6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt ein Matt – zwei Läufer auf kreuzenden Diagonalen.","Ein Damenopfer öffnet die Bahn, auf der der zweite Läufer mattet.","Die Dame schlägt auf c3 und leitet das erzwungene Matt ein."],"en":["Black forces mate, two bishops on crossing diagonals.","A queen sacrifice opens the path where the second bishop mates.","The queen takes on c3, starting the forced mate."],"hr":["Crni iznuđuje mat, a dva lovca na ukrštenim dijagonalama.","Žrtva dame otvara put na kojem drugi lovac daje mat.","Dama uzima na c3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt ein Matt – das Läuferpaar webt das Netz.","Ein Damenopfer reißt die Diagonale auf, auf der der Läufer mattet.","Die Dame schlägt auf c3 und leitet das erzwungene Matt ein."],"en":["Black forces mate, the bishop pair weaving the net.","A queen sacrifice rips open the diagonal where a bishop mates.","The queen takes on c3, starting the forced mate."],"hr":["Crni iznuđuje mat, a par lovaca plete mrežu.","Žrtva dame otvara dijagonalu na kojoj lovac daje mat.","Dama uzima na c3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – zwei Läufer kreuzen ihre Diagonalen.","Ein Damenopfer lockt einen Verteidiger weg, dann mattet der Läufer.","Die Dame schlägt auf e6 und leitet das erzwungene Matt ein."],"en":["White forces mate, two bishops crossing their diagonals.","A queen sacrifice lures a defender away, then a bishop mates.","The queen takes on e6, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a dva lovca križaju svoje dijagonale.","Žrtva dame odvlači branitelja, a onda lovac daje mat.","Dama uzima na e6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – das Läuferpaar entscheidet.","Ein schönes Damenopfer öffnet die Diagonale für den Mattläufer.","Die Dame schlägt auf e6 und leitet das erzwungene Matt ein."],"en":["White forces mate, the bishop pair deciding it.","A fine queen sacrifice opens the diagonal for the mating bishop.","The queen takes on e6, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a odlučuje par lovaca.","Lijepa žrtva dame otvara dijagonalu lovcu koji daje mat.","Dama uzima na e6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – zwei Läufer auf kreuzenden Diagonalen.","Ein Damenopfer öffnet die Bahn, auf der der Läufer mattsetzt.","Die Dame schlägt auf f7 und leitet das erzwungene Matt ein."],"en":["White forces mate, two bishops on crossing diagonals.","A queen sacrifice opens the path where a bishop will mate.","The queen takes on f7, starting the forced mate."],"hr":["Bijeli iznuđuje mat, a dva lovca na ukrštenim dijagonalama.","Žrtva dame otvara put na kojem lovac daje mat.","Dama uzima na f7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – der König ist eingeschnürt.","Deine Dame öffnet mit einem Opfer die Bahn, danach erledigen die Läufer entlang der Diagonalen den Rest.","Die Dame schlägt auf e6 und leitet das Matt ein."],"en":["A forced mate is waiting – the king is hemmed in.","A queen sacrifice clears the path so your bishops finish along the diagonals.","The queen takes on e6 to begin the forced mate."],"hr":["Tu postoji prisilni mat — kralj je stiješnjen.","Žrtva dame otvara put, a lovci dovršavaju duž dijagonala.","Dama uzima na e6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Matt lässt sich erzwingen – die Königsstellung ist zerrüttet.","Ein Damenopfer reißt die Deckung weg, dann schlägt der Läufer ein.","Die Dame schlägt auf h3 und beginnt das erzwungene Matt."],"en":["You can force mate – the king''s cover is in tatters.","A queen sacrifice strips a defender, then the bishop strikes.","The queen takes on h3 to start the forced mate."],"hr":["Mat se može iznuditi — kraljeva zaštita je razbijena.","Žrtva dame uklanja branitelja, zatim lovac udara.","Dama uzima na h3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:023.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – treibe den König zurück.","Die Dame schnürt die Fluchtfelder ein, den letzten Schlag führt der Läufer.","Die Dame zieht auf d6 und beginnt die Mattführung."],"en":["A forced mate is there – drive the king back.","The queen seals the escape squares while the bishop lands the final blow.","The queen goes to d6 to begin the mating sequence."],"hr":["Postoji prisilni mat — potjeraj kralja unatrag.","Dama zatvara polja za bijeg, a lovac zadaje završni udarac.","Dama ide na d6 i započinje matiranje."]}', HintsVersion=1 WHERE LineId LIKE '%:024.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steht ein erzwungenes Matt bereit.","Die Dame deckt die Fluchtfelder, der Läufer setzt matt.","Die Dame zieht nach f8 und leitet das Matt ein."],"en":["A forced mate stands ready here.","The queen covers the flight squares and the bishop mates.","The queen moves to f8 to begin the mate."],"hr":["Ovdje je spreman prisilni mat.","Dama pokriva polja za bijeg, a lovac matira.","Dama ide na f8 i pokreće mat."]}', HintsVersion=1 WHERE LineId LIKE '%:024.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist möglich – der König wird gejagt.","Erst schachen, die Fluchtfelder werden gedeckt, dann gibt der Läufer den Todesstoß.","Die Dame schlägt auf f8 und beginnt die Mattjagd."],"en":["A forced mate is on – the king gets hunted down.","Check first, the escape squares get covered, then the bishop delivers the blow.","The queen takes on f8 to begin the mating hunt."],"hr":["Moguć je prisilni mat — kralj je progonjen.","Prvo šah, polja za bijeg se pokrivaju, zatim lovac zadaje udarac.","Dama uzima na f8 i započinje matiranje."]}', HintsVersion=1 WHERE LineId LIKE '%:024.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft.","Eine Umwandlung lockt den König, dann deckt die Dame und der Läufer setzt matt.","Der Bauer wandelt auf e8 zur Dame um und startet die Mattführung."],"en":["A forced mate is in the air.","A promotion lures the king, then the queen covers and the bishop mates.","The pawn promotes on e8 to a queen and starts the mating line."],"hr":["U zraku je prisilni mat.","Promocija mami kralja, zatim dama pokriva, a lovac matira.","Pješak se promovira na e8 u damu i započinje matiranje."]}', HintsVersion=1 WHERE LineId LIKE '%:024.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird festgenagelt.","Die Dame nimmt dem König die Felder, der Läufer schließt das Netz.","Die Dame schlägt auf f6 und beginnt die Mattführung."],"en":["A forced mate is here – the king gets pinned down.","The queen strips the king''s squares, the bishop closes the net.","The queen takes on f6 to begin the mate."],"hr":["Tu je prisilni mat — kralj je prikovan.","Dama oduzima kralju polja, a lovac zatvara mrežu.","Dama uzima na f6 i započinje matiranje."]}', HintsVersion=1 WHERE LineId LIKE '%:024.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet auf den nackten König.","Die Dame deckt, eine Umwandlung räumt den Verteidiger, der Läufer setzt matt.","Die Dame schlägt auf e6 und leitet das Matt ein."],"en":["A forced mate awaits the bare king.","The queen covers, a promotion removes the defender, the bishop mates.","The queen takes on e6 to begin the mate."],"hr":["Gologa kralja čeka prisilni mat.","Dama pokriva, promocija uklanja branitelja, lovac matira.","Dama uzima na e6 i pokreće mat."]}', HintsVersion=1 WHERE LineId LIKE '%:024.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz Materialnachteils steckt hier ein erzwungenes Matt.","Bauern- und Damenopfer reißen die Stellung des Königs auf, dann setzt der Läufer matt.","Der Turm schlägt auf b2 und beginnt die Mattkombination."],"en":["Despite the material, a forced mate is hidden here.","Pawn and queen sacrifices tear open the king, then the bishop mates.","The rook takes on b2 to begin the mating combination."],"hr":["Unatoč materijalu, ovdje je skriven prisilni mat.","Žrtve pješaka i dame otvaraju kralja, zatim lovac matira.","Top uzima na b2 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:024.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier lässt sich ein Matt erzwingen.","Ein Damen- und Bauernopfer schneiden dem König die Flucht ab, der Läufer schlägt ein.","Die Dame schlägt auf h3 und leitet das Matt ein."],"en":["A mate can be forced here.","A queen and pawn sacrifice cut off the king''s flight, then the bishop strikes.","The queen takes on h3 to begin the mate."],"hr":["Ovdje se mat može iznuditi.","Žrtve dame i pješaka odsijecaju kralju bijeg, a lovac udara.","Dama uzima na h3 i pokreće mat."]}', HintsVersion=1 WHERE LineId LIKE '%:024.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – zwei Figuren spielen zusammen.","Zwei Springer kooperieren, um den König in der Ecke zu erlegen.","Der Springer zieht nach f6 und beginnt die Springer-Mattführung."],"en":["A forced mate is there – two pieces team up.","Two knights cooperate to trap the king in the corner.","The knight goes to f6 to begin the knights'' mate."],"hr":["Tu je prisilni mat — dvije figure surađuju.","Dva skakača zajedno hvataju kralja u kutu.","Skakač ide na f6 i započinje mat skakačima."]}', HintsVersion=1 WHERE LineId LIKE '%:025.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit.","Zwei Springer arbeiten zusammen und treiben den König in die Ecke.","Der Springer schlägt auf f6 und beginnt die Doppelspringer-Mattführung."],"en":["A forced mate is ready.","Two knights work together and herd the king into the corner.","The knight takes on f6 to begin the double-knight mate."],"hr":["Spreman je prisilni mat.","Dva skakača surađuju i tjeraju kralja u kut.","Skakač uzima na f6 i započinje mat dvama skakačima."]}', HintsVersion=1 WHERE LineId LIKE '%:025.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein erzwungenes Matt.","Beide Springer schließen zusammen, um den König in der Ecke matt zu setzen.","Der Springer schlägt auf e7 und beginnt die Doppelspringer-Mattführung."],"en":["A forced mate is waiting.","Both knights combine to mate the king in the corner.","The knight takes on e7 to begin the double-knight mate."],"hr":["Ovdje čeka prisilni mat.","Oba skakača se udružuju da matiraju kralja u kutu.","Skakač uzima na e7 i započinje mat dvama skakačima."]}', HintsVersion=1 WHERE LineId LIKE '%:025.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt lässt sich herausarbeiten.","Erst wird der König gefangen, dann liefern zwei Springer das Matt.","Der Turm zieht nach d8 und beginnt die Mattführung."],"en":["A forced mate can be worked out.","First the king is boxed in, then two knights deliver the mate.","The rook goes to d8 to begin the mating sequence."],"hr":["Prisilni mat se može iznuditi.","Najprije se kralj zatvara, zatim dva skakača matiraju.","Top ide na d8 i započinje matiranje."]}', HintsVersion=1 WHERE LineId LIKE '%:025.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit.","Zwei Springer wirken zusammen und setzen den König in der Ecke matt.","Der Springer zieht nach f3 und beginnt die Springer-Mattführung."],"en":["A forced mate is ready.","Two knights act together to mate the king in the corner.","The knight goes to f3 to begin the knights'' mate."],"hr":["Spreman je prisilni mat.","Dva skakača djeluju zajedno i matiraju kralja u kutu.","Skakač ide na f3 i započinje mat skakačima."]}', HintsVersion=1 WHERE LineId LIKE '%:025.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist möglich.","Ein Damenopfer lockt einen Verteidiger weg, dann setzen zwei Springer matt.","Die Dame schlägt auf g7 und beginnt die Springer-Mattkombination."],"en":["A forced mate is possible.","A queen sacrifice lures a defender away, then two knights mate.","The queen takes on g7 to begin the knights'' mating combination."],"hr":["Moguć je prisilni mat.","Žrtva dame odvlači branitelja, zatim dva skakača matiraju.","Dama uzima na g7 i započinje matnu kombinaciju skakačima."]}', HintsVersion=1 WHERE LineId LIKE '%:025.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt.","Ein Damenopfer öffnet die Königsstellung, dann erledigen zwei Springer das Matt.","Die Dame schlägt auf g6 und leitet die Mattkombination ein."],"en":["A forced mate is hidden here.","A queen sacrifice opens the king, then two knights finish the mate.","The queen takes on g6 to begin the mating combination."],"hr":["Ovdje je skriven prisilni mat.","Žrtva dame otvara kralja, zatim dva skakača dovršavaju mat.","Dama uzima na g6 i pokreće matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:025.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor.","Ein Damenopfer lenkt den Gegenkönig ein, dann setzen zwei Springer matt.","Die Dame schlägt auf e8 und beginnt die Springer-Mattführung."],"en":["A forced mate is at hand.","A queen sacrifice draws the king in, then two knights deliver mate.","The queen takes on e8 to begin the knights'' mate."],"hr":["Pred tobom je prisilni mat.","Žrtva dame uvlači kralja, zatim dva skakača matiraju.","Dama uzima na e8 i započinje mat skakačima."]}', HintsVersion=1 WHERE LineId LIKE '%:025.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da.","Erst wird der König herausgezogen, dann setzen zwei Springer das Netz zu.","Der König zieht nach d7 und beginnt die Mattführung."],"en":["A forced mate is there.","First the king is pulled out, then two knights close the net.","The king goes to d7 to begin the mating sequence."],"hr":["Tu je prisilni mat.","Najprije se kralj izvuče, zatim dva skakača zatvaraju mrežu.","Kralj ide na d7 i započinje matiranje."]}', HintsVersion=1 WHERE LineId LIKE '%:025.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit.","Ein Springer- und Damenopfer öffnen den König, dann setzen zwei Springer matt.","Der Springer zieht nach b3 und beginnt die Mattkombination."],"en":["A forced mate is ready.","A knight and queen sacrifice open the king, then two knights mate.","The knight goes to b3 to begin the mating combination."],"hr":["Spreman je prisilni mat.","Žrtve skakača i dame otvaraju kralja, zatim dva skakača matiraju.","Skakač ide na b3 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:025.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – zwei Figuren auf benachbarten Diagonalen.","Ein Damenopfer lockt eine Figur auf die richtige Diagonale, dann setzen zwei Läufer matt.","Die Dame schlägt auf d4 und beginnt die Läufer-Mattkombination."],"en":["A forced mate is there – two pieces on neighbouring diagonals.","A queen sacrifice lures a piece onto the right diagonal, then two bishops mate.","The queen takes on d4 to begin the bishops'' mating combination."],"hr":["Tu je prisilni mat — dvije figure na susjednim dijagonalama.","Žrtva dame mami figuru na pravu dijagonalu, zatim dva lovca matiraju.","Dama uzima na d4 i započinje matnu kombinaciju lovcima."]}', HintsVersion=1 WHERE LineId LIKE '%:026.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt lässt sich herausarbeiten.","Mit Opfern werden die Diagonalen geöffnet, dann setzen zwei Läufer matt.","Der Läufer schlägt auf g7 und beginnt die Mattkombination."],"en":["A forced mate can be worked out.","Sacrifices open the diagonals, then two bishops deliver mate.","The bishop takes on g7 to begin the mating combination."],"hr":["Prisilni mat se može iznuditi.","Žrtvama se otvaraju dijagonale, zatim dva lovca matiraju.","Lovac uzima na g7 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:026.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt.","Ein Damenopfer öffnet die lange Diagonale, dann schlägt der Läufer ein.","Die Dame schlägt auf f3 und leitet das Läufer-Matt ein."],"en":["A forced mate is hidden here.","A queen sacrifice opens the long diagonal, then the bishop strikes.","The queen takes on f3 to begin the bishop mate."],"hr":["Ovdje je skriven prisilni mat.","Žrtva dame otvara dugu dijagonalu, zatim lovac udara.","Dama uzima na f3 i pokreće mat lovcem."]}', HintsVersion=1 WHERE LineId LIKE '%:026.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist möglich.","Ein Turmschach lenkt einen Verteidiger ab, dann setzen zwei Läufer matt.","Der Turm schlägt auf c8 und beginnt die Läufer-Mattkombination."],"en":["A forced mate is possible.","A rook check distracts a defender, then two bishops mate.","The rook takes on c8 to begin the bishops'' mating combination."],"hr":["Moguć je prisilni mat.","Šah topom odvlači branitelja, zatim dva lovca matiraju.","Top uzima na c8 i započinje matnu kombinaciju lovcima."]}', HintsVersion=1 WHERE LineId LIKE '%:026.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit.","Die Verteidiger des Königs werden weggeschlagen, dann setzen zwei Läufer matt.","Die Dame zieht nach e5 und beginnt die Mattkombination."],"en":["A forced mate is ready.","The king''s defenders get removed, then two bishops mate.","The queen goes to e5 to begin the mating combination."],"hr":["Spreman je prisilni mat.","Kraljevi branitelji se uklanjaju, zatim dva lovca matiraju.","Dama ide na e5 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:026.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein erzwungenes Matt.","Reihenweise Opfer räumen die Diagonalen, dann setzen zwei Läufer matt.","Der Springer schlägt auf c7 und beginnt die Mattkombination."],"en":["A forced mate is waiting.","A string of sacrifices clears the diagonals, then two bishops mate.","The knight takes on c7 to begin the mating combination."],"hr":["Ovdje čeka prisilni mat.","Niz žrtava čisti dijagonale, zatim dva lovca matiraju.","Skakač uzima na c7 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:026.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da.","Ein Opfer beseitigt den Deckungspunkt, dann setzen zwei Läufer matt.","Der Läufer schlägt auf d4 und beginnt die Läufer-Mattkombination."],"en":["A forced mate is there.","A sacrifice removes the key defender, then two bishops mate.","The bishop takes on d4 to begin the bishops'' mating combination."],"hr":["Tu je prisilni mat.","Žrtva uklanja ključnog branitelja, zatim dva lovca matiraju.","Lovac uzima na d4 i započinje matnu kombinaciju lovcima."]}', HintsVersion=1 WHERE LineId LIKE '%:026.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt lässt sich erzwingen.","Ein Turmopfer öffnet den Weg, dann setzen zwei Läufer matt.","Der Turm schlägt auf h4 und beginnt die Läufer-Mattkombination."],"en":["A forced mate can be brought about.","A rook sacrifice opens the way, then two bishops mate.","The rook takes on h4 to begin the bishops'' mating combination."],"hr":["Prisilni mat se može iznuditi.","Žrtva topa otvara put, zatim dva lovca matiraju.","Top uzima na h4 i započinje matnu kombinaciju lovcima."]}', HintsVersion=1 WHERE LineId LIKE '%:026.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt.","Ein Damenopfer öffnet die Diagonale, dann setzen zwei Läufer matt.","Die Dame schlägt auf d5 und beginnt die Läufer-Mattkombination."],"en":["A forced mate is hidden here.","A queen sacrifice opens the diagonal, then two bishops mate.","The queen takes on d5 to begin the bishops'' mating combination."],"hr":["Ovdje je skriven prisilni mat.","Žrtva dame otvara dijagonalu, zatim dva lovca matiraju.","Dama uzima na d5 i započinje matnu kombinaciju lovcima."]}', HintsVersion=1 WHERE LineId LIKE '%:026.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist möglich.","Ein Damenopfer treibt den König ins Mattnetz, dann schlägt der Läufer entscheidend zu.","Die Dame schlägt auf d5 und beginnt die Mattkombination."],"en":["A forced mate is possible.","A queen sacrifice drives the king into a mating net, then a bishop strikes.","The queen takes on d5 to begin the mating combination."],"hr":["Moguć je prisilni mat.","Žrtva dame tjera kralja u matnu mrežu, zatim lovac udara.","Dama uzima na d5 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:026.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – treib den König in die Enge.","Deine beiden Läufer beherrschen die Diagonalen; ein Opfer reißt die entscheidende Linie auf.","Schlage mit der Dame auf d5 – das leitet das Mattnetz ein."],"en":["A forced mate is hiding here — drive the king into the net.","Both your bishops rule the diagonals; a sacrifice rips open the key line.","Queen takes on d5 — this opens the forced mating sequence."],"hr":["Ovdje se krije prisilni mat — natjeraj kralja u mrežu.","Oba tvoja lovca vladaju dijagonalama; žrtva otvara ključnu liniju.","Dama uzima na d5 — to pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:026.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – öffne dem Läuferpaar den Weg.","Ein Damenopfer lockt einen Bauern weg und gibt den Läufern freie Bahn.","Ziehe die Dame nach f4 als Opfer – der Auftakt zum Mattnetz."],"en":["A forced mate is in the air — clear the path for the bishop pair.","A queen sacrifice lures a pawn away and frees the bishops'' diagonals.","Queen to f4 as a sacrifice — the start of the mating net."],"hr":["U zraku je prisilni mat — otvori put paru lovaca.","Žrtva dame odvlači pješaka i oslobađa dijagonale lovaca.","Dama na f4 kao žrtva — početak matne mreže."]}', HintsVersion=1 WHERE LineId LIKE '%:026.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – nach Blackburne-Art.","Ein Damenopfer öffnet die Diagonale für deine Läufer zum König.","Ziehe die Dame nach h5 als Opfer – der Beginn des Mattangriffs."],"en":["A forced mate awaits — in Blackburne style.","A queen sacrifice opens the diagonal for your bishops toward the king.","Queen to h5 as a sacrifice — the start of the mating attack."],"hr":["Čeka te prisilni mat — u Blackburneovom stilu.","Žrtva dame otvara dijagonalu tvojim lovcima prema kralju.","Dama na h5 kao žrtva — početak matnog napada."]}', HintsVersion=1 WHERE LineId LIKE '%:027.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt im Blackburne-Stil.","Ein Damenopfer reißt die Königsstellung auf, Läufer und Springer machen den Rest.","Ziehe die Dame nach h5 als Opfer – der Auftakt zum Matt."],"en":["A forced mate lies hidden here, Blackburne style.","A queen sacrifice tears open the king''s cover; bishop and knight finish.","Queen to h5 as a sacrifice — the prelude to mate."],"hr":["Ovdje se krije prisilni mat, u Blackburneovom stilu.","Žrtva dame razbija kraljev zaklon; lovac i skakač dovršavaju.","Dama na h5 kao žrtva — uvod u mat."]}', HintsVersion=1 WHERE LineId LIKE '%:027.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt bereit – Blackburne lässt grüßen.","Ein Springeropfer lockt den Verteidiger weg und öffnet die Läuferdiagonale.","Ziehe den Springer nach h6 als Opfer – Beginn des Mattnetzes."],"en":["A forced mate is ready — a Blackburne-style finish.","A knight sacrifice lures the defender away and opens the bishop''s diagonal.","Knight to h6 as a sacrifice — the start of the mating net."],"hr":["Spreman je prisilni mat — u Blackburneovom stilu.","Žrtva skakača odvlači branitelja i otvara dijagonalu lovca.","Skakač na h6 kao žrtva — početak matne mreže."]}', HintsVersion=1 WHERE LineId LIKE '%:027.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug und kannst ein erzwungenes Matt einleiten.","Dein Springer und Läufer zielen auf die geschwächte Rochadestellung des Königs.","Ziehe den Springer nach g4 – so beginnt das Mattnetz."],"en":["It''s your move and a forced mate is on — get the attack rolling.","Your knight and bishop target the king''s weakened castled position.","Knight to g4 — this opens the mating sequence."],"hr":["Ti si na potezu i možeš pokrenuti prisilni mat.","Tvoj skakač i lovac ciljaju oslabljenu kraljevu rošadu.","Skakač na g4 — tako počinje matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:027.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – mit Läufern und Springer.","Ein Damenopfer öffnet die Diagonale, dann setzen Läufer und Springer matt.","Ziehe die Dame nach h5 als Opfer – der Auftakt zum Matt."],"en":["A forced mate is here — with bishops and knight.","A queen sacrifice opens the diagonal, then bishop and knight deliver mate.","Queen to h5 as a sacrifice — the prelude to mate."],"hr":["Tu je prisilni mat — s lovcima i skakačem.","Žrtva dame otvara dijagonalu, zatim lovac i skakač matiraju.","Dama na h5 kao žrtva — uvod u mat."]}', HintsVersion=1 WHERE LineId LIKE '%:027.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Stellung – Blackburne-Motiv.","Ein Damenopfer öffnet die Königsstellung, Springer und Läufer übernehmen.","Schlage mit der Dame auf h6 – so beginnt das Mattnetz."],"en":["A forced mate is in the position — a Blackburne motif.","A queen sacrifice opens the king''s shelter; knight and bishop take over.","Queen takes on h6 — this opens the mating net."],"hr":["U poziciji je prisilni mat — Blackburneov motiv.","Žrtva dame otvara kraljev zaklon; skakač i lovac preuzimaju.","Dama uzima na h6 — tako počinje matna mreža."]}', HintsVersion=1 WHERE LineId LIKE '%:027.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – im Stil von Blackburne.","Ein Damenopfer reißt die Bauerndeckung auf, der Läufer setzt nach.","Schlage mit der Dame auf h6 – Auftakt zum Mattnetz."],"en":["A forced mate awaits — Blackburne style.","A queen sacrifice rips open the pawn cover, then the bishop follows up.","Queen takes on h6 — the start of the mating net."],"hr":["Čeka prisilni mat — u Blackburneovom stilu.","Žrtva dame razbija pješački zaklon, a lovac slijedi.","Dama uzima na h6 — početak matne mreže."]}', HintsVersion=1 WHERE LineId LIKE '%:027.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – deine Türme dominieren die siebte Reihe.","Beide Türme arbeiten zusammen, treiben den König hin und her bis zum Matt.","Ziehe den Turm nach g7 – Beginn des Mattmanövers."],"en":["A forced mate is here — your rooks dominate the seventh rank.","Both rooks work together, bouncing the king back and forth to mate.","Rook to g7 — the start of the mating maneuver."],"hr":["Tu je prisilni mat — tvoje topove dominiraju sedmim redom.","Oba topa rade zajedno, tjeraju kralja amo-tamo do mata.","Top na g7 — početak matnog manevra."]}', HintsVersion=1 WHERE LineId LIKE '%:028.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Türme regieren die siebte Reihe.","Deine beiden Türme und der Springer weben gemeinsam das Mattnetz.","Ziehe den Turm nach g7 – so leitest du das Matt ein."],"en":["A forced mate is on — the rooks rule the seventh rank.","Your two rooks and the knight weave the mating net together.","Rook to g7 — this leads into the mate."],"hr":["Pred tobom je prisilni mat — topovi vladaju sedmim redom.","Tvoja dva topa i skakač zajedno pletu matnu mrežu.","Top na g7 — tako uvodiš mat."]}', HintsVersion=1 WHERE LineId LIKE '%:028.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – Türme auf der siebten Reihe.","Beide Türme stützen einander und schnüren den König ein.","Ziehe den Turm nach g7 – Auftakt zum Mattnetz."],"en":["A forced mate is in there — rooks on the seventh rank.","Both rooks support each other and box the king in.","Rook to g7 — the start of the mating net."],"hr":["Unutra je prisilni mat — topovi na sedmom redu.","Oba topa podupiru jedan drugoga i zatvaraju kralja.","Top na g7 — početak matne mreže."]}', HintsVersion=1 WHERE LineId LIKE '%:028.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Türme erobern die siebte Reihe.","Deine Türme rücken nebeneinander vor und nehmen dem König die Luft.","Ziehe den Turm nach f7 – Beginn des Mattmanövers."],"en":["A forced mate awaits — the rooks seize the seventh rank.","Your rooks advance side by side and suffocate the king.","Rook to f7 — the start of the mating maneuver."],"hr":["Čeka prisilni mat — topovi osvajaju sedmi red.","Tvoji topovi napreduju jedan uz drugoga i guše kralja.","Top na f7 — početak matnog manevra."]}', HintsVersion=1 WHERE LineId LIKE '%:028.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug und ein erzwungenes Matt liegt bereit – siebte Reihe für Schwarz.","Deine beiden Türme dringen ein und arbeiten Hand in Hand.","Schlage mit dem Turm auf h2 – so beginnt das Mattnetz."],"en":["It''s your move and a forced mate is ready — the rooks own the rank.","Your two rooks break in and work hand in hand.","Rook takes on h2 — this opens the mating net."],"hr":["Ti si na potezu i spreman je prisilni mat — topovi vladaju redom.","Tvoja dva topa prodiru i rade ruku pod ruku.","Top uzima na h2 — tako počinje matna mreža."]}', HintsVersion=1 WHERE LineId LIKE '%:028.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird zwischen seine eigenen Figuren gezwängt.","Türme räumen die hinterste Reihe leer, die Dame gibt den letzten Stoß.","Ziehe den Turm nach f8 als Opfer – der Auftakt zum Matt."],"en":["A forced mate is here — the king gets wedged between his own pieces.","Rooks clear the back rank, the queen delivers the final blow.","Rook to f8 as a sacrifice — the prelude to mate."],"hr":["Tu je prisilni mat — kralj se zaglavi između vlastitih figura.","Topovi čiste zadnji red, dama zadaje završni udarac.","Top na f8 kao žrtva — uvod u mat."]}', HintsVersion=1 WHERE LineId LIKE '%:029.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der König wird eingeklemmt.","Springer und Türme treiben den König an den Rand, wo er von eigenen Steinen blockiert ist.","Ziehe den Springer nach d6 – so beginnt das Mattmanöver."],"en":["A forced mate is on — the king will be wedged in.","Knight and rooks drive the king to the edge, hemmed by his own men.","Knight to d6 — the start of the mating maneuver."],"hr":["Pred tobom je prisilni mat — kralj se zaglavljuje.","Skakač i topovi tjeraju kralja na rub, gdje ga koče vlastite figure.","Skakač na d6 — tako počinje matni manevar."]}', HintsVersion=1 WHERE LineId LIKE '%:029.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Zug setzt sofort matt – der König steckt zwischen seinen Figuren.","Deine Dame nutzt die eingeengte Königsstellung am Rand aus.","Ziehe die Dame nach c7 – matt."],"en":["One move mates at once — the king is trapped between his pieces.","Your queen exploits the king''s cramped position on the edge.","Queen to c7 — mate."],"hr":["Jedan potez odmah matira — kralj je zarobljen među svojim figurama.","Tvoja dama iskorištava skučen položaj kralja na rubu.","Dama na c7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:029.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – der König wird eingeklemmt.","Ein Läuferopfer entblößt den König, die Dame nutzt die offene Stellung.","Schlage mit dem Läufer auf f6 – der Auftakt zum Matt."],"en":["A forced mate is in there — the king gets wedged in.","A bishop sacrifice exposes the king, the queen exploits the opening.","Bishop takes on f6 — the prelude to mate."],"hr":["Unutra je prisilni mat — kralj se zaglavljuje.","Žrtva lovca razgolićuje kralja, dama iskorištava otvor.","Lovac uzima na f6 — uvod u mat."]}', HintsVersion=1 WHERE LineId LIKE '%:029.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der König wird zwischen seine Figuren gezwängt.","Deine Dame jagt den König über das Brett, bis er eingeklemmt ist.","Ziehe die Dame nach e5 – so beginnt das Mattnetz."],"en":["A forced mate awaits — the king gets wedged between his pieces.","Your queen chases the king across the board until he''s boxed in.","Queen to e5 — this opens the mating net."],"hr":["Čeka prisilni mat — kralj se zaglavi između svojih figura.","Tvoja dama goni kralja preko ploče dok ga ne zatvori.","Dama na e5 — tako počinje matna mreža."]}', HintsVersion=1 WHERE LineId LIKE '%:029.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug und ein erzwungenes Matt liegt bereit – der König wird eingeklemmt.","Dame und Turm umzingeln den König, Schwarz nimmt die Verteidiger weg.","Ziehe die Dame nach d3 – Auftakt zum Mattmanöver."],"en":["It''s your move and a forced mate is ready — the king gets wedged in.","Queen and rook surround the king while you strip the defenders.","Queen to d3 — the start of the mating maneuver."],"hr":["Ti si na potezu i spreman je prisilni mat — kralj se zaglavljuje.","Dama i top opkoljavaju kralja dok skidaš branitelje.","Dama na d3 — početak matnog manevra."]}', HintsVersion=1 WHERE LineId LIKE '%:029.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug und ein erzwungenes Matt steckt drin – der König wird eingezwängt.","Deine Dame führt den Angriff, die Figuren des Gegners verstellen dem König die Flucht.","Ziehe die Dame nach f3 – so beginnt das Mattnetz."],"en":["It''s your move and a forced mate is in there — the king gets wedged in.","Your queen leads the attack while the king''s own men block his escape.","Queen to f3 — this opens the mating net."],"hr":["Ti si na potezu i unutra je prisilni mat — kralj se zaglavljuje.","Tvoja dama vodi napad, a kraljeve vlastite figure mu priječe bijeg.","Dama na f3 — tako počinje matna mreža."]}', HintsVersion=1 WHERE LineId LIKE '%:029.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug und ein erzwungenes Matt wartet – der König wird eingeklemmt.","Ein Turmopfer lenkt einen Bauern ab, dann schlägt die Dame zu.","Schlage mit dem Turm auf h4 als Opfer – der Auftakt zum Matt."],"en":["It''s your move and a forced mate awaits — the king gets wedged in.","A rook sacrifice deflects a pawn, then the queen strikes.","Rook takes on h4 as a sacrifice — the prelude to mate."],"hr":["Ti si na potezu i čeka prisilni mat — kralj se zaglavljuje.","Žrtva topa odvlači pješaka, zatim udara dama.","Top uzima na h4 kao žrtva — uvod u mat."]}', HintsVersion=1 WHERE LineId LIKE '%:029.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Grundreihe des Gegners ist verwundbar.","Deine Türme arbeiten auf der hintersten Linie zusammen.","Ziehe den Turm nach d8 als Opfer – der Auftakt zum Grundreihenmatt."],"en":["A forced mate is here — the opponent''s back rank is vulnerable.","Your rooks combine along the last rank.","Rook to d8 as a sacrifice — the prelude to the back-rank mate."],"hr":["Tu je prisilni mat — protivnikov zadnji red je ranjiv.","Tvoji topovi djeluju zajedno po zadnjem redu.","Top na d8 kao žrtva — uvod u mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Grundreihe ist die Schwäche.","Türme und Dame zielen auf die eingeklemmte Königsstellung an der hinteren Linie.","Ziehe den Turm nach d8 als Opfer – so beginnt das Grundreihenmatt."],"en":["A forced mate is on — the back rank is the weakness.","Rooks and queen target the king boxed in on the last rank.","Rook to d8 as a sacrifice — this opens the back-rank mate."],"hr":["Pred tobom je prisilni mat — zadnji red je slabost.","Topovi i dama ciljaju kralja zatvorenog na zadnjem redu.","Top na d8 kao žrtva — tako počinje mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – die Grundreihe des Königs ist schwach.","Ein Turmopfer lenkt einen Verteidiger ab, die Dame setzt auf der hintersten Reihe matt.","Ziehe den Turm nach c8 als Opfer – der Auftakt zum Grundreihenmatt."],"en":["A forced mate is in there — the king''s back rank is weak.","A rook sacrifice deflects a defender, the queen mates on the last rank.","Rook to c8 as a sacrifice — the prelude to the back-rank mate."],"hr":["Unutra je prisilni mat — kraljev zadnji red je slab.","Žrtva topa odvlači branitelja, dama matira na zadnjem redu.","Top na c8 kao žrtva — uvod u mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die hinterste Reihe ist die Achillesferse.","Dame und Turm bündeln ihre Kraft gegen die schwache Grundreihe.","Ziehe die Dame nach d6 – so beginnt das Mattmanöver."],"en":["A forced mate awaits — the back rank is the Achilles'' heel.","Queen and rook combine their force against the weak last rank.","Queen to d6 — the start of the mating maneuver."],"hr":["Čeka prisilni mat — zadnji red je Ahilova peta.","Dama i top udružuju snagu protiv slabog zadnjeg reda.","Dama na d6 — početak matnog manevra."]}', HintsVersion=1 WHERE LineId LIKE '%:030.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt bereit – die Grundreihe ist verwundbar.","Dame und Turm schalten die Verteidiger aus und greifen die hinterste Linie an.","Ziehe den Turm nach d8 – so leitest du das Grundreihenmatt ein."],"en":["A forced mate is ready — the back rank is vulnerable.","Queen and rook eliminate the defenders and hit the last rank.","Rook to d8 — this leads into the back-rank mate."],"hr":["Spreman je prisilni mat — zadnji red je ranjiv.","Dama i top uklanjaju branitelje i napadaju zadnji red.","Top na d8 — tako uvodiš mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Grundreihe ist tödlich schwach.","Ein Damenopfer lenkt den Verteidiger ab, dann setzt der Turm auf der hintersten Reihe matt.","Schlage mit der Dame auf f7 als Opfer – der Auftakt zum Grundreihenmatt."],"en":["A forced mate is here — the back rank is fatally weak.","A queen sacrifice deflects the defender, then the rook mates on the last rank.","Queen takes on f7 as a sacrifice — the prelude to the back-rank mate."],"hr":["Tu je prisilni mat — zadnji red je kobno slab.","Žrtva dame odvlači branitelja, zatim top matira na zadnjem redu.","Dama uzima na f7 kao žrtva — uvod u mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug und ein erzwungenes Matt steckt drin – die Grundreihe ist schwach.","Turm und Dame nutzen die Schwäche der hintersten Reihe des Gegners aus.","Schlage mit dem Turm auf d1 als Opfer – so beginnt das Grundreihenmatt."],"en":["It''s your move and a forced mate is in there — the back rank is weak.","Rook and queen exploit the weakness of the opponent''s last rank.","Rook takes on d1 as a sacrifice — this opens the back-rank mate."],"hr":["Ti si na potezu i unutra je prisilni mat — zadnji red je slab.","Top i dama iskorištavaju slabost protivnikova zadnjeg reda.","Top uzima na d1 kao žrtva — tako počinje mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du bist am Zug und ein erzwungenes Matt wartet – die Grundreihe ist die Schwäche.","Turm und Dame öffnen die hinterste Reihe und brechen ein.","Schlage mit dem Turm auf f2 als Opfer – der Auftakt zum Grundreihenmatt."],"en":["It''s your move and a forced mate awaits — the back rank is the weakness.","Rook and queen pry open the last rank and break through.","Rook takes on f2 as a sacrifice — the prelude to the back-rank mate."],"hr":["Ti si na potezu i čeka prisilni mat — zadnji red je slabost.","Top i dama otvaraju zadnji red i probijaju se.","Top uzima na f2 kao žrtva — uvod u mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der gegnerische König klebt an der Grundreihe – ein Matt liegt in der Luft.","Beseitige zuerst den letzten Verteidiger der Grundreihe, dann schlägt der Turm zu.","Dame schlägt auf g2 – nach dem Bauernschlag erzwingt der Turm das Grundreihenmatt."],"en":["The enemy king is glued to its back rank – a forced mate is in the air.","Remove the last defender shielding the back rank, then the rook strikes.","Queen takes on g2 – after the pawn recaptures, the rook forces back-rank mate."],"hr":["Protivnički kralj je prikovan uz zadnji red — prisilni mat visi u zraku.","Ukloni posljednjeg branitelja zadnjeg reda, a onda topom udari.","Dama uzima na g2 — nakon uzimanja pješakom top forsira mat na zadnjem redu."]}', HintsVersion=1 WHERE LineId LIKE '%:030.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Auf der Grundreihe lauert ein erzwungenes Matt.","Der Springer schaltet sich per Abzug ein und treibt den König fest, danach mattsetzt der Turm.","Springer nach f7 – der Abzug leitet die Mattführung ein."],"en":["A forced mate lurks on the back rank.","The knight joins in with a discovered check and pins the king down, then the rook mates.","Knight to f7 – the discovered check starts the mating sequence."],"hr":["Na zadnjem redu vreba prisilni mat.","Skakač se uključuje otkrivenim šahom i prikuje kralja, a onda top matira.","Skakač na f7 — otkriveni šah pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:030.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingesperrte König erlaubt ein erzwungenes Grundreihenmatt.","Turm und Springer arbeiten zusammen, um die letzte Flucht zu nehmen.","Turm schlägt auf f7 – Auftakt zur erzwungenen Mattführung."],"en":["The boxed-in king allows a forced back-rank mate.","Rook and knight cooperate to take away the last escape.","Rook takes on f7 – the start of the forced mating line."],"hr":["Zatvoreni kralj dopušta prisilni mat na zadnjem redu.","Top i skakač surađuju kako bi oduzeli posljednji bijeg.","Top uzima na f7 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:030.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer bahnt den Weg zu einem erzwungenen Grundreihenmatt.","Erst lockst du die weiße Figur weg, dann übernehmen Läufer, Springer und Turm.","Dame nach d4 – das Opfer eröffnet die Mattführung."],"en":["A queen sacrifice paves the way to a forced back-rank mate.","First lure the white piece away, then bishop, knight and rook take over.","Queen to d4 – the sacrifice opens the mating line."],"hr":["Žrtva dame otvara put do prisilnog mata na zadnjem redu.","Prvo odvuci bijelu figuru, a onda preuzimaju lovac, skakač i top.","Dama na d4 — žrtva otvara matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:030.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Schwäche der gegnerischen Grundreihe lässt sich in Materialgewinn ummünzen.","Die Dame zentralisiert sich und droht zugleich gegen Reihe und Figur.","Dame nach e4 – der Doppelangriff gewinnt Material."],"en":["The opponent''s weak back rank can be turned into material gain.","The queen centralizes and threatens both the rank and a loose piece at once.","Queen to e4 – the double threat wins material."],"hr":["Slabost protivničkog zadnjeg reda može se pretvoriti u dobitak materijala.","Dama se centralizira i istovremeno prijeti i redu i figuri.","Dama na e4 — dvostruka prijetnja dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:030.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Grundreihendrohung erzwingt Materialgewinn.","Die Dame stellt sich ins Zentrum und nutzt die Schwäche der hintersten Reihe aus.","Dame nach e5 – die Drohung gewinnt Material."],"en":["A back-rank threat forces material gain.","The queen plants herself in the center, exploiting the weak last rank.","Queen to e5 – the threat wins material."],"hr":["Prijetnja na zadnjem redu prisiljava na dobitak materijala.","Dama se postavlja u centar i iskorištava slab zadnji red.","Dama na e5 — prijetnja dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:030.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Grundreihendrohung gewinnt Material.","Ein Damenopfer lenkt einen Verteidiger ab, dann setzt der Läufer den Doppelangriff.","Dame schlägt auf e4 – der Auftakt gewinnt Material."],"en":["A back-rank threat wins material.","A queen sacrifice deflects a defender, then the bishop sets up a double attack.","Queen takes on e4 – the start that wins material."],"hr":["Prijetnja na zadnjem redu dobiva materijal.","Žrtva dame odvlači branitelja, a onda lovac postavlja dvostruki napad.","Dama uzima na e4 — početak koji dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:030.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die schwache Grundreihe des Gegners lässt sich in Materialgewinn verwandeln.","Die Dame schlägt zentral ein und droht zugleich der hintersten Reihe.","Dame schlägt auf e4 – der Doppelangriff gewinnt Material."],"en":["The opponent''s weak back rank can be converted into material.","The queen captures centrally and simultaneously eyes the last rank.","Queen takes on e4 – the double threat wins material."],"hr":["Protivnikov slab zadnji red može se pretvoriti u materijal.","Dama uzima u centru i istovremeno gleda na zadnji red.","Dama uzima na e4 — dvostruka prijetnja dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:030.017' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Grundreihendrohung gewinnt Material.","Der Läufer schwenkt auf die Diagonale und kombiniert die Drohung mit dem Angriff auf eine Figur.","Läufer nach h6 – der Doppelangriff gewinnt Material."],"en":["A back-rank threat wins material.","The bishop swings to the diagonal, combining the threat with an attack on a piece.","Bishop to h6 – the double attack wins material."],"hr":["Prijetnja na zadnjem redu dobiva materijal.","Lovac se prebacuje na dijagonalu i spaja prijetnju s napadom na figuru.","Lovac na h6 — dvostruki napad dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:030.018' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die Grundreihenschwäche des Gegners erlaubt einen materialgewinnenden Schlag.","Der Läufer schlägt zentral und schafft eine Gabel samt Grundreihendrohung.","Läufer schlägt auf c4 – der Doppelschlag gewinnt Material."],"en":["The opponent''s back-rank weakness allows a material-winning blow.","The bishop captures centrally, creating a fork plus a back-rank threat.","Bishop takes on c4 – the double blow wins material."],"hr":["Slabost protivničkog zadnjeg reda dopušta udarac koji dobiva materijal.","Lovac uzima u centru i stvara viljušku uz prijetnju na zadnjem redu.","Lovac uzima na c4 — dvostruki udarac dobiva materijal."]}', HintsVersion=1 WHERE LineId LIKE '%:030.019' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit zwei Schwerfiguren lässt sich der König wie mit einem Rasenmäher zum Rand treiben und matt setzen.","Dame und Turm geben abwechselnd Schach und drängen den König immer weiter zurück.","Dame nach h4 – der erste Schach im Treppenmatt."],"en":["With two heavy pieces the king can be driven to the edge and mated like a lawnmower.","Queen and rook give alternating checks, pushing the king ever backward.","Queen to h4 – the first check of the staircase mate."],"hr":["S dvije teške figure kralj se može potjerati na rub i matirati poput kosilice.","Dama i top naizmjenično šahiraju i tjeraju kralja sve dalje.","Dama na h4 — prvi šah u stepenastom matu."]}', HintsVersion=1 WHERE LineId LIKE '%:031.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Zwei Türme treiben den König treppenförmig zum Rand und setzen matt.","Die beiden Türme geben abwechselnd Schach und schneiden Reihe um Reihe ab.","Turm nach h8 – Auftakt zum Treppenmatt."],"en":["Two rooks drive the king up the staircase to the edge and mate.","The two rooks check in turn, cutting off rank after rank.","Rook to h8 – the start of the lawnmower mate."],"hr":["Dva topa tjeraju kralja stepenasto prema rubu i matiraju.","Oba topa naizmjenično šahiraju i odsijecaju red za redom.","Top na h8 — početak stepenastog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:031.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Zwei Türme rollen den König wie ein Rasenmäher zum Rand und setzen matt.","Die Türme geben abwechselnd Schach, während ein Freibauer mithilft.","Turm nach d8 – der erste Schritt der Treppe."],"en":["Two rooks roll the king to the edge like a lawnmower and mate.","The rooks check alternately while a passed pawn lends a hand.","Rook to d8 – the first step of the staircase."],"hr":["Dva topa kotrljaju kralja prema rubu poput kosilice i matiraju.","Topovi naizmjenično šahiraju dok slobodni pješak pomaže.","Top na d8 — prvi korak stepenica."]}', HintsVersion=1 WHERE LineId LIKE '%:031.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die beiden Türme treiben den König treppenförmig in die Enge.","Die Türme schieben den König zurück, der Läufer riegelt das letzte Fluchtfeld ab.","Turm nach a8 – Beginn der Treppenführung."],"en":["The two rooks drive the king into a corner along the staircase.","The rooks push the king back while the bishop seals the last escape square.","Rook to a8 – the start of the staircase chase."],"hr":["Dva topa stepenasto tjeraju kralja u kut.","Topovi guraju kralja unatrag dok lovac zatvara posljednje polje bijega.","Top na a8 — početak stepenastog gonjenja."]}', HintsVersion=1 WHERE LineId LIKE '%:031.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Auf der offenen Linie wartet ein Treppenmatt der Schwerfiguren.","Erst ein Damenopfer reißt die Linie auf, dann walzen die Türme den König nieder.","Dame schlägt auf h7 – das Opfer öffnet die Linie zum Treppenmatt."],"en":["An open file sets up a lawnmower mate with the heavy pieces.","First a queen sacrifice rips the file open, then the rooks bulldoze the king.","Queen takes on h7 – the sacrifice opens the file for the lawnmower mate."],"hr":["Na otvorenoj liniji čeka stepenasti mat teških figura.","Najprije žrtva dame otvara liniju, a onda topovi gaze kralja.","Dama uzima na h7 — žrtva otvara liniju za stepenasti mat."]}', HintsVersion=1 WHERE LineId LIKE '%:031.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer öffnet die Linie für ein Treppenmatt.","Die Dame opfert sich, dann übernehmen die beiden Türme die Treppe.","Dame schlägt auf h7 – das Opfer leitet das Treppenmatt ein."],"en":["A queen sacrifice opens the file for a lawnmower mate.","The queen sacrifices herself, then the two rooks take over the staircase.","Queen takes on h7 – the sacrifice starts the lawnmower mate."],"hr":["Žrtva dame otvara liniju za stepenasti mat.","Dama se žrtvuje, a onda dva topa preuzimaju stepenice.","Dama uzima na h7 — žrtva pokreće stepenasti mat."]}', HintsVersion=1 WHERE LineId LIKE '%:031.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer am Königsflügel bahnt das Treppenmatt an.","Die Dame opfert sich, dann walzen die zwei Schwerfiguren den König nieder.","Dame schlägt auf h7 – das Opfer öffnet die Linie."],"en":["A queen sacrifice on the kingside paves the way to a lawnmower mate.","The queen sacrifices herself, then the two heavy pieces bulldoze the king.","Queen takes on h7 – the sacrifice opens the file."],"hr":["Žrtva dame na kraljevom krilu otvara put stepenastom matu.","Dama se žrtvuje, a onda dvije teške figure gaze kralja.","Dama uzima na h7 — žrtva otvara liniju."]}', HintsVersion=1 WHERE LineId LIKE '%:031.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit Damen- und Turmschach lässt sich der König zum Rand walzen und matt setzen.","Erst zieht ein Damenschach den König heraus, dann erledigen Turm und Dame die Treppe.","Dame nach g5 – Auftakt zum Treppenmatt."],"en":["Queen and rook checks roll the king to the edge for a lawnmower mate.","First a queen check drags the king out, then rook and queen run the staircase.","Queen to g5 – the start of the lawnmower mate."],"hr":["Šahovima dame i topa kralj se može otkotrljati na rub i matirati.","Najprije šah damom izvlači kralja, a onda top i dama izvode stepenice.","Dama na g5 — početak stepenastog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:031.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steckt in ernsten Schwierigkeiten – ein erzwungenes Treppenmatt droht.","Dame und Turm bauen den Angriff auf, während ein Opfer den König entblößt.","Dame nach g6 – der Auftakt zur erzwungenen Mattführung."],"en":["The white king is in serious trouble – a forced lawnmower mate looms.","Queen and rook build the attack while a sacrifice strips the king bare.","Queen to g6 – the start of the forced mating sequence."],"hr":["Bijeli kralj je u ozbiljnoj nevolji — prijeti prisilni stepenasti mat.","Dama i top grade napad dok žrtva ogoljuje kralja.","Dama na g6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:031.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz Materialrückstand steht ein erzwungenes Treppenmatt bereit.","Ein Opfer reißt die Königsstellung auf, dann walzen Turm und Läufer alles nieder.","Dame schlägt auf h2 – das Opfer eröffnet die Mattführung."],"en":["Despite being down material, a forced lawnmower mate is ready.","A sacrifice tears open the king''s shelter, then rook and bishop bulldoze through.","Queen takes on h2 – the sacrifice opens the mating line."],"hr":["Unatoč manjku materijala, spreman je prisilni stepenasti mat.","Žrtva otvara kraljev zaklon, a onda top i lovac sve gaze.","Dama uzima na h2 — žrtva otvara matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:031.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer lockt einen Verteidiger weg und ebnet das Treppenmatt.","Die Dame opfert sich, dann erledigen die beiden Türme den König am Rand.","Dame nach f6 – das Opfer leitet das Treppenmatt ein."],"en":["A queen sacrifice decoys a defender and paves the lawnmower mate.","The queen sacrifices herself, then the two rooks finish the king at the edge.","Queen to f6 – the sacrifice starts the lawnmower mate."],"hr":["Žrtva dame odvlači branitelja i otvara stepenasti mat.","Dama se žrtvuje, a onda dva topa dokrajče kralja na rubu.","Dama na f6 — žrtva pokreće stepenasti mat."]}', HintsVersion=1 WHERE LineId LIKE '%:031.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwächen in der Rochadestellung münden in ein erzwungenes Treppenmatt.","Turm und Dame schwenken zum Königsflügel und reißen die Deckung auf.","Turm nach h3 – Auftakt zur erzwungenen Mattführung."],"en":["Weaknesses around the castled king lead to a forced lawnmower mate.","Rook and queen swing to the kingside and rip open the cover.","Rook to h3 – the start of the forced mating sequence."],"hr":["Slabosti oko rokiranog kralja vode do prisilnog stepenastog mata.","Top i dama prebacuju se na kraljevo krilo i otvaraju zaštitu.","Top na h3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:031.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer und ein Freibauer ebnen den Weg zum Treppenmatt.","Die Dame opfert sich, ein Bauer wird zur Dame, dann walzen die Türme den König nieder.","Dame schlägt auf h6 – das Opfer eröffnet die Mattführung."],"en":["A queen sacrifice and a passed pawn pave the way to a lawnmower mate.","The queen sacrifices herself, a pawn promotes, then the rooks bulldoze the king.","Queen takes on h6 – the sacrifice opens the mating line."],"hr":["Žrtva dame i slobodni pješak otvaraju put stepenastom matu.","Dama se žrtvuje, pješak se pretvara, a onda topovi gaze kralja.","Dama uzima na h6 — žrtva otvara matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:031.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer lenkt einen Verteidiger ab und bahnt das Treppenmatt.","Die Dame opfert sich, dann erledigen Läufer und Turm den König.","Dame schlägt auf e7 – das Opfer leitet das Treppenmatt ein."],"en":["A queen sacrifice deflects a defender and paves the lawnmower mate.","The queen sacrifices herself, then bishop and rook finish the king.","Queen takes on e7 – the sacrifice starts the lawnmower mate."],"hr":["Žrtva dame odvlači branitelja i otvara stepenasti mat.","Dama se žrtvuje, a onda lovac i top dokrajče kralja.","Dama uzima na e7 — žrtva pokreće stepenasti mat."]}', HintsVersion=1 WHERE LineId LIKE '%:031.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer öffnet die Linie für ein Treppenmatt.","Die Dame opfert sich, dann walzen die beiden Türme den König zum Rand.","Dame schlägt auf f6 – das Opfer leitet die Treppe ein."],"en":["A queen sacrifice opens the file for a lawnmower mate.","The queen sacrifices herself, then the two rooks roll the king to the edge.","Queen takes on f6 – the sacrifice starts the staircase."],"hr":["Žrtva dame otvara liniju za stepenasti mat.","Dama se žrtvuje, a onda dva topa kotrljaju kralja prema rubu.","Dama uzima na f6 — žrtva pokreće stepenice."]}', HintsVersion=1 WHERE LineId LIKE '%:031.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer öffnet eine Linie für die Schwerfiguren und ein Treppenmatt.","Erst wird ein Verteidiger weggeopfert, dann übernehmen Dame und Turm.","Läufer schlägt auf h7 – das Opfer öffnet die Linie zum Treppenmatt."],"en":["A sacrifice opens a line for the heavy pieces and a lawnmower mate.","First a defender is sacrificed away, then queen and rook take over.","Bishop takes on h7 – the sacrifice opens the line for the lawnmower mate."],"hr":["Žrtva otvara liniju teškim figurama i stepenasti mat.","Najprije se žrtvuje branitelj, a onda preuzimaju dama i top.","Lovac uzima na h7 — žrtva otvara liniju za stepenasti mat."]}', HintsVersion=1 WHERE LineId LIKE '%:031.017' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer öffnet die Linie für ein erzwungenes Treppenmatt.","Der Springer opfert sich, dann übernehmen Turm und Dame die Treppe.","Springer nach f6 – das Opfer leitet die Mattführung ein."],"en":["A knight sacrifice opens the line for a forced lawnmower mate.","The knight sacrifices itself, then rook and queen run the staircase.","Knight to f6 – the sacrifice starts the mating line."],"hr":["Žrtva skakača otvara liniju za prisilni stepenasti mat.","Skakač se žrtvuje, a onda top i dama izvode stepenice.","Skakač na f6 — žrtva pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:031.018' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer reißt die Königsstellung auf und bahnt das Treppenmatt.","Die Dame opfert sich, dann walzen Turm und Turm den König nieder.","Dame schlägt auf g6 – das Opfer eröffnet die Mattführung."],"en":["A queen sacrifice tears open the king''s shelter and paves the lawnmower mate.","The queen sacrifices herself, then rook and rook bulldoze the king.","Queen takes on g6 – the sacrifice opens the mating line."],"hr":["Žrtva dame otvara kraljev zaklon i otvara stepenasti mat.","Dama se žrtvuje, a onda top i top gaze kralja.","Dama uzima na g6 — žrtva otvara matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:031.019' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer öffnet die Linie für ein erzwungenes Treppenmatt.","Der Springer opfert sich, um die Linie freizulegen, dann schlägt der Turm zu.","Springer nach d3 – das Opfer leitet das Treppenmatt ein."],"en":["A knight sacrifice opens the file for a forced lawnmower mate.","The knight sacrifices itself to clear the file, then the rook strikes.","Knight to d3 – the sacrifice starts the lawnmower mate."],"hr":["Žrtva skakača otvara liniju za prisilni stepenasti mat.","Skakač se žrtvuje da očisti liniju, a onda top udari.","Skakač na d3 — žrtva pokreće stepenasti mat."]}', HintsVersion=1 WHERE LineId LIKE '%:031.020' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Die fehlende Koordination der weißen Figuren erlaubt ein erzwungenes Treppenmatt.","Erst lockst du den König heraus, dann opfert sich der Läufer für die Linie.","Läufer nach b5 – der Auftakt zur erzwungenen Mattführung."],"en":["White''s uncoordinated pieces allow a forced lawnmower mate.","First draw the king out, then the bishop sacrifices itself to open the line.","Bishop to b5 – the start of the forced mating sequence."],"hr":["Nekoordinirane bijele figure dopuštaju prisilni stepenasti mat.","Najprije izvuci kralja, a onda se lovac žrtvuje da otvori liniju.","Lovac na b5 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:031.021' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattfolge steckt in der Stellung – treibe den König und schlage zu.","Dame und Turm arbeiten zusammen; ein Turmschach zwingt den König in das tödliche Dreieck.","Turm gibt Schach auf f8, treibt den König weg und leitet das Matt ein."],"en":["A forced mate is here – drive the king and finish it off.","Queen and rook cooperate; a rook check herds the king into the deadly triangle.","Rook to f8 gives check, pushes the king away and sets up the mate."],"hr":["Ovdje je prisilni mat — potjeraj kralja i dokrajči ga.","Dama i top surađuju; topov šah tjera kralja u smrtonosni trokut.","Top na f8 daje šah, odguruje kralja i priprema mat."]}', HintsVersion=1 WHERE LineId LIKE '%:032.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst ein Matt erzwingen – jage den König mit fortgesetzten Schachs.","Die Dame liefert das Matt, vom Turm gestützt; lenke sie zunächst ins Spiel.","Die Dame zieht nach d6 und beginnt die erzwungene Mattjagd."],"en":["You can force mate – hunt the king with relentless checks.","The queen delivers the mate, backed by the rook; first bring her into play.","The queen goes to d6 and begins the forced mating hunt."],"hr":["Možeš prisiliti mat — lovi kralja neprekidnim šahovima.","Dama daje mat uz topovu podršku; najprije je uključi u napad.","Dama ide na d6 i započinje prisilni lov na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:032.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König steht offen in der Mitte – ein Matt lässt sich erzwingen.","Der gefesselte Verteidiger und das Dameneingreifen weben das Mattnetz; ein Läufer eröffnet es.","Läufer nach f4 leitet die erzwungene Mattfolge ein."],"en":["The king is exposed in the centre – a mate can be forced.","A pinned defender and the entering queen weave the net; a bishop opens it.","Bishop to f4 launches the forced mating sequence."],"hr":["Kralj je izložen u sredini — mat se može prisiliti.","Vezana figura i ulazak dame pletu mrežu; lovac je otvara.","Lovac na f4 pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:032.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattkombination liegt bereit – beginne mit einem Schlag.","Beseitige den Verteidiger, dann übernehmen Turm und Dame die Mattführung.","Springer schlägt auf g5 und startet die erzwungene Mattfolge."],"en":["A forced mating combination is ready – open with a capture.","Remove the defender, then rook and queen take over the mate.","Knight takes on g5 and begins the forced mating line."],"hr":["Prisilna matna kombinacija je spremna — počni uzimanjem.","Ukloni branitelja, zatim top i dama preuzimaju mat.","Skakač uzima na g5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:032.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Matt in wenigen Zügen ist erzwingbar – treibe den König in die Ecke.","Dame und Türme bauen das Mattnetz; ein Damenschlag eröffnet die Jagd.","Dame schlägt auf d8 und beginnt die erzwungene Mattfolge."],"en":["Mate in a few moves can be forced – drive the king to the corner.","Queen and rooks build the net; a queen capture opens the hunt.","Queen takes on d8 and begins the forced mating sequence."],"hr":["Mat u nekoliko poteza je prisilan — potjeraj kralja u kut.","Dama i topovi grade mrežu; uzimanje damom otvara lov.","Dama uzima na d8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:032.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattfolge ist da – der König wird wie auf Schienen getrieben.","Dame und Turm bilden zwei Gleise und treiben den König mit Wechselschachs voran.","Turm nach f3 setzt den König in Bewegung und startet die Mattjagd."],"en":["A forced mate is here – the king is railroaded along the tracks.","Queen and rook form two rails, driving the king with alternating checks.","Rook to f3 sets the king moving and begins the mating hunt."],"hr":["Ovdje je prisilni mat — kralj se tjera kao po tračnicama.","Dama i top čine dvije tračnice i tjeraju kralja naizmjeničnim šahovima.","Top na f3 pokreće kralja i započinje matni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:032.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer öffnet eine erzwungene Mattfolge – wage den Einschlag.","Nach dem Opfer treiben Dame und Turm den König ins tödliche Dreieck.","Turm schlägt auf h5 und opfert sich, um das Matt einzuleiten."],"en":["A sacrifice opens a forced mate – dare the breakthrough.","After the offer, queen and rook herd the king into the deadly triangle.","Rook takes on h5, sacrificing to launch the mate."],"hr":["Žrtva otvara prisilni mat — odvaži se na proboj.","Nakon žrtve dama i top tjeraju kralja u smrtonosni trokut.","Top uzima na h5 žrtvujući se da pokrene mat."]}', HintsVersion=1 WHERE LineId LIKE '%:032.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattfolge wartet – treibe den König über das Brett.","Läufer, Turm und Dame jagen den König mit Wechselschachs ins Matt.","Läufer nach b5 gibt Schach und startet die erzwungene Mattjagd."],"en":["A forced mate awaits – drive the king across the board.","Bishop, rook and queen chase the king into mate with alternating checks.","Bishop to b5 checks and begins the forced mating hunt."],"hr":["Čeka prisilni mat — potjeraj kralja preko ploče.","Lovac, top i dama gone kralja u mat naizmjeničnim šahovima.","Lovac na b5 daje šah i započinje prisilni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:032.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst Matt erzwingen – jage den weißen König mit Schachs.","Dame und Turm bilden die Schienen und treiben den König ins Dreieck.","Dame nach g2 gibt Schach und startet die erzwungene Mattfolge."],"en":["You can force mate – hunt the white king with checks.","Queen and rook form the rails and drive the king into the triangle.","Queen to g2 checks and begins the forced mating sequence."],"hr":["Možeš prisiliti mat — lovi bijelog kralja šahovima.","Dama i top čine tračnice i tjeraju kralja u trokut.","Dama na g2 daje šah i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:032.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattfolge liegt bereit – treibe den weißen König voran.","Dame, Turm und der zweite Turm bilden die Schienen für die Mattjagd.","Dame schlägt auf h1 und gibt Schach, um die Mattfolge zu starten."],"en":["A forced mate is ready – push the white king along.","Queen, rook and the second rook form the rails for the mating hunt.","Queen takes on h1 with check to start the mating sequence."],"hr":["Prisilni mat je spreman — tjeraj bijelog kralja naprijed.","Dama, top i drugi top čine tračnice za matni lov.","Dama uzima na h1 uz šah i započinje mat."]}', HintsVersion=1 WHERE LineId LIKE '%:032.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – treibe den König an den Rand.","Der Turm gibt das Matt, von der Dame gestützt, die die Fluchtfelder deckt.","Turm nach d8 gibt Schach und treibt den König ins Mattnetz."],"en":["A forced mate is ready – drive the king to the edge.","The rook delivers mate, backed by the queen covering the escapes.","Rook to d8 checks and drives the king into the mating net."],"hr":["Spreman je prisilni mat — potjeraj kralja na rub.","Top daje mat uz potporu dame koja pokriva bjegove.","Top na d8 daje šah i tjera kralja u matnu mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:033.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Matt lässt sich erzwingen – bringe alle Figuren ins Spiel.","Springer, Dame und Turm bauen die Mattbox; beginne mit einem Turmschach.","Turm nach d8 gibt Schach und leitet die erzwungene Mattfolge ein."],"en":["Mate can be forced – bring every piece into the attack.","Knight, queen and rook build the kill box; start with a rook check.","Rook to d8 checks and begins the forced mating sequence."],"hr":["Mat se može prisiliti — uključi sve figure u napad.","Skakač, dama i top grade kutiju; počni topovim šahom.","Top na d8 daje šah i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:033.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – opfere, um den König zu fangen.","Dame, Springer und Turm schnüren die Mattbox; ein Springerschlag eröffnet sie.","Springer schlägt auf f7 und gibt Schach, um die Mattfolge zu starten."],"en":["A forced mate is here – sacrifice to trap the king.","Queen, knight and rook tie the kill box; a knight capture opens it.","Knight takes on f7 with check to begin the mating sequence."],"hr":["Ovdje je prisilni mat — žrtvuj da uloviš kralja.","Dama, skakač i top vežu kutiju; uzimanje skakačem je otvara.","Skakač uzima na f7 uz šah i započinje mat."]}', HintsVersion=1 WHERE LineId LIKE '%:033.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst Matt erzwingen – die schwarzen Schwerfiguren jagen den König.","Türme und Dame bauen die Mattbox; ein Damenschach treibt den König vor.","Dame nach h3 gibt Schach und beginnt die erzwungene Mattfolge."],"en":["You can force mate – the black heavy pieces hunt the king.","Rooks and queen build the kill box; a queen check pushes the king on.","Queen to h3 checks and begins the forced mating sequence."],"hr":["Možeš prisiliti mat — crne teške figure love kralja.","Topovi i dama grade kutiju; damin šah tjera kralja naprijed.","Dama na h3 daje šah i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:033.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – ein Opfer reißt die Königsstellung auf.","Türme, Dame und Läufer weben das Netz; opfere zuerst, um die Box zu bauen.","Turm schlägt auf h2 und opfert sich, um die Mattfolge zu starten."],"en":["A forced mate awaits – a sacrifice rips open the king.","Rooks, queen and bishop weave the net; sacrifice first to build the box.","Rook takes on h2, sacrificing to start the mating sequence."],"hr":["Čeka prisilni mat — žrtva otvara kraljevu poziciju.","Topovi, dama i lovac pletu mrežu; najprije žrtvuj da izgradiš kutiju.","Top uzima na h2 žrtvujući se da pokrene mat."]}', HintsVersion=1 WHERE LineId LIKE '%:033.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattfolge ist da – treibe den König wie auf Schienen.","Dame und Turm sind die Gleise; Wechselschachs schieben den König in die Box.","Turm nach f4 gibt Schach und startet die Mattjagd."],"en":["A forced mate is here – railroad the king along the tracks.","Queen and rook are the rails; alternating checks push the king into the box.","Rook to f4 checks and begins the mating hunt."],"hr":["Ovdje je prisilni mat — tjeraj kralja kao po tračnicama.","Dama i top su tračnice; naizmjenični šahovi guraju kralja u kutiju.","Top na f4 daje šah i započinje matni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:033.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bevor – jage den schwarzen König mit Schachs.","Dame und Turm bilden die Schienen und drängen den König in die Mattbox.","Dame nach g6 gibt Schach und beginnt die erzwungene Mattfolge."],"en":["A forced mate is near – hunt the black king with checks.","Queen and rook form the rails and squeeze the king into the kill box.","Queen to g6 checks and begins the forced mating sequence."],"hr":["Prisilni mat je blizu — lovi crnog kralja šahovima.","Dama i top čine tračnice i tjeraju kralja u kutiju.","Dama na g6 daje šah i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:033.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattfolge liegt bereit – treibe den König über die Reihen.","Dame und Turm sind die Schienen, die den König in die Box leiten.","Dame nach g6 gibt Schach und startet die erzwungene Mattjagd."],"en":["A forced mate is ready – drive the king across the ranks.","Queen and rook are the rails guiding the king into the box.","Queen to g6 checks and begins the forced mating hunt."],"hr":["Prisilni mat je spreman — tjeraj kralja preko redova.","Dama i top su tračnice koje vode kralja u kutiju.","Dama na g6 daje šah i započinje prisilni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:033.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst Matt erzwingen – zerre den weißen König in die Mitte.","Türme und Dame bilden die Schienen für die Mattbox; beginne mit einem Schach.","Turm nach d1 gibt Schach und startet die erzwungene Mattfolge."],"en":["You can force mate – drag the white king to the centre.","Rooks and queen form the rails for the kill box; open with a check.","Rook to d1 checks and begins the forced mating sequence."],"hr":["Možeš prisiliti mat — odvuci bijelog kralja u sredinu.","Topovi i dama čine tračnice za kutiju; počni šahom.","Top na d1 daje šah i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:033.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattfolge wartet – ein Opfer beseitigt den Verteidiger.","Turm, Dame und Läufer bauen die Box; opfere zuerst, um die Schienen zu legen.","Bauer schlägt auf g3 und eröffnet die erzwungene Mattfolge."],"en":["A forced mate awaits – a sacrifice removes the defender.","Rook, queen and bishop build the box; sacrifice first to lay the rails.","Pawn takes on g3 and opens the forced mating sequence."],"hr":["Čeka prisilni mat — žrtva uklanja branitelja.","Top, dama i lovac grade kutiju; najprije žrtvuj da postaviš tračnice.","Pješak uzima na g3 i otvara prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:033.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Matt steckt schon in der Eröffnung – der schwarze König ist eingeklemmt.","Der Springer liefert ein ersticktes Matt, weil die eigenen Steine den König einsperren.","Springer nach d6 – ersticktes Matt."],"en":["A mate hides in the opening – the black king is hemmed in.","The knight delivers a smothered mate, the king boxed in by its own men.","Knight to d6 — mate."],"hr":["Mat se krije već u otvaranju — crni kralj je sapet.","Skakač daje ugušeni mat jer kralja zatvaraju vlastite figure.","Skakač na d6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Matt schlummert in der Eröffnung – der König ist von eigenen Steinen umstellt.","Der Springer setzt erstickt matt, weil die eigenen Figuren alle Felder versperren.","Springer nach d6 – ersticktes Matt."],"en":["A mate lurks in the opening – the king is fenced in by its own pieces.","The knight gives a smothered mate, every flight blocked by its own men.","Knight to d6 — mate."],"hr":["Mat vreba u otvaranju — kralja okružuju vlastite figure.","Skakač daje ugušeni mat jer vlastite figure zatvaraju sva polja.","Skakač na d6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schon in der Eröffnung wartet ein Matt – der schwarze König ist eingesperrt.","Der Springer setzt erstickt matt, gefangen von den eigenen Verteidigern.","Springer nach d6 – ersticktes Matt."],"en":["A mate waits already in the opening – the black king is locked in.","The knight delivers a smothered mate, the king caged by its own pieces.","Knight to d6 — mate."],"hr":["Već u otvaranju čeka mat — crni kralj je zatvoren.","Skakač daje ugušeni mat, kralja zatvaraju vlastite figure.","Skakač na d6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz kann in der Eröffnung sofort matt setzen – der weiße König ist eingeengt.","Der schwarze Springer liefert ein ersticktes Matt, der König von eigenen Steinen umstellt.","Springer nach f3 – ersticktes Matt."],"en":["Black can mate at once in the opening – the white king is boxed in.","The black knight gives a smothered mate, the king ringed by its own men.","Knight to f3 — mate."],"hr":["Crni može odmah matirati u otvaranju — bijeli kralj je sapet.","Crni skakač daje ugušeni mat, kralja okružuju vlastite figure.","Skakač na f3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Matt in der Eröffnung wartet – die geschwächte Königsstellung rächt sich.","Die Dame stürmt über die offene Diagonale zum König und setzt matt.","Dame nach g6 – matt."],"en":["A mate in the opening awaits – the weakened king position backfires.","The queen storms along the open diagonal to the king and mates.","Queen to g6 — mate."],"hr":["Mat u otvaranju čeka — oslabljena kraljeva pozicija se sveti.","Dama juri otvorenom dijagonalom do kralja i matira.","Dama na g6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schon in der Eröffnung droht Matt – die offene Königsstellung ist fatal.","Die Dame schlüpft auf der freien Diagonale zum König und setzt matt.","Dame nach g6 – matt."],"en":["Mate looms already in the opening – the open king position is fatal.","The queen slips along the free diagonal to the king and mates.","Queen to g6 — mate."],"hr":["Već u otvaranju prijeti mat — otvorena kraljeva pozicija je kobna.","Dama klizi slobodnom dijagonalom do kralja i matira.","Dama na g6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Eröffnung – ein Damenschach leitet es ein.","Die Dame zieht zum Königsflügel und gibt Schach, dann folgt das Matt.","Dame nach h5 gibt Schach und startet die kurze Mattfolge."],"en":["A forced mate hides in the opening – a queen check sets it up.","The queen swings to the kingside with check, then mate follows.","Queen to h5 checks and begins the short mating sequence."],"hr":["Prisilni mat se krije u otvaranju — damin šah ga priprema.","Dama prelazi na kraljevo krilo uz šah, zatim slijedi mat.","Dama na h5 daje šah i započinje kratki mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz setzt in der Eröffnung sofort matt – die offene Königsstellung ist verheerend.","Die schwarze Dame stürmt auf den geschwächten König und setzt matt.","Dame nach h4 – matt."],"en":["Black mates at once in the opening – the open king position is ruinous.","The black queen storms the weakened king and mates.","Queen to h4 — mate."],"hr":["Crni odmah matira u otvaranju — otvorena kraljeva pozicija je pogubna.","Crna dama juri na oslabljenog kralja i matira.","Dama na h4 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Matt in der Eröffnung wartet – der schwache Punkt vor dem König fällt.","Die Dame schlägt den verwundbaren Bauern beim König und setzt matt.","Dame schlägt auf f7 – matt."],"en":["A mate in the opening awaits – the weak point by the king falls.","The queen takes the vulnerable pawn beside the king and mates.","Queen takes on f7 — mate."],"hr":["Mat u otvaranju čeka — slaba točka kraj kralja pada.","Dama uzima ranjivog pješaka uz kralja i matira.","Dama uzima na f7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Matt in der Eröffnung steht bereit – der Punkt vor dem König ist der Schwachpunkt.","Die Dame, vom Läufer gestützt, schlägt am König ein und setzt matt.","Dame schlägt auf f7 – matt."],"en":["A mate in the opening is ready – the square by the king is the weak point.","The queen, backed by the bishop, strikes at the king and mates.","Queen takes on f7 — mate."],"hr":["Mat u otvaranju je spreman — polje kraj kralja je slaba točka.","Dama, uz potporu lovca, udara na kralja i matira.","Dama uzima na f7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schon in der Eröffnung lauert ein erzwungenes Matt am verwundbaren Königsfeld.","Dein Läufer steht ideal und deine Dame stürmt zum Schwachpunkt direkt vor dem König.","Damenschlag auf f2 – matt."],"en":["A forced mate already lurks against the vulnerable square by the king.","Your bishop is perfectly placed while your queen storms the soft spot in front of the king.","Queen takes on f2 — mate."],"hr":["Već u otvaranju vreba prisilni mat na ranjivom polju kraj kralja.","Tvoj lovac je idealno postavljen dok dama juriša na slabu točku pred kraljem.","Dama uzima na f2 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mitten in der Eröffnung gibt es ein erzwungenes Matt am Schwachpunkt vor dem König.","Deine Dame liefert den Schlag, der Läufer kontrolliert die Fluchtlinie.","Dame schlägt auf f2 – matt."],"en":["Right in the opening there is a forced mate at the weak spot before the king.","Your queen delivers the blow while the bishop covers the escape.","Queen takes on f2 — mate."],"hr":["Usred otvaranja postoji prisilni mat na slaboj točki pred kraljem.","Tvoja dama zadaje udarac dok lovac pokriva bijeg.","Dama uzima na f2 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein klassisches Eröffnungsopfer erzwingt das Matt.","Der Läufer opfert sich am Schwachpunkt, dann vollenden die Springer.","Läufer schlägt auf f7 und leitet das Matt ein."],"en":["A classic opening sacrifice forces the mate.","The bishop sacrifices itself at the weak point, then the knights finish.","Bishop takes on f7, starting the forced mate."],"hr":["Klasična žrtva u otvaranju forsira mat.","Lovac se žrtvuje na slaboj točki, a zatim skakači dovršavaju.","Lovac uzima na f7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.018' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springeropfer reißt die Königsstellung auf und erzwingt das Matt.","Erst lockt ein Springer den Bauern weg, dann schlägt der Läufer durch.","Springer schlägt auf f6 und beginnt die Mattkombination."],"en":["A knight sacrifice tears open the king and forces mate.","First a knight lures a pawn away, then the bishop crashes through.","Knight takes on f6, starting the mating combination."],"hr":["Žrtva skakača otvara kraljev zaklon i forsira mat.","Prvo skakač odvlači pješaka, a zatim lovac probija.","Skakač uzima na f6 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:034.019' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Eröffnungsopfer am Schwachpunkt erzwingt das Matt.","Der Läufer opfert sich vor dem König, danach kommt die Figur mit Tempo.","Läufer schlägt auf f7 und leitet das Matt ein."],"en":["An opening sacrifice at the weak point forces mate.","The bishop sacrifices before the king, then a piece joins with tempo.","Bishop takes on f7, beginning the forced mate."],"hr":["Žrtva u otvaranju na slaboj točki forsira mat.","Lovac se žrtvuje pred kraljem, zatim figura dolazi s tempom.","Lovac uzima na f7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:034.020' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer am verwundbaren Feld erzwingt das Matt.","Dein Läufer schlägt vor dem König ein, dann setzt der Springer das Netz.","Läufer schlägt auf f2 und beginnt die Mattführung."],"en":["A sacrifice at the vulnerable square forces mate.","Your bishop strikes before the king, then the knight weaves the net.","Bishop takes on f2, beginning the forced mate."],"hr":["Žrtva na ranjivom polju forsira mat.","Tvoj lovac udara pred kraljem, a zatim skakač plete mrežu.","Lovac uzima na f2 i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:034.021' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein versteckter Springerzug setzt sofort matt.","Der Springer dringt ein und der König erstickt an den eigenen Figuren.","Springer schlägt auf d6 – matt."],"en":["A hidden knight move delivers immediate mate.","The knight leaps in and the king is smothered by its own pieces.","Knight takes on d6 — mate."],"hr":["Skriveni potez skakača daje neposredan mat.","Skakač uskače, a kralja guše vlastite figure.","Skakač uzima na d6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer am Schwachpunkt erzwingt das Matt.","Der Läufer schlägt vor dem König, dann vollenden die Springer.","Läufer schlägt auf f7 und leitet das Matt ein."],"en":["A sacrifice at the weak point forces mate.","The bishop strikes before the king, then the knights finish.","Bishop takes on f7, starting the forced mate."],"hr":["Žrtva na slaboj točki forsira mat.","Lovac udara pred kraljem, a zatim skakači dovršavaju.","Lovac uzima na f7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer auf der zweiten Reihe erzwingt das Matt.","Die Türme arbeiten zusammen, der Läufer hält die lange Diagonale.","Turm schlägt auf g7 und beginnt das Matt."],"en":["A rook sacrifice on the rank forces the mate.","The rooks work together while the bishop rules the long diagonal.","Rook takes on g7, beginning the forced mate."],"hr":["Žrtva topa forsira mat.","Topovi surađuju dok lovac vlada dugom dijagonalom.","Top uzima na g7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Ablenkungsopfer öffnet den Weg zum erzwungenen Matt.","Der Turm lockt die Dame weg, dann vollendet die eigene Dame.","Turm schlägt auf c8 und leitet das Matt ein."],"en":["A deflecting sacrifice clears the way to forced mate.","The rook lures the queen away, then your own queen finishes.","Rook takes on c8, starting the forced mate."],"hr":["Žrtva odvlačenja otvara put do prisilnog mata.","Top odvlači damu, a zatim tvoja dama dovršava.","Top uzima na c8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Kombination am König erzwingt das Matt auf der Grundreihe.","Die Dame dringt ein, danach entscheidet der Turm auf der letzten Reihe.","Dame zieht nach d5 und beginnt das erzwungene Matt."],"en":["A combination against the king forces a back-rank mate.","The queen invades, then the rook decides on the last rank.","Queen to d5, beginning the forced mate."],"hr":["Kombinacija protiv kralja forsira mat na zadnjoj liniji.","Dama prodire, a zatim top odlučuje na posljednjem redu.","Dama na d5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Selbst im Endspiel gibt es ein erzwungenes Matt mit wenigen Steinen.","Der Springer treibt den König, ein Bauer gibt den letzten Stoß.","Springer schlägt auf b7 und leitet das Matt ein."],"en":["Even in the endgame there is a forced mate with few pieces.","The knight drives the king while a pawn gives the final push.","Knight takes on b7, starting the forced mate."],"hr":["Čak i u završnici postoji prisilni mat s malo figura.","Skakač goni kralja dok pješak zadaje posljednji udarac.","Skakač uzima na b7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springermanöver erzwingt das Matt in der Königsecke.","Der Springer nimmt ein Fluchtfeld, der Turm vollendet.","Springer schlägt auf h6 und beginnt das erzwungene Matt."],"en":["A knight maneuver forces mate in the king''s corner.","The knight removes a flight square while the rook finishes.","Knight takes on h6, beginning the forced mate."],"hr":["Manevar skakača forsira mat u kraljevu kutu.","Skakač oduzima polje bijega dok top dovršava.","Skakač uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer öffnet die Stellung zum erzwungenen Matt.","Der Turm lockt eine Deckung weg, dann stößt ein Bauer durch.","Turm schlägt auf f6 und leitet das Matt ein."],"en":["A rook sacrifice opens the position for a forced mate.","The rook lures away a defender, then a pawn pushes through.","Rook takes on f6, starting the forced mate."],"hr":["Žrtva topa otvara položaj za prisilni mat.","Top odvlači branitelja, a zatim pješak probija.","Top uzima na f6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer am König erzwingt das Matt.","Die Dame schlägt vor dem König ein, dann liefert der Turm den Schlag.","Dame schlägt auf h7 und leitet das Matt ein."],"en":["A queen sacrifice at the king forces mate.","The queen strikes before the king, then the rook delivers.","Queen takes on h7, starting the forced mate."],"hr":["Žrtva dame kod kralja forsira mat.","Dama udara pred kraljem, a zatim top zadaje udarac.","Dama uzima na h7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Folge von Turmopfern erzwingt das Matt am eingeklemmten König.","Die Türme stürmen nacheinander die offene Linie zum König.","Turm schlägt auf h1 und beginnt die erzwungene Mattserie."],"en":["A series of rook sacrifices forces mate on the cornered king.","The rooks storm the open file at the king one after another.","Rook takes on h1, starting the forced mating sequence."],"hr":["Niz žrtava topova forsira mat na sabijenom kralju.","Topovi jedan za drugim jurišaju otvorenom linijom prema kralju.","Top uzima na h1 i započinje prisilni matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:035.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Im Endspiel führt ein präziser Plan zum erzwungenen Matt.","Der vorgerückte Bauer und der Springer weben das Mattnetz.","Bauer zieht nach a7 und leitet das erzwungene Matt ein."],"en":["In the endgame a precise plan leads to forced mate.","The advanced pawn and the knight weave the mating net.","Pawn to a7, starting the forced mate."],"hr":["U završnici precizan plan vodi do prisilnog mata.","Napredni pješak i skakač pletu matnu mrežu.","Pješak na a7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein ersticktes Matt ein.","Erst opfert die Dame, dann setzt der Springer das erstickte Matt.","Dame schlägt auf g8 und beginnt das erzwungene Matt."],"en":["A queen sacrifice leads to a smothered mate.","First the queen sacrifices, then the knight smothers the king.","Queen takes on g8, beginning the forced mate."],"hr":["Žrtva dame uvodi ugušeni mat.","Prvo se dama žrtvuje, zatim skakač daje ugušeni mat.","Dama uzima na g8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer- und Turmopfer erzwingt das Matt am König.","Der Springer öffnet die Linie, dann opfert sich der Turm vor dem König.","Springer schlägt auf e7 und leitet das erzwungene Matt ein."],"en":["A knight and rook sacrifice forces mate against the king.","The knight opens lines, then the rook sacrifices before the king.","Knight takes on e7, starting the forced mate."],"hr":["Žrtva skakača i topa forsira mat na kralju.","Skakač otvara linije, a zatim se top žrtvuje pred kraljem.","Skakač uzima na e7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine Opferfolge erzwingt das Matt auf der Grundreihe.","Dame und Läufer lenken die Deckung ab, dann entscheidet der Turm.","Dame schlägt auf f1 und beginnt die erzwungene Mattführung."],"en":["A series of sacrifices forces mate on the back rank.","Queen and bishop divert the defense, then the rook decides.","Queen takes on f1, beginning the forced mate."],"hr":["Niz žrtava forsira mat na zadnjoj liniji.","Dama i lovac odvlače obranu, a zatim top odlučuje.","Dama uzima na f1 i započinje prisilni matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:035.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer erzwingt das Matt mit Dame und Läufer.","Der Turm lockt eine Figur weg, dann schlägt die Dame zu.","Turm schlägt auf e8 und leitet das erzwungene Matt ein."],"en":["A rook sacrifice forces mate with queen and bishop.","The rook lures a piece away, then the queen strikes.","Rook takes on e8, starting the forced mate."],"hr":["Žrtva topa forsira mat damom i lovcem.","Top odvlači figuru, a zatim dama udara.","Top uzima na e8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer erzwingt das Matt am offenen König.","Der Turm öffnet die Königsstellung, dann jagt die Dame.","Turm zieht nach g7 und beginnt das erzwungene Matt."],"en":["A rook sacrifice forces mate against the exposed king.","The rook cracks the king''s shelter, then the queen hunts.","Rook to g7, beginning the forced mate."],"hr":["Žrtva topa forsira mat na otkrivenom kralju.","Top razbija kraljev zaklon, a zatim dama lovi.","Top na g7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.017' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer treibt den König ins Matt.","Die Dame jagt den König heraus, der Läufer schneidet die Felder ab.","Dame schlägt auf b8 und leitet das erzwungene Matt ein."],"en":["A queen sacrifice drives the king into mate.","The queen hunts the king out while the bishop cuts off squares.","Queen takes on b8, starting the forced mate."],"hr":["Žrtva dame goni kralja u mat.","Dama izgoni kralja dok lovac odsijeca polja.","Dama uzima na b8 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.018' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein langes Walzenmatt erzwingt das Ende mit Turm und Dame.","Erst opfert sich die Dame, dann walzen die Türme den König nieder.","Dame schlägt auf f7 und beginnt das erzwungene Matt."],"en":["A long rolling mate forces the end with rook and queen.","First the queen sacrifices, then the rooks roll the king down.","Queen takes on f7, beginning the forced mate."],"hr":["Dugi valjkasti mat forsira kraj topom i damom.","Prvo se dama žrtvuje, zatim topovi gaze kralja.","Dama uzima na f7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.019' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer erzwingt das Matt mit Läufer und Springer.","Der Turm reißt die Königsstellung auf, dann schlägt der Läufer durch.","Turm schlägt auf g7 und leitet das erzwungene Matt ein."],"en":["A rook sacrifice forces mate with bishop and knight.","The rook tears open the king while the bishop crashes through.","Rook takes on g7, starting the forced mate."],"hr":["Žrtva topa forsira mat lovcem i skakačem.","Top otvara kraljev zaklon, a zatim lovac probija.","Top uzima na g7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.020' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer erzwingt das Matt mit Dame und Läufer.","Der Turm lockt eine Deckung weg, dann fängt der Läufer den König.","Turm schlägt auf g6 und beginnt das erzwungene Matt."],"en":["A rook sacrifice forces mate with queen and bishop.","The rook lures away a defender, then the bishop traps the king.","Rook takes on g6, beginning the forced mate."],"hr":["Žrtva topa forsira mat damom i lovcem.","Top odvlači branitelja, a zatim lovac hvata kralja.","Top uzima na g6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.021' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer in der Eröffnung erzwingt das Matt.","Die Dame opfert sich am Schwachpunkt, dann gibt ein Bauer den letzten Stoß.","Dame schlägt auf f7 und leitet das erzwungene Matt ein."],"en":["A queen sacrifice in the opening forces mate.","The queen sacrifices at the weak point, then a pawn gives the final blow.","Queen takes on f7, starting the forced mate."],"hr":["Žrtva dame u otvaranju forsira mat.","Dama se žrtvuje na slaboj točki, a zatim pješak zadaje posljednji udarac.","Dama uzima na f7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.022' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferzug leitet ein erzwungenes Matt am König ein.","Der Läufer dringt ein, dann liefert der Turm über die offene Linie das Matt.","Läufer schlägt auf e3 und beginnt das erzwungene Matt."],"en":["A bishop move starts a forced mate against the king.","The bishop invades, then the rook delivers down the open file.","Bishop takes on e3, beginning the forced mate."],"hr":["Potez lovca pokreće prisilni mat na kralju.","Lovac prodire, a zatim top zadaje mat otvorenom linijom.","Lovac uzima na e3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.023' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenmanöver erzwingt das Matt am König.","Die Dame schwenkt herum und treibt den König ins Mattnetz.","Dame zieht nach c4 und leitet das erzwungene Matt ein."],"en":["A queen maneuver forces mate against the king.","The queen swings over and drives the king into the mating net.","Queen to c4, starting the forced mate."],"hr":["Manevar dame forsira mat na kralju.","Dama prelazi i goni kralja u matnu mrežu.","Dama na c4 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.024' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer am Schwachpunkt erzwingt das Matt.","Der Turm opfert sich vor dem König, dann schlägt die Dame durch.","Turm schlägt auf f7 und leitet das erzwungene Matt ein."],"en":["A rook sacrifice at the weak point forces mate.","The rook sacrifices before the king, then the queen crashes through.","Rook takes on f7, starting the forced mate."],"hr":["Žrtva topa na slaboj točki forsira mat.","Top se žrtvuje pred kraljem, a zatim dama probija.","Top uzima na f7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.025' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König im Zentrum ist gefangen – hier steckt ein erzwungenes Matt.","Die Dame zwingt den feindlichen König nach vorn, und die Türme bauen den tödlichen Käfig.","Dame zieht nach d3 und treibt den König in das Mattnetz."],"en":["The enemy king is caught in the open — a forced mate is here.","Your queen drives the king forward while the rooks build the killing cage.","Queen to d3 starts the forced mating net."],"hr":["Protivnički kralj zarobljen je u centru — tu se krije prisilni mat.","Dama tjera kralja naprijed dok topovi grade smrtonosni kavez.","Dama na d3 započinje prisilnu matnu mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:035.026' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König steht noch in der Mitte – ein schnelles erzwungenes Matt droht.","Dame und Läufer zielen gemeinsam auf das schwache Feld vor dem König.","Dame nach h5 leitet das erzwungene Matt ein."],"en":["The king is still in the centre — a quick forced mate looms.","Queen and bishop combine against the weak square near the king.","Queen to h5 begins the forced mate."],"hr":["Kralj je još u centru — prijeti brzi prisilni mat.","Dama i lovac zajedno gađaju slabo polje pokraj kralja.","Dama na h5 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.027' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König ist von eigenen Bauern erstickt – ein Matt liegt in der Luft.","Ein Turmopfer reißt die Königsstellung auf, der zweite Turm vollendet.","Turm schlägt auf g6 und beginnt das erzwungene Matt."],"en":["The king is boxed in by his own pawns — mate is in the air.","A rook sacrifice tears open the cover so the second rook finishes.","Rook takes on g6 to start the forced mate."],"hr":["Kralja guše vlastiti pješaci — mat visi u zraku.","Žrtva topa otvara zaklon kako bi drugi top dovršio.","Top uzima na g6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.028' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König klebt im Zentrum – ein erzwungenes Matt wartet.","Ein vorgerückter Bauer und der Springer schnüren das Mattnetz.","Bauer schlägt auf b7 und beginnt die Mattjagd."],"en":["The king is stuck in the centre — a forced mate awaits.","An advanced pawn and the knight weave the mating net.","Pawn takes on b7 to begin the mating attack."],"hr":["Kralj je zaglavio u centru — čeka prisilni mat.","Napredni pješak i skakač pletu matnu mrežu.","Pješak uzima na b7 i započinje matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:035.029' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der bloßgestellte König fällt einem erzwungenen Matt zum Opfer.","Ein Läuferopfer lockt eine Figur weg, dann schlägt der Bauer durch.","Läufer schlägt auf f6 und leitet das Matt ein."],"en":["The exposed king falls to a forced mate.","A bishop sacrifice lures a defender away, then the pawn strikes.","Bishop takes on f6 to begin the mate."],"hr":["Izloženi kralj pada od prisilnog mata.","Žrtva lovca odvlači branitelja, a onda pješak udara.","Lovac uzima na f6 i započinje mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.030' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König wird an den Rand gedrängt – ein Matt ist erzwungen.","Der Turm verfolgt den König, gestützt vom weit vorgerückten Bauern.","Turm schlägt auf g7 und treibt den König ins Matt."],"en":["The king is pushed to the edge — mate is forced.","The rook hunts the king, backed by the far-advanced pawn.","Rook takes on g7 to drive the king to mate."],"hr":["Kralj je potjeran na rub — mat je prisilan.","Top lovi kralja uz potporu daleko naprednog pješaka.","Top uzima na g7 i tjera kralja u mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.031' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Königsflügel ist morsch – ein erzwungenes Matt droht.","Ein Damenopfer öffnet die Tür, dann setzt der Springer matt.","Dame schlägt auf h6 und leitet das erzwungene Matt ein."],"en":["The kingside is rotten — a forced mate looms.","A queen sacrifice opens the door, then the knight delivers mate.","Queen takes on h6 to begin the forced mate."],"hr":["Kraljevo krilo je trulo — prijeti prisilni mat.","Žrtva dame otvara vrata, a onda skakač daje mat.","Dama uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.032' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist eingeengt – Schwarz hat ein erzwungenes Matt.","Der Turm dringt ein und liefert auf der Grundreihe das Matt.","Turm schlägt auf g2 und beginnt das Matt."],"en":["The white king is cramped — Black has a forced mate.","The rook infiltrates and delivers mate along the back.","Rook takes on g2 to begin the mate."],"hr":["Bijeli kralj je stiješnjen — crni ima prisilni mat.","Top prodire i daje mat uz posljednji red.","Top uzima na g2 i započinje mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.033' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König hinter seinem Bauern ist mattreif.","Ein Turmopfer räumt die Linie, dann schlägt der zweite schwere Stein zu.","Turm nach f8 leitet das erzwungene Matt ein."],"en":["The king behind his own pawn is ripe for mate.","A rook sacrifice clears the line, then the heavy pieces strike.","Rook to f8 begins the forced mate."],"hr":["Kralj iza vlastitog pješaka zreo je za mat.","Žrtva topa čisti liniju, a onda teške figure udaraju.","Top na f8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.034' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt gegen den eingeengten König.","Ein Damenopfer lenkt den Verteidiger ab, dann matt auf der Grundreihe.","Dame nach c1 leitet das erzwungene Matt ein."],"en":["Black has a forced mate against the boxed-in king.","A queen sacrifice deflects the defender, then mate on the back rank.","Queen to c1 begins the forced mate."],"hr":["Crni ima prisilni mat protiv stiješnjenog kralja.","Žrtva dame odvlači branitelja, a onda mat na posljednjem redu.","Dama na c1 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.035' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird aufgerissen – Schwarz setzt erzwungen matt.","Ein Läuferopfer holt den König heraus, dann jagen Turm und Dame.","Läufer schlägt auf g2 und beginnt die Mattjagd."],"en":["The white king is ripped open — Black forces mate.","A bishop sacrifice pulls the king out, then rook and queen chase.","Bishop takes on g2 to begin the mating hunt."],"hr":["Bijeli kralj je razotkriven — crni prisilno daje mat.","Žrtva lovca izvlači kralja, a onda top i dama love.","Lovac uzima na g2 i započinje matni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:035.036' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König im Zentrum fällt einem erzwungenen Matt zum Opfer.","Ein Damenopfer lockt eine Figur weg, dann setzt der Springer matt.","Dame schlägt auf e6 und leitet das Matt ein."],"en":["The centralized king falls to a forced mate.","A queen sacrifice lures a piece away, then the knight mates.","Queen takes on e6 to begin the mate."],"hr":["Kralj u centru pada od prisilnog mata.","Žrtva dame odvlači figuru, a onda skakač daje mat.","Dama uzima na e6 i započinje mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.037' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Zug setzt den weißen König matt.","Der eingedrungene Turm liefert das tödliche Schach.","Turm nach f1 – matt."],"en":["A single move mates the white king.","The infiltrated rook delivers the killing check.","Rook to f1 — mate."],"hr":["Jedan jedini potez daje mat bijelom kralju.","Prodrli top daje smrtonosni šah.","Top na f1 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.038' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König steht offen im Zentrum – ein erzwungenes Matt wartet.","Der Springer geht mit Schach voran, dann vollendet der Turm.","Springer schlägt auf f6 und leitet das Matt ein."],"en":["The king stands exposed in the centre — a forced mate awaits.","The knight leads with check, then the rook finishes.","Knight takes on f6 to begin the mate."],"hr":["Kralj stoji izložen u centru — čeka prisilni mat.","Skakač vodi sa šahom, a onda top dovršava.","Skakač uzima na f6 i započinje mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.039' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand fällt einem erzwungenen Matt zum Opfer.","Ein Damenopfer räumt die Reihe, dann arbeiten die Läufer zusammen.","Dame nach d8 leitet das erzwungene Matt ein."],"en":["The king on the edge falls to a forced mate.","A queen sacrifice clears the rank, then the bishops combine.","Queen to d8 begins the forced mate."],"hr":["Kralj na rubu pada od prisilnog mata.","Žrtva dame čisti red, a onda lovci surađuju.","Dama na d8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.040' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der nackte schwarze König ist in einem Mattkäfig gefangen.","Dame und Turm umstellen den König und schließen das Netz.","Dame nach c6 leitet das erzwungene Matt ein."],"en":["The bare black king is trapped in a mating box.","Queen and rook surround the king and close the net.","Queen to c6 begins the forced mate."],"hr":["Goli crni kralj zarobljen je u matnom kavezu.","Dama i top okružuju kralja i zatvaraju mrežu.","Dama na c6 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.041' AND BookFileName='chessable-u5-243265.pgn';
