UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt gegen den König in der Ecke.","Ein Turmopfer öffnet die Linie, dann setzt der andere Turm matt.","Turm nach a3 leitet das erzwungene Matt ein."],"en":["Black has a forced mate against the cornered king.","A rook sacrifice opens the line, then the other rook mates.","Rook to a3 begins the forced mate."],"hr":["Crni ima prisilni mat protiv kralja u kutu.","Žrtva topa otvara liniju, a onda drugi top daje mat.","Top na a3 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.044' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt auf der Grundreihe des weißen Königs.","Wiederholte Opfer ziehen die Verteidiger weg, dann fällt die Grundreihe.","Dame schlägt auf f2 und beginnt die erzwungene Mattfolge."],"en":["Black forces mate on the white king''s back rank.","Repeated sacrifices drag the defenders off, then the back rank falls.","Queen takes on f2 to begin the forced sequence."],"hr":["Crni prisiljava mat na posljednjem redu bijelog kralja.","Ponovljene žrtve odvlače branitelje, a onda pada posljednji red.","Dama uzima na f2 i započinje prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.045' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König wird aufgerissen – ein erzwungenes Matt folgt.","Ein Turmopfer holt den König heraus, dann übernehmen die anderen Steine.","Turm schlägt auf g7 und leitet die Mattjagd ein."],"en":["The king is ripped open — a forced mate follows.","A rook sacrifice pulls the king out, then the rest take over.","Rook takes on g7 to begin the mating hunt."],"hr":["Kralj je razotkriven — slijedi prisilni mat.","Žrtva topa izvlači kralja, a onda preuzimaju ostale figure.","Top uzima na g7 i započinje matni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:035.046' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt gegen den eingeengten König.","Die Dame manövriert sich an den entscheidenden Diagonalpunkt.","Dame nach h3 leitet das erzwungene Matt ein."],"en":["Black has a forced mate against the cramped king.","The queen maneuvers to the decisive diagonal point.","Queen to h3 begins the forced mate."],"hr":["Crni ima prisilni mat protiv stiješnjenog kralja.","Dama manevrira do odlučujuće dijagonalne točke.","Dama na h3 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.047' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über das Brett gejagt – Matt ist erzwungen.","Dame und Turm treiben den König in einen tödlichen Käfig.","Dame schlägt auf d8 und beginnt die Mattjagd."],"en":["The black king is chased across the board — mate is forced.","Queen and rook drive the king into a killing box.","Queen takes on d8 to begin the mating hunt."],"hr":["Crni kralj je potjeran preko ploče — mat je prisilan.","Dama i top tjeraju kralja u smrtonosni kavez.","Dama uzima na d8 i započinje matni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:035.048' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird umstellt – Schwarz erzwingt das Matt.","Der Turm zwingt den König in die Ecke, der Springer hilft mit.","Turm schlägt auf a8 und leitet das erzwungene Matt ein."],"en":["The white king gets surrounded — Black forces mate.","The rook forces the king into the corner, the knight assists.","Rook takes on a8 to begin the forced mate."],"hr":["Bijeli kralj je opkoljen — crni prisiljava mat.","Top tjera kralja u kut, a skakač pomaže.","Top uzima na a8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.049' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König klemmt zwischen den eigenen Steinen – ein Matt droht.","Ein Damen- und Turmopfer entblößen den König für den Mattschlag.","Dame schlägt auf h6 und leitet das erzwungene Matt ein."],"en":["The king is wedged among his own pieces — mate looms.","A queen and rook sacrifice strip the king bare for the finish.","Queen takes on h6 to begin the forced mate."],"hr":["Kralj je zaglavljen među vlastitim figurama — prijeti mat.","Žrtva dame i topa razgolićuje kralja za završni udarac.","Dama uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.050' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt gegen den weißen König.","Die Türme arbeiten im Tandem und schnüren das Mattnetz.","Turm schlägt auf g2 und leitet die erzwungene Mattfolge ein."],"en":["Black has a forced mate against the white king.","The rooks work in tandem to weave the mating net.","Rook takes on g2 to begin the forced sequence."],"hr":["Crni ima prisilni mat protiv bijelog kralja.","Topovi rade u tandemu i pletu matnu mrežu.","Top uzima na g2 i započinje prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.051' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der König am Rand ist mattreif – ein erzwungenes Matt wartet.","Ein Turmopfer öffnet die Reihe, dann liefern Dame und Bauer das Matt.","Turm nach f8 leitet das erzwungene Matt ein."],"en":["The king on the edge is ripe for mate — a forced mate awaits.","A rook sacrifice opens the rank, then queen and pawn deliver mate.","Rook to f8 begins the forced mate."],"hr":["Kralj na rubu zreo je za mat — čeka prisilni mat.","Žrtva topa otvara red, a onda dama i pješak daju mat.","Top na f8 započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.052' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König in der Ecke ist mattreif.","Ein Turmopfer entblößt den König, dann setzt der zweite Turm matt.","Turm schlägt auf h7 und leitet das erzwungene Matt ein."],"en":["The black king in the corner is ripe for mate.","A rook sacrifice strips the king, then the second rook mates.","Rook takes on h7 to begin the forced mate."],"hr":["Crni kralj u kutu zreo je za mat.","Žrtva topa razgolićuje kralja, a onda drugi top daje mat.","Top uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.053' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der eingeengte König fällt einem erzwungenen Matt zum Opfer.","Eine Bauernumwandlung in einen Springer setzt das Mattnetz fort.","Bauer wandelt auf f8 in einen Springer um und leitet das Matt ein."],"en":["The cramped king falls to a forced mate.","Underpromoting the pawn to a knight continues the mating net.","Pawn promotes to a knight on f8 to begin the mate."],"hr":["Stiješnjeni kralj pada od prisilnog mata.","Promocija pješaka u skakača nastavlja matnu mrežu.","Pješak se promovira u skakača na f8 i započinje mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.054' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt gegen den weißen König.","Ein Turmopfer lenkt ab, dann führt der Springer das Matt herbei.","Turm schlägt auf e1 und leitet das erzwungene Matt ein."],"en":["Black has a forced mate against the white king.","A rook sacrifice deflects, then the knight engineers the mate.","Rook takes on e1 to begin the forced mate."],"hr":["Crni ima prisilni mat protiv bijelog kralja.","Žrtva topa odvlači, a onda skakač priprema mat.","Top uzima na e1 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.055' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – treibe den König in die Enge.","Deine schweren Figuren halten den König fest, ein Bauer gibt den letzten Stoß.","Beginne mit dem Turmschach von e8 nach g8 – das Matt folgt erzwungen."],"en":["A forced mate is here — drive the king into the corner.","Your heavy pieces pin the king down while a pawn delivers the finish.","Start with the rook from e8 to g8 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — stjeraj kralja u kut.","Tvoje teške figure drže kralja, a pješak zadaje završni udarac.","Počni topom s e8 na g8 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.056' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – räume die Grundreihe frei.","Dein Läufer und Turm bündeln ihre Kraft auf der letzten Reihe.","Beginne mit dem Damenopfer auf e1 – das Matt folgt erzwungen."],"en":["A forced mate awaits — clear the path to the back rank.","Your bishop and rook combine their force on the last rank.","Start with the queen sacrifice on e1 — mate is forced to follow."],"hr":["Čeka te prisilni mat — raščisti put do posljednje linije.","Tvoj lovac i top udružuju snagu na zadnjoj liniji.","Počni žrtvom dame na e1 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.057' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – der König erstickt im eigenen Lager.","Springer und Dame zwingen den König in die Ecke.","Beginne mit dem Springerschach auf h6 – das erstickte Matt folgt."],"en":["A forced mate is in the air — the king suffocates among his own men.","Knight and queen herd the king into the corner.","Start with the knight check on h6 — the smothered mate follows."],"hr":["Prisilni mat je u zraku — kralj se guši među vlastitim figurama.","Skakač i dama tjeraju kralja u kut.","Počni šahom skakačem na h6 — slijedi ugušeni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.058' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – nutze deinen Vorstoß im Zentrum.","Bauer und Springer arbeiten zusammen, der Turm gibt den Rest.","Beginne mit dem Bauernzug nach e3 – das Matt folgt erzwungen."],"en":["A forced mate is here — push your central pawn forward.","Pawn and knight cooperate while the rook finishes the job.","Start with the pawn to e3 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — gurni svog središnjeg pješaka.","Pješak i skakač surađuju, a top dovršava posao.","Počni pješakom na e3 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.059' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – walze den König mit den Türmen ab.","Deine beiden Türme bilden eine rollende Mauer gegen den König.","Beginne mit dem Turmschach auf f7 – das Matt wird erzwungen."],"en":["A forced mate awaits — roll the king down with your rooks.","Your two rooks form an advancing wall against the king.","Start with the rook check on f7 — mate will be forced."],"hr":["Čeka te prisilni mat — valjaj kralja topovima.","Tvoja dva topa čine pokretni zid protiv kralja.","Počni šahom topom na f7 — mat će biti prisiljen."]}', HintsVersion=1 WHERE LineId LIKE '%:035.060' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Stellung – die Diagonalen sind tödlich.","Deine beiden Läufer kreuzen ihre Wirkung auf den König.","Beginne mit dem Damenopfer auf f6 – das Matt folgt erzwungen."],"en":["A forced mate is in the position — the diagonals are lethal.","Your two bishops cross their fire onto the king.","Start with the queen sacrifice on f6 — mate is forced to follow."],"hr":["U poziciji postoji prisilni mat — dijagonale su smrtonosne.","Tvoja dva lovca ukrštaju vatru na kralja.","Počni žrtvom dame na f6 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.061' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – jage den König aufs Feld hinaus.","Turm und Dame fahren den König wie auf Schienen vor sich her.","Beginne mit dem Turmschach auf f8 – das Matt folgt erzwungen."],"en":["A forced mate is here — chase the king out into the open.","Rook and queen drive the king along as if on rails.","Start with the rook check on f8 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — istjeraj kralja na otvoreno.","Top i dama tjeraju kralja kao po tračnicama.","Počni šahom topom na f8 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.062' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Grundreihe ist die Schwäche.","Turm und Dame zielen gemeinsam auf den eingesperrten König.","Beginne mit dem Turmopfer auf f8 – das Matt folgt erzwungen."],"en":["A forced mate awaits — the back rank is the weakness.","Rook and queen aim together at the boxed-in king.","Start with the rook sacrifice on f8 — mate is forced to follow."],"hr":["Čeka te prisilni mat — zadnja linija je slabost.","Top i dama zajedno ciljaju na zatočenog kralja.","Počni žrtvom topa na f8 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.063' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – der König sitzt zwischen eigenen Figuren fest.","Dein Turm liefert das Matt, wenn die Bauerndeckung weggelockt ist.","Beginne mit dem Damenopfer auf g6 – das Matt folgt erzwungen."],"en":["A forced mate is here — the king is wedged between his own men.","Your rook delivers mate once the pawn guard is lured away.","Start with the queen sacrifice on g6 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — kralj je stiješnjen među svojim figurama.","Tvoj top zadaje mat kad se pješak-čuvar odmami.","Počni žrtvom dame na g6 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.064' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Dame dringt unaufhaltsam ein.","Deine Dame und der Läufer bilden ein tödliches Duo am König.","Beginne mit dem Damenschach auf f2 – das Matt folgt erzwungen."],"en":["A forced mate awaits — the queen breaks in unstoppably.","Your queen and bishop form a deadly pair around the king.","Start with the queen check on f2 — mate is forced to follow."],"hr":["Čeka te prisilni mat — dama nezaustavljivo prodire.","Tvoja dama i lovac čine smrtonosni par oko kralja.","Počni šahom damom na f2 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.065' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – zwei Läufer und die Dame sind im Anmarsch.","Ein Damenopfer öffnet den Weg, dann gibt der Läufer das Matt.","Beginne mit dem Damenopfer auf g2 – das Matt folgt erzwungen."],"en":["A forced mate is here — two bishops and the queen close in.","A queen sacrifice opens the way, then the bishop mates.","Start with the queen sacrifice on g2 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — dva lovca i dama nadiru.","Žrtva dame otvara put, a zatim lovac mati.","Počni žrtvom dame na g2 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.066' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Eröffnung – der König wird sofort gejagt.","Läuferopfer und ein Springer fangen den König in der Mitte.","Beginne mit dem Läuferopfer auf f7 – das Matt folgt erzwungen."],"en":["A forced mate is in the opening — the king is hunted at once.","A bishop sacrifice and a knight trap the king in the centre.","Start with the bishop sacrifice on f7 — mate is forced to follow."],"hr":["Prisilni mat krije se u otvaranju — kralj se odmah goni.","Žrtva lovca i skakač hvataju kralja u sredini.","Počni žrtvom lovca na f7 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.067' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Dame schlägt sich durch.","Deine Dame nutzt die Lücken um den feindlichen König gnadenlos aus.","Beginne mit dem Damenzug nach c4 – das Matt folgt erzwungen."],"en":["A forced mate awaits — the queen carves her way through.","Your queen exploits the gaps around the enemy king mercilessly.","Start with the queen to c4 — mate is forced to follow."],"hr":["Čeka te prisilni mat — dama probija put.","Tvoja dama nemilosrdno koristi rupe oko neprijateljskog kralja.","Počni damom na c4 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.068' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Diagonalen führen zum König.","Beide Läufer kreuzen ihre Linien, ein Opfer reißt die Deckung ein.","Beginne mit dem Turmopfer auf e6 – das Matt folgt erzwungen."],"en":["A forced mate is here — the diagonals lead to the king.","Both bishops cross their lines while a sacrifice tears the cover.","Start with the rook sacrifice on e6 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — dijagonale vode do kralja.","Oba lovca ukrštaju linije dok žrtva razdire zaštitu.","Počni žrtvom topa na e6 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.069' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – zwei Springer umzingeln den König.","Deine beiden Springer weben ein Netz um den feindlichen König.","Beginne mit dem Springerschach auf e2 – das Matt folgt erzwungen."],"en":["A forced mate is here — two knights surround the king.","Your pair of knights weaves a net around the enemy king.","Start with the knight check on e2 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — dva skakača okružuju kralja.","Tvoj par skakača plete mrežu oko neprijateljskog kralja.","Počni šahom skakačem na e2 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.070' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Grundreihe ist offen.","Dein vorgeschobener Bauer und der Turm stürmen die letzte Reihe.","Beginne mit dem Bauernzug nach f7 – das Matt folgt erzwungen."],"en":["A forced mate awaits — the back rank lies open.","Your advanced pawn and rook storm the last rank.","Start with the pawn to f7 — mate is forced to follow."],"hr":["Čeka te prisilni mat — zadnja linija je otvorena.","Tvoj napredni pješak i top jurišaju na posljednju liniju.","Počni pješakom na f7 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.071' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – der Springer wirbelt um den König.","Springer und Dame treiben den König in ein erstickendes Netz.","Beginne mit dem Damenschach auf b5 – das Matt wird erzwungen."],"en":["A forced mate is here — the knight whirls around the king.","Knight and queen drive the king into a smothering net.","Start with the queen check on b5 — mate will be forced."],"hr":["Ovdje postoji prisilni mat — skakač kruži oko kralja.","Skakač i dama tjeraju kralja u zagušljivu mrežu.","Počni šahom damom na b5 — mat će biti prisiljen."]}', HintsVersion=1 WHERE LineId LIKE '%:035.072' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt schon in der Eröffnung – der König erstickt.","Ein einzelner Springer erledigt alles auf einen Schlag.","Springe nach d3 – matt."],"en":["A forced mate already in the opening — the king suffocates.","A single knight settles everything in one stroke.","Jump to d3 — mate."],"hr":["Prisilni mat već u otvaranju — kralj se guši.","Jedan jedini skakač rješava sve jednim potezom.","Skoči na d3 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.073' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der König erstickt im eigenen Lager.","Ein Damenopfer und der Springer schnüren das tödliche Netz.","Beginne mit dem Damenopfer auf g8 – das erstickte Matt folgt."],"en":["A forced mate awaits — the king suffocates among his own men.","A queen sacrifice and the knight tie the deadly net.","Start with the queen sacrifice on g8 — the smothered mate follows."],"hr":["Čeka te prisilni mat — kralj se guši među svojim figurama.","Žrtva dame i skakač spliću smrtonosnu mrežu.","Počni žrtvom dame na g8 — slijedi ugušeni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.074' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die beiden Läufer harmonieren tödlich.","Ein Opfer lenkt den König ab, dann schlagen die Läufer zu.","Beginne mit dem Damenopfer auf e5 – das Matt folgt erzwungen."],"en":["A forced mate is here — the two bishops harmonise lethally.","A sacrifice pulls the king aside, then the bishops strike.","Start with the queen sacrifice on e5 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — dva lovca smrtonosno surađuju.","Žrtva odvlači kralja, a zatim lovci udaraju.","Počni žrtvom dame na e5 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.075' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Stellung – ein Bauer gibt den letzten Stoß.","Dame und Springer öffnen die Tür, dann mattet der kleine Bauer.","Beginne mit dem Damenopfer auf g7 – das Matt folgt erzwungen."],"en":["A forced mate is here — a humble pawn delivers the finish.","Queen and knight open the door, then the little pawn mates.","Start with the queen sacrifice on g7 — mate is forced to follow."],"hr":["U poziciji postoji prisilni mat — skromni pješak zadaje završni udarac.","Dama i skakač otvaraju vrata, a zatim mali pješak mati.","Počni žrtvom dame na g7 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.076' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Dame klettert zum König hinauf.","Dame und Läufer steigen Stufe um Stufe zum König empor.","Beginne mit dem Damenschach auf h1 – das Matt folgt erzwungen."],"en":["A forced mate awaits — the queen climbs up toward the king.","Queen and bishop ascend step by step toward the king.","Start with the queen check on h1 — mate is forced to follow."],"hr":["Čeka te prisilni mat — dama se penje prema kralju.","Dama i lovac se uspinju korak po korak prema kralju.","Počni šahom damom na h1 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.077' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – Springer und Turm jagen den nackten König.","Dein Springer schneidet Felder ab, der Turm gibt den Rest.","Beginne mit dem Springerschach auf h2 – das Matt folgt erzwungen."],"en":["A forced mate is here — knight and rook hunt the bare king.","Your knight cuts off squares while the rook finishes.","Start with the knight check on h2 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — skakač i top gone golog kralja.","Tvoj skakač oduzima polja, a top dovršava.","Počni šahom skakačem na h2 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.078' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Grundreihe ist die Achillesferse.","Turm und Dame räumen die letzte Reihe für den finalen Stoß frei.","Beginne mit dem Turmschach auf a8 – das Matt folgt erzwungen."],"en":["A forced mate awaits — the back rank is the Achilles heel.","Rook and queen clear the last rank for the final blow.","Start with the rook check on a8 — mate is forced to follow."],"hr":["Čeka te prisilni mat — zadnja linija je Ahilova peta.","Top i dama raščišćavaju posljednju liniju za završni udarac.","Počni šahom topom na a8 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.079' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – treibe den König in die Ecke.","Ein Damenopfer öffnet die Linie, dann mattet der Springer.","Beginne mit dem Damenopfer auf f1 – das Matt folgt erzwungen."],"en":["A forced mate is here — drive the king into the corner.","A queen sacrifice opens the line, then the knight mates.","Start with the queen sacrifice on f1 — mate is forced to follow."],"hr":["Ovdje postoji prisilni mat — stjeraj kralja u kut.","Žrtva dame otvara liniju, a zatim skakač mati.","Počni žrtvom dame na f1 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.080' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Stellung – die Diagonalen sind tödlich.","Beide Läufer bündeln ihre Wirkung auf den entblößten König.","Beginne mit dem Läuferzug nach f7 – das Matt folgt erzwungen."],"en":["A forced mate is here — the diagonals are lethal.","Both bishops concentrate their force on the exposed king.","Start with the bishop to f7 — mate is forced to follow."],"hr":["U poziciji postoji prisilni mat — dijagonale su smrtonosne.","Oba lovca usredotočuju snagu na izloženog kralja.","Počni lovcem na f7 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.081' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt im Bauernendspiel – der Freibauer entscheidet.","König und der vorrückende Bauer übernehmen die Arbeit.","Beginne mit dem Königszug nach c6 – das Matt folgt erzwungen."],"en":["A forced mate lies in the pawn endgame — the passer decides.","King and the advancing pawn do the work together.","Start with the king to c6 — mate is forced to follow."],"hr":["Prisilni mat krije se u pješačkoj završnici — slobodnjak odlučuje.","Kralj i napredujući pješak zajedno obavljaju posao.","Počni kraljem na c6 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.082' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt in der Eröffnung – der König erstickt.","Ein Springer schnürt dem König im eigenen Lager die Luft ab.","Beginne mit dem Springerschach auf h4 – das Matt folgt erzwungen."],"en":["A forced mate is in the opening — the king suffocates.","A knight cuts off the king''s air among his own men.","Start with the knight check on h4 — mate is forced to follow."],"hr":["Prisilni mat krije se u otvaranju — kralj se guši.","Skakač oduzima kralju zrak među vlastitim figurama.","Počni šahom skakačem na h4 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.083' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – locke den König mit einem Opfer heraus.","Ein Turmopfer reißt die Königsstellung auf, der zweite Turm mattet.","Beginne mit dem Turmopfer auf h2 – das Matt folgt erzwungen."],"en":["A forced mate awaits — lure the king out with a sacrifice.","A rook sacrifice rips open the king''s shelter, the other rook mates.","Start with the rook sacrifice on h2 — mate is forced to follow."],"hr":["Čeka te prisilni mat — izmami kralja žrtvom.","Žrtva topa razdire kraljevo sklonište, drugi top mati.","Počni žrtvom topa na h2 — mat slijedi prisilno."]}', HintsVersion=1 WHERE LineId LIKE '%:035.084' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt schon in der Eröffnung – der König erstickt.","Ein einzelner Springer erledigt das Matt im Alleingang.","Springe nach d6 – matt."],"en":["A forced mate already in the opening — the king suffocates.","A single knight delivers the mate all by itself.","Jump to d6 — mate."],"hr":["Prisilni mat već u otvaranju — kralj se guši.","Jedan jedini skakač sam zadaje mat.","Skoči na d6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.085' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – greif sofort an.","Deine Dame und der vorgeschobene Bauer reißen die weiße Königsstellung ein.","Schlag mit der Dame auf h3 und beginne die Mattführung."],"en":["A forced mate is hiding here — strike at once.","Your queen and the advanced pawn tear open White''s king.","Take with the queen on h3 to start the forced mate."],"hr":["Ovdje se krije prisilni mat — udari odmah.","Tvoja dama i napredni pješak razbijaju bijelog kralja.","Uzmi damom na h3 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.086' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer ebnet den Weg zum erzwungenen Matt.","Ein Springer wirft sich ein, danach übernimmt der Turm.","Schlag mit dem Springer auf g3 und leite die Mattführung ein."],"en":["A sacrifice opens the road to a forced mate.","A knight throws itself in, then the rook finishes.","Take with the knight on g3 to begin the forced mate."],"hr":["Žrtva otvara put do prisilnog mata.","Skakač se žrtvuje, a zatim top dovršava posao.","Uzmi skakačem na g3 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.087' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein erzwungenes Matt ein.","Die Dame räumt sich weg, dann gibt der Turm den tödlichen Schlag.","Schlag mit der Dame auf h2 und beginne die Mattführung."],"en":["A queen sacrifice ushers in a forced mate.","The queen clears herself away, then the rook delivers.","Take with the queen on h2 to start the forced mate."],"hr":["Žrtva dame uvodi prisilni mat.","Dama se uklanja, a zatim top zadaje smrtonosni udarac.","Uzmi damom na h2 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.088' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Springerzug setzt matt.","Der Springer hüpft in die Ecke des Königs und vollendet alles.","Springer nach f7 – matt."],"en":["A single knight move delivers mate.","The knight hops toward the king''s corner and finishes it.","Knight to f7 — mate."],"hr":["Jedan jedini potez skakača daje mat.","Skakač skače prema kraljevu kutu i sve dovršava.","Skakač na f7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.089' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Dein König wird per Treppe zum erzwungenen Matt gejagt.","Dame und Läufer treiben den feindlichen König Schritt für Schritt.","Schlag mit der Dame auf g8 und beginne die Mattführung."],"en":["The enemy king is chased up a staircase to a forced mate.","Queen and bishop herd him step by step.","Take with the queen on g8 to begin the forced mate."],"hr":["Neprijateljski kralj se stepenicama tjera u prisilni mat.","Dama i lovac ga gone korak po korak.","Uzmi damom na g8 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.090' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer öffnet das Tor zum erzwungenen Matt.","Die Dame opfert sich, dann erledigt der Turm den König am Rand.","Schlag mit der Dame auf h2 und leite die Mattführung ein."],"en":["A queen sacrifice opens the gate to a forced mate.","The queen sacrifices herself, then the rook finishes the king on the edge.","Take with the queen on h2 to begin the forced mate."],"hr":["Žrtva dame otvara vrata prisilnom matu.","Dama se žrtvuje, a zatim top dovršava kralja na rubu.","Uzmi damom na h2 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.091' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer erzwingt das Matt.","Die Dame räumt die Linie, der Turm holt den König nach.","Schlag mit dem Turm auf h2 und beginne die Mattführung."],"en":["A queen sacrifice forces the mate.","The rook clears the line, then the queen runs the king down.","Take with the rook on h2 to begin the forced mate."],"hr":["Žrtva tjera mat.","Top čisti liniju, a dama stiže kralja.","Uzmi topom na h2 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.092' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer erstickt den König zum erzwungenen Matt.","Der Springer dringt ein und der König wird von eigenen Steinen erstickt.","Schlag mit dem Springer auf f2 und leite die Mattführung ein."],"en":["A knight suffocates the king into a forced mate.","The knight invades and the king is choked by his own pieces.","Take with the knight on f2 to begin the forced mate."],"hr":["Skakač guši kralja u prisilni mat.","Skakač upada, a kralja guše vlastite figure.","Uzmi skakačem na f2 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.093' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer reißt die Königsstellung auf und erzwingt Matt.","Erst ein Springeropfer, dann schlägt der Läufer beim König ein.","Schlag mit dem Springer auf f6 und leite die Mattführung ein."],"en":["A sacrifice rips open the king and forces mate.","First a knight offer, then the bishop crashes in on the king.","Take with the knight on f6 to begin the forced mate."],"hr":["Žrtva razbija kraljevu poziciju i tjera mat.","Prvo žrtva skakača, zatim lovac udara na kralja.","Uzmi skakačem na f6 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.094' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf der Grundreihe erzwingt das Matt.","Die Dame opfert sich, dann übernehmen Läufer und Turm.","Schlag mit der Dame auf f1 und leite die Mattführung ein."],"en":["A sacrifice on the back rank forces mate.","The queen sacrifices, then bishop and rook take over.","Take with the queen on f1 to begin the forced mate."],"hr":["Žrtva na zadnjem redu tjera mat.","Dama se žrtvuje, a zatim lovac i top preuzimaju.","Uzmi damom na f1 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.095' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer bahnt den Weg zum erzwungenen Matt.","Die Dame lockt einen Bauern weg, dann schlägt der Turm zu.","Zieh die Dame nach h5 und leite die Mattführung ein."],"en":["A queen sacrifice paves the way to a forced mate.","The queen lures a pawn away, then the rook strikes.","Move the queen to h5 to begin the forced mate."],"hr":["Žrtva dame krči put do prisilnog mata.","Dama odvlači pješaka, a zatim top udara.","Pomakni damu na h5 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.096' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein einziger Läuferzug setzt matt.","Der Läufer schließt das Netz um den feindlichen König.","Läufer nach e6 – matt."],"en":["A single bishop move delivers mate.","The bishop closes the net around the enemy king.","Bishop to e6 — mate."],"hr":["Jedan jedini potez lovca daje mat.","Lovac zatvara mrežu oko neprijateljskog kralja.","Lovac na e6 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.097' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf der Grundreihe erzwingt das Matt.","Die Dame opfert sich, dann gibt der Turm das letzte Wort.","Schlag mit der Dame auf d1 und leite die Mattführung ein."],"en":["A back-rank sacrifice forces mate.","The queen sacrifices herself, then the rook has the last word.","Take with the queen on d1 to begin the forced mate."],"hr":["Žrtva na zadnjem redu tjera mat.","Dama se žrtvuje, a zatim top ima zadnju riječ.","Uzmi damom na d1 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.098' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein erzwungenes Matt ein.","Die Dame schlägt einen Verteidiger, dann folgt der zweite Schlag.","Schlag mit der Dame auf h4 und leite die Mattführung ein."],"en":["A queen sacrifice ushers in a forced mate.","The queen removes a defender, then the second blow lands.","Take with the queen on h4 to begin the forced mate."],"hr":["Žrtva dame uvodi prisilni mat.","Dama uklanja branitelja, a zatim slijedi drugi udarac.","Uzmi damom na h4 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.099' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springer leitet ein erzwungenes Erstickungsmatt ein.","Springer und Dame umstellen den König, der von eigenen Steinen erstickt wird.","Springer schlägt auf h6 und beginnt die Mattführung."],"en":["A knight begins a forced smothered mate.","Knight and queen box in the king, choked by his own pieces.","Knight takes on h6 to begin the forced mate."],"hr":["Skakač započinje prisilni ugušeni mat.","Skakač i dama zatvaraju kralja kojeg guše vlastite figure.","Skakač uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.100' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer öffnet die Stellung zum erzwungenen Matt.","Die Dame opfert sich, dann übernehmen die schweren Figuren.","Schlag mit der Dame auf f3 und leite die Mattführung ein."],"en":["A sacrifice cracks the position open for a forced mate.","The queen sacrifices, then the heavy pieces take charge.","Take with the queen on f3 to begin the forced mate."],"hr":["Žrtva otvara poziciju za prisilni mat.","Dama se žrtvuje, a zatim teške figure preuzimaju.","Uzmi damom na f3 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.101' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer reißt den König heraus und erzwingt Matt.","Der Turm opfert sich, dann jagen Dame und der zweite Turm den König.","Schlag mit dem Turm auf g7 und leite die lange Mattführung ein."],"en":["A rook sacrifice drags out the king and forces mate.","The rook sacrifices, then queen and second rook hunt the king down.","Take with the rook on g7 to begin the long forced mate."],"hr":["Žrtva topa izvlači kralja i tjera mat.","Top se žrtvuje, a zatim dama i drugi top gone kralja.","Uzmi topom na g7 i započni dugi prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.102' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer erzwingt das Matt im offenen Zentrum.","Der Läufer schlägt sich ein, dann gibt der Springer den letzten Hieb.","Schlag mit dem Läufer auf f2 und leite die Mattführung ein."],"en":["A bishop sacrifice forces mate in the open center.","The bishop crashes in, then the knight delivers the final blow.","Take with the bishop on f2 to begin the forced mate."],"hr":["Žrtva lovca tjera mat u otvorenom centru.","Lovac udara, a zatim skakač zadaje posljednji udarac.","Uzmi lovcem na f2 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.103' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schach treibt den König ins erzwungene Matt.","Dame und Springer arbeiten zusammen, bis der Turm vollendet.","Zieh die Dame nach h7 und leite die Mattführung ein."],"en":["A check drives the king into a forced mate.","Queen and knight cooperate until the rook finishes.","Move the queen to h7 to begin the forced mate."],"hr":["Šah tjera kralja u prisilni mat.","Dama i skakač surađuju dok top ne dovrši.","Pomakni damu na h7 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.104' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schach leitet ein erzwungenes Erstickungsmatt ein.","Dame und Springer treiben den König, bis er erstickt.","Zieh die Dame nach e6 und beginne die Mattführung."],"en":["A check sets up a forced smothered mate.","Queen and knight herd the king until he is smothered.","Move the queen to e6 to begin the forced mate."],"hr":["Šah uvodi prisilni ugušeni mat.","Dama i skakač gone kralja dok se ne uguši.","Pomakni damu na e6 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.105' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer öffnet den König zum erzwungenen Matt.","Die Dame räumt sich weg, dann liefern Turm und Läufer.","Schlag mit der Dame auf h2 und leite die Mattführung ein."],"en":["A queen sacrifice opens the king to a forced mate.","The queen clears away, then rook and bishop deliver.","Take with the queen on h2 to begin the forced mate."],"hr":["Žrtva dame otvara kralja za prisilni mat.","Dama se uklanja, a zatim top i lovac dovršavaju.","Uzmi damom na h2 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.106' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmvorstoß leitet ein erzwungenes Matt am Rand ein.","Türme und Springer schnüren den König in der Ecke ein.","Zieh den Turm nach b3 und beginne die Mattführung."],"en":["A rook thrust begins a forced mate on the edge.","Rooks and knight tie the king down in the corner.","Move the rook to b3 to begin the forced mate."],"hr":["Prodor topa započinje prisilni mat na rubu.","Topovi i skakač vežu kralja u kutu.","Pomakni top na b3 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.107' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer reißt den König heraus zum erzwungenen Matt.","Erst der Läufer, dann Dame und der zweite Läufer überrennen den König.","Schlag mit dem Läufer auf f2 und leite die Mattführung ein."],"en":["A bishop sacrifice drags the king out to a forced mate.","First the bishop, then queen and the other bishop overrun him.","Take with the bishop on f2 to begin the forced mate."],"hr":["Žrtva lovca izvlači kralja u prisilni mat.","Prvo lovac, zatim dama i drugi lovac gaze kralja.","Uzmi lovcem na f2 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.108' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Schach jagt den König ins erzwungene Matt.","Dame und Turm treiben den weißen König über das Brett.","Zieh die Dame nach e1 und beginne die Mattführung."],"en":["A check chases the king into a forced mate.","Queen and rook drive the white king across the board.","Move the queen to e1 to begin the forced mate."],"hr":["Šah goni kralja u prisilni mat.","Dama i top tjeraju bijelog kralja preko ploče.","Pomakni damu na e1 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.109' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Opfer auf der offenen Linie erzwingt das Grundreihenmatt.","Die Dame dringt ein, dann erledigt der Turm den eingeengten König.","Zieh die Dame nach e4 und leite die Mattführung ein."],"en":["A sacrifice down the open file forces a back-rank mate.","The queen invades, then the rook finishes the boxed-in king.","Move the queen to e4 to begin the forced mate."],"hr":["Žrtva na otvorenoj liniji tjera mat na zadnjem redu.","Dama upada, a zatim top dovršava stiješnjenog kralja.","Pomakni damu na e4 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.110' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmvorstoß leitet ein erzwungenes Matt am Rand ein.","Der Turm schwenkt herüber und fängt den König an der Seite.","Zieh den Turm nach d4 und beginne die Mattführung."],"en":["A rook lift begins a forced mate on the edge.","The rook swings over and traps the king on the side.","Move the rook to d4 to begin the forced mate."],"hr":["Podizanje topa započinje prisilni mat na rubu.","Top se prebacuje i hvata kralja sa strane.","Pomakni top na d4 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.111' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein erzwungenes Grundreihenmatt ein.","Die Dame opfert sich, dann übernehmen Springer und Turm.","Schlag mit der Dame auf d1 und leite die Mattführung ein."],"en":["A queen sacrifice sets up a forced back-rank mate.","The queen sacrifices, then knight and rook take over.","Take with the queen on d1 to begin the forced mate."],"hr":["Žrtva dame uvodi prisilni mat na zadnjem redu.","Dama se žrtvuje, a zatim skakač i top preuzimaju.","Uzmi damom na d1 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.112' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer erzwingt das Matt am eingeklemmten König.","Der Turm opfert sich, dann gibt der zweite Turm den tödlichen Schlag.","Zieh den Turm nach g8 und leite die Mattführung ein."],"en":["A rook sacrifice forces mate on the wedged-in king.","The rook sacrifices, then the second rook delivers the fatal blow.","Move the rook to g8 to begin the forced mate."],"hr":["Žrtva topa tjera mat na stiješnjenom kralju.","Top se žrtvuje, a zatim drugi top zadaje smrtonosni udarac.","Pomakni top na g8 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.113' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer reißt den König frei zum erzwungenen Matt.","Der Läufer opfert sich, dann holt die Dame den entblößten König.","Schlag mit dem Läufer auf g6 und leite die Mattführung ein."],"en":["A bishop sacrifice exposes the king to a forced mate.","The bishop sacrifices, then the queen catches the bared king.","Take with the bishop on g6 to begin the forced mate."],"hr":["Žrtva lovca razgolićuje kralja za prisilni mat.","Lovac se žrtvuje, a zatim dama hvata golog kralja.","Uzmi lovcem na g6 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.114' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer leitet ein erzwungenes Matt am Rand ein.","Die Dame opfert sich, dann übernehmen die Türme die Linie.","Zieh die Dame nach d8 und leite die Mattführung ein."],"en":["A queen sacrifice begins a forced mate on the edge.","The queen sacrifices, then the rooks take over the file.","Move the queen to d8 to begin the forced mate."],"hr":["Žrtva dame započinje prisilni mat na rubu.","Dama se žrtvuje, a zatim topovi preuzimaju liniju.","Pomakni damu na d8 i započni prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.115' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – der König wird in den eigenen Reihen erstickt.","Deine Dame opfert sich, dann gibt der Springer den letzten Stoß.","Die Dame schlägt auf b1; nach dem Rückschlag folgt das erstickte Matt mit dem Springer."],"en":["A forced mate is here – the king gets smothered by its own pieces.","Your queen sacrifices herself, then the knight delivers the blow.","Queen takes on b1; after the recapture the knight gives smothered mate."],"hr":["Ovdje je prisilni mat — kralja guše vlastite figure.","Tvoja se dama žrtvuje, a onda skakač zadaje udarac.","Dama uzima na b1; nakon uzvrata skakač daje ugušeni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.116' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattangriff gegen den König wartet – wirf die schweren Figuren hinein.","Turm und Dame arbeiten zusammen am König heran.","Turm zieht und schlägt auf g2; das leitet die erzwungene Mattführung ein."],"en":["A mating attack on the king awaits – throw in the heavy pieces.","Rook and queen team up to break through to the king.","Rook takes on g2; this starts the forced mating sequence."],"hr":["Čeka matni napad na kralja — ubaci teške figure.","Top i dama zajedno probijaju do kralja.","Top uzima na g2; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.117' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – der König wird aus der Deckung gezerrt.","Der Läufer opfert sich, und die Dame liefert von der Seite den Schlag.","Der Läufer schlägt auf h7; das ist der Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is in the air – the king is dragged into the open.","The bishop sacrifices itself, and the queen strikes from the side.","Bishop takes on h7; this begins the forced mating sequence."],"hr":["U zraku je prisilni mat — kralja se izvlači na otvoreno.","Lovac se žrtvuje, a dama udara sa strane.","Lovac uzima na h7; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.118' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schon in der Eröffnung droht ein blitzartiges Matt gegen den entblößten König.","Dame und Läufer dringen gemeinsam in die schwache Königsstellung ein.","Die Dame zieht nach h4 und startet den erzwungenen Mattangriff."],"en":["Even in the opening a lightning mate looms against the bare king.","Queen and bishop break into the weak king position together.","The queen goes to h4 and launches the forced mating attack."],"hr":["Već u otvaranju prijeti munjeviti mat golom kralju.","Dama i lovac zajedno prodiru u slabu kraljevu poziciju.","Dama ide na h4 i pokreće prisilni matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:035.119' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – Turm und Springer fangen den König im Eck.","Springer und Turm spinnen das klassische Netz im Eck.","Der Turm zieht und gibt Schach; das leitet die lange erzwungene Mattführung ein."],"en":["A forced mate is here – rook and knight trap the king in the corner.","Knight and rook weave the classic corner net.","The rook moves and checks; this starts the long forced mating sequence."],"hr":["Tu je prisilni mat — top i skakač hvataju kralja u kutu.","Skakač i top pletu klasičnu mrežu u kutu.","Top povlači i daje šah; time počinje dugi prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.120' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein Springeropfer reißt die Deckung weg.","Beide Springer und die Dame umzingeln den König.","Der Springer schlägt auf f2; nach dem Rückschlag folgt die erzwungene Mattführung."],"en":["A forced mate is here – a knight sacrifice tears away the cover.","Both knights and the queen close in on the king.","The knight takes on f2; after the recapture the forced mate follows."],"hr":["Tu je prisilni mat — žrtva skakača kida zaštitu.","Oba skakača i dama opkoljavaju kralja.","Skakač uzima na f2; nakon uzvrata slijedi prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.121' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – Schwerfiguren reißen die Deckung auf.","Turmopfer, dann setzen Dame und Läufer den König matt.","Der Turm schlägt auf h1; das startet die erzwungene Mattführung."],"en":["A forced mate is at hand – heavy pieces rip open the cover.","Rook sacrifice, then queen and bishop finish the king.","Rook takes on h1; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — teške figure razbijaju zaštitu.","Žrtva topa, pa dama i lovac matiraju kralja.","Top uzima na h1; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.122' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – ein Opfer öffnet die Reihen des Königs.","Türme und Springer kombinieren zum klassischen Matt.","Der Turm schlägt auf f8; das leitet die erzwungene Mattführung ein."],"en":["A forced mate awaits – a sacrifice opens the king''s ranks.","Rooks and knight combine for the classic mate.","The rook takes on f8; this begins the forced mating sequence."],"hr":["Čeka prisilni mat — žrtva otvara kraljeve redove.","Topovi i skakač kombiniraju za klasični mat.","Top uzima na f8; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.123' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Bauerndeckung wird geopfert weggelockt.","Dame und beide Läufer kreuzen ihre Wirkung auf den König.","Die Dame schlägt auf f6; nach dem Rückschlag folgt das erzwungene Matt."],"en":["A forced mate is here – the pawn cover is lured away by sacrifice.","Queen and both bishops cross their fire on the king.","The queen takes on f6; after the recapture the forced mate follows."],"hr":["Tu je prisilni mat — pješačka zaštita se žrtvom odvlači.","Dama i oba lovca križaju djelovanje na kralja.","Dama uzima na f6; nakon uzvrata slijedi prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.124' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Damenopfer lockt den König heraus.","Dame und Läufer treiben den König, dann gibt der Turm den Schlag.","Die Dame schlägt auf d8; das startet die erzwungene Mattführung."],"en":["A forced mate is here – a queen sacrifice lures the king out.","Queen and bishop drive the king, then the rook strikes.","The queen takes on d8; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva dame izvlači kralja.","Dama i lovac tjeraju kralja, pa top zadaje udarac.","Dama uzima na d8; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.125' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – die Grundreihe des Königs ist verwundbar.","Dame und Läufer kombinieren gegen die schwache letzte Reihe.","Die Dame zieht nach e1; das leitet die erzwungene Mattführung ein."],"en":["A forced mate is here – the king''s back rank is vulnerable.","Queen and bishop combine against the weak last rank.","The queen goes to e1; this begins the forced mating sequence."],"hr":["Tu je prisilni mat — kraljev je zadnji red ranjiv.","Dama i lovac kombiniraju protiv slabog zadnjeg reda.","Dama ide na e1; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.126' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – ein Damenopfer reißt die Linie auf.","Dame und Turm dringen über die offene Linie zum König vor.","Die Dame schlägt auf h8; das startet die erzwungene Mattführung."],"en":["A forced mate is here – a queen sacrifice rips open the file.","Queen and rook drive down the open file to the king.","The queen takes on h8; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva dame otvara liniju.","Dama i top prodiru otvorenom linijom do kralja.","Dama uzima na h8; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.127' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Turmopfer entblößt den König.","Turm opfert sich, dann setzt die Dame das Netz zu.","Der Turm schlägt auf g7; das leitet die erzwungene Mattführung ein."],"en":["A forced mate is here – a rook sacrifice strips the king bare.","The rook sacrifices itself, then the queen closes the net.","The rook takes on g7; this begins the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva topa razgolićuje kralja.","Top se žrtvuje, pa dama zatvara mrežu.","Top uzima na g7; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.128' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein Opfer öffnet die Königsstellung.","Dame, Läufer und Turm verbinden sich zum klassischen Matt.","Die Dame schlägt auf e8; das startet die erzwungene Mattführung."],"en":["A forced mate is here – a sacrifice opens the king''s position.","Queen, bishop and rook combine for the classic mate.","The queen takes on e8; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva otvara kraljevu poziciju.","Dama, lovac i top spajaju se u klasični mat.","Dama uzima na e8; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.129' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – zwei Springer umkreisen den König.","Beide Springer arbeiten Hand in Hand am König heran.","Der Springer zieht nach f6 und startet die erzwungene Mattführung."],"en":["A forced mate is here – two knights circle the king.","Both knights work hand in hand toward the king.","The knight goes to f6 and starts the forced mating sequence."],"hr":["Tu je prisilni mat — dva skakača kruže oko kralja.","Oba skakača rade ruku pod ruku prema kralju.","Skakač ide na f6 i pokreće prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.130' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Schwerfiguren jagen den König.","Dame und Turm treiben den König ins Verderben.","Der Turm zieht nach g1 und gibt Schach; so beginnt die erzwungene Mattführung."],"en":["A forced mate is here – the heavy pieces hunt the king.","Queen and rook drive the king to his doom.","The rook goes to g1 with check; thus the forced mate begins."],"hr":["Tu je prisilni mat — teške figure love kralja.","Dama i top tjeraju kralja u propast.","Top ide na g1 sa šahom; tako počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.131' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein Opfer öffnet die Bahn zum König.","Turm und Springer reißen auf, dann gibt ein Bauer den Schlag.","Der Turm schlägt auf h3; das leitet die erzwungene Mattführung ein."],"en":["A forced mate is here – a sacrifice clears the path to the king.","Rook and knight break through, then a pawn delivers the blow.","The rook takes on h3; this begins the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva otvara put do kralja.","Top i skakač probijaju, pa pješak zadaje udarac.","Top uzima na h3; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.132' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schon in der Eröffnung wartet ein erzwungenes Matt am König.","Dame und Läufer stürmen die offene Königsstellung.","Die Dame schlägt auf h8; das startet die erzwungene Mattführung."],"en":["A forced mate awaits at the king already in the opening.","Queen and bishop storm the exposed king position.","The queen takes on h8; this starts the forced mating sequence."],"hr":["Već u otvaranju čeka prisilni mat kralju.","Dama i lovac jurišaju na izloženu kraljevu poziciju.","Dama uzima na h8; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.133' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – ein Läuferopfer lockt den König heraus.","Beide Läufer kreuzen ihre Diagonalen über den König.","Der Läufer zieht nach d5; das leitet die erzwungene Mattführung ein."],"en":["A forced mate is here – a bishop sacrifice lures the king out.","Both bishops cross their diagonals over the king.","The bishop goes to d5; this begins the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva lovca izvlači kralja.","Oba lovca križaju svoje dijagonale nad kraljem.","Lovac ide na d5; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.134' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Opfer öffnet die Linie zum König.","Dame und Turm reißen auf, dann gibt ein Bauer den Schlag.","Die Dame schlägt auf g6; das startet die erzwungene Mattführung."],"en":["A forced mate is here – a sacrifice opens the line to the king.","Queen and rook break through, then a pawn strikes.","The queen takes on g6; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva otvara liniju do kralja.","Dama i top probijaju, pa pješak zadaje udarac.","Dama uzima na g6; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.135' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – die Dame lockt den König ins Eck.","Dame und ein vorgerückter Bauer setzen den König matt.","Die Dame schlägt auf g6; das leitet die erzwungene Mattführung ein."],"en":["A forced mate is here – the queen pulls the king into the corner.","Queen and an advanced pawn close the mating net.","The queen takes on g6; this begins the forced mating sequence."],"hr":["Tu je prisilni mat — dama uvlači kralja u kut.","Dama i napredni pješak zatvaraju matnu mrežu.","Dama uzima na g6; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.136' AND BookFileName='chessable-u5-243265.pgn';
