UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Turmopfer zieht den König ins Freie.","Turm opfert sich, dann gibt die Dame den entscheidenden Schlag.","Der Turm schlägt auf h7; das startet die erzwungene Mattführung."],"en":["A forced mate is here – a rook sacrifice draws the king into the open.","The rook sacrifices itself, then the queen lands the blow.","The rook takes on h7; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva topa izvlači kralja na otvoreno.","Top se žrtvuje, pa dama zadaje odlučujući udarac.","Top uzima na h7; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.141' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein Damenopfer öffnet die Königsstellung.","Dame reißt auf, dann setzt ein vorgerückter Bauer matt.","Die Dame schlägt auf g8; das leitet die erzwungene Mattführung ein."],"en":["A forced mate is here – a queen sacrifice opens the king''s position.","The queen breaks through, then an advanced pawn mates.","The queen takes on g8; this begins the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva dame otvara kraljevu poziciju.","Dama probija, pa napredni pješak matira.","Dama uzima na g8; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.142' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – ein Opfer reißt die Königsdeckung weg.","Beide Springer umkreisen den entblößten König.","Der Springer schlägt auf g2; das startet die erzwungene Mattführung."],"en":["A forced mate is here – a sacrifice tears away the king''s cover.","Both knights circle the exposed king.","The knight takes on g2; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva kida kraljevu zaštitu.","Oba skakača kruže oko izloženog kralja.","Skakač uzima na g2; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.143' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – ein Opfer lockt den Turm vom Posten.","Beide Läufer kreuzen ihre Wirkung auf den König.","Die Dame schlägt auf e2; das leitet die erzwungene Mattführung ein."],"en":["A forced mate is here – a sacrifice lures the rook off its post.","Both bishops cross their fire on the king.","The queen takes on e2; this begins the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva odvlači topa s mjesta.","Oba lovca križaju djelovanje na kralja.","Dama uzima na e2; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.144' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steckt drin – ein Turmopfer ebnet den Weg.","Turm opfert sich, dann gibt der zweite Turm das Matt.","Der Turm schlägt auf g1; das startet die erzwungene Mattführung."],"en":["A forced mate is here – a rook sacrifice clears the way.","One rook sacrifices itself, then the other rook mates.","The rook takes on g1; this starts the forced mating sequence."],"hr":["Tu je prisilni mat — žrtva topa krči put.","Jedan top se žrtvuje, pa drugi top matira.","Top uzima na g1; time počinje prisilni niz do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.145' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – der Gegner ist auf der Grundreihe verwundbar.","Ein schweres Stück opfert sich, damit das andere die ungedeckte Grundreihe nutzt.","Schlage mit der Dame auf f2 – der Auftakt einer erzwungenen Mattfolge."],"en":["A forced mate is here – the enemy back rank is vulnerable.","One heavy piece sacrifices itself so the other can strike the weak back rank.","Queen takes on f2 – the start of a forced mating sequence."],"hr":["Ovdje postoji prisilni mat — protivnička zadnja linija je ranjiva.","Jedna teška figura se žrtvuje da bi druga iskoristila slabu zadnju liniju.","Dama uzima na f2 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.146' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – das doppelte Läuferpaar wirkt zusammen.","Ein Damenopfer öffnet die Diagonalen für die beiden Läufer.","Dame schlägt auf e6 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is in the air – the two bishops work in tandem.","A queen sacrifice clears the diagonals for the bishop pair.","Queen takes on e6 – the start of the forced mating line."],"hr":["Prisilni mat je u zraku — dva lovca djeluju zajedno.","Žrtva dame otvara dijagonale za lovački par.","Dama uzima na e6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.147' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird von zwei Diagonalen eingekreist.","Ein Läuferopfer reißt die Bauernstellung vor dem König auf.","Läufer schlägt auf g3 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate is here – the king gets caught between two diagonals.","A bishop sacrifice tears open the pawns in front of the king.","Bishop takes on g3 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je uhvaćen između dvije dijagonale.","Žrtva lovca razbija pješake ispred kralja.","Lovac uzima na g3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.148' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Rochadestellung des Gegners zerbricht.","Eine Dame dringt neben den König ein und bereitet den Sturm vor.","Dame zieht nach h6 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate awaits – the enemy castled position is crumbling.","A queen lands beside the king and prepares the assault.","Queen to h6 – the start of the forced mating sequence."],"hr":["Prisilni mat čeka — protivnička rokirana pozicija se ruši.","Dama ulazi pokraj kralja i priprema napad.","Dama na h6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.149' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – der König wird in der Ecke erstickt.","Ein Damenopfer lenkt den Turm ab, dann setzt der Springer ein.","Dame schlägt auf g8 – Auftakt zum erstickten Matt."],"en":["A forced mate looms – the king will be smothered in the corner.","A queen sacrifice deflects the rook, then the knight strikes.","Queen takes on g8 – the start of the smothered mate."],"hr":["Prisilni mat prijeti — kralj će biti ugušen u kutu.","Žrtva dame odvlači topa, zatim skakač zadaje udarac.","Dama uzima na g8 — početak ugušenog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.150' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird zwischen eigene Figuren gezwängt.","Türme räumen die Bahn frei, dann gibt die Dame den letzten Schlag.","Turm schlägt auf f8 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king gets boxed in by its own pieces.","Rooks clear the path, then the queen delivers the final blow.","Rook takes on f8 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je stiješnjen vlastitim figurama.","Topovi raščišćavaju put, zatim dama zadaje završni udarac.","Top uzima na f8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.151' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der König wird ins Netz getrieben.","Ein Turmopfer lenkt ab, dann übernimmt die Dame die Führung.","Turm zieht nach d8 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate is at hand – the king is driven into a net.","A rook sacrifice deflects, then the queen takes over.","Rook to d8 – the start of the forced mating line."],"hr":["Prisilni mat je tu — kralj je natjeran u mrežu.","Žrtva topa odvlači, zatim dama preuzima vodstvo.","Top na d8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.152' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König am Rand wird eingefangen.","Eine Dame opfert sich, dann liefern Läufer und Bauer das Netz.","Dame schlägt auf g3 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king on the edge gets trapped.","A queen sacrifices itself, then bishop and pawn weave the net.","Queen takes on g3 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj na rubu je uhvaćen.","Dama se žrtvuje, zatim lovac i pješak pletu mrežu.","Dama uzima na g3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.153' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – die Dame schwenkt zum Königsflügel.","Die Dame nimmt eine neue Diagonale, um den König zu fassen.","Dame zieht nach a3 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate looms – the queen swings toward the king.","The queen takes a new diagonal to corner the king.","Queen to a3 – the start of the forced mating line."],"hr":["Prisilni mat prijeti — dama se prebacuje prema kralju.","Dama zauzima novu dijagonalu da uhvati kralja.","Dama na a3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.154' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird über das Brett getrieben.","Ein Turm beginnt die Treibjagd, Dame und Bauer schließen das Netz.","Turm zieht nach h3 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king is hunted across the board.","A rook starts the chase while queen and pawn seal the net.","Rook to h3 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je gonjen preko ploče.","Top započinje hajku dok dama i pješak zatvaraju mrežu.","Top na h3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.155' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der eingeengte König fällt.","Ein Springer gibt den ersten Stoß, dann übernimmt der Turm.","Springer zieht nach g3 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate is at hand – the cramped king falls.","A knight gives the first nudge, then the rook takes over.","Knight to g3 – the start of the forced mating line."],"hr":["Prisilni mat je tu — stiješnjeni kralj pada.","Skakač zadaje prvi udarac, zatim top preuzima.","Skakač na g3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.156' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – der Königsflügel wird aufgesprengt.","Ein Läuferopfer auf der Königsstellung öffnet die Tür für die Dame.","Läufer schlägt auf h7 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate looms – the kingside is blown open.","A bishop sacrifice on the king''s cover opens the door for the queen.","Bishop takes on h7 – the start of the forced mating line."],"hr":["Prisilni mat prijeti — kraljevo krilo je razbijeno.","Žrtva lovca na kraljevu zaštitu otvara vrata dami.","Lovac uzima na h7 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.157' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird an der Kante gefasst.","Ein Springercheck zwingt den König, dann brechen die Türme durch.","Springer schlägt auf e7 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate is here – the king gets pinned to the edge.","A knight check forces the king, then the rooks break through.","Knight takes on e7 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je prikovan uz rub.","Šah skakačem tjera kralja, zatim topovi probijaju.","Skakač uzima na e7 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.158' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – der König erstickt zwischen eigenen Steinen.","Ein Springercheck treibt den König in die Enge für den Läufer.","Springer schlägt auf f6 – Auftakt zum Erstickungsmatt."],"en":["A forced mate looms – the king suffocates among its own men.","A knight check drives the king into a corner for the bishop.","Knight takes on f6 – the start of the suffocation mate."],"hr":["Prisilni mat prijeti — kralj se guši među vlastitim figurama.","Šah skakačem tjera kralja u kut za lovca.","Skakač uzima na f6 — početak ugušujućeg mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.159' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird Stufe für Stufe getrieben.","Die Dame jagt den König im Treppenmuster zum Verderben.","Dame zieht nach g8 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king is driven step by step.","The queen chases the king in a staircase pattern to his doom.","Queen to g8 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je gonjen korak po korak.","Dama goni kralja stepenastim uzorkom do propasti.","Dama na g8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.160' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – Dame und Läufer umstellen den König.","Die Dame schwenkt zum Königsflügel, der Läufer liefert nach.","Dame zieht nach h6 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate looms – queen and bishop encircle the king.","The queen swings to the kingside while the bishop supports.","Queen to h6 – the start of the forced mating line."],"hr":["Prisilni mat prijeti — dama i lovac okružuju kralja.","Dama se prebacuje na kraljevo krilo dok lovac podržava.","Dama na h6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.161' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird zur Kante gefangen.","Ein Springercheck reißt die Königsstellung auf für den Dameneinschlag.","Springer schlägt auf e7 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king gets trapped against the edge.","A knight check rips open the king''s shelter for the queen.","Knight takes on e7 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je uhvaćen uz rub.","Šah skakačem otvara kraljevo sklonište za prodor dame.","Skakač uzima na e7 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.162' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – die Umwandlung entscheidet alles.","Ein Bauer wird zur Dame und lenkt den König ab.","Bauer wandelt auf f8 zur Dame um – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate looms – the promotion decides everything.","A pawn becomes a queen and deflects the king.","Pawn promotes to queen on f8 – the start of the forced mating line."],"hr":["Prisilni mat prijeti — pretvorba odlučuje sve.","Pješak postaje dama i odvlači kralja.","Pješak se pretvara u damu na f8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.163' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird an die Kante getrieben.","Ein Damenopfer öffnet die Linie, dann liefert der Turm das Matt.","Dame schlägt auf h6 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate is here – the king is driven to the edge.","A queen sacrifice opens the file, then the rook delivers mate.","Queen takes on h6 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je natjeran na rub.","Žrtva dame otvara liniju, zatim top zadaje mat.","Dama uzima na h6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.164' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der König wird in der Ecke gefasst.","Ein Turmopfer zieht den König heran, dann übernimmt die Dame.","Turm schlägt auf b2 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is at hand – the king gets caught in the corner.","A rook sacrifice draws the king in, then the queen takes over.","Rook takes on b2 – the start of the forced mating line."],"hr":["Prisilni mat je tu — kralj je uhvaćen u kutu.","Žrtva topa privlači kralja, zatim dama preuzima.","Top uzima na b2 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.165' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – der Königsflügel bricht zusammen.","Ein Damenopfer reißt die Königsdeckung auf, dann folgt der Turm.","Dame schlägt auf h2 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate looms – the kingside collapses.","A queen sacrifice tears open the king''s cover, then the rook follows.","Queen takes on h2 – the start of the forced mating line."],"hr":["Prisilni mat prijeti — kraljevo krilo se ruši.","Žrtva dame otvara kraljevu zaštitu, zatim slijedi top.","Dama uzima na h2 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.166' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird zwischen den eigenen Steinen erstickt.","Ein Turmopfer in der Ecke öffnet den Weg für den Springer.","Turm zieht nach c8 – Auftakt zum Erstickungsmatt."],"en":["A forced mate is here – the king suffocates among its own men.","A rook sacrifice in the corner clears the way for the knight.","Rook to c8 – the start of the suffocation mate."],"hr":["Prisilni mat postoji — kralj se guši među vlastitim figurama.","Žrtva topa u kutu otvara put skakaču.","Top na c8 — početak ugušujućeg mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.167' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der König am Rand wird eingefangen.","Ein Springeropfer öffnet die Linie, dann brechen Turm und Dame durch.","Springer schlägt auf g3 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is at hand – the king on the edge gets trapped.","A knight sacrifice opens the file, then rook and queen break through.","Knight takes on g3 – the start of the forced mating line."],"hr":["Prisilni mat je tu — kralj na rubu je uhvaćen.","Žrtva skakača otvara liniju, zatim top i dama probijaju.","Skakač uzima na g3 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.168' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – die Rochadestellung wird gesprengt.","Ein Turmopfer reißt den König heraus, dann schwenkt die Dame ein.","Turm schlägt auf h8 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate looms – the castled position is blown open.","A rook sacrifice drags the king out, then the queen swings in.","Rook takes on h8 – the start of the forced mating line."],"hr":["Prisilni mat prijeti — rokirana pozicija je razbijena.","Žrtva topa izvlači kralja, zatim dama uskače.","Top uzima na h8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.169' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Königsstellung wird zertrümmert.","Ein Turmopfer öffnet die Deckung, dann liefern Dame und Bauer nach.","Turm schlägt auf g6 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king''s shelter is shattered.","A rook sacrifice opens the cover, then queen and pawn pile in.","Rook takes on g6 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kraljevo sklonište je razbijeno.","Žrtva topa otvara zaštitu, zatim dama i pješak nasrću.","Top uzima na g6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.170' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der König wird in der Ecke eingeschnürt.","Der Turm weicht zurück, dann treiben Dame und Bauer den König fest.","Turm schlägt auf a6 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate is at hand – the king gets boxed into the corner.","The rook steps back, then queen and pawn nail the king down.","Rook takes on a6 – the start of the forced mating line."],"hr":["Prisilni mat je tu — kralj je stiješnjen u kut.","Top se povlači, zatim dama i pješak prikivaju kralja.","Top uzima na a6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.171' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – der König wird in der Ecke erstickt.","Ein Damenopfer lenkt die Dame ab, dann setzt der Springer matt.","Dame schlägt auf h2 – Auftakt zum erstickten Matt."],"en":["A forced mate looms – the king will be smothered in the corner.","A queen sacrifice deflects the defender, then the knight mates.","Queen takes on h2 – the start of the smothered mate."],"hr":["Prisilni mat prijeti — kralj će biti ugušen u kutu.","Žrtva dame odvlači branitelja, zatim skakač daje mat.","Dama uzima na h2 — početak ugušenog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:035.172' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – der König wird an die Kante gefangen.","Ein Damenopfer zieht den König, dann liefert der Turm das Matt.","Dame schlägt auf h8 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king gets trapped against the edge.","A queen sacrifice pulls the king, then the rook delivers mate.","Queen takes on h8 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kralj je uhvaćen uz rub.","Žrtva dame privlači kralja, zatim top zadaje mat.","Dama uzima na h8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.173' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – der König wird quer übers Brett getrieben.","Die Dame und der Läufer jagen den König von Feld zu Feld.","Dame zieht nach b8 – Auftakt der erzwungenen Mattfolge."],"en":["A forced mate looms – the king is marched across the board.","The queen and bishop hound the king from square to square.","Queen to b8 – the start of the forced mating line."],"hr":["Prisilni mat prijeti — kralj je tjeran preko cijele ploče.","Dama i lovac gone kralja s polja na polje.","Dama na b8 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.174' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Königsstellung zerbricht.","Ein Turmopfer öffnet die Deckung, dann brechen Springer und Dame durch.","Turm schlägt auf g7 – Beginn der erzwungenen Mattfolge."],"en":["A forced mate is here – the king''s shelter falls apart.","A rook sacrifice opens the cover, then knight and queen break through.","Rook takes on g7 – the start of the forced mating line."],"hr":["Prisilni mat postoji — kraljevo sklonište se raspada.","Žrtva topa otvara zaštitu, zatim skakač i dama probijaju.","Top uzima na g7 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.175' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier gibt es ein erzwungenes Matt, lass den feindlichen König nicht entwischen.","Deine Dame und der schwere Turm an der Seite wirken zusammen, um das Netz zu schließen.","Beginne mit der Dame nach f7 – der König wird in die tödliche Box getrieben."],"en":["A forced mate is here — don''t let the enemy king slip away.","Your queen and the rook on the flank cooperate to close the net.","Start with the queen to f7 — the king is herded into the killing box."],"hr":["Ovdje postoji prisilni mat — ne daj kralju da pobjegne.","Tvoja dama i top na bočnoj liniji surađuju kako bi zatvorili mrežu.","Počni damom na f7 — kralj se tjera u smrtonosnu kutiju."]}', HintsVersion=1 WHERE LineId LIKE '%:035.176' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattangriff gegen den eingeengten König wartet.","Dein Springer öffnet die Bahn, dann setzt der Turm den Punkt.","Springer schlägt auf c3 mit Schach – die Mattwendung beginnt."],"en":["A mating attack on the boxed-in king is waiting.","Your knight clears the way, then the rook delivers the point.","Knight takes on c3 with check — the mating turn begins."],"hr":["Čeka matni napad na stiješnjenog kralja.","Tvoj skakač otvara put, a zatim top postavlja poantu.","Skakač uzima na c3 sa šahom — počinje matni obrat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.177' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Diagonalmatt liegt in der Luft – opfere, um die Linien zu öffnen.","Der Turm reißt die Stellung auf, dann erledigen die Läufer den König.","Turm schlägt auf c3 – das Bauernopfer leitet das Diagonalmatt ein."],"en":["A criss-cross bishop mate is in the air — sacrifice to open lines.","The rook tears the position open, then the bishops finish the king.","Rook takes on c3 — the sacrifice sets up the diagonal mate."],"hr":["U zraku je matni udar dvaju lovaca — žrtvuj da otvoriš linije.","Top razbija položaj, a zatim lovci dokrajče kralja.","Top uzima na c3 — žrtva priprema dijagonalni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.178' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein klassisches ersticktes Matt steckt in der Stellung.","Erst räumt ein Turmopfer die Rochadestellung, dann springt der Springer ein.","Turm schlägt auf h7 – das Opfer leitet das Erstickungsmatt ein."],"en":["A classic smothered mate hides in the position.","First a rook sacrifice clears the king''s shelter, then the knight strikes.","Rook takes on h7 — the sacrifice opens the smothered mate."],"hr":["U položaju se krije klasični ugušeni mat.","Najprije žrtva topa razbija kraljev zaklon, a zatim skakač udara.","Top uzima na h7 — žrtva otvara ugušeni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.179' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattangriff auf den eingeklemmten König ist möglich.","Dein Läufer dringt entscheidend ein und zieht die Figuren ins Mattnetz.","Läufer nach f3 – der Vorstoß startet die erzwungene Mattfolge."],"en":["A mating attack against the cramped king is available.","Your bishop penetrates decisively and drags the pieces into the net.","Bishop to f3 — the thrust begins the forced mating sequence."],"hr":["Moguć je matni napad na stiješnjenog kralja.","Tvoj lovac odlučujuće prodire i uvlači figure u matnu mrežu.","Lovac na f3 — prodor započinje prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.180' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Rückreihenmatt lässt sich erzwingen.","Deine Dame führt den Angriff, der schwere Turm sichert die Grundreihe.","Dame nach h6 – der Beginn der erzwungenen Mattjagd."],"en":["A back-rank mate can be forced.","Your queen leads the attack while the heavy rook seals the last rank.","Queen to h6 — the start of the forced mating hunt."],"hr":["Mat na zadnjoj liniji može se prisiliti.","Tvoja dama vodi napad dok teški top osigurava zadnju liniju.","Dama na h6 — početak prisilnog matnog lova."]}', HintsVersion=1 WHERE LineId LIKE '%:035.181' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattangriff über die offene Linie zum König ist da.","Erst öffnet ein Turmopfer die Linie, dann doppelt der zweite Turm.","Turm schlägt auf h7 – das Opfer reißt die Königsstellung auf."],"en":["A mating attack down the open file to the king is there.","First a rook sacrifice opens the file, then the second rook doubles.","Rook takes on h7 — the sacrifice rips open the king''s cover."],"hr":["Tu je matni napad otvorenom linijom prema kralju.","Najprije žrtva topa otvara liniju, a zatim drugi top udvostručuje.","Top uzima na h7 — žrtva razbija kraljev zaklon."]}', HintsVersion=1 WHERE LineId LIKE '%:035.182' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen den entblößten König wartet.","Deine schweren Figuren liefern sich aus, damit Läufer und Turm matten.","Turm nach h5 – der Beginn der erzwungenen Mattfolge."],"en":["A forced mate against the exposed king is waiting.","Your heavy pieces give themselves up so bishop and rook can mate.","Rook to h5 — the start of the forced mating sequence."],"hr":["Čeka prisilni mat protiv izloženog kralja.","Tvoje teške figure se predaju da lovac i top mogu matirati.","Top na h5 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.183' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattangriff gegen den nackten König lässt sich erzwingen.","Erst lockt ein Springeropfer, dann dringen Dame und Bauer durch.","Springer nach f8 – das Opfer leitet die Mattjagd ein."],"en":["A mating attack against the bare king can be forced.","First a knight sacrifice lures, then queen and pawn break through.","Knight to f8 — the sacrifice begins the mating hunt."],"hr":["Matni napad na ogoljenog kralja može se prisiliti.","Najprije žrtva skakača mami, a zatim dama i pješak probijaju.","Skakač na f8 — žrtva započinje matni lov."]}', HintsVersion=1 WHERE LineId LIKE '%:035.184' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattnetz lässt sich Schritt für Schritt knüpfen.","Springer und Turm öffnen mit Opfern die Linien zum König.","Springer schlägt auf g3 – das Opfer eröffnet die Mattfolge."],"en":["A mating net can be woven step by step.","Knight and rook open the lines to the king with sacrifices.","Knight takes on g3 — the sacrifice opens the mating sequence."],"hr":["Matna mreža može se isplesti korak po korak.","Skakač i top žrtvama otvaraju linije prema kralju.","Skakač uzima na g3 — žrtva otvara matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.185' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt treibt den König unaufhaltsam ins Eck.","Deine Dame und der Bauer manövrieren den König in die Falle.","Dame schlägt auf h2 mit Schach – der König wird ins Netz getrieben."],"en":["A forced mate drives the king inexorably into the corner.","Your queen and the pawn maneuver the king into the trap.","Queen takes on h2 with check — the king is herded into the net."],"hr":["Prisilni mat neumoljivo tjera kralja u kut.","Tvoja dama i pješak manevriraju kralja u zamku.","Dama uzima na h2 sa šahom — kralj se tjera u mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:035.186' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattangriff gegen die kurze Rochade wartet auf dich.","Läufer und Dame schnüren das Netz an der Königsflanke zusammen.","Turm nach g8 – der erste Schritt der erzwungenen Mattfolge."],"en":["A mating attack against the kingside castling awaits you.","Bishop and queen weave the net around the king''s flank.","Rook to g8 — the first step of the forced mating sequence."],"hr":["Čeka te matni napad na kratku rokadu.","Lovac i dama pletu mrežu oko kraljeva krila.","Top na g8 — prvi korak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.187' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen den König am Rand ist da.","Springer und Turm fangen den König in der tödlichen Box.","Bauer nach e6 – der Auftakt zur erzwungenen Mattfolge."],"en":["A forced mate against the king on the edge is there.","Knight and rook trap the king in the killing box.","Pawn to e6 — the prelude to the forced mating sequence."],"hr":["Tu je prisilni mat protiv kralja na rubu.","Skakač i top hvataju kralja u smrtonosnu kutiju.","Pješak na e6 — uvod u prisilni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.188' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen den entblößten König wartet.","Dein Läufer öffnet die Stellung, dann schlägt der Turm zu.","Läufer schlägt auf h2 mit Schach – das Opfer eröffnet das Matt."],"en":["A forced mate against the exposed king is waiting.","Your bishop opens the position, then the rook strikes.","Bishop takes on h2 with check — the sacrifice opens the mate."],"hr":["Čeka prisilni mat protiv izloženog kralja.","Tvoj lovac otvara položaj, a zatim top udara.","Lovac uzima na h2 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.189' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Trotz drohender Umwandlung gibt es ein erzwungenes Matt.","Dein Bauer und der Turm schließen das Netz am König.","König nach g3 – der erste Zug der erzwungenen Mattfolge."],"en":["Despite the looming promotion, there is a forced mate.","Your pawn and the rook close the net around the king.","King to g3 — the first move of the forced mating sequence."],"hr":["Unatoč prijetećoj promociji, postoji prisilni mat.","Tvoj pješak i top zatvaraju mrežu oko kralja.","Kralj na g3 — prvi potez prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.190' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt mit beiden Springern liegt bereit.","Die zwei Springer arbeiten zusammen, um den König zu fangen.","Springer schlägt auf c7 mit Schach – der Beginn des Doppelspringermatts."],"en":["A forced mate with both knights is ready.","The two knights work together to trap the king.","Knight takes on c7 with check — the start of the double-knight mate."],"hr":["Spreman je prisilni mat s oba skakača.","Dva skakača surađuju kako bi uhvatili kralja.","Skakač uzima na c7 sa šahom — početak mata dvaju skakača."]}', HintsVersion=1 WHERE LineId LIKE '%:035.191' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steht ein Matt in einem einzigen Zug.","Deine Dame greift den verwundbaren Punkt vor dem König an.","Dame schlägt auf f7 – matt."],"en":["A mate in a single move stands here.","Your queen attacks the vulnerable point in front of the king.","Queen takes on f7 — mate."],"hr":["Ovdje stoji mat u jednom potezu.","Tvoja dama napada ranjivu točku ispred kralja.","Dama uzima na f7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.192' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Mattangriff gegen die kurze Rochade wartet.","Erst lockt ein Damenopfer, dann dringt der Turm zum König durch.","Dame schlägt auf h7 mit Schach – das Opfer leitet das Matt ein."],"en":["A mating attack against the kingside castling awaits.","First a queen sacrifice lures, then the rook breaks through to the king.","Queen takes on h7 with check — the sacrifice opens the mate."],"hr":["Čeka matni napad na kratku rokadu.","Najprije žrtva dame mami, a zatim top probija do kralja.","Dama uzima na h7 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.193' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen den König wartet auf dich.","Erst lenkt ein Turmopfer ab, dann schlägt die Dame entscheidend zu.","Turm schlägt auf h8 mit Schach – das Opfer leitet das Matt ein."],"en":["A forced mate against the king awaits you.","First a rook sacrifice deflects, then the queen strikes decisively.","Rook takes on h8 with check — the sacrifice opens the mate."],"hr":["Čeka te prisilni mat protiv kralja.","Najprije žrtva topa odvlači, a zatim dama odlučujuće udara.","Top uzima na h8 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.194' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen den König in der Mitte ist da.","Erst lockt ein Läuferopfer einen Verteidiger weg, dann matt der Turm.","Läufer nach f4 – das Opfer leitet die Mattfolge ein."],"en":["A forced mate against the king in the center is there.","First a bishop sacrifice lures a defender away, then the rook mates.","Bishop to f4 — the sacrifice opens the mating sequence."],"hr":["Tu je prisilni mat protiv kralja u sredini.","Najprije žrtva lovca odvlači branitelja, a zatim top matira.","Lovac na f4 — žrtva otvara matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.195' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen die Königsflanke wartet.","Dame und Turm öffnen mit Opfern den Weg zur Königsstellung.","Dame schlägt auf h6 mit Schach – das Opfer eröffnet das Matt."],"en":["A forced mate against the king''s flank is waiting.","Queen and rook open the way to the king''s shelter with sacrifices.","Queen takes on h6 with check — the sacrifice opens the mate."],"hr":["Čeka prisilni mat protiv kraljeva krila.","Dama i top žrtvama otvaraju put do kraljeva zaklona.","Dama uzima na h6 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.196' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erstickendes Matt steckt in der Stellung.","Erst räumt ein Damenopfer das Feld, dann erstickt der Springer den König.","Dame schlägt auf f1 mit Schach – das Opfer leitet das Erstickungsmatt ein."],"en":["A suffocation mate hides in the position.","First a queen sacrifice clears the square, then the knight smothers the king.","Queen takes on f1 with check — the sacrifice opens the smothered mate."],"hr":["U položaju se krije ugušeni mat.","Najprije žrtva dame čisti polje, a zatim skakač guši kralja.","Dama uzima na f1 sa šahom — žrtva otvara ugušeni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.197' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erstickendes Matt gegen die kurze Rochade lässt sich erzwingen.","Erst lockt ein Damenopfer, dann erstickt der Springer den König.","Dame schlägt auf h6 mit Schach – das Opfer leitet das Erstickungsmatt ein."],"en":["A suffocation mate against the kingside castling can be forced.","First a queen sacrifice lures, then the knight smothers the king.","Queen takes on h6 with check — the sacrifice opens the smothered mate."],"hr":["Ugušeni mat na kratku rokadu može se prisiliti.","Najprije žrtva dame mami, a zatim skakač guši kralja.","Dama uzima na h6 sa šahom — žrtva otvara ugušeni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.198' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt mit den verdoppelten Türmen wartet.","Erst räumt ein Springeropfer, dann walzen die zwei Türme über die Reihe.","Springer schlägt auf e6 mit Schach – das Opfer leitet das Matt ein."],"en":["A forced mate with the doubled rooks awaits.","First a knight sacrifice clears, then the two rooks roll along the rank.","Knight takes on e6 with check — the sacrifice opens the mate."],"hr":["Čeka prisilni mat s udvostručenim topovima.","Najprije žrtva skakača čisti, a zatim dva topa valjaju duž linije.","Skakač uzima na e6 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.199' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen die Königsflanke ist da.","Erst lenkt ein Damenopfer ab, dann mattet der Läufer von der Diagonale.","Dame nach h5 – das Opfer leitet das erzwungene Matt ein."],"en":["A forced mate against the king''s flank is there.","First a queen sacrifice deflects, then the bishop mates along the diagonal.","Queen to h5 — the sacrifice opens the forced mate."],"hr":["Tu je prisilni mat protiv kraljeva krila.","Najprije žrtva dame odvlači, a zatim lovac matira po dijagonali.","Dama na h5 — žrtva otvara prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.200' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen den König in der Mitte wartet.","Erst lenkt ein Turmopfer einen Verteidiger ab, dann dringt der Turm durch.","Turm schlägt auf c6 mit Schach – das Opfer leitet das Matt ein."],"en":["A forced mate against the king in the center awaits.","First a rook sacrifice deflects a defender, then the rook breaks through.","Rook takes on c6 with check — the sacrifice opens the mate."],"hr":["Čeka prisilni mat protiv kralja u sredini.","Najprije žrtva topa odvlači branitelja, a zatim top probija.","Top uzima na c6 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.201' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steht ein Matt in einem einzigen Zug.","Deine Dame stützt sich auf den Läufer, der die lange Diagonale beherrscht.","Dame schlägt auf c7 – matt."],"en":["A mate in a single move stands here.","Your queen leans on the bishop ruling the long diagonal.","Queen takes on c7 — mate."],"hr":["Ovdje stoji mat u jednom potezu.","Tvoja dama se oslanja na lovca koji vlada dugom dijagonalom.","Dama uzima na c7 — mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.202' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen den eingeengten König wartet.","Erst lockt ein Damenopfer, dann setzt der Turm zwischen den eigenen Figuren matt.","Dame schlägt auf e3 mit Schach – das Opfer leitet das Matt ein."],"en":["A forced mate against the boxed-in king awaits.","First a queen sacrifice lures, then the rook mates between his own pieces.","Queen takes on e3 with check — the sacrifice opens the mate."],"hr":["Čeka prisilni mat protiv stiješnjenog kralja.","Najprije žrtva dame mami, a zatim top matira između vlastitih figura.","Dama uzima na e3 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.203' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Rückreihenmatt lässt sich gegen den eingeengten König erzwingen.","Deine Dame dringt ein und nutzt die schwache Grundreihe aus.","Dame schlägt auf h6 – der Beginn der erzwungenen Mattfolge."],"en":["A back-rank mate can be forced against the cramped king.","Your queen penetrates and exploits the weak last rank.","Queen takes on h6 — the start of the forced mating sequence."],"hr":["Mat na zadnjoj liniji može se prisiliti protiv stiješnjenog kralja.","Tvoja dama prodire i iskorištava slabu zadnju liniju.","Dama uzima na h6 — početak prisilnog matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.204' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt gegen die Königsflanke wartet auf dich.","Erst lockt ein Damenopfer, dann schnüren Türme und Läufer das Netz zu.","Dame schlägt auf h7 mit Schach – das Opfer leitet das Matt ein."],"en":["A forced mate against the king''s flank awaits you.","First a queen sacrifice lures, then rooks and bishop close the net.","Queen takes on h7 with check — the sacrifice opens the mate."],"hr":["Čeka te prisilni mat protiv kraljeva krila.","Najprije žrtva dame mami, a zatim topovi i lovac zatvaraju mrežu.","Dama uzima na h7 sa šahom — žrtva otvara mat."]}', HintsVersion=1 WHERE LineId LIKE '%:035.205' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es steckt ein erzwungenes Matt in der Stellung – treib den König ins Netz.","Deine Dame und der weit vorgeschobene Turm spinnen das Mattnetz.","Beginne mit der Dame nach g5 als Auftakt der Mattfolge."],"en":["A forced mate is hiding here — drive the king into the net.","Your queen and the advanced rook weave the mating net.","Start with the queen to g5 to launch the mating sequence."],"hr":["Ovdje se krije prisilni mat — natjeraj kralja u mrežu.","Tvoja dama i napredni top pletu matnu mrežu.","Počni damom na g5 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.206' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt in der Luft – der gegnerische König ist eingeengt.","Deine Dame liefert das Matt, der eigene Bauer und König schneiden Felder ab.","Beginne mit der Dame nach c7 als Start der Mattfolge."],"en":["A forced mate is in the air — the enemy king is boxed in.","Your queen delivers it while your pawn and king cut off escape squares.","Begin with the queen to c7 to start the mating sequence."],"hr":["Prisilni mat visi u zraku — neprijateljski kralj je stiješnjen.","Tvoja dama daje mat dok pješak i kralj odsijecaju polja.","Počni damom na c7 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.207' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier wartet ein erzwungenes Matt – der weiße König sitzt in der Falle.","Deine Dame dringt in die Ecke ein und gibt den entscheidenden Schlag.","Schlage mit der Dame auf h1 als Auftakt der Mattfolge."],"en":["A forced mate awaits — the white king is trapped in the corner.","Your queen invades the corner to deliver the decisive blow.","Take with the queen on h1 to launch the mating sequence."],"hr":["Ovdje čeka prisilni mat — bijeli kralj je u zamci u kutu.","Tvoja dama prodire u kut i zadaje odlučujući udarac.","Uzmi damom na h1 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.208' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – die Grundreihe des Gegners ist verwundbar.","Ein Damenopfer reißt den Wächter weg, dann schlägt der Turm zu.","Opfere die Dame mit Schlag auf g2 als Start der Mattfolge."],"en":["A forced mate is here — the enemy back rank is vulnerable.","A queen sacrifice removes the defender, then the rook strikes.","Sacrifice the queen taking on g2 to start the mating sequence."],"hr":["Prisilni mat je tu — protivnička zadnja linija je ranjiva.","Žrtva dame uklanja branitelja, zatim top udara.","Žrtvuj damu uzimajući na g2 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.209' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – öffne die Linie zum König.","Erst räumt der Springer das entscheidende Feld, dann dringt der Turm ein.","Ziehe den Springer nach f6 als Auftakt der Mattfolge."],"en":["A forced mate is here — open the file toward the king.","First the knight clears the key square, then the rook breaks in.","Play the knight to f6 to launch the mating sequence."],"hr":["Prisilni mat je pred tobom — otvori liniju prema kralju.","Prvo skakač čisti ključno polje, zatim top prodire.","Odigraj skakača na f6 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.210' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet – locke den weißen König nach vorn.","Ein Damenopfer zieht den König heraus, dann setzt der Läufer matt.","Opfere die Dame mit Schlag auf h2 als Start der Mattfolge."],"en":["A forced mate awaits — lure the white king forward.","A queen sacrifice drags the king out, then the bishop mates.","Sacrifice the queen taking on h2 to start the mating sequence."],"hr":["Prisilni mat čeka — namami bijelog kralja naprijed.","Žrtva dame izvlači kralja, zatim lovac matira.","Žrtvuj damu uzimajući na h2 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:035.211' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – nutze die offene Stellung am König.","Läufer und die beiden Türme arbeiten zusammen zum Matt.","Ziehe den Läufer nach f6 als Auftakt der Mattfolge."],"en":["A forced mate is ready — exploit the king''s exposed shelter.","The bishop and both rooks coordinate to deliver mate.","Play the bishop to f6 to launch the mating sequence."],"hr":["Prisilni mat je spreman — iskoristi izloženog kralja.","Lovac i oba topa surađuju za mat.","Odigraj lovca na f6 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:035.212' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist vorhanden – ein Diagonalkreuzfeuer auf den König.","Dame und Springer opfern sich, damit die beiden Läufer matt setzen.","Opfere die Dame mit Schlag auf f8 als Start der Mattfolge."],"en":["A forced mate is present — a diagonal crossfire on the king.","Queen and knight sacrifice so the two bishops can mate.","Sacrifice the queen taking on f8 to start the mating sequence."],"hr":["Prisilni mat postoji — dijagonalna unakrsna vatra na kralja.","Dama i skakač se žrtvuju da dva lovca matiraju.","Žrtvuj damu uzimajući na f8 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.002' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Diagonalen kreuzen sich am König.","Dame und Läufer setzen den König aus zwei Richtungen unter Feuer.","Ziehe die Dame nach h5 als Auftakt der Mattfolge."],"en":["A forced mate is here — the diagonals cross on the king.","Queen and bishop hit the king from two directions.","Play the queen to h5 to launch the mating sequence."],"hr":["Prisilni mat je pred tobom — dijagonale se sijeku na kralju.","Dama i lovac napadaju kralja iz dva smjera.","Odigraj damu na h5 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.003' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – der König ist im Zentrum gefangen.","Der vorgeschobene Bauer und der Läufer erledigen die Arbeit.","Schlage mit dem Bauern auf h7 als Start der Mattfolge."],"en":["A forced mate is ready — the king is stuck in the center.","The advanced pawn and the bishop do the work.","Take with the pawn on h7 to start the mating sequence."],"hr":["Prisilni mat je spreman — kralj je zaglavljen u centru.","Napredni pješak i lovac obavljaju posao.","Uzmi pješakom na h7 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.004' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – dein vorgerückter Bauer wird zur Waffe.","Ablenkungsopfer ebnen dem kleinen Bauern den Weg zum Mattschlag.","Schlage mit der Dame auf c3 als Auftakt der Mattfolge."],"en":["A forced mate awaits — your advanced pawn becomes the weapon.","Deflection sacrifices clear the path for the little pawn to mate.","Take with the queen on c3 to launch the mating sequence."],"hr":["Prisilni mat čeka — tvoj napredni pješak postaje oružje.","Žrtve odvlačenja krče put malom pješaku do mata.","Uzmi damom na c3 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.005' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – reiße den König aus der Deckung.","Damenopfer und Springeropfer legen den König für den Schlag frei.","Schlage mit der Dame auf h6 als Start der Mattfolge."],"en":["A forced mate is here — strip the king of its cover.","Queen and knight sacrifices expose the king for the blow.","Take with the queen on h6 to start the mating sequence."],"hr":["Prisilni mat je tu — ogoli kralja od zaštite.","Žrtve dame i skakača izlažu kralja za udarac.","Uzmi damom na h6 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.006' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – locke den König in die Ecke.","Ein Damenopfer und der Turm bauen das klassische Eckmatt.","Ziehe die Dame nach f2 als Auftakt der Mattfolge."],"en":["A forced mate is here — pull the king into the corner.","A queen sacrifice and the rook build the classic corner mate.","Play the queen to f2 to launch the mating sequence."],"hr":["Prisilni mat je pred tobom — namami kralja u kut.","Žrtva dame i top grade klasični mat u kutu.","Odigraj damu na f2 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.007' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – das gegnerische Lager erstickt.","Läufer und Springer schnüren dem König alle Felder ab.","Ziehe den Läufer nach d6 als Start der Mattfolge."],"en":["A forced mate is ready — the enemy camp suffocates.","Bishop and knight seal off every square around the king.","Play the bishop to d6 to start the mating sequence."],"hr":["Prisilni mat je spreman — protivnički tabor se guši.","Lovac i skakač zatvaraju sva polja oko kralja.","Odigraj lovca na d6 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.008' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – öffne den Weg zum weißen König.","Springer und Läufer kreuzen ihr Feuer auf der Diagonale.","Schlage mit der Dame auf f2 als Auftakt der Mattfolge."],"en":["A forced mate awaits — open the path to the white king.","Knights and bishop cross their fire on the diagonal.","Take with the queen on f2 to launch the mating sequence."],"hr":["Prisilni mat čeka — otvori put prema bijelom kralju.","Skakači i lovac ukrštaju vatru na dijagonali.","Uzmi damom na f2 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.009' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – Turm und Springer jagen den König.","Erst stört der Turm, dann webt der Springer das Netz.","Ziehe den Turm nach c7 als Start der Mattfolge."],"en":["A forced mate is here — rook and knight hunt the king.","First the rook harasses, then the knight weaves the net.","Play the rook to c7 to start the mating sequence."],"hr":["Prisilni mat je tu — top i skakač love kralja.","Prvo top uznemiruje, zatim skakač plete mrežu.","Odigraj top na c7 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.010' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Grundreihe ist der Schlüssel.","Turmopfer und Springeropfer reißen die Verteidigung auf.","Ziehe den Turm nach e8 als Auftakt der Mattfolge."],"en":["A forced mate is here — the back rank is the key.","Rook and knight sacrifices tear open the defense.","Play the rook to e8 to launch the mating sequence."],"hr":["Prisilni mat je pred tobom — zadnja linija je ključ.","Žrtve topa i skakača razbijaju obranu.","Odigraj top na e8 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.011' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – der König wird langsam erstickt.","Ein Läuferopfer öffnet die Linie, dann tanzt der Springer zum Matt.","Schlage mit dem Läufer auf e4 als Start der Mattfolge."],"en":["A forced mate is ready — the king is slowly suffocated.","A bishop sacrifice opens the line, then the knight dances to mate.","Take with the bishop on e4 to start the mating sequence."],"hr":["Prisilni mat je spreman — kralj se polako guši.","Žrtva lovca otvara liniju, zatim skakač pleše do mata.","Uzmi lovcem na e4 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Diagonale zielt auf die Ecke.","Bauer, Turm und Dame brechen die letzte Verteidigung.","Schlage mit dem Bauern auf g3 als Auftakt der Mattfolge."],"en":["A forced mate awaits — the diagonal aims at the corner.","Pawn, rook and queen break the last line of defense.","Take with the pawn on g3 to launch the mating sequence."],"hr":["Prisilni mat čeka — dijagonala cilja u kut.","Pješak, top i dama ruše posljednju obranu.","Uzmi pješakom na g3 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – der vorgeschobene Bauer fixiert den König.","Damenopfer reißen die Bauerndeckung weg, dann dringt der Turm ein.","Opfere die Dame mit Schlag auf h8 als Start der Mattfolge."],"en":["A forced mate is here — the advanced pawn pins the king down.","Queen sacrifices peel away the pawn cover, then the rook invades.","Sacrifice the queen taking on h8 to start the mating sequence."],"hr":["Prisilni mat je tu — napredni pješak prikiva kralja.","Žrtve dame skidaju pješačku zaštitu, zatim top prodire.","Žrtvuj damu uzimajući na h8 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Grundreihe des Weißen bricht.","Ablenkungsopfer und der Läufer bereiten den Schlussschlag.","Schlage mit der Dame auf f2 als Auftakt der Mattfolge."],"en":["A forced mate is here — White''s back rank collapses.","Deflection sacrifices and the bishop set up the final blow.","Take with the queen on f2 to launch the mating sequence."],"hr":["Prisilni mat je pred tobom — bijela zadnja linija puca.","Žrtve odvlačenja i lovac pripremaju završni udarac.","Uzmi damom na f2 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – sprenge die Bauernstellung des Königs.","Erst opfert der Läufer, dann liefert die Dame mit Bauernhilfe das Matt.","Schlage mit dem Läufer auf h7 als Start der Mattfolge."],"en":["A forced mate is ready — blast open the king''s pawn cover.","First the bishop sacrifices, then the queen mates with pawn support.","Take with the bishop on h7 to start the mating sequence."],"hr":["Prisilni mat je spreman — razbij pješačku zaštitu kralja.","Prvo se žrtvuje lovac, zatim dama matira uz pomoć pješaka.","Uzmi lovcem na h7 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – dränge den König an den Rand.","Dame und Turm jagen den König, der Läufer gibt den letzten Schlag.","Ziehe die Dame nach g6 als Auftakt der Mattfolge."],"en":["A forced mate awaits — push the king to the edge.","Queen and rook chase the king while the bishop delivers the end.","Play the queen to g6 to launch the mating sequence."],"hr":["Prisilni mat čeka — potjeraj kralja na rub.","Dama i top gone kralja dok lovac zadaje završni udarac.","Odigraj damu na g6 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.017' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – locke die Verteidiger weg vom König.","Ein Springeropfer und die Dame setzen den Königsfang fort.","Schlage mit dem Springer auf h7 als Start der Mattfolge."],"en":["A forced mate is here — lure the defenders away from the king.","A knight sacrifice and the queen continue the king hunt.","Take with the knight on h7 to start the mating sequence."],"hr":["Prisilni mat je tu — odvuci branitelje od kralja.","Žrtva skakača i dama nastavljaju lov na kralja.","Uzmi skakačem na h7 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.018' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – dein kleiner Bauer wird zum Matter.","Der Turm fesselt das Lager, dann marschiert der Bauer zum Schlag.","Ziehe den Turm nach d2 als Auftakt der Mattfolge."],"en":["A forced mate is here — your little pawn becomes the executioner.","The rook ties down the camp, then the pawn marches to mate.","Play the rook to d2 to launch the mating sequence."],"hr":["Prisilni mat je pred tobom — tvoj mali pješak postaje krvnik.","Top sputava tabor, zatim pješak korača do mata.","Odigraj top na d2 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.019' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – zwei Springer umzingeln den König.","Ein Turmopfer öffnet die Tür, dann setzen die Springer matt.","Schlage mit dem Turm auf g2 als Start der Mattfolge."],"en":["A forced mate is ready — two knights surround the king.","A rook sacrifice opens the door, then the knights deliver mate.","Take with the rook on g2 to start the mating sequence."],"hr":["Prisilni mat je spreman — dva skakača opkoljavaju kralja.","Žrtva topa otvara vrata, zatim skakači matiraju.","Uzmi topom na g2 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.020' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die beiden Läufer kreuzen am König.","Erst lockt der Turm, dann arbeiten Läufer zusammen zum Matt.","Ziehe den Turm nach e8 als Auftakt der Mattfolge."],"en":["A forced mate awaits — the two bishops cross on the king.","First the rook lures, then the bishops combine to mate.","Play the rook to e8 to launch the mating sequence."],"hr":["Prisilni mat čeka — dva lovca se sijeku na kralju.","Prvo top namami, zatim lovci surađuju za mat.","Odigraj top na e8 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.021' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – jage den König über das Brett.","Dame und Springer opfern sich, der Turm vollendet das Netz.","Ziehe die Dame nach c4 als Start der Mattfolge."],"en":["A forced mate is here — chase the king across the board.","Queen and knight sacrifice while the rook completes the net.","Play the queen to c4 to start the mating sequence."],"hr":["Prisilni mat je tu — potjeraj kralja preko ploče.","Dama i skakač se žrtvuju dok top dovršava mrežu.","Odigraj damu na c4 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.022' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – treib den weißen König in die Box.","Springer- und Bauernschlag öffnen den Weg, dann jagt die Dame ihn.","Schlage mit dem Springer auf f4 als Auftakt der Mattfolge."],"en":["A forced mate is here — drive the white king into the box.","A knight and pawn capture open the way, then the queen hunts him.","Take with the knight on f4 to launch the mating sequence."],"hr":["Prisilni mat je pred tobom — natjeraj bijelog kralja u kutiju.","Skakač i pješak otvaraju put, zatim ga dama goni.","Uzmi skakačem na f4 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.023' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – die Ecke wird zur Falle für Weiß.","Ein Turmopfer reißt die Deckung weg, dann jagt die Dame den König.","Schlage mit dem Turm auf a2 als Start der Mattfolge."],"en":["A forced mate is ready — the corner becomes a trap for White.","A rook sacrifice rips away the cover, then the queen hunts the king.","Take with the rook on a2 to start the mating sequence."],"hr":["Prisilni mat je spreman — kut postaje zamka za bijelog.","Žrtva topa skida zaštitu, zatim dama goni kralja.","Uzmi topom na a2 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.024' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König steht eingeengt – hier steckt ein erzwungenes Matt.","Die weiße Dame opfert sich, dann liefern Springer und Turm das Netz.","Die Dame schlägt auf h4 und beginnt die Mattkombination."],"en":["The black king is boxed in – a forced mate is hiding here.","The white queen sacrifices herself, then knight and rook weave the net.","The queen takes on h4 and starts the mating combination."],"hr":["Crni kralj je stiješnjen — ovdje se krije prisilni mat.","Bijela dama se žrtvuje, a zatim skakač i top pletu mrežu.","Dama uzima na h4 i započinje matnu kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.025' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein bescheidener Bauer setzt den König zum Schluss matt.","Lockere zuerst den deckenden Springer mit einem Turmopfer.","Der Turm schlägt auf h8 und leitet das Bauernmatt ein."],"en":["A humble pawn delivers the final blow to the king.","First peel away the defending knight with a rook sacrifice.","The rook takes on h8 and sets up the pawn mate."],"hr":["Skromni pješak na kraju daje kralju mat.","Najprije ukloni branećeg skakača žrtvom topa.","Top uzima na h8 i priprema pješački mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.026' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist ungeschützt – ein erzwungenes Matt wartet.","Dame und Läufer arbeiten zusammen am bloßen König.","Die Dame zieht nach f4 und beginnt die Jagd."],"en":["The white king is exposed – a forced mate awaits.","Queen and bishop combine against the bare king.","The queen goes to f4 and begins the hunt."],"hr":["Bijeli kralj je nezaštićen — čeka prisilni mat.","Dama i lovac surađuju protiv golog kralja.","Dama ide na f4 i započinje hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.027' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist entblößt – ein erzwungenes Matt steht bereit.","Reiße zuerst den König heraus, dann schließt der Springer das Netz.","Die Dame schlägt auf a2 und startet die Kombination."],"en":["The white king is laid bare – a forced mate is ready.","Drag the king out first, then the knight closes the net.","The queen takes on a2 and starts the combination."],"hr":["Bijeli kralj je razgolićen — spreman je prisilni mat.","Najprije izvuci kralja, zatim skakač zatvara mrežu.","Dama uzima na a2 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.028' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König ist eingemauert – ein erzwungenes Matt liegt vor.","Springer und Turm dringen ein, die Dame gibt den Todesstoß am Rand.","Der Springer schlägt auf g6 und eröffnet die Kombination."],"en":["The black king is walled in – a forced mate is at hand.","Knight and rook break in, the queen delivers the edge blow.","The knight takes on g6 and opens the combination."],"hr":["Crni kralj je zazidan — pred nama je prisilni mat.","Skakač i top prodiru, dama zadaje udarac uz rub.","Skakač uzima na g6 i otvara kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.029' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Treibe den König an den Rand – ein erzwungenes Matt folgt.","Läufer und Türme nehmen den König in die Zange, ein Bauer schließt ab.","Der Läufer zieht nach a6 und beginnt die Treibjagd."],"en":["Drive the king to the edge – a forced mate follows.","Bishop and rooks pincer the king, a pawn seals it.","The bishop goes to a6 and starts the chase."],"hr":["Otjeraj kralja na rub — slijedi prisilni mat.","Lovac i topovi stišću kralja, pješak zapečaćuje.","Lovac ide na a6 i započinje hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.030' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand erlaubt ein erzwungenes Matt.","Räume mit einem Turmopfer, dann setzen die zwei Läufer matt.","Der Turm schlägt auf g8 und beginnt die Kombination."],"en":["The black king on the edge allows a forced mate.","Clear with a rook sacrifice, then two bishops deliver mate.","The rook takes on g8 and starts the combination."],"hr":["Crni kralj na rubu dopušta prisilni mat.","Raščisti žrtvom topa, zatim dva lovca daju mat.","Top uzima na g8 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.031' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird zerlegt – ein erzwungenes Matt droht.","Läufer und Dame reißen die Königsstellung auf.","Der Läufer schlägt auf h7 und entfesselt den Angriff."],"en":["The black king gets dismantled – a forced mate looms.","Bishop and queen tear open the king''s shelter.","The bishop takes on h7 and unleashes the attack."],"hr":["Crni kralj se rastavlja — prijeti prisilni mat.","Lovac i dama razbijaju kraljev zaklon.","Lovac uzima na h7 i pokreće napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.032' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand fällt einem erzwungenen Matt zum Opfer.","Der Turm zieht den König heran, ein Bauer beendet es.","Der Turm zieht nach a8 und beginnt die Kombination."],"en":["The black king on the edge falls to a forced mate.","The rook draws the king in, a pawn finishes the job.","The rook goes to a8 and starts the combination."],"hr":["Crni kralj na rubu pada pred prisilnim matom.","Top privlači kralja, pješak završava posao.","Top ide na a8 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.033' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist wehrlos – ein erzwungenes Matt steht bereit.","Räume die Verteidiger, dann kreuzen sich die Läuferdiagonalen.","Die Dame schlägt auf e3 und startet die Kombination."],"en":["The white king is defenseless – a forced mate is ready.","Remove the defenders, then the bishops'' diagonals cross.","The queen takes on e3 and starts the combination."],"hr":["Bijeli kralj je bespomoćan — spreman je prisilni mat.","Ukloni branitelje, zatim se dijagonale lovaca križaju.","Dama uzima na e3 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.034' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird langsam erstickt – ein Matt ist erzwingbar.","Bring deinen König in Sicherheit, dann arbeiten Dame und Läufer am Rand.","Der König geht nach g2 und leitet das lange Mattnetz ein."],"en":["The black king is slowly smothered – mate can be forced.","Tuck your king to safety, then queen and bishop work the edge.","The king steps to g2 and begins the long mating net."],"hr":["Crni kralj se polako guši — mat se može iznuditi.","Skloni svog kralja na sigurno, pa dama i lovac rade uz rub.","Kralj ide na g2 i započinje dugu matnu mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:036.035' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird ins Freie getrieben – ein erzwungenes Matt naht.","Räume mit Turmopfern, dann jagen Dame und Türme den König.","Der Turm schlägt auf e7 und beginnt die Treibjagd."],"en":["The black king is forced into the open – a forced mate nears.","Clear with rook sacrifices, then queen and rooks hunt the king.","The rook takes on e7 and starts the chase."],"hr":["Crni kralj je istjeran na otvoreno — bliži se prisilni mat.","Raščisti žrtvama topova, pa dama i topovi love kralja.","Top uzima na e7 i započinje hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.036' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird hin- und hergetrieben – ein erzwungenes Matt folgt.","Die Dame nimmt dem König die Felder, bis das Netz zuschnappt.","Die Dame schlägt auf h1 und beginnt die Treibjagd."],"en":["The white king is shuffled back and forth – a forced mate follows.","The queen strips the king''s squares until the net snaps shut.","The queen takes on h1 and starts the chase."],"hr":["Bijeli kralj se tjera amo-tamo — slijedi prisilni mat.","Dama oduzima kralju polja dok se mreža ne zatvori.","Dama uzima na h1 i započinje hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.037' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird zugemauert – ein erzwungenes Matt droht.","Die Dame drängt sich ans Königsfeld, der Turm dringt ein.","Die Dame schlägt auf h6 und entfesselt den Angriff."],"en":["The black king gets boxed in – a forced mate looms.","The queen squeezes next to the king, the rook breaks in.","The queen takes on h6 and unleashes the attack."],"hr":["Crni kralj se zazidava — prijeti prisilni mat.","Dama se stišće uz kralja, top prodire.","Dama uzima na h6 i pokreće napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.038' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand erlaubt ein erzwungenes Matt.","Turm und Läufer pferchen den König ein, dann brechen die Bauern durch.","Der Turm zieht nach d8 und beginnt die lange Mattführung."],"en":["The black king on the edge allows a forced mate.","Rook and bishop pen the king in, then the pawns break through.","The rook goes to d8 and begins the long mating sequence."],"hr":["Crni kralj na rubu dopušta prisilni mat.","Top i lovac zatvaraju kralja, pa pješaci probijaju.","Top ide na d8 i započinje dugu matnu sekvencu."]}', HintsVersion=1 WHERE LineId LIKE '%:036.039' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird aufgerissen – ein erzwungenes Matt wartet.","Läufer und Turm dringen über die Diagonale und die Grundreihe ein.","Der Turm zieht nach g8 und startet die Kombination."],"en":["The white king gets ripped open – a forced mate awaits.","Bishop and rook invade along the diagonal and back rank.","The rook goes to g8 and starts the combination."],"hr":["Bijeli kralj se razbija — čeka prisilni mat.","Lovac i top prodiru dijagonalom i osnovnom linijom.","Top ide na g8 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.040' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird überrollt – ein erzwungenes Matt liegt vor.","Opfere auf der Königsstellung, dann liefern Dame und Springer das Netz.","Der Turm schlägt auf g2 und beginnt die Kombination."],"en":["The white king gets overrun – a forced mate is at hand.","Sacrifice on the king''s pocket, then queen and knight weave the net.","The rook takes on g2 and starts the combination."],"hr":["Bijeli kralj biva pregažen — pred nama je prisilni mat.","Žrtvuj na kraljevu zaklonu, pa dama i skakač pletu mrežu.","Top uzima na g2 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.041' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König steht im Kreuzfeuer – ein erzwungenes Matt droht.","Öffne die Linien mit dem Bauern, dann strömen Läufer und Türme heran.","Der Bauer schlägt auf e4 und entfesselt den Angriff."],"en":["The white king is caught in crossfire – a forced mate looms.","Open lines with the pawn, then bishop and rooks pour in.","The pawn takes on e4 and unleashes the attack."],"hr":["Bijeli kralj je u unakrsnoj vatri — prijeti prisilni mat.","Otvori linije pješakom, pa lovac i topovi navale.","Pješak uzima na e4 i pokreće napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.042' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird freigelegt – ein erzwungenes Matt steht bereit.","Opfere auf der Rochadestellung, dann jagen Läufer und Turm den König.","Der Turm schlägt auf g7 und beginnt die Kombination."],"en":["The black king is stripped bare – a forced mate is ready.","Sacrifice on the castled shelter, then bishop and rook hunt the king.","The rook takes on g7 and starts the combination."],"hr":["Crni kralj je razgolićen — spreman je prisilni mat.","Žrtvuj na rošadnom zaklonu, pa lovac i top love kralja.","Top uzima na g7 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.043' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird über das Brett gejagt – ein erzwungenes Matt folgt.","Opfere zur Öffnung, dann mähen Dame und Springer alle Fluchtfelder ab.","Der Turm schlägt auf h7 und beginnt die Treibjagd."],"en":["The black king is chased across the board – a forced mate follows.","Sacrifice to open up, then queen and knight mow down every escape.","The rook takes on h7 and starts the chase."],"hr":["Crni kralj se goni po ploči — slijedi prisilni mat.","Žrtvuj za otvaranje, pa dama i skakač kose sva bježna polja.","Top uzima na h7 i započinje hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.044' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist hilflos – ein erzwungenes Matt wartet.","Räume das schützende Feld, dann arbeiten Dame und Läufer am König.","Der Läufer schlägt auf g2 und startet die Kombination."],"en":["The white king is helpless – a forced mate awaits.","Clear the sheltering square, then queen and bishop work the king.","The bishop takes on g2 and starts the combination."],"hr":["Bijeli kralj je bespomoćan — čeka prisilni mat.","Raščisti zaštitno polje, pa dama i lovac rade na kralju.","Lovac uzima na g2 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.045' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird erstickt – ein erzwungenes Matt droht.","Dame und Springer drängen den König in die eigene Ecke.","Die Dame schlägt auf e6 und beginnt die Erstickungsjagd."],"en":["The black king gets smothered – a forced mate looms.","Queen and knight crowd the king into his own corner.","The queen takes on e6 and starts the smothering hunt."],"hr":["Crni kralj se guši — prijeti prisilni mat.","Dama i skakač guraju kralja u vlastiti kut.","Dama uzima na e6 i započinje gušeću hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.046' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird freigelegt – ein erzwungenes Matt liegt vor.","Lock mit einem Damenopfer, dann dringen Turm und Läufer ein.","Die Dame schlägt auf f7 und startet die Kombination."],"en":["The black king is laid bare – a forced mate is at hand.","Lure with a queen sacrifice, then rook and bishop break in.","The queen takes on f7 and starts the combination."],"hr":["Crni kralj je razgolićen — pred nama je prisilni mat.","Namami žrtvom dame, pa top i lovac prodiru.","Dama uzima na f7 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.047' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König am Rand erlaubt ein erzwungenes Matt.","Lock den König mit dem Bauern heraus, dann schnappen Dame und Turm zu.","Der Bauer zieht nach g5 und beginnt die Kombination."],"en":["The black king on the edge allows a forced mate.","Lure the king out with the pawn, then queen and rook snap shut.","The pawn goes to g5 and starts the combination."],"hr":["Crni kralj na rubu dopušta prisilni mat.","Namami kralja pješakom, pa dama i top zatvore mrežu.","Pješak ide na g5 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.048' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird hin- und hergejagt – ein erzwungenes Matt folgt.","Springer und Dame nehmen dem König nach und nach alle Felder.","Der Springer schlägt auf g6 und beginnt die Treibjagd."],"en":["The black king is chased back and forth – a forced mate follows.","Knight and queen strip the king of his squares one by one.","The knight takes on g6 and starts the chase."],"hr":["Crni kralj se goni amo-tamo — slijedi prisilni mat.","Skakač i dama kralju oduzimaju polja jedno po jedno.","Skakač uzima na g6 i započinje hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.049' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird überwältigt – ein erzwungenes Matt wartet.","Opfere die Türme nacheinander, dann fängt die Dame den König.","Der Turm schlägt auf e1 und beginnt die Kombination."],"en":["The white king gets overwhelmed – a forced mate awaits.","Sacrifice the rooks in turn, then the queen traps the king.","The rook takes on e1 and starts the combination."],"hr":["Bijeli kralj biva svladan — čeka prisilni mat.","Žrtvuj topove jedan za drugim, pa dama hvata kralja.","Top uzima na e1 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.050' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König in der Ecke erlaubt ein erzwungenes Matt.","Räume die Verteidiger, dann setzen die beiden Springer matt.","Der Springer zieht nach c4 und beginnt die Kombination."],"en":["The white king in the corner allows a forced mate.","Clear the defenders, then the two knights deliver mate.","The knight goes to c4 and starts the combination."],"hr":["Bijeli kralj u kutu dopušta prisilni mat.","Ukloni branitelje, pa dva skakača daju mat.","Skakač ide na c4 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.051' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird aufgerissen – ein erzwungenes Matt droht.","Opfere auf der Königsstellung, dann setzen Dame und Springer den Haken.","Der Turm schlägt auf h7 und entfesselt den Angriff."],"en":["The black king gets ripped open – a forced mate looms.","Sacrifice on the king''s shelter, then queen and knight set the hook.","The rook takes on h7 and unleashes the attack."],"hr":["Crni kralj se razbija — prijeti prisilni mat.","Žrtvuj na kraljevu zaklonu, pa dama i skakač postave kuku.","Top uzima na h7 i pokreće napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.052' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König wird umzingelt – ein erzwungenes Matt liegt vor.","Räume mit einem Turmopfer, dann arbeiten Turm und Läufer am König.","Der Turm schlägt auf c2 und startet die Kombination."],"en":["The white king gets surrounded – a forced mate is at hand.","Clear with a rook sacrifice, then rook and bishop work the king.","The rook takes on c2 and starts the combination."],"hr":["Bijeli kralj je opkoljen — pred nama je prisilni mat.","Raščisti žrtvom topa, pa top i lovac rade na kralju.","Top uzima na c2 i započinje kombinaciju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.053' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der schwarze König wird erdrückt – ein erzwungenes Matt naht, samt Umwandlung.","Bauer, Läufer und Dame drängen den König unaufhaltsam in die Ecke.","Der Bauer zieht nach g6 und beginnt die lange Mattführung."],"en":["The black king gets crushed – a forced mate nears, with a promotion.","Pawn, bishop and queen press the king relentlessly into the corner.","The pawn goes to g6 and begins the long mating sequence."],"hr":["Crni kralj biva pregažen — bliži se prisilni mat, uz promociju.","Pješak, lovac i dama neumoljivo guraju kralja u kut.","Pješak ide na g6 i započinje dugu matnu sekvencu."]}', HintsVersion=1 WHERE LineId LIKE '%:036.054' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat einen erzwungenen Mattangriff am Königsflügel.","Läufer und Dame arbeiten zusammen, um die Felder um den schwarzen König zu ersticken.","Läufer schlägt auf f4 und beginnt das Mattnetz."],"en":["White has a forced mating attack on the kingside.","The bishop and queen team up to smother the squares around the black king.","Bishop takes on f4, starting the forced mating sequence."],"hr":["Bijeli ima prisilni matni napad na kraljevom krilu.","Lovac i dama udružuju se da uguše polja oko crnog kralja.","Lovac uzima na f4 i započinje matnu mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:036.055' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz treibt den weißen König in ein erzwungenes Matt.","Die Dame jagt den König, während der Läufer das Fluchtfeld abdeckt.","Dame nach c3 leitet die Treibjagd zum Matt ein."],"en":["Black drives the white king into a forced mate.","The queen hunts the king while the bishop seals the escape square.","Queen to c3 begins the forced king hunt to mate."],"hr":["Crni tjera bijelog kralja u prisilni mat.","Dama lovi kralja dok lovac pokriva polje za bijeg.","Dama na c3 započinje hajku do mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.056' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt mit den schweren Figuren ein Matt.","Der Turm dringt ein, während Dame und Läufer den König einkreisen.","Turm nach f5 startet die erzwungene Mattfolge."],"en":["Black forces mate using the heavy pieces.","The rook infiltrates while queen and bishop hem in the king.","Rook to f5 starts the forced mating sequence."],"hr":["Crni teškim figurama forsira mat.","Top prodire dok dama i lovac stišću kralja.","Top na f5 započinje prisilnu matnu seriju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.057' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt, das mit einem Damenopfer beginnt.","Die Dame opfert sich, damit Türme und ein Bauer das Matt vollenden.","Dame schlägt auf g6 und leitet das erzwungene Matt ein."],"en":["White has a forced mate beginning with a queen sacrifice.","The queen is given up so the rooks and a pawn deliver mate.","Queen takes on g6, launching the forced mate."],"hr":["Bijeli ima prisilni mat koji počinje žrtvom dame.","Dama se žrtvuje da topovi i pješak završe mat.","Dama uzima na g6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.058' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Erstickungsmatt vor Augen.","Der Springer manövriert, um den eingeengten König zu ersticken.","Springer schlägt auf f6 und beginnt die erzwungene Mattfolge."],"en":["White has a forced suffocation mate on the horizon.","The knight maneuvers to smother the boxed-in king.","Knight takes on f6, starting the forced mating sequence."],"hr":["Bijeli vidi prisilni ugušeni mat.","Skakač manevrira da uguši zarobljenog kralja.","Skakač uzima na f6 i započinje prisilnu matnu seriju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.059' AND BookFileName='chessable-u5-243265.pgn';
