UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat trotz der weißen Bauern ein erzwungenes Matt.","Der König marschiert vor, damit der Turm das Matt setzen kann.","König nach d4 beginnt die erzwungene Mattfolge."],"en":["Black has a forced mate despite White''s pawns.","The king marches forward so the rook can deliver mate.","King to d4 begins the forced mating sequence."],"hr":["Crni ima prisilni mat unatoč bijelim pješacima.","Kralj kreće naprijed da top može dati mat.","Kralj na d4 započinje prisilnu matnu seriju."]}', HintsVersion=1 WHERE LineId LIKE '%:036.061' AND BookFileName='chessable-u5-243265.pgn';
