UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt durch ein Damenopfer im Zentrum.","Die Dame wird geopfert, dann treiben Läufer und Dame den König nieder.","Dame schlägt auf d7 und leitet das erzwungene Matt ein."],"en":["White forces mate with a central queen sacrifice.","The queen is sacrificed, then bishop and queen run the king down.","Queen takes on d7, launching the forced mate."],"hr":["Bijeli forsira mat žrtvom dame u centru.","Dama se žrtvuje, zatim lovac i dama tjeraju kralja.","Dama uzima na d7 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.064' AND BookFileName='chessable-u5-243265.pgn';
