UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – opfere zur Königsjagd.","Springer, Dame und Türme treiben den König über das Brett.","Schlage mit der Dame auf f8 und beginne die erzwungene Folge."],"en":["White forces mate — sacrifice to start the king hunt.","Knight, queen and rooks drive the king across the board.","Take on f8 with the queen to begin the forced sequence."],"hr":["Bijeli prisiljava mat — žrtvuj za lov na kralja.","Skakač, dama i topovi gone kralja preko ploče.","Uzmi damom na f8 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.133' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – opfere zum Durchbruch.","Türme, Läufer und Dame stürmen gemeinsam den König.","Schlage mit der Dame auf e3 und beginne die erzwungene Folge."],"en":["Black has a forced mate — sacrifice to break through.","The rooks, bishop and queen storm the king together.","Take on e3 with the queen to begin the forced sequence."],"hr":["Crni ima prisilni mat — žrtvuj za proboj.","Topovi, lovac i dama zajedno jurišaju na kralja.","Uzmi damom na e3 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.134' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – opfere zur Linienöffnung.","Dame, Läufer und Türme dringen über die freigelegten Felder ein.","Schlage mit dem Turm auf g7 und beginne die erzwungene Folge."],"en":["White forces mate — sacrifice to open the lines.","Queen, bishop and rooks pour in over the opened squares.","Take on g7 with the rook to begin the forced sequence."],"hr":["Bijeli prisiljava mat — žrtvuj za otvaranje linija.","Dama, lovac i topovi prodiru preko otvorenih polja.","Uzmi topom na g7 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.135' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – treibe den König heraus.","Dame, Läufer und Springer jagen den König ins Freie.","Ziehe die Dame nach h3 und beginne die erzwungene Folge."],"en":["Black has a forced mate — flush the king out.","The queen, bishop and knight hunt the king into the open.","Push the queen to h3 to begin the forced sequence."],"hr":["Crni ima prisilni mat — istjeraj kralja.","Dama, lovac i skakač gone kralja na otvoreno.","Pomakni damu na h3 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.136' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – treibe den König die Reihen entlang.","Türme, Dame und Läufer rollen den König unaufhaltsam auf.","Schlage mit dem Turm auf a6 und beginne die erzwungene Folge."],"en":["White forces mate — march the king down the ranks.","The rooks, queen and bishop roll the king up relentlessly.","Take on a6 with the rook to begin the forced sequence."],"hr":["Bijeli prisiljava mat — tjeraj kralja niz redove.","Topovi, dama i lovac neumoljivo gaze kralja.","Uzmi topom na a6 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.137' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – opfere am König.","Läufer, beide Türme und Dame brechen über die Flanke ein.","Schlage mit dem Läufer auf h7 und beginne die erzwungene Folge."],"en":["White forces mate — sacrifice against the king.","Bishop, both rooks and queen crash through on the flank.","Take on h7 with the bishop to begin the forced sequence."],"hr":["Bijeli prisiljava mat — žrtvuj na kralju.","Lovac, oba topa i dama probijaju se po krilu.","Uzmi lovcem na h7 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.138' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – opfere zur Linienöffnung.","Türme, Läufer und Springer wirken gegen den König zusammen.","Ziehe den Bauern nach d6 und leite die Mattfolge ein."],"en":["White has a forced mate — sacrifice to open lines.","The rooks, bishop and knight combine against the king.","Push the pawn to d6 to start the mating sequence."],"hr":["Bijeli ima prisilni mat — žrtvuj za otvaranje linija.","Topovi, lovac i skakač djeluju zajedno protiv kralja.","Pomakni pješaka na d6 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.139' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – ersticke den König.","Springer, Läufer und Dame schnüren die Rochadestellung ein.","Ziehe den Springer nach f5 und beginne die erzwungene Folge."],"en":["White forces mate — smother the king.","Knight, bishop and queen lock down the castled king.","Hop the knight to f5 to begin the forced sequence."],"hr":["Bijeli prisiljava mat — uguši kralja.","Skakač, lovac i dama sapinju rokiranog kralja.","Skoči skakačem na f5 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.140' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – locke den König heraus.","Ein Bauernopfer und die Dame schließen das Königsgehäuse.","Schlage mit dem Bauern auf h7 und beginne die erzwungene Folge."],"en":["White forces mate — draw the king out.","A pawn sacrifice and the queen seal the king in a box.","Take on h7 with the pawn to begin the forced sequence."],"hr":["Bijeli prisiljava mat — izvuci kralja.","Žrtva pješaka i dama zatvaraju kralja u kutiju.","Uzmi pješakom na h7 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.141' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß holt sich ein erzwungenes Matt – reiße die Königsdeckung auf.","Läufer und Dame brechen über die geschwächten Felder durch.","Schlage mit dem Läufer auf f6 und beginne die erzwungene Folge."],"en":["White lands a forced mate — tear open the king''s cover.","The bishops and queen break through the weakened squares.","Take on f6 with the bishop to begin the forced sequence."],"hr":["Bijeli postiže prisilni mat — razbij kraljevu zaštitu.","Lovci i dama probijaju se kroz oslabljena polja.","Uzmi lovcem na f6 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.142' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – opfere, um den König herauszuziehen.","Springer, Dame und Turm jagen den entblößten König.","Ziehe den Springer nach f6 und beginne die erzwungene Folge."],"en":["White forces mate — sacrifice to drag the king out.","Knight, queen and rook hunt the exposed king.","Hop the knight to f6 to begin the forced sequence."],"hr":["Bijeli prisiljava mat — žrtvuj da izvučeš kralja.","Skakač, dama i top gone izloženog kralja.","Skoči skakačem na f6 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.143' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt ein Matt – opfere am Königsflügel.","Bauern, Läufer, Dame und Turm überrollen die Königsstellung.","Schlage mit dem Bauern auf h7 und beginne die erzwungene Folge."],"en":["White forces mate — sacrifice on the kingside.","Pawn, bishop, queen and rook overrun the king''s shelter.","Take on h7 with the pawn to begin the forced sequence."],"hr":["Bijeli prisiljava mat — žrtvuj na kraljevom krilu.","Pješak, lovac, dama i top pregaze kraljevu zaštitu.","Uzmi pješakom na h7 i započni prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.144' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – treibe den feindlichen König ins Netz.","Springer und schwere Figuren bauen rund um den König den tödlichen Kasten.","Springerschach mit Sh5 leitet die Mattkombination ein."],"en":["A forced mate is waiting — drive the enemy king into the net.","Your knight and heavy pieces build a lethal box around his king.","Knight check Nh5 launches the mating sequence."],"hr":["Čeka prisilni mat — natjeraj protivničkog kralja u mrežu.","Skakač i teške figure grade smrtonosnu kutiju oko kralja.","Skakačev šah Nh5 pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.145' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – opfere für den Königsangriff.","Springer und Dame reißen die Königsstellung auf, ein Bauer gibt den letzten Stoß.","Der Springerzug Nf6 öffnet die Schlinge."],"en":["A forced mate is in the air — sacrifice to expose the king.","Knight and queen tear open the king''s cover and a pawn delivers the final blow.","The knight move Nf6 begins the rout."],"hr":["Prisilni mat je u zraku — žrtvuj da otkriješ kralja.","Skakač i dama razbijaju zaklon kralja, a pješak zadaje završni udarac.","Potez skakača Nf6 otvara stupicu."]}', HintsVersion=1 WHERE LineId LIKE '%:036.146' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet auf der Grundreihe.","Turmopfer räumen die Verteidiger weg, dann schlägt die Dame ein.","Der Turm schlägt mit Txe7 zu und beginnt die Mattfolge."],"en":["A forced mate lurks on the back rank.","Rook sacrifices clear the defenders, then the queen strikes.","The rook takes on e7 to start the mating line."],"hr":["Prisilni mat vreba na zadnjem redu.","Žrtve topova uklanjaju branitelje, zatim udara dama.","Top uzima na e7 i započinje matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.147' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist erreichbar – die Türme jagen den König.","Dame und Turm treiben den König wie auf Schienen ins tödliche Feld.","Das Damenschach Dxh6 setzt die Treibjagd in Gang."],"en":["A forced mate is there — your rook and queen hunt the king.","Queen and rook drive the king along the rails into the killing box.","The queen takes on h6 to begin the chase."],"hr":["Prisilni mat je tu — top i dama love kralja.","Dama i top tjeraju kralja kao po tračnicama u smrtonosno polje.","Dama uzima na h6 i pokreće hajku."]}', HintsVersion=1 WHERE LineId LIKE '%:036.148' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – nutze den eingeklemmten König.","Dame und Läufer wirken zusammen, ein Springeropfer öffnet die Bahn.","Das Damenschach Qh5 leitet die klassische Mattkombination ein."],"en":["A forced mate is ready — exploit the boxed-in king.","Queen and bishop combine while a knight sacrifice clears the path.","The queen check Qh5 begins the classic mating pattern."],"hr":["Prisilni mat je spreman — iskoristi stiješnjenog kralja.","Dama i lovac surađuju, žrtva skakača otvara put.","Damin šah Qh5 pokreće klasični matni obrazac."]}', HintsVersion=1 WHERE LineId LIKE '%:036.149' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – sprenge die Königsdeckung.","Ein Damenopfer lenkt den Verteidiger ab, dann dringen die Figuren durch.","Das Damenopfer Qxa6 entfacht die Mattkombination."],"en":["A forced mate is at hand — blast open the king''s guard.","A queen sacrifice deflects the defender, then your pieces break through.","The queen takes on a6 to ignite the mate."],"hr":["Prisilni mat je nadohvat — razbij obranu kralja.","Žrtva dame odvlači branitelja, zatim figure prodiru.","Dama uzima na a6 i pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.150' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – treibe den weißen König in die Enge.","Dame und Bauer arbeiten zusammen für das erstickende Mattnetz.","Das Damenschach Qe1 beginnt die Mattfolge."],"en":["A forced mate is set — pin the white king down.","Queen and pawn cooperate to weave the suffocating net.","The queen check Qe1 starts the mating sequence."],"hr":["Prisilni mat je spreman — pritisni bijelog kralja.","Dama i pješak surađuju u zagušujućoj mreži.","Damin šah Qe1 započinje matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.151' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt nur einen Weg – ein erzwungenes Matt am Königsflügel.","Die Springer und die Dame ersticken den König in der Ecke.","Das Damenopfer Qxg1 erzwingt das Mattnetz."],"en":["There''s only one path — a forced mate against the king.","The knights and queen smother the king in his own camp.","The queen takes on g1 to force the mating net."],"hr":["Postoji samo jedan put — prisilni mat protiv kralja.","Skakači i dama guše kralja u njegovom kutu.","Dama uzima na g1 i prisiljava matnu mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:036.152' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die Grundreihe ist der Schwachpunkt.","Turm und Läufer kooperieren gegen den eingeengten König.","Das Turmopfer Txh1 leitet die Mattfolge ein."],"en":["A forced mate awaits — the back rank is the weak spot.","Rook and bishop cooperate against the cornered king.","The rook takes on h1 to begin the mating line."],"hr":["Prisilni mat čeka — zadnji red je slaba točka.","Top i lovac surađuju protiv stiješnjenog kralja.","Top uzima na h1 i započinje matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.153' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Türme dominieren den Königsflügel.","Turmopfer ziehen den König heran, der Läufer gibt den Todesstoß.","Das Turmopfer Txg2 beginnt die Mattkombination."],"en":["A forced mate is here — the rooks dominate the king''s wing.","Rook sacrifices draw the king out, then the bishop finishes.","The rook takes on g2 to begin the mate."],"hr":["Prisilni mat je tu — topovi dominiraju kraljevim krilom.","Žrtve topova izvlače kralja, lovac zadaje smrtni udarac.","Top uzima na g2 i pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.154' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – nutze die Schwäche in der Ecke.","Die Springer wirken zusammen und ersticken den König.","Der Springerzug Ng3 leitet das Eckenmatt ein."],"en":["A forced mate is here — exploit the corner weakness.","The knights work together to smother the king.","The knight move Ng3 begins the corner mate."],"hr":["Prisilni mat je tu — iskoristi slabost u kutu.","Skakači surađuju i guše kralja.","Potez skakača Ng3 pokreće mat u kutu."]}', HintsVersion=1 WHERE LineId LIKE '%:036.155' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – jage den schwarzen König.","Dame und Läufer treiben den König heran, ein Bauer setzt matt.","Das Damenopfer Qxd6 leitet die Königsjagd ein."],"en":["A forced mate is ready — hunt the black king.","Queen and bishop herd the king while a pawn delivers mate.","The queen takes on d6 to begin the king hunt."],"hr":["Prisilni mat je spreman — lovi crnog kralja.","Dama i lovac tjeraju kralja, a pješak daje mat.","Dama uzima na d6 i pokreće lov na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:036.156' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – treibe den weißen König ins Netz.","Turmopfer locken den König, dann schließt sich der Kasten.","Das Turmopfer Txf3 entfesselt die Mattkombination."],"en":["A forced mate waits — drive the white king into the net.","Rook sacrifices lure the king before the box snaps shut.","The rook takes on f3 to unleash the mating attack."],"hr":["Prisilni mat čeka — natjeraj bijelog kralja u mrežu.","Žrtve topova mame kralja, zatim se kutija zatvara.","Top uzima na f3 i pokreće matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.157' AND BookFileName='chessable-u5-243265.pgn';
