UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – sprenge die Königsdeckung.","Läufer, Dame und Türme walzen den König systematisch nieder.","Das Läuferopfer Bxh7 leitet den Königsangriff ein."],"en":["A forced mate is here — blast open the king''s cover.","Bishop, queen and rooks mow the king down step by step.","The bishop takes on h7 to begin the attack."],"hr":["Prisilni mat je tu — razbij zaklon kralja.","Lovac, dama i topovi sustavno gaze kralja.","Lovac uzima na h7 i pokreće napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.162' AND BookFileName='chessable-u5-243265.pgn';
