UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist erreichbar – treibe den schwarzen König.","Dame, Springer und Bauer fangen den König im Haken.","Das Damenopfer Qxe5 leitet die Königsjagd ein."],"en":["A forced mate is reachable — drive the black king.","Queen, knight and pawn snare the king in the hook.","The queen takes on e5 to begin the king hunt."],"hr":["Prisilni mat je dohvatljiv — tjeraj crnog kralja.","Dama, skakač i pješak hvataju kralja u kuku.","Dama uzima na e5 i pokreće lov na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:036.166' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – opfere für den Königsangriff.","Dame, Türme und Läufer stürmen die schwarze Königsburg.","Das Damenschach Qg4 leitet die Mattkombination ein."],"en":["A forced mate is set — sacrifice to crack the king.","Queen, rook and bishop storm the black king''s castle.","The queen check Qg4 begins the mating attack."],"hr":["Prisilni mat je spreman — žrtvuj za napad na kralja.","Dama, topovi i lovac jurišaju na crnu kraljevu utvrdu.","Damin šah Qg4 pokreće matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.167' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – nutze die Schwäche des weißen Königs.","Dame und Türme arbeiten zusammen für das Haken-Mattnetz.","Das Damenopfer Qxh4 leitet die Mattfolge ein."],"en":["A forced mate waits — exploit the white king''s weakness.","Queen and rooks combine for the hook mating net.","The queen takes on h4 to begin the mating line."],"hr":["Prisilni mat čeka — iskoristi slabost bijelog kralja.","Dama i topovi surađuju u kuka-matnoj mreži.","Dama uzima na h4 i započinje matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.168' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – jage den schwarzen König.","Turm, Läufer und Dame treiben den König über das Brett.","Das Turmopfer Rxg6 leitet die Königsjagd ein."],"en":["A forced mate is here — hunt the black king.","Rook, bishop and queen chase the king across the board.","The rook takes on g6 to begin the king hunt."],"hr":["Prisilni mat je tu — lovi crnog kralja.","Top, lovac i dama tjeraju kralja preko ploče.","Top uzima na g6 i pokreće lov na kralja."]}', HintsVersion=1 WHERE LineId LIKE '%:036.169' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – sprenge die schwarze Königsstellung.","Läufer, Dame und Springer kombinieren zum Erstickungsmatt.","Das Läuferopfer Bxh7 leitet die Mattkombination ein."],"en":["A forced mate is set — blast open the black king.","Bishop, queen and knight combine for the smother.","The bishop takes on h7 to begin the mating attack."],"hr":["Prisilni mat je spreman — razbij crnu kraljevu poziciju.","Lovac, dama i skakač spajaju se za ugušni mat.","Lovac uzima na h7 i pokreće matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.170' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – nutze die Schwäche des weißen Königs.","Dame, Springer und Turm bilden das Arabische Mattnetz.","Das Damenopfer Qxg2 leitet die Mattfolge ein."],"en":["A forced mate waits — exploit the white king''s weakness.","Queen, knight and rook form the Arabian mating net.","The queen takes on g2 to begin the mating line."],"hr":["Prisilni mat čeka — iskoristi slabost bijelog kralja.","Dama, skakač i top tvore arapsku matnu mrežu.","Dama uzima na g2 i započinje matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.171' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – treibe den schwarzen König in die Ecke.","Dame und Springer wirken zusammen für das Eckenmatt.","Das Damenschach Qb8 leitet die Mattkombination ein."],"en":["A forced mate is here — drive the black king to the corner.","Queen and knight cooperate for the corner mate.","The queen check Qb8 begins the mating combination."],"hr":["Prisilni mat je tu — natjeraj crnog kralja u kut.","Dama i skakač surađuju za mat u kutu.","Damin šah Qb8 pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.172' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – opfere für den Königsangriff.","Turm, Dame und Bauern erdrücken den schwarzen König.","Das Turmopfer Rxe8 leitet die Mattkombination ein."],"en":["A forced mate is set — sacrifice to crack the king.","Rook, queen and pawns crush the black king.","The rook takes on e8 to begin the mating attack."],"hr":["Prisilni mat je spreman — žrtvuj za napad na kralja.","Top, dama i pješaci gnječe crnog kralja.","Top uzima na e8 i pokreće matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.173' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – sprenge die Königsdeckung.","Dame und Türme dringen über die offenen Linien zum König.","Das Damenopfer Qxh7 leitet die Mattkombination ein."],"en":["A forced mate waits — blast open the king''s cover.","Queen and rooks pour through the open lines to the king.","The queen takes on h7 to begin the mating attack."],"hr":["Prisilni mat čeka — razbij zaklon kralja.","Dama i topovi prodiru otvorenim linijama do kralja.","Dama uzima na h7 i pokreće matni napad."]}', HintsVersion=1 WHERE LineId LIKE '%:036.174' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – treibe den König ins Netz.","Dein Damenangriff im Verbund mit Läufer und Turm zerschlägt die Königsstellung.","Die Dame schlägt auf e6 und leitet das erzwungene Matt ein."],"en":["A forced mate is hiding here — drive the king into the net.","Your queen working with the bishops and the rook tears the king''s shelter apart.","The queen takes on e6 and starts the forced mate."],"hr":["Ovdje se krije prisilni mat — natjeraj kralja u mrežu.","Tvoja dama uz lovce i top razbija kraljev zaklon.","Dama uzima na e6 i pokreće prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.175' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – nutze die schwache Grundreihe und die offene Linie.","Turm und Dame arbeiten zusammen, der gegnerische König hat kaum Luft.","Der Turm zieht nach g4 und beginnt das erzwungene Matt."],"en":["There is a forced mate — exploit the weak back rank and the open line.","Your rook and queen cooperate, and the enemy king is short of air.","The rook moves to g4 and begins the forced mate."],"hr":["Postoji prisilni mat — iskoristi slabu zadnju liniju i otvoreni stupac.","Top i dama surađuju, a neprijateljski kralj jedva diše.","Top ide na g4 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.176' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist in der Luft – der schwarze König ist nackt.","Dame, Turm und Springer wirken zusammen, ein kleiner Bauer setzt den Schlusspunkt.","Die Dame zieht nach g7 und beginnt das erzwungene Matt."],"en":["A forced mate is in the air — the black king stands bare.","Queen, rook and knight combine, with a little pawn delivering the finish.","The queen goes to g7 and begins the forced mate."],"hr":["Prisilni mat visi u zraku — crni kralj je gol.","Dama, top i skakač djeluju zajedno, a mali pješak daje završnicu.","Dama ide na g7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.177' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – ersticke den König in seiner eigenen Stellung.","Dame und Springer dringen vor, während die eigenen Bauern den König einsperren.","Die Dame schlägt auf g7 und beginnt das erzwungene Matt."],"en":["A forced mate awaits — smother the king in his own position.","Queen and knight break in while the king''s own pawns hem him in.","The queen takes on g7 and begins the forced mate."],"hr":["Čeka te prisilni mat — uguši kralja u vlastitoj poziciji.","Dama i skakač prodiru dok kraljevi vlastiti pješaci ga zatvaraju.","Dama uzima na g7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.178' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – opfere für den Königsangriff.","Turm und Läufer stürmen die Königsstellung, die Dame folgt entscheidend.","Der Turm schlägt auf h2 und beginnt das erzwungene Matt."],"en":["Black has a forced mate — sacrifice to crack the king open.","Rook and bishop storm the king while the queen follows decisively.","The rook takes on h2 and begins the forced mate."],"hr":["Crni ima prisilni mat — žrtvuj da otvoriš kralja.","Top i lovac jurišaju na kralja, a dama presudno slijedi.","Top uzima na h2 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.179' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt – die Bauernumwandlung ebnet den Weg.","Läufer und Turm reißen die Stellung auf, ein Bauer verwandelt sich entscheidend.","Der Läufer schlägt auf f2 und beginnt das erzwungene Matt."],"en":["Black forces mate — a pawn promotion clears the path.","Bishop and rook tear things open while a pawn promotes decisively.","The bishop takes on f2 and begins the forced mate."],"hr":["Crni forsira mat — promocija pješaka krči put.","Lovac i top razbijaju poziciju dok se pješak presudno promovira.","Lovac uzima na f2 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.180' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß setzt erzwungen matt – treibe den König an den Rand.","Springer, Turm und der vorgeschobene Bauer weben das Mattnetz.","Der Springer zieht nach h7 und beginnt das erzwungene Matt."],"en":["White forces mate — push the king to the edge.","Knight, rook and the advanced pawn weave the mating net.","The knight goes to h7 and begins the forced mate."],"hr":["Bijeli forsira mat — natjeraj kralja na rub.","Skakač, top i napredni pješak pletu matnu mrežu.","Skakač ide na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.181' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – jage den weißen König mit Schachs.","Deine beiden Damen umzingeln den ungeschützten König.","Die Dame zieht nach b3 und beginnt das erzwungene Matt."],"en":["Black has a forced mate — hunt the white king with checks.","Your two queens surround the exposed king.","The queen goes to b3 and begins the forced mate."],"hr":["Crni ima prisilni mat — lovi bijelog kralja šahovima.","Tvoje dvije dame okružuju izloženog kralja.","Dama ide na b3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.182' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt – räume die Grundreihe mit Opfern frei.","Beide Türme opfern sich, dann gibt die Dame den letzten Stoß.","Der Turm schlägt auf a1 und beginnt das erzwungene Matt."],"en":["Black forces mate — clear the back rank with sacrifices.","Both rooks sacrifice themselves, then the queen lands the final blow.","The rook takes on a1 and begins the forced mate."],"hr":["Crni forsira mat — žrtvama očisti zadnju liniju.","Oba topa se žrtvuju, zatim dama zadaje posljednji udarac.","Top uzima na a1 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.183' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß setzt erzwungen matt – ersticke den eingeklemmten König.","Springer und Dame umkreisen den König, dessen eigene Figuren ihn behindern.","Der Springer schlägt auf f7 und beginnt das erzwungene Matt."],"en":["White forces mate — smother the boxed-in king.","Knight and queen circle the king whose own pieces block him.","The knight takes on f7 and begins the forced mate."],"hr":["Bijeli forsira mat — uguši zatvorenog kralja.","Skakač i dama kruže oko kralja kojeg vlastite figure blokiraju.","Skakač uzima na f7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.184' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – opfere, um die Königsstellung zu sprengen.","Dame und Springer schlagen ein, dann gibt ein kleiner Bauer den Todesstoß.","Die Dame schlägt auf h2 und beginnt das erzwungene Matt."],"en":["Black has a forced mate — sacrifice to blow open the king.","Queen and knight crash in, then a little pawn delivers the killing blow.","The queen takes on h2 and begins the forced mate."],"hr":["Crni ima prisilni mat — žrtvuj da raznese kralja.","Dama i skakač upadaju, zatim mali pješak zadaje smrtni udarac.","Dama uzima na h2 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.185' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt – ein Opfer öffnet die Linie zum König.","Springer und Dame räumen den Weg, ein Bauer setzt am Ende matt.","Der Springer schlägt auf e3 und beginnt das erzwungene Matt."],"en":["Black forces mate — a sacrifice opens the line to the king.","Knight and queen clear the way, and a pawn delivers mate at the end.","The knight takes on e3 and begins the forced mate."],"hr":["Crni forsira mat — žrtva otvara liniju prema kralju.","Skakač i dama krče put, a pješak na kraju daje mat.","Skakač uzima na e3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.186' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz setzt erzwungen matt – jage den König mit den Schwerfiguren.","Beide Türme und die Dame treiben den eingeengten König in die Enge.","Die Dame zieht nach g5 und beginnt das erzwungene Matt."],"en":["Black forces mate — chase the king with the heavy pieces.","Both rooks and the queen drive the cramped king into a corner.","The queen goes to g5 and begins the forced mate."],"hr":["Crni forsira mat — goni kralja teškim figurama.","Oba topa i dama tjeraju stiješnjenog kralja u kut.","Dama ide na g5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.187' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – das klassische Läuferopfer am Königsflügel.","Läufer, Dame und Springer dringen gemeinsam zum König durch.","Der Läufer schlägt auf h7 und beginnt das erzwungene Matt."],"en":["White has a forced mate — the classic bishop sacrifice on the king''s wing.","Bishop, queen and knight break through to the king together.","The bishop takes on h7 and begins the forced mate."],"hr":["Bijeli ima prisilni mat — klasična žrtva lovca na kraljevom krilu.","Lovac, dama i skakač zajedno probijaju do kralja.","Lovac uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.188' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt – opfere, um den weißen König freizulegen.","Turm und Dame walzen die Königsstellung systematisch nieder.","Der Turm schlägt auf h3 und beginnt das erzwungene Matt."],"en":["Black forces mate — sacrifice to lay the white king bare.","Rook and queen roll over the king''s position step by step.","The rook takes on h3 and begins the forced mate."],"hr":["Crni forsira mat — žrtvuj da ogoliš bijelog kralja.","Top i dama sustavno valjaju kraljevu poziciju.","Top uzima na h3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.189' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – die Läufer und der Turm beherrschen das Brett.","Springer, Läufer und Turm spannen ein Netz um den weißen König.","Der Springer schlägt auf c4 und beginnt das erzwungene Matt."],"en":["Black has a forced mate — the bishops and rook dominate the board.","Knight, bishop and rook spin a net around the white king.","The knight takes on c4 and begins the forced mate."],"hr":["Crni ima prisilni mat — lovci i top dominiraju pločom.","Skakač, lovac i top pletu mrežu oko bijelog kralja.","Skakač uzima na c4 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.190' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt – opfere, um den weißen König zu fangen.","Beide Springer, Dame und Turm überlasten die Verteidigung des Königs.","Der Springer schlägt auf h3 und beginnt das erzwungene Matt."],"en":["Black forces mate — sacrifice to trap the white king.","Both knights, the queen and a rook overwhelm the king''s defence.","The knight takes on h3 and begins the forced mate."],"hr":["Crni forsira mat — žrtvuj da uhvatiš bijelog kralja.","Oba skakača, dama i top preopterećuju kraljevu obranu.","Skakač uzima na h3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.191' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – das Läuferopfer reißt den König heraus.","Läufer, Dame und Springer arbeiten Hand in Hand zum König.","Der Läufer schlägt auf h7 und beginnt das erzwungene Matt."],"en":["White has a forced mate — the bishop sacrifice drags the king out.","Bishop, queen and knight work hand in hand toward the king.","The bishop takes on h7 and begins the forced mate."],"hr":["Bijeli ima prisilni mat — žrtva lovca izvlači kralja.","Lovac, dama i skakač rade ruku pod ruku prema kralju.","Lovac uzima na h7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.192' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – ein Turmopfer öffnet den Weg.","Turm, Dame und Läufer dirigieren den schwarzen König ins Verderben.","Der Turm schlägt auf f8 und beginnt das erzwungene Matt."],"en":["White forces mate — a rook sacrifice opens the path.","Rook, queen and bishop steer the black king to his doom.","The rook takes on f8 and begins the forced mate."],"hr":["Bijeli forsira mat — žrtva topa otvara put.","Top, dama i lovac usmjeravaju crnog kralja u propast.","Top uzima na f8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.193' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – treibe den König zwischen seine eigenen Türme.","Dame und Turm opfern sich, um den König einzumauern.","Die Dame schlägt auf e8 und beginnt das erzwungene Matt."],"en":["White has a forced mate — wedge the king between his own rooks.","Queen and rook sacrifice to wall the king in.","The queen takes on e8 and begins the forced mate."],"hr":["Bijeli ima prisilni mat — ukliješti kralja između vlastitih topova.","Dama i top se žrtvuju da zazidaju kralja.","Dama uzima na e8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.194' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt – Turm und Springer im Zusammenspiel.","Der Springer schneidet Felder ab, während der Turm den König stellt.","Der Springer zieht nach f3 und beginnt das erzwungene Matt."],"en":["Black forces mate — rook and knight in perfect harmony.","The knight cuts off escape squares while the rook hunts the king.","The knight goes to f3 and begins the forced mate."],"hr":["Crni forsira mat — top i skakač u savršenom skladu.","Skakač oduzima polja bijega dok top goni kralja.","Skakač ide na f3 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.195' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – opfere den Turm, um den König herauszuziehen.","Dame und Turm jagen den schwarzen König über das Brett.","Die Dame schlägt auf e6 und beginnt das erzwungene Matt."],"en":["White forces mate — sacrifice the rook to drag the king out.","Queen and rook chase the black king across the board.","The queen takes on e6 and begins the forced mate."],"hr":["Bijeli forsira mat — žrtvuj top da izvučeš kralja.","Dama i top gone crnog kralja preko ploče.","Dama uzima na e6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.196' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – die Diagonale zum König ist tödlich.","Turm, Läufer und Dame bündeln ihre Kraft gegen den weißen König.","Der Turm schlägt auf h6 und beginnt das erzwungene Matt."],"en":["Black has a forced mate — the diagonal to the king is lethal.","Rook, bishop and queen pool their force against the white king.","The rook takes on h6 and begins the forced mate."],"hr":["Crni ima prisilni mat — dijagonala prema kralju je smrtonosna.","Top, lovac i dama udružuju snagu protiv bijelog kralja.","Top uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.197' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – ein Turmopfer lockt den Verteidiger weg.","Turm, Dame und der vorgeschobene Bauer ersticken den König.","Der Turm schlägt auf f7 und beginnt das erzwungene Matt."],"en":["White forces mate — a rook sacrifice lures the defender away.","Rook, queen and the advanced pawn smother the king.","The rook takes on f7 and begins the forced mate."],"hr":["Bijeli forsira mat — žrtva topa odvlači branitelja.","Top, dama i napredni pješak guše kralja.","Top uzima na f7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.198' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – zerre den König mit einem Opfer ins Freie.","Dame und die beiden Läufer kreuzen ihr Feuer auf dem König.","Die Dame schlägt auf h6 und beginnt das erzwungene Matt."],"en":["White has a forced mate — drag the king out with a sacrifice.","The queen and both bishops cross their fire on the king.","The queen takes on h6 and begins the forced mate."],"hr":["Bijeli ima prisilni mat — žrtvom izvuci kralja na otvoreno.","Dama i oba lovca ukrštaju vatru na kralju.","Dama uzima na h6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.199' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – die Türme dringen auf die siebte Reihe.","Springer und die beiden Türme verschnüren den schwarzen König.","Der Springer schlägt auf f8 und beginnt das erzwungene Matt."],"en":["White forces mate — the rooks invade the seventh rank.","Knight and both rooks tie up the black king.","The knight takes on f8 and begins the forced mate."],"hr":["Bijeli forsira mat — topovi prodiru na sedmu liniju.","Skakač i oba topa sapinju crnog kralja.","Skakač uzima na f8 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.200' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – die Läufer halten die Diagonalen.","Dame und beide Läufer bauen langsam das Mattnetz um den König.","Die Dame zieht nach h5 und beginnt das erzwungene Matt."],"en":["White has a forced mate — the bishops own the diagonals.","The queen and both bishops slowly build the mating net.","The queen goes to h5 and begins the forced mate."],"hr":["Bijeli ima prisilni mat — lovci drže dijagonale.","Dama i oba lovca polako grade matnu mrežu oko kralja.","Dama ide na h5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.201' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – treibe den König mit dem Turm vor dir her.","Turm und der weit vorgerückte Bauer setzen den Schlussstein.","Der Turm zieht nach d7 und beginnt das erzwungene Matt."],"en":["White forces mate — herd the king forward with the rook.","The rook and the far-advanced pawn set the final stone.","The rook goes to d7 and begins the forced mate."],"hr":["Bijeli forsira mat — tjeraj kralja topom ispred sebe.","Top i daleko napredovali pješak postavljaju završni kamen.","Top ide na d7 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.202' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – opfere die Dame, um die Verteidiger wegzuziehen.","Beide Läufer und der Turm kreuzen ihr Feuer auf dem König.","Die Dame schlägt auf d6 und beginnt das erzwungene Matt."],"en":["White has a forced mate — sacrifice the queen to pull the defenders away.","Both bishops and the rook cross their fire on the king.","The queen takes on d6 and begins the forced mate."],"hr":["Bijeli ima prisilni mat — žrtvuj damu da odvučeš branitelje.","Oba lovca i top ukrštaju vatru na kralju.","Dama uzima na d6 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.203' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – die beiden Läufer durchschneiden die Stellung.","Dame und beide Läufer reißen die Königsdeckung auf.","Die Dame zieht nach d5 und beginnt das erzwungene Matt."],"en":["White forces mate — the two bishops slice through the position.","The queen and both bishops tear open the king''s cover.","The queen goes to d5 and begins the forced mate."],"hr":["Bijeli forsira mat — dva lovca presijecaju poziciju.","Dama i oba lovca razbijaju kraljev zaklon.","Dama ide na d5 i započinje prisilni mat."]}', HintsVersion=1 WHERE LineId LIKE '%:036.204' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt ein erzwungenes Matt – nutze die freie Stellung des feindlichen Königs.","Deine Dame führt das Werk, doch zuerst muss ein Bauer Linien öffnen.","Mit Bauer g4 leitest du die Mattkombination ein."],"en":["A forced mate is hiding here — exploit the exposed enemy king.","Your queen does the work, but first a pawn must open lines.","Play pawn to g4 to start the mating combination."],"hr":["Ovdje se krije prisilni mat — iskoristi izloženog kralja.","Tvoja dama izvršava posao, ali prvo pješak mora otvoriti linije.","Odigraj pješakom na g4 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.205' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der weiße König ist gefangen – ein erzwungenes Matt wartet.","Springer und Läufer weben das Netz, ein ruhiger Zug schließt es.","Ziehe den König nach g7 als Auftakt zur Mattfolge."],"en":["The white king is trapped — a forced mate awaits.","Knight and bishop weave the net, a quiet move seals it.","Move the king to g7 to begin the mating sequence."],"hr":["Bijeli kralj je u zamci — čeka prisilni mat.","Skakač i lovac pletu mrežu, miran potez je zatvara.","Pomakni kralja na g7 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.206' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt in der Luft – der weiße König ist nackt.","Deine Dame opfert sich, damit der Turm zuschlagen kann.","Mit der Dame nach g5 beginnt die Mattkombination."],"en":["A forced mate is in the air — the white king is bare.","Your queen sacrifices so the rook can deliver.","Bring the queen to g5 to start the mating combination."],"hr":["Prisilni mat je u zraku — bijeli kralj je gol.","Tvoja dama se žrtvuje da bi top zadao udarac.","Dovedi damu na g5 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.207' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der schwarze König steht entblößt.","Springer- und Damenopfer reißen die Königsstellung auf, der Turm vollendet.","Schlage mit dem Springer auf f6 und starte die Mattfolge."],"en":["A forced mate awaits — the black king stands exposed.","Knight and queen sacrifices tear open the castle, the rook finishes.","Take with the knight on f6 to launch the mating sequence."],"hr":["Čeka prisilni mat — crni kralj je izložen.","Žrtve skakača i dame razbijaju zaklon, top dovršava.","Uzmi skakačem na f6 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.208' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – der weiße König ist in der Ecke gefangen.","Dein Läufer und die Dame umzingeln den König unausweichlich.","Ziehe die Dame nach h1 als Auftakt zur Mattfolge."],"en":["There is a forced mate — the white king is cornered.","Your bishop and queen close in inescapably.","Move the queen to h1 to begin the mating sequence."],"hr":["Postoji prisilni mat — bijeli kralj je u kutu.","Tvoj lovac i dama ga neumitno okružuju.","Pomakni damu na h1 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.209' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – beide Springer wirken zusammen.","Die Springer treiben den König ins Verderben.","Ziehe den Springer nach e5, der Beginn der Mattfolge."],"en":["A forced mate is here — both knights work together.","The knights drive the king to ruin.","Move the knight to e5 to begin the mating sequence."],"hr":["Tu je prisilni mat — oba skakača djeluju zajedno.","Skakači tjeraju kralja u propast.","Pomakni skakača na e5 kao početak matnog niza."]}', HintsVersion=1 WHERE LineId LIKE '%:036.210' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet auf den eingeengten schwarzen König.","Läuferzug und Damenopfer öffnen den Weg, der Turm vollendet.","Ziehe den Läufer nach c4 und leite die Mattfolge ein."],"en":["A forced mate awaits the cramped black king.","A bishop move and queen sacrifice clear the path, the rook finishes.","Move the bishop to c4 to launch the mating sequence."],"hr":["Prisilni mat čeka skučenog crnog kralja.","Potez lovca i žrtva dame otvaraju put, top dovršava.","Pomakni lovca na c4 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.211' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der schwarze König wird entblößt.","Ein Springeropfer lockt einen Bauern weg, dann schlägt die Dame zu.","Opfere den Springer auf h5, der Auftakt zur Mattfolge."],"en":["A forced mate is at hand — the black king gets exposed.","A knight sacrifice lures a pawn away, then the queen strikes.","Sacrifice the knight on h5 to begin the mating sequence."],"hr":["Prisilni mat je nadohvat — crni kralj postaje izložen.","Žrtva skakača mami pješaka, zatim dama udara.","Žrtvuj skakača na h5 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.212' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der schwarze König wird aufgerissen.","Ein Bauernopfer und Figurenstürme bahnen den Weg für die Schwerfiguren.","Ziehe den Bauern nach e6 und beginne die Mattfolge."],"en":["A forced mate awaits — the black king will be torn open.","A pawn sacrifice and piece storm pave the way for the heavy pieces.","Push the pawn to e6 to begin the mating sequence."],"hr":["Čeka prisilni mat — crni kralj će biti razbijen.","Žrtva pješaka i juriš figura otvaraju put teškim figurama.","Gurni pješaka na e6 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.213' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Grundreihe ist die Schwäche.","Dame und Turm kombinieren gegen die ungedeckte hintere Reihe.","Ziehe die Dame nach c4 als Auftakt zur Mattfolge."],"en":["A forced mate is here — the back rank is the weakness.","Queen and rook combine against the undefended last rank.","Move the queen to c4 to begin the mating sequence."],"hr":["Tu je prisilni mat — zadnji red je slabost.","Dama i top udružuju se protiv nebranjenog zadnjeg reda.","Pomakni damu na c4 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.214' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – das klassische Erstickungsmotiv.","Der Springer treibt den König in die Ecke, die Dame opfert sich.","Ziehe den Springer nach h6 und beginne die erstickende Mattfolge."],"en":["A forced mate looms — the classic smothered theme.","The knight drives the king into the corner, the queen sacrifices.","Move the knight to h6 to begin the smothered mating sequence."],"hr":["Prijeti prisilni mat — klasični ugušeni motiv.","Skakač tjera kralja u kut, dama se žrtvuje.","Pomakni skakača na h6 i pokreni ugušeni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.215' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der schwarze König wird herausgelockt.","Ein Turmopfer zieht den König heraus, dann arbeiten Dame und Läufer.","Schlage mit dem Turm auf f8 und beginne die Mattfolge."],"en":["A forced mate awaits — the black king gets dragged out.","A rook sacrifice pulls the king out, then queen and bishop work.","Take with the rook on f8 to begin the mating sequence."],"hr":["Čeka prisilni mat — crni kralj biva izvučen.","Žrtva topa izvlači kralja, zatim dama i lovac rade.","Uzmi topom na f8 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.216' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – das arabische Motiv mit Turm und Springer.","Dame und Springer zwingen den König, der Turm vollendet in der Ecke.","Ziehe die Dame nach h4 als Auftakt zur Mattfolge."],"en":["A forced mate is here — the Arabian motif with rook and knight.","Queen and knight force the king, the rook finishes in the corner.","Move the queen to h4 to begin the mating sequence."],"hr":["Tu je prisilni mat — arapski motiv s topom i skakačem.","Dama i skakač prisiljavaju kralja, top dovršava u kutu.","Pomakni damu na h4 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.217' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – das arabische Motiv ist im Spiel.","Ein Damenopfer und ein Springersprung bereiten den Turmstoß vor.","Ziehe die Dame nach g6 und beginne die Mattfolge."],"en":["A forced mate awaits — the Arabian motif is in play.","A queen sacrifice and a knight leap prepare the rook''s blow.","Move the queen to g6 to begin the mating sequence."],"hr":["Čeka prisilni mat — arapski motiv je u igri.","Žrtva dame i skok skakača pripremaju udarac topa.","Pomakni damu na g6 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.218' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – der schwarze König wird entblößt.","Ein Springeropfer räumt den Verteidiger, dann schlägt die Dame zu.","Ziehe den Springer nach e7 als Auftakt zur Mattfolge."],"en":["A forced mate looms — the black king will be exposed.","A knight sacrifice removes the defender, then the queen strikes.","Move the knight to e7 to begin the mating sequence."],"hr":["Prijeti prisilni mat — crni kralj će biti izložen.","Žrtva skakača uklanja branitelja, zatim dama udara.","Pomakni skakača na e7 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.219' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – der schwarze König wird aufgerissen.","Springer- und Turmopfer öffnen den König für die Doppeltürme.","Ziehe den Springer nach g6 und beginne die Mattfolge."],"en":["A forced mate awaits — the black king will be torn open.","Knight and rook sacrifices open the king for the doubled rooks.","Move the knight to g6 to begin the mating sequence."],"hr":["Čeka prisilni mat — crni kralj će biti razbijen.","Žrtve skakača i topa otvaraju kralja za udvojene topove.","Pomakni skakača na g6 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.220' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Walze rollt über den König.","Ein Damenopfer reißt die Bauernkette auf, dann walzen die Schwerfiguren.","Schlage mit der Dame auf g7 und beginne die Mattfolge."],"en":["A forced mate is at hand — the roller flattens the king.","A queen sacrifice rips open the pawn shield, then the heavy pieces roll.","Take with the queen on g7 to begin the mating sequence."],"hr":["Prisilni mat je nadohvat — valjak gazi kralja.","Žrtva dame razbija pješački štit, zatim teške figure valjaju.","Uzmi damom na g7 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.221' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – das Eckmotiv mit Dame und Springer.","Ein Damenopfer lockt den König, dann zwingt der Turm ihn in die Ecke.","Schlage mit der Dame auf g7 und beginne die Mattfolge."],"en":["A forced mate awaits — the corner motif with queen and knight.","A queen sacrifice lures the king, then the rook forces it to the edge.","Take with the queen on g7 to begin the mating sequence."],"hr":["Čeka prisilni mat — kutni motiv s damom i skakačem.","Žrtva dame mami kralja, zatim top tjera u kut.","Uzmi damom na g7 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.222' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – die Türme walzen den weißen König nieder.","Beide Türme arbeiten Reihe um Reihe gegen den König.","Schlage mit dem Turm auf h2 als Auftakt zur Mattfolge."],"en":["A forced mate is here — the rooks mow down the white king.","Both rooks work rank by rank against the king.","Take with the rook on h2 to begin the mating sequence."],"hr":["Tu je prisilni mat — topovi kose bijelog kralja.","Oba topa rade red po red protiv kralja.","Uzmi topom na h2 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.223' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – das Opernmotiv mit Turm und Läufer.","Ein Turmopfer reißt den König heraus, dann arbeiten Turm und Läufer.","Schlage mit dem Turm auf f7 und beginne die Mattfolge."],"en":["A forced mate awaits — the opera motif with rook and bishop.","A rook sacrifice drags the king out, then rook and bishop work.","Take with the rook on f7 to begin the mating sequence."],"hr":["Čeka prisilni mat — operni motiv s topom i lovcem.","Žrtva topa izvlači kralja, zatim top i lovac rade.","Uzmi topom na f7 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.224' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der schwarze König wird umstellt.","Turm- und Damenopfer treiben den König, dann schließt sich das Netz.","Schlage mit dem Turm auf e7 und beginne die Mattfolge."],"en":["A forced mate is at hand — the black king will be surrounded.","Rook and queen sacrifices drive the king, then the net closes.","Take with the rook on e7 to begin the mating sequence."],"hr":["Prisilni mat je nadohvat — crni kralj biva okružen.","Žrtve topa i dame tjeraju kralja, zatim se mreža zatvara.","Uzmi topom na e7 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.225' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – das Eckmotiv mit Springer und Turm.","Turm- und Damenopfer entblößen den König, dann zwingt der Springer.","Ziehe den Turm nach d8 und beginne die Mattfolge."],"en":["A forced mate looms — the corner motif with knight and rook.","Rook and queen sacrifices bare the king, then the knight forces it.","Move the rook to d8 to begin the mating sequence."],"hr":["Prijeti prisilni mat — kutni motiv sa skakačem i topom.","Žrtve topa i dame ogoljuju kralja, zatim skakač prisiljava.","Pomakni top na d8 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.226' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – das Erstickungsmotiv für den weißen König.","Ein Turmopfer und Damenopfer ersticken den König mit eigenen Steinen.","Schlage mit dem Turm auf f1 und beginne die Mattfolge."],"en":["A forced mate is here — the suffocation motif for the white king.","A rook and queen sacrifice smother the king with his own men.","Take with the rook on f1 to begin the mating sequence."],"hr":["Tu je prisilni mat — motiv gušenja za bijelog kralja.","Žrtve topa i dame guše kralja vlastitim figurama.","Uzmi topom na f1 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.227' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – die zwei Läufer dominieren.","Ein Turmopfer und Läuferspiel öffnen die Diagonalen gegen den König.","Schlage mit dem Turm auf e7 und beginne die Mattfolge."],"en":["A forced mate awaits — the two bishops dominate.","A rook sacrifice and bishop play open the diagonals against the king.","Take with the rook on e7 to begin the mating sequence."],"hr":["Čeka prisilni mat — dva lovca dominiraju.","Žrtva topa i igra lovcima otvaraju dijagonale prema kralju.","Uzmi topom na e7 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.228' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – die Walze treibt den König nieder.","Turm und Bauern walzen den eingeschnürten König Reihe um Reihe.","Schlage mit dem Turm auf g7 und beginne die Mattfolge."],"en":["A forced mate is at hand — the roller drives the king down.","Rook and pawns mow the boxed-in king rank by rank.","Take with the rook on g7 to begin the mating sequence."],"hr":["Prisilni mat je nadohvat — valjak tjera kralja.","Top i pješaci kose stiješnjenog kralja red po red.","Uzmi topom na g7 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.229' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – beide Springer fangen den König.","Die Springer manövrieren den eingeengten König ins Verderben.","Ziehe den Springer nach d7 als Auftakt zur Mattfolge."],"en":["A forced mate is here — both knights trap the king.","The knights maneuver the cramped king to his doom.","Move the knight to d7 to begin the mating sequence."],"hr":["Tu je prisilni mat — oba skakača hvataju kralja.","Skakači manevriraju skučenog kralja u propast.","Pomakni skakača na d7 kao uvod u matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.230' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt wartet – ein Bauer gibt den letzten Stoß.","Ein Damenopfer und Turmeinbruch räumen den Weg, der Bauer mattiert.","Schlage mit der Dame auf f1 und beginne die Mattfolge."],"en":["A forced mate awaits — a pawn delivers the final blow.","A queen sacrifice and rook invasion clear the way, the pawn mates.","Take with the queen on f1 to begin the mating sequence."],"hr":["Čeka prisilni mat — pješak zadaje završni udarac.","Žrtva dame i prodor topa čiste put, pješak matira.","Uzmi damom na f1 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.231' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – der weiße König wird entblößt.","Turm- und Turmopfer reißen die Deckung weg, dann schlägt die Dame zu.","Schlage mit dem Turm auf h2 und beginne die Mattfolge."],"en":["A forced mate is at hand — the white king will be exposed.","Two rook sacrifices strip the cover, then the queen strikes.","Take with the rook on h2 to begin the mating sequence."],"hr":["Prisilni mat je nadohvat — bijeli kralj će biti izložen.","Dvije žrtve topova skidaju zaštitu, zatim dama udara.","Uzmi topom na h2 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.232' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – das Bodensche Motiv der Kreuzläufer.","Ein Turmopfer lockt die Dame, dann mattet ein Läufer.","Ziehe den Turm nach e5, der Beginn der Mattfolge."],"en":["A forced mate is here — Boden''s criss-crossing bishops.","A rook sacrifice lures the queen, then a bishop mates.","Move the rook to e5 to begin the mating sequence."],"hr":["Tu je prisilni mat — Bodenov motiv ukrštenih lovaca.","Žrtva topa mami damu, zatim lovac matira.","Pomakni top na e5 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.233' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt droht – die beiden Läufer zerschneiden den König.","Ein Damen- und Läuferopfer öffnen die Diagonalen gegen den weißen König.","Schlage mit der Dame auf g2 und beginne die Mattfolge."],"en":["A forced mate looms — the two bishops slice up the king.","A queen and bishop sacrifice open the diagonals against the white king.","Take with the queen on g2 to begin the mating sequence."],"hr":["Prijeti prisilni mat — dva lovca sijeku kralja.","Žrtve dame i lovca otvaraju dijagonale prema bijelom kralju.","Uzmi damom na g2 i pokreni matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:036.234' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier steckt eine erzwungene Mattkombination – beginne mit einem zwingenden Opfer.","Deine Dame lockt zuerst, danach erledigt der Springer in der Ecke das Werk.","Dame schlägt auf e7 – Auftakt zum erzwungenen Matt."],"en":["A forced mating combination is waiting – start with a forcing sacrifice.","The queen lures first, then the knight delivers the blow near the corner.","Queen takes on e7 – the start of the forced mate."],"hr":["Ovdje vreba prisilni mat – počni prisilnom žrtvom.","Dama prvo namami, a zatim skakač u kutu dovršava posao.","Dama uzima na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.235' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt in der Luft – treibe den König mit Tempogewinn ins Verderben.","Der Springer dringt entscheidend ein, später setzt die schwere Figur den Schlusspunkt.","Springer nach e7 – Beginn der erzwungenen Mattführung."],"en":["A forced mate is in the air – drive the king with gain of tempo.","The knight breaks in decisively, and a heavy piece finishes later.","Knight to e7 – the start of the forced mate."],"hr":["Prisilni mat je u zraku – tjeraj kralja uz dobitak tempa.","Skakač presudno prodire, a teška figura kasnije završava.","Skakač na e7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.236' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – fixiere zuerst den König in der Ecke.","Dame und Springer weben ein Netz, das im klassischen erstickten Matt endet.","Dame nach b3 – Auftakt zum erzwungenen erstickten Matt."],"en":["A forced mate is ready – first pin the king to its corner.","Queen and knight weave a net ending in the classic smothered mate.","Queen to b3 – the start of the forced smothered mate."],"hr":["Prisilni mat je spreman – prvo prikuj kralja u kutu.","Dama i skakač pletu mrežu koja završava ugušenim matom.","Dama na b3 — početak prisilnog ugušenog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.237' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert mattsetzen – ein Läufer-Manöver bahnt der Schwerfigur den Weg.","Erst lenkt der Läufer ab, dann fährt der Turm auf der Grundreihe ein.","Läufer nach b3 – Beginn der erzwungenen Mattführung."],"en":["You can force mate – a bishop manoeuvre clears the way for the heavy piece.","First the bishop deflects, then the rook crashes in on the back rank.","Bishop to b3 – the start of the forced mate."],"hr":["Možeš prisiliti mat – potez lovca otvara put teškoj figuri.","Prvo lovac odvlači, a zatim top upada na posljednjoj liniji.","Lovac na b3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.238' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – beseitige die Verteidigung mit einem Opfer.","Turm und Läufer reißen die Stellung auf, ehe die Dame das Schlussmatt liefert.","Turm schlägt auf c4 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here – remove the defence with a sacrifice.","Rook and bishop tear the position open before the queen mates.","Rook takes on c4 – the start of the forced mate."],"hr":["Prisilni mat je tu – ukloni obranu žrtvom.","Top i lovac otvaraju poziciju prije nego dama matira.","Top uzima na c4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.239' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du setzt forciert matt – ein Damenopfer zieht den König heraus.","Nach dem Damenopfer gibt der Läufer den entscheidenden Schlag.","Dame schlägt auf b1 – Beginn des erzwungenen Matts."],"en":["You force mate – a queen sacrifice drags the king out.","After the queen sacrifice the bishop delivers the decisive blow.","Queen takes on b1 – the start of the forced mate."],"hr":["Prisiljavaš mat – žrtva dame izvlači kralja.","Nakon žrtve dame lovac zadaje presudan udarac.","Dama uzima na b1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.240' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet – räume mit Opfern die Wege zum König frei.","Dame und Läufer opfern sich, damit der Turm in die Ecke einfällt.","Dame schlägt auf e5 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate awaits – clear the lines to the king with sacrifices.","Queen and bishop give themselves up so the rook crashes into the corner.","Queen takes on e5 – the start of the forced mate."],"hr":["Prisilni mat čeka – žrtvama otvori linije prema kralju.","Dama i lovac se žrtvuju kako bi top upao u kut.","Dama uzima na e5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.241' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert matt geben – beginne mit einem aufreißenden Bauernstoß.","Der Bauer öffnet die Linie, dann liefert ein Schwerfiguren-Opfer das Matt.","Bauer nach g5 – Beginn der erzwungenen Mattführung."],"en":["You can force mate – begin with a line-opening pawn thrust.","The pawn opens the file, then a heavy-piece sacrifice mates.","Pawn to g5 – the start of the forced mate."],"hr":["Možeš prisiliti mat – počni prodorom pješaka koji otvara liniju.","Pješak otvara liniju, a zatim žrtva teške figure matira.","Pješak na g5 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.242' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – lenke zuerst eine Figur in die Ecke.","Der Turm lockt, danach reißt ein Damenopfer den Bauern zum Schlussschlag heran.","Turm nach h8 – Auftakt zum erzwungenen Matt."],"en":["A forced mate is ready – first lure a piece into the corner.","The rook lures, then a queen sacrifice brings a pawn in to finish.","Rook to h8 – the start of the forced mate."],"hr":["Prisilni mat je spreman – prvo namami figuru u kut.","Top namami, a žrtva dame dovodi pješaka za završni udarac.","Top na h8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.243' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du setzt forciert matt – ein stiller Zug bereitet den Knockout vor.","Der Turm schaltet den frechen Springer aus, dann fällt er auf der Grundreihe ein.","Turm nach f1 – Beginn der erzwungenen Mattführung."],"en":["You force mate – a quiet move prepares the knockout.","The rook removes the cheeky knight, then strikes on the back rank.","Rook to f1 – the start of the forced mate."],"hr":["Prisiljavaš mat – tihi potez priprema nokaut.","Top uklanja drskog skakača, a zatim udara na posljednjoj liniji.","Top na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.244' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt ist da – treibe den König mit Tempogewinn übers Brett.","Turm und Dame jagen den König, bis er im offenen Feld mattgesetzt wird.","Turm nach e8 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here – chase the king with gain of tempo.","Rook and queen hunt the king until he is mated in the open.","Rook to e8 – the start of the forced mate."],"hr":["Prisilni mat je tu – tjeraj kralja uz dobitak tempa.","Top i dama love kralja dok ne bude matiran u otvorenom polju.","Top na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.245' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert mattsetzen – beginne mit einem Turmopfer zur Ablenkung.","Erst opfert der Turm, dann verschnüren Dame und zweiter Turm den König.","Turm schlägt auf g8 – Beginn der erzwungenen Mattführung."],"en":["You can force mate – start with a deflecting rook sacrifice.","First the rook sacrifices, then queen and second rook box the king in.","Rook takes on g8 – the start of the forced mate."],"hr":["Možeš prisiliti mat – počni žrtvom topa za odvlačenje.","Prvo se top žrtvuje, a zatim dama i drugi top zatvaraju kralja.","Top uzima na g8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.246' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du setzt forciert matt – manövriere den Springer ans Schlüsselfeld.","Der Springer und die vorrückenden Bauern erdrücken den König in der Ecke.","Springer schlägt auf g4 – Auftakt zur erzwungenen Mattführung."],"en":["You force mate – manoeuvre the knight to its key square.","The knight and the advancing pawns crush the king in the corner.","Knight takes on g4 – the start of the forced mate."],"hr":["Prisiljavaš mat – odvedi skakača na ključno polje.","Skakač i pješaci u napredovanju gnječe kralja u kutu.","Skakač uzima na g4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.247' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt liegt vor – öffne mit Opfern die diagonalen Linien.","Läufer und Springer reißen die Stellung auf, ehe die Dame mit Läufer mattsetzt.","Läufer schlägt auf d7 – Beginn der erzwungenen Mattführung."],"en":["A forced mate is here – open the diagonals with sacrifices.","Bishop and knight tear things open before the queen mates with the bishop.","Bishop takes on d7 – the start of the forced mate."],"hr":["Prisilni mat je tu – žrtvama otvori dijagonale.","Lovac i skakač otvaraju poziciju prije nego dama matira uz lovca.","Lovac uzima na d7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.248' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert matt geben – beginne mit einem Damenopfer am König.","Die Dame opfert sich, dann liefert der Turm zusammen mit dem Bauern das Matt.","Dame schlägt auf g7 – Auftakt zum erzwungenen Matt."],"en":["You can force mate – start with a queen sacrifice at the king.","The queen sacrifices, then the rook with the pawn delivers mate.","Queen takes on g7 – the start of the forced mate."],"hr":["Možeš prisiliti mat – počni žrtvom dame na kralju.","Dama se žrtvuje, a zatim top zajedno s pješakom matira.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.249' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt wartet – opfere zur Ablenkung des Verteidigers.","Der Turm opfert sich, dann krönt der weit vorgerückte Bauer das Matt.","Turm schlägt auf f7 – Beginn der erzwungenen Mattführung."],"en":["A forced mate awaits – sacrifice to deflect the defender.","The rook sacrifices, then the far-advanced pawn crowns the mate.","Rook takes on f7 – the start of the forced mate."],"hr":["Prisilni mat čeka – žrtvuj za odvlačenje branitelja.","Top se žrtvuje, a daleko napredovali pješak kruni mat.","Top uzima na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.250' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du setzt forciert matt – tausche dich mit Opfern zur Grundreihe durch.","Beide Türme und die Dame opfern sich, bis der zweite Turm in der Ecke mattsetzt.","Turm nach d8 – Auftakt zur erzwungenen Mattführung."],"en":["You force mate – sacrifice your way through to the back rank.","Both rooks and the queen give themselves up until the second rook mates in the corner.","Rook to d8 – the start of the forced mate."],"hr":["Prisiljavaš mat – probij se žrtvama do posljednje linije.","Oba topa i dama se žrtvuju dok drugi top ne matira u kutu.","Top na d8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.251' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – öffne mit einem Turmopfer die Linie.","Der Turm opfert sich, dann zwingt die Dame den König in die tödliche Bauerngabel.","Turm schlägt auf e6 – Beginn der erzwungenen Mattführung."],"en":["A forced mate is here – open the file with a rook sacrifice.","The rook sacrifices, then the queen forces the king into a deadly net.","Rook takes on e6 – the start of the forced mate."],"hr":["Prisilni mat je tu – otvori liniju žrtvom topa.","Top se žrtvuje, a zatim dama tjera kralja u smrtonosnu mrežu.","Top uzima na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.252' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert mattsetzen – beginne mit einem Turmopfer in der Ecke.","Turm und Springer locken, dann fällt der zweite Turm zum Matt ein.","Turm schlägt auf h7 – Auftakt zur erzwungenen Mattführung."],"en":["You can force mate – start with a rook sacrifice in the corner.","Rook and knight lure, then the second rook crashes in to mate.","Rook takes on h7 – the start of the forced mate."],"hr":["Možeš prisiliti mat – počni žrtvom topa u kutu.","Top i skakač namame, a zatim drugi top upada za mat.","Top uzima na h7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.253' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht bereit – beginne mit einem Springeropfer.","Der Springer lockt den König, dann setzt der Turm in der Ecke matt.","Springer schlägt auf e8 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is ready – start with a knight sacrifice.","The knight lures the king, then the rook mates in the corner.","Knight takes on e8 – the start of the forced mate."],"hr":["Prisilni mat je spreman – počni žrtvom skakača.","Skakač namami kralja, a zatim top matira u kutu.","Skakač uzima na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.254' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du setzt forciert matt – beginne mit einem Läuferopfer am Königsflügel.","Läufer und Türme opfern sich, bis die Dame das Schlussmatt liefert.","Läufer schlägt auf g2 – Beginn der erzwungenen Mattführung."],"en":["You force mate – start with a bishop sacrifice on the kingside.","Bishops and rooks sacrifice until the queen delivers the final mate.","Bishop takes on g2 – the start of the forced mate."],"hr":["Prisiljavaš mat – počni žrtvom lovca na kraljevom krilu.","Lovci i topovi se žrtvuju dok dama ne zada završni mat.","Lovac uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.255' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt ist da – treibe den feindlichen König in die Enge.","Turm und Springer arbeiten zusammen und liefern das Mattnetz.","Turm schlägt auf g2 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here – drive the enemy king into a corner.","Rook and knight cooperate to weave the mating net.","Rook takes on g2 – the start of the forced mate."],"hr":["Prisilni mat je tu – stjeraj protivničkog kralja u kut.","Top i skakač surađuju i pletu matirajuću mrežu.","Top uzima na g2 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.256' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert mattsetzen – jage den König mit Tempogewinn übers Brett.","Turm und Dame opfern sich, danach erledigt der Läufer den König im freien Feld.","Turm schlägt auf g8 – Auftakt zur langen erzwungenen Mattführung."],"en":["You can force mate – chase the king across the board with gain of tempo.","Rook and queen sacrifice, then the bishop finishes the king in the open.","Rook takes on g8 – the start of the long forced mate."],"hr":["Možeš prisiliti mat – tjeraj kralja preko ploče uz dobitak tempa.","Top i dama se žrtvuju, a zatim lovac dokrajči kralja u otvorenom polju.","Top uzima na g8 — početak duge prisilne matirajuće serije."]}', HintsVersion=1 WHERE LineId LIKE '%:036.257' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt vor – manövriere den Springer ans Schlüsselfeld.","Beide Springer und der Turm umzingeln den König zum Hakenmatt.","Springer nach d6 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here – manoeuvre the knight to its key square.","Both knights and the rook surround the king for a hook mate.","Knight to d6 – the start of the forced mate."],"hr":["Prisilni mat je tu – odvedi skakača na ključno polje.","Oba skakača i top okružuju kralja za mat na kuku.","Skakač na d6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.258' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du setzt forciert matt – opfere zuerst die Dame zur Ablenkung.","Die Dame opfert sich, danach setzt das Läuferpaar tödlich matt.","Dame schlägt auf e3 – Beginn der erzwungenen Mattführung."],"en":["You force mate – first sacrifice the queen to deflect.","The queen sacrifices, then the bishop pair delivers a deadly mate.","Queen takes on e3 – the start of the forced mate."],"hr":["Prisiljavaš mat – prvo žrtvuj damu za odvlačenje.","Dama se žrtvuje, a zatim par lovaca zadaje smrtonosni mat.","Dama uzima na e3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.259' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein erzwungenes Matt steht bereit – locke den König mit Opfern heraus.","Turm und Dame opfern sich, bis der König im Kasten gefangen mattgesetzt wird.","Turm schlägt auf f4 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is ready – lure the king out with sacrifices.","Rook and queen sacrifice until the king is mated, trapped in a box.","Rook takes on f4 – the start of the forced mate."],"hr":["Prisilni mat je spreman – namami kralja van žrtvama.","Top i dama se žrtvuju dok kralj ne bude matiran, zarobljen u kutiji.","Top uzima na f4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.260' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert mattsetzen – beginne mit einem Damenopfer zur Ablenkung.","Dame und Türme opfern sich, danach gibt der Läufer das Schlussmatt.","Dame schlägt auf a8 – Auftakt zur erzwungenen Mattführung."],"en":["You can force mate – start with a deflecting queen sacrifice.","Queen and rooks sacrifice, then the bishop delivers the final mate.","Queen takes on a8 – the start of the forced mate."],"hr":["Možeš prisiliti mat – počni žrtvom dame za odvlačenje.","Dama i topovi se žrtvuju, a zatim lovac zadaje završni mat.","Dama uzima na a8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.261' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du setzt forciert matt – beginne mit einem Turmopfer am König.","Turm und Dame opfern sich, bis der Läufer das tödliche Matt liefert.","Turm schlägt auf b3 – Beginn der erzwungenen Mattführung."],"en":["You force mate – start with a rook sacrifice at the king.","Rook and queen sacrifice until the bishop delivers the deadly mate.","Rook takes on b3 – the start of the forced mate."],"hr":["Prisiljavaš mat – počni žrtvom topa na kralju.","Top i dama se žrtvuju dok lovac ne zada smrtonosni mat.","Top uzima na b3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.262' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt liegt vor – opfere zuerst die Dame zur Ablenkung.","Dame und Türme opfern sich, dann fällt der letzte Turm auf der Grundreihe ein.","Dame schlägt auf g7 – Auftakt zur erzwungenen Mattführung."],"en":["A forced mate is here – first sacrifice the queen to deflect.","Queen and rooks sacrifice, then the last rook crashes in on the back rank.","Queen takes on g7 – the start of the forced mate."],"hr":["Prisilni mat je tu – prvo žrtvuj damu za odvlačenje.","Dama i topovi se žrtvuju, a zatim posljednji top upada na posljednjoj liniji.","Dama uzima na g7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:036.263' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert mattsetzen – beginne mit einem Turmopfer am König.","Türme, Läufer und Dame opfern sich nacheinander, bis die Dame das Matt liefert.","Turm schlägt auf g7 – Auftakt zur langen erzwungenen Mattführung."],"en":["You can force mate – start with a rook sacrifice at the king.","Rooks, bishop and queen sacrifice in turn until the queen delivers mate.","Rook takes on g7 – the start of the long forced mate."],"hr":["Možeš prisiliti mat – počni žrtvom topa na kralju.","Topovi, lovac i dama se žrtvuju redom dok dama ne zada mat.","Top uzima na g7 — početak duge prisilne matirajuće serije."]}', HintsVersion=1 WHERE LineId LIKE '%:036.264' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert matt setzen – sieh dir die schwache Königsstellung an.","Deine Dame führt die Attacke, der Springer auf der zweiten Reihe öffnet die Tür.","Beginne mit Dame schlägt auf f2."],"en":["A forced mate is here — look at the exposed king.","Your queen leads the attack, the knight near the second rank pries it open.","Start with the queen taking on f2."],"hr":["Ovdje postoji prisilni mat — pogledaj izloženog kralja.","Tvoja dama vodi napad, skakač blizu druge linije otvara vrata.","Počni damom koja uzima na f2."]}', HintsVersion=1 WHERE LineId LIKE '%:036.265' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Es gibt ein erzwungenes Matt – locke den König heraus.","Türme und Läufer arbeiten zusammen, opfere zur Bahnöffnung.","Beginne mit Turm schlägt auf c1."],"en":["A forced mate awaits — drag the king out.","Rooks and bishop combine; sacrifice to open the lines.","Begin with the rook taking on c1."],"hr":["Čeka prisilni mat — izvuci kralja.","Topovi i lovac surađuju; žrtvuj da otvoriš linije.","Počni topom koji uzima na c1."]}', HintsVersion=1 WHERE LineId LIKE '%:036.266' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Hier liegt ein erzwungenes Matt in der Luft – jage den König.","Dame und Türme treiben den König über das Brett.","Beginne mit der Dame nach h4."],"en":["A forced mate is in the air — hunt the king.","Queen and rooks drive the king across the board.","Begin with the queen to h4."],"hr":["Prisilni mat visi u zraku — lovi kralja.","Dama i topovi tjeraju kralja preko ploče.","Počni damom na h4."]}', HintsVersion=1 WHERE LineId LIKE '%:036.267' AND BookFileName='chessable-u5-243265.pgn';
