UPDATE BookPuzzles SET HintsJson='{"de":["Du kannst forciert matt setzen – opfere, um den König festzulegen.","Turm, Bauer und Dame fangen den König im Schwalbenschwanz.","Beginne mit Turm schlägt auf f4."],"en":["A forced mate is here — sacrifice to pin the king in place.","Rook, pawn and queen trap the king in a swallow''s-tail net.","Begin with the rook taking on f4."],"hr":["Ovdje je prisilni mat — žrtvuj da fiksiraš kralja.","Top, pješak i dama hvataju kralja u mrežu lastinog repa.","Počni topom koji uzima na f4."]}', HintsVersion=1 WHERE LineId LIKE '%:037.012' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Eine erzwungene Mattführung wartet auf den Nachziehenden.","Öffne mit einem Bauernschlag Linien, dann übernimmt die Dame zusammen mit einem winzigen Bauern die Arbeit.","Schlage mit dem Bauern auf d4 – es folgt eine erzwungene Mattführung."],"en":["A forced mate is waiting for the side to move.","Crack the position open with a pawn capture, then the queen and a tiny pawn finish the job.","Take on d4 with the pawn — the start of a forced mate."],"hr":["Prisilni mat čeka onoga tko je na potezu.","Otvori linije udarcem pješaka, a dama zajedno sa sićušnim pješakom obavlja posao.","Uzmi pješakom na d4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.013' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein forciertes Matt steht für Weiß bereit.","Ein Damenopfer lockt einen Verteidiger weg, dann mattsetzt der Turm auf der Grundreihe.","Schlage mit der Dame auf e6 – der Beginn einer erzwungenen Mattführung."],"en":["A forced mate is ready for White.","A queen sacrifice drags a defender away, then the rook delivers mate on the back rank.","Take on e6 with the queen — the start of a forced mate."],"hr":["Prisilni mat spreman je za bijelog.","Žrtva dame odvlači branitelja, a zatim top matira na zadnjoj liniji.","Uzmi damom na e6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.014' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Nachziehende kann ein Matt erzwingen.","Dame und Läufer jagen den König in eine tödliche Ecke.","Ziehe die Dame nach d3 – der Beginn einer erzwungenen Mattführung."],"en":["The side to move can force mate.","The queen and bishop hunt the king into a fatal corner.","Play the queen to d3 — the start of a forced mate."],"hr":["Onaj tko je na potezu može prisiliti mat.","Dama i lovac tjeraju kralja u koban kut.","Odigraj damu na d3 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.015' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Nachziehende hat ein erstickendes Matt zur Hand.","Springer und Dame umzingeln den eingeengten König.","Spiele Damenzug nach c6 – der Beginn einer erzwungenen Mattführung."],"en":["The side to move has a smothered mate available.","The knight and queen close in on the boxed-in king.","Play the queen to c6 — the start of a forced mate."],"hr":["Onaj tko je na potezu ima ugušeni mat.","Skakač i dama opkoljavaju stiješnjenog kralja.","Odigraj damu na c6 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.016' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß kann ein Matt erzwingen.","Dame und Läufer drängen den König ins Netz, bis er erstickt.","Ziehe die Dame nach f7 – der Beginn einer erzwungenen Mattführung."],"en":["White can force mate.","The queen and bishop crowd the king until he suffocates.","Play the queen to f7 — the start of a forced mate."],"hr":["Bijeli može prisiliti mat.","Dama i lovac tjeraju kralja sve dok se ne uguši.","Odigraj damu na f7 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.017' AND BookFileName='chessable-u5-243265.pgn';
