UPDATE BookPuzzles SET HintsJson='{"de":["Weiß setzt in wenigen Zügen matt.","Ein Damenopfer lenkt ab, dann mattsetzen die beiden Läufer gemeinsam.","Schlage mit der Dame auf e8 – der Beginn einer erzwungenen Mattführung."],"en":["White mates in just a few moves.","A queen sacrifice deflects, then the two bishops mate together.","Take on e8 with the queen — the start of a forced mate."],"hr":["Bijeli matira u nekoliko poteza.","Žrtva dame odvlači, a zatim dva lovca zajedno matiraju.","Uzmi damom na e8 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.023' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Der Nachziehende hat ein erzwungenes Matt.","Ein Springeropfer lockt den König, dann setzt die Dame matt.","Ziehe den Springer nach f1 – der Beginn einer erzwungenen Mattführung."],"en":["The side to move has a forced mate.","A knight sacrifice lures the king, then the queen mates.","Play the knight to f1 — the start of a forced mate."],"hr":["Onaj tko je na potezu ima prisilni mat.","Žrtva skakača mami kralja, a zatim dama matira.","Odigraj skakača na f1 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.024' AND BookFileName='chessable-u5-243265.pgn';
