UPDATE BookPuzzles SET HintsJson='{"de":["Der Nachziehende verfügt über eine erzwungene Mattführung.","Die Dame stürmt heran, der Läufer schließt das Netz, der Turm fällt.","Ziehe die Dame nach h4 – der Beginn einer erzwungenen Mattführung."],"en":["The side to move has a forced mate.","The queen storms in, the bishop closes the net, and a rook is offered.","Play the queen to h4 — the start of a forced mate."],"hr":["Onaj tko je na potezu ima prisilni mat.","Dama nadire, lovac zatvara mrežu, a top se žrtvuje.","Odigraj damu na h4 — početak prisilnog mata."]}', HintsVersion=1 WHERE LineId LIKE '%:037.042' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat eine erzwungene Mattführung – finde sie.","Der Läufer und ein Turm weben ein Netz um den weißen König.","Beginne mit dem Läufer nach g2, der das Mattnetz einleitet."],"en":["Black has a forced mate hidden in the position.","A bishop and rook spin a net around the white king.","Start with the bishop to g2 to launch the mating sequence."],"hr":["Crni ima prisilni mat skriven u poziciji.","Lovac i top pletu mrežu oko bijelog kralja.","Počni lovcem na g2 koji pokreće matni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:037.043' AND BookFileName='chessable-u5-243265.pgn';
