UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – ein Opfer öffnet den König.","Dame, Türme und Springer überrollen den schwarzen König.","Beginne mit dem Springer nach f6, der das Opfer einleitet."],"en":["White has a forced mate — a sacrifice opens the king.","Queen, rooks and knight overwhelm the black king.","Begin with the knight to f6 to launch the sacrifice."],"hr":["Bijeli ima prisilni mat — žrtva otvara kralja.","Dama, topovi i skakač preplavljuju crnog kralja.","Počni skakačem na f6 koji pokreće žrtvu."]}', HintsVersion=1 WHERE LineId LIKE '%:037.059' AND BookFileName='chessable-u5-243265.pgn';
