UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – der König erstickt.","Springer und Läufer schnüren den weißen König ein.","Beginne mit dem Springer nach d3, der das Netz schließt."],"en":["Black has a forced mate — the king suffocates.","The knights and bishops lock the white king in.","Begin with the knight to d3 to close the net."],"hr":["Crni ima prisilni mat — kralj se guši.","Skakači i lovci zaključavaju bijelog kralja.","Počni skakačem na d3 koji zatvara mrežu."]}', HintsVersion=1 WHERE LineId LIKE '%:037.061' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – ein stiller Turmzug bereitet alles vor.","Türme, Läufer und Dame umzingeln den schwarzen König.","Beginne mit dem Turm nach e1 und beginne die erzwungene Folge."],"en":["White forces mate — a quiet rook move prepares it all.","Rooks, bishops and queen surround the black king.","Begin with the rook to e1 to start the forced sequence."],"hr":["Bijeli prisiljava mat — tihi potez topa sve priprema.","Topovi, lovci i dama okružuju crnog kralja.","Počni topom na e1 da započneš prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:037.062' AND BookFileName='chessable-u5-243265.pgn';
