UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt auf der Grundreihe.","Turm und Läufer ebnen mit einem Bauern den Weg zur Umwandlung.","Beginne mit dem Turm nach b7 und beginne die erzwungene Folge."],"en":["White forces mate on the back rank.","The rook and bishop clear the path for a pawn to promote.","Begin with the rook to b7 to start the forced sequence."],"hr":["Bijeli prisiljava mat na zadnjoj liniji.","Top i lovac otvaraju put pješaku do promocije.","Počni topom na b7 da pokreneš prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:037.064' AND BookFileName='chessable-u5-243265.pgn';
