UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt – ein Opfer lenkt ab.","Springer und beide Läufer überrollen den weißen König.","Schlage mit dem Turm auf g5 und beginne die erzwungene Folge."],"en":["Black has a forced mate — a sacrifice deflects the defender.","A knight and both bishops overrun the white king.","Take on g5 with the rook to begin the forced sequence."],"hr":["Crni ima prisilni mat — žrtva odvlači branitelja.","Skakač i oba lovca preplavljuju bijelog kralja.","Uzmi topom na g5 da pokreneš prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:037.068' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – ein Opfer zerstört die Verteidigung.","Dame, Turm und Läufer brechen zur Königsfestung durch.","Beginne mit dem Springer nach h5 und beginne die erzwungene Folge."],"en":["White forces mate — a sacrifice removes the defender.","Queen, rook and bishop break through to the king.","Begin with the knight to h5 to start the forced sequence."],"hr":["Bijeli prisiljava mat — žrtva uklanja branitelja.","Dama, top i lovac probijaju se do kralja.","Počni skakačem na h5 da pokreneš prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:037.069' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß erzwingt das Matt – ein Opfer öffnet das Mattnetz.","Bauern und Dame schnüren den schwarzen König im Zentrum ein.","Beginne mit dem Springer nach g4 und beginne die erzwungene Folge."],"en":["White forces mate — a sacrifice opens the mating net.","Pawns and the queen trap the black king in the centre.","Begin with the knight to g4 to start the forced sequence."],"hr":["Bijeli prisiljava mat — žrtva otvara matnu mrežu.","Pješaci i dama zatvaraju crnog kralja u centru.","Počni skakačem na g4 da pokreneš prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:037.070' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Weiß hat ein erzwungenes Matt – ein stiller Zug fesselt den König.","Dame und beide Läufer arbeiten auf das Matt hin.","Beginne mit dem Turm nach e1 und beginne die erzwungene Folge."],"en":["White has a forced mate — a quiet move ties the king down.","The queen and both bishops aim at the mating square.","Begin with the rook to e1 to start the forced sequence."],"hr":["Bijeli ima prisilni mat — tihi potez veže kralja.","Dama i oba lovca rade prema matu.","Počni topom na e1 da pokreneš prisilni niz."]}', HintsVersion=1 WHERE LineId LIKE '%:037.071' AND BookFileName='chessable-u5-243265.pgn';
