UPDATE BookPuzzles SET HintsJson='{"de":["Mit den leichten Figuren lässt sich der König ins Mattnetz treiben.","Ein Springer leitet die entscheidende Jagd ein, der zweite und ein Bauer vollenden.","Springer von d3 nach b4 startet die erzwungene Mattführung."],"en":["The minor pieces can herd the king into a forced mate.","One knight begins the decisive hunt while its partner and a pawn finish.","Knight from d3 to b4 starts the forced mating sequence."],"hr":["Lakim figurama kralja se može utjerati u matnu mrežu.","Jedan skakač započinje odlučujuću hajku, drugi i pješak dovršavaju.","Skakač s d3 na b4 pokreće prisilni matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.073' AND BookFileName='chessable-u5-243265.pgn';
