UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer reißt die Königsstellung auf und erzwingt das Matt.","Läufer und doppelte Türme auf der vorletzten Reihe vollstrecken.","Läufer von d3 nach f5 opfert und leitet die Mattführung ein."],"en":["A queen sacrifice tears open the king and forces mate.","A bishop and the doubled rooks on the seventh do the deadly work.","Bishop from d3 to f5 sacrifices and starts the forced mate."],"hr":["Žrtva dame razbija kraljevu poziciju i prisiljava mat.","Lovac i udvojeni topovi na sedmom redu izvršavaju kaznu.","Lovac s d3 na f5 žrtvuje i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.075' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Mit einem Opfer wird der König freigelegt und mattgesetzt.","Ein Turmopfer beseitigt den Verteidiger, der zweite Turm schlägt zu.","Turm von e5 nach g5 opfert und leitet die Mattführung ein."],"en":["A sacrifice strips the king bare and delivers mate.","One rook is offered to remove a defender, the other strikes home.","Rook from e5 to g5 sacrifices and begins the forced mate."],"hr":["Žrtvom se kralj ogoljuje i matira.","Žrtva topa uklanja branitelja, drugi top zadaje udarac.","Top s e5 na g5 žrtvuje i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.076' AND BookFileName='chessable-u5-243265.pgn';
