UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer reißt den König heraus und erzwingt das Matt.","Springer, Läufer und Turm setzen den freigelegten König matt.","Dame von c2 nach h7 opfert und leitet die Mattführung ein."],"en":["A queen sacrifice drags the king out and forces mate.","Knight, bishop and rook mate the exposed king.","Queen from c2 to h7 sacrifices and begins the forced mate."],"hr":["Žrtva dame izvlači kralja i prisiljava mat.","Skakač, lovac i top matiraju izloženog kralja.","Dama s c2 na h7 žrtvuje i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.091' AND BookFileName='chessable-u5-243265.pgn';
