UPDATE BookPuzzles SET HintsJson='{"de":["Ein Läuferopfer leitet ein erzwungenes Matt ein.","Die Türme dringen auf den hinteren Reihen ein und vollstrecken.","Läufer von g2 nach c6 opfert und beginnt die Mattführung."],"en":["A bishop sacrifice sets up a forced mate.","The rooks invade on the back ranks and finish the king.","Bishop from g2 to c6 sacrifices and begins the forced mate."],"hr":["Žrtva lovca uvodi prisilni mat.","Topovi prodiru na zadnjim redovima i izvršavaju kaznu.","Lovac s g2 na c6 žrtvuje i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.093' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damenopfer entfesselt ein erzwungenes Matt.","Springer, Läufer und Dame jagen den König systematisch.","Dame von h5 nach f7 opfert und leitet die Mattführung ein."],"en":["A queen sacrifice unleashes a forced mate.","Knight, bishop and queen hunt the king methodically.","Queen from h5 to f7 sacrifices and begins the forced mate."],"hr":["Žrtva dame oslobađa prisilni mat.","Skakač, lovac i dama metodično love kralja.","Dama s h5 na f7 žrtvuje i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.094' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt mit Opfern das Matt.","Türme, Dame und Läufer brechen den weißen König.","Bauer von f4 nach g3 opfert und leitet die Mattführung ein."],"en":["Black forces mate through sacrifices.","Rooks, queen and bishop break the white king down.","Pawn from f4 to g3 sacrifices and begins the forced mate."],"hr":["Crni žrtvama prisiljava mat.","Topovi, dama i lovac lome bijelog kralja.","Pješak s f4 na g3 žrtvuje i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.095' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein erzwungenes Matt.","Läufer, Turm und Dame stürmen gemeinsam auf den König ein.","Läufer von g5 nach e3 leitet die Mattführung ein."],"en":["Black has a forced mate.","Bishops, rook and queen storm the king together.","Bishop from g5 to e3 begins the forced mate."],"hr":["Crni ima prisilni mat.","Lovci, top i dama zajedno jurišaju na kralja.","Lovac s g5 na e3 započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.096' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Turmopfer reißt den Königsschutz auf und erzwingt das Matt.","Türme und Dame durchbrechen die Bauernkette vor dem König.","Turm von b2 nach b7 opfert und leitet die Mattführung ein."],"en":["A rook sacrifice tears open the king''s cover and forces mate.","The rooks and queen smash through the pawns guarding the king.","Rook from b2 to b7 sacrifices and begins the forced mate."],"hr":["Žrtva topa razbija kraljev zaklon i prisiljava mat.","Topovi i dama probijaju pješake ispred kralja.","Top s b2 na b7 žrtvuje i započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.097' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Springerzug leitet einen erzwungenen Mattangriff ein.","Dame, Läufer und Turm bündeln sich gegen den eingeschlossenen König.","Springer von d5 nach e7 leitet die Mattführung ein."],"en":["A knight move launches a forced mating attack.","Queen, bishop and rook converge on the boxed-in king.","Knight from d5 to e7 begins the forced mate."],"hr":["Potez skakača pokreće prisilni matni napad.","Dama, lovac i top usmjeravaju se na zatvorenog kralja.","Skakač s d5 na e7 započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.098' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz erzwingt das Matt am verwundbaren weißen König.","Dame, Läufer und Turm zielen auf die schwache Grundreihe.","Dame von g5 nach h4 leitet die Mattführung ein."],"en":["Black forces mate against the vulnerable white king.","Queen, bishop and rook target the weak back rank.","Queen from g5 to h4 begins the forced mate."],"hr":["Crni prisiljava mat protiv ranjivog bijelog kralja.","Dama, lovac i top ciljaju slabi zadnji red.","Dama s g5 na h4 započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.099' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Ein Damen-Endspiel birgt ein erzwungenes Matt.","Dame und ein Bauer treiben den schwarzen König ins Netz.","Dame von b8 nach h8 leitet die Mattführung ein."],"en":["A queen endgame hides a forced mate.","The queen and a pawn drive the black king into the net.","Queen from b8 to h8 begins the forced mate."],"hr":["Završnica s damom krije prisilni mat.","Dama i pješak tjeraju crnog kralja u mrežu.","Dama s b8 na h8 započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.100' AND BookFileName='chessable-u5-243265.pgn';
UPDATE BookPuzzles SET HintsJson='{"de":["Schwarz hat ein verstecktes erzwungenes Matt.","Springer, Dame und Turm spannen ein Netz um den weißen König.","Springer von e3 nach d1 leitet die Mattführung ein."],"en":["Black has a hidden forced mate.","Knight, queen and rook weave a net around the white king.","Knight from e3 to d1 begins the forced mate."],"hr":["Crni ima skriveni prisilni mat.","Skakač, dama i top pletu mrežu oko bijelog kralja.","Skakač s e3 na d1 započinje matni slijed."]}', HintsVersion=1 WHERE LineId LIKE '%:037.101' AND BookFileName='chessable-u5-243265.pgn';
